def sha256_file(path: Path, limit_mb: int | None = None) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        if limit_mb is None:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        else:
            h.update(f.read(limit_mb * 1024 * 1024))
    return h.hexdigest()


def stable_hash(*parts: object, n: int = 16) -> str:
    h = hashlib.sha256()
    for p in parts:
        h.update(str(p).encode("utf-8", errors="replace"))
        h.update(b"\0")
    return h.hexdigest()[:n]


def canonical_json(payload: Mapping[str, Any]) -> str:
    def clean(v: Any) -> Any:
        if isinstance(v, (np.integer,)):
            return int(v)
        if isinstance(v, (np.floating,)):
            f = float(v)
            return None if not math.isfinite(f) else f
        if isinstance(v, (pd.Timestamp, datetime)):
            return pd.Timestamp(v).isoformat()
        if not isinstance(v, (dict, list, tuple, set)):
            try:
                if pd.isna(v):
                    return None
            except Exception:
                pass
        return v
    return json.dumps({str(k): clean(v) for k, v in payload.items()}, sort_keys=True, separators=(",", ":"))


def parameter_vector_dict(candidate: Mapping[str, Any], engine: FamilyEngine | None = None) -> dict[str, Any]:
    engine_id = str(candidate.get("family_engine_id", ""))
    row_sem = candidate.get("row_semantics")
    if not row_sem and engine_id in ENGINES:
        row_sem = ENGINES[engine_id].row_semantics()
    out: dict[str, Any] = {}
    for field in PARAMETER_VECTOR_FIELDS:
        if field == "row_semantics":
            out[field] = row_sem or (engine.row_semantics() if engine is not None else "")
        elif field == "event_semantics_version":
            out[field] = candidate.get(field, EVENT_SEMANTICS_VERSION)
        else:
            out[field] = candidate.get(field, "")
    return out


def parameter_vector_json(candidate: Mapping[str, Any], engine: FamilyEngine | None = None) -> str:
    existing = candidate.get("parameter_vector_json", "")
    if isinstance(existing, str) and existing.strip():
        return existing
    return canonical_json(parameter_vector_dict(candidate, engine))


def parameter_vector_hash(candidate: Mapping[str, Any], engine: FamilyEngine | None = None) -> str:
    existing = str(candidate.get("parameter_vector_hash", "") or "")
    if existing and existing.lower() not in {"nan", "none"}:
        return existing
    return hashlib.sha256(parameter_vector_json(candidate, engine).encode("utf-8")).hexdigest()[:24]


def definition_identity(candidate: Mapping[str, Any]) -> str:
    existing = str(candidate.get("candidate_definition_id", "") or "")
    if existing and existing.lower() not in {"nan", "none"}:
        return existing
    cid = str(candidate.get("candidate_id", "") or "")
    if cid and cid.lower() not in {"nan", "none"}:
        return cid
    return f"kraken_agg__{candidate.get('hypothesis_id', '')}__{candidate.get('definition_id', '')}"


def symbol_identity(candidate: Mapping[str, Any], symbol: str | None = None) -> str:
    existing = str(candidate.get("candidate_symbol_id", "") or "")
    if existing and existing.lower() not in {"nan", "none"}:
        return existing
    sym = str(symbol or candidate.get("symbol", "") or "")
    return f"{definition_identity(candidate)}__{sym}" if sym else ""


def identity_enriched_record(record: Mapping[str, Any], engine: FamilyEngine | None = None, *, symbol: str | None = None) -> dict[str, Any]:
    out = dict(record)
    engine = engine or (ENGINES.get(str(out.get("family_engine_id"))) if str(out.get("family_engine_id")) in ENGINES else None)
    out["candidate_definition_id"] = definition_identity(out)
    out["candidate_id"] = out["candidate_definition_id"]
    if symbol is not None:
        out["symbol"] = symbol
    out["candidate_symbol_id"] = symbol_identity(out, str(out.get("symbol", "")))
    out["event_semantics_version"] = out.get("event_semantics_version", EVENT_SEMANTICS_VERSION)
    out["row_semantics"] = out.get("row_semantics", engine.row_semantics() if engine is not None else "")
    out["contract_event_type"] = out.get("contract_event_type", engine.contract_event_type() if engine is not None else "")
    out["engine_contract_hash"] = out.get("engine_contract_hash", engine.engine_contract_hash() if engine is not None else "")
    out["parameter_vector_json"] = parameter_vector_json(out, engine)
    out["parameter_vector_hash"] = parameter_vector_hash(out, engine)
    out["parameter_manifest_pointer"] = out.get("parameter_manifest_pointer", "")
    return out


def utc_stamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")


def resolve_path(path: str | Path) -> Path:
    p = Path(path)
    return p if p.is_absolute() else REPO / p


def write_text(path: Path, text: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")


def write_csv(path: Path, rows: pd.DataFrame | Sequence[Mapping[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    df = rows if isinstance(rows, pd.DataFrame) else pd.DataFrame(list(rows))
    df.to_csv(path, index=False)


def append_csv(path: Path, rows: pd.DataFrame | Sequence[Mapping[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    df = rows if isinstance(rows, pd.DataFrame) else pd.DataFrame(list(rows))
    if df.empty:
        return
    df.to_csv(path, index=False, mode="a", header=not path.exists())


def read_csv_safe(path: Path) -> pd.DataFrame:
    if not path.exists() or path.stat().st_size == 0:
        return pd.DataFrame()
    try:
        return pd.read_csv(path)
    except Exception:
        return pd.DataFrame()


TRUE_TOKENS = {"true", "1", "yes", "y"}
FALSE_TOKENS = {"false", "0", "no", "n"}


def parse_bool_value(value: Any, *, default: bool | None = None, strict: bool = True) -> bool:
    if isinstance(value, (bool, np.bool_)):
        return bool(value)
    try:
        if pd.isna(value):
            if default is not None:
                return bool(default)
            if strict:
                raise ValueError("ambiguous boolean value: null")
            return False
    except Exception:
        pass
    if isinstance(value, (int, float, np.integer, np.floating)) and math.isfinite(float(value)):
        if float(value) == 1.0:
            return True
        if float(value) == 0.0:
            return False
    text = str(value).strip().lower()
    if text in TRUE_TOKENS:
        return True
    if text in FALSE_TOKENS:
        return False
    if default is not None:
        return bool(default)
    if strict:
        raise ValueError(f"ambiguous boolean value: {value!r}")
    return False


def parse_bool_series(series: pd.Series | Sequence[Any] | Any, *, default: bool | None = None, strict: bool = True) -> pd.Series:
    if isinstance(series, pd.Series):
        src = series
    elif isinstance(series, (list, tuple, np.ndarray)):
        src = pd.Series(series)
    else:
        src = pd.Series([series])
    return src.apply(lambda v: bool(parse_bool_value(v, default=default, strict=strict)))


def any_true(series: pd.Series | Sequence[Any] | Any, *, default: bool | None = None, strict: bool = True) -> bool:
    return bool(parse_bool_series(series, default=default, strict=strict).any())


def all_true(series: pd.Series | Sequence[Any] | Any, *, default: bool | None = None, strict: bool = True) -> bool:
    parsed = parse_bool_series(series, default=default, strict=strict)
    return bool(len(parsed) > 0 and parsed.all())


TRANSLATION_MERGE_KEY_FIELDS = ("hypothesis_id", "family_engine_id")
TRANSLATION_COMPATIBILITY_FIELDS = (
    "priority_lane",
    "current_data_tier",
    "required_data_tier",
    "current_testability",
    "forward_capture_upgrade_path",
    "translation_type",
    "translation_rankable",
    "translated_engine",
    "translation_reason",
)
CANDIDATE_SYMBOL_IDENTITY_FIELDS = (
    "candidate_definition_id",
    "parameter_vector_hash",
    "candidate_symbol_id",
    "symbol",
    "event_semantics_version",
)


def normalized_cell(value: Any) -> str:
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    text = str(value).strip()
    return "" if text.lower() in {"nan", "none", "nat"} else text


def unique_nonblank_values(series: pd.Series) -> list[str]:
    vals = sorted({normalized_cell(v) for v in series.tolist() if normalized_cell(v)})
    return vals


def collapse_translation_manifest(translations: pd.DataFrame, audit_path: Path | None = None) -> tuple[pd.DataFrame, pd.DataFrame]:
    """Collapse compatible duplicate hypothesis/engine translation rows before merging definitions.

    The prelaunch definition manifest is definition-level. The translation audit is hypothesis-level and
    may contain multiple source-family rows for the same hypothesis/engine. Those rows can annotate one
    definition, but they must not create a many-to-many merge that duplicates candidate definitions.
    """
    if translations.empty:
        audit = pd.DataFrame([{"status": "pass", "detail": "empty_translation_manifest"}])
        if audit_path is not None:
            write_csv(audit_path, audit)
        return translations.copy(), audit
    missing = [c for c in TRANSLATION_MERGE_KEY_FIELDS if c not in translations.columns]
    if missing:
        audit = pd.DataFrame([{"status": "fail", "detail": f"missing_translation_merge_key:{';'.join(missing)}"}])
        if audit_path is not None:
            write_csv(audit_path, audit)
        raise RuntimeError(f"translation manifest missing merge keys: {missing}")
    rows: list[dict[str, Any]] = []
    collapsed: list[dict[str, Any]] = []
    contradiction = False
    grouped = translations.groupby(list(TRANSLATION_MERGE_KEY_FIELDS), dropna=False, sort=False)
    for key, group in grouped:
        rec = group.iloc[0].to_dict()
        duplicate_count = int(len(group))
        contradictory_fields: list[str] = []
        if duplicate_count > 1:
            for col in TRANSLATION_COMPATIBILITY_FIELDS:
                if col in group.columns and len(unique_nonblank_values(group[col])) > 1:
                    contradictory_fields.append(col)
            if "source_family" in group.columns:
                rec["source_family"] = ";".join(unique_nonblank_values(group["source_family"]))
        status = "pass" if not contradictory_fields else "fail"
        action = "unique_key"
        if duplicate_count > 1 and not contradictory_fields:
            action = "compatible_duplicate_collapsed"
        elif contradictory_fields:
            action = "contradictory_duplicate_fail_closed"
            contradiction = True
        key_values = key if isinstance(key, tuple) else (key,)
        rows.append({
            "hypothesis_id": key_values[0],
            "family_engine_id": key_values[1],
            "translation_rows": duplicate_count,
            "status": status,
            "action": action,
            "contradictory_fields": ";".join(contradictory_fields),
            "source_families": rec.get("source_family", ""),
        })
        if not contradictory_fields:
            collapsed.append(rec)
    audit = pd.DataFrame(rows)
    if audit_path is not None:
        write_csv(audit_path, audit)
    if contradiction:
        raise RuntimeError("contradictory duplicate translation rows before prelaunch merge")
    return pd.DataFrame(collapsed), audit


def definition_identity_key_columns(frame: pd.DataFrame) -> list[str]:
    if "definition_id" in frame.columns:
        return ["definition_id", "parameter_vector_hash"] if "parameter_vector_hash" in frame.columns else ["definition_id"]
    if "candidate_definition_id" in frame.columns:
        return ["candidate_definition_id", "parameter_vector_hash"] if "parameter_vector_hash" in frame.columns else ["candidate_definition_id"]
    return []


def deduplicate_definition_manifest(frame: pd.DataFrame, *, context: str, audit_path: Path | None = None) -> pd.DataFrame:
    if frame.empty:
        audit = pd.DataFrame([{"context": context, "status": "pass", "action": "empty_manifest"}])
        if audit_path is not None:
            write_csv(audit_path, audit)
        return frame.copy()
    key_cols = definition_identity_key_columns(frame)
    if not key_cols:
        audit = pd.DataFrame([{"context": context, "status": "fail", "action": "missing_definition_identity_key"}])
        if audit_path is not None:
            write_csv(audit_path, audit)
        raise RuntimeError(f"{context}: missing definition identity key")
    work = frame.copy()
    dup_mask = work.duplicated(key_cols, keep=False)
    audit_rows: list[dict[str, Any]] = [{
        "context": context,
        "identity_key": ";".join(key_cols),
        "duplicate_rows": int(dup_mask.sum()),
        "duplicate_groups": int(work.loc[dup_mask, key_cols].drop_duplicates().shape[0]) if dup_mask.any() else 0,
        "status": "pass",
        "action": "no_duplicate_definition_identity" if not dup_mask.any() else "duplicates_checked",
        "differing_fields": "",
    }]
    conflict = False
    if dup_mask.any():
        for key, group in work.loc[dup_mask].groupby(key_cols, dropna=False, sort=False):
            differing = [col for col in work.columns if len(unique_nonblank_values(group[col])) > 1]
            key_values = key if isinstance(key, tuple) else (key,)
            if differing:
                conflict = True
                action = "conflicting_duplicate_definition_fail_closed"
                status = "fail"
            else:
                action = "exact_duplicate_definition_dropped"
                status = "pass"
            audit_rows.append({
                "context": context,
                "identity_key": ";".join(f"{col}={val}" for col, val in zip(key_cols, key_values)),
                "duplicate_rows": int(len(group)),
                "duplicate_groups": 1,
                "status": status,
                "action": action,
                "differing_fields": ";".join(differing),
            })
    audit = pd.DataFrame(audit_rows)
    if audit_path is not None:
        write_csv(audit_path, audit)
    if conflict:
        raise RuntimeError(f"{context}: conflicting duplicate definition identity rows")
    return work.drop_duplicates(key_cols, keep="first").copy()


def candidate_symbol_uniqueness_audit_frame(frame: pd.DataFrame, *, context: str) -> pd.DataFrame:
    if frame.empty:
        return pd.DataFrame([{"context": context, "check": "candidate_symbol_identity_unique", "status": "pass", "bad_rows": 0, "duplicate_groups": 0}])
    missing = [c for c in CANDIDATE_SYMBOL_IDENTITY_FIELDS if c not in frame.columns]
    if missing:
        return pd.DataFrame([{"context": context, "check": "candidate_symbol_identity_unique", "status": "fail", "bad_rows": len(frame), "duplicate_groups": 0, "detail": f"missing:{';'.join(missing)}"}])
    dup = frame.duplicated(list(CANDIDATE_SYMBOL_IDENTITY_FIELDS), keep=False)
    rows = [{
        "context": context,
        "check": "candidate_symbol_identity_unique",
        "status": "fail" if dup.any() else "pass",
        "bad_rows": int(dup.sum()),
        "duplicate_groups": int(frame.loc[dup, list(CANDIDATE_SYMBOL_IDENTITY_FIELDS)].drop_duplicates().shape[0]) if dup.any() else 0,
        "detail": "duplicate candidate-symbol rows would double-count aggregate metrics" if dup.any() else "unique",
    }]
    if dup.any():
        for key, group in frame.loc[dup].groupby(list(CANDIDATE_SYMBOL_IDENTITY_FIELDS), dropna=False, sort=False):
            key_values = key if isinstance(key, tuple) else (key,)
            rows.append({
                "context": context,
                "check": "candidate_symbol_identity_duplicate_group",
                "status": "fail",
                "bad_rows": int(len(group)),
                "duplicate_groups": 1,
                "detail": ";".join(f"{col}={val}" for col, val in zip(CANDIDATE_SYMBOL_IDENTITY_FIELDS, key_values)),
            })
            if len(rows) >= 101:
                rows.append({"context": context, "check": "candidate_symbol_identity_duplicate_group", "status": "fail", "bad_rows": 0, "duplicate_groups": 0, "detail": "truncated_after_100_duplicate_groups"})
                break
    return pd.DataFrame(rows)


def assert_candidate_symbol_uniqueness(frame: pd.DataFrame, *, context: str, audit_path: Path | None = None) -> pd.DataFrame:
    audit = candidate_symbol_uniqueness_audit_frame(frame, context=context)
    if audit_path is not None:
        write_csv(audit_path, audit)
    if audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any():
        raise RuntimeError(f"{context}: duplicate candidate-symbol identity rows")
    return audit


def read_parquet_safe(path: Path) -> pd.DataFrame:
    if not path.exists() or path.stat().st_size == 0:
        return pd.DataFrame()
    try:
        return pd.read_parquet(path)
    except Exception:
        return pd.DataFrame()


def read_json(path: Path, default: Any = None) -> Any:
    try:
        return json.loads(path.read_text())
    except Exception:
        return default


def safe_float(v: Any, default: float = float("nan")) -> float:
    try:
        f = float(v)
        return f if math.isfinite(f) else default
    except Exception:
        return default


def bool_mask(mask: pd.Series) -> pd.Series:
    """Normalize nullable/object masks to plain bool without relying on pandas downcasting."""
    if not isinstance(mask, pd.Series):
        mask = pd.Series(mask)
    eq_true = mask.eq(True)
    try:
        values = eq_true.to_numpy(dtype=bool, na_value=False)
    except TypeError:
        values = np.asarray(eq_true, dtype=bool)
    return pd.Series(values, index=mask.index)


TSMOM_SIDE_SEMANTICS = {
    "long": {"direction": "long", "diagnostic": False, "label_cap": ""},
    "long_flat": {"direction": "long", "diagnostic": False, "label_cap": ""},
    "short": {"direction": "short", "diagnostic": False, "label_cap": ""},
    "short_diagnostic": {"direction": "short", "diagnostic": True, "label_cap": "short_diagnostic_cap_not_primary_tsmom_evidence"},
    "zero_fee_diagnostic": {"direction": "long", "diagnostic": True, "label_cap": "zero_fee_current_account_diagnostic_not_primary_tsmom_evidence"},
}


def normalize_tsmom_side(side: Any) -> str:
    text = str(side or "long").strip().lower()
    if text not in TSMOM_SIDE_SEMANTICS:
        raise ValueError(f"unsupported TSMOM side semantics: {side!r}")
    return text


def tsmom_side_direction(side: Any) -> str:
    return str(TSMOM_SIDE_SEMANTICS[normalize_tsmom_side(side)]["direction"])


def tsmom_side_label_cap(side: Any) -> str:
    return str(TSMOM_SIDE_SEMANTICS[normalize_tsmom_side(side)]["label_cap"])


def pf(vals: pd.Series) -> float:
    v = pd.to_numeric(vals, errors="coerce").dropna()
    wins = v[v > 0].sum()
    losses = -v[v < 0].sum()
    if losses <= 0:
        return float("inf") if wins > 0 else float("nan")
    return float(wins / losses)


def max_dd(vals: pd.Series) -> float:
    v = pd.to_numeric(vals, errors="coerce").fillna(0.0).to_numpy(dtype=float)
    if len(v) == 0:
        return float("nan")
    eq = np.cumsum(v)
    peak = np.maximum.accumulate(eq)
    return float((eq - peak).min())


def parse_time_ms_or_iso(series: pd.Series) -> pd.Series:
    if pd.api.types.is_numeric_dtype(series):
        return pd.to_datetime(series, unit="ms", utc=True, errors="coerce")
    return pd.to_datetime(series, utc=True, errors="coerce")


def dataframe_hash(df: pd.DataFrame, cols: Sequence[str] | None = None) -> str:
    if df.empty:
        return stable_hash("empty", n=24)
    use = df[list(cols)] if cols else df
    payload = use.astype(str).to_csv(index=False)
    return hashlib.sha256(payload.encode("utf-8", errors="replace")).hexdigest()


def file_size_bytes(path: Path) -> int:
    if path.is_file():
        return path.stat().st_size
    if path.is_dir():
        return sum(p.stat().st_size for p in path.rglob("*") if p.is_file())
    return 0


class RunNotifier:
    def __init__(self, run_root: Path, *, disabled: bool, require_remote: bool, allow_no_remote: bool):
        self.run_root = run_root
        self.disabled = disabled
        self.require_remote = require_remote
        self.allow_no_remote = allow_no_remote
        self.events_path = run_root / "notifications/telegram_events.jsonl"
        self.events_path.parent.mkdir(parents=True, exist_ok=True)
        self.remote_available = False
        self.status = "disabled" if disabled else "local_jsonl_only"
        self._remote = None
        if not disabled and TelegramNotifier is not None:
            try:
                class Args:
                    tg_bot_token = ""
                    tg_chat_id = ""
                    tg_auto_chat = False
                    disable_telegram = False
                    telegram_dry_run = False
                self._remote = TelegramNotifier.from_args(Args(), run_label="kraken-family-engine-aggregate")
                self.remote_available = bool(getattr(self._remote, "enabled", False))
                self.status = "remote_available" if self.remote_available else "local_jsonl_only"
            except Exception as exc:  # pragma: no cover
                self.status = f"remote_init_failed:{type(exc).__name__}"
        if require_remote and not allow_no_remote and not self.remote_available and not disabled:
            raise RuntimeError("--require-telegram set but remote Telegram is unavailable")

    def send(self, title: str, body: str, *, level: str = "info") -> None:
        payload = {"ts_utc": utc_now(), "title": title, "body": body, "level": level, "sent": False, "status": self.status}
        if not self.disabled and self._remote is not None and self.remote_available:
            try:
                payload["sent"] = bool(self._remote.send(title, body))
            except Exception as exc:  # pragma: no cover
                payload["error"] = f"{type(exc).__name__}: {exc}"
        with self.events_path.open("a", encoding="utf-8") as f:
            f.write(json.dumps(payload, sort_keys=True) + "\n")


@dataclass
class Context:
    args: argparse.Namespace
    run_root: Path
    start: pd.Timestamp
    end: pd.Timestamp
    notifier: RunNotifier
    stage_sizes: list[dict[str, Any]] = field(default_factory=list)
    stop_after_current_stage: bool = False


@dataclass(frozen=True)
class EventAddress:
    candidate_id: str
    definition_id: str
    hypothesis_id: str
    family: str
    engine_id: str
    symbol: str
    idx: int
    seq: int
    decision_ts: pd.Timestamp
    entry_idx: int
    exit_idx: int
    row_semantics: str
    contract_event_type: str


class FamilyEngine:
    engine_id = "base_engine"
    archetype = "base"
    valid_parameter_dimensions = ("lookback_bars", "hold_bars", "stop_bps", "threshold", "side")

    def contract_event_type(self) -> str:
        return CONTRACT_EVENT_TYPE[self.engine_id]

    def row_semantics(self) -> str:
        return ROW_SEMANTICS[self.contract_event_type()]

    def engine_contract_hash(self) -> str:
        return stable_hash(self.engine_id, self.archetype, self.contract_event_type(), self.row_semantics(), self.valid_parameter_dimensions, n=24)

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        raise NotImplementedError

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        raise NotImplementedError

    def compute_exact_aggregate_metrics(self, bars: pd.DataFrame, funding: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        stats = StreamingAggregate(candidate, self)
        for ev in self._iter_events(bars, funding, candidate):
            stats.add_event(ev)
        return stats.as_candidate_summary()

    def regenerate_materialized_ledger(self, bars: pd.DataFrame, funding: pd.DataFrame, candidate: Mapping[str, Any]) -> pd.DataFrame:
        return pd.DataFrame(list(self._iter_events(bars, funding, candidate)))

    def build_matched_controls(self, events: pd.DataFrame, *, nulls_per_event: int, seed: int) -> tuple[pd.DataFrame, pd.DataFrame]:
        if events.empty:
            return pd.DataFrame(), pd.DataFrame()
        standardized = standardize_event_ledger(events, source_path="materialized_selected", family_hint=str(events["family"].iloc[0]))
        _, controls, summary = build_real_controls(standardized, nulls_per_event=nulls_per_event, seed=seed)
        if not controls.empty:
            controls["control_row_semantics_policy"] = self.row_semantics()
            controls["control_engine_id"] = self.engine_id
        return controls, summary

    def run_family_specific_stress(self, events: pd.DataFrame) -> pd.DataFrame:
        rows: list[dict[str, Any]] = []
        if events.empty:
            return pd.DataFrame(rows)
        vals = pd.to_numeric(events["net_R"], errors="coerce").dropna()
        base = float(vals.sum()) if len(vals) else 0.0
        for bps in [4, 8, 12, 25, 50]:
            rows.append({"stress_name": f"extra_cost_{bps}bps", "engine_id": self.engine_id, "events": len(vals), "net_R_stress": base - len(vals) * (bps / 100.0), "status": "computed_from_materialized"})
        if len(vals) >= 100:
            cutoff_1 = vals.quantile(0.99)
            cutoff_5 = vals.quantile(0.95)
            rows.append({"stress_name": "remove_top_1pct", "engine_id": self.engine_id, "events": int((vals < cutoff_1).sum()), "net_R_stress": float(vals[vals < cutoff_1].sum()), "status": "computed_from_materialized"})
            rows.append({"stress_name": "remove_top_5pct", "engine_id": self.engine_id, "events": int((vals < cutoff_5).sum()), "net_R_stress": float(vals[vals < cutoff_5].sum()), "status": "computed_from_materialized"})
        return pd.DataFrame(rows)

    def _iter_events(self, bars: pd.DataFrame, funding: pd.DataFrame, candidate: Mapping[str, Any]) -> Iterable[dict[str, Any]]:
        for addr in self.enumerate_valid_event_addresses(bars, candidate):
            ev = event_from_address(candidate, bars, funding, addr)
            if ev is not None:
                yield ev

    def _base_mask_inputs(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> tuple[pd.Series, pd.Series, pd.Series, pd.Series, int, float, str]:
        lookback = max(2, int(safe_float(candidate.get("lookback_bars"), 12)))
        threshold = float(safe_float(candidate.get("threshold"), 0.005))
        side = str(candidate.get("side", "long"))
        close = pd.to_numeric(bars["close"], errors="coerce")
        high = pd.to_numeric(bars["high"], errors="coerce")
        low = pd.to_numeric(bars["low"], errors="coerce")
        open_ = pd.to_numeric(bars["open"], errors="coerce")
        return close, high, low, open_, lookback, threshold, side

    def _addresses_from_indices(self, bars: pd.DataFrame, candidate: Mapping[str, Any], idxs: Sequence[int]) -> list[EventAddress]:
        hold = interval_bars_for_candidate(candidate, self.engine_id)
        out: list[EventAddress] = []
        for seq, idx in enumerate(map(int, idxs)):
            entry_idx = idx + 1
            exit_idx = min(len(bars) - 1, entry_idx + hold)
            if entry_idx >= len(bars) or exit_idx <= entry_idx:
                continue
            out.append(EventAddress(
                candidate_id=str(candidate["candidate_id"]),
                definition_id=str(candidate.get("definition_id", candidate["candidate_id"])),
                hypothesis_id=str(candidate.get("hypothesis_id", "")),
                family=str(candidate.get("family", "")),
                engine_id=self.engine_id,
                symbol=str(candidate.get("symbol", "")),
                idx=idx,
                seq=seq,
                decision_ts=pd.Timestamp(bars.iloc[idx]["ts"]),
                entry_idx=entry_idx,
                exit_idx=exit_idx,
                row_semantics=self.row_semantics(),
                contract_event_type=self.contract_event_type(),
            ))
        return out


class ScheduledTsmomEngine(FamilyEngine):
    engine_id = "scheduled_tsmom_engine"
    archetype = "tsmom"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, _, _, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        ret = close / close.shift(lookback) - 1.0
        direction = tsmom_side_direction(side)
        cond = ret > threshold if direction == "long" else ret < -threshold
        interval = interval_bars_for_candidate(candidate, self.engine_id)
        sched = pd.Series(False, index=bars.index)
        start = max(lookback + 1, interval)
        sched.iloc[list(range(start, max(start, len(bars) - 2), interval))] = True
        cond_b = bool_mask(cond)
        return {"raw_condition": cond_b, "scheduled": sched, "entry_mask": (cond_b & sched)}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        idxs = np.flatnonzero(m["entry_mask"].to_numpy())
        return self._addresses_from_indices(bars, candidate, idxs)


class LiquidContinuationBreakoutEngine(FamilyEngine):
    engine_id = "liquid_continuation_breakout_engine"
    archetype = "liquid_continuation"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, _, _, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        ret = close / close.shift(lookback) - 1.0
        roll_high = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).max()
        roll_low = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).min()
        if side == "long":
            raw = (ret > threshold) & (close > roll_high * (1 - threshold))
        else:
            raw = (ret < -threshold) & (close < roll_low * (1 + threshold))
        raw_b = bool_mask(raw)
        transition = raw_b & ~bool_mask(raw_b.shift(1))
        return {"raw_condition": raw_b, "transition": transition, "entry_mask": transition}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        idxs = suppress_reentries(np.flatnonzero(m["entry_mask"].to_numpy()), int(candidate.get("hold_bars", 12)), int(candidate.get("lookback_bars", 12)))
        return self._addresses_from_indices(bars, candidate, idxs)


class PriorHighReclaimEngine(FamilyEngine):
    engine_id = "prior_high_reclaim_engine"
    archetype = "prior_high"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, _, _, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        direction = prior_high_side_direction(side)
        roll_high = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).max()
        roll_low = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).min()
        signal_type = str(candidate.get("signal_type", candidate.get("definition_kind", "prior_high_breakout"))).lower()
        ret = close / close.shift(lookback) - 1.0
        if direction == "long":
            if "breakout" in signal_type and "failed" not in signal_type:
                raw = close > roll_high * (1 + threshold)
            elif "relative_strength" in signal_type or "proximity" in signal_type:
                raw = (close >= roll_high * (1 - threshold)) & (ret > 0)
            elif "retest" in signal_type or "lifecycle" in signal_type:
                breakout = close.shift(3) > roll_high.shift(3) * (1 + threshold)
                retest = close.shift(1) <= roll_high.shift(1) * (1 + threshold)
                raw = bool_mask(breakout) & bool_mask(retest) & (close >= roll_high * (1 - threshold))
            else:
                raw = close >= roll_high * (1 - threshold)
        else:
            if "failed_breakout" in signal_type:
                recent_breakout = (close.shift(1) > roll_high.shift(1) * (1 + threshold)).rolling(max(2, min(lookback, 288)), min_periods=1).max().astype(bool)
                raw = recent_breakout & (close < roll_high * (1 - threshold))
            else:
                raw = close <= roll_low * (1 + threshold)
        raw_b = bool_mask(raw)
        transition = raw_b & ~bool_mask(raw_b.shift(1))
        cadence_value = candidate.get("bar_timeframe", "") or candidate.get("signal_timeframe", "")
        cadence = 288 if str(cadence_value).lower() in {"daily", "1d", "d"} else 48 if str(cadence_value).lower() in {"4h", "completed_4h"} else max(1, int(safe_float(candidate.get("rebalance_bars"), 1)))
        sched = pd.Series(False, index=bars.index)
        start = max(lookback + 1, cadence)
        sched.iloc[list(range(start, max(start, len(bars) - 2), cadence))] = True
        entry = transition & sched
        return {"raw_condition": raw_b, "transition": transition, "scheduled_close": sched, "entry_mask": entry}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        idxs = suppress_reentries(np.flatnonzero(m["entry_mask"].to_numpy()), int(candidate.get("hold_bars", 12)), int(candidate.get("lookback_bars", 12)))
        return self._addresses_from_indices(bars, candidate, idxs)


class RetestReclaimLifecycleEngine(FamilyEngine):
    engine_id = "retest_reclaim_lifecycle_engine"
    archetype = "retest_reclaim"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, high, low, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        roll_high = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).max()
        roll_low = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).min()
        if side == "long":
            breakout = close > roll_high * (1 + threshold)
            retest = low <= roll_high * (1 + threshold) * (1 + threshold)
            reclaim = close > roll_high * (1 - threshold)
            raw = bool_mask(breakout.shift(3)) & bool_mask(retest.shift(1)) & bool_mask(reclaim)
        else:
            breakout = close < roll_low * (1 - threshold)
            retest = high >= roll_low * (1 - threshold) * (1 - threshold)
            reclaim = close < roll_low * (1 + threshold)
            raw = bool_mask(breakout.shift(3)) & bool_mask(retest.shift(1)) & bool_mask(reclaim)
        raw_b = bool_mask(raw)
        transition = raw_b & ~bool_mask(raw_b.shift(1))
        return {"raw_condition": raw_b, "transition": transition, "entry_mask": transition}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        idxs = suppress_reentries(np.flatnonzero(m["entry_mask"].to_numpy()), int(candidate.get("hold_bars", 12)), int(candidate.get("lookback_bars", 12)))
        return self._addresses_from_indices(bars, candidate, idxs)


class CompressionBreakoutEngine(FamilyEngine):
    engine_id = "compression_breakout_engine"
    archetype = "compression_breakout"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, high, low, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        ret = close.pct_change()
        rv = ret.rolling(lookback, min_periods=max(3, lookback // 3)).std()
        rv_ref = rv.shift(max(2, lookback // 2)).rolling(max(3, lookback // 2), min_periods=3).median()
        roll_high = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).max()
        roll_low = close.shift(1).rolling(lookback, min_periods=max(3, lookback // 3)).min()
        comp = rv < rv_ref * 0.8
        if side == "long":
            raw = comp & (close > roll_high * (1 + threshold))
        else:
            raw = comp & (close < roll_low * (1 - threshold))
        raw_b = bool_mask(raw)
        transition = raw_b & ~bool_mask(raw_b.shift(1))
        return {"raw_condition": raw_b, "transition": transition, "entry_mask": transition}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        idxs = suppress_reentries(np.flatnonzero(m["entry_mask"].to_numpy()), int(candidate.get("hold_bars", 12)), int(candidate.get("lookback_bars", 12)))
        return self._addresses_from_indices(bars, candidate, idxs)


class SessionCalendarEngine(FamilyEngine):
    engine_id = "session_calendar_engine"
    archetype = "session_calendar"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, _, _, open_, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        ret = close / close.shift(lookback) - 1.0
        hours = pd.to_datetime(bars["ts"], utc=True).dt.hour
        session = hours.isin([0, 8, 13, 14, 15, 16])
        direction = close > open_ if side == "long" else close < open_
        raw = session & direction & (ret.abs() > threshold / 2)
        raw_b = bool_mask(raw)
        df = pd.DataFrame({"raw": raw_b, "date": pd.to_datetime(bars["ts"], utc=True).dt.strftime("%Y-%m-%d"), "hour": hours})
        entry = pd.Series(False, index=bars.index)
        for _, g in df[df["raw"]].groupby(["date", "hour"], sort=False):
            if len(g):
                entry.iloc[int(g.index[0])] = True
        return {"raw_condition": raw_b, "session": session, "entry_mask": entry}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        return self._addresses_from_indices(bars, candidate, np.flatnonzero(m["entry_mask"].to_numpy()))


class FundingCrowdingEngine(FamilyEngine):
    engine_id = "funding_crowding_engine"
    archetype = "funding_crowding"

    def build_candidate_masks(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> dict[str, Any]:
        close, _, _, _, lookback, threshold, side = self._base_mask_inputs(bars, candidate)
        ret = close / close.shift(lookback) - 1.0
        raw = ret > threshold if side == "long" else ret < -threshold
        ts = pd.to_datetime(bars["ts"], utc=True)
        bucket = (ts.astype("int64") // (8 * 3600 * 10**9)).astype("int64")
        raw_b = bool_mask(raw)
        df = pd.DataFrame({"raw": raw_b, "bucket": bucket})
        entry = pd.Series(False, index=bars.index)
        for _, g in df[df["raw"]].groupby("bucket", sort=False):
            if len(g):
                entry.iloc[int(g.index[0])] = True
        return {"raw_condition": raw_b, "funding_bucket": bucket, "entry_mask": entry}

    def enumerate_valid_event_addresses(self, bars: pd.DataFrame, candidate: Mapping[str, Any]) -> list[EventAddress]:
        m = self.build_candidate_masks(bars, candidate)
        return self._addresses_from_indices(bars, candidate, np.flatnonzero(m["entry_mask"].to_numpy()))


ENGINES: dict[str, FamilyEngine] = {
    e.engine_id: e for e in [
        ScheduledTsmomEngine(),
        LiquidContinuationBreakoutEngine(),
        PriorHighReclaimEngine(),
        RetestReclaimLifecycleEngine(),
        CompressionBreakoutEngine(),
        SessionCalendarEngine(),
        FundingCrowdingEngine(),
    ]
}


def engine_for_candidate(candidate: Mapping[str, Any]) -> FamilyEngine:
    engine_id = str(candidate.get("family_engine_id") or ARCHETYPE_ENGINE_ID.get(str(candidate.get("archetype", "")), "liquid_continuation_breakout_engine"))
    if engine_id not in ENGINES:
        raise KeyError(f"unknown family engine: {engine_id}")
    return ENGINES[engine_id]


def suppress_reentries(indices: Sequence[int], hold_bars: int, lookback_bars: int) -> np.ndarray:
    kept: list[int] = []
    last_exit = -10**12
    cooldown = max(1, min(max(1, int(hold_bars)), max(1, int(lookback_bars))))
    for idx in map(int, indices):
        if idx <= last_exit + cooldown:
            continue
        kept.append(idx)
        last_exit = idx + max(1, int(hold_bars))
    return np.array(kept, dtype=int)


def interval_bars_for_candidate(candidate: Mapping[str, Any], engine_id: str) -> int:
    hold = max(1, int(safe_float(candidate.get("hold_bars"), 12)))
    if engine_id == "scheduled_tsmom_engine":
        return max(48, hold)
    if engine_id == "funding_crowding_engine":
        return max(96, hold)
    if engine_id == "session_calendar_engine":
        return max(12, hold)
    return hold


class StreamingAggregate:
    def __init__(self, candidate: Mapping[str, Any], engine: FamilyEngine):
        self.candidate = candidate
        self.engine = engine
        self.count = 0
        self.net = 0.0
        self.gross = 0.0
        self.fees = 0.0
        self.funding = 0.0
        self.slippage = 0.0
        self.raw_net = 0.0
        self.raw_gross = 0.0
        self.raw_fees = 0.0
        self.raw_funding = 0.0
        self.raw_slippage = 0.0
        self.values: list[float] = []
        self.symbols: set[str] = set()
        self.months: set[str] = set()
        self.regimes: set[str] = set()
        self.funding_proxy_used = False
        self.mark_proxy_used = False
        self.funding_exact_all = True
        self.mark_available_all = True
        self.first_ts: str = ""
        self.last_ts: str = ""

    def add_event(self, ev: Mapping[str, Any]) -> None:
        net = safe_float(ev.get("net_R"), 0.0)
        self.count += 1
        self.net += net
        self.gross += safe_float(ev.get("gross_R"), 0.0)
        self.fees += safe_float(ev.get("fees_R"), 0.0)
        self.funding += safe_float(ev.get("funding_R"), 0.0)
        self.slippage += safe_float(ev.get("slippage_R"), 0.0)
        self.raw_net += safe_float(ev.get("raw_net_R", ev.get("net_R")), 0.0)
        self.raw_gross += safe_float(ev.get("raw_gross_R", ev.get("gross_R")), 0.0)
        self.raw_fees += safe_float(ev.get("raw_fee_R", ev.get("fees_R")), 0.0)
        self.raw_funding += safe_float(ev.get("raw_funding_R", ev.get("funding_R")), 0.0)
        self.raw_slippage += safe_float(ev.get("raw_slippage_R", ev.get("slippage_R", 0.0)), 0.0)
        self.values.append(net)
        self.symbols.add(str(ev.get("symbol", "")))
        ts = pd.Timestamp(ev.get("decision_ts"))
        mo = ts.strftime("%Y-%m") if pd.notna(ts) else ""
        self.months.add(mo)
        self.regimes.add(str(ev.get("regime_label", "unknown")))
        self.funding_proxy_used = self.funding_proxy_used or bool(ev.get("funding_proxy_used", False))
        self.mark_proxy_used = self.mark_proxy_used or bool(ev.get("mark_proxy_used", False))
        self.funding_exact_all = self.funding_exact_all and bool(ev.get("funding_exact", False))
        self.mark_available_all = self.mark_available_all and bool(ev.get("mark_available", False))
        ts_s = str(ev.get("decision_ts"))
        if not self.first_ts or ts_s < self.first_ts:
            self.first_ts = ts_s
        if not self.last_ts or ts_s > self.last_ts:
            self.last_ts = ts_s

    def as_candidate_summary(self) -> dict[str, Any]:
        vals = pd.Series(self.values, dtype=float)
        row_sem = self.engine.row_semantics()
        closed_interval = row_sem in {"trade_episode", "position_interval"}
        trade_metric_applicability = "applicable" if closed_interval else "not_applicable"
        data_caps: list[str] = ["kraken_survivorship_lifecycle_cap"]
        if self.funding_proxy_used:
            data_caps.append("funding_proxy_cap")
        if self.mark_proxy_used:
            data_caps.append("mark_proxy_cap")
        cid = definition_identity(self.candidate)
        csid = symbol_identity(self.candidate)
        pjson = parameter_vector_json(self.candidate, self.engine)
        phash = parameter_vector_hash(self.candidate, self.engine)
        out = {
            "candidate_id": cid,
            "candidate_definition_id": cid,
            "candidate_symbol_id": csid,
            "definition_id": self.candidate.get("definition_id", self.candidate.get("candidate_id")),
            "hypothesis_id": self.candidate.get("hypothesis_id", ""),
            "family": self.candidate.get("family", ""),
            "family_engine_id": self.engine.engine_id,
            "engine_contract_hash": self.engine.engine_contract_hash(),
            "symbol": self.candidate.get("symbol", ""),
            "row_semantics": row_sem,
            "contract_event_type": self.engine.contract_event_type(),
            "event_semantics_version": EVENT_SEMANTICS_VERSION,
            "parameter_vector_hash": phash,
            "parameter_vector_json": pjson,
            "parameter_manifest_pointer": self.candidate.get("parameter_manifest_pointer", ""),
            "side": self.candidate.get("side", ""),
            "lookback_bars": self.candidate.get("lookback_bars", ""),
            "hold_bars": self.candidate.get("hold_bars", ""),
            "stop_bps": self.candidate.get("stop_bps", ""),
            "threshold": self.candidate.get("threshold", ""),
            "entry_template": self.candidate.get("entry_template", ""),
            "exit_template": self.candidate.get("exit_template", ""),
            "stop_template": self.candidate.get("stop_template", ""),
            "regime_activation": self.candidate.get("regime_activation", ""),
            "symbol_universe_hash": self.candidate.get("symbol_universe_hash", ""),
            "trade_metric_applicability": trade_metric_applicability,
            "events": int(self.count),
            "event_count": int(self.count),
            "net_R": float(self.net),
            "gross_R": float(self.gross),
            "fees_R": float(self.fees),
            "funding_R": float(self.funding),
            "slippage_R": float(self.slippage),
            "raw_net_R": float(self.raw_net),
            "raw_gross_R": float(self.raw_gross),
            "raw_fee_R": float(self.raw_fees),
            "raw_funding_R": float(self.raw_funding),
            "raw_slippage_R": float(self.raw_slippage),
            "scaled_net_R": float(self.net),
            "scaled_gross_R": float(self.gross),
            "scaled_fee_R": float(self.fees),
            "scaled_funding_R": float(self.funding),
            "scaled_slippage_R": float(self.slippage),
            "PF": pf(vals) if row_sem == "trade_episode" else (pf(vals) if row_sem == "position_interval" and self.count else np.nan),
            "win_rate": float((vals > 0).mean()) if closed_interval and self.count else np.nan,
            "avg_R": float(vals.mean()) if self.count else np.nan,
            "median_R": float(vals.median()) if self.count else np.nan,
            "trimmed_mean_R": trimmed_mean(vals),
            "max_dd_R": max_dd(vals) if closed_interval else np.nan,
            "active_symbols": int(len(self.symbols)),
            "active_months": int(len([m for m in self.months if m])),
            "active_regimes": int(len(self.regimes)),
            "first_decision_ts": self.first_ts,
            "last_decision_ts": self.last_ts,
            "funding_exact": bool(self.funding_exact_all),
            "funding_proxy_used": bool(self.funding_proxy_used),
            "mark_available": bool(self.mark_available_all),
            "mark_proxy_used": bool(self.mark_proxy_used),
            "funding_cap": "funding_proxy_cap" if self.funding_proxy_used else "none",
            "mark_cap": "mark_proxy_cap" if self.mark_proxy_used else "none",
            "survivorship_cap": "kraken_survivorship_lifecycle_cap",
            "data_cap": ";".join(sorted(set(data_caps))),
            "coverage_ratio": 1.0,
            "event_sampling_used": False,
            "aggregate_metric_basis": "exact_from_all_events",
            "evidence_level": "level_2_path_or_interval_support_only" if row_sem == "position_interval" else "level_1_generator_support",
            "candidate_status": "aggregate_screen_only_current_translation_weak",
        }
        for field in TSMOM_ACTIVE_PARAMETER_FIELDS:
            out.setdefault(field, self.candidate.get(field, ""))
        return out


def trimmed_mean(vals: pd.Series) -> float:
    v = pd.to_numeric(vals, errors="coerce").dropna().sort_values()
    n = len(v)
    if n == 0:
        return float("nan")
    if n < 10:
        return float(v.mean())
    lo = int(math.floor(n * 0.1))
    hi = int(math.ceil(n * 0.9))
    return float(v.iloc[lo:hi].mean())


def compute_round_trip_fee_R(
    entry_price: float,
    exit_price: float,
    risk_price: float,
    *,
    qty: float = 1.0,
    contract_size_or_multiplier: float = 1.0,
    entry_fee_bps_per_side: float = 10.0,
    exit_fee_bps_per_side: float | None = None,
) -> dict[str, float]:
    """Return explicit entry+exit notional fee components normalized by R risk."""
    exit_bps = entry_fee_bps_per_side if exit_fee_bps_per_side is None else exit_fee_bps_per_side
    notional_multiplier = abs(float(qty)) * abs(float(contract_size_or_multiplier))
    risk_usd = abs(float(risk_price)) * notional_multiplier
    if not math.isfinite(risk_usd) or risk_usd <= 0:
        return {"entry_fee_R": float("nan"), "exit_fee_R": float("nan"), "fee_R": float("nan"), "risk_usd": risk_usd}
    entry_notional_usd = abs(float(entry_price)) * notional_multiplier
    exit_notional_usd = abs(float(exit_price)) * notional_multiplier
    entry_fee_usd = entry_notional_usd * float(entry_fee_bps_per_side) / 10000.0
    exit_fee_usd = exit_notional_usd * float(exit_bps) / 10000.0
    return {
        "entry_notional_usd": entry_notional_usd,
        "exit_notional_usd": exit_notional_usd,
        "entry_fee_usd": entry_fee_usd,
        "exit_fee_usd": exit_fee_usd,
        "entry_fee_R": -entry_fee_usd / risk_usd,
        "exit_fee_R": -exit_fee_usd / risk_usd,
        "fee_R": -(entry_fee_usd + exit_fee_usd) / risk_usd,
        "risk_usd": risk_usd,
    }


def infer_funding_cadence_hours(funding: pd.DataFrame) -> int:
    if funding.empty or "timestamp" not in funding.columns:
        return DEFAULT_FUNDING_CADENCE_HOURS
    ts = pd.to_datetime(funding["timestamp"], utc=True, errors="coerce").dropna().sort_values()
    if len(ts) < 2:
        return DEFAULT_FUNDING_CADENCE_HOURS
    diffs = ts.diff().dropna().dt.total_seconds() / 3600.0
    if diffs.empty:
        return DEFAULT_FUNDING_CADENCE_HOURS
    cadence = int(round(float(diffs.median())))
    return cadence if cadence > 0 else DEFAULT_FUNDING_CADENCE_HOURS


def proxy_funding_boundary_count(entry_ts: pd.Timestamp, exit_ts: pd.Timestamp, cadence_hours: int = DEFAULT_FUNDING_CADENCE_HOURS) -> int:
    if pd.isna(entry_ts) or pd.isna(exit_ts) or exit_ts <= entry_ts or cadence_hours <= 0:
        return 0
    entry = pd.Timestamp(entry_ts).tz_convert("UTC") if pd.Timestamp(entry_ts).tzinfo else pd.Timestamp(entry_ts, tz="UTC")
    exit_ = pd.Timestamp(exit_ts).tz_convert("UTC") if pd.Timestamp(exit_ts).tzinfo else pd.Timestamp(exit_ts, tz="UTC")
    cadence_ns = int(cadence_hours * 3600 * 1_000_000_000)
    entry_bucket = int(entry.value // cadence_ns)
    exit_bucket = int(exit_.value // cadence_ns)
    # Settlement boundaries are counted only when boundary_ts is > entry_ts and <= exit_ts.
    return max(0, exit_bucket - entry_bucket)


def funding_components_for_event(
    funding: pd.DataFrame,
    entry_ts: pd.Timestamp,
    exit_ts: pd.Timestamp,
    *,
    side: str,
    entry_price: float,
    risk_price: float,
) -> dict[str, Any]:
    fwin = funding_between(funding, entry_ts, exit_ts)
    cadence_hours = infer_funding_cadence_hours(funding)
    if fwin.empty:
        proxy_count = proxy_funding_boundary_count(entry_ts, exit_ts, cadence_hours)
        if proxy_count == 0:
            return {
                "funding_exact_R": 0.0,
                "funding_proxy_R": 0.0,
                "adverse_missing_funding_proxy_R": 0.0,
                "funding_R_used_for_selection": 0.0,
                "funding_R": 0.0,
                "exact_funding_rate": 0.0,
                "funding_exact": True,
                "funding_proxy_used": False,
                "funding_unavailable": False,
                "funding_boundary_crossed": False,
                "funding_boundary_count_exact": 0,
                "funding_boundary_count_proxy": 0,
                "funding_schedule_source": "no_funding_boundary_crossed",
                "funding_label_cap_reason": "",
                "funding_base_mode": "no_funding_boundary_crossed",
            }
        proxy_R = -0.05 * proxy_count
        return {
            "funding_exact_R": float("nan"),
            "funding_proxy_R": proxy_R,
            "adverse_missing_funding_proxy_R": proxy_R,
            "funding_R_used_for_selection": 0.0,
            "funding_R": 0.0,
            "exact_funding_rate": float("nan"),
            "funding_exact": False,
            "funding_proxy_used": True,
            "funding_unavailable": True,
            "funding_boundary_crossed": True,
            "funding_boundary_count_exact": 0,
            "funding_boundary_count_proxy": int(proxy_count),
            "funding_schedule_source": f"proxy_{cadence_hours}h_utc_boundaries_no_exact_rows",
            "funding_label_cap_reason": "funding_proxy_selection_cap;adverse_missing_funding_proxy_stress_only",
            "funding_base_mode": "gross_minus_fees_missing_exact_funding_not_charged",
        }
    rate_source = "relativeFundingRate" if "relativeFundingRate" in fwin.columns else "fundingRate"
    rates = pd.to_numeric(fwin.get(rate_source, pd.Series(dtype=float)), errors="coerce").fillna(0.0)
    sign = -1.0 if side == "long" else 1.0
    funding_R = float(sign * rates.sum() * entry_price / risk_price)
    return {
        "funding_exact_R": funding_R,
        "funding_proxy_R": 0.0,
        "adverse_missing_funding_proxy_R": 0.0,
        "funding_R_used_for_selection": funding_R,
        "funding_R": funding_R,
        "exact_funding_rate": float(rates.mean()) if len(rates) else 0.0,
        "funding_exact": True,
        "funding_proxy_used": False,
        "funding_unavailable": False,
        "funding_boundary_crossed": bool(len(rates)),
        "funding_boundary_count_exact": int(len(rates)),
        "funding_boundary_count_proxy": 0,
        "funding_schedule_source": "kraken_exact_funding_rows",
        "funding_rate_source": rate_source,
        "funding_label_cap_reason": "",
        "funding_base_mode": "exact_funding",
    }


def effective_interval_end_ts(entry_ts: pd.Timestamp, exit_ts: pd.Timestamp, *, same_bar_adverse_stop: bool, bar_minutes: int = 5) -> pd.Timestamp:
    """Return the end of the bar interval used for purge/funding when an adverse stop occurs in the entry bar."""
    entry = pd.Timestamp(entry_ts)
    exit_ = pd.Timestamp(exit_ts)
    if same_bar_adverse_stop and pd.notna(entry) and pd.notna(exit_) and exit_ <= entry:
        return exit_ + pd.Timedelta(minutes=bar_minutes)
    return exit_


def interval_end_series(frame: pd.DataFrame, fallback_start: pd.Series | None = None) -> pd.Series:
    for col in ["effective_exit_ts_for_purge", "exit_interval_end_ts", "interval_end_ts", "candidate_window_end", "exit_ts"]:
        if col in frame.columns:
            return pd.to_datetime(frame[col], utc=True, errors="coerce")
    if fallback_start is not None:
        return fallback_start
    return pd.Series(pd.NaT, index=frame.index)


_PARENT_GATE_CACHE: dict[tuple[str, str, str, str, str], pd.DataFrame] = {}
_PRIOR_HIGH_VWAP_CACHE: dict[tuple[int, int, str, str, str], pd.DataFrame] = {}
_FIND_SYMBOL_FILES_CACHE: dict[tuple[str, str], tuple[Path, ...]] = {}
_PIT_LIQUIDITY_RANKING_CACHE: dict[tuple[str, ...], pd.DataFrame] = {}
_PIT_LIQUIDITY_CHUNK_META_CACHE: dict[tuple[str, str], dict[str, dict[str, Any]]] = {}
_PIT_LIFECYCLE_META_CACHE: dict[str, dict[str, dict[str, Any]]] = {}
_PIT_POLICY_SYMBOLS_CACHE: dict[tuple[str, str, str, str, str, str], tuple[str, ...]] = {}
_RANK_TOP_N_DECISION_CACHE: dict[tuple[str, str, str, str, str, int, int, str], tuple[str, ...]] = {}
_RANK_SYMBOL_BARS_CACHE: dict[tuple[str, str, str, str], pd.DataFrame] = {}
_PANEL_MANIFEST_CACHE: dict[str, pd.DataFrame] = {}


class MemoryGuardStop(SystemExit):
    pass


def current_rss_bytes() -> int:
    try:
        psutil = __import__("psutil")
        return int(psutil.Process(os.getpid()).memory_info().rss)
    except Exception:
        try:
            for line in Path("/proc/self/status").read_text(encoding="utf-8").splitlines():
                if line.startswith("VmRSS:"):
                    return int(line.split()[1]) * 1024
        except Exception:
            return 0
    return 0


def system_memory_bytes() -> int:
    try:
        psutil = __import__("psutil")
        return int(psutil.virtual_memory().total)
    except Exception:
        try:
            for line in Path("/proc/meminfo").read_text(encoding="utf-8").splitlines():
                if line.startswith("MemTotal:"):
                    return int(line.split()[1]) * 1024
        except Exception:
            pass
    try:
        pages = os.sysconf("SC_PHYS_PAGES")
        page_size = os.sysconf("SC_PAGE_SIZE")
        return int(pages * page_size)
    except Exception:
        return 0


def memory_soft_limit_bytes(ctx: Context) -> int:
    configured_gb = safe_float(getattr(ctx.args, "memory_soft_limit_gb", 0.0), 0.0)
    if configured_gb > 0:
        return int(configured_gb * 1024 ** 3)
    total = system_memory_bytes()
    default = 10 * 1024 ** 3
    return int(min(default, total * 0.70)) if total > 0 else default


def cache_size_snapshot() -> dict[str, int]:
    return {
        "rank_symbol_bars_cache_entries": len(_RANK_SYMBOL_BARS_CACHE),
        "rank_top_n_decision_cache_entries": len(_RANK_TOP_N_DECISION_CACHE),
        "pit_liquidity_ranking_cache_entries": len(_PIT_LIQUIDITY_RANKING_CACHE),
        "pit_liquidity_chunk_meta_cache_entries": len(_PIT_LIQUIDITY_CHUNK_META_CACHE),
        "pit_lifecycle_meta_cache_entries": len(_PIT_LIFECYCLE_META_CACHE),
        "pit_policy_symbols_cache_entries": len(_PIT_POLICY_SYMBOLS_CACHE),
        "panel_manifest_cache_entries": len(_PANEL_MANIFEST_CACHE),
        "parent_gate_cache_entries": len(_PARENT_GATE_CACHE),
    }


def clear_aggregate_caches(ctx: Context | None = None, *, reason: str = "batch_complete", scope: str = "", clear_pit_policy: bool = True) -> None:
    before = cache_size_snapshot()
    _RANK_SYMBOL_BARS_CACHE.clear()
    _RANK_TOP_N_DECISION_CACHE.clear()
    if clear_pit_policy:
        _PIT_LIQUIDITY_RANKING_CACHE.clear()
        _PIT_LIQUIDITY_CHUNK_META_CACHE.clear()
        _PIT_LIFECYCLE_META_CACHE.clear()
        _PIT_POLICY_SYMBOLS_CACHE.clear()
    gc.collect()
    after = cache_size_snapshot()
    if ctx is not None:
        row = {
            "ts_utc": utc_now(),
            "reason": reason,
            "scope": scope,
            "rss_bytes": current_rss_bytes(),
            **{f"before_{k}": v for k, v in before.items()},
            **{f"after_{k}": v for k, v in after.items()},
        }
        append_csv(ctx.run_root / "performance/cache_lifecycle_audit.csv", [row])


def record_memory_usage(ctx: Context, *, stage: str, processed: int, total: int, extra: Mapping[str, Any] | None = None) -> dict[str, Any]:
    rss = current_rss_bytes()
    limit = memory_soft_limit_bytes(ctx)
    total_mem = system_memory_bytes()
    row = {
        "ts_utc": utc_now(),
        "stage": stage,
        "processed_candidate_symbol_rows": int(processed),
        "total_candidate_symbol_rows": int(total),
        "rss_bytes": int(rss),
        "rss_gib": rss / 1024 ** 3,
        "soft_limit_bytes": int(limit),
        "soft_limit_gib": limit / 1024 ** 3,
        "system_memory_bytes": int(total_mem),
        "rss_pct_system": (rss / total_mem) if total_mem else np.nan,
    }
    if extra:
        row.update(dict(extra))
    append_csv(ctx.run_root / "resources/memory_usage_timeseries.csv", [row])
    return row


def memory_guard_check(ctx: Context, *, stage: str, processed: int, total: int, pending_candidates: pd.DataFrame | None = None) -> None:
    row = record_memory_usage(ctx, stage=stage, processed=processed, total=total)
    if int(row["rss_bytes"]) <= int(row["soft_limit_bytes"]):
        return
    pending_count = int(len(pending_candidates)) if pending_candidates is not None else max(0, int(total) - int(processed))
    if pending_candidates is not None and not pending_candidates.empty:
        pending = pending_candidates.copy()
        pending["candidate_status"] = "pending_compute_interrupted"
        write_csv(ctx.run_root / "interruptions/pending_compute_interrupted.csv", pending)
    report = (
        "# Memory Guard Stop\n\n"
        f"Status: `interrupted_resource_guard`\n"
        f"Stage: `{stage}`\n"
        f"Processed candidate-symbol rows: `{processed}` / `{total}`\n"
        f"Pending candidate-symbol rows: `{pending_count}`\n"
        f"RSS GiB: `{row['rss_gib']:.3f}`\n"
        f"Soft limit GiB: `{row['soft_limit_gib']:.3f}`\n\n"
        "The process stopped cleanly before kernel OOM. Unprocessed definitions are marked `pending_compute_interrupted`.\n"
    )
    write_text(ctx.run_root / "interruptions/memory_guard_stop_report.md", report)
    write_json(ctx.run_root / "decision_summary.json", {
        "run_root": str(ctx.run_root),
        "status": "interrupted_resource_guard",
        "stage": stage,
        "processed_candidate_symbol_rows": int(processed),
        "total_candidate_symbol_rows": int(total),
        "pending_compute_interrupted": pending_count,
        "rss_bytes": int(row["rss_bytes"]),
        "soft_limit_bytes": int(row["soft_limit_bytes"]),
        "next_operator_decision": "repair_memory_or_reduce_batch_next",
        "ts_utc": utc_now(),
    })
    write_status(ctx, "interrupted_resource_guard", stage)
    ctx.notifier.send("Kraken sweep memory guard stop", f"{stage}: RSS {row['rss_gib']:.2f} GiB exceeded soft limit {row['soft_limit_gib']:.2f} GiB", level="warning")
    raise MemoryGuardStop(0)


def local_data_paths_from_root(root_value: Any) -> dict[str, Path]:
    root = resolve_path(str(root_value or DEFAULT_KRAKEN_DATA_ROOT))
    return {
        "root": root,
        "trade_5m": root / "parquet/historical_trade_candles_5m",
        "mark_5m": root / "parquet/historical_mark_candles_5m",
        "alt_trade": root / "parquet/trade",
        "alt_mark": root / "parquet/mark",
        "funding": root / "parquet/funding",
        "instruments": root / "parquet/instruments",
        "manifests": root / "manifests",
        "qc": root / "qc",
    }


def ts_utc(ts: Any) -> pd.Timestamp:
    out = pd.Timestamp(ts)
    return out.tz_convert("UTC") if out.tzinfo else pd.Timestamp(out, tz="UTC")


def load_parent_gate_frame(candidate: Mapping[str, Any], symbol: str, start: pd.Timestamp, end: pd.Timestamp) -> pd.DataFrame:
    root = str(candidate.get("kraken_data_root", DEFAULT_KRAKEN_DATA_ROOT))
    key = (root, symbol, str(start), str(end), "completed_4h_v1")
    cached = _PARENT_GATE_CACHE.get(key)
    if cached is not None:
        return cached
    paths = local_data_paths_from_root(root)
    bars = load_symbol_bars(paths, symbol, start - pd.Timedelta(days=100), end)
    if bars.empty:
        frame = pd.DataFrame(columns=["source_ts", "close", "sma_40d", "ret_20d", "up", "down"])
        _PARENT_GATE_CACHE[key] = frame
        return frame
    work = bars[["ts", "close"]].copy()
    work["known_ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce") + pd.Timedelta(minutes=5)
    work = work.dropna(subset=["known_ts", "close"]).set_index("known_ts").sort_index()
    closes = pd.to_numeric(work["close"], errors="coerce").resample("4h", label="right", closed="right").last().dropna()
    frame = pd.DataFrame({"close": closes})
    frame["source_ts"] = frame.index
    frame["sma_40d"] = frame["close"].rolling(40 * 6, min_periods=40 * 6).mean()
    frame["ret_20d"] = frame["close"] / frame["close"].shift(20 * 6) - 1.0
    frame["up"] = (frame["close"] > frame["sma_40d"]) & (frame["ret_20d"] >= 0)
    frame["down"] = (frame["close"] < frame["sma_40d"]) | (frame["ret_20d"] < 0)
    _PARENT_GATE_CACHE[key] = frame
    return frame


def latest_parent_gate_row(frame: pd.DataFrame, decision_ts: pd.Timestamp) -> pd.Series | None:
    if frame.empty or "source_ts" not in frame.columns:
        return None
    decision = ts_utc(decision_ts)
    source = frame["source_ts"]
    if pd.api.types.is_datetime64_any_dtype(source):
        source_ts = source
    else:
        source_ts = pd.to_datetime(source, utc=True, errors="coerce")
    eligible = frame[source_ts <= decision]
    if eligible.empty:
        return None
    return eligible.iloc[-1]


def evaluate_parent_regime_gate(candidate: Mapping[str, Any], bars: pd.DataFrame, decision_ts: pd.Timestamp) -> dict[str, Any]:
    gate = str(candidate.get("parent_regime_gate", "") or "").strip()
    if not gate or gate == "all_context_diagnostic":
        return {"allowed": True, "cap": "", "skip_reason": "", "btc_ref_ts": "", "eth_ref_ts": "", "feature_source_ts": str(decision_ts), "btc_trend_value": "", "eth_trend_value": "", "missing_action": "", "source_ts_lte_decision": True, "status": "no_parent_gate"}
    # Full-window candidates share one parent-state table. Deriving this range
    # from each traded symbol's lifecycle fragments the cache and repeatedly
    # reloads BTC/ETH history without changing point-in-time gate semantics.
    configured_start = pd.to_datetime(candidate.get("run_start_ts"), utc=True, errors="coerce")
    configured_end = pd.to_datetime(candidate.get("run_end_ts"), utc=True, errors="coerce")
    bars_start = pd.to_datetime(bars["ts"], utc=True, errors="coerce").min() if "ts" in bars.columns and not bars.empty else pd.NaT
    bars_end = pd.to_datetime(bars["ts"], utc=True, errors="coerce").max() if "ts" in bars.columns and not bars.empty else pd.NaT
    start = configured_start if pd.notna(configured_start) else (bars_start if pd.notna(bars_start) else ts_utc(decision_ts) - pd.Timedelta(days=120))
    end = configured_end if pd.notna(configured_end) else (bars_end if pd.notna(bars_end) else ts_utc(decision_ts))
    btc = latest_parent_gate_row(load_parent_gate_frame(candidate, "PF_XBTUSD", start, end), decision_ts)
    eth = latest_parent_gate_row(load_parent_gate_frame(candidate, "PF_ETHUSD", start, end), decision_ts)
    if btc is None or eth is None or pd.isna(btc.get("sma_40d")) or pd.isna(eth.get("sma_40d")) or pd.isna(btc.get("ret_20d")) or pd.isna(eth.get("ret_20d")):
        return {"allowed": False, "cap": "parent_gate_warmup_skip", "skip_reason": "parent_gate_warmup_skip", "btc_ref_ts": "" if btc is None else str(btc.get("source_ts")), "eth_ref_ts": "" if eth is None else str(eth.get("source_ts")), "feature_source_ts": str(decision_ts), "btc_trend_value": "" if btc is None else safe_float(btc.get("ret_20d"), np.nan), "eth_trend_value": "" if eth is None else safe_float(eth.get("ret_20d"), np.nan), "missing_action": "parent_gate_warmup_skip", "source_ts_lte_decision": True, "status": "warmup_skip"}
    btc_up = bool(btc.get("up", False))
    eth_up = bool(eth.get("up", False))
    btc_down = bool(btc.get("down", False))
    eth_down = bool(eth.get("down", False))
    btc_ret = safe_float(btc.get("ret_20d"), np.nan)
    eth_ret = safe_float(eth.get("ret_20d"), np.nan)
    if gate == "btc_eth_trend_up":
        allowed = btc_up and eth_up
    elif gate == "btc_eth_trend_up_or_neutral":
        allowed = (btc_up or eth_up) and not (btc_ret < -0.10 or eth_ret < -0.10)
    elif gate == "btc_eth_trend_down_diagnostic":
        allowed = btc_down and eth_down
    else:
        feature_source_ts = max(ts_utc(btc.get("source_ts")), ts_utc(eth.get("source_ts")))
        return {"allowed": False, "cap": "unknown_parent_gate_skip", "skip_reason": f"unknown_parent_gate:{gate}", "btc_ref_ts": str(btc.get("source_ts")), "eth_ref_ts": str(eth.get("source_ts")), "feature_source_ts": str(feature_source_ts), "btc_trend_value": btc_ret, "eth_trend_value": eth_ret, "missing_action": "unknown_parent_gate_skip", "source_ts_lte_decision": bool(feature_source_ts <= ts_utc(decision_ts)), "status": "unknown_gate"}
    feature_source_ts = max(ts_utc(btc.get("source_ts")), ts_utc(eth.get("source_ts")))
    return {
        "allowed": bool(allowed),
        "cap": "" if allowed else "parent_gate_filter_skip",
        "skip_reason": "" if allowed else "parent_gate_filter_skip",
        "btc_ref_ts": str(btc.get("source_ts")),
        "eth_ref_ts": str(eth.get("source_ts")),
        "feature_source_ts": str(feature_source_ts),
        "btc_trend_value": btc_ret,
        "eth_trend_value": eth_ret,
        "missing_action": "",
        "source_ts_lte_decision": bool(feature_source_ts <= ts_utc(decision_ts)),
        "status": "pass" if allowed else "filtered",
    }


def percentile_rank(values: pd.Series, value: float) -> float:
    clean = pd.to_numeric(values, errors="coerce").dropna()
    if clean.empty or not math.isfinite(value):
        return float("nan")
    return float((clean <= value).mean())


def evaluate_funding_gate(candidate: Mapping[str, Any], funding: pd.DataFrame, decision_ts: pd.Timestamp) -> dict[str, Any]:
    gate = str(candidate.get("funding_gate", "") or "").strip()
    if not gate or gate in {"all_context_diagnostic", "no_funding_gate_diagnostic_cap"}:
        cap = "no_funding_gate_diagnostic_cap" if gate == "no_funding_gate_diagnostic_cap" else ""
        return {"allowed": True, "cap": cap, "skip_reason": "", "status": "no_gate_or_diagnostic", "funding_percentile": "", "latest_funding_rate": "", "feature_source_ts": str(decision_ts), "funding_exact_available": False, "missing_action": "", "funding_gate_pass": True}
    exact = not funding.empty and {"timestamp", "fundingRate"}.issubset(funding.columns)
    if exact:
        f = funding.copy()
        f["timestamp"] = pd.to_datetime(f["timestamp"], utc=True, errors="coerce")
        rate_col = "relativeFundingRate" if "relativeFundingRate" in f.columns else "fundingRate"
        f[rate_col] = pd.to_numeric(f[rate_col], errors="coerce")
        decision = ts_utc(decision_ts)
        trail = f[(f["timestamp"] < decision) & (f["timestamp"] >= decision - pd.Timedelta(days=90))].dropna(subset=[rate_col])
    else:
        rate_col = "fundingRate"
        trail = pd.DataFrame()
    insufficient = len(trail) < 30
    if trail.empty or insufficient:
        if gate == "funding_extreme_required":
            return {"allowed": False, "cap": "funding_extreme_unavailable_skip", "skip_reason": "funding_extreme_unavailable_skip", "status": "missing_exact_skip", "funding_percentile": "", "latest_funding_rate": "", "feature_source_ts": str(decision_ts), "funding_exact_available": False, "missing_action": "funding_extreme_unavailable_skip", "funding_gate_pass": False}
        cap = "funding_gate_unavailable_cap" if gate in {"exclude_top_decile_positive_funding", "exclude_top_20pct_positive_funding"} else "funding_aware_cap_missing_or_insufficient"
        return {"allowed": True, "cap": cap, "skip_reason": "", "status": "missing_exact_allowed_capped", "funding_percentile": "", "latest_funding_rate": "", "feature_source_ts": str(decision_ts), "funding_exact_available": False, "missing_action": cap, "funding_gate_pass": True}
    latest = safe_float(trail.sort_values("timestamp")[rate_col].iloc[-1], np.nan)
    pct = percentile_rank(trail[rate_col], latest)
    feature_source_ts = str(trail.sort_values("timestamp")["timestamp"].iloc[-1])
    if gate == "exclude_top_decile_positive_funding":
        skip = latest > 0 and pct >= 0.90
        return {"allowed": not skip, "cap": "top_decile_positive_funding_skip" if skip else "", "skip_reason": "top_decile_positive_funding_skip" if skip else "", "status": "filtered" if skip else "pass", "funding_percentile": pct, "latest_funding_rate": latest, "feature_source_ts": feature_source_ts, "funding_exact_available": True, "missing_action": "", "funding_gate_pass": not skip}
    if gate == "exclude_top_20pct_positive_funding":
        skip = latest > 0 and pct >= 0.80
        return {"allowed": not skip, "cap": "top_20pct_positive_funding_skip" if skip else "", "skip_reason": "top_20pct_positive_funding_skip" if skip else "", "status": "filtered" if skip else "pass", "funding_percentile": pct, "latest_funding_rate": latest, "feature_source_ts": feature_source_ts, "funding_exact_available": True, "missing_action": "", "funding_gate_pass": not skip}
    if gate == "funding_aware_cap":
        cap = "funding_aware_extreme_cap" if (latest > 0 and pct >= 0.90) else ""
        return {"allowed": True, "cap": cap, "skip_reason": "", "status": "pass_capped" if cap else "pass", "funding_percentile": pct, "latest_funding_rate": latest, "feature_source_ts": feature_source_ts, "funding_exact_available": True, "missing_action": "", "funding_gate_pass": True}
    if gate == "funding_extreme_required":
        allowed = bool(abs(pct - 0.5) >= 0.40)
        return {"allowed": allowed, "cap": "" if allowed else "funding_extreme_condition_not_met_skip", "skip_reason": "" if allowed else "funding_extreme_condition_not_met_skip", "status": "pass" if allowed else "filtered", "funding_percentile": pct, "latest_funding_rate": latest, "feature_source_ts": feature_source_ts, "funding_exact_available": True, "missing_action": "", "funding_gate_pass": allowed}
    return {"allowed": False, "cap": f"unknown_funding_gate_skip:{gate}", "skip_reason": f"unknown_funding_gate:{gate}", "status": "unknown_gate", "funding_percentile": pct, "latest_funding_rate": latest, "feature_source_ts": feature_source_ts, "funding_exact_available": True, "missing_action": "unknown_funding_gate_skip", "funding_gate_pass": False}


def vol_target_scale_for_event(candidate: Mapping[str, Any], bars: pd.DataFrame, decision_ts: pd.Timestamp) -> dict[str, Any]:
    vol_target = safe_float(candidate.get("vol_target"), np.nan)
    if not math.isfinite(vol_target) or vol_target <= 0:
        return {"vol_scale": 1.0, "realized_vol_estimate": np.nan, "cap": "", "status": "not_configured"}
    window_days = max(1, int(safe_float(candidate.get("vol_window_days"), 20)))
    decision = ts_utc(decision_ts)
    if bars.empty or "ts" not in bars.columns or "close" not in bars.columns:
        return {"vol_scale": 1.0, "realized_vol_estimate": np.nan, "cap": "vol_target_missing_price_history_cap", "status": "missing_bars"}
    work = bars[["ts", "close"]].copy()
    work["ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce")
    work["close"] = pd.to_numeric(work["close"], errors="coerce")
    prior = work[work["ts"] < decision].dropna().tail(window_days * 288)
    if len(prior) < max(48, min(window_days * 288, 240)):
        return {"vol_scale": 1.0, "realized_vol_estimate": np.nan, "cap": "vol_target_warmup_cap", "status": "warmup_cap"}
    ret = prior["close"].pct_change().dropna()
    realized = float(ret.std() * math.sqrt(365 * 24 * 12)) if len(ret) else float("nan")
    if not math.isfinite(realized) or realized <= 0:
        return {"vol_scale": 1.0, "realized_vol_estimate": realized, "cap": "vol_target_invalid_realized_vol_cap", "status": "invalid_realized_vol"}
    min_scale = safe_float(candidate.get("vol_scale_min"), 0.25)
    max_scale = safe_float(candidate.get("vol_scale_max"), 2.0)
    scale = min(max(vol_target / realized, min_scale), max_scale)
    return {"vol_scale": float(scale), "realized_vol_estimate": realized, "cap": "", "status": "pass"}


def prior_high_signal_timeframe(candidate: Mapping[str, Any]) -> str:
    tf = str(candidate.get("bar_timeframe", candidate.get("signal_timeframe", "daily")) or "daily").strip().lower()
    if tf in {"daily", "1d", "d"}:
        return "1d"
    if tf in {"4h", "completed_4h"}:
        return "4h"
    return tf


def prior_high_signal_cadence_bars(candidate: Mapping[str, Any]) -> int:
    return 288 if prior_high_signal_timeframe(candidate) == "1d" else 48 if prior_high_signal_timeframe(candidate) == "4h" else 1


def completed_ohlcv_frame(bars: pd.DataFrame, timeframe: str) -> pd.DataFrame:
    if bars.empty or "ts" not in bars.columns:
        return pd.DataFrame(columns=["source_ts", "open", "high", "low", "close", "volume"])
    rule = "1D" if timeframe in {"1d", "daily"} else "4h" if timeframe in {"4h", "completed_4h"} else "5min"
    work = bars.copy()
    work["known_ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce") + pd.Timedelta(minutes=5)
    for col in ["open", "high", "low", "close", "volume"]:
        if col not in work.columns:
            work[col] = np.nan if col != "volume" else 0.0
        work[col] = pd.to_numeric(work[col], errors="coerce")
    work = work.dropna(subset=["known_ts", "open", "high", "low", "close"]).set_index("known_ts").sort_index()
    if work.empty:
        return pd.DataFrame(columns=["source_ts", "open", "high", "low", "close", "volume"])
    agg = work.resample(rule, label="right", closed="right").agg({
        "open": "first",
        "high": "max",
        "low": "min",
        "close": "last",
        "volume": "sum",
    }).dropna(subset=["open", "high", "low", "close"])
    agg["source_ts"] = agg.index
    return agg.reset_index(drop=True)


def prior_high_atr_resolution(candidate: Mapping[str, Any]) -> dict[str, Any]:
    tf = str(candidate.get("atr_bar_timeframe", "") or "").strip().lower()
    unit = str(candidate.get("atr_window_unit", "") or "").strip().lower()
    value = safe_float(candidate.get("atr_window_value", np.nan), np.nan)
    rankable = str(candidate.get("allowed_lane", "")).lower() not in {"diagnostic_only", "candidate_library_only"} and "diagnostic" not in str(candidate.get("side", "")).lower()
    if not tf or not unit or not math.isfinite(value):
        return {"status": "fail", "reason": "missing_explicit_atr_timeframe_unit_or_value", "atr_bar_timeframe": tf, "atr_window_unit": unit, "atr_window_value": value, "atr_lookback_bars_resolved": np.nan}
    if tf in {"5m", "5min", "execution_5m"} and rankable:
        return {"status": "fail", "reason": "rankable_prior_high_5m_atr_forbidden", "atr_bar_timeframe": tf, "atr_window_unit": unit, "atr_window_value": value, "atr_lookback_bars_resolved": np.nan}
    if tf in {"daily", "1d", "d"}:
        atr_tf = "1d"
        resolved = int(value) if unit in {"days", "day", "bars"} else 0
    elif tf in {"4h", "completed_4h"}:
        atr_tf = "4h"
        resolved = int(value * 6) if unit in {"days", "day"} else int(value) if unit in {"bars", "4h_bars"} else 0
    else:
        return {"status": "fail", "reason": f"unknown_atr_bar_timeframe:{tf}", "atr_bar_timeframe": tf, "atr_window_unit": unit, "atr_window_value": value, "atr_lookback_bars_resolved": np.nan}
    expected = int(safe_float(candidate.get("atr_lookback_bars_resolved"), resolved))
    status = "pass" if resolved > 0 and expected == resolved else "fail"
    reason = "" if status == "pass" else f"atr_lookback_resolution_mismatch:expected_{resolved}_manifest_{expected}"
    return {"status": status, "reason": reason, "atr_bar_timeframe": atr_tf, "atr_window_unit": unit, "atr_window_value": int(value), "atr_lookback_bars_resolved": resolved}


def prior_high_atr_at_decision(candidate: Mapping[str, Any], bars: pd.DataFrame, decision_ts: pd.Timestamp) -> dict[str, Any]:
    res = prior_high_atr_resolution(candidate)
    if res.get("status") != "pass":
        return {**res, "atr_value": np.nan, "atr_feature_source_ts": ""}
    include_current = parse_bool_value(candidate.get("atr_current_decision_bar_included", False), default=False)
    frame = completed_ohlcv_frame(bars, str(res["atr_bar_timeframe"]))
    if frame.empty:
        return {**res, "status": "fail", "reason": "missing_atr_frame", "atr_value": np.nan, "atr_feature_source_ts": ""}
    frame["source_ts"] = pd.to_datetime(frame["source_ts"], utc=True, errors="coerce")
    decision = ts_utc(decision_ts)
    eligible = frame[frame["source_ts"] <= decision].copy() if include_current else frame[frame["source_ts"] < decision].copy()
    resolved = int(res["atr_lookback_bars_resolved"])
    if len(eligible) < resolved + 1:
        return {**res, "status": "fail", "reason": "atr_warmup_insufficient", "atr_value": np.nan, "atr_feature_source_ts": str(eligible["source_ts"].max()) if len(eligible) else ""}
    work = eligible.tail(resolved + 1).copy()
    prev_close = pd.to_numeric(work["close"], errors="coerce").shift(1)
    high = pd.to_numeric(work["high"], errors="coerce")
    low = pd.to_numeric(work["low"], errors="coerce")
    tr = pd.concat([(high - low), (high - prev_close).abs(), (low - prev_close).abs()], axis=1).max(axis=1).dropna().tail(resolved)
    if len(tr) < resolved:
        return {**res, "status": "fail", "reason": "atr_true_range_incomplete", "atr_value": np.nan, "atr_feature_source_ts": str(work["source_ts"].max())}
    return {
        **res,
        "status": "pass",
        "reason": "",
        "atr_value": float(tr.mean()),
        "atr_feature_source_ts": str(work["source_ts"].max()),
        "atr_current_decision_bar_included": include_current,
    }


def prior_high_structure_level(candidate: Mapping[str, Any], bars: pd.DataFrame, decision_idx: int) -> dict[str, Any]:
    lookback = max(2, int(safe_float(candidate.get("lookback_bars"), 12)))
    close = pd.to_numeric(bars.get("close", pd.Series(dtype=float)), errors="coerce")
    if decision_idx <= 0 or len(close) <= decision_idx:
        return {"structure_level": np.nan, "structure_feature_source_ts": "", "structure_level_source": "unavailable"}
    side = str(candidate.get("side", "long")).lower()
    if side == "short":
        level = close.shift(1).rolling(lookback, min_periods=max(3, min(lookback, lookback // 3))).min().iloc[decision_idx]
    else:
        level = close.shift(1).rolling(lookback, min_periods=max(3, min(lookback, lookback // 3))).max().iloc[decision_idx]
    return {
        "structure_level": safe_float(level, np.nan),
        "structure_feature_source_ts": str(pd.Timestamp(bars.iloc[decision_idx]["ts"])),
        "structure_level_source": "prior_high_excluding_current_decision_bar",
    }


def prior_high_vwap_series(bars: pd.DataFrame, vwap_type: str, anchor_ts: pd.Timestamp | None = None) -> pd.DataFrame:
    if bars.empty:
        return pd.DataFrame(columns=["ts", "vwap"])
    vtype = str(vwap_type or "daily").lower()
    first_ts = str(bars["ts"].iloc[0]) if "ts" in bars.columns and len(bars) else ""
    last_ts = str(bars["ts"].iloc[-1]) if "ts" in bars.columns and len(bars) else ""
    cache_key = (id(bars), len(bars), first_ts, last_ts, vtype)
    if vtype != "anchored":
        cached = _PRIOR_HIGH_VWAP_CACHE.get(cache_key)
        if isinstance(cached, pd.DataFrame):
            return cached
    work = bars[["ts", "high", "low", "close", "volume"]].copy()
    work["ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce")
    for col in ["high", "low", "close", "volume"]:
        work[col] = pd.to_numeric(work[col], errors="coerce")
    work = work.dropna(subset=["ts", "high", "low", "close"]).sort_values("ts")
    work["volume"] = work["volume"].fillna(0.0)
    work["typical"] = (work["high"] + work["low"] + work["close"]) / 3.0
    if vtype == "anchored" and anchor_ts is not None:
        mask = work["ts"] >= ts_utc(anchor_ts)
        grp = pd.Series(0, index=work.index)
        work = work[mask].copy()
        work["_grp"] = grp[mask]
    elif vtype == "session":
        ts = work["ts"]
        work["_grp"] = (ts.astype("int64") // (8 * 3600 * 10**9)).astype("int64")
    else:
        work["_grp"] = work["ts"].dt.strftime("%Y-%m-%d")
    pv = work["typical"] * work["volume"].replace(0, np.nan)
    work["cum_pv"] = pv.groupby(work["_grp"]).cumsum()
    work["cum_vol"] = work["volume"].replace(0, np.nan).groupby(work["_grp"]).cumsum()
    work["vwap"] = work["cum_pv"] / work["cum_vol"]
    result = work[["ts", "vwap"]].dropna()
    if vtype != "anchored":
        if len(_PRIOR_HIGH_VWAP_CACHE) >= 32:
            _PRIOR_HIGH_VWAP_CACHE.pop(next(iter(_PRIOR_HIGH_VWAP_CACHE)))
        _PRIOR_HIGH_VWAP_CACHE[cache_key] = result
    return result


def prior_high_latest_vwap(bars: pd.DataFrame, decision_ts: pd.Timestamp, vwap_type: str, anchor_ts: pd.Timestamp | None = None) -> tuple[float, str]:
    frame = prior_high_vwap_series(bars, vwap_type, anchor_ts)
    if frame.empty:
        return np.nan, ""
    eligible = frame[pd.to_datetime(frame["ts"], utc=True, errors="coerce") <= ts_utc(decision_ts)]
    if eligible.empty:
        return np.nan, ""
    row = eligible.iloc[-1]
    return safe_float(row.get("vwap"), np.nan), str(row.get("ts"))


def prior_high_exit_candidate(
    *,
    reason: str,
    idx: int,
    price: float,
    signal_ts: pd.Timestamp,
    priority: int,
    adverse_sort: float,
    fields: Mapping[str, Any],
) -> dict[str, Any]:
    return {"exit_reason": reason, "exit_idx": int(idx), "exit_price": float(price), "exit_signal_ts": signal_ts, "priority": int(priority), "adverse_sort": float(adverse_sort), **dict(fields)}


def prior_high_exit_plan(candidate: Mapping[str, Any], bars: pd.DataFrame, addr: EventAddress, entry_price: float, direction: str) -> dict[str, Any]:
    decision_ts = ts_utc(addr.decision_ts)
    entry_i = int(addr.entry_idx)
    exit_limit = int(addr.exit_idx)
    side_sign = 1.0 if direction == "long" else -1.0
    atr = prior_high_atr_at_decision(candidate, bars, decision_ts)
    structure = prior_high_structure_level(candidate, bars, int(addr.idx))
    atr_value = safe_float(atr.get("atr_value"), np.nan)
    if not math.isfinite(atr_value) or atr_value <= 0:
        return {"status": "fail", "reason": atr.get("reason", "invalid_atr"), "exit_module_bound": False}
    atr_stop_mult = safe_float(candidate.get("atr_stop_mult", candidate.get("atr_stop_multiple")), np.nan)
    atr_trail_mult = safe_float(candidate.get("atr_trail_mult", candidate.get("atr_trailing_stop_multiple")), np.nan)
    structure_buffer = safe_float(candidate.get("structure_buffer_atr"), 0.0)
    if not math.isfinite(atr_stop_mult) or atr_stop_mult <= 0:
        return {"status": "fail", "reason": "missing_atr_stop_mult", "exit_module_bound": False}
    initial_stop = entry_price - side_sign * atr_stop_mult * atr_value
    signal_frame = completed_ohlcv_frame(bars, prior_high_signal_timeframe(candidate))
    signal_frame["source_ts"] = pd.to_datetime(signal_frame.get("source_ts", pd.Series(dtype=str)), utc=True, errors="coerce")
    path5 = bars.iloc[entry_i:exit_limit + 1].copy()
    path5["ts"] = pd.to_datetime(path5["ts"], utc=True, errors="coerce")
    exit_candidates: list[dict[str, Any]] = []
    # Time exit is always executable at the last available 5m close in the hold interval.
    time_row = bars.iloc[exit_limit]
    time_price = safe_float(time_row.get("close"), np.nan)
    if math.isfinite(time_price) and time_price > 0:
        exit_candidates.append(prior_high_exit_candidate(
            reason="time_exit",
            idx=exit_limit,
            price=time_price,
            signal_ts=ts_utc(time_row["ts"]),
            priority=99,
            adverse_sort=-side_sign * time_price,
            fields={},
        ))
    # ATR initial stop uses post-entry 5m OHLCV trigger/fill approximation.
    for j, row in path5.iterrows():
        open_ = safe_float(row.get("open"), np.nan)
        high = safe_float(row.get("high"), np.nan)
        low = safe_float(row.get("low"), np.nan)
        ts = ts_utc(row.get("ts"))
        triggered = False
        fill = np.nan
        if direction == "long":
            if math.isfinite(open_) and open_ <= initial_stop:
                fill = open_; triggered = True
            elif math.isfinite(low) and low <= initial_stop:
                fill = initial_stop; triggered = True
        else:
            if math.isfinite(open_) and open_ >= initial_stop:
                fill = open_; triggered = True
            elif math.isfinite(high) and high >= initial_stop:
                fill = initial_stop; triggered = True
        if triggered and math.isfinite(fill):
            exit_candidates.append(prior_high_exit_candidate(
                reason="atr_initial_stop",
                idx=int(j),
                price=fill,
                signal_ts=ts,
                priority=1,
                adverse_sort=-side_sign * fill,
                fields={
                    "atr_stop_triggered": True,
                    "atr_stop_trigger_ts": str(ts),
                    "atr_stop_exit_price": fill,
                },
            ))
            break
    signal_after = signal_frame[(signal_frame["source_ts"] > decision_ts) & (signal_frame["source_ts"] <= ts_utc(bars.iloc[exit_limit]["ts"]) + pd.Timedelta(minutes=5))].copy()
    entry_signal = signal_frame[signal_frame["source_ts"] <= decision_ts].tail(1)
    high_close = safe_float(entry_signal["close"].iloc[-1], entry_price) if not entry_signal.empty else entry_price
    low_close = high_close
    structure_level = safe_float(structure.get("structure_level"), np.nan)
    vwap_type = str(candidate.get("vwap_type", candidate.get("vwap_mode", "")) or "").strip().lower()
    vwap_value, vwap_ts = prior_high_latest_vwap(bars, decision_ts, vwap_type or "daily")
    vwap_filter_pass = True
    if vwap_type:
        if direction == "long":
            vwap_filter_pass = math.isfinite(vwap_value) and safe_float(bars.iloc[int(addr.idx)].get("close"), np.nan) >= vwap_value
        else:
            vwap_filter_pass = math.isfinite(vwap_value) and safe_float(bars.iloc[int(addr.idx)].get("close"), np.nan) <= vwap_value
    if not vwap_filter_pass:
        return {
            "status": "filtered",
            "reason": "vwap_entry_filter_reject",
            "exit_module_bound": True,
            "vwap_filter_pass": False,
            "vwap_value": vwap_value,
            "vwap_feature_source_ts": vwap_ts,
        }
    bar_ts = pd.to_datetime(bars["ts"], utc=True, errors="coerce")
    bar_ts_ns = bar_ts.astype("int64").to_numpy()
    for _, srow in signal_after.iterrows():
        close = safe_float(srow.get("close"), np.nan)
        source_ts = ts_utc(srow.get("source_ts"))
        if not math.isfinite(close):
            continue
        if direction == "long":
            high_close = max(high_close, close)
            trail_level = high_close - safe_float(atr_trail_mult, atr_stop_mult) * atr_value
            trail_hit = close < trail_level
            structure_level_eff = structure_level + structure_buffer * atr_value
            structure_hit = math.isfinite(structure_level_eff) and close < structure_level_eff
            vwap_now, vwap_now_ts = prior_high_latest_vwap(bars, source_ts, vwap_type or "daily", anchor_ts=decision_ts if vwap_type == "anchored" else None)
            vwap_hit = bool(vwap_type and math.isfinite(vwap_now) and close < vwap_now)
        else:
            low_close = min(low_close, close)
            trail_level = low_close + safe_float(atr_trail_mult, atr_stop_mult) * atr_value
            trail_hit = close > trail_level
            structure_level_eff = structure_level - structure_buffer * atr_value
            structure_hit = math.isfinite(structure_level_eff) and close > structure_level_eff
            vwap_now, vwap_now_ts = prior_high_latest_vwap(bars, source_ts, vwap_type or "daily", anchor_ts=decision_ts if vwap_type == "anchored" else None)
            vwap_hit = bool(vwap_type and math.isfinite(vwap_now) and close > vwap_now)
        exec_pos = int(np.searchsorted(bar_ts_ns, ts_utc(source_ts).value, side="right"))
        if exec_pos >= len(bars):
            continue
        exec_idx = int(bars.index[exec_pos])
        exec_row = bars.iloc[exec_pos]
        exec_price = safe_float(exec_row.get("open"), np.nan)
        if not math.isfinite(exec_price) or exec_price <= 0:
            continue
        if trail_hit:
            exit_candidates.append(prior_high_exit_candidate(
                reason="atr_trailing_stop",
                idx=exec_idx,
                price=exec_price,
                signal_ts=source_ts,
                priority=2,
                adverse_sort=-side_sign * exec_price,
                fields={
                    "atr_trailing_triggered": True,
                    "atr_trailing_exit_ts": str(pd.Timestamp(exec_row["ts"])),
                    "atr_trailing_exit_price": exec_price,
                    "trailing_reference_close": high_close if direction == "long" else low_close,
                    "atr_trailing_level": trail_level,
                    "atr_trailing_feature_source_ts": str(source_ts),
                },
            ))
        if structure_hit:
            exit_candidates.append(prior_high_exit_candidate(
                reason="structure_stop",
                idx=exec_idx,
                price=exec_price,
                signal_ts=source_ts,
                priority=3,
                adverse_sort=-side_sign * exec_price,
                fields={
                    "structure_stop_triggered": True,
                    "structure_stop_exit_ts": str(pd.Timestamp(exec_row["ts"])),
                    "structure_stop_exit_price": exec_price,
                },
            ))
        if vwap_hit:
            exit_candidates.append(prior_high_exit_candidate(
                reason="vwap_exit",
                idx=exec_idx,
                price=exec_price,
                signal_ts=source_ts,
                priority=4,
                adverse_sort=-side_sign * exec_price,
                fields={
                    "vwap_exit_triggered": True,
                    "vwap_exit_ts": str(pd.Timestamp(exec_row["ts"])),
                    "vwap_exit_price": exec_price,
                    "vwap_value": vwap_now,
                    "vwap_feature_source_ts": vwap_now_ts,
                },
            ))
    if not exit_candidates:
        return {"status": "fail", "reason": "no_valid_exit_candidate", "exit_module_bound": False}
    exit_candidates.sort(key=lambda r: (r["exit_idx"], r["priority"], r["adverse_sort"]))
    chosen = exit_candidates[0]
    same_bar = [r for r in exit_candidates if r["exit_idx"] == chosen["exit_idx"]]
    if len(same_bar) > 1:
        same_bar.sort(key=lambda r: (r["adverse_sort"], r["priority"]))
        chosen = same_bar[0]
    defaults = {
        "atr_window": atr.get("atr_window_value", ""),
        "atr_value": atr_value,
        "atr_feature_source_ts": atr.get("atr_feature_source_ts", ""),
        "atr_stop_mult": atr_stop_mult,
        "atr_stop_level": initial_stop,
        "atr_stop_triggered": False,
        "atr_stop_trigger_ts": "",
        "atr_stop_exit_price": "",
        "atr_trail_mult": atr_trail_mult,
        "trailing_reference_close": high_close if direction == "long" else low_close,
        "atr_trailing_level": "",
        "atr_trailing_feature_source_ts": "",
        "atr_trailing_triggered": False,
        "atr_trailing_exit_ts": "",
        "atr_trailing_exit_price": "",
        "structure_level": structure_level,
        "structure_level_source": structure.get("structure_level_source", ""),
        "structure_feature_source_ts": structure.get("structure_feature_source_ts", ""),
        "structure_stop_triggered": False,
        "structure_stop_exit_ts": "",
        "structure_stop_exit_price": "",
        "vwap_type": vwap_type,
        "vwap_anchor_ts": str(decision_ts if vwap_type == "anchored" else ""),
        "vwap_value": vwap_value,
        "vwap_feature_source_ts": vwap_ts,
        "vwap_filter_pass": vwap_filter_pass,
        "vwap_exit_triggered": False,
        "vwap_exit_ts": "",
        "vwap_exit_price": "",
        "exit_signal_ts": str(chosen["exit_signal_ts"]),
        "exit_path_policy": "earliest_executable_exit_most_adverse_same_bar_no_target_first",
        "same_bar_ambiguity_cap": len(same_bar) > 1,
        "metadata_only_exit_field_count": 0,
        "exit_module_bound": True,
        "ohlcv_stop_trigger_approximation_cap": True,
        "atr_bar_timeframe": atr.get("atr_bar_timeframe", ""),
        "atr_window_unit": atr.get("atr_window_unit", ""),
        "atr_window_value": atr.get("atr_window_value", ""),
        "atr_lookback_bars_resolved": atr.get("atr_lookback_bars_resolved", ""),
        "atr_current_decision_bar_included": atr.get("atr_current_decision_bar_included", False),
    }
    defaults.update(chosen)
    defaults["status"] = "pass"
    return defaults


def prior_high_event_from_address(candidate: Mapping[str, Any], bars: pd.DataFrame, funding: pd.DataFrame, addr: EventAddress, fee_bps: float = 10.0) -> dict[str, Any] | None:
    side = str(candidate.get("side", "long"))
    direction = prior_high_side_direction(side)
    entry_i = addr.entry_idx
    if entry_i >= len(bars) or addr.exit_idx <= entry_i:
        return None
    entry = bars.iloc[entry_i]
    entry_price = safe_float(entry.get("open"), np.nan)
    if not math.isfinite(entry_price) or entry_price <= 0:
        return None
    decision_ts = pd.Timestamp(addr.decision_ts)
    if not candidate_event_universe_allowed(candidate, addr.symbol, decision_ts):
        return None
    parent_gate = evaluate_parent_regime_gate(candidate, bars, decision_ts=decision_ts)
    if not bool(parent_gate.get("allowed", True)):
        return None
    funding_gate = evaluate_funding_gate(candidate, funding, decision_ts)
    if not bool(funding_gate.get("allowed", True)):
        return None
    plan = prior_high_exit_plan(candidate, bars, addr, entry_price, direction)
    if plan.get("status") in {"filtered", "fail"}:
        return None
    exit_i = int(plan["exit_idx"])
    exit_row = bars.iloc[exit_i]
    exit_price = safe_float(plan.get("exit_price"), np.nan)
    if not math.isfinite(exit_price) or exit_price <= 0:
        return None
    atr_stop_level = safe_float(plan.get("atr_stop_level"), np.nan)
    risk = abs(entry_price - atr_stop_level) if math.isfinite(atr_stop_level) else entry_price * safe_float(candidate.get("stop_bps"), 100.0) / 10000.0
    if not math.isfinite(risk) or risk <= 0:
        return None
    gross = (exit_price - entry_price) / risk if direction == "long" else (entry_price - exit_price) / risk
    entry_fee_bps = safe_float(candidate.get("entry_fee_bps_per_side", candidate.get("taker_fee_bps_per_side", candidate.get("fee_bps_per_side", fee_bps))), fee_bps)
    exit_fee_bps = safe_float(candidate.get("exit_fee_bps_per_side", candidate.get("taker_fee_bps_per_side", candidate.get("fee_bps_per_side", fee_bps))), entry_fee_bps)
    qty = safe_float(candidate.get("qty", candidate.get("quantity", 1.0)), 1.0)
    contract_size = safe_float(candidate.get("contract_size_or_multiplier", candidate.get("contract_multiplier", 1.0)), 1.0)
    fee_components = compute_round_trip_fee_R(
        entry_price,
        exit_price,
        risk,
        qty=qty,
        contract_size_or_multiplier=contract_size,
        entry_fee_bps_per_side=entry_fee_bps,
        exit_fee_bps_per_side=exit_fee_bps,
    )
    fee_R = safe_float(fee_components.get("fee_R"), float("nan"))
    if not math.isfinite(fee_R):
        return None
    entry_ts = pd.Timestamp(entry["ts"])
    exit_ts = pd.Timestamp(exit_row["ts"])
    same_bar_adverse_stop = bool(str(plan.get("exit_reason", "")).endswith("stop") and exit_i == entry_i)
    exit_interval_end_ts = effective_interval_end_ts(entry_ts, exit_ts, same_bar_adverse_stop=same_bar_adverse_stop)
    funding_fields = funding_components_for_event(funding, entry_ts, exit_interval_end_ts, side=direction, entry_price=entry_price, risk_price=risk)
    funding_R = safe_float(funding_fields.get("funding_R"), 0.0)
    raw_slippage_R = 0.0
    raw_net = gross + fee_R + funding_R + raw_slippage_R
    protected = any(pd.Timestamp(x) >= PROTECTED_TS for x in [decision_ts, entry_ts, exit_ts, exit_interval_end_ts])
    if protected:
        return None
    mark_available = bool(pd.notna(entry.get("mark_close")) and pd.notna(exit_row.get("mark_close")))
    funding_proxy = bool(funding_fields.get("funding_proxy_used", False))
    cap = ["kraken_survivorship_lifecycle_cap", "prior_high_train_only_cap", "ohlcv_stop_trigger_approximation_cap", "no_depth_slippage_cap"]
    if funding_proxy:
        cap.extend(["funding_missing_adverse_proxy", "funding_proxy_selection_cap"])
    if not mark_available:
        cap.append("mark_missing_or_incomplete")
    if bool(plan.get("same_bar_ambiguity_cap", False)) or same_bar_adverse_stop:
        cap.append("same_bar_ambiguity_cap")
    if parent_gate.get("cap"):
        cap.append(str(parent_gate["cap"]))
    if funding_gate.get("cap"):
        cap.append(str(funding_gate["cap"]))
    cid = definition_identity(candidate)
    csid = symbol_identity(candidate, addr.symbol)
    pjson = parameter_vector_json(candidate, ENGINES.get(addr.engine_id))
    phash = parameter_vector_hash(candidate, ENGINES.get(addr.engine_id))
    base = {
        "event_id": stable_hash(addr.candidate_id, addr.symbol, decision_ts, addr.seq, n=20),
        "candidate_id": cid,
        "candidate_definition_id": cid,
        "candidate_symbol_id": csid,
        "definition_id": addr.definition_id,
        "hypothesis_id": addr.hypothesis_id,
        "family": addr.family,
        "family_engine_id": addr.engine_id,
        "symbol": addr.symbol,
        "row_semantics": addr.row_semantics,
        "contract_event_type": addr.contract_event_type,
        "event_semantics_version": EVENT_SEMANTICS_VERSION,
        "parameter_vector_hash": phash,
        "parameter_vector_json": pjson,
        "parameter_manifest_pointer": candidate.get("parameter_manifest_pointer", ""),
        "decision_ts": decision_ts,
        "entry_ts": entry_ts,
        "exit_ts": exit_ts,
        "exit_interval_end_ts": exit_interval_end_ts,
        "effective_exit_ts_for_purge": exit_interval_end_ts,
        "side": side,
        "entry_price": entry_price,
        "exit_price": exit_price,
        "stop_price": plan.get("atr_stop_level", ""),
        "exit_reason": plan.get("exit_reason", ""),
        "gross_R": gross,
        "fees_R": fee_R,
        "entry_fee_R": safe_float(fee_components.get("entry_fee_R"), np.nan),
        "exit_fee_R": safe_float(fee_components.get("exit_fee_R"), np.nan),
        "total_fee_R": fee_R,
        "fee_formula": "entry_and_exit_notional_per_side_bps_over_risk_usd",
        "entry_notional_usd": safe_float(fee_components.get("entry_notional_usd"), np.nan),
        "exit_notional_usd": safe_float(fee_components.get("exit_notional_usd"), np.nan),
        "risk_usd": safe_float(fee_components.get("risk_usd"), np.nan),
        "entry_fee_bps_per_side": entry_fee_bps,
        "exit_fee_bps_per_side": exit_fee_bps,
        "slippage_R": raw_slippage_R,
        "funding_R": funding_R,
        "funding_exact_R": funding_fields.get("funding_exact_R", np.nan),
        "funding_proxy_R": funding_fields.get("funding_proxy_R", 0.0),
        "funding_R_used_for_selection": funding_fields.get("funding_R_used_for_selection", funding_R),
        "net_R": raw_net,
        "raw_gross_R": gross,
        "raw_fee_R": fee_R,
        "raw_funding_R": funding_R,
        "raw_slippage_R": raw_slippage_R,
        "raw_net_R": raw_net,
        "vol_scale": 1.0,
        "realized_vol_estimate": np.nan,
        "vol_target": "not_applicable_prior_high",
        "vol_target_status": "not_applicable_prior_high",
        "scaled_gross_R": gross,
        "scaled_fee_R": fee_R,
        "scaled_funding_R": funding_R,
        "scaled_slippage_R": raw_slippage_R,
        "scaled_net_R": raw_net,
        "r_metric_basis": "raw_trade_R_prior_high_no_vol_target",
        "funding_timestamps_crossed": int(funding_fields.get("funding_boundary_count_exact", 0) or funding_fields.get("funding_boundary_count_proxy", 0) or 0),
        "funding_boundary_crossed": funding_fields.get("funding_boundary_crossed", False),
        "funding_boundary_count_exact": funding_fields.get("funding_boundary_count_exact", 0),
        "funding_boundary_count_proxy": funding_fields.get("funding_boundary_count_proxy", 0),
        "exact_funding_rate": funding_fields.get("exact_funding_rate", np.nan),
        "funding_exact": funding_fields.get("funding_exact", False),
        "funding_proxy_used": funding_proxy,
        "funding_unavailable": funding_fields.get("funding_unavailable", False),
        "funding_schedule_source": funding_fields.get("funding_schedule_source", ""),
        "funding_rate_source": funding_fields.get("funding_rate_source", ""),
        "funding_label_cap_reason": ";".join(sorted({x for x in [str(funding_fields.get("funding_label_cap_reason", "") or ""), str(funding_gate.get("cap", "") or "")] if x})),
        "fee_model_used": "conservative_all_taker_entry_exit_per_side_bps",
        "fee_assumption_source": "kraken_family_engine_default_conservative",
        "trade_price_source": "5m_trade_open_close_path",
        "mark_price_source": "5m_mark_candle_join" if mark_available else "missing_mark_cap",
        "index_price_source": "unavailable",
        "mark_available": mark_available,
        "mark_proxy_used": not mark_available,
        "mark_liquidation_flag": False,
        "lifecycle_status": "eligible_from_k0_or_snapshot",
        "delist_settlement_flag": False,
        "same_bar_ambiguity_flag": bool(plan.get("same_bar_ambiguity_cap", False)),
        "same_bar_adverse_stop_interval_cap": same_bar_adverse_stop,
        "label_cap_reason": ";".join(sorted(set(cap))),
        "candidate_window_start": entry_ts,
        "candidate_window_end": exit_interval_end_ts,
        "feature_source_ts": decision_ts,
        "trigger_source_ts": decision_ts,
        "state_source_ts": decision_ts,
        "parent_gate": candidate.get("parent_regime_gate", ""),
        "parent_regime_gate": candidate.get("parent_regime_gate", ""),
        "parent_gate_pass": bool(parent_gate.get("allowed", True)),
        "parent_btc_reference_ts": parent_gate.get("btc_ref_ts", ""),
        "parent_eth_reference_ts": parent_gate.get("eth_ref_ts", ""),
        "parent_btc_feature_source_ts": parent_gate.get("btc_ref_ts", ""),
        "parent_eth_feature_source_ts": parent_gate.get("eth_ref_ts", ""),
        "parent_gate_feature_source_ts": parent_gate.get("feature_source_ts", decision_ts),
        "parent_btc_trend_value": parent_gate.get("btc_trend_value", ""),
        "parent_eth_trend_value": parent_gate.get("eth_trend_value", ""),
        "parent_gate_missing_action": parent_gate.get("missing_action", ""),
        "parent_gate_status": parent_gate.get("status", ""),
        "funding_gate": candidate.get("funding_gate", ""),
        "funding_gate_pass": bool(funding_gate.get("funding_gate_pass", funding_gate.get("allowed", True))),
        "funding_gate_status": funding_gate.get("status", ""),
        "funding_gate_percentile": funding_gate.get("funding_percentile", ""),
        "funding_percentile": funding_gate.get("funding_percentile", ""),
        "funding_gate_latest_rate": funding_gate.get("latest_funding_rate", ""),
        "funding_feature_source_ts": funding_gate.get("feature_source_ts", decision_ts),
        "funding_exact_available": funding_gate.get("funding_exact_available", False),
        "funding_missing_action": funding_gate.get("missing_action", ""),
        "source_ts_lte_decision": bool(parent_gate.get("source_ts_lte_decision", True)),
        "raw_trade_pointer": str(candidate.get("trade_pointer", "")),
        "raw_mark_pointer": str(candidate.get("mark_pointer", "")),
        "raw_funding_pointer": str(candidate.get("funding_pointer", "")),
        "regime_label": str(candidate.get("regime_activation", "all_context_diagnostic")),
    }
    for key, value in plan.items():
        if key not in {"status", "priority", "adverse_sort", "exit_idx"}:
            base[key] = value
    return base


def event_from_address(candidate: Mapping[str, Any], bars: pd.DataFrame, funding: pd.DataFrame, addr: EventAddress, fee_bps: float = 10.0) -> dict[str, Any] | None:
    if str(candidate.get("family_engine_id", addr.engine_id)) == "prior_high_reclaim_engine":
        return prior_high_event_from_address(candidate, bars, funding, addr, fee_bps=fee_bps)
    side = normalize_tsmom_side(candidate.get("side", "long")) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else str(candidate.get("side", "long"))
    direction = tsmom_side_direction(side) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else ("long" if side == "long" else "short")
    entry_i = addr.entry_idx
    exit_limit = addr.exit_idx
    if entry_i >= len(bars) or exit_limit <= entry_i:
        return None
    entry = bars.iloc[entry_i]
    entry_price = safe_float(entry.get("open"), np.nan)
    if not math.isfinite(entry_price) or entry_price <= 0:
        return None
    decision_ts = pd.Timestamp(addr.decision_ts)
    if not candidate_event_universe_allowed(candidate, addr.symbol, decision_ts):
        return None
    stop_bps = float(safe_float(candidate.get("stop_bps"), 100.0))
    risk = entry_price * stop_bps / 10000.0
    if not math.isfinite(risk) or risk <= 0:
        return None
    stop_price = entry_price - risk if direction == "long" else entry_price + risk
    high = pd.to_numeric(bars["high"].iloc[entry_i:exit_limit + 1], errors="coerce").to_numpy(dtype=float)
    low = pd.to_numeric(bars["low"].iloc[entry_i:exit_limit + 1], errors="coerce").to_numpy(dtype=float)
    exit_reason = "interval_close" if addr.row_semantics == "position_interval" else "time_exit"
    ambiguity = False
    if direction == "long":
        hits = np.flatnonzero(np.isfinite(low) & (low <= stop_price))
        if hits.size:
            rel = int(hits[0]); exit_i = entry_i + rel; exit_reason = "stop_5m_adverse"; ambiguity = math.isfinite(high[rel]) and high[rel] > entry_price
        else:
            exit_i = exit_limit
    else:
        hits = np.flatnonzero(np.isfinite(high) & (high >= stop_price))
        if hits.size:
            rel = int(hits[0]); exit_i = entry_i + rel; exit_reason = "stop_5m_adverse"; ambiguity = math.isfinite(low[rel]) and low[rel] < entry_price
        else:
            exit_i = exit_limit
    exit_row = bars.iloc[exit_i]
    exit_price = stop_price if exit_reason.startswith("stop") else safe_float(exit_row.get("close"), np.nan)
    if not math.isfinite(exit_price) or exit_price <= 0:
        return None
    gross = (exit_price - entry_price) / risk if direction == "long" else (entry_price - exit_price) / risk
    entry_fee_bps = safe_float(candidate.get("entry_fee_bps_per_side", candidate.get("taker_fee_bps_per_side", candidate.get("fee_bps_per_side", fee_bps))), fee_bps)
    exit_fee_bps = safe_float(candidate.get("exit_fee_bps_per_side", candidate.get("taker_fee_bps_per_side", candidate.get("fee_bps_per_side", fee_bps))), entry_fee_bps)
    qty = safe_float(candidate.get("qty", candidate.get("quantity", 1.0)), 1.0)
    contract_size = safe_float(candidate.get("contract_size_or_multiplier", candidate.get("contract_multiplier", 1.0)), 1.0)
    fee_components = compute_round_trip_fee_R(
        entry_price,
        exit_price,
        risk,
        qty=qty,
        contract_size_or_multiplier=contract_size,
        entry_fee_bps_per_side=entry_fee_bps,
        exit_fee_bps_per_side=exit_fee_bps,
    )
    fee_R = safe_float(fee_components.get("fee_R"), float("nan"))
    if not math.isfinite(fee_R):
        return None
    entry_ts = pd.Timestamp(entry["ts"])
    exit_ts = pd.Timestamp(exit_row["ts"])
    same_bar_adverse_stop = bool(exit_reason.startswith("stop") and exit_i == entry_i)
    exit_interval_end_ts = effective_interval_end_ts(entry_ts, exit_ts, same_bar_adverse_stop=same_bar_adverse_stop)
    parent_gate = evaluate_parent_regime_gate(candidate, bars, decision_ts=decision_ts) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else {"allowed": True, "cap": "", "status": "not_applicable", "feature_source_ts": decision_ts}
    if not bool(parent_gate.get("allowed", True)):
        return None
    funding_gate = evaluate_funding_gate(candidate, funding, decision_ts) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else {"allowed": True, "cap": "", "status": "not_applicable"}
    if not bool(funding_gate.get("allowed", True)):
        return None
    funding_fields = funding_components_for_event(funding, entry_ts, exit_interval_end_ts, side=direction, entry_price=entry_price, risk_price=risk)
    funding_R = safe_float(funding_fields.get("funding_R"), 0.0)
    funding_exact = bool(funding_fields.get("funding_exact", False))
    funding_proxy = bool(funding_fields.get("funding_proxy_used", False))
    boundary = bool(funding_fields.get("funding_boundary_crossed", False))
    exact_rate = funding_fields.get("exact_funding_rate", np.nan)
    crossed = int(funding_fields.get("funding_boundary_count_exact", 0) or funding_fields.get("funding_boundary_count_proxy", 0) or 0)
    mark_available = bool(pd.notna(entry.get("mark_close")) and pd.notna(exit_row.get("mark_close")))
    mark_proxy = not mark_available
    raw_slippage_R = 0.0
    raw_net = gross + fee_R + funding_R + raw_slippage_R
    protected = any(pd.Timestamp(x) >= PROTECTED_TS for x in [decision_ts, entry_ts, exit_ts, exit_interval_end_ts])
    if protected:
        return None
    cap = ["kraken_survivorship_lifecycle_cap"]
    if funding_proxy:
        cap.append("funding_missing_adverse_proxy")
        cap.append("funding_proxy_selection_cap")
    if mark_proxy:
        cap.append("mark_missing_or_incomplete")
    if ambiguity or same_bar_adverse_stop:
        cap.append("same_bar_adverse_stop_interval_cap")
    side_cap = tsmom_side_label_cap(side) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else ""
    if side_cap:
        cap.append(side_cap)
    if parent_gate.get("cap"):
        cap.append(str(parent_gate["cap"]))
    if funding_gate.get("cap"):
        cap.append(str(funding_gate["cap"]))
    vol = vol_target_scale_for_event(candidate, bars, decision_ts) if str(candidate.get("family_engine_id", addr.engine_id)) == "scheduled_tsmom_engine" else {"vol_scale": 1.0, "realized_vol_estimate": np.nan, "cap": "", "status": "not_applicable"}
    if vol.get("cap"):
        cap.append(str(vol["cap"]))
    vol_scale = safe_float(vol.get("vol_scale"), 1.0)
    scaled_gross = gross * vol_scale
    scaled_fee = fee_R * vol_scale
    scaled_funding = funding_R * vol_scale
    scaled_slippage = raw_slippage_R * vol_scale
    scaled_net = raw_net * vol_scale
    cid = definition_identity(candidate)
    csid = symbol_identity(candidate, addr.symbol)
    pjson = parameter_vector_json(candidate, ENGINES.get(addr.engine_id))
    phash = parameter_vector_hash(candidate, ENGINES.get(addr.engine_id))
    return {
        "event_id": stable_hash(addr.candidate_id, addr.symbol, decision_ts, addr.seq, n=20),
        "candidate_id": cid,
        "candidate_definition_id": cid,
        "candidate_symbol_id": csid,
        "definition_id": addr.definition_id,
        "hypothesis_id": addr.hypothesis_id,
        "family": addr.family,
        "family_engine_id": addr.engine_id,
        "symbol": addr.symbol,
        "row_semantics": addr.row_semantics,
        "contract_event_type": addr.contract_event_type,
        "event_semantics_version": EVENT_SEMANTICS_VERSION,
        "parameter_vector_hash": phash,
        "parameter_vector_json": pjson,
        "parameter_manifest_pointer": candidate.get("parameter_manifest_pointer", ""),
        "decision_ts": decision_ts,
        "entry_ts": entry_ts,
        "exit_ts": exit_ts,
        "exit_interval_end_ts": exit_interval_end_ts,
        "effective_exit_ts_for_purge": exit_interval_end_ts,
        "side": side,
        "entry_price": entry_price,
        "exit_price": exit_price,
        "stop_price": stop_price,
        "exit_reason": exit_reason,
        "gross_R": scaled_gross,
        "fees_R": scaled_fee,
        "entry_fee_R": safe_float(fee_components.get("entry_fee_R"), np.nan),
        "exit_fee_R": safe_float(fee_components.get("exit_fee_R"), np.nan),
        "total_fee_R": fee_R,
        "fee_formula": "entry_and_exit_notional_per_side_bps_over_risk_usd",
        "entry_notional_usd": safe_float(fee_components.get("entry_notional_usd"), np.nan),
        "exit_notional_usd": safe_float(fee_components.get("exit_notional_usd"), np.nan),
        "risk_usd": safe_float(fee_components.get("risk_usd"), np.nan),
        "entry_fee_bps_per_side": entry_fee_bps,
        "exit_fee_bps_per_side": exit_fee_bps,
        "slippage_R": scaled_slippage,
        "funding_R": scaled_funding,
        "funding_exact_R": safe_float(funding_fields.get("funding_exact_R", np.nan), np.nan) * vol_scale if math.isfinite(safe_float(funding_fields.get("funding_exact_R", np.nan), np.nan)) else funding_fields.get("funding_exact_R", np.nan),
        "funding_proxy_R": safe_float(funding_fields.get("funding_proxy_R", 0.0), 0.0) * vol_scale,
        "funding_R_used_for_selection": safe_float(funding_fields.get("funding_R_used_for_selection", funding_R), funding_R) * vol_scale,
        "net_R": scaled_net,
        "raw_gross_R": gross,
        "raw_fee_R": fee_R,
        "raw_funding_R": funding_R,
        "raw_slippage_R": raw_slippage_R,
        "raw_net_R": raw_net,
        "vol_scale": vol_scale,
        "realized_vol_estimate": vol.get("realized_vol_estimate", np.nan),
        "vol_target": candidate.get("vol_target", ""),
        "vol_target_status": vol.get("status", ""),
        "scaled_gross_R": scaled_gross,
        "scaled_fee_R": scaled_fee,
        "scaled_funding_R": scaled_funding,
        "scaled_slippage_R": scaled_slippage,
        "scaled_net_R": scaled_net,
        "r_metric_basis": "scaled_portfolio_contribution_raw_R_preserved",
        "funding_timestamps_crossed": crossed,
        "funding_boundary_crossed": boundary,
        "funding_boundary_count_exact": funding_fields.get("funding_boundary_count_exact", 0),
        "funding_boundary_count_proxy": funding_fields.get("funding_boundary_count_proxy", 0),
        "exact_funding_rate": exact_rate,
        "funding_exact": funding_exact,
        "funding_proxy_used": funding_proxy,
        "funding_unavailable": funding_fields.get("funding_unavailable", False),
        "funding_schedule_source": funding_fields.get("funding_schedule_source", ""),
        "funding_rate_source": funding_fields.get("funding_rate_source", ""),
        "funding_label_cap_reason": ";".join(sorted({x for x in [str(funding_fields.get("funding_label_cap_reason", "") or ""), str(funding_gate.get("cap", "") or "")] if x})),
        "fee_model_used": "conservative_all_taker_entry_exit_per_side_bps",
        "fee_assumption_source": "kraken_family_engine_default_conservative",
        "trade_price_source": "5m_trade_open_close_path",
        "mark_price_source": "5m_mark_candle_join" if mark_available else "missing_mark_cap",
        "index_price_source": "unavailable",
        "mark_available": mark_available,
        "mark_proxy_used": mark_proxy,
        "mark_liquidation_flag": False,
        "lifecycle_status": "eligible_from_k0_or_snapshot",
        "delist_settlement_flag": False,
        "same_bar_ambiguity_flag": bool(ambiguity),
        "same_bar_adverse_stop_interval_cap": same_bar_adverse_stop,
        "label_cap_reason": ";".join(sorted(set(cap))),
        "candidate_window_start": entry_ts,
        "candidate_window_end": exit_interval_end_ts,
        "feature_source_ts": decision_ts,
        "trigger_source_ts": decision_ts,
        "state_source_ts": decision_ts,
        "parent_gate": candidate.get("parent_regime_gate", ""),
        "parent_regime_gate": candidate.get("parent_regime_gate", ""),
        "parent_gate_pass": bool(parent_gate.get("allowed", True)),
        "parent_btc_reference_ts": parent_gate.get("btc_ref_ts", ""),
        "parent_eth_reference_ts": parent_gate.get("eth_ref_ts", ""),
        "parent_btc_feature_source_ts": parent_gate.get("btc_ref_ts", ""),
        "parent_eth_feature_source_ts": parent_gate.get("eth_ref_ts", ""),
        "parent_gate_feature_source_ts": parent_gate.get("feature_source_ts", decision_ts),
        "parent_btc_trend_value": parent_gate.get("btc_trend_value", ""),
        "parent_eth_trend_value": parent_gate.get("eth_trend_value", ""),
        "parent_gate_missing_action": parent_gate.get("missing_action", ""),
        "parent_gate_status": parent_gate.get("status", ""),
        "funding_gate": candidate.get("funding_gate", ""),
        "funding_gate_pass": bool(funding_gate.get("funding_gate_pass", funding_gate.get("allowed", True))),
        "funding_gate_status": funding_gate.get("status", ""),
        "funding_gate_percentile": funding_gate.get("funding_percentile", ""),
        "funding_percentile": funding_gate.get("funding_percentile", ""),
        "funding_gate_latest_rate": funding_gate.get("latest_funding_rate", ""),
        "funding_feature_source_ts": funding_gate.get("feature_source_ts", decision_ts),
        "funding_exact_available": funding_gate.get("funding_exact_available", False),
        "funding_missing_action": funding_gate.get("missing_action", ""),
        "source_ts_lte_decision": bool(parent_gate.get("source_ts_lte_decision", True)),
        "raw_trade_pointer": str(candidate.get("trade_pointer", "")),
        "raw_mark_pointer": str(candidate.get("mark_pointer", "")),
        "raw_funding_pointer": str(candidate.get("funding_pointer", "")),
        "regime_label": str(candidate.get("regime_activation", "all_context_diagnostic")),
    }


def funding_between(funding: pd.DataFrame, entry_ts: pd.Timestamp, exit_ts: pd.Timestamp) -> pd.DataFrame:
    if funding.empty or "timestamp" not in funding.columns:
        return pd.DataFrame()
    return funding[(funding["timestamp"] > entry_ts) & (funding["timestamp"] <= exit_ts)].copy()


def parse_args(argv: list[str] | None = None) -> argparse.Namespace:
    p = argparse.ArgumentParser(description="Kraken family-engine aggregate-first sweep")
    p.add_argument("--stage", choices=STAGES, default="all")
    p.add_argument("--phase-profile", choices=sorted(PHASE_PROFILES), default=DEFAULT_PHASE_PROFILE)
    p.add_argument("--resume", action="store_true")
    p.add_argument("--smoke", action="store_true")
    p.add_argument("--max-symbols", type=int, default=0)
    p.add_argument("--start", default="2024-01-01")
    p.add_argument("--end", default=str(SCREENING_END))
    p.add_argument("--chunk-size", type=int, default=50)
    p.add_argument("--aggregate-batch-size", type=int, default=25)
    p.add_argument("--memory-soft-limit-gb", type=float, default=0.0)
    p.add_argument("--aggregate-cache-mode", choices=["off", "audit", "accelerated"], default="off")
    p.add_argument("--cache-root", default="")
    p.add_argument("--max-output-gb", type=float, default=80.0)
    p.add_argument("--allow-large-output", action="store_true")
    p.add_argument("--disable-telegram", action="store_true")
    p.add_argument("--require-telegram", action="store_true")
    p.add_argument("--allow-no-telegram", action="store_true")
    p.add_argument("--dry-run", action="store_true")
    p.add_argument("--seed", type=int, default=DEFAULT_SEED)
    p.add_argument("--hypothesis-library", default=str(DEFAULT_HYPOTHESIS_LIBRARY.relative_to(REPO)))
    p.add_argument("--research-input-dir", default=str(DEFAULT_RESEARCH_INPUT_DIR.relative_to(REPO)))
    p.add_argument("--kraken-data-root", default=str(DEFAULT_KRAKEN_DATA_ROOT))
    p.add_argument("--k0-root", default=str(DEFAULT_K0_ROOT.relative_to(REPO)))
    p.add_argument("--readiness-root", default=str(DEFAULT_READINESS_ROOT.relative_to(REPO)))
    p.add_argument("--repair-root", default=str(DEFAULT_REPAIR_ROOT.relative_to(REPO)))
    p.add_argument("--mechanical-qa-root", default=str(DEFAULT_MECHANICAL_QA_ROOT.relative_to(REPO)))
    p.add_argument("--sampled-sweep-root", default=str(DEFAULT_SAMPLED_SWEEP_ROOT.relative_to(REPO)))
    p.add_argument("--bruteforce-root", default=str(DEFAULT_BRUTEFORCE_ROOT.relative_to(REPO)))
    p.add_argument("--prior-benchmark-root", default="")
    p.add_argument("--structural-repair-root", default=str(DEFAULT_STRUCTURAL_REPAIR_ROOT.relative_to(REPO)))
