    p.add_argument("--stopped-engine-wave-root", default=str(FAILED_ENGINE_WAVE_ROOT.relative_to(REPO)))
    p.add_argument("--candidate-definition-budget", type=int, default=60000)
    p.add_argument("--coarse-definition-budget", type=int, default=45000)
    p.add_argument("--refine-definition-budget", type=int, default=15000)
