def stage_list(stage: str) -> list[str]:
    # Backward-compatible fallback; main() passes the active profile explicitly.
    return list(PHASE_PROFILES[DEFAULT_PHASE_PROFILE]["stages"]) if stage == "all" else [stage]


def active_phase_profile(args: argparse.Namespace) -> Mapping[str, Any]:
    return PHASE_PROFILES.get(getattr(args, "phase_profile", DEFAULT_PHASE_PROFILE), PHASE_PROFILES[DEFAULT_PHASE_PROFILE])


def active_stage_list(args: argparse.Namespace) -> list[str]:
    return list(active_phase_profile(args)["stages"]) if args.stage == "all" else [args.stage]


def active_run_id(args: argparse.Namespace) -> str:
    return str(active_phase_profile(args)["run_id"])


def is_tsmom_retest_profile(profile: object) -> bool:
    return str(profile) in {
        TSMOM_RETEST_PHASE_PROFILE,
        TSMOM_RETEST_P1_PHASE_PROFILE,
        TSMOM_RETEST_P1_CANARY_PHASE_PROFILE,
        TSMOM_RETEST_P1_ULTRA_CANARY_FAST_PHASE_PROFILE,
        TSMOM_RETEST_P1_STANDARD_CANARY_PHASE_PROFILE,
    }


def is_tsmom_canary_profile(profile: object) -> bool:
    return str(profile) in {
        TSMOM_RETEST_P1_CANARY_PHASE_PROFILE,
        TSMOM_RETEST_P1_ULTRA_CANARY_FAST_PHASE_PROFILE,
        TSMOM_RETEST_P1_STANDARD_CANARY_PHASE_PROFILE,
    }


def is_fast_tsmom_canary_profile(profile: object) -> bool:
    return str(profile) == TSMOM_RETEST_P1_ULTRA_CANARY_FAST_PHASE_PROFILE


def is_uncapped_two_family_profile(profile: object) -> bool:
    return str(profile) in {
        UNCAPPED_TWO_FAMILY_PHASE_PROFILE,
        REPAIRED_TWO_FAMILY_PHASE_PROFILE,
        MEMORYSAFE_TWO_FAMILY_PHASE_PROFILE,
    }


def is_repaired_two_family_profile(profile: object) -> bool:
    return str(profile) in {REPAIRED_TWO_FAMILY_PHASE_PROFILE, MEMORYSAFE_TWO_FAMILY_PHASE_PROFILE}


def is_memorysafe_two_family_profile(profile: object) -> bool:
    return str(profile) == MEMORYSAFE_TWO_FAMILY_PHASE_PROFILE


def prior_high_side_direction(side: object) -> str:
    text = str(side or "long").strip().lower()
    return "short" if text in {"short", "short_diagnostic"} else "long"


def requires_p1_dependency_profile(profile: object) -> bool:
    return str(profile) in {
        TSMOM_RETEST_P1_PHASE_PROFILE,
        TSMOM_RETEST_P1_CANARY_PHASE_PROFILE,
        TSMOM_RETEST_P1_ULTRA_CANARY_FAST_PHASE_PROFILE,
        TSMOM_RETEST_P1_STANDARD_CANARY_PHASE_PROFILE,
    }


def active_prior_benchmark_root(args: argparse.Namespace) -> Path:
    configured = getattr(args, "prior_benchmark_root", "")
    if configured:
        return resolve_path(configured)
    return resolve_path(active_phase_profile(args)["prior_benchmark_root"])


def resolve_run_root(args: argparse.Namespace) -> tuple[Path, str]:
    if args.run_root:
        root = resolve_path(args.run_root)
        return root, root.name
    run_id = active_run_id(args)
    base = RESULTS_ROOT / run_id
    if not base.exists():
        return base, run_id
    stamped = RESULTS_ROOT / f"{run_id}_{utc_stamp()}"
    return stamped, stamped.name


def init_context(args: argparse.Namespace) -> Context:
    run_root, _ = resolve_run_root(args)
    if not args.smoke and int(getattr(args, "max_symbols", 0) or 0) > 0:
        raise RuntimeError("--max-symbols is smoke-only; non-smoke runs and launch-gate dry-runs must use full PIT inventory")
    if (
        is_tsmom_retest_profile(getattr(args, "phase_profile", ""))
        and args.run_root
        and args.resume
        and run_root.exists()
        and (run_root / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json").exists()
    ):
        raise RuntimeError("refusing to resume TSMOM retest from a root with an existing wave_gate_decision.json")
    generated_dirs = [
        "preflight", "notifications", "tmux", "seal", "prior", "panels", "engines", "budget", "benchmark",
        "gate", "compiler", "universe", "optimization", "priority", "priority_tranche",
        "coarse", "selection", "materialized", "audit", "controls", "mechanics", "stress", "context",
        "validation", "analysis_ready", "candidate_library", "remote_archive", "decision", "compact_review_bundle", "funding",
        "stage_status", "tmp", "resources", "prelaunch", "engine_wave", "waves", "cross_wave", "concentration",
        "quarantine", "contracts", "resume", "tests", "interruptions", "canary", "current_run", "diagnostics", "performance",
        "ingest", "parameters", "redesign", "classification", "manifest", "binding", "timing", "dry_run", "lineage", "triage", "handoff",
        "watchdog", "tsmom", "prior_high", "contract", "exits", "calibration", "mechanical", "sizing", "regime",
        "active_run", "active", "baseline", "shadow", "cache", "cache_manifests", "registry", "shards", "parallelism",
    ]
    if run_root.exists() and not args.resume:
        for rel in generated_dirs:
            p = run_root / rel
            if p.exists():
                shutil.rmtree(p)
        for rel in ["watch_status.json", "decision_summary.json", "KRAKEN_FAMILY_ENGINE_AGGREGATE_FIRST_SWEEP_REPORT.md"]:
            p = run_root / rel
            if p.exists():
                p.unlink()
    for rel in generated_dirs:
        (run_root / rel).mkdir(parents=True, exist_ok=True)
    start = pd.Timestamp(args.start, tz="UTC") if pd.Timestamp(args.start).tzinfo is None else pd.Timestamp(args.start).tz_convert("UTC")
    end_raw = pd.Timestamp(args.end, tz="UTC") if pd.Timestamp(args.end).tzinfo is None else pd.Timestamp(args.end).tz_convert("UTC")
    end = min(end_raw, SCREENING_END)
    notifier = RunNotifier(run_root, disabled=args.disable_telegram, require_remote=args.require_telegram, allow_no_remote=args.allow_no_telegram)
    ctx = Context(args=args, run_root=run_root, start=start, end=end, notifier=notifier)
    write_status(ctx, "running", "init")
    return ctx


def write_status(ctx: Context, status: str, stage: str = "") -> None:
    write_json(ctx.run_root / "watch_status.json", {"run_root": str(ctx.run_root), "status": status, "stage": stage, "ts_utc": utc_now()})


def stage_done_path(ctx: Context, stage: str) -> Path:
    return ctx.run_root / "stage_status" / f"{stage}.done"


def should_skip(ctx: Context, stage: str) -> bool:
    return bool(ctx.args.resume and stage_done_path(ctx, stage).exists())


def mark_done(ctx: Context, stage: str) -> None:
    write_json(stage_done_path(ctx, stage), {"stage": stage, "status": "done", "ts_utc": utc_now()})


def optimisation_plan_path() -> Path:
    return REPO / "docs/optimisation_plan.md"


def read_optimisation_plan_text() -> str:
    path = optimisation_plan_path()
    if not path.exists():
        raise RuntimeError("docs/optimisation_plan.md is required for cache acceleration foundation")
    return path.read_text(encoding="utf-8")


def cache_foundation_stage_start_check(ctx: Context, stage: str) -> None:
    plan = read_optimisation_plan_text()
    status = "pass" if stage in plan or stage in {"decision-report", "compact-review-bundle"} else "fail"
    append_csv(ctx.run_root / "audit/optimisation_plan_stage_checks.csv", [{
        "ts_utc": utc_now(),
        "stage": stage,
        "docs_path": str(optimisation_plan_path()),
        "docs_sha256": sha256_file(optimisation_plan_path()),
        "stage_listed_in_docs": status == "pass",
        "status": status,
    }])
    if status != "pass":
        raise RuntimeError(f"cache foundation stage `{stage}` not found in docs/optimisation_plan.md")


def run_stage(ctx: Context, stage: str, fn) -> None:
    if should_skip(ctx, stage):
        return
    write_status(ctx, "running", stage)
    if getattr(ctx.args, "phase_profile", "") == CACHE_ACCELERATION_FOUNDATION_PHASE_PROFILE:
        cache_foundation_stage_start_check(ctx, stage)
    ctx.notifier.send("Kraken aggregate engine stage started", f"stage={stage}\nrun_root={ctx.run_root}")
    before = file_size_bytes(ctx.run_root)
    fn(ctx)
    after = file_size_bytes(ctx.run_root)
    ctx.stage_sizes.append({"stage": stage, "size_before_bytes": before, "size_after_bytes": after, "delta_bytes": after - before})
    write_csv(ctx.run_root / "resources/output_budget_by_stage.csv", ctx.stage_sizes)
    mark_done(ctx, stage)
    ctx.notifier.send("Kraken aggregate engine stage completed", f"stage={stage}\nrun_root={ctx.run_root}")


def data_paths(ctx: Context) -> dict[str, Path]:
    root = resolve_path(ctx.args.kraken_data_root)
    return {
        "root": root,
        "trade_5m": root / "parquet/historical_trade_candles_5m",
        "mark_5m": root / "parquet/historical_mark_candles_5m",
        "alt_trade": root / "parquet/trade",
        "alt_mark": root / "parquet/mark",
        "funding": root / "parquet/funding",
        "instruments": root / "parquet/instruments",
        "manifests": root / "manifests",
        "qc": root / "qc",
    }


def find_symbol_files(base: Path, symbol: str) -> list[Path]:
    key = (str(base), str(symbol))
    cached = _FIND_SYMBOL_FILES_CACHE.get(key)
    if cached is not None:
        return list(cached)
    if (base / symbol).is_dir():
        out = sorted((base / symbol).glob("*.parquet"))
    else:
        out = sorted(base.glob(f"{symbol}_*.parquet")) if base.exists() else []
    _FIND_SYMBOL_FILES_CACHE[key] = tuple(out)
    return list(out)


def symbol_from_kraken_path(path: Path) -> str:
    name = path.name
    if path.is_dir():
        return name
    match = re.match(r"^(PF_[A-Z0-9]+USD)(?:_|\\.|$)", name)
    return match.group(1) if match else ""


def symbols_in_dataset(base: Path) -> set[str]:
    out: set[str] = set()
    if not base.exists():
        return out
    for p in base.iterdir():
        sym = symbol_from_kraken_path(p)
        if sym.startswith("PF_"):
            out.add(sym)
    return out


def symbol_file_chunk_starts(files: Sequence[Path]) -> list[pd.Timestamp]:
    starts: list[pd.Timestamp] = []
    for p in files:
        ts = file_chunk_start_ts(p)
        if ts is not None and ts < PROTECTED_TS:
            starts.append(ts)
    return sorted(starts)


def symbol_files_intersect_train(files: Sequence[Path], start: pd.Timestamp, end: pd.Timestamp) -> bool:
    lookback_buffer = pd.Timedelta(days=7)
    for ts in symbol_file_chunk_starts(files):
        if ts <= end and ts >= start - lookback_buffer:
            return True
    return False


def alias_candidates_for_symbol(symbol: str, available_symbols: set[str]) -> list[str]:
    candidates: set[str] = set()
    if "XBT" in symbol:
        candidates.add(symbol.replace("XBT", "BTC"))
    if "BTC" in symbol:
        candidates.add(symbol.replace("BTC", "XBT"))
    base = re.sub(r"^PF_|USD$", "", symbol)
    for s in available_symbols:
        if re.sub(r"^PF_|USD$", "", s) == base:
            candidates.add(s)
    return sorted(candidates & available_symbols)


def file_chunk_start_ts(path: Path) -> pd.Timestamp | None:
    match = re.search(r"(20\d{6}T\d{6})", path.name)
    if not match:
        return None
    try:
        return pd.Timestamp(datetime.strptime(match.group(1), "%Y%m%dT%H%M%S"), tz="UTC")
    except Exception:
        return None


def is_protected_chunk_file(path: Path) -> bool:
    chunk_start = file_chunk_start_ts(path)
    return bool(chunk_start is not None and chunk_start >= PROTECTED_TS)


def pre_holdout_files(files: Sequence[Path]) -> list[Path]:
    return [p for p in files if not is_protected_chunk_file(p)]


RANKABLE_TRAIN_START = pd.Timestamp("2023-01-01T00:00:00Z")


def assert_rankable_file_authority(
    paths: Mapping[str, Any],
    path: Path,
    *,
    funding: bool = False,
) -> None:
    authorities = paths.get("rankable_file_authority")
    authority = authorities.get(str(path)) if isinstance(authorities, Mapping) else None
    if not isinstance(authority, Mapping):
        raise RuntimeError(f"rankable file authority missing or unprovable: {path}")
    if str(authority.get("purpose", "")) != "rankable_research":
        raise RuntimeError(f"rankable file authority purpose rejected: {path}")
    if str(authority.get("venue", "")).lower() != "kraken":
        raise RuntimeError(f"rankable file authority venue rejected: {path}")
    contains_protected = str(authority.get("contains_protected_period", "false")).strip().lower() in {"true", "1"}
    rankable_pre_holdout = str(authority.get("rankable_pre_holdout", "true")).strip().lower() in {"true", "1"}
    if contains_protected or not rankable_pre_holdout:
        raise RuntimeError(f"rankable file authority status rejected: {path}")
    start = pd.to_datetime(authority.get("start_ts"), utc=True, errors="coerce")
    end = pd.to_datetime(authority.get("end_ts"), utc=True, errors="coerce")
    if pd.isna(start) or pd.isna(end) or start > end or end >= PROTECTED_TS:
        raise RuntimeError(f"rankable file authority interval rejected: {path}")
    if funding and str(authority.get("funding_type", "")) != "exact":
        raise RuntimeError(f"rankable file authority funding type rejected: {path}")


def rankable_kraken_rows(df: pd.DataFrame, symbol: str) -> pd.DataFrame:
    keep = pd.Series(True, index=df.index)
    if "venue" in df.columns:
        keep &= df["venue"].astype(str).str.lower().eq("kraken")
    if "venue_symbol" in df.columns:
        keep &= df["venue_symbol"].astype(str).eq(symbol)
    return df.loc[keep]


def explicit_true_rows(values: pd.Series) -> pd.Series:
    return values.astype(str).str.strip().str.lower().isin({"true", "1"})


def list_symbols(paths: Mapping[str, Path], max_symbols: int = 0) -> list[str]:
    syms: set[str] = set()
    for base in [paths["trade_5m"], paths["alt_trade"]]:
        if not base.exists():
            continue
        for p in base.iterdir():
            if p.is_dir() and p.name.startswith("PF_"):
                syms.add(p.name)
            elif p.is_file() and p.name.startswith("PF_"):
                syms.add(p.name.split("_")[0] + "_" + p.name.split("_")[1] if p.name.count("_") >= 1 else p.stem)
    out = sorted(syms)
    return out[:max_symbols] if max_symbols else out


def load_funding(paths: Mapping[str, Any], symbol: str, end: pd.Timestamp) -> pd.DataFrame:
    files = find_symbol_files(paths["funding"], symbol)
    if not files:
        return pd.DataFrame(columns=["timestamp", "fundingRate"])
    frames = []
    for p in files:
        assert_rankable_file_authority(paths, p, funding=True)
        try:
            df = pd.read_parquet(p)
        except Exception:
            continue
        if "timestamp" in df.columns:
            df = df.copy()
            df["timestamp"] = pd.to_datetime(df["timestamp"], utc=True, errors="coerce")
            df = rankable_kraken_rows(df, symbol)
            if "funding_exact" in df.columns:
                df = df[explicit_true_rows(df["funding_exact"])]
            if "funding_imputed" in df.columns:
                df = df[~explicit_true_rows(df["funding_imputed"])]
            frames.append(df[(df["timestamp"] >= RANKABLE_TRAIN_START) & (df["timestamp"] < min(PROTECTED_TS, end + pd.Timedelta(days=1)))])
    return pd.concat(frames, ignore_index=True).drop_duplicates() if frames else pd.DataFrame(columns=["timestamp", "fundingRate"])


def load_symbol_bars(paths: Mapping[str, Any], symbol: str, start: pd.Timestamp, end: pd.Timestamp) -> pd.DataFrame:
    files = find_symbol_files(paths["trade_5m"], symbol) or find_symbol_files(paths["alt_trade"], symbol)
    frames = []
    for p in files:
        assert_rankable_file_authority(paths, p)
        try:
            df = pd.read_parquet(p)
        except Exception:
            continue
        time_col = "time" if "time" in df.columns else ("timestamp" if "timestamp" in df.columns else None)
        if time_col is None or not {"open", "high", "low", "close"}.issubset(df.columns):
            continue
        df = df.copy()
        df["ts"] = parse_time_ms_or_iso(df[time_col])
        df = rankable_kraken_rows(df, symbol)
        df = df[(df["ts"] >= max(start, RANKABLE_TRAIN_START)) & (df["ts"] <= end) & (df["ts"] < PROTECTED_TS)]
        if df.empty:
            continue
        for c in ["open", "high", "low", "close", "volume"]:
            if c in df.columns:
                df[c] = pd.to_numeric(df[c], errors="coerce")
        keep = [c for c in ["ts", "open", "high", "low", "close", "volume", "venue", "venue_symbol", "source_url", "chunk_start_utc", "chunk_end_utc"] if c in df.columns]
        frames.append(df[keep])
    if not frames:
        return pd.DataFrame()
    trade = pd.concat(frames, ignore_index=True).dropna(subset=["ts", "open", "high", "low", "close"])
    trade = trade.sort_values("ts").drop_duplicates("ts", keep="last").reset_index(drop=True)
    mark_files = find_symbol_files(paths["mark_5m"], symbol) or find_symbol_files(paths["alt_mark"], symbol)
    mark_frames = []
    for p in mark_files:
        assert_rankable_file_authority(paths, p)
        try:
            m = pd.read_parquet(p)
        except Exception:
            continue
        time_col = "time" if "time" in m.columns else ("timestamp" if "timestamp" in m.columns else None)
        if time_col is None or "close" not in m.columns:
            continue
        m = m.copy()
        m["ts"] = parse_time_ms_or_iso(m[time_col])
        m = rankable_kraken_rows(m, symbol)
        m = m[(m["ts"] >= max(start, RANKABLE_TRAIN_START)) & (m["ts"] <= end) & (m["ts"] < PROTECTED_TS)]
        if m.empty:
            continue
        for c in ["open", "high", "low", "close"]:
            if c in m.columns:
                m[c] = pd.to_numeric(m[c], errors="coerce")
        cols = ["ts"] + [c for c in ["open", "high", "low", "close"] if c in m.columns]
        mark_frames.append(m[cols].rename(columns={"open": "mark_open", "high": "mark_high", "low": "mark_low", "close": "mark_close"}))
    if mark_frames:
        mark = pd.concat(mark_frames, ignore_index=True).dropna(subset=["ts"]).sort_values("ts").drop_duplicates("ts", keep="last")
        trade = trade.merge(mark, on="ts", how="left")
    else:
        trade["mark_close"] = np.nan
        trade["mark_high"] = np.nan
        trade["mark_low"] = np.nan
    trade["symbol"] = symbol
    if "volume" not in trade.columns:
        trade["volume"] = np.nan
    return trade


def load_symbol_signal_bars(paths: Mapping[str, Path], symbol: str, start: pd.Timestamp, end: pd.Timestamp) -> pd.DataFrame:
    files = pre_holdout_files(find_symbol_files(paths["trade_5m"], symbol) or find_symbol_files(paths["alt_trade"], symbol))
    frames = []
    for p in files:
        df = pd.DataFrame()
        for time_col in ("time", "timestamp"):
            try:
                df = pd.read_parquet(p, columns=[time_col, "close"])
                break
            except Exception:
                df = pd.DataFrame()
        if df.empty:
            continue
        time_col = "time" if "time" in df.columns else ("timestamp" if "timestamp" in df.columns else None)
        if time_col is None or "close" not in df.columns:
            continue
        df = df.copy()
        df["ts"] = parse_time_ms_or_iso(df[time_col])
        df = df[(df["ts"] >= start) & (df["ts"] <= end) & (df["ts"] < PROTECTED_TS)]
        if df.empty:
            continue
        df["close"] = pd.to_numeric(df["close"], errors="coerce")
        frames.append(df[["ts", "close"]])
    if not frames:
        return pd.DataFrame(columns=["ts", "close"])
    out = pd.concat(frames, ignore_index=True).dropna(subset=["ts", "close"])
    return out.sort_values("ts").drop_duplicates("ts", keep="last").reset_index(drop=True)


def full_k0_symbol_inventory_frame(ctx: Context | SimpleNamespace) -> pd.DataFrame:
    paths = data_paths(ctx)
    trade_symbols = symbols_in_dataset(paths["trade_5m"]) | symbols_in_dataset(paths["alt_trade"])
    mark_symbols = symbols_in_dataset(paths["mark_5m"]) | symbols_in_dataset(paths["alt_mark"])
    funding_symbols = symbols_in_dataset(paths["funding"])
    all_symbols = sorted(trade_symbols | mark_symbols | funding_symbols)
    rows: list[dict[str, Any]] = []
    for sym in all_symbols:
        trade_files = pre_holdout_files(find_symbol_files(paths["trade_5m"], sym) or find_symbol_files(paths["alt_trade"], sym))
        mark_files = pre_holdout_files(find_symbol_files(paths["mark_5m"], sym) or find_symbol_files(paths["alt_mark"], sym))
        funding_files = pre_holdout_files(find_symbol_files(paths["funding"], sym))
        trade_starts = symbol_file_chunk_starts(trade_files)
        mark_starts = symbol_file_chunk_starts(mark_files)
        funding_starts = symbol_file_chunk_starts(funding_files)
        all_starts = [*trade_starts, *mark_starts, *funding_starts]
        train_trade = symbol_files_intersect_train(trade_files, ctx.start, ctx.end)
        rows.append({
            "symbol": sym,
            "has_5m_bars": bool(trade_files),
            "has_mark_bars": bool(mark_files),
            "has_funding": bool(funding_files),
            "trade_file_count_pre_holdout": len(trade_files),
            "mark_file_count_pre_holdout": len(mark_files),
            "funding_file_count_pre_holdout": len(funding_files),
            "train_trade_file_count_proxy": sum(1 for ts in trade_starts if ctx.start - pd.Timedelta(days=7) <= ts <= ctx.end),
            "train_mark_file_count_proxy": sum(1 for ts in mark_starts if ctx.start - pd.Timedelta(days=7) <= ts <= ctx.end),
            "train_funding_file_count_proxy": sum(1 for ts in funding_starts if ctx.start - pd.Timedelta(days=7) <= ts <= ctx.end),
            "start_ts": str(min(all_starts)) if all_starts else "",
            "end_ts": str(max(all_starts)) if all_starts else "",
            "bar_rows": len(trade_files),
            "funding_rows": len(funding_files),
            "status": "available" if train_trade else ("missing_train_bars" if trade_files else "missing_bars"),
            "lifecycle_eligible_train_window": bool(train_trade),
            "liquidity_proxy_source": "pre_holdout_trade_file_chunks_plus_funding_file_chunks",
        })
    return pd.DataFrame(rows)


def full_panel_for_launch_gate(ctx: Context | SimpleNamespace) -> pd.DataFrame:
    inventory = full_k0_symbol_inventory_frame(ctx)
    if inventory.empty:
        return inventory
    panel = inventory.copy()
    panel["bar_rows"] = pd.to_numeric(panel.get("train_trade_file_count_proxy", 0), errors="coerce").fillna(0)
    panel["funding_rows"] = pd.to_numeric(panel.get("train_funding_file_count_proxy", 0), errors="coerce").fillna(0)
    panel["status"] = np.where(panel["lifecycle_eligible_train_window"].astype(bool), "available", "missing_train_bars")
    return panel


def trailing_30d_liquidity_proxy(paths: Mapping[str, Path], symbol: str, checkpoint_ts: pd.Timestamp) -> dict[str, Any]:
    files = pre_holdout_files(find_symbol_files(paths["trade_5m"], symbol) or find_symbol_files(paths["alt_trade"], symbol))
    funding_files = pre_holdout_files(find_symbol_files(paths["funding"], symbol))
    checkpoint = ts_utc(checkpoint_ts)
    start = checkpoint - pd.Timedelta(days=30)
    trade_chunk_files = [p for p in files if (ts := file_chunk_start_ts(p)) is not None and start <= ts <= checkpoint]
    funding_chunk_files = [p for p in funding_files if (ts := file_chunk_start_ts(p)) is not None and start <= ts <= checkpoint]
    trade_bytes = sum(p.stat().st_size for p in trade_chunk_files if p.exists())
    funding_bytes = sum(p.stat().st_size for p in funding_chunk_files if p.exists())
    hash_tie_breaker = int(hashlib.sha256(symbol.encode("utf-8")).hexdigest()[:8], 16) / 1e12
    score = float(trade_bytes + funding_bytes * 0.01 + hash_tie_breaker)
    return {
        "trailing_30d_trade_file_count": len(trade_chunk_files),
        "trailing_30d_funding_file_count": len(funding_chunk_files),
        "trailing_30d_notional_proxy": "",
        "trailing_30d_notional_rows": "",
        "trailing_30d_trade_file_bytes": trade_bytes,
        "trailing_30d_funding_file_bytes": funding_bytes,
        "pit_liquidity_proxy_score": float(score),
        "pit_liquidity_proxy_basis": "trailing_30d_file_size_coverage_proxy_with_hash_tiebreaker",
    }


def pit_liquidity_ranking_by_checkpoint(ctx: Context | SimpleNamespace, panel: pd.DataFrame, checkpoint_ts: pd.Timestamp) -> pd.DataFrame:
    paths = data_paths(ctx)
    symbols_key = stable_hash(*panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), n=24) if not panel.empty else "empty"
    cache_key = (str(paths["root"]), ts_utc(checkpoint_ts).isoformat(), symbols_key)
    cached = _PIT_LIQUIDITY_RANKING_CACHE.get(cache_key)
    if cached is not None:
        return cached.copy()
    chunks_key = (str(paths["root"]), symbols_key)
    chunks = _PIT_LIQUIDITY_CHUNK_META_CACHE.get(chunks_key)
    if chunks is None:
        chunks = tsmom_precompute_liquidity_chunk_metadata(ctx, panel)
        _PIT_LIQUIDITY_CHUNK_META_CACHE[chunks_key] = chunks
    lifecycle = _PIT_LIFECYCLE_META_CACHE.get(symbols_key)
    if lifecycle is None:
        lifecycle = precompute_panel_lifecycle(panel)
        _PIT_LIFECYCLE_META_CACHE[symbols_key] = lifecycle
    rows: list[dict[str, Any]] = []
    for sym in panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist():
        eligible, reason = panel_lifecycle_eligible_precomputed(lifecycle, panel, sym, checkpoint_ts)
        rows.append({
            "symbol": sym,
            "checkpoint_ts": ts_utc(checkpoint_ts).isoformat(),
            "eligible_at_checkpoint": bool(eligible),
            "eligibility_reason": reason,
            **trailing_30d_liquidity_proxy_from_chunk_metadata(chunks, sym, checkpoint_ts),
        })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out = out.sort_values(["eligible_at_checkpoint", "pit_liquidity_proxy_score", "symbol"], ascending=[False, False, True]).reset_index(drop=True)
    out["pit_rank"] = np.arange(1, len(out) + 1)
    _PIT_LIQUIDITY_RANKING_CACHE[cache_key] = out.copy()
    return out


def tsmom_policy_symbols_at_checkpoint_v3(ctx: Context | SimpleNamespace, definition: Mapping[str, Any], panel: pd.DataFrame, checkpoint_ts: pd.Timestamp) -> tuple[list[str], pd.DataFrame]:
    policy = str(definition.get("universe_policy", "") or "").strip()
    top_limit = int(safe_float(definition.get("top_major_target_size", TSMOM_TOP_MAJOR_UNIVERSE_LIMIT), TSMOM_TOP_MAJOR_UNIVERSE_LIMIT))
    tier_limit = int(safe_float(definition.get("tier_ab_target_size", TSMOM_TIER_AB_UNIVERSE_LIMIT), TSMOM_TIER_AB_UNIVERSE_LIMIT))
    ranked = pit_liquidity_ranking_by_checkpoint(ctx, panel, checkpoint_ts)
    if ranked.empty:
        return [], ranked
    eligible = ranked[ranked["eligible_at_checkpoint"].astype(bool)].copy()
    if policy == "pit_liquidity_top_majors":
        majors = eligible[eligible["symbol"].isin(REDESIGNED_EXPECTED_MAJORS)].copy()
        selected = majors.sort_values(["pit_liquidity_proxy_score", "symbol"], ascending=[False, True]).head(top_limit)
        if len(selected) < top_limit:
            fill = eligible[~eligible["symbol"].isin(selected["symbol"])].head(top_limit - len(selected))
            selected = pd.concat([selected, fill], ignore_index=True)
        minimum_size = min(8, top_limit)
    elif policy == "pit_liquidity_tier_ab":
        selected = eligible.head(tier_limit)
        minimum_size = min(30, tier_limit)
    else:
        selected = eligible.head(tier_limit)
        minimum_size = min(30, tier_limit)
    symbols = selected["symbol"].astype(str).tolist()
    audit = ranked.copy()
    audit["included"] = audit["symbol"].isin(symbols)
    audit["universe_policy"] = policy
    audit["configured_target_size"] = top_limit if policy == "pit_liquidity_top_majors" else tier_limit
    audit["configured_minimum_size"] = minimum_size
    audit["selected_symbol_count"] = len(symbols)
    audit["inclusion_exclusion_reason"] = np.where(
        audit["included"],
        "included_by_pit_liquidity_policy_v3",
        np.where(audit["eligible_at_checkpoint"], "eligible_but_outside_policy_rank_or_limit", audit["eligibility_reason"]),
    )
    return symbols, audit


def read_panel_manifest_cached(path_value: Any) -> pd.DataFrame:
    path_s = str(path_value or "").strip()
    if not path_s:
        return pd.DataFrame()
    cached = _PANEL_MANIFEST_CACHE.get(path_s)
    if cached is not None:
        return cached.copy()
    path = resolve_path(path_s)
    panel = read_csv_safe(path)
    _PANEL_MANIFEST_CACHE[path_s] = panel.copy()
    return panel


def candidate_ctx_for_pit_policy(candidate: Mapping[str, Any]) -> SimpleNamespace:
    root = str(candidate.get("kraken_data_root", DEFAULT_KRAKEN_DATA_ROOT) or DEFAULT_KRAKEN_DATA_ROOT)
    start = pd.to_datetime(candidate.get("run_start_ts", SCREENING_END - pd.Timedelta(days=730)), utc=True, errors="coerce")
    end = pd.to_datetime(candidate.get("run_end_ts", SCREENING_END), utc=True, errors="coerce")
    return SimpleNamespace(
        args=SimpleNamespace(kraken_data_root=root),
        start=start if pd.notna(start) else SCREENING_END - pd.Timedelta(days=730),
        end=end if pd.notna(end) else SCREENING_END,
    )


def pit_policy_symbols_for_decision(candidate: Mapping[str, Any], decision_ts: pd.Timestamp) -> tuple[str, ...]:
    policy = str(candidate.get("universe_policy", "") or "").strip()
    if not policy:
        return tuple()
    panel = read_panel_manifest_cached(candidate.get("pit_panel_manifest_path", ""))
    if panel.empty:
        return tuple()
    root = str(candidate.get("kraken_data_root", DEFAULT_KRAKEN_DATA_ROOT) or DEFAULT_KRAKEN_DATA_ROOT)
    key = (
        root,
        str(candidate.get("universe_policy_hash", policy)),
        str(candidate.get("top_major_target_size", "")),
        str(candidate.get("tier_ab_target_size", "")),
        ts_utc(decision_ts).isoformat(),
        stable_hash(*panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), n=24),
    )
    cached = _PIT_POLICY_SYMBOLS_CACHE.get(key)
    if cached is not None:
        return cached
    symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(candidate_ctx_for_pit_policy(candidate), candidate, panel, ts_utc(decision_ts))
    out = tuple(symbols)
    _PIT_POLICY_SYMBOLS_CACHE[key] = out
    return out


def trailing_rank_metric_from_bars(bars: pd.DataFrame, decision_ts: pd.Timestamp, lookback_days: int, metric: str) -> tuple[float, str]:
    decision = ts_utc(decision_ts)
    if bars.empty or "ts" not in bars.columns or "close" not in bars.columns:
        return float("nan"), ""
    work = bars[["ts", "close"]].copy()
    work["ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce")
    work["close"] = pd.to_numeric(work["close"], errors="coerce")
    eligible = work[(work["ts"] < decision) & work["close"].notna()].sort_values("ts")
    if len(eligible) < 2:
        return float("nan"), ""
    recent = eligible[eligible["ts"] >= decision - pd.Timedelta(days=max(1, int(lookback_days)))]
    if len(recent) < 2:
        return float("nan"), ""
    first = safe_float(recent["close"].iloc[0], np.nan)
    last = safe_float(recent["close"].iloc[-1], np.nan)
    if not math.isfinite(first) or not math.isfinite(last) or first <= 0:
        return float("nan"), ""
    ret = last / first - 1.0
    metric_s = str(metric or "trailing_return").strip().lower()
    if metric_s in {"risk_adjusted_return", "risk_adjusted", "sharpe_like"}:
        rets = pd.to_numeric(recent["close"], errors="coerce").pct_change().dropna()
        vol = float(rets.std()) if len(rets) else float("nan")
        score = ret / vol if math.isfinite(vol) and vol > 0 else float("nan")
    elif metric_s in {"relative_strength", "trailing_return", "return"}:
        score = ret
    else:
        score = float("nan")
    return float(score), str(recent["ts"].iloc[-1])


def trailing_rank_metric_at_decision(paths: Mapping[str, Path], symbol: str, decision_ts: pd.Timestamp, lookback_days: int, metric: str) -> tuple[float, str]:
    decision = ts_utc(decision_ts)
    start = decision - pd.Timedelta(days=max(1, int(lookback_days)) + 2)
    bars = load_symbol_bars(paths, symbol, start, decision)
    return trailing_rank_metric_from_bars(bars, decision, lookback_days, metric)


def symbol_files_for_window(files: Sequence[Path], start: pd.Timestamp, end: pd.Timestamp) -> list[Path]:
    start = ts_utc(start)
    end = ts_utc(end)
    out: list[Path] = []
    for p in pre_holdout_files(files):
        chunk_ts = file_chunk_start_ts(p)
        if chunk_ts is None:
            out.append(p)
            continue
        # Kraken candle chunks are day-sized in the local data; include adjacent
        # chunks so boundary bars are not dropped before row-level timestamp filter.
        if start - pd.Timedelta(days=1) <= chunk_ts <= end + pd.Timedelta(days=1):
            out.append(p)
    return out


def load_symbol_rank_close_window(paths: Mapping[str, Path], symbol: str, start: pd.Timestamp, end: pd.Timestamp) -> pd.DataFrame:
    files = find_symbol_files(paths["trade_5m"], symbol) or find_symbol_files(paths["alt_trade"], symbol)
    frames: list[pd.DataFrame] = []
    for p in symbol_files_for_window(files, start, end):
        try:
            try:
                df = pd.read_parquet(p, columns=["time", "close"])
                time_col = "time"
            except Exception:
                df = pd.read_parquet(p, columns=["timestamp", "close"])
                time_col = "timestamp"
        except Exception:
            continue
        if time_col not in df.columns or "close" not in df.columns:
            continue
        work = df[[time_col, "close"]].copy()
        work["ts"] = parse_time_ms_or_iso(work[time_col])
        work["close"] = pd.to_numeric(work["close"], errors="coerce")
        work = work[(work["ts"] >= start) & (work["ts"] < end) & (work["ts"] < PROTECTED_TS)].dropna(subset=["ts", "close"])
        if not work.empty:
            frames.append(work[["ts", "close"]])
    if not frames:
        return pd.DataFrame(columns=["ts", "close"])
    return pd.concat(frames, ignore_index=True).sort_values("ts").drop_duplicates("ts", keep="last").reset_index(drop=True)


def rank_score_bundle_from_close_window(close_window: pd.DataFrame, decision_ts: pd.Timestamp, lookback_days: int) -> dict[str, Any]:
    if close_window.empty:
        return {"source_ts": "", "trailing_return": float("nan"), "risk_adjusted_return": float("nan"), "relative_strength": float("nan")}
    decision = ts_utc(decision_ts)
    recent = close_window.copy()
    recent["ts"] = pd.to_datetime(recent["ts"], utc=True, errors="coerce")
    recent["close"] = pd.to_numeric(recent["close"], errors="coerce")
    recent = recent[(recent["ts"] < decision) & (recent["ts"] >= decision - pd.Timedelta(days=max(1, int(lookback_days))))].dropna(subset=["ts", "close"]).sort_values("ts")
    if len(recent) < 2:
        return {"source_ts": "", "trailing_return": float("nan"), "risk_adjusted_return": float("nan"), "relative_strength": float("nan")}
    first = safe_float(recent["close"].iloc[0], np.nan)
    last = safe_float(recent["close"].iloc[-1], np.nan)
    if not math.isfinite(first) or not math.isfinite(last) or first <= 0:
        return {"source_ts": "", "trailing_return": float("nan"), "risk_adjusted_return": float("nan"), "relative_strength": float("nan")}
    ret = last / first - 1.0
    rets = pd.to_numeric(recent["close"], errors="coerce").pct_change().dropna()
    vol = float(rets.std()) if len(rets) else float("nan")
    risk_adjusted = ret / vol if math.isfinite(vol) and vol > 0 else float("nan")
    return {
        "source_ts": str(recent["ts"].iloc[-1]),
        "trailing_return": float(ret),
        "risk_adjusted_return": float(risk_adjusted),
        "relative_strength": float(ret),
    }


def rank_symbol_bars_for_candidate(candidate: Mapping[str, Any], symbol: str, lookback_days: int) -> pd.DataFrame:
    root = str(candidate.get("kraken_data_root", DEFAULT_KRAKEN_DATA_ROOT) or DEFAULT_KRAKEN_DATA_ROOT)
    run_start = pd.to_datetime(candidate.get("run_start_ts", SCREENING_END - pd.Timedelta(days=730)), utc=True, errors="coerce")
    run_end = pd.to_datetime(candidate.get("run_end_ts", SCREENING_END), utc=True, errors="coerce")
    if pd.isna(run_start):
        run_start = SCREENING_END - pd.Timedelta(days=730)
    if pd.isna(run_end):
        run_end = SCREENING_END
    start = ts_utc(run_start) - pd.Timedelta(days=max(1, int(lookback_days)) + 2)
    end = ts_utc(run_end)
    key = (root, str(symbol), start.isoformat(), end.isoformat())
    cached = _RANK_SYMBOL_BARS_CACHE.get(key)
    if cached is not None:
        return cached
    paths = local_data_paths_from_root(root)
    # Ranking needs only completed close values. Loading full OHLCV+mark
    # history here makes per-decision top-N checks pathologically slow and
    # memory-heavy while adding no ranking information.
    bars = load_symbol_rank_close_window(paths, str(symbol), start, end)
    _RANK_SYMBOL_BARS_CACHE[key] = bars
    return bars


def rank_top_n_symbols_for_decision(candidate: Mapping[str, Any], decision_ts: pd.Timestamp) -> tuple[str, ...]:
    topn = int(safe_float(candidate.get("rank_top_n", 0), 0))
    if topn <= 0:
        return tuple()
    policy_symbols = pit_policy_symbols_for_decision(candidate, decision_ts)
    if not policy_symbols:
        return tuple()
    root = str(candidate.get("kraken_data_root", DEFAULT_KRAKEN_DATA_ROOT) or DEFAULT_KRAKEN_DATA_ROOT)
    lookback_days = int(safe_float(candidate.get("lookback_days", 0), 0) or max(1, int(safe_float(candidate.get("lookback_bars", 288), 288)) // 288))
    metric = str(candidate.get("rank_metric", "trailing_return") or "trailing_return")
    key = (
        root,
        str(candidate.get("universe_policy_hash", candidate.get("universe_policy", ""))),
        str(candidate.get("rank_policy_hash", "")),
        ts_utc(decision_ts).isoformat(),
        metric,
        topn,
        lookback_days,
        stable_hash(*policy_symbols, n=24),
    )
    cached = _RANK_TOP_N_DECISION_CACHE.get(key)
    if cached is not None:
        return cached
    rows: list[dict[str, Any]] = []
    for sym in policy_symbols:
        bars = rank_symbol_bars_for_candidate(candidate, sym, lookback_days)
        score, source_ts = trailing_rank_metric_from_bars(bars, decision_ts, lookback_days, metric)
        if math.isfinite(score) and source_ts and ts_utc(source_ts) < ts_utc(decision_ts):
            rows.append({"symbol": sym, "score": score, "source_ts": source_ts})
    if not rows:
        out: tuple[str, ...] = tuple()
    else:
        ranked = pd.DataFrame(rows)
        ranked["tie_break_hash"] = ranked["symbol"].astype(str).map(lambda s: stable_hash(s, n=16))
        ranked = ranked.sort_values(["score", "tie_break_hash"], ascending=[False, True], kind="mergesort").head(topn)
        out = tuple(ranked["symbol"].astype(str).tolist())
    _RANK_TOP_N_DECISION_CACHE[key] = out
    return out


def candidate_event_universe_allowed(candidate: Mapping[str, Any], symbol: str, decision_ts: pd.Timestamp) -> bool:
    policy = str(candidate.get("universe_policy", "") or "").strip()
    if not policy:
        return True
    symbols = pit_policy_symbols_for_decision(candidate, decision_ts)
    if not symbols or str(symbol) not in set(symbols):
        return False
    if str(candidate.get("family_engine_id", "")) == "scheduled_tsmom_engine" and int(safe_float(candidate.get("rank_top_n", 0), 0)) > 0:
        return str(symbol) in set(rank_top_n_symbols_for_decision(candidate, decision_ts))
    return True


def universe_symbols_are_alphabetical_first_n(symbols: Sequence[str], all_symbols: Sequence[str]) -> bool:
    selected = [str(s) for s in symbols]
    return bool(selected and selected == sorted([str(s) for s in all_symbols])[: len(selected)])


def load_contract_sources(readiness_root: Path, repair_root: Path) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    for root, source in [(readiness_root, "readiness"), (repair_root, "repair")]:
        trace = read_csv_safe(root / "compiler/hypothesis_to_contract_trace.csv")
        if not trace.empty:
            for _, r in trace.iterrows():
                rows.append({
                    "hypothesis_id": r.get("hypothesis_id", ""),
                    "family": r.get("family", r.get("source_sheet", "unknown")),
                    "contract_id": r.get("contract_id", stable_hash(source, r.get("hypothesis_id", ""))),
                    "contract_source": source,
                    "allowed_lane": r.get("lane", r.get("compile_decision", "kraken_tier1_ready")),
                    "archetype": infer_archetype_from_row(r),
                })
        comp_dir = root / "compiler/compiled_contracts"
        for p in sorted(comp_dir.glob("*.json")) if comp_dir.exists() else []:
            obj = read_json(p, {})
            hid = str(obj.get("hypothesis_id") or obj.get("id") or p.stem)
            rows.append({
                "hypothesis_id": hid,
                "family": str(obj.get("family", obj.get("strategy_family", "unknown"))),
                "contract_id": str(obj.get("contract_id", p.stem)),
                "contract_source": source,
                "allowed_lane": str(obj.get("lane", obj.get("allowed_lane", "kraken_tier1_ready"))),
                "archetype": infer_archetype_from_text(" ".join(map(str, obj.values()))),
            })
    if not rows:
        # Safe fallback used for smoke/tests if readiness artifacts are absent.
        rows = [
            {"hypothesis_id": "H02", "family": "Liquid continuation / Momentum", "contract_id": "fallback_H02", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "tsmom"},
            {"hypothesis_id": "H13", "family": "Liquid continuation / Momentum", "contract_id": "fallback_H13", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "liquid_continuation"},
            {"hypothesis_id": "H03", "family": "Prior-high / ATH / reclaim", "contract_id": "fallback_H03", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "prior_high"},
            {"hypothesis_id": "H04", "family": "Retest / Reclaim", "contract_id": "fallback_H04", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "retest_reclaim"},
            {"hypothesis_id": "H12", "family": "Compression breakout", "contract_id": "fallback_H12", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "compression_breakout"},
            {"hypothesis_id": "H09", "family": "Session / Calendar / Flow", "contract_id": "fallback_H09", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "session_calendar"},
            {"hypothesis_id": "H07", "family": "Funding / Basis / Crowding", "contract_id": "fallback_H07", "contract_source": "fallback", "allowed_lane": "kraken_tier1_ready", "archetype": "funding_crowding"},
        ]
    df = pd.DataFrame(rows).drop_duplicates(["hypothesis_id", "contract_id", "archetype"])
    df["family_engine_id"] = df["archetype"].map(ARCHETYPE_ENGINE_ID).fillna("liquid_continuation_breakout_engine")
    return df


def infer_archetype_from_row(row: Mapping[str, Any]) -> str:
    return infer_archetype_from_text(" ".join(str(v) for v in dict(row).values()))


def infer_archetype_from_text(text: str) -> str:
    t = text.lower()
    if "tsmom" in t or "time-series" in t or "volatility-managed" in t:
        return "tsmom"
    if "session" in t or "calendar" in t or "time-of-day" in t:
        return "session_calendar"
    if "funding" in t or "crowding" in t or "basis" in t:
        return "funding_crowding"
    if "compression" in t or "squeeze" in t:
        return "compression_breakout"
    if "retest" in t or "reclaim" in t:
        return "retest_reclaim"
    if "prior" in t or "ath" in t or "high" in t:
        return "prior_high"
    return "liquid_continuation"


def canonical_definition_rows(rank_df: pd.DataFrame) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    kinds = [
        ("plain_baseline", 12, 24, 150.0, 0.005, "fixed_hold", "fixed_bps", "intended_regime", "long"),
        ("conservative", 24, 12, 100.0, 0.010, "fixed_hold", "atr_proxy", "intended_regime", "short"),
        ("aggressive", 48, 36, 300.0, 0.0025, "target_R", "breakout_bar_extreme", "intended_regime", "long"),
        ("alternative_exit", 96, 48, 200.0, 0.005, "ema_trail", "structure", "intended_regime", "short"),
        ("alternative_stop", 144, 24, 250.0, 0.0075, "structure_loss", "structure", "intended_regime", "long"),
        ("all_context_diagnostic", 72, 24, 200.0, 0.005, "fixed_hold", "fixed_bps", "all_context_diagnostic", "long"),
        ("all_context_alt", 36, 18, 175.0, 0.006, "structure_loss", "atr_proxy", "all_context_diagnostic", "short"),
    ]
    for _, r in rank_df.iterrows():
        for kind, lookback, hold, stop_bps, threshold, exit_t, stop_t, regime, side in kinds:
            did = f"canon__{r['hypothesis_id']}__{stable_hash(r.get('archetype'), kind, lookback, hold, stop_bps, threshold, side, n=12)}"
            rows.append({
                "definition_id": did,
                "hypothesis_id": r["hypothesis_id"],
                "family": r["family"],
                "contract_id": r["contract_id"],
                "contract_source": r["contract_source"],
                "allowed_lane": r.get("allowed_lane", "kraken_tier1_ready"),
                "family_engine_id": r["family_engine_id"],
                "archetype": r["archetype"],
                "definition_kind": kind,
                "entry_template": f"{r['archetype']}_close_confirmed",
                "exit_template": exit_t,
                "stop_template": stop_t,
                "regime_activation": regime,
                "regime_variant": regime,
                "side": side,
                "lookback_bars": lookback,
                "hold_bars": hold,
                "stop_bps": stop_bps,
                "threshold": threshold,
                "canonical": True,
                "data_cap": "none",
            })
    return pd.DataFrame(rows)


def deterministic_space_fill(rank_df: pd.DataFrame, target_defs: int, seed: int) -> tuple[pd.DataFrame, pd.DataFrame]:
    rows: list[dict[str, Any]] = []
    rejected: list[dict[str, Any]] = []
    if target_defs <= 0 or rank_df.empty:
        return pd.DataFrame(rows), pd.DataFrame(rejected)
    rng = random.Random(seed)
    lookbacks = [12, 24, 36, 48, 72, 96, 144, 288]
    holds = [6, 12, 24, 36, 48, 96, 288]
    stops = [75, 100, 150, 200, 250, 300, 500]
    thresholds = [0.001, 0.0025, 0.005, 0.0075, 0.01, 0.015]
    exits = ["fixed_hold", "target_R", "ema_trail", "structure_loss"]
    stop_templates = ["fixed_bps", "atr_proxy", "structure", "breakout_bar_extreme"]
    sides = ["long", "short"]
    rank_rows = rank_df.to_dict("records")
    attempts = 0
    while len(rows) < target_defs and attempts < target_defs * 10:
        r = rank_rows[attempts % len(rank_rows)]
        lb = lookbacks[(attempts + rng.randrange(len(lookbacks))) % len(lookbacks)]
        hold = holds[(attempts * 3 + rng.randrange(len(holds))) % len(holds)]
        stop = stops[(attempts * 5 + rng.randrange(len(stops))) % len(stops)]
        th = thresholds[(attempts * 7 + rng.randrange(len(thresholds))) % len(thresholds)]
        side = sides[(attempts + rng.randrange(2)) % 2]
        exit_t = exits[(attempts * 2 + rng.randrange(len(exits))) % len(exits)]
        stop_t = stop_templates[(attempts * 3 + rng.randrange(len(stop_templates))) % len(stop_templates)]
        attempts += 1
        if hold < 2 or stop <= 0:
            rejected.append({"hypothesis_id": r["hypothesis_id"], "reason": "invalid_hold_or_stop"})
            continue
        did = f"sf__{r['hypothesis_id']}__{stable_hash(r.get('archetype'), attempts, lb, hold, stop, th, side, exit_t, stop_t, n=12)}"
        rows.append({
            "definition_id": did,
            "hypothesis_id": r["hypothesis_id"],
            "family": r["family"],
            "contract_id": r["contract_id"],
            "contract_source": r["contract_source"],
            "allowed_lane": r.get("allowed_lane", "kraken_tier1_ready"),
            "family_engine_id": r["family_engine_id"],
            "archetype": r["archetype"],
            "definition_kind": "space_filling",
            "entry_template": f"{r['archetype']}_close_confirmed",
            "exit_template": exit_t,
            "stop_template": stop_t,
            "regime_activation": "intended_regime" if attempts % 3 else "all_context_diagnostic",
            "regime_variant": "intended_regime" if attempts % 3 else "all_context_diagnostic",
            "side": side,
            "lookback_bars": lb,
            "hold_bars": hold,
            "stop_bps": float(stop),
            "threshold": float(th),
            "canonical": False,
            "data_cap": "none",
        })
    return pd.DataFrame(rows), pd.DataFrame(rejected)


def generate_candidate_registry(defs: pd.DataFrame, symbols: Sequence[str], budget: int) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    selected = defs.head(max(0, budget)) if budget else defs.iloc[0:0]
    universe_hash = stable_hash(*symbols, n=24)
    for _, d in selected.iterrows():
        engine = ENGINES[str(d["family_engine_id"])]
        base = identity_enriched_record(d.to_dict(), engine)
        for sym in symbols:
            rows.append({**identity_enriched_record(base, engine, symbol=sym),
                "symbol_universe_hash": universe_hash,
                "engine_contract_hash": engine.engine_contract_hash(),
                "event_semantics_version": EVENT_SEMANTICS_VERSION,
                "row_semantics": engine.row_semantics(),
                "contract_event_type": engine.contract_event_type(),
            })
    return pd.DataFrame(rows)


def generate_candidate_registry_for_family_universe(defs: pd.DataFrame, universe: Mapping[str, Sequence[str]], budget: int = 0, *, panel: pd.DataFrame | None = None, ctx: Context | None = None) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    selected = defs.head(max(0, budget)) if budget else defs
    for _, d in selected.iterrows():
        engine_id = str(d["family_engine_id"])
        engine = ENGINES[engine_id]
        if engine_id in {"scheduled_tsmom_engine", "prior_high_reclaim_engine"} and str(d.get("universe_policy", "")).strip() and panel is not None:
            # Registry rows must be the union of the same point-in-time policy that
            # event generation enforces at each decision timestamp. The event-time
            # filter remains authoritative, but the registry must not fan out to a
            # generic/static universe that can later be misread as intended scope.
            checkpoints = universe_checkpoints(ctx, panel) if ctx is not None else [("final_pre_holdout", SCREENING_END)]
            symbols = []
            seen: set[str] = set()
            pit_ctx = ctx or SimpleNamespace(args=SimpleNamespace(kraken_data_root=str(DEFAULT_KRAKEN_DATA_ROOT)), start=SCREENING_END - pd.Timedelta(days=365), end=SCREENING_END)
            for _, ts in checkpoints:
                checkpoint_symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(pit_ctx, d.to_dict(), panel, ts)
                for sym in checkpoint_symbols:
                    if sym not in seen:
                        symbols.append(sym)
                        seen.add(sym)
        else:
            symbols = list(universe.get(engine_id, []))
        universe_hash = stable_hash(engine_id, *symbols, n=24)
        base = identity_enriched_record(d.to_dict(), engine)
        for sym in symbols:
            panel_rec = panel_record_for_symbol(panel, sym) if panel is not None else {}
            rows.append({**identity_enriched_record(base, engine, symbol=sym),
                "symbol_universe_hash": universe_hash,
                "pit_universe_hash": universe_hash,
                "symbol_panel_start_ts": panel_rec.get("start_ts", ""),
                "symbol_panel_end_ts": panel_rec.get("end_ts", ""),
                "symbol_panel_status": panel_rec.get("status", ""),
                "pit_panel_manifest_path": str(ctx.run_root / "panels/aggregate_panel_manifest.csv") if ctx is not None and panel is not None else "",
                "kraken_data_root": str(resolve_path(ctx.args.kraken_data_root)) if ctx is not None else str(DEFAULT_KRAKEN_DATA_ROOT),
                "run_start_ts": str(ctx.start) if ctx is not None else "",
                "run_end_ts": str(ctx.end) if ctx is not None else "",
                "pit_universe_event_time_check": bool(str(d.get("universe_policy", "")).strip()),
                "rank_top_n_event_time_check": bool(engine_id == "scheduled_tsmom_engine" and safe_float(d.get("rank_top_n", 0), 0) > 0),
                "liquidity_proxy_universe_cap": bool(str(base.get("universe_liquidity_metric_source", "")).startswith("proxy") or panel is not None),
                "engine_contract_hash": engine.engine_contract_hash(),
                "event_semantics_version": EVENT_SEMANTICS_VERSION,
                "row_semantics": engine.row_semantics(),
                "contract_event_type": engine.contract_event_type(),
            })
    return pd.DataFrame(rows)


def stage_preflight(ctx: Context) -> None:
    paths = [
        resolve_path(ctx.args.k0_root), resolve_path(ctx.args.readiness_root), resolve_path(ctx.args.repair_root),
        resolve_path(ctx.args.mechanical_qa_root), resolve_path(ctx.args.sampled_sweep_root), resolve_path(ctx.args.bruteforce_root),
        active_prior_benchmark_root(ctx.args), resolve_path(ctx.args.structural_repair_root), resolve_path(ctx.args.stat_protocol_repair_root), resolve_path(ctx.args.p1_repair_root),
        resolve_path(ctx.args.global_audit_root), resolve_path(ctx.args.hypothesis_library), resolve_path(ctx.args.research_input_dir), resolve_path(ctx.args.kraken_data_root), Path(__file__).resolve(),
        REPO / "tools/qlmg_evidence_contracts.py", REPO / "tools/qlmg_real_controls.py", REPO / "tools/qlmg_screening_core.py",
        REPO / "tools/kraken_aggregate_cache_layer.py",
    ]
    manifest = []
    hashes: dict[str, Any] = {}
    for p in paths:
        rec = {"path": str(p), "exists": p.exists(), "is_dir": p.is_dir(), "size_bytes": file_size_bytes(p)}
        if p.is_file():
            rec["sha256"] = sha256_file(p)
            hashes[str(p)] = rec["sha256"]
        elif p.is_dir():
            files = sorted([x for x in p.rglob("*") if x.is_file()])[:200]
            rec["sample_file_count_hashed"] = len(files)
            hashes[str(p)] = stable_hash(*[str(x.relative_to(p)) + ":" + sha256_file(x, limit_mb=1) for x in files], n=64)
        manifest.append(rec)
    write_csv(ctx.run_root / "preflight/input_artifact_manifest.csv", manifest)
    write_json(ctx.run_root / "preflight/input_manifest.json", {"inputs": manifest, "active_phase_profile": ctx.args.phase_profile, "active_stage_sequence": active_stage_list(ctx.args), "global_audit_root": str(resolve_path(ctx.args.global_audit_root))})
    code_rows = [r for r in manifest if str(r.get("path", "")).endswith(".py")]
    write_csv(ctx.run_root / "preflight/code_hash_manifest.csv", code_rows)
    try:
        commit = subprocess.check_output(["git", "rev-parse", "HEAD"], cwd=REPO, text=True, stderr=subprocess.DEVNULL).strip()
    except Exception:
        commit = "unknown"
    try:
        status_snapshot = subprocess.check_output(["git", "status", "--short"], cwd=REPO, text=True, stderr=subprocess.DEVNULL)
    except Exception:
        status_snapshot = "git status unavailable\n"
    write_text(ctx.run_root / "preflight/git_status_snapshot.txt", status_snapshot)
    hashes["git_commit"] = commit
    write_json(ctx.run_root / "preflight/frozen_artifact_hashes.json", hashes)
    snap = resource_snapshot(ctx.run_root)
    guard = check_resource_guard(snap, estimated_output_gb=0.1, hard_stage_output_gb=ctx.args.max_output_gb, allow_large_output=ctx.args.allow_large_output)
    write_text(ctx.run_root / "preflight/preflight_report.md", f"# Preflight Report\n\nRun root: `{ctx.run_root}`\nGit commit: `{commit}`\nResource guard: `{guard['status']}`\nFree disk GB: `{guard['free_disk_gb']:.2f}`\n")
    write_text(ctx.run_root / "preflight/phase_profile_reproducibility_report.md", "\n".join([
        "# Phase Profile Reproducibility Report",
        "",
        f"Active phase profile: `{ctx.args.phase_profile}`",
        f"Active run id: `{active_run_id(ctx.args)}`",
        f"Active stage sequence: `{','.join(active_stage_list(ctx.args))}`",
        f"Active prior benchmark root: `{active_prior_benchmark_root(ctx.args)}`",
        f"Callable profiles: `{','.join(sorted(PHASE_PROFILES))}`",
        "",
        "Prior profiles remain callable through `--phase-profile`; explicit `--run-root` still reproduces old run roots without changing repo behavior.",
        "This phase launches only the work authorized by its phase profile. The engine-wave v0 profile is train-only and never launches the broad 1,693-definition tranche or full aggregate sweep.",
    ]) + "\n")
    if guard["status"] == "hard_stop":
        raise RuntimeError("resource guard hard stop: " + ";".join(guard["reasons"]))
    if getattr(ctx.args, "phase_profile", "") == P1_PROTOCOL_REPAIR_PHASE_PROFILE:
        global_root = resolve_path(ctx.args.global_audit_root)
        issue_register = global_root / "issue_register.csv"
        gate = read_json(global_root / "gate/rerun_readiness_gate.json", {})
        issue_df = read_csv_safe(issue_register)
        required = {"P1-MECH-LABEL-001", "P1-FEE-FORMULA-001", "P1-FUNDING-PROXY-001", "P1-CTRL-CAP-001", "P1-STAT-MTEST-001"}
        present = set(issue_df.get("issue_id", pd.Series(dtype=str)).astype(str)) if not issue_df.empty else set()
        status = "pass" if global_root.exists() and required.issubset(present) else "fail"
        write_text(ctx.run_root / "preflight/global_audit_dependency_check.md", "\n".join([
            "# Global Audit Dependency Check",
            "",
            f"Global audit root: `{global_root}`",
            f"Issue register exists: `{issue_register.exists()}`",
            f"Required P1 issues present: `{required.issubset(present)}`",
            f"Prior TSMOM rerun allowed: `{gate.get('tsmom_non_smoke_rerun_allowed', False)}`",
            f"Status: `{status}`",
        ]) + "\n")
        if status != "pass":
            write_json(ctx.run_root / "decision_summary.json", {"run_root": str(ctx.run_root), "status": "blocked", "phase_profile": ctx.args.phase_profile, "next_operator_decision": "blocked_by_protocol_issue", "reason": "missing_global_audit_dependency", "ts_utc": utc_now()})
            write_status(ctx, "blocked", "missing_global_audit_dependency")
            ctx.stop_after_current_stage = True
    if getattr(ctx.args, "phase_profile", "") == STAT_PROTOCOL_REPAIR_PHASE_PROFILE:
        ok = stage_structural_repair_dependency_check(ctx)
        if not ok:
            decision = {
                "run_root": str(ctx.run_root),
                "status": "blocked",
                "phase_profile": ctx.args.phase_profile,
                "next_operator_decision": "blocked_by_structural_repair_dependency",
                "repair_only": True,
                "waves_launched": False,
                "strategy_evidence_produced": False,
                "ts_utc": utc_now(),
            }
            write_json(ctx.run_root / "decision_summary.json", decision)
            write_text(ctx.run_root / "KRAKEN_ENGINE_WAVE_STAT_PROTOCOL_REPAIR_REPORT.md", "# Kraken Engine-Wave Statistical Protocol Repair Report\n\nBlocked by missing or failed structural repair dependency. See `preflight/structural_repair_dependency_check.md`.\n")
            write_status(ctx, "blocked", "blocked_by_structural_repair_dependency")
            ctx.stop_after_current_stage = True
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        ok = stage_repaired_dependency_check(ctx)
        if not ok:
            decision = {
                "run_root": str(ctx.run_root),
                "status": "blocked",
                "phase_profile": ctx.args.phase_profile,
                "next_operator_decision": "blocked_by_protocol_issue",
                "dependency_check_pass": False,
                "priority_tranche_launched": False,
                "full_sweep_launched": False,
                "ts_utc": utc_now(),
            }
            write_json(ctx.run_root / "decision_summary.json", decision)
            write_status(ctx, "blocked", "blocked_by_tsmom_retest_dependency")
            ctx.stop_after_current_stage = True


