def stage_seal(ctx: Context) -> None:
    if ctx.end >= PROTECTED_TS:
        raise RuntimeError("end timestamp crosses protected holdout")
    result = scan_output_tree_for_protected(ctx.run_root)
    write_json(ctx.run_root / "seal/protected_timestamp_scan.json", result_to_jsonable(result))
    write_text(ctx.run_root / "seal/seal_guard_report.md", f"# Seal Guard\n\nProtected start: `{PROTECTED_TS}`\nRun start/end: `{ctx.start}` / `{ctx.end}`\nCurrent output scan: `{result.status}`\n")


