    write_text(ctx.run_root / "prior/sampled_sweep_demotion_report.md", "# Sampled Sweep Demotion\n\nPrior sampled sweep is infrastructure/routing reference only and not alpha evidence.\n")
    write_text(ctx.run_root / "prior/bruteforce_materialization_demotion_report.md", "# Brute-Force Materialization Demotion\n\nThe brute-force full-coverage part001 output is operational feasibility only. It is not candidate evidence because controls/stress/stability did not run and materialization was infeasible at full registry scale.\n")
