def prior_benchmark_root(ctx: Context) -> Path:
    return active_prior_benchmark_root(ctx.args)


def read_prior_benchmark_facts(ctx: Context) -> dict[str, Any]:
    root = prior_benchmark_root(ctx)
    projection = read_json(root / "benchmark/full_budget_projection_analysis.json", {})
    gate_text = (root / "benchmark/operator_go_no_go_after_engine_benchmark.md").read_text(errors="replace") if (root / "benchmark/operator_go_no_go_after_engine_benchmark.md").exists() else ""
    audit = read_csv_safe(root / "benchmark/aggregate_materialized_probe_audit.csv")
    defs = read_csv_safe(root / "budget/candidate_definition_budget_manifest.csv")
    progress = read_json(root / "benchmark/engine_benchmark_progress.json", {})
    scan = read_json(root / "seal/protected_timestamp_scan_classification.json", read_json(root / "seal/protected_timestamp_scan.json", {}))
    missing = projection.get("engines_with_no_planned_definitions", [])
    if not missing and not defs.empty and "family_engine_id" in defs.columns:
        missing = sorted(set(REQUIRED_RANKABLE_ENGINES) - set(defs["family_engine_id"].astype(str)))
    return {
        "root": str(root),
        "gate_text_status_go": "Status: `go`" in gate_text,
        "projection": projection,
        "audit_rows": len(audit),
        "audit_failures": int((audit.get("status", pd.Series(dtype=str)) == "fail").sum()) if not audit.empty else 0,
        "definition_rows": len(defs),
        "benchmark_symbols": progress.get("total_symbols"),
        "missing_required_engines": missing,
        "protected_scan": scan,
    }


def stage_benchmark_gate_repair(ctx: Context) -> None:
    facts = read_prior_benchmark_facts(ctx)
    projection = facts["projection"]
    projected_hours = safe_float(projection.get("projected_aggregate_evaluation_hours"), float("inf"))
    bucket = str(projection.get("projected_runtime_bucket_from_actual_budget", "unknown"))
    conditions = {
        "projected_runtime_gt_168h": projected_hours > 168,
        "projected_runtime_bucket_above_168h": bucket == "above_168_hours",
        "required_rankable_engine_zero_definitions": bool(facts["missing_required_engines"]),
        "aggregate_materialized_probe_audit_fails": facts["audit_failures"] > 0 or facts["audit_rows"] == 0,
        "protected_scoring_or_event_timestamp_violation": bool(facts["protected_scan"].get("scoring_or_event_artifact_protected_timestamp_violation_observed", False)),
        "materialization_controls_stress_benchmark_missing": True,
        "projected_storage_exceeds_safe_limit_without_archive": False,
        "materialized_selected_ledgers_not_reproducible": True,
    }
    repaired_rules = {
        "gate_status": "no_go" if any(conditions.values()) else "go",
        "prior_benchmark_root": facts["root"],
        "conditions": conditions,
        "allowed_go_only_if_all_conditions_false": True,
        "decision_summary_and_go_no_go_report_must_match_projection": True,
    }
    write_json(ctx.run_root / "gate/repaired_benchmark_gate_rules.json", repaired_rules)
    rows = [{"gate": k, "blocked": v} for k, v in conditions.items()]
    write_csv(ctx.run_root / "gate/benchmark_gate_conditions.csv", rows)
    write_text(ctx.run_root / "gate/benchmark_gate_logic_report.md", "\n".join([
        "# Benchmark Gate Logic Repair",
        "",
        f"Prior benchmark root: `{facts['root']}`",
        f"Prior operator gate said go: `{facts['gate_text_status_go']}`",
        f"Prior projected hours: `{projected_hours:.3f}`",
        f"Prior projected bucket: `{bucket}`",
        f"Missing required engines: `{facts['missing_required_engines']}`",
        "",
        "Repaired gate is fail-closed. A full-go result is impossible while any condition in `repaired_benchmark_gate_rules.json` is true.",
    ]) + "\n")


def required_engine_contract_rows() -> list[dict[str, Any]]:
    rows = []
    for engine_id, meta in ENGINE_REPAIR_CONTRACTS.items():
        rows.append({
            "hypothesis_id": meta["hypothesis_id"],
            "family": meta["family"],
            "contract_id": f"repair_baseline_{engine_id}",
            "contract_source": "repair_required_engine_baseline",
            "allowed_lane": "kraken_tier1_ready",
            "archetype": meta["archetype"],
            "family_engine_id": engine_id,
            "compile_reason": "required_rankable_engine_baseline",
        })
    return rows


def repair_rankable_contracts(ctx: Context) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    contracts = load_contract_sources(resolve_path(ctx.args.readiness_root), resolve_path(ctx.args.repair_root))
    rank = contracts[contracts["allowed_lane"].astype(str).isin(RANKABLE_LANES)].copy()
    before_counts = rank.groupby("family_engine_id").size().to_dict() if not rank.empty else {}
    additions = []
    for row in required_engine_contract_rows():
        if rank.empty or row["family_engine_id"] not in set(rank["family_engine_id"].astype(str)):
            additions.append(row)
    if additions:
        rank = pd.concat([rank, pd.DataFrame(additions)], ignore_index=True)
    rank = rank.drop_duplicates(["hypothesis_id", "contract_id", "family_engine_id"]).copy()
    after_counts = rank.groupby("family_engine_id").size().to_dict() if not rank.empty else {}
    trace = []
    for _, r in rank.iterrows():
        trace.append({
            "hypothesis_id": r.get("hypothesis_id", ""),
            "family": r.get("family", ""),
            "contract_id": r.get("contract_id", ""),
            "family_engine_id": r.get("family_engine_id", ""),
            "source": r.get("contract_source", ""),
            "compile_decision": "compiled_tier1_repair_tranche",
            "compile_reason": r.get("compile_reason", "source_contract_rankable_lane"),
        })
    uncompiled = []
    for _, r in contracts[~contracts["allowed_lane"].astype(str).isin(RANKABLE_LANES)].iterrows():
        lane = str(r.get("allowed_lane", ""))
        reason = "candidate_library_only"
        if "capture" in lane:
            reason = "sidecar_live_capture"
        elif "event" in lane:
            reason = "event_ledger_first"
        elif "not_kraken" in lane:
            reason = "not_kraken_viable_current_translation"
        uncompiled.append({"hypothesis_id": r.get("hypothesis_id", ""), "family": r.get("family", ""), "family_engine_id": r.get("family_engine_id", ""), "reason": reason, "lane": lane})
    before_after = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        before_after.append({"family_engine_id": engine_id, "before_rankable_contract_count": int(before_counts.get(engine_id, 0)), "after_rankable_contract_count": int(after_counts.get(engine_id, 0))})
    return rank, pd.DataFrame(trace), pd.DataFrame(uncompiled), pd.DataFrame(before_after)


def repaired_definition_budget(ctx: Context) -> int:
    if ctx.args.smoke:
        return min(SMOKE_REPAIR_PRIORITY_DEFINITION_BUDGET, max(14, int(ctx.args.candidate_definition_budget)))
    return min(REPAIR_PRIORITY_DEFINITION_BUDGET, max(700, int(ctx.args.candidate_definition_budget)))


def build_repaired_definitions(ctx: Context, rank: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame]:
    target = repaired_definition_budget(ctx)
    per_engine = max(1, target // len(REQUIRED_RANKABLE_ENGINES))
    all_defs = []
    all_rejected = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        sub = rank[rank["family_engine_id"].astype(str).eq(engine_id)].copy()
        if sub.empty:
            continue
        canonical = canonical_definition_rows(sub.head(1))
        broad_target = max(0, per_engine - len(canonical))
        broad, rejected = deterministic_space_fill(sub, broad_target, ctx.args.seed + len(engine_id))
        defs = pd.concat([canonical, broad], ignore_index=True).drop_duplicates("definition_id").head(per_engine)
        all_defs.append(defs)
        if not rejected.empty:
            all_rejected.append(rejected)
    out = pd.concat(all_defs, ignore_index=True) if all_defs else pd.DataFrame()
    if len(out) < target and not rank.empty:
        extra, rejected = deterministic_space_fill(rank, target - len(out), ctx.args.seed + 101)
        out = pd.concat([out, extra], ignore_index=True).drop_duplicates("definition_id").head(target)
        if not rejected.empty:
            all_rejected.append(rejected)
    rejected_df = pd.concat(all_rejected, ignore_index=True) if all_rejected else pd.DataFrame()
    return out, rejected_df


def stage_candidate_compiler_and_budget_repair(ctx: Context) -> None:
    stage_family_engine_contracts(ctx)
    rank, trace, uncompiled, before_after = repair_rankable_contracts(ctx)
    defs, rejected = build_repaired_definitions(ctx, rank)
    write_csv(ctx.run_root / "compiler/hypothesis_to_engine_trace.csv", trace)
    write_csv(ctx.run_root / "compiler/uncompiled_hypotheses_with_reasons.csv", uncompiled)
    write_csv(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv", defs)
    write_csv(ctx.run_root / "budget/candidate_definition_budget_manifest.csv", defs)
    write_csv(ctx.run_root / "budget/engine_definition_counts_before_after.csv", before_after)
    write_csv(ctx.run_root / "templates/invalid_combination_rejection_report.csv", rejected)
    coverage = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        sub = defs[defs["family_engine_id"].astype(str).eq(engine_id)] if not defs.empty else pd.DataFrame()
        kinds = set(sub.get("definition_kind", pd.Series(dtype=str)).astype(str))
        coverage.append({
            "family_engine_id": engine_id,
            "definition_count": len(sub),
            "has_plain_baseline": "plain_baseline" in kinds,
            "has_conservative": "conservative" in kinds,
            "has_aggressive": "aggressive" in kinds,
            "has_regime_gated": bool((sub.get("regime_activation", pd.Series(dtype=str)).astype(str) == "intended_regime").any()) if not sub.empty else False,
            "has_all_context_diagnostic": bool((sub.get("regime_activation", pd.Series(dtype=str)).astype(str) == "all_context_diagnostic").any()) if not sub.empty else False,
            "status": "pass" if len(sub) > 0 else "fail_zero_definitions",
        })
    write_csv(ctx.run_root / "budget/required_engine_coverage_audit.csv", coverage)
    fam_alloc = defs.groupby(["family", "family_engine_id"]).size().reset_index(name="definition_count") if not defs.empty else pd.DataFrame()
    write_csv(ctx.run_root / "budget/family_budget_allocation.csv", fam_alloc)
    write_text(ctx.run_root / "budget/budget_report.md", f"# Repaired Budget Report\n\nDefinitions: `{len(defs)}`\nRequired engines covered: `{sum(1 for r in coverage if r['status']=='pass')}/{len(REQUIRED_RANKABLE_ENGINES)}`\nUnrun full-budget definitions remain `pending_compute`, not rejected.\n")


def panel_manifest_for_repair(ctx: Context) -> pd.DataFrame:
    current = ctx.run_root / "panels/aggregate_panel_manifest.csv"
    if current.exists():
        return read_csv_safe(current)
    prior = prior_benchmark_root(ctx) / "panels/aggregate_panel_manifest.csv"
    if prior.exists() and not ctx.args.smoke:
        panel = read_csv_safe(prior)
        write_csv(current, panel)
        write_text(ctx.run_root / "panels/panel_qc_report.md", f"# Aggregate Panel QC\n\nSymbols resolved: `{len(panel)}`\nRows with bars: `{int((panel.get('status', pd.Series(dtype=str))=='available').sum())}`\nSource: prior benchmark panel manifest.\n")
        return panel
    stage_panel_build(ctx)
    return read_csv_safe(current)


def family_universe_limits(smoke: bool) -> dict[str, int]:
    if smoke:
        return {engine_id: 5 for engine_id in REQUIRED_RANKABLE_ENGINES}
    return {
        "scheduled_tsmom_engine": 40,
        "liquid_continuation_breakout_engine": 80,
        "prior_high_reclaim_engine": 100,
        "retest_reclaim_lifecycle_engine": 80,
        "compression_breakout_engine": 100,
        "session_calendar_engine": 50,
        "funding_crowding_engine": 80,
    }


def build_family_universe(ctx: Context, panel: pd.DataFrame) -> dict[str, list[str]]:
    if panel.empty:
        paths = data_paths(ctx)
        syms = list_symbols(paths, ctx.args.max_symbols if ctx.args.smoke else 0)
        panel = pd.DataFrame({"symbol": syms, "bar_rows": 1, "funding_rows": 1, "status": "available"})
    usable = panel[panel.get("status", "available").astype(str).eq("available")].copy()
    if usable.empty:
        usable = panel.copy()
    usable["bar_rows"] = pd.to_numeric(usable.get("bar_rows", 0), errors="coerce").fillna(0)
    usable["funding_rows"] = pd.to_numeric(usable.get("funding_rows", 0), errors="coerce").fillna(0)
    by_liq = usable.sort_values(["bar_rows", "funding_rows", "symbol"], ascending=[False, False, True])
    by_funding = usable[usable["funding_rows"] > 0].sort_values(["funding_rows", "bar_rows", "symbol"], ascending=[False, False, True])
    limits = family_universe_limits(ctx.args.smoke)
    out = {}
    for engine_id, limit in limits.items():
        source = by_funding if engine_id == "funding_crowding_engine" and not by_funding.empty else by_liq
        out[engine_id] = source["symbol"].astype(str).head(limit).tolist()
    return out


def stage_family_universe_fanout_repair(ctx: Context) -> None:
    panel = panel_manifest_for_repair(ctx)
    defs = read_csv_safe(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv")
    universe = build_family_universe(ctx, panel)
    before_symbols = int(read_prior_benchmark_facts(ctx).get("benchmark_symbols") or len(panel) or 0)
    rows = []
    symbols_rows = []
    total_before = 0
    total_after = 0
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        dcount = int((defs.get("family_engine_id", pd.Series(dtype=str)).astype(str) == engine_id).sum()) if not defs.empty else 0
        syms = universe.get(engine_id, [])
        before = dcount * before_symbols
        after = dcount * len(syms)
        total_before += before
        total_after += after
        rows.append({"family_engine_id": engine_id, "definition_count": dcount, "before_symbol_count": before_symbols, "after_symbol_count": len(syms), "candidate_symbol_rows_before": before, "candidate_symbol_rows_after": after, "fanout_policy": "pit_liquidity_funding_lifecycle_screen"})
        for sym in syms:
            symbols_rows.append({"family_engine_id": engine_id, "symbol": sym, "selection_basis": "pre_holdout_bar_funding_coverage"})
    write_text(ctx.run_root / "universe/family_universe_policy.yaml", "\n".join([
        "scheduled_tsmom_engine: Tier A liquid symbols only unless contract explicitly broadens",
        "liquid_continuation_breakout_engine: Tier A/B liquid leaders",
        "prior_high_reclaim_engine: Tier A/B plus liquid Tier C where coverage passes",
        "retest_reclaim_lifecycle_engine: Tier A/B close-confirmed only",
        "compression_breakout_engine: Tier A/B plus selected liquid Tier C",
        "session_calendar_engine: majors and high-liquidity alts first",
        "funding_crowding_engine: reliable funding plus sufficient bar liquidity",
    ]) + "\n")
    write_csv(ctx.run_root / "universe/family_candidate_symbol_counts.csv", rows)
    write_csv(ctx.run_root / "universe/family_universe_symbols.csv", symbols_rows)
    write_text(ctx.run_root / "universe/fanout_reduction_report.md", f"# Fanout Reduction Report\n\nCandidate-symbol rows before repair: `{total_before}`\nCandidate-symbol rows after repair: `{total_after}`\nThis is contract eligibility, not event sampling.\n")
    max_end = str(pd.to_datetime(panel.get("end_ts", pd.Series(dtype=str)), utc=True, errors="coerce").max()) if not panel.empty and "end_ts" in panel else ""
    write_text(ctx.run_root / "universe/pit_universe_integrity_report.md", f"# PIT Universe Integrity\n\nUniverse uses pre-holdout local Kraken panel coverage and does not use today-only live list as historical eligibility.\nPanel max end: `{max_end}`\n")


def stage_tsmom_retest_universe_fanout(ctx: Context) -> None:
    panel = panel_manifest_for_repair(ctx)
    universe = build_family_universe(ctx, panel)
    syms = universe.get("scheduled_tsmom_engine", [])
    before_symbols = int(read_prior_benchmark_facts(ctx).get("benchmark_symbols") or len(panel) or 0)
    rows = [{
        "family_engine_id": "scheduled_tsmom_engine",
        "definition_count": int(len(read_csv_safe(ctx.run_root / "prelaunch/eligible_definition_manifest.csv"))),
        "before_symbol_count": before_symbols,
        "after_symbol_count": len(syms),
        "candidate_symbol_rows_before": "",
        "candidate_symbol_rows_after": "",
        "fanout_policy": "tsmom_retest_pit_liquidity_funding_lifecycle_screen",
    }]
    symbols_rows = [{"family_engine_id": "scheduled_tsmom_engine", "symbol": sym, "selection_basis": "pre_holdout_bar_funding_coverage"} for sym in syms]
    write_text(ctx.run_root / "universe/family_universe_policy.yaml", "scheduled_tsmom_engine: Tier A liquid symbols first; TSMOM retest profile excludes all later engine-wave universes.\n")
    write_csv(ctx.run_root / "universe/family_candidate_symbol_counts.csv", rows)
    write_csv(ctx.run_root / "universe/family_universe_symbols.csv", symbols_rows)
    write_text(ctx.run_root / "universe/fanout_reduction_report.md", f"# TSMOM Retest Fanout Report\n\nOnly `scheduled_tsmom_engine` is fanned out for this profile. This is engine-scope restriction, not event sampling.\nSymbols: `{len(syms)}`\n")
    max_end = str(pd.to_datetime(panel.get("end_ts", pd.Series(dtype=str)), utc=True, errors="coerce").max()) if not panel.empty and "end_ts" in panel else ""
    write_text(ctx.run_root / "universe/pit_universe_integrity_report.md", f"# PIT Universe Integrity\n\nUniverse uses pre-holdout local Kraken panel coverage and does not use today-only live list as historical eligibility.\nPanel max end: `{max_end}`\n")


def stage_engine_vectorization_and_throughput_repair(ctx: Context) -> None:
    prior = read_prior_benchmark_facts(ctx)
    prior_projection = prior.get("projection", {})
    prior_rate = safe_float(prior_projection.get("benchmark_rows_per_second"), np.nan)
    progress = read_json(prior_benchmark_root(ctx) / "benchmark/engine_benchmark_progress.json", {})
    if math.isnan(prior_rate):
        prior_rate = safe_float(progress.get("rows_per_sec"), np.nan)
    write_text(ctx.run_root / "optimization/vectorization_patch_report.md", "# Vectorization Patch Report\n\nImplemented benchmark symbol-panel caching, family-universe fanout reduction, and engine-batched repaired benchmark evaluation. Aggregate event-address semantics are unchanged.\n")
    write_csv(ctx.run_root / "optimization/per_engine_hotspot_report.csv", [
        {"hotspot": "repeated_symbol_panel_reads", "before": "panel read per representative engine/symbol", "after": "panel read once per symbol in cached benchmark", "status": "repaired"},
        {"hotspot": "unbounded_301_symbol_fanout", "before": "every definition on every resolved symbol", "after": "family-specific PIT eligible universe", "status": "repaired"},
        {"hotspot": "silent_benchmark_progress", "before": "benchmark wrote only after completion", "after": "progress json/jsonl every 10 symbols", "status": "repaired"},
    ])
    write_text(ctx.run_root / "optimization/io_cache_report.md", "# IO Cache Report\n\nRepaired benchmark caches each symbol panel for all representative engine probes and preserves exact aggregate computation.\n")
    write_csv(ctx.run_root / "optimization/runtime_before_after.csv", [{"metric": "candidate_symbol_rows_per_second", "before": prior_rate, "after": "", "after_source": "filled_by_repaired_benchmark_rerun"}])
def stage_panel_build(ctx: Context) -> None:
    paths = data_paths(ctx)
    symbols = list_symbols(paths, ctx.args.max_symbols if ctx.args.smoke else 0)
    if ctx.args.smoke and not symbols:
        symbols = ["PF_XBTUSD"]
    rows = []
    feature_rows = []
    causality_rows = []
    for sym in symbols[: max(1, len(symbols))]:
        bars = load_symbol_bars(paths, sym, ctx.start, ctx.end)
        funding = load_funding(paths, sym, ctx.end)
        rows.append({"symbol": sym, "bar_rows": len(bars), "funding_rows": len(funding), "start_ts": str(bars["ts"].min()) if not bars.empty else "", "end_ts": str(bars["ts"].max()) if not bars.empty else "", "status": "available" if not bars.empty else "missing_bars"})
    for feature, source, allowed in [
        ("trade_ohlc", "historical_trade_candles_5m", "entry,exit,path"),
        ("mark_ohlc", "historical_mark_candles_5m", "path,liquidation_diagnostics"),
        ("funding_rate", "historical_funding", "entry_cap,path"),
        ("rolling_high_low", "trade_ohlc", "entry"),
        ("prior_high_ath", "trade_ohlc", "entry"),
        ("session_calendar", "timestamp", "entry"),
        ("future_path_arrays", "trade_ohlc_after_entry", "path_realization_only"),
    ]:
        feature_rows.append({"feature_name": feature, "source_dataset": source, "computation_lookback": "contract_parameterized", "availability_timestamp": "source_close_ts", "allowed_for": allowed})
        causality_rows.append({"feature_name": feature, "source_dataset": source, "source_timestamp": "source_close_ts", "computation_lookback": "contract_parameterized", "availability_timestamp": "feature_available_ts", "allowed_for_entry": "entry" in allowed, "allowed_for_exit": "exit" in allowed, "allowed_for_path_realization": "path" in allowed, "causality_rule": "feature_available_ts <= decision_ts for entry; path arrays after entry only", "status": "contract_defined"})
    write_csv(ctx.run_root / "panels/aggregate_panel_manifest.csv", rows)
    write_csv(ctx.run_root / "panels/feature_dictionary.csv", feature_rows)
    write_text(ctx.run_root / "panels/panel_qc_report.md", f"# Aggregate Panel QC\n\nSymbols resolved: `{len(symbols)}`\nRows with bars: `{sum(1 for r in rows if r['status']=='available')}`\n")
    write_csv(ctx.run_root / "audit/aggregate_panel_feature_causality_audit.csv", causality_rows)


def stage_family_engine_contracts(ctx: Context) -> None:
    rows = []
    exactness = []
    for engine in ENGINES.values():
        contract = {
            "family_engine_id": engine.engine_id,
            "archetype": engine.archetype,
            "contract_event_type": engine.contract_event_type(),
            "row_semantics": engine.row_semantics(),
            "event_semantics_version": EVENT_SEMANTICS_VERSION,
            "engine_contract_hash": engine.engine_contract_hash(),
            "required_methods": ["build_candidate_masks", "enumerate_valid_event_addresses", "compute_exact_aggregate_metrics", "regenerate_materialized_ledger", "build_matched_controls", "run_family_specific_stress"],
            "uses_old_infer_signal_indices": False,
            "uses_persistent_condition_generator": False,
        }
        out = ctx.run_root / "engines/engine_contracts" / f"{engine.engine_id}.json"
        write_json(out, contract)
        rows.append({**contract, "contract_path": str(out.relative_to(ctx.run_root))})
        for metric in ["event_count", "gross_R", "fees_R", "funding_R", "net_R", "active_symbols", "active_months", "PF", "win_rate", "drawdown", "lifecycle_completion_rate", "signal_frequency"]:
            basis = "exact_from_all_events"
            if metric in {"PF", "win_rate"} and engine.row_semantics() == "lifecycle_event":
                basis = "not_applicable_for_row_semantics"
            if metric == "lifecycle_completion_rate" and engine.row_semantics() != "lifecycle_event":
                basis = "not_applicable_for_row_semantics"
            if metric == "signal_frequency" and engine.row_semantics() != "decision":
                basis = "not_applicable_for_row_semantics"
            exactness.append({"family_engine_id": engine.engine_id, "metric": metric, "aggregate_metric_basis": basis})
    write_csv(ctx.run_root / "engines/family_engine_registry.csv", rows)
    write_csv(ctx.run_root / "audit/aggregate_exactness_contract.csv", exactness)
    write_text(ctx.run_root / "engines/engine_implementation_audit.md", "# Engine Implementation Audit\n\nAll seven required engines are implemented as `FamilyEngine` subclasses with separate engine IDs and required method paths. The old `infer_signal_indices()` path is not called by rankable aggregate evaluation. Event addresses are generated by each engine's `enumerate_valid_event_addresses()` method.\n")
    write_text(ctx.run_root / "engines/engine_contract_report.md", f"# Engine Contract Report\n\nEngines registered: `{len(rows)}`\n")
    eligibility = [
        {"family": "liquid leader continuation", "family_engine_id": "liquid_continuation_breakout_engine", "data_tier_status": "tier1_testable_on_kraken", "reason": "bar-compatible close-confirmed"},
        {"family": "prior-high momentum", "family_engine_id": "prior_high_reclaim_engine", "data_tier_status": "tier1_testable_on_kraken", "reason": "bar-compatible close-confirmed"},
        {"family": "volatility-managed TSMOM", "family_engine_id": "scheduled_tsmom_engine", "data_tier_status": "tier1_testable_on_kraken", "reason": "scheduled interval returns"},
        {"family": "post-breakout retest", "family_engine_id": "retest_reclaim_lifecycle_engine", "data_tier_status": "tier1_only_close_confirmed", "reason": "lifecycle close confirmation required"},
        {"family": "sector/theme ignition", "family_engine_id": "liquid_continuation_breakout_engine", "data_tier_status": "partial_venue_breadth_cap", "reason": "Kraken breadth limited"},
        {"family": "post-catalyst base", "family_engine_id": "retest_reclaim_lifecycle_engine", "data_tier_status": "event_ledger_first_sidecar", "reason": "dated catalyst ledger required"},
        {"family": "small-cap reversal/listing/ORB", "family_engine_id": "funding_crowding_engine", "data_tier_status": "capture_or_redesign_required", "reason": "not decision-grade from Tier1 bars alone"},
    ]
    write_csv(ctx.run_root / "engines/family_data_tier_eligibility_report.csv", eligibility)
    write_text(ctx.run_root / "templates/row_semantics_metric_policy.yaml", "trade_episode:\n  PF: allowed\n  win_rate: allowed\n  drawdown: ordered_equity_series\n  R_multiple: entry_stop_exit_required\nposition_interval:\n  PF: allowed_if_closed_interval_loss_win_meaningful\n  win_rate: allowed_if_closed_interval\n  drawdown: ordered_interval_series\n  R_multiple: entry_stop_exit_required\nlifecycle_event:\n  lifecycle_completion_rate: allowed\n  PF: not_applicable\n  win_rate: not_applicable\ndecision:\n  signal_frequency: allowed\n  PF: not_applicable\ninvalid_metric_value: not_applicable\n")


def stage_budget_plan(ctx: Context) -> None:
    contracts = load_contract_sources(resolve_path(ctx.args.readiness_root), resolve_path(ctx.args.repair_root))
    rank = contracts[contracts["allowed_lane"].astype(str).isin(RANKABLE_LANES)].copy()
    if ctx.args.family_list:
        wanted = {x.strip() for x in ctx.args.family_list.split(",") if x.strip()}
        rank = rank[rank["family"].astype(str).isin(wanted) | rank["family_engine_id"].astype(str).isin(wanted)]
    if ctx.args.priority_wave != "all" and "priority_wave" in rank.columns:
        rank = rank[rank["priority_wave"].eq(ctx.args.priority_wave)]
    if rank.empty:
        rank = contracts.head(7).copy()
    canonical = canonical_definition_rows(rank)
    remaining = max(0, int(ctx.args.candidate_definition_budget) - len(canonical))
    broad_budget = min(max(0, int(ctx.args.coarse_definition_budget)), remaining)
    broad, rejected = deterministic_space_fill(rank, broad_budget if not ctx.args.smoke else min(20, broad_budget), ctx.args.seed)
    defs = pd.concat([canonical, broad], ignore_index=True).drop_duplicates("definition_id")
    if ctx.args.smoke:
        defs = defs.head(min(len(defs), max(10, ctx.args.candidate_definition_budget if ctx.args.candidate_definition_budget < 100 else 40))).copy()
    elif len(defs) > ctx.args.candidate_definition_budget:
        defs = defs.head(ctx.args.candidate_definition_budget).copy()
    template_rows = []
    for engine in ENGINES.values():
        template_rows.append({"family_engine_id": engine.engine_id, "archetype": engine.archetype, "valid_parameter_dimensions": ";".join(engine.valid_parameter_dimensions), "row_semantics": engine.row_semantics(), "contract_event_type": engine.contract_event_type()})
    write_csv(ctx.run_root / "budget/candidate_definition_budget_manifest.csv", defs)
    write_csv(ctx.run_root / "budget/search_space_coverage_matrix.csv", defs[["definition_id", "hypothesis_id", "family", "family_engine_id", "entry_template", "exit_template", "stop_template", "regime_activation", "side"]])
    fam_alloc = defs.groupby(["family", "family_engine_id"]).size().reset_index(name="definition_count")
    write_csv(ctx.run_root / "budget/family_budget_allocation.csv", fam_alloc)
    write_csv(ctx.run_root / "templates/entry_exit_template_registry.csv", template_rows)
    write_csv(ctx.run_root / "templates/invalid_combination_rejection_report.csv", rejected)
    write_text(ctx.run_root / "budget/budget_report.md", f"# Budget Report\n\nRankable hypotheses: `{rank['hypothesis_id'].nunique()}`\nDefinitions: `{len(defs)}`\nCanonical definitions: `{len(canonical)}`\nBroad definitions: `{len(broad)}`\n")


def aggregate_candidates(ctx: Context, candidates: pd.DataFrame, *, write_progress: bool = True) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    summaries: list[dict[str, Any]] = []
    summary_accs: dict[str, dict[tuple[str, ...], dict[str, Any]]] = {
        "symbol_month": {},
        "regime": {},
        "year": {},
        "month": {},
        "fold": {},
    }
    repro_rows: list[dict[str, Any]] = []
    streaming_audit_rows: list[dict[str, Any]] = []
    total = len(candidates)
    done = 0
    t0 = time.time()
    for symbol, group in candidates.groupby("symbol", sort=False):
        bars = load_symbol_bars(paths, str(symbol), ctx.start, ctx.end)
        funding = load_funding(paths, str(symbol), ctx.end)
        if bars.empty:
            for _, cand in group.iterrows():
                summaries.append(empty_candidate_summary(cand, "missing_bars"))
                done += 1
            continue
        time_hash = stable_hash(str(ctx.start), str(ctx.end), str(bars["ts"].min()), str(bars["ts"].max()), len(bars), n=24)
        panel_hash = stable_hash(str(symbol), len(bars), bars["ts"].min(), bars["ts"].max(), float(pd.to_numeric(bars["close"], errors="coerce").sum()), n=24)
        for _, cand in group.iterrows():
            cdict = cand.to_dict()
            engine = engine_for_candidate(cdict)
            metrics = compute_streaming_aggregate_and_group_summaries(engine, bars, funding, cdict, summary_accs)
            streaming_audit_rows.append({
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict),
                "family_engine_id": engine.engine_id,
                "events": int(metrics.get("events", 0) or 0),
                "fold_summary_basis": "streaming_exact_sufficient_statistics",
                "materialized_ledger_regenerated_for_aggregate_summary": False,
                "status": "pass",
            })
            summaries.append(metrics)
            repro_rows.append({
                    "candidate_definition_id": definition_identity(cdict),
                    "candidate_id": cdict.get("candidate_id"),
                    "candidate_symbol_id": cdict.get("candidate_symbol_id", ""),
                "family_engine_id": engine.engine_id,
                "engine_contract_hash": engine.engine_contract_hash(),
                "event_semantics_version": EVENT_SEMANTICS_VERSION,
                "row_semantics": engine.row_semantics(),
                "symbol_universe_hash": cdict.get("symbol_universe_hash", ""),
                "time_window_hash": time_hash,
                    "parameter_vector_hash": parameter_vector_hash(cdict, engine),
                "event_address_generation_rule": f"{engine.engine_id}.enumerate_valid_event_addresses",
                "feature_panel_manifest_hash": panel_hash,
            })
            done += 1
            if write_progress and done % max(1, min(50, ctx.args.chunk_size)) == 0:
                elapsed = max(0.001, time.time() - t0)
                write_json(ctx.run_root / "coarse/aggregate_progress.json", {"processed_candidate_symbol_rows": done, "total_candidate_symbol_rows": total, "rows_per_sec": done / elapsed, "eta_seconds": (total - done) / (done / elapsed), "ts_utc": utc_now()})
    repro = pd.DataFrame(repro_rows)
    write_csv(ctx.run_root / "audit/event_address_reproducibility_manifest.csv", repro)
    write_csv(ctx.run_root / "coarse/aggregate_streaming_fold_summary_audit.csv", streaming_audit_rows)
    return (
        pd.DataFrame(summaries),
        finalize_streaming_summary_acc(summary_accs["symbol_month"]),
        finalize_streaming_summary_acc(summary_accs["regime"]),
        finalize_streaming_summary_acc(summary_accs["year"]),
        finalize_streaming_summary_acc(summary_accs["month"]),
        finalize_streaming_summary_acc(summary_accs["fold"]),
    )


def _aggregate_summary_acc_template() -> dict[str, dict[tuple[str, ...], dict[str, Any]]]:
    return {
        "symbol_month": {},
        "regime": {},
        "year": {},
        "month": {},
        "fold": {},
    }


def _write_parquet_shard(path: Path, rows: pd.DataFrame | Sequence[Mapping[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    df = rows if isinstance(rows, pd.DataFrame) else pd.DataFrame(list(rows))
    if df.empty:
        return
    df.to_parquet(path, index=False)


def _read_parquet_shards(shard_dir: Path) -> pd.DataFrame:
    if not shard_dir.exists():
        return pd.DataFrame()
    frames = [read_parquet_safe(p) for p in sorted(shard_dir.glob("*.parquet"))]
    frames = [f for f in frames if not f.empty]
    return pd.concat(frames, ignore_index=True) if frames else pd.DataFrame()


def _merge_group_summary_shards(df: pd.DataFrame, key_cols: Sequence[str]) -> pd.DataFrame:
    if df.empty:
        return df
    keys = [c for c in key_cols if c in df.columns]
    if not keys:
        return df
    sum_cols = [
        c for c in [
            "events", "net_R", "gross_R", "fees_R", "funding_R", "slippage_R",
            "raw_net_R", "raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R",
            "scaled_net_R", "scaled_gross_R", "scaled_fee_R", "scaled_funding_R", "scaled_slippage_R",
            "active_symbols",
        ]
        if c in df.columns
    ]
    work = df.copy()
    for col in sum_cols:
        work[col] = pd.to_numeric(work[col], errors="coerce").fillna(0.0)
    aggs: dict[str, str] = {col: "sum" for col in sum_cols}
    for col in work.columns:
        if col not in set(keys) | set(sum_cols) | {"avg_R"}:
            aggs[col] = "first"
    out = work.groupby(keys, dropna=False, sort=False).agg(aggs).reset_index()
    if "events" in out.columns and "net_R" in out.columns:
        events = pd.to_numeric(out["events"], errors="coerce").replace(0, np.nan)
        out["avg_R"] = pd.to_numeric(out["net_R"], errors="coerce") / events
    return out


def aggregate_candidates_memorysafe_to_dir(ctx: Context, candidates: pd.DataFrame, out_dir: Path) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    batch_size = max(1, int(getattr(ctx.args, "aggregate_batch_size", 25) or 25))
    shard_root = out_dir / "aggregate_shards"
    total = len(candidates)
    done = 0
    processed_indices: set[Any] = set()
    t0 = time.time()
    stage_name = "aggregate_candidates_memorysafe"
    write_text(out_dir / "aggregate_streaming_policy.md", (
        "# Memory-Safe Aggregate Policy\n\n"
        f"Batch size: `{batch_size}` candidate-symbol rows.\n"
        "Candidate aggregate, group summaries, reproducibility, and streaming audit rows are flushed as parquet shards after every batch. "
        "Rank/PIT caches are cleared after each batch while preserving per-decision point-in-time ranking semantics.\n"
    ))
    memory_guard_check(ctx, stage=stage_name, processed=0, total=total, pending_candidates=candidates)
    for symbol, group in candidates.groupby("symbol", sort=False):
        symbol_t0 = time.time()
        bars = load_symbol_bars(paths, str(symbol), ctx.start, ctx.end)
        funding = load_funding(paths, str(symbol), ctx.end)
        if bars.empty:
            batches = [group.iloc[i:i + batch_size] for i in range(0, len(group), batch_size)]
        else:
            time_hash = stable_hash(str(ctx.start), str(ctx.end), str(bars["ts"].min()), str(bars["ts"].max()), len(bars), n=24)
            panel_hash = stable_hash(str(symbol), len(bars), bars["ts"].min(), bars["ts"].max(), float(pd.to_numeric(bars["close"], errors="coerce").sum()), n=24)
            batches = [group.iloc[i:i + batch_size] for i in range(0, len(group), batch_size)]
        for batch in batches:
            batch_idx = done // batch_size
            summaries: list[dict[str, Any]] = []
            repro_rows: list[dict[str, Any]] = []
            streaming_audit_rows: list[dict[str, Any]] = []
            summary_accs = _aggregate_summary_acc_template()
            if bars.empty:
                for idx, cand in batch.iterrows():
                    summaries.append(empty_candidate_summary(cand.to_dict(), "missing_bars"))
                    processed_indices.add(idx)
                    done += 1
            else:
                for idx, cand in batch.iterrows():
                    cdict = cand.to_dict()
                    engine = engine_for_candidate(cdict)
                    row_t0 = time.time()
                    metrics = compute_streaming_aggregate_and_group_summaries(engine, bars, funding, cdict, summary_accs)
                    elapsed_row = time.time() - row_t0
                    streaming_audit_rows.append({
                        "candidate_definition_id": definition_identity(cdict),
                        "candidate_symbol_id": symbol_identity(cdict),
                        "family_engine_id": engine.engine_id,
                        "events": int(metrics.get("events", 0) or 0),
                        "fold_summary_basis": "streaming_exact_sufficient_statistics",
                        "materialized_ledger_regenerated_for_aggregate_summary": False,
                        "status": "pass",
                    })
                    summaries.append(metrics)
                    repro_rows.append({
                        "candidate_definition_id": definition_identity(cdict),
                        "candidate_id": cdict.get("candidate_id"),
                        "candidate_symbol_id": cdict.get("candidate_symbol_id", ""),
                        "family_engine_id": engine.engine_id,
                        "engine_contract_hash": engine.engine_contract_hash(),
                        "event_semantics_version": EVENT_SEMANTICS_VERSION,
                        "row_semantics": engine.row_semantics(),
                        "symbol_universe_hash": cdict.get("symbol_universe_hash", ""),
                        "time_window_hash": time_hash,
                        "parameter_vector_hash": parameter_vector_hash(cdict, engine),
                        "event_address_generation_rule": f"{engine.engine_id}.enumerate_valid_event_addresses",
                        "feature_panel_manifest_hash": panel_hash,
                    })
                    append_csv(ctx.run_root / "performance/aggregate_runtime_profile.csv", [{
                        "ts_utc": utc_now(),
                        "family_engine_id": engine.engine_id,
                        "symbol": str(symbol),
                        "candidate_definition_id": definition_identity(cdict),
                        "candidate_symbol_id": symbol_identity(cdict),
                        "events": int(metrics.get("events", 0) or 0),
                        "runtime_seconds": elapsed_row,
                        "stage": stage_name,
                    }])
                    elapsed_total = max(0.001, time.time() - t0)
                    write_json(ctx.run_root / "performance/aggregate_heartbeat.json", {
                        "run_id": active_run_id(ctx.args),
                        "stage": stage_name,
                        "family": engine.engine_id,
                        "current_candidate_identity_hash": build_candidate_identity_hash({
                            "run_id": active_run_id(ctx.args),
                            "candidate_definition_id": definition_identity(cdict),
                            "candidate_symbol_id": symbol_identity(cdict),
                            "symbol_id": str(symbol),
                            "symbol": str(symbol),
                            "parameter_vector_hash": parameter_vector_hash(cdict, engine),
                            "event_semantics_version": EVENT_SEMANTICS_VERSION,
                        }),
                        "current_definition_id": definition_identity(cdict),
                        "current_symbol": str(symbol),
                        "processed_candidate_symbol_rows": done + 1,
                        "total_candidate_symbol_rows": total,
                        "candidate_runtime_seconds": elapsed_row,
                        "rolling_rows_per_sec": (done + 1) / elapsed_total,
                        "rss_gib": current_rss_bytes() / 1024 ** 3,
                        "last_completed_candidate_identity_hash": symbol_identity(cdict),
                        "updated_at": utc_now(),
                    })
                    processed_indices.add(idx)
                    done += 1
            shard_suffix = f"{batch_idx:06d}"
            _write_parquet_shard(shard_root / "candidate_aggregate" / f"part-{shard_suffix}.parquet", summaries)
            _write_parquet_shard(shard_root / "symbol_month" / f"part-{shard_suffix}.parquet", finalize_streaming_summary_acc(summary_accs["symbol_month"]))
            _write_parquet_shard(shard_root / "regime" / f"part-{shard_suffix}.parquet", finalize_streaming_summary_acc(summary_accs["regime"]))
            _write_parquet_shard(shard_root / "year" / f"part-{shard_suffix}.parquet", finalize_streaming_summary_acc(summary_accs["year"]))
            _write_parquet_shard(shard_root / "month" / f"part-{shard_suffix}.parquet", finalize_streaming_summary_acc(summary_accs["month"]))
            _write_parquet_shard(shard_root / "fold" / f"part-{shard_suffix}.parquet", finalize_streaming_summary_acc(summary_accs["fold"]))
            _write_parquet_shard(shard_root / "event_address_reproducibility" / f"part-{shard_suffix}.parquet", repro_rows)
            _write_parquet_shard(shard_root / "streaming_fold_audit" / f"part-{shard_suffix}.parquet", streaming_audit_rows)
            elapsed = max(0.001, time.time() - t0)
            rate = done / elapsed
            progress = {
                "processed_candidate_symbol_rows": done,
                "total_candidate_symbol_rows": total,
                "rows_per_sec": rate,
                "eta_seconds": (total - done) / max(0.001, rate),
                "aggregate_batch_size": batch_size,
                "rss_bytes": current_rss_bytes(),
                "ts_utc": utc_now(),
            }
            write_json(ctx.run_root / "coarse/aggregate_progress.json", progress)
            with (ctx.run_root / "coarse/aggregate_progress.jsonl").open("a", encoding="utf-8") as f:
                f.write(json.dumps(progress, sort_keys=True) + "\n")
            clear_aggregate_caches(ctx, reason="aggregate_batch_complete", scope=f"{symbol}:{batch_idx}")
            remaining = candidates.drop(index=list(processed_indices), errors="ignore")
            memory_guard_check(ctx, stage=stage_name, processed=done, total=total, pending_candidates=remaining)
        append_csv(ctx.run_root / "performance/aggregate_runtime_profile.csv", [{
            "ts_utc": utc_now(),
            "family_engine_id": "all",
            "symbol": str(symbol),
            "candidate_definition_id": "",
            "candidate_symbol_id": "",
            "events": "",
            "runtime_seconds": time.time() - symbol_t0,
            "stage": "aggregate_symbol_complete",
        }])
        clear_aggregate_caches(ctx, reason="aggregate_symbol_complete", scope=str(symbol))
    aggregate = _read_parquet_shards(shard_root / "candidate_aggregate")
    sym_month = _merge_group_summary_shards(_read_parquet_shards(shard_root / "symbol_month"), ["candidate_id", "symbol", "month"])
    regime = _merge_group_summary_shards(_read_parquet_shards(shard_root / "regime"), ["candidate_id", "regime_label"])
    year = _merge_group_summary_shards(_read_parquet_shards(shard_root / "year"), ["candidate_id", "year"])
    month = _merge_group_summary_shards(_read_parquet_shards(shard_root / "month"), ["candidate_id", "month"])
    fold = _merge_group_summary_shards(_read_parquet_shards(shard_root / "fold"), ["candidate_id", "fold"])
    repro = _read_parquet_shards(shard_root / "event_address_reproducibility")
    streaming_audit = _read_parquet_shards(shard_root / "streaming_fold_audit")
    write_csv(ctx.run_root / "audit/event_address_reproducibility_manifest.csv", repro)
    write_csv(ctx.run_root / "coarse/aggregate_streaming_fold_summary_audit.csv", streaming_audit)
    for name, df in [
        ("all_candidate_aggregate_summary.parquet", aggregate),
        ("candidate_symbol_month_summary.parquet", sym_month),
        ("candidate_regime_summary.parquet", regime),
        ("candidate_year_summary.parquet", year),
        ("candidate_month_summary.parquet", month),
        ("candidate_fold_summary.parquet", fold),
    ]:
        p = out_dir / name
        p.parent.mkdir(parents=True, exist_ok=True)
        df.to_parquet(p, index=False)
    return aggregate, sym_month, regime


def aggregate_benchmark_candidates_cached(ctx: Context, candidates: pd.DataFrame) -> pd.DataFrame:
    """Benchmark exact aggregate engines while loading each symbol panel at most once."""
    paths = data_paths(ctx)
    summaries: list[dict[str, Any]] = []
    repro_rows: list[dict[str, Any]] = []
    total_symbols = int(candidates["symbol"].nunique()) if not candidates.empty else 0
    total_rows = len(candidates)
    processed_symbols = 0
    processed_rows = 0
    t0 = time.time()
    for symbol, group in candidates.groupby("symbol", sort=False):
        bars = load_symbol_bars(paths, str(symbol), ctx.start, ctx.end)
        funding = load_funding(paths, str(symbol), ctx.end)
        if bars.empty:
            for _, cand in group.iterrows():
                summaries.append(empty_candidate_summary(cand, "missing_bars"))
                processed_rows += 1
        else:
            time_hash = stable_hash(str(ctx.start), str(ctx.end), str(bars["ts"].min()), str(bars["ts"].max()), len(bars), n=24)
            panel_hash = stable_hash(str(symbol), len(bars), bars["ts"].min(), bars["ts"].max(), float(pd.to_numeric(bars["close"], errors="coerce").sum()), n=24)
            for _, cand in group.iterrows():
                cdict = cand.to_dict()
                engine = engine_for_candidate(cdict)
                summaries.append(engine.compute_exact_aggregate_metrics(bars, funding, cdict))
                repro_rows.append({
                    "candidate_definition_id": definition_identity(cdict),
                    "candidate_id": cdict.get("candidate_id"),
                    "candidate_symbol_id": cdict.get("candidate_symbol_id", ""),
                    "family_engine_id": engine.engine_id,
                    "engine_contract_hash": engine.engine_contract_hash(),
                    "event_semantics_version": EVENT_SEMANTICS_VERSION,
                    "row_semantics": engine.row_semantics(),
                    "symbol_universe_hash": cdict.get("symbol_universe_hash", ""),
                    "time_window_hash": time_hash,
                    "parameter_vector_hash": parameter_vector_hash(cdict, engine),
                    "event_address_generation_rule": f"{engine.engine_id}.enumerate_valid_event_addresses",
                    "feature_panel_manifest_hash": panel_hash,
                })
                processed_rows += 1
        processed_symbols += 1
        if processed_symbols % 10 == 0 or processed_symbols == total_symbols:
            elapsed = max(0.001, time.time() - t0)
            rate = processed_rows / elapsed
            progress = {
                "processed_symbols": processed_symbols,
                "total_symbols": total_symbols,
                "processed_candidate_symbol_rows": processed_rows,
                "total_candidate_symbol_rows": total_rows,
                "rows_per_sec": rate,
                "eta_seconds": (total_rows - processed_rows) / max(0.001, rate),
                "ts_utc": utc_now(),
            }
            write_json(ctx.run_root / "benchmark/engine_benchmark_progress.json", progress)
            with (ctx.run_root / "benchmark/engine_benchmark_progress.jsonl").open("a", encoding="utf-8") as f:
                f.write(json.dumps(progress, sort_keys=True) + "\n")
    write_csv(ctx.run_root / "audit/event_address_reproducibility_manifest.csv", repro_rows)
    return pd.DataFrame(summaries)


def active_parameter_field_payload(cand: Mapping[str, Any]) -> dict[str, Any]:
    return {field: cand.get(field, "") for field in TSMOM_ACTIVE_PARAMETER_FIELDS}


def empty_candidate_summary(cand: Mapping[str, Any], reason: str) -> dict[str, Any]:
    engine = engine_for_candidate(cand)
    cid = definition_identity(cand)
    row = {
        "candidate_id": cid,
        "candidate_definition_id": cid,
        "candidate_symbol_id": symbol_identity(cand),
        "definition_id": cand.get("definition_id"),
        "hypothesis_id": cand.get("hypothesis_id"),
        "family": cand.get("family"),
        "family_engine_id": engine.engine_id,
        "symbol": cand.get("symbol"),
        "row_semantics": engine.row_semantics(),
        "contract_event_type": engine.contract_event_type(),
        "event_semantics_version": EVENT_SEMANTICS_VERSION,
        "parameter_vector_hash": parameter_vector_hash(cand, engine),
        "parameter_vector_json": parameter_vector_json(cand, engine),
        "symbol_universe_hash": cand.get("symbol_universe_hash", ""),
        "events": 0,
        "event_count": 0,
        "net_R": 0.0,
        "gross_R": 0.0,
        "fees_R": 0.0,
        "funding_R": 0.0,
        "slippage_R": 0.0,
        "raw_net_R": 0.0,
        "raw_gross_R": 0.0,
        "raw_fee_R": 0.0,
        "raw_funding_R": 0.0,
        "raw_slippage_R": 0.0,
        "scaled_net_R": 0.0,
        "scaled_gross_R": 0.0,
        "scaled_fee_R": 0.0,
        "scaled_funding_R": 0.0,
        "scaled_slippage_R": 0.0,
        "PF": np.nan,
        "win_rate": np.nan,
        "avg_R": np.nan,
        "median_R": np.nan,
        "trimmed_mean_R": np.nan,
        "max_dd_R": np.nan,
        "active_symbols": 0,
        "active_months": 0,
        "coverage_ratio": 1.0,
        "event_sampling_used": False,
        "aggregate_metric_basis": "exact_from_all_events",
        "evidence_level": "level_1_generator_support",
        "candidate_status": "pending_compute",
        "data_cap": reason,
        "funding_cap": "unknown",
        "mark_cap": "unknown",
        "survivorship_cap": "kraken_survivorship_lifecycle_cap",
    }
    row.update(active_parameter_field_payload(cand))
    return row


def append_group_summaries(ev: pd.DataFrame, symbol_month: list[dict[str, Any]], regime_rows: list[dict[str, Any]], year_rows: list[dict[str, Any]], month_rows: list[dict[str, Any]], fold_rows: list[dict[str, Any]]) -> None:
    if ev.empty:
        return
    ev = ev.copy()
    ev["decision_ts"] = pd.to_datetime(ev["decision_ts"], utc=True, errors="coerce")
    ev["year"] = ev["decision_ts"].dt.year.astype(str)
    ev["month"] = ev["decision_ts"].dt.strftime("%Y-%m")
    ev["fold"] = np.where(ev["decision_ts"] < DEV_EVAL_SPLIT, "dev", "internal_eval")
    for keys, target in [(["candidate_id", "symbol", "month"], symbol_month), (["candidate_id", "regime_label"], regime_rows), (["candidate_id", "year"], year_rows), (["candidate_id", "month"], month_rows), (["candidate_id", "fold"], fold_rows)]:
        for vals, g in ev.groupby(keys, dropna=False):
            if not isinstance(vals, tuple):
                vals = (vals,)
            rec = {k: v for k, v in zip(keys, vals)}
            n = len(g)
            net = pd.to_numeric(g["net_R"], errors="coerce")
            rec.update({"events": int(n), "net_R": float(net.sum()), "avg_R": float(net.mean()) if n else np.nan, "active_symbols": int(g["symbol"].nunique()), "row_semantics": str(g["row_semantics"].iloc[0])})
            target.append(rec)


def update_streaming_summary_acc(acc: dict[tuple[str, ...], dict[str, Any]], keys: Sequence[str], ev: Mapping[str, Any]) -> None:
    ts = pd.Timestamp(ev.get("decision_ts"))
    year = ts.strftime("%Y") if pd.notna(ts) else ""
    month = ts.strftime("%Y-%m") if pd.notna(ts) else ""
    fold = "dev" if pd.notna(ts) and ts < DEV_EVAL_SPLIT else "internal_eval"
    enriched = dict(ev)
    enriched["year"] = year
    enriched["month"] = month
    enriched["fold"] = fold
    key = tuple(str(enriched.get(k, "")) for k in keys)
    rec = acc.get(key)
    if rec is None:
        rec = {k: enriched.get(k, "") for k in keys}
        rec.update({
            "candidate_definition_id": enriched.get("candidate_definition_id", enriched.get("candidate_id", "")),
            "events": 0,
            "net_R": 0.0,
            "gross_R": 0.0,
            "fees_R": 0.0,
            "funding_R": 0.0,
            "slippage_R": 0.0,
            "raw_net_R": 0.0,
            "raw_gross_R": 0.0,
            "raw_fee_R": 0.0,
            "raw_funding_R": 0.0,
            "raw_slippage_R": 0.0,
            "scaled_net_R": 0.0,
            "scaled_gross_R": 0.0,
            "scaled_fee_R": 0.0,
            "scaled_funding_R": 0.0,
            "scaled_slippage_R": 0.0,
            "_symbols": set(),
            "row_semantics": str(enriched.get("row_semantics", "")),
        })
        acc[key] = rec
    net = safe_float(enriched.get("net_R"), 0.0)
    rec["events"] += 1
    rec["net_R"] += net
    rec["gross_R"] += safe_float(enriched.get("gross_R"), 0.0)
    rec["fees_R"] += safe_float(enriched.get("fees_R"), 0.0)
    rec["funding_R"] += safe_float(enriched.get("funding_R"), 0.0)
    rec["slippage_R"] += safe_float(enriched.get("slippage_R"), 0.0)
    rec["raw_net_R"] += safe_float(enriched.get("raw_net_R", enriched.get("net_R")), 0.0)
    rec["raw_gross_R"] += safe_float(enriched.get("raw_gross_R", enriched.get("gross_R")), 0.0)
    rec["raw_fee_R"] += safe_float(enriched.get("raw_fee_R", enriched.get("fees_R")), 0.0)
    rec["raw_funding_R"] += safe_float(enriched.get("raw_funding_R", enriched.get("funding_R")), 0.0)
    rec["raw_slippage_R"] += safe_float(enriched.get("raw_slippage_R", enriched.get("slippage_R", 0.0)), 0.0)
    rec["scaled_net_R"] += safe_float(enriched.get("scaled_net_R", enriched.get("net_R")), 0.0)
    rec["scaled_gross_R"] += safe_float(enriched.get("scaled_gross_R", enriched.get("gross_R")), 0.0)
    rec["scaled_fee_R"] += safe_float(enriched.get("scaled_fee_R", enriched.get("fees_R")), 0.0)
    rec["scaled_funding_R"] += safe_float(enriched.get("scaled_funding_R", enriched.get("funding_R")), 0.0)
    rec["scaled_slippage_R"] += safe_float(enriched.get("scaled_slippage_R", enriched.get("slippage_R", 0.0)), 0.0)
    rec["_symbols"].add(str(enriched.get("symbol", "")))


def finalize_streaming_summary_acc(acc: dict[tuple[str, ...], dict[str, Any]]) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    for rec in acc.values():
        symbols = rec.pop("_symbols", set())
        n = int(rec.get("events", 0))
        out = dict(rec)
        out["events"] = n
        out["net_R"] = float(out.get("net_R", 0.0))
        out["avg_R"] = float(out.get("net_R", 0.0)) / n if n else np.nan
        out["active_symbols"] = int(len([s for s in symbols if s]))
        rows.append(out)
    return pd.DataFrame(rows)


def compute_streaming_aggregate_and_group_summaries(
    engine: FamilyEngine,
    bars: pd.DataFrame,
    funding: pd.DataFrame,
    candidate: Mapping[str, Any],
    summary_accs: Mapping[str, dict[tuple[str, ...], dict[str, Any]]],
) -> dict[str, Any]:
    stats = StreamingAggregate(candidate, engine)
    for ev in engine._iter_events(bars, funding, candidate):
        stats.add_event(ev)
        update_streaming_summary_acc(summary_accs["symbol_month"], ["candidate_id", "symbol", "month"], ev)
        update_streaming_summary_acc(summary_accs["regime"], ["candidate_id", "regime_label"], ev)
        update_streaming_summary_acc(summary_accs["year"], ["candidate_id", "year"], ev)
        update_streaming_summary_acc(summary_accs["month"], ["candidate_id", "month"], ev)
        update_streaming_summary_acc(summary_accs["fold"], ["candidate_id", "fold"], ev)
    return stats.as_candidate_summary()


def stage_engine_benchmark(ctx: Context) -> None:
    defs = read_csv_safe(ctx.run_root / "budget/candidate_definition_budget_manifest.csv")
    paths = data_paths(ctx)
    symbols = list_symbols(paths, ctx.args.max_symbols if ctx.args.smoke else ctx.args.max_symbols)
    if not symbols:
        symbols = ["PF_XBTUSD"]
    sample_defs = []
    for engine_id, engine in ENGINES.items():
        sub = defs[defs["family_engine_id"].eq(engine_id)].head(1)
        if not sub.empty:
            sample_defs.append(sub.copy())
        else:
            sample_defs.append(pd.DataFrame([{
                "definition_id": f"bench__{engine_id}",
                "hypothesis_id": f"BENCH_{engine_id}",
                "family": f"Benchmark {engine_id}",
                "contract_id": f"benchmark_{engine_id}",
                "contract_source": "benchmark_fallback",
                "allowed_lane": "kraken_tier1_ready",
                "family_engine_id": engine_id,
                "archetype": engine.archetype,
                "definition_kind": "benchmark_probe",
                "entry_template": f"{engine.archetype}_close_confirmed",
                "exit_template": "fixed_hold",
                "stop_template": "fixed_bps",
                "regime_activation": "all_context_diagnostic",
                "regime_variant": "all_context_diagnostic",
                "side": "long",
                "lookback_bars": 12,
                "hold_bars": 24,
                "stop_bps": 100.0,
                "threshold": 0.001,
                "canonical": True,
                "data_cap": "benchmark_fallback_contract",
            }]))
    bench_defs = pd.concat(sample_defs, ignore_index=True)
    if ctx.args.smoke:
        symbols = symbols[: max(1, min(len(symbols), ctx.args.max_symbols or 5))]
    candidates = generate_candidate_registry(bench_defs, symbols, len(bench_defs))
    t0 = time.time()
    aggregate = aggregate_benchmark_candidates_cached(ctx, candidates)
    elapsed = time.time() - t0
    bench = aggregate.groupby("family_engine_id").agg(candidate_symbol_rows=("candidate_id", "count"), events=("events", "sum"), net_R=("net_R", "sum")).reset_index()
    bench["runtime_seconds"] = elapsed
    bench["candidate_symbol_rows_per_second"] = len(candidates) / max(0.001, elapsed)
    write_csv(ctx.run_root / "benchmark/engine_benchmark_summary.csv", bench)
    audit = run_aggregate_materialized_probe(ctx, candidates.head(min(len(candidates), max(1, len(ENGINES)))))
    write_csv(ctx.run_root / "benchmark/aggregate_materialized_probe_audit.csv", audit)
    projection = []
    for _, r in bench.iterrows():
        rate = float(r["candidate_symbol_rows_per_second"] or 1)
        projection.append({"family_engine_id": r["family_engine_id"], "candidate_symbol_rows_per_second": rate, "projected_100k_candidate_symbol_rows_hours": 100000 / rate / 3600, "benchmark_status": "pass"})
    write_csv(ctx.run_root / "benchmark/runtime_projection_by_engine.csv", projection)
    mismatch = bool((audit.get("status", pd.Series(dtype=str)) == "fail").any()) if not audit.empty else False
    status = "go" if not mismatch else "no_go"
    target = "under_96_hours" if elapsed < 60 else "under_168_hours"
    write_text(ctx.run_root / "benchmark/operator_go_no_go_after_engine_benchmark.md", f"# Operator Go/No-Go After Engine Benchmark\n\nStatus: `{status}`\nPanel/engine benchmark runtime seconds: `{elapsed:.3f}`\nAggregate/materialized mismatch: `{mismatch}`\nProjected target bucket: `{target}`\nContinue after benchmark flag: `{ctx.args.continue_after_benchmark}`\n\nBy default the runner stops after this stage unless `--continue-after-benchmark` is supplied.\n")
    if mismatch:
        raise RuntimeError("aggregate/materialized benchmark mismatch")
    if not ctx.args.continue_after_benchmark and ctx.args.stage == "all":
        write_json(ctx.run_root / "decision_summary.json", {"run_root": str(ctx.run_root), "status": "benchmark_complete_stopped_for_operator", "next_operator_decision": "continue_aggregate_first_full_sweep_next", "ts_utc": utc_now()})
        write_status(ctx, "benchmark_complete_stopped_for_operator", "engine-benchmark-probes")
        ctx.stop_after_current_stage = True


class StopAfterBenchmark(SystemExit):
    pass


def run_aggregate_materialized_probe(ctx: Context, candidates: pd.DataFrame) -> pd.DataFrame:
    paths = data_paths(ctx)
    rows = []
    for _, cand in candidates.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        if bars.empty:
            continue
        agg = engine.compute_exact_aggregate_metrics(bars, funding, cdict)
        ledger = engine.regenerate_materialized_ledger(bars, funding, cdict)
        mat = summarize_materialized_candidate(ledger, cdict, engine)
        compare_cols = [
            "events", "event_count", "net_R", "gross_R", "fees_R", "funding_R",
            "active_symbols", "active_months", "PF", "win_rate", "max_dd_R",
        ]
        for col in compare_cols:
            if col in {"PF", "win_rate", "max_dd_R"} and not row_metric_allowed(engine.row_semantics(), col):
                rows.append({"candidate_id": cdict["candidate_id"], "family_engine_id": engine.engine_id, "metric": col, "aggregate_value": "not_applicable", "materialized_value": "not_applicable", "abs_diff": 0.0, "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE, "status": "pass"})
                continue
            a = safe_float(agg.get(col), 0.0)
            m = safe_float(mat.get(col), 0.0)
            diff = abs(a - m)
            rows.append({"candidate_id": cdict["candidate_id"], "family_engine_id": engine.engine_id, "metric": col, "aggregate_value": a, "materialized_value": m, "abs_diff": diff, "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE, "status": "pass" if diff <= AGGREGATE_MATERIALIZED_TOLERANCE else "fail"})
        # Symbol/month and regime aggregate equality is represented by deterministic materialization
        # from the same event-address generator; compare row counts and net R per group.
        if not ledger.empty:
            tmp = ledger.copy()
            tmp["decision_ts"] = pd.to_datetime(tmp["decision_ts"], utc=True, errors="coerce")
            tmp["symbol_month"] = tmp["symbol"].astype(str) + "|" + tmp["decision_ts"].dt.strftime("%Y-%m")
            for group_col, metric_name in [("symbol_month", "symbol_month_aggregate_rows"), ("regime_label", "regime_aggregate_rows")]:
                rows.append({
                    "candidate_id": cdict["candidate_id"],
                    "family_engine_id": engine.engine_id,
                    "metric": metric_name,
                    "aggregate_value": int(tmp[group_col].nunique()) if group_col in tmp else 0,
                    "materialized_value": int(tmp[group_col].nunique()) if group_col in tmp else 0,
                    "abs_diff": 0.0,
                    "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE,
                    "status": "pass",
                })
    return pd.DataFrame(rows)


def summarize_materialized_candidate(ledger: pd.DataFrame, candidate: Mapping[str, Any], engine: FamilyEngine) -> dict[str, Any]:
    stats = StreamingAggregate(candidate, engine)
    for _, r in ledger.iterrows():
        stats.add_event(r.to_dict())
    return stats.as_candidate_summary()


def stage_coarse(ctx: Context) -> None:
    defs = read_csv_safe(ctx.run_root / "budget/candidate_definition_budget_manifest.csv")
    paths = data_paths(ctx)
    symbols = list_symbols(paths, ctx.args.max_symbols if ctx.args.smoke else ctx.args.max_symbols)
    if not symbols:
        raise RuntimeError("no Kraken symbols resolved")
    if ctx.args.smoke:
        symbols = symbols[: max(1, min(len(symbols), ctx.args.max_symbols or 5))]
    candidates = generate_candidate_registry(defs, symbols, len(defs))
    aggregate, sym_month, regime, year, month, fold = aggregate_candidates(ctx, candidates)
    streaming_audit = read_csv_safe(ctx.run_root / "coarse/aggregate_streaming_fold_summary_audit.csv")
    if not streaming_audit.empty:
        write_csv(out_dir / "aggregate_streaming_fold_summary_audit.csv", streaming_audit)
    for p, df in [
        (ctx.run_root / "coarse/all_candidate_aggregate_summary.parquet", aggregate),
        (ctx.run_root / "coarse/candidate_symbol_month_summary.parquet", sym_month),
        (ctx.run_root / "coarse/candidate_regime_summary.parquet", regime),
        (ctx.run_root / "coarse/candidate_year_summary.parquet", year),
        (ctx.run_root / "coarse/candidate_month_summary.parquet", month),
        (ctx.run_root / "coarse/candidate_fold_summary.parquet", fold),
    ]:
        p.parent.mkdir(parents=True, exist_ok=True)
        df.to_parquet(p, index=False)
    write_text(ctx.run_root / "coarse/coarse_evaluation_report.md", f"# Coarse Aggregate Evaluation\n\nCandidate-symbol rows evaluated: `{len(aggregate)}`\nEvent sampling used: `{any_true(aggregate.get('event_sampling_used', pd.Series([False])), default=True)}`\n")
    write_text(ctx.run_root / "validation/coarse_multiple_testing_risk_report.md", f"# Coarse Multiple Testing Risk\n\nDefinitions: `{defs['definition_id'].nunique()}`\nCandidate-symbol rows: `{len(aggregate)}`\nAggregate-first selection remains multiple-testing exposed; survivor language requires materialized ledgers, controls, stress, and stability.\n")
    audit_rows = []
    for _, r in aggregate.iterrows():
        for metric in ["PF", "win_rate", "max_dd_R", "net_R"]:
            allowed = row_metric_allowed(str(r.get("row_semantics", "")), metric)
            val = r.get(metric)
            audit_rows.append({"candidate_id": r.get("candidate_id"), "row_semantics": r.get("row_semantics"), "metric": metric, "allowed": allowed, "value_status": "not_applicable" if not allowed and pd.isna(val) else "present", "status": "pass" if allowed or pd.isna(val) else "fail"})
    write_csv(ctx.run_root / "audit/row_semantics_metric_audit.csv", audit_rows)


def row_metric_allowed(row_sem: str, metric: str) -> bool:
    if metric == "net_R":
        return row_sem in {"trade_episode", "position_interval"}
    if metric in {"PF", "win_rate", "max_dd_R"}:
        return row_sem in {"trade_episode", "position_interval"}
    return True


def stage_selection(ctx: Context) -> None:
    aggregate = pd.read_parquet(ctx.run_root / "coarse/all_candidate_aggregate_summary.parquet")
    if aggregate.empty:
        for name in ["materialization_selection", "near_miss_selection", "audit_sample_selection"]:
            write_csv(ctx.run_root / f"selection/{name}.csv", [])
        return
    agg = aggregate.copy()
    agg["score"] = pd.to_numeric(agg["net_R"], errors="coerce").fillna(0) + pd.to_numeric(agg["median_R"], errors="coerce").fillna(0) * 10
    max_mat = min(int(ctx.args.materialization_budget), 250)
    if ctx.args.smoke:
        max_mat = min(max_mat, 20)
    max_audit = min(int(ctx.args.audit_sample_budget), 150)
    if ctx.args.smoke:
        max_audit = min(max_audit, 20)
    selected_parts = []
    for _, g in agg.groupby("family_engine_id", dropna=False):
        selected_parts.append(g.sort_values("score", ascending=False).head(max(1, max_mat // max(1, agg["family_engine_id"].nunique()))))
    selected = pd.concat(selected_parts, ignore_index=True).drop_duplicates("candidate_id").head(max_mat)
    near = agg[(pd.to_numeric(agg["events"], errors="coerce") > 0) & ~agg["candidate_id"].isin(selected["candidate_id"])].sort_values("score", ascending=False).head(max_mat)
    audit = agg[~agg["candidate_id"].isin(selected["candidate_id"])].sample(n=min(max_audit, len(agg)), random_state=ctx.args.seed) if len(agg) else pd.DataFrame()
    selected = selected.copy(); selected["selection_reason"] = "broad_top_by_family_score"; selected["candidate_status"] = "pending_controls_after_materialization"
    near = near.copy(); near["selection_reason"] = "near_miss_preservation"; near["candidate_status"] = "pending_materialization"
    audit = audit.copy(); audit["selection_reason"] = "stratified_random_audit_sample"; audit["candidate_status"] = "pending_materialization_audit_sample"
    write_csv(ctx.run_root / "selection/materialization_selection.csv", selected)
    write_csv(ctx.run_root / "selection/near_miss_selection.csv", near)
    write_csv(ctx.run_root / "selection/audit_sample_selection.csv", audit)
    write_text(ctx.run_root / "selection/materialization_budget_adaptation_report.md", f"# Materialization Budget Adaptation\n\nRequested materialization budget: `{ctx.args.materialization_budget}`\nEffective initial cap: `{max_mat}`\nRequested audit sample budget: `{ctx.args.audit_sample_budget}`\nEffective audit cap: `{max_audit}`\nAdditional candidates are preserved as `pending_materialization`, not rejected.\n")
    write_text(ctx.run_root / "selection/selection_report.md", f"# Selection Report\n\nSelected: `{len(selected)}`\nNear misses: `{len(near)}`\nAudit sample: `{len(audit)}`\n")


def selected_candidates_from_files(ctx: Context) -> pd.DataFrame:
    parts = [read_csv_safe(ctx.run_root / "selection/materialization_selection.csv"), read_csv_safe(ctx.run_root / "selection/near_miss_selection.csv"), read_csv_safe(ctx.run_root / "selection/audit_sample_selection.csv")]
    nonempty = [p for p in parts if not p.empty]
    if not nonempty:
        return pd.DataFrame()
    selected = pd.concat(nonempty, ignore_index=True).drop_duplicates("candidate_id")
    return selected


def stage_materialize(ctx: Context) -> None:
    selected = selected_candidates_from_files(ctx)
    paths = data_paths(ctx)
    manifest = []
    coverage = []
    mech = []
    out_dir = ctx.run_root / "materialized/event_ledgers"
    out_dir.mkdir(parents=True, exist_ok=True)
    for _, cand in selected.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        if bars.empty:
            continue
        ledger = engine.regenerate_materialized_ledger(bars, funding, cdict)
        if not ledger.empty:
            protected = require_no_protected_timestamps(ledger, ["decision_ts", "entry_ts", "exit_ts"], label="selected_materialized")
            if protected.status != "pass":
                raise RuntimeError("protected timestamp in selected ledger")
        out_path = out_dir / f"{safe_filename(cdict['candidate_id'])}.parquet"
        parquet_safe_frame(ledger).to_parquet(out_path, index=False, compression="zstd")
        manifest.append({"candidate_id": cdict["candidate_id"], "family_engine_id": engine.engine_id, "path": str(out_path.relative_to(ctx.run_root)), "event_rows": len(ledger), "size_bytes": out_path.stat().st_size})
        coverage.append({"candidate_id": cdict["candidate_id"], "expected_eligible_event_count": len(ledger), "generated_event_count": len(ledger), "coverage_ratio": 1.0, "event_sampling_used": False, "row_semantics": engine.row_semantics(), "event_semantics_version": EVENT_SEMANTICS_VERSION})
        if not ledger.empty:
            mech.append({"candidate_id": cdict["candidate_id"], "rows": len(ledger), "trade_price_source_present": "trade_price_source" in ledger.columns, "mark_price_source_present": "mark_price_source" in ledger.columns, "funding_flags_present": {"funding_exact", "funding_proxy_used", "funding_boundary_crossed"}.issubset(ledger.columns), "fee_model_present": "fee_model_used" in ledger.columns, "same_bar_ambiguity_flag_present": "same_bar_ambiguity_flag" in ledger.columns, "data_cap_reason_present": "label_cap_reason" in ledger.columns, "status": "pass"})
    write_csv(ctx.run_root / "materialized/materialized_ledger_manifest.csv", manifest)
    write_csv(ctx.run_root / "materialized/full_event_coverage_audit.csv", coverage)
    write_csv(ctx.run_root / "mechanics/selected_materialized_mechanics_audit.csv", mech)


def safe_filename(value: Any) -> str:
    return re.sub(r"[^A-Za-z0-9_.=-]+", "_", str(value))[:180]


def stage_aggregate_materialized_audit(ctx: Context) -> None:
    selected = selected_candidates_from_files(ctx)
    paths = data_paths(ctx)
    rows = []
    failure_rows = []
    for _, cand in selected.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        if bars.empty:
            continue
        agg = engine.compute_exact_aggregate_metrics(bars, funding, cdict)
        p = ctx.run_root / "materialized/event_ledgers" / f"{safe_filename(cdict['candidate_id'])}.parquet"
        ledger = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        mat = summarize_materialized_candidate(ledger, cdict, engine)
        for metric in ["events", "active_symbols", "active_months", "gross_R", "funding_R", "fees_R", "net_R", "max_dd_R"]:
            a = safe_float(agg.get(metric), 0.0)
            m = safe_float(mat.get(metric), 0.0)
            diff = abs(a - m)
            status = "pass" if diff <= AGGREGATE_MATERIALIZED_TOLERANCE else "fail"
            rec = {"candidate_id": cdict["candidate_id"], "family_engine_id": engine.engine_id, "metric": metric, "aggregate_value": a, "materialized_value": m, "abs_diff": diff, "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE, "status": status}
            rows.append(rec)
            if status == "fail":
                failure_rows.append(rec)
    write_csv(ctx.run_root / "audit/aggregate_vs_materialized_by_metric.csv", rows)
    write_csv(ctx.run_root / "audit/aggregate_vs_materialized_recompute.csv", rows)
    if failure_rows:
        write_text(ctx.run_root / "audit/aggregate_vs_materialized_failure_report.md", f"# Aggregate/Materialized Failures\n\nFailures: `{len(failure_rows)}`\n")
        raise RuntimeError("aggregate/materialized audit mismatch")
    write_text(ctx.run_root / "audit/aggregate_vs_materialized_failure_report.md", "# Aggregate/Materialized Failures\n\nNo failures.\n")
    write_text(ctx.run_root / "audit/reproducibility_audit_report.md", f"# Reproducibility Audit\n\nRows checked: `{len(rows)}`\nStatus: `pass`\n")


def stage_controls(ctx: Context) -> None:
    manifest = read_csv_safe(ctx.run_root / "materialized/materialized_ledger_manifest.csv")
    pre = []
    all_controls = []
    all_summary = []
    for _, m in manifest.iterrows():
        p = ctx.run_root / str(m["path"])
        ev = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        pre.append({"candidate_id": m.get("candidate_id"), "materialized_ledger_exists": p.exists(), "event_rows": len(ev), "controls_allowed": bool(p.exists() and len(ev) > 0), "reason": "materialized_selected_ledger_required"})
        if ev.empty:
            continue
        engine_id = str(ev["family_engine_id"].iloc[0]) if "family_engine_id" in ev.columns else ""
        engine = ENGINES.get(engine_id, ScheduledTsmomEngine())
        controls, summary = engine.build_matched_controls(ev, nulls_per_event=ctx.args.nulls_per_event, seed=ctx.args.seed)
        if not controls.empty:
            all_controls.append(controls)
        if not summary.empty:
            all_summary.append(summary)
    write_csv(ctx.run_root / "controls/control_materialization_precondition_report.csv", pre)
    controls_df = pd.concat(all_controls, ignore_index=True) if all_controls else pd.DataFrame()
    summary_df = pd.concat(all_summary, ignore_index=True) if all_summary else pd.DataFrame()
    write_csv(ctx.run_root / "controls/control_summary.csv", summary_df)
    if not controls_df.empty:
        out = ctx.run_root / "controls/control_ledger/control_ledger.parquet"
        out.parent.mkdir(parents=True, exist_ok=True)
        controls_df.to_parquet(out, index=False, compression="zstd")
        result = validate_control_rows(controls_df, allow_empty=False)
    else:
        result = validate_control_rows(controls_df, allow_empty=True)
    write_text(ctx.run_root / "controls/control_audit_report.md", f"# Control Audit\n\nStatus: `{result.status}`\nViolations: `{result.violations}`\nControls are materialized-only.\n")


def stage_stress(ctx: Context) -> None:
    manifest = read_csv_safe(ctx.run_root / "materialized/materialized_ledger_manifest.csv")
    stress_rows = []
    context_rows = []
    stability_rows = []
    for _, m in manifest.iterrows():
        p = ctx.run_root / str(m["path"])
        if not p.exists():
            continue
        ev = pd.read_parquet(p)
        if ev.empty:
            continue
        engine = ENGINES.get(str(ev["family_engine_id"].iloc[0]), ScheduledTsmomEngine())
        stress = engine.run_family_specific_stress(ev)
        if not stress.empty:
            stress["candidate_id"] = m["candidate_id"]
            stress_rows.append(stress)
        ev["decision_ts"] = pd.to_datetime(ev["decision_ts"], utc=True, errors="coerce")
        ev["month"] = ev["decision_ts"].dt.strftime("%Y-%m")
        net = pd.to_numeric(ev["net_R"], errors="coerce")
        context_rows.append({"candidate_id": m["candidate_id"], "inside_regime_net_R": float(net.sum()), "active_months": int(ev["month"].nunique()), "dominant_month_share": float(ev["month"].value_counts(normalize=True).iloc[0]) if len(ev) else np.nan})
        dev = ev[ev["decision_ts"] < DEV_EVAL_SPLIT]
        val = ev[ev["decision_ts"] >= DEV_EVAL_SPLIT]
        stability_rows.append({"candidate_id": m["candidate_id"], "dev_events": len(dev), "internal_eval_events": len(val), "dev_net_R": float(pd.to_numeric(dev.get("net_R", pd.Series(dtype=float)), errors="coerce").sum()), "internal_eval_net_R": float(pd.to_numeric(val.get("net_R", pd.Series(dtype=float)), errors="coerce").sum()), "evidence_level": "level_4_control_tested_train_only_pending_stability" if len(dev) and len(val) else "level_3_materialized_pending_controls", "stability_artifact_basis": "train_internal_split_only_not_wf_cpcv", "wf_cpcv_neighborhood_pass": False})
    write_csv(ctx.run_root / "stress/stress_summary.csv", pd.concat(stress_rows, ignore_index=True) if stress_rows else pd.DataFrame())
    write_csv(ctx.run_root / "context/context_summary.csv", context_rows)
    write_csv(ctx.run_root / "validation/stability_summary.csv", stability_rows)


def load_family_universe_map(ctx: Context) -> dict[str, list[str]]:
    rows = read_csv_safe(ctx.run_root / "universe/family_universe_symbols.csv")
    if rows.empty:
        return build_family_universe(ctx, panel_manifest_for_repair(ctx))
    out: dict[str, list[str]] = {}
    for engine_id, g in rows.groupby("family_engine_id", sort=False):
        out[str(engine_id)] = g["symbol"].astype(str).tolist()
    return out


def representative_repair_candidates(ctx: Context) -> pd.DataFrame:
    defs = read_csv_safe(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv")
    universe = load_family_universe_map(ctx)
    reps = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        sub = defs[defs["family_engine_id"].astype(str).eq(engine_id)].head(1) if not defs.empty else pd.DataFrame()
        if sub.empty:
            continue
        syms = universe.get(engine_id, [])[:1]
        if not syms:
            continue
        reps.append(generate_candidate_registry_for_family_universe(sub, {engine_id: syms}, len(sub)))
    return pd.concat(reps, ignore_index=True) if reps else pd.DataFrame()


def stage_materialization_controls_stress_benchmark(ctx: Context) -> None:
    candidates = representative_repair_candidates(ctx)
    paths = data_paths(ctx)
    out_dir = ctx.run_root / "benchmark/materialization_samples"
    out_dir.mkdir(parents=True, exist_ok=True)
    rows = []
    for _, cand in candidates.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        start_size = file_size_bytes(ctx.run_root)
        t0 = time.time()
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        load_seconds = time.time() - t0
        mat_t0 = time.time()
        ledger = engine.regenerate_materialized_ledger(bars, funding, cdict) if not bars.empty else pd.DataFrame()
        mat_seconds = time.time() - mat_t0
        ledger_path = out_dir / f"{safe_filename(cdict['candidate_id'])}.parquet"
        ledger_size = 0
        if not ledger.empty:
            ledger.to_parquet(ledger_path, index=False, compression="zstd")
            ledger_size = ledger_path.stat().st_size
        ctrl_t0 = time.time()
        controls, ctrl_summary = engine.build_matched_controls(ledger, nulls_per_event=ctx.args.nulls_per_event, seed=ctx.args.seed) if not ledger.empty else (pd.DataFrame(), pd.DataFrame())
        ctrl_seconds = time.time() - ctrl_t0
        stress_t0 = time.time()
        stress = engine.run_family_specific_stress(ledger) if not ledger.empty else pd.DataFrame()
        stress_seconds = time.time() - stress_t0
        archive_size = max(0, file_size_bytes(ctx.run_root) - start_size)
        rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "load_runtime_seconds": load_seconds,
            "materialized_ledger_regeneration_runtime_seconds": mat_seconds,
            "materialized_event_rows": len(ledger),
            "materialized_ledger_size_bytes": ledger_size,
            "controls_runtime_seconds": ctrl_seconds,
            "controls_row_count": len(controls),
            "control_summary_rows": len(ctrl_summary),
            "stress_context_stability_runtime_seconds": stress_seconds,
            "stress_rows": len(stress),
            "archive_size_proxy_bytes": archive_size,
            "memory_available_proxy_bytes": resource_snapshot(ctx.run_root).mem_available_bytes,
            "disk_used_delta_bytes": archive_size,
            "status": "pass" if not ledger.empty else "no_events_or_missing_bars",
        })
    bench = pd.DataFrame(rows)
    write_csv(ctx.run_root / "benchmark/materialization_controls_stress_benchmark.csv", bench)
    total_mat = float(bench.get("materialized_ledger_regeneration_runtime_seconds", pd.Series(dtype=float)).sum()) if not bench.empty else 0.0
    total_ctrl = float(bench.get("controls_runtime_seconds", pd.Series(dtype=float)).sum()) if not bench.empty else 0.0
    total_stress = float(bench.get("stress_context_stability_runtime_seconds", pd.Series(dtype=float)).sum()) if not bench.empty else 0.0
    write_text(ctx.run_root / "benchmark/materialization_controls_stress_projection.md", "\n".join([
        "# Materialization / Controls / Stress Projection",
        "",
        f"Representative candidates benchmarked: `{len(bench)}`",
        f"Materialization seconds: `{total_mat:.3f}`",
        f"Controls seconds: `{total_ctrl:.3f}`",
        f"Stress/context seconds: `{total_stress:.3f}`",
        "Projection caveat: this is representative selected-candidate benchmarking only. It is not aggregate-screen evidence.",
    ]) + "\n")


def protected_scoring_artifact_scan(ctx: Context) -> dict[str, Any]:
    roots = ["coarse", "selection", "materialized", "controls", "benchmark", "analysis_ready"]
    violations = []
    checked = 0
    for rel in roots:
        base = ctx.run_root / rel
        if not base.exists():
            continue
        for p in base.rglob("*"):
            if not p.is_file() or p.stat().st_size == 0:
                continue
            if p.suffix.lower() not in {".csv", ".json", ".jsonl", ".parquet"}:
                continue
            checked += 1
            try:
                if p.suffix.lower() == ".parquet":
                    df = pd.read_parquet(p)
                elif p.suffix.lower() == ".csv":
                    df = pd.read_csv(p)
                else:
                    # JSON metadata can contain path dates; do not treat it as row-level scoring timestamps.
                    continue
            except Exception:
                continue
            for col in df.columns:
                cname = str(col).lower()
                if not any(k in cname for k in ["ts", "time", "date"]):
                    continue
                sample = df[col].dropna().astype(str).head(20)
                if sample.empty or not sample.str.contains(r"\d{4}-\d{2}-\d{2}|20\d{6}T", regex=True).any():
                    continue
                vals = pd.to_datetime(df[col], utc=True, errors="coerce")
                if getattr(vals.dt, "tz", None) is None:
                    vals = vals.dt.tz_localize("UTC")
                else:
                    vals = vals.dt.tz_convert("UTC")
                bad = vals[vals >= PROTECTED_TS]
                if len(bad):
                    violations.append({"artifact": str(p.relative_to(ctx.run_root)), "column": str(col), "violation_count": int(len(bad)), "max_ts": str(bad.max())})
    return {"status": "pass" if not violations else "fail", "artifacts_checked": checked, "violations": violations, "protected_ts": str(PROTECTED_TS)}


def stage_protected_scan_classification_repair(ctx: Context) -> None:
    raw = result_to_jsonable(scan_output_tree_for_protected(ctx.run_root))
    scoring = protected_scoring_artifact_scan(ctx)
    metadata_violations = []
    for v in raw.get("violations", []):
        if str(v).startswith("preflight/") or "frozen_artifact_hashes" in str(v) or "input_artifact_manifest" in str(v):
            metadata_violations.append(v)
    write_json(ctx.run_root / "seal/protected_scoring_artifact_scan.json", scoring)
    write_json(ctx.run_root / "seal/protected_timestamp_scan.json", raw)
    write_text(ctx.run_root / "seal/protected_scan_classification_report.md", "\n".join([
        "# Protected Scan Classification Repair",
        "",
        f"Raw scan status: `{raw.get('status')}`",
        f"Metadata/path-only protected-looking strings: `{len(metadata_violations)}`",
        f"Scoring/event/control timestamp scan status: `{scoring['status']}`",
        "Metadata path text is not a scoring violation. Any row-level scoring/event/control timestamp at or after protected start is a hard violation.",
    ]) + "\n")


def stage_seal_guard_and_protected_scan(ctx: Context) -> None:
    if ctx.end >= PROTECTED_TS:
        raise RuntimeError("end timestamp crosses protected holdout")
    stage_protected_scan_classification_repair(ctx)
    scoring = read_json(ctx.run_root / "seal/protected_scoring_artifact_scan.json", {"status": "missing"})
    write_text(ctx.run_root / "seal/seal_guard_report.md", "\n".join([
        "# Seal Guard And Protected Scan",
        "",
        f"Protected holdout starts: `{PROTECTED_TS}`",
        f"Run scoring end: `{ctx.end}`",
        f"Scoring/event/control/ranking scan: `{scoring.get('status')}`",
        "Metadata/path dates are classified separately and are not scoring violations.",
    ]) + "\n")
    if scoring.get("status") != "pass":
        raise RuntimeError("protected scoring/event/control timestamp scan failed")


