def priority_lane_for_row(row: Mapping[str, Any]) -> tuple[str, str, str, str, str]:
    text = " ".join(str(v).lower() for v in dict(row).values())
    archetype = str(row.get("archetype") or infer_archetype_from_row(row))
    tier1 = {"tsmom", "liquid_continuation", "prior_high", "retest_reclaim", "compression_breakout", "session_calendar", "funding_crowding"}
    if any(k in text for k in ["c2", "catalyst", "legal", "regulatory", "etf", "institutional", "exchange access", "leverage access"]):
        return "event_ledger_first_sidecar", "Tier 2 event ledger", "Tier 1 bars plus dated catalyst ledger", "event_ledger_first", "dated event ledger required before Kraken ranking"
    if any(k in text for k in ["liquidation", "deleverage", "order book", "book", "listing", "orb", "scalp", "microstructure", "cross-venue"]):
        return "forward_capture_sidecar", "Tier 2/3 capture", "Tier 2/3 capture", "capture_sidecar", "execution-sensitive translation needs forward capture substitute"
    if "tier c" in text or "small-cap" in text or "thin" in text or "illiquid" in text:
        return "priority_tier1_with_caps", "Tier 1 with liquidity cap", "Tier 1 with caps or capture", "capped_screen", "Tier C preserved but capped outside first clean continuation tranche"
    if archetype in tier1:
        if "analytics" in text or "proxy" in text or "cap" in text:
            return "priority_tier1_with_caps", "Tier 1 with caps", "Tier 1 plus capped analytics", "capped_screen", "bar-compatible but capped by data availability"
        return "priority_tier1_full_train_candidate", "Tier 1", "Tier 1", "screen_now", "bar-compatible close-confirmed next-bar executable"
    return "candidate_library_only", "unknown", "Tier 1+ redesign", "library_only", "not currently expressible as conservative Kraken Tier 1 historical test"


def stage_priority_lane_classification(ctx: Context) -> None:
    contracts = load_contract_sources(resolve_path(ctx.args.readiness_root), resolve_path(ctx.args.repair_root))
    req_rows = []
    for engine_id, meta in ENGINE_REPAIR_CONTRACTS.items():
        req_rows.append({
            "hypothesis_id": meta["hypothesis_id"],
            "family": meta["family"],
            "contract_id": f"repair_required_{engine_id}",
            "contract_source": "required_engine_repair_contract",
            "allowed_lane": "kraken_tier1_ready",
            "archetype": meta["archetype"],
            "family_engine_id": engine_id,
        })
    all_rows = pd.concat([contracts, pd.DataFrame(req_rows)], ignore_index=True).drop_duplicates(["hypothesis_id", "contract_id", "archetype"], keep="first")
    lane_rows = []
    for _, r in all_rows.iterrows():
        lane, cur_tier, req_tier, testability, reason = priority_lane_for_row(r)
        row = r.to_dict()
        row.update({
            "priority_lane": lane,
            "current_data_tier": cur_tier,
            "required_data_tier": req_tier,
            "current_testability": testability,
            "forward_capture_upgrade_path": "not_required_for_tier1" if lane.startswith("priority_tier1") else ("build_forward_capture_bundle" if lane == "forward_capture_sidecar" else "build_source_traced_event_ledger" if lane == "event_ledger_first_sidecar" else "none"),
            "lane_assignment_reason": reason,
        })
        lane_rows.append(row)
    lane_df = pd.DataFrame(lane_rows)
    if lane_df.astype(str).apply(lambda col: col.str.contains("waiting_for_vendor_data", case=False, regex=False)).any().any():
        raise RuntimeError("forbidden waiting_for_vendor_data lane text")
    write_csv(ctx.run_root / "priority/hypothesis_priority_lane.csv", lane_df)
    summary = lane_df.groupby(["priority_lane", "family_engine_id"], dropna=False).size().reset_index(name="hypothesis_rows")
    write_csv(ctx.run_root / "priority/family_priority_lane_summary.csv", summary)
    write_text(ctx.run_root / "priority/priority_classification_report.md", "\n".join([
        "# Priority Lane Classification",
        "",
        f"Rows classified: `{len(lane_df)}`",
        "Priority Tier 1 rows are bar-compatible, close-confirmed, and next-bar executable under current Kraken historical data.",
        "Execution-sensitive, C2/event, and Tier C variants are preserved but routed to capped, sidecar, or library lanes.",
    ]) + "\n")


