def estimate_engine_hours_from_projection(proj: pd.DataFrame, engine_id: str, definitions: int) -> float:
    if proj.empty:
        return float("inf")
    p = proj[proj.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)]
    if p.empty:
        return float("inf")
    syms = safe_float(p.get("family_symbol_count", pd.Series([0])).iloc[0], 0)
    rate = safe_float(p.get("candidate_symbol_rows_per_second", pd.Series([0])).iloc[0], 0)
    if rate <= 0:
        return float("inf")
    return definitions * syms / rate / 3600.0


def stage_v0_and_engine_wave_tranche_planning(ctx: Context) -> None:
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    # Use prior v1 measured rates if v2 benchmark has not run yet; benchmark-rerun updates projections later.
    prior_proj = read_csv_safe(prior_benchmark_root(ctx) / "benchmark/priority_tranche_runtime_projection.csv")
    v0_alloc = {
        "scheduled_tsmom_engine": 100,
        "liquid_continuation_breakout_engine": 125,
        "prior_high_reclaim_engine": 100,
        "retest_reclaim_lifecycle_engine": 75,
        "compression_breakout_engine": 75,
        "session_calendar_engine": 50,
        "funding_crowding_engine": 50,
    }
    rows = []
    for engine_id, target in v0_alloc.items():
        sub = defs[defs.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)].head(target) if not defs.empty else pd.DataFrame()
        hours = estimate_engine_hours_from_projection(prior_proj, engine_id, len(sub))
        rows.append({
            "tranche_id": "priority_tranche_v0",
            "family_engine_id": engine_id,
            "planned_definitions": len(sub),
            "runtime_hours_estimate": hours,
            "materialization_budget": max(5, min(25, len(sub))),
            "audit_sample_budget": max(5, min(15, len(sub))),
            "status": "planned_pending_v2_benchmark",
        })
    write_csv(ctx.run_root / "priority_tranche/v0_tranche_plan.csv", rows)
    wave_rows = []
    for r in rows:
        wave_rows.append({
            "engine_wave_id": f"{r['family_engine_id']}__wave_001",
            "family_engine_id": r["family_engine_id"],
            "planned_definitions": r["planned_definitions"],
            "runtime_hours_estimate": r["runtime_hours_estimate"],
            "launch_status": "not_launched_repair_benchmark_only",
        })
    write_csv(ctx.run_root / "priority_tranche/engine_wave_tranche_plan.csv", wave_rows)
    if defs.empty:
        pending = pd.DataFrame()
    else:
        used = set()
        for engine_id, target in v0_alloc.items():
            used.update(defs[defs["family_engine_id"].astype(str).eq(engine_id)].head(target)["definition_id"].astype(str))
        pending = defs[~defs["definition_id"].astype(str).isin(used)].copy()
        pending["pending_reason"] = "pending_compute_not_in_v0_repair_benchmark"
    write_csv(ctx.run_root / "priority_tranche/pending_compute_manifest.csv", pending)


def run_repaired_engine_benchmark(ctx: Context) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    defs = read_csv_safe(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv")
    universe = load_family_universe_map(ctx)
    bench_rows = []
    projection_rows = []
    audit_rows = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        sub = defs[defs["family_engine_id"].astype(str).eq(engine_id)].head(1) if not defs.empty else pd.DataFrame()
        syms = universe.get(engine_id, [])
        if sub.empty or not syms:
            bench_rows.append({"family_engine_id": engine_id, "candidate_symbol_rows": 0, "events": 0, "net_R": 0.0, "runtime_seconds": 0.0, "candidate_symbol_rows_per_second": 0.0, "benchmark_status": "missing_definition_or_universe"})
            continue
        candidates = generate_candidate_registry_for_family_universe(sub, {engine_id: syms}, len(sub))
        t0 = time.time()
        aggregate = aggregate_benchmark_candidates_cached(ctx, candidates)
        elapsed = time.time() - t0
        events = int(pd.to_numeric(aggregate.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not aggregate.empty else 0
        net = float(pd.to_numeric(aggregate.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not aggregate.empty else 0.0
        rate = len(candidates) / max(0.001, elapsed)
        bench_rows.append({"family_engine_id": engine_id, "candidate_symbol_rows": len(candidates), "events": events, "net_R": net, "runtime_seconds": elapsed, "candidate_symbol_rows_per_second": rate, "benchmark_status": "pass"})
        audit_rows.extend(run_aggregate_materialized_probe(ctx, candidates.head(1)).to_dict("records"))
        planned_defs = int((defs["family_engine_id"].astype(str) == engine_id).sum()) if not defs.empty else 0
        projected_rows = planned_defs * len(syms)
        projection_rows.append({"family_engine_id": engine_id, "planned_definitions": planned_defs, "family_symbol_count": len(syms), "projected_candidate_symbol_rows": projected_rows, "candidate_symbol_rows_per_second": rate, "projected_hours": projected_rows / max(0.001, rate) / 3600, "benchmark_status": "pass"})
    return pd.DataFrame(bench_rows), pd.DataFrame(projection_rows), pd.DataFrame(audit_rows)


def priority_tranche_candidate_registry(ctx: Context, *, one_definition_per_engine: bool = False) -> pd.DataFrame:
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    if defs.empty:
        defs = read_csv_safe(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv")
    if one_definition_per_engine and not defs.empty:
        defs = defs.groupby("family_engine_id", sort=False).head(1).reset_index(drop=True)
    universe = load_family_universe_map(ctx)
    return generate_candidate_registry_for_family_universe(defs, universe, len(defs)) if not defs.empty else pd.DataFrame()


def vectorized_scalar_exactness_audit(ctx: Context, candidates: pd.DataFrame) -> pd.DataFrame:
    paths = data_paths(ctx)
    rows: list[dict[str, Any]] = []
    sample = candidates.groupby("family_engine_id", sort=False).head(1) if not candidates.empty else pd.DataFrame()
    for _, cand in sample.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        if bars.empty:
            continue
        scalar = engine.compute_exact_aggregate_metrics(bars, funding, cdict)
        # Current vectorized repair path is exact cached batch evaluation; compare its per-row output to scalar.
        vector = aggregate_benchmark_candidates_cached(ctx, pd.DataFrame([cdict])).iloc[0].to_dict()
        for col in ["events", "event_count", "net_R", "gross_R", "fees_R", "funding_R", "active_symbols", "active_months", "PF", "win_rate", "max_dd_R"]:
            if col in {"PF", "win_rate", "max_dd_R"} and not row_metric_allowed(engine.row_semantics(), col):
                rows.append({
                    "candidate_id": cdict["candidate_id"],
                    "family_engine_id": engine.engine_id,
                    "metric": col,
                    "scalar_value": "not_applicable",
                    "vectorized_value": "not_applicable",
                    "abs_diff": 0.0,
                    "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE,
                    "status": "pass",
                })
                continue
            s = safe_float(scalar.get(col), 0.0)
            v = safe_float(vector.get(col), 0.0)
            rows.append({
                "candidate_id": cdict["candidate_id"],
                "family_engine_id": engine.engine_id,
                "metric": col,
                "scalar_value": s,
                "vectorized_value": v,
                "abs_diff": abs(s - v),
                "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE,
                "status": "pass" if abs(s - v) <= AGGREGATE_MATERIALIZED_TOLERANCE else "fail",
            })
    return pd.DataFrame(rows)


def stage_vectorized_benchmark_rerun(ctx: Context) -> None:
    priority_candidates = priority_tranche_candidate_registry(ctx, one_definition_per_engine=True)
    t0 = time.time()
    bench, projection, audit = run_repaired_engine_benchmark(ctx)
    elapsed = time.time() - t0
    write_csv(ctx.run_root / "benchmark/vectorized_repaired_engine_benchmark_summary.csv", bench)
    write_csv(ctx.run_root / "benchmark/vectorized_repaired_runtime_projection_by_engine.csv", projection)
    write_csv(ctx.run_root / "audit/vectorized_vs_materialized_audit.csv", audit)
    scalar_audit = vectorized_scalar_exactness_audit(ctx, priority_candidates)
    write_csv(ctx.run_root / "audit/vectorized_vs_scalar_aggregate_audit.csv", scalar_audit)
    failures = []
    if not audit.empty:
        failures.extend(audit[audit.get("status", pd.Series(dtype=str)).astype(str).ne("pass")].to_dict("records"))
    if not scalar_audit.empty:
        failures.extend(scalar_audit[scalar_audit.get("status", pd.Series(dtype=str)).astype(str).ne("pass")].to_dict("records"))
    write_text(ctx.run_root / "audit/vectorized_exactness_failure_report.md", f"# Vectorized Exactness Failure Report\n\nFailures: `{len(failures)}`\n")
    if failures:
        raise RuntimeError("vectorized exactness audit failed")

    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    universe = load_family_universe_map(ctx)
    prior = read_csv_safe(prior_benchmark_root(ctx) / "benchmark/repaired_runtime_projection_by_engine.csv")
    proj_rows = []
    full_rows = []
    fallback_rows = []
    for engine_id in REQUIRED_RANKABLE_ENGINES:
        p = projection[projection.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)] if not projection.empty else pd.DataFrame()
        prior_p = prior[prior.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)] if not prior.empty else pd.DataFrame()
        rate = safe_float(p["candidate_symbol_rows_per_second"].iloc[0], np.nan) if not p.empty else np.nan
        prior_rate = safe_float(prior_p["candidate_symbol_rows_per_second"].iloc[0], np.nan) if not prior_p.empty else np.nan
        speedup = rate / prior_rate if math.isfinite(rate) and math.isfinite(prior_rate) and prior_rate > 0 else np.nan
        dcount = int((defs.get("family_engine_id", pd.Series(dtype=str)).astype(str) == engine_id).sum()) if not defs.empty else 0
        syms = len(universe.get(engine_id, []))
        rows = dcount * syms
        hours = rows / max(0.001, rate) / 3600 if math.isfinite(rate) else float("inf")
        proj_rows.append({"family_engine_id": engine_id, "priority_tranche_definitions": dcount, "family_symbol_count": syms, "projected_candidate_symbol_rows": rows, "candidate_symbol_rows_per_second": rate, "prior_rows_per_second": prior_rate, "speedup": speedup, "projected_aggregate_hours": hours})
        full_defs = 500 if not ctx.args.smoke else max(2, dcount)
        full_rows_count = full_defs * syms
        full_rows.append({"family_engine_id": engine_id, "full_repaired_definitions": full_defs, "family_symbol_count": syms, "projected_candidate_symbol_rows": full_rows_count, "candidate_symbol_rows_per_second": rate, "projected_aggregate_hours": full_rows_count / max(0.001, rate) / 3600 if math.isfinite(rate) else float("inf")})
        fallback_rows.append({
            "family_engine_id": engine_id,
            "candidate_definitions_vectorized": dcount,
            "candidate_definitions_scalar_fallback": 0,
            "fallback_reason": "",
            "runtime_share_from_fallback": 0.0,
            "fallback_blocks_tranche_launch": False,
        })
    priority_projection = pd.DataFrame(proj_rows)
    full_projection = pd.DataFrame(full_rows)
    write_csv(ctx.run_root / "benchmark/priority_tranche_runtime_projection.csv", priority_projection)
    write_csv(ctx.run_root / "benchmark/vectorized_repaired_runtime_projection_by_engine.csv", full_projection)
    write_csv(ctx.run_root / "optimization/runtime_before_after_by_engine.csv", proj_rows)
    parallel_rows = []
    for r in proj_rows:
        h = safe_float(r.get("projected_aggregate_hours"), float("nan"))
        parallel_rows.append({
            "family_engine_id": r.get("family_engine_id"),
            "workers_1_runtime_hours": h,
            "workers_2_runtime_hours": h / 1.7 if math.isfinite(h) else np.nan,
            "workers_4_runtime_hours": h / 2.7 if math.isfinite(h) else np.nan,
            "parallelism_status": "projection_only_not_launch_authorization",
            "note": "Parallelism is secondary; repair must reduce repeated work before increasing workers.",
        })
    write_csv(ctx.run_root / "optimization/parallelism_projection_by_engine.csv", parallel_rows)
    write_text(ctx.run_root / "optimization/io_saturation_risk_report.md", "\n".join([
        "# IO Saturation Risk Report",
        "",
        "Parallel projections are discounted to account for disk and cache contention.",
        "This repair phase does not launch parallel workers. If runtime remains above gates, use v0 or engine-wave tranche planning rather than saturating disk with scalar loops.",
    ]) + "\n")
    write_csv(ctx.run_root / "optimization/scalar_fallback_report.csv", fallback_rows)
    priority_hours = float(pd.to_numeric(priority_projection.get("projected_aggregate_hours", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not priority_projection.empty else float("inf")
    full_hours = float(pd.to_numeric(full_projection.get("projected_aggregate_hours", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not full_projection.empty else float("inf")
    speedups = [safe_float(r.get("speedup"), np.nan) for r in proj_rows]
    median_speedup = float(pd.Series(speedups, dtype=float).dropna().median()) if pd.Series(speedups, dtype=float).dropna().size else np.nan
    write_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {
        "full_repaired_aggregate_hours": full_hours,
        "priority_tranche_aggregate_hours": priority_hours,
        "median_speedup_vs_prior_repair": median_speedup,
        "benchmark_mode": "true_batch_vectorized" if math.isfinite(median_speedup) and median_speedup >= 3.0 else "cached_scalar_benchmark",
        "speedup_threshold_for_true_batch_vectorized": 3.0,
        "benchmark_runtime_seconds": elapsed,
        "event_sampling_used": False,
        "aggregate_materialized_audit_pass": True,
        "vectorized_scalar_audit_pass": True,
    })
    kernel = read_csv_safe(ctx.run_root / "optimization/per_engine_vectorized_kernel_report.csv")
    if not kernel.empty:
        kernel = kernel.copy()
        speed_map = {str(r["family_engine_id"]): safe_float(r.get("speedup"), np.nan) for r in proj_rows}
        kernel["measured_speedup"] = kernel["family_engine_id"].astype(str).map(speed_map)
        kernel["measured_kernel_mode"] = np.where(pd.to_numeric(kernel["measured_speedup"], errors="coerce").fillna(0) >= 3.0, "true_batch_vectorized", "cached_scalar_benchmark")
        write_csv(ctx.run_root / "optimization/per_engine_vectorized_kernel_report.csv", kernel)
    write_text(ctx.run_root / "optimization/true_batch_vectorization_report.md", "\n".join([
        "# True Batch Vectorization Report",
        "",
        f"Median speedup: `{median_speedup}`",
        f"Benchmark mode: `{'true_batch_vectorized' if math.isfinite(median_speedup) and median_speedup >= 3.0 else 'cached_scalar_benchmark'}`",
        "If measured speedup is below `3x`, the phase does not claim true vectorization and falls back to staged tranche planning.",
    ]) + "\n")


def stage_materialization_controls_stress_rebenchmark(ctx: Context) -> None:
    cluster = read_csv_safe(ctx.run_root / "priority_tranche/materialization_cluster_selection.csv")
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    if cluster.empty or defs.empty:
        raise RuntimeError("clustered materialization selection missing")
    selected_defs = defs[defs["definition_id"].astype(str).isin(cluster["definition_id"].astype(str))].copy()
    universe = load_family_universe_map(ctx)
    candidates = generate_candidate_registry_for_family_universe(selected_defs, {k: v[:1] for k, v in universe.items()}, len(selected_defs))
    if ctx.args.smoke:
        candidates = candidates.groupby("family_engine_id", sort=False).head(1).reset_index(drop=True)
    paths = data_paths(ctx)
    out_dir = ctx.run_root / "benchmark/priority_tranche_materialization_samples"
    out_dir.mkdir(parents=True, exist_ok=True)
    bench_rows = []
    diag_rows = []
    control_rows_all = []
    control_summary_all = []
    self_audit = []
    examples = []
    for _, cand in candidates.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        start_size = file_size_bytes(ctx.run_root)
        load_t0 = time.time()
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        load_seconds = time.time() - load_t0
        mat_t0 = time.time()
        ledger = engine.regenerate_materialized_ledger(bars, funding, cdict) if not bars.empty else pd.DataFrame()
        mat_seconds = time.time() - mat_t0
        ledger_path = out_dir / f"{safe_filename(cdict['candidate_id'])}.parquet"
        ledger_size = 0
        if not ledger.empty:
            ledger.to_parquet(ledger_path, index=False, compression="zstd")
            ledger_size = ledger_path.stat().st_size
        ctrl_t0 = time.time()
        controls, ctrl_summary, ctrl_diag = build_real_null_controls(cdict, engine, bars, funding, ledger, nulls_per_event=ctx.args.nulls_per_event)
        ctrl_seconds = time.time() - ctrl_t0
        if not controls.empty:
            control_rows_all.append(controls)
            examples.extend(controls.head(3).to_dict("records"))
            self_audit.append({
                "candidate_id": cdict["candidate_id"],
                "family_engine_id": engine.engine_id,
                "control_rows": len(controls),
                "self_match_rows": int(parse_bool_series(controls.get("self_match", pd.Series(dtype=bool)), default=True).sum()),
                "status": "pass" if not bool(parse_bool_series(controls.get("self_match", pd.Series(dtype=bool)), default=True).any()) else "fail",
            })
        else:
            self_audit.append({"candidate_id": cdict["candidate_id"], "family_engine_id": engine.engine_id, "control_rows": 0, "self_match_rows": 0, "status": "no_controls"})
        if not ctrl_summary.empty:
            control_summary_all.append(ctrl_summary)
        stress_t0 = time.time()
        stress = engine.run_family_specific_stress(ledger) if not ledger.empty else pd.DataFrame()
        stress_seconds = time.time() - stress_t0
        zero_reason = ctrl_diag.get("zero_control_reason", "")
        diag_rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "row_semantics": engine.row_semantics(),
            "controls_row_count": len(controls),
            "zero_control_reason": zero_reason,
            "zero_control_status": "ok_nonzero" if len(controls) else "blocking_zero_controls",
        })
        bench_rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "load_runtime_seconds": load_seconds,
            "materialized_ledger_regeneration_runtime_seconds": mat_seconds,
            "materialized_event_rows": len(ledger),
            "materialized_ledger_size_bytes": ledger_size,
            "controls_runtime_seconds": ctrl_seconds,
            "controls_row_count": len(controls),
            "control_summary_rows": len(ctrl_summary),
            "stress_context_stability_runtime_seconds": stress_seconds,
            "stress_rows": len(stress),
            "archive_size_proxy_bytes": max(0, file_size_bytes(ctx.run_root) - start_size),
            "status": "pass" if not ledger.empty and (len(controls) or zero_reason) else "fail",
        })
    bench = pd.DataFrame(bench_rows)
    diagnostics = pd.DataFrame(diag_rows)
    write_csv(ctx.run_root / "benchmark/priority_tranche_materialization_controls_stress_benchmark.csv", bench)
    write_csv(ctx.run_root / "benchmark/priority_tranche_controls_diagnostics.csv", diagnostics)
    write_csv(ctx.run_root / "controls/control_zero_row_diagnostics.csv", diagnostics)
    write_csv(ctx.run_root / "controls/control_row_semantics_match_examples.csv", examples)
    write_csv(ctx.run_root / "controls/control_self_match_leakage_audit.csv", self_audit)
    write_text(ctx.run_root / "controls/control_null_design_by_row_semantics.yaml", "\n".join([
        "position_interval: same-symbol scheduled null intervals at matching cadence, excluding signal intervals",
        "trade_episode: same-symbol non-trigger transition windows with matched hold horizon",
        "lifecycle_event: same-symbol lifecycle windows without candidate entry trigger",
        "decision: signal-frequency diagnostics only; trade metrics require interval/episode conversion",
    ]) + "\n")
    write_text(ctx.run_root / "controls/control_matching_repair_report.md", "\n".join([
        "# Control Matching Repair Report",
        "",
        f"Benchmark candidates: `{len(bench)}`",
        f"Control rows generated: `{int(pd.to_numeric(bench.get('controls_row_count', pd.Series(dtype=float)), errors='coerce').fillna(0).sum()) if not bench.empty else 0}`",
        "Controls are generated from real same-symbol null windows in the Kraken bar/funding panel; another candidate's event ledger is not used as a pseudo-control.",
    ]) + "\n")
    controls_df = pd.concat(control_rows_all, ignore_index=True) if control_rows_all else pd.DataFrame()
    summary_df = pd.concat(control_summary_all, ignore_index=True) if control_summary_all else pd.DataFrame()
    if not controls_df.empty:
        out = ctx.run_root / "controls/control_ledger/control_ledger.parquet"
        out.parent.mkdir(parents=True, exist_ok=True)
        controls_df.to_parquet(out, index=False, compression="zstd")
    write_csv(ctx.run_root / "controls/control_summary.csv", summary_df)
    agg_hours = safe_float(read_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {}).get("priority_tranche_aggregate_hours"), float("inf"))
    mat_seconds = float(pd.to_numeric(bench.get("materialized_ledger_regeneration_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not bench.empty else 0.0
    ctrl_seconds = float(pd.to_numeric(bench.get("controls_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not bench.empty else 0.0
    stress_seconds = float(pd.to_numeric(bench.get("stress_context_stability_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not bench.empty else 0.0
    sample_count = max(1, len(bench))
    selected_budget = min(250, int(ctx.args.materialization_budget))
    priority_total = agg_hours + ((mat_seconds + ctrl_seconds + stress_seconds) / sample_count * selected_budget / 3600.0)
    full_agg = safe_float(read_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {}).get("full_repaired_aggregate_hours"), float("inf"))
    write_json(ctx.run_root / "benchmark/priority_tranche_total_runtime_projection.json", {
        "priority_tranche_aggregate_hours": agg_hours,
        "projected_materialization_controls_stress_hours": ((mat_seconds + ctrl_seconds + stress_seconds) / sample_count * selected_budget / 3600.0),
        "projected_archive_hours": 0.25,
        "projected_storage_gb": float(pd.to_numeric(bench.get("materialized_ledger_size_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).mean() * selected_budget / (1024 ** 3)) if not bench.empty else 0.0,
        "projected_total_hours": priority_total + 0.25,
        "runtime_gate": "go_under_72h" if priority_total + 0.25 <= 72 else ("conditional_operator_approval_72_to_168h" if priority_total + 0.25 <= 168 else "no_go_over_168h"),
    })
    write_json(ctx.run_root / "benchmark/full_repaired_total_runtime_projection.json", {
        "full_repaired_aggregate_hours": full_agg,
        "projected_total_hours": full_agg + 0.25,
        "runtime_gate": "go_under_168h" if full_agg + 0.25 <= 168 else "no_go_over_168h",
    })


def stratified_benchmark_candidates(ctx: Context) -> pd.DataFrame:
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    design = read_csv_safe(ctx.run_root / "benchmark/row_semantics_stratified_benchmark_design.csv")
    if defs.empty or design.empty:
        return pd.DataFrame()
    rows = []
    for _, d in defs.groupby("family_engine_id", sort=False).head(1).iterrows():
        engine_id = str(d["family_engine_id"])
        design_available = parse_bool_series(design["available"], default=False)
        syms = design[(design["family_engine_id"].astype(str) == engine_id) & design_available]["symbol"].astype(str).dropna().drop_duplicates().head(3).tolist()
        if not syms:
            continue
        rows.append(generate_candidate_registry_for_family_universe(pd.DataFrame([d]), {engine_id: syms}, 1))
    return pd.concat(rows, ignore_index=True) if rows else pd.DataFrame()


def stage_symbol_stratified_materialization_controls_stress_benchmark(ctx: Context) -> None:
    candidates = stratified_benchmark_candidates(ctx)
    if candidates.empty:
        raise RuntimeError("symbol-stratified benchmark candidate design produced no candidates")
    paths = data_paths(ctx)
    out_dir = ctx.run_root / "benchmark/symbol_stratified_materialization_samples"
    out_dir.mkdir(parents=True, exist_ok=True)
    bench_rows: list[dict[str, Any]] = []
    diag_rows: list[dict[str, Any]] = []
    cap_rows: list[dict[str, Any]] = []
    control_rows_all: list[pd.DataFrame] = []
    summary_all: list[pd.DataFrame] = []
    examples: list[dict[str, Any]] = []
    self_audit: list[dict[str, Any]] = []
    for _, cand in candidates.iterrows():
        cdict = cand.to_dict()
        engine = engine_for_candidate(cdict)
        bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
        funding = load_funding(paths, str(cdict["symbol"]), ctx.end)
        load_status = "bars_loaded" if not bars.empty else "missing_bars"
        t0 = time.time()
        ledger = engine.regenerate_materialized_ledger(bars, funding, cdict) if not bars.empty else pd.DataFrame()
        mat_seconds = time.time() - t0
        ledger_path = out_dir / f"{safe_filename(cdict['candidate_id'] + '__' + str(cdict['symbol']))}.parquet"
        ledger_size = 0
        if not ledger.empty:
            ledger.to_parquet(ledger_path, index=False, compression="zstd")
            ledger_size = ledger_path.stat().st_size
        candidate_decisions = set(pd.to_datetime(ledger["decision_ts"], utc=True, errors="coerce").dropna()) if not ledger.empty and "decision_ts" in ledger else set()
        all_idxs, _ = null_control_indices(engine, bars, cdict, candidate_decisions, 1_000_000)
        ctrl_t0 = time.time()
        controls, summary, ctrl_diag = build_real_null_controls(cdict, engine, bars, funding, ledger, nulls_per_event=ctx.args.nulls_per_event)
        ctrl_seconds = time.time() - ctrl_t0
        stress_t0 = time.time()
        stress = engine.run_family_specific_stress(ledger) if not ledger.empty else pd.DataFrame()
        stress_seconds = time.time() - stress_t0
        if not controls.empty:
            control_rows_all.append(controls)
            examples.extend(controls.head(2).to_dict("records"))
        if not summary.empty:
            summary_all.append(summary)
        self_rows = int(parse_bool_series(controls.get("self_match", pd.Series(dtype=bool)), default=True).sum()) if not controls.empty else 0
        self_audit.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "control_rows": len(controls),
            "self_match_rows": self_rows,
            "status": "pass" if self_rows == 0 else "fail",
        })
        zero_reason = ctrl_diag.get("zero_control_reason", "")
        diag_rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "row_semantics": engine.row_semantics(),
            "controls_row_count": len(controls),
            "zero_control_reason": zero_reason,
            "zero_control_status": "ok_nonzero" if len(controls) else ("explicit_no_candidate_events_not_control_claim" if zero_reason == "no_candidate_events" else "blocking_zero_controls"),
        })
        cap_applied = bool(len(all_idxs) > len(controls))
        cap_rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "total_matched_controls_available": int(len(all_idxs)),
            "controls_retained": int(len(controls)),
            "cap_applied": cap_applied,
            "cap_method": "deterministic_time_order_retention" if cap_applied else "all_controls",
            "random_seed": ctx.args.seed,
            "cap_scope": "benchmark_diagnostic_only" if cap_applied else "all_controls_retained",
            "final_evidence_eligible": not cap_applied,
        })
        bench_rows.append({
            "candidate_id": cdict["candidate_id"],
            "family_engine_id": engine.engine_id,
            "symbol": cdict["symbol"],
            "row_semantics": engine.row_semantics(),
            "materialized_ledger_regeneration_runtime_seconds": mat_seconds,
            "materialized_event_rows": len(ledger),
            "materialized_ledger_size_bytes": ledger_size,
            "controls_runtime_seconds": ctrl_seconds,
            "controls_row_count": len(controls),
            "stress_context_stability_runtime_seconds": stress_seconds,
            "stress_rows": len(stress),
            "load_status": load_status,
            "status": "pass" if not ledger.empty and len(controls) else "fail",
        })
    bench = pd.DataFrame(bench_rows)
    write_csv(ctx.run_root / "benchmark/symbol_stratified_materialization_controls_stress_benchmark.csv", bench)
    write_csv(ctx.run_root / "benchmark/priority_tranche_materialization_controls_stress_benchmark.csv", bench)
    write_csv(ctx.run_root / "benchmark/priority_tranche_controls_diagnostics.csv", diag_rows)
    write_csv(ctx.run_root / "controls/control_zero_row_diagnostics.csv", diag_rows)
    write_csv(ctx.run_root / "controls/control_cap_diagnostics.csv", cap_rows)
    write_csv(ctx.run_root / "controls/control_row_semantics_match_examples.csv", examples)
    write_csv(ctx.run_root / "controls/control_self_match_leakage_audit.csv", self_audit)
    summary_df = pd.concat(summary_all, ignore_index=True) if summary_all else pd.DataFrame()
    controls_df = pd.concat(control_rows_all, ignore_index=True) if control_rows_all else pd.DataFrame()
    write_csv(ctx.run_root / "controls/control_summary.csv", summary_df)
    if not controls_df.empty:
        out = ctx.run_root / "controls/control_ledger/control_ledger.parquet"
        out.parent.mkdir(parents=True, exist_ok=True)
        controls_df.to_parquet(out, index=False, compression="zstd")
    represented_symbols = int(bench["symbol"].nunique()) if not bench.empty else 0
    represented_semantics = sorted(bench["row_semantics"].dropna().astype(str).unique()) if not bench.empty else []
    pass_status = represented_symbols > 1 and {"position_interval", "trade_episode", "lifecycle_event"}.issubset(set(represented_semantics)) and bool((bench["status"].astype(str) == "pass").any())
    write_text(ctx.run_root / "benchmark/symbol_representativeness_report.md", "\n".join([
        "# Symbol Representativeness Report",
        "",
        f"Distinct benchmark symbols materialized: `{represented_symbols}`",
        f"Row semantics materialized: `{','.join(represented_semantics)}`",
        f"Symbol-stratified materialization/control/stress benchmark pass: `{pass_status}`",
        "A one-symbol benchmark cannot satisfy the materialization/control/stress gate.",
    ]) + "\n")


def update_v2_runtime_plans(ctx: Context) -> None:
    proj = read_csv_safe(ctx.run_root / "benchmark/priority_tranche_runtime_projection.csv")
    mat = read_csv_safe(ctx.run_root / "benchmark/symbol_stratified_materialization_controls_stress_benchmark.csv")
    v0 = read_csv_safe(ctx.run_root / "priority_tranche/v0_tranche_plan.csv")
    vector = read_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {})
    agg_hours = safe_float(vector.get("priority_tranche_aggregate_hours"), float("inf"))
    full_agg_hours = safe_float(vector.get("full_repaired_aggregate_hours"), float("inf"))
    per_candidate_hours = 0.0
    if not mat.empty:
        per_candidate_hours = float((pd.to_numeric(mat.get("materialized_ledger_regeneration_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)
                                   + pd.to_numeric(mat.get("controls_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)
                                   + pd.to_numeric(mat.get("stress_context_stability_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)).mean()) / 3600.0
    materialization_budget = 250 if not ctx.args.smoke else min(20, max(1, len(mat)))
    priority_total = agg_hours + per_candidate_hours * materialization_budget + 0.25
    write_json(ctx.run_root / "benchmark/priority_tranche_total_runtime_projection.json", {
        "priority_tranche_aggregate_hours": agg_hours,
        "projected_materialization_controls_stress_hours": per_candidate_hours * materialization_budget,
        "projected_archive_hours": 0.25,
        "projected_storage_gb": float(pd.to_numeric(mat.get("materialized_ledger_size_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).mean() * materialization_budget / (1024 ** 3)) if not mat.empty else 0.0,
        "projected_total_hours": priority_total,
        "runtime_gate": "go_under_72h" if priority_total <= 72 else ("conditional_operator_approval_72_to_168h" if priority_total <= 168 else "no_go_over_168h"),
    })
    write_json(ctx.run_root / "benchmark/full_repaired_total_runtime_projection.json", {
        "full_repaired_aggregate_hours": full_agg_hours,
        "projected_total_hours": full_agg_hours + 0.25,
        "runtime_gate": "go_under_168h" if full_agg_hours + 0.25 <= 168 else "no_go_over_168h",
    })
    engine_rows = []
    if not v0.empty:
        updated = []
        for _, r in v0.iterrows():
            engine_id = str(r["family_engine_id"])
            agg_hours = estimate_engine_hours_from_projection(proj, engine_id, int(safe_float(r.get("planned_definitions"), 0)))
            m = mat[mat.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)] if not mat.empty else pd.DataFrame()
            per_candidate = 0.0
            if not m.empty:
                per_candidate = float((pd.to_numeric(m.get("materialized_ledger_regeneration_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)
                                       + pd.to_numeric(m.get("controls_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)
                                       + pd.to_numeric(m.get("stress_context_stability_runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0)).mean()) / 3600.0
            mat_budget = int(safe_float(r.get("materialization_budget"), 0))
            total = agg_hours + per_candidate * mat_budget + 0.1
            rec = r.to_dict()
            rec.update({"runtime_hours_estimate": total, "aggregate_hours_estimate": agg_hours, "benchmark_updated": True, "status": "fits_72h" if total <= 72 else "over_72h_pending_compute"})
            updated.append(rec)
            engine_rows.append({
                "engine_wave_id": f"{engine_id}__wave_001",
                "family_engine_id": engine_id,
                "planned_definitions": int(safe_float(r.get("planned_definitions"), 0)),
                "runtime_hours_estimate": total,
                "launch_status": "not_launched_repair_benchmark_only",
                "fits_72h": bool(total <= 72),
            })
        write_csv(ctx.run_root / "priority_tranche/v0_tranche_plan.csv", updated)
        write_csv(ctx.run_root / "priority_tranche/engine_wave_tranche_plan.csv", engine_rows)


def stage_benchmark_rerun_v2(ctx: Context) -> None:
    stage_vectorized_benchmark_rerun(ctx)
    stage_symbol_stratified_materialization_controls_stress_benchmark(ctx)
    update_v2_runtime_plans(ctx)


def stage_priority_tranche_go_no_go(ctx: Context) -> None:
    if getattr(getattr(ctx, "args", None), "phase_profile", "") == V2_PHASE_PROFILE:
        stage_priority_tranche_go_no_go_v2(ctx)
        return
    scoring = protected_scoring_artifact_scan(ctx)
    write_json(ctx.run_root / "seal/protected_scoring_artifact_scan.json", scoring)
    priority_proj = read_json(ctx.run_root / "benchmark/priority_tranche_total_runtime_projection.json", {})
    full_proj = read_json(ctx.run_root / "benchmark/full_repaired_total_runtime_projection.json", {})
    vector = read_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {})
    diag = read_csv_safe(ctx.run_root / "controls/control_zero_row_diagnostics.csv")
    bench = read_csv_safe(ctx.run_root / "benchmark/priority_tranche_materialization_controls_stress_benchmark.csv")
    lanes = read_csv_safe(ctx.run_root / "priority/hypothesis_priority_lane.csv")
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    blockers = []
    if scoring.get("status") != "pass":
        blockers.append("protected_scoring_event_scan_failed")
    if not bool(vector.get("aggregate_materialized_audit_pass")) or not bool(vector.get("vectorized_scalar_audit_pass")):
        blockers.append("vectorized_exactness_audit_failed")
    if diag.empty or bool((pd.to_numeric(diag.get("controls_row_count", pd.Series(dtype=float)), errors="coerce").fillna(0) <= 0).any()):
        blockers.append("zero_controls_for_benchmark_candidate")
    if bench.empty:
        blockers.append("materialization_controls_stress_benchmark_missing")
    if lanes.empty or bool(lanes.astype(str).apply(lambda col: col.str.contains("waiting_for_vendor_data", case=False, regex=False)).any().any()):
        blockers.append("priority_lane_classification_invalid")
    runtime_gate = str(priority_proj.get("runtime_gate", "missing"))
    if runtime_gate == "no_go_over_168h" or runtime_gate == "missing":
        blockers.append("priority_tranche_runtime_not_acceptable")
    full_runtime_gate = str(full_proj.get("runtime_gate", "missing"))
    if blockers:
        if "zero_controls_for_benchmark_candidate" in blockers:
            decision = "repair_control_matching_next"
        elif "priority_lane_classification_invalid" in blockers:
            decision = "repair_priority_lane_classification_next"
        elif "priority_tranche_runtime_not_acceptable" in blockers:
            decision = "repair_engine_vectorization_next"
        else:
            decision = "blocked_by_protocol_issue"
    else:
        decision = "launch_priority_tranche_next"
    if full_runtime_gate == "go_under_168h" and decision == "launch_priority_tranche_next":
        full_note = "Full broad sweep is still not launched by this repair phase; separate operator approval is required."
    else:
        full_note = "Full broad sweep is not recommended/launched from this phase."
    result = {
        "gate_status": "go" if not blockers else "no_go",
        "gate_blockers": blockers,
        "next_operator_decision": decision,
        "priority_tranche_runtime_gate": runtime_gate,
        "full_repaired_runtime_gate": full_runtime_gate,
        "event_sampling_used": False,
        "protected_scoring_event_scan_status": scoring.get("status"),
        "full_sweep_launch_authorized": False,
        "priority_tranche_launched": False,
    }
    write_json(ctx.run_root / "gate/priority_tranche_go_no_go.json", result)
    write_text(ctx.run_root / "gate/priority_tranche_go_no_go_report.md", "\n".join([
        "# Priority Tranche Go/No-Go",
        "",
        f"Gate status: `{result['gate_status']}`",
        f"Next operator decision: `{decision}`",
        f"Priority runtime gate: `{runtime_gate}`",
        f"Full runtime gate: `{full_runtime_gate}`",
        f"Blockers: `{blockers}`",
        full_note,
        "This repair phase does not launch the priority tranche or full aggregate sweep.",
    ]) + "\n")
    evidence_rows = []
    for _, r in defs.iterrows():
        evidence_rows.append({
            "definition_id": r.get("definition_id"),
            "hypothesis_id": r.get("hypothesis_id"),
            "family_engine_id": r.get("family_engine_id"),
            "evidence_level": "level_1_generator_support",
            "candidate_status": "pending_compute_priority_tranche_not_launched",
            "aggregate_only_survivor_label": False,
        })
    write_csv(ctx.run_root / "analysis_ready/evidence_level_assignment.csv", evidence_rows)
    write_csv(ctx.run_root / "candidate_library/aggregate_first_candidate_status_update.csv", evidence_rows)


def stage_priority_tranche_go_no_go_v2(ctx: Context) -> None:
    scoring = protected_scoring_artifact_scan(ctx)
    write_json(ctx.run_root / "seal/protected_scoring_artifact_scan.json", scoring)
    vector = read_json(ctx.run_root / "benchmark/vectorized_full_budget_projection.json", {})
    priority_proj = read_json(ctx.run_root / "benchmark/priority_tranche_total_runtime_projection.json", {})
    full_proj = read_json(ctx.run_root / "benchmark/full_repaired_total_runtime_projection.json", {})
    v0 = read_csv_safe(ctx.run_root / "priority_tranche/v0_tranche_plan.csv")
    waves = read_csv_safe(ctx.run_root / "priority_tranche/engine_wave_tranche_plan.csv")
    diag = read_csv_safe(ctx.run_root / "controls/control_zero_row_diagnostics.csv")
    self_audit = read_csv_safe(ctx.run_root / "controls/control_self_match_leakage_audit.csv")
    cap = read_csv_safe(ctx.run_root / "controls/control_cap_diagnostics.csv")
    lanes = read_csv_safe(ctx.run_root / "priority/hypothesis_priority_lane.csv")
    bench = read_csv_safe(ctx.run_root / "benchmark/symbol_stratified_materialization_controls_stress_benchmark.csv")
    exact_fail = read_text_safe(ctx.run_root / "audit/vectorized_exactness_failure_report.md")
    rep_text = read_text_safe(ctx.run_root / "benchmark/symbol_representativeness_report.md")
    blockers: list[str] = []
    if scoring.get("status") != "pass":
        blockers.append("protected_scoring_event_scan_failed")
    if "Failures: `0`" not in exact_fail:
        blockers.append("vectorized_exactness_audit_failed")
    if bench.empty or bench["symbol"].astype(str).nunique() <= 1 or "benchmark pass: `True`" not in rep_text:
        blockers.append("symbol_stratified_benchmark_failed")
    zero_status = diag.get("zero_control_status", pd.Series(dtype=str)).astype(str) if not diag.empty else pd.Series(dtype=str)
    if diag.empty or bool(zero_status.eq("blocking_zero_controls").any()):
        blockers.append("zero_controls_for_benchmark_candidate")
    if not self_audit.empty and bool((pd.to_numeric(self_audit.get("self_match_rows", pd.Series(dtype=float)), errors="coerce").fillna(0) > 0).any()):
        blockers.append("control_self_match_leakage")
    if lanes.empty or bool(lanes.astype(str).apply(lambda col: col.str.contains("waiting_for_vendor_data", case=False, regex=False)).any().any()):
        blockers.append("priority_lane_classification_invalid")
    benchmark_mode = str(vector.get("benchmark_mode", "cached_scalar_benchmark"))
    v0_total = float(pd.to_numeric(v0.get("runtime_hours_estimate", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not v0.empty else float("inf")
    wave_fit = bool((pd.to_numeric(waves.get("runtime_hours_estimate", pd.Series(dtype=float)), errors="coerce").fillna(float("inf")) <= 72).any()) if not waves.empty else False
    if blockers:
        if any(b in blockers for b in ["zero_controls_for_benchmark_candidate", "control_self_match_leakage"]):
            decision = "repair_control_matching_next"
        elif "priority_lane_classification_invalid" in blockers:
            decision = "repair_priority_lane_classification_next"
        else:
            decision = "blocked_by_protocol_issue"
        gate_status = "no_go"
    elif v0_total <= 72:
        decision = "launch_priority_tranche_v0_next"
        gate_status = "go_v0_recommended"
    elif wave_fit:
        decision = "launch_engine_wave_tranche_next"
        gate_status = "go_engine_wave_recommended"
    else:
        decision = "repair_engine_vectorization_next"
        gate_status = "no_go_runtime"
    if decision not in V2_ALLOWED_NEXT_DECISIONS:
        decision = "blocked_by_protocol_issue"
    result = {
        "gate_status": gate_status,
        "gate_blockers": blockers,
        "next_operator_decision": decision,
        "benchmark_mode": benchmark_mode,
        "vectorization_speedup_median": safe_float(vector.get("median_speedup_vs_prior_repair"), float("nan")),
        "priority_1700_runtime_hours": safe_float(priority_proj.get("projected_total_hours"), float("nan")),
        "v0_tranche_runtime_hours": v0_total,
        "engine_wave_any_fits_72h": wave_fit,
        "event_sampling_used": False,
        "protected_scoring_event_scan_status": scoring.get("status"),
        "priority_tranche_launched": False,
        "full_sweep_launched": False,
        "control_caps_benchmark_only": bool(not cap.empty and (cap.get("cap_scope", pd.Series(dtype=str)).astype(str).str.contains("benchmark", case=False, na=False).any())),
    }
    write_json(ctx.run_root / "gate/priority_tranche_go_no_go.json", result)
    write_text(ctx.run_root / "gate/priority_tranche_go_no_go_report.md", "\n".join([
        "# Priority Tranche Go/No-Go v2",
        "",
        f"Gate status: `{gate_status}`",
        f"Next operator decision: `{decision}`",
        f"Benchmark mode: `{benchmark_mode}`",
        f"Priority 1,700 runtime hours: `{result['priority_1700_runtime_hours']}`",
        f"v0 tranche runtime hours: `{v0_total}`",
        f"Engine wave any fits 72h: `{wave_fit}`",
        f"Blockers: `{blockers}`",
        "This repair phase does not launch v0, engine-wave tranches, the 1,700-definition tranche, or the full sweep.",
    ]) + "\n")
    defs = read_csv_safe(ctx.run_root / "priority_tranche/priority_tranche_definition_manifest.csv")
    status_rows = []
    allowed_statuses = {
        "pending_compute", "priority_tier1_full_train_candidate", "priority_tier1_with_caps",
        "forward_capture_sidecar", "event_ledger_first_sidecar", "candidate_library_only",
        "not_kraken_viable_current_translation",
    }
    for _, r in defs.iterrows():
        status_rows.append({
            "definition_id": r.get("definition_id"),
            "hypothesis_id": r.get("hypothesis_id"),
            "family_engine_id": r.get("family_engine_id"),
            "candidate_status": "pending_compute",
            "evidence_level": "level_1_generator_support",
            "aggregate_only_survivor_label": False,
        })
    lane_source = read_csv_safe(ctx.run_root / "compiler/hypothesis_to_engine_translation_audit.csv")
    for _, r in lane_source.iterrows():
        lane = str(r.get("priority_lane", "candidate_library_only"))
        status = lane if lane in allowed_statuses else ("priority_tier1_with_caps" if lane == "priority_tier1_with_caps" else "priority_tier1_full_train_candidate" if lane == "priority_tier1_full_train_candidate" else "candidate_library_only")
        if status not in allowed_statuses:
            status = "candidate_library_only"
        status_rows.append({
            "definition_id": "",
            "hypothesis_id": r.get("hypothesis_id"),
            "family_engine_id": r.get("family_engine_id"),
            "candidate_status": status,
            "evidence_level": "level_1_generator_support",
            "aggregate_only_survivor_label": False,
        })
    library_df = pd.DataFrame(status_rows)
    if bool(library_df.astype(str).apply(lambda col: col.str.contains("waiting_for_vendor_data", case=False, regex=False)).any().any()):
        raise RuntimeError("forbidden waiting_for_vendor_data in candidate library update")
    write_csv(ctx.run_root / "candidate_library/vectorized_priority_repair_candidate_status_update.csv", library_df)
    write_csv(ctx.run_root / "analysis_ready/evidence_level_assignment.csv", library_df[["definition_id", "hypothesis_id", "family_engine_id", "evidence_level", "candidate_status", "aggregate_only_survivor_label"]] if not library_df.empty else library_df)


def engine_wave_source_root(ctx: Context) -> Path:
    return prior_benchmark_root(ctx)


def preservation_state_for_exclusion(reason: str) -> str:
    r = reason.lower()
    if "capture" in r or "microstructure" in r or "liquidation" in r or "orb" in r or "listing" in r:
        return "forward_capture_sidecar"
    if "event-ledger" in r or "event_ledger" in r or "c2" in r:
        return "event_ledger_first_sidecar"
    if "repair" in r or "not_compilable" in r or "conflict" in r:
        return "current_translation_needs_repair"
    if "compute" in r:
        return "pending_compute"
    return "candidate_library_only"


def load_engine_wave_source_manifests(ctx: Context) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    root = engine_wave_source_root(ctx)
    defs = read_csv_safe(root / "priority_tranche/priority_tranche_definition_manifest.csv")
    translations = read_csv_safe(root / "compiler/hypothesis_to_engine_translation_audit.csv")
    v0 = read_csv_safe(root / "priority_tranche/v0_tranche_plan.csv")
    waves = read_csv_safe(root / "priority_tranche/engine_wave_tranche_plan.csv")
    if defs.empty:
        raise RuntimeError(f"missing source priority tranche definition manifest: {root}")
    return defs, translations, v0, waves


def parse_interval_to_5m_bars(value: object, *, default_bars: int) -> int:
    text = str(value or "").strip().lower()
    if not text or text in {"nan", "none"}:
        return int(default_bars)
    aliases = {"daily": 24 * 60, "1d": 24 * 60, "8h": 8 * 60, "4h": 4 * 60}
    if text in aliases:
        return max(1, aliases[text] // 5)
    m = re.fullmatch(r"(\d+(?:\.\d+)?)(m|h|d)", text)
    if m:
        qty = float(m.group(1))
        unit = m.group(2)
        minutes = qty if unit == "m" else qty * 60 if unit == "h" else qty * 24 * 60
        return max(1, int(round(minutes / 5)))
    return int(default_bars)


def load_candidate_definition_manifest(ctx: Context, path_arg: str | Path) -> pd.DataFrame:
    path = resolve_path(path_arg)
    if not path.exists():
        alt = ctx.run_root / str(path_arg)
        path = alt if alt.exists() else path
    raw = read_csv_safe(path)
    if raw.empty:
        raise RuntimeError(f"candidate definition manifest is missing or empty: {path}")
    rows: list[dict[str, Any]] = []
    for i, (_, row) in enumerate(raw.iterrows(), start=1):
        rec = row.to_dict()
        rec.setdefault("family_engine_id", "scheduled_tsmom_engine")
        rec.setdefault("archetype", "tsmom")
        rec.setdefault("family", "Redesigned TSMOM")
        rec.setdefault("hypothesis_id", "H02")
        rec.setdefault("contract_id", f"redesigned_tsmom_{i:03d}")
        rec.setdefault("contract_source", "redesigned_candidate_manifest")
        rec.setdefault("allowed_lane", "compiled_tier1_redesign")
        rec.setdefault("priority_lane", "priority_tier1_full_train_candidate")
        rec.setdefault("current_data_tier", "Tier 1")
        rec.setdefault("required_data_tier", "Tier 1")
        rec.setdefault("current_testability", "screen_now")
        rec.setdefault("forward_capture_upgrade_path", "not_required_for_tier1")
        rec.setdefault("translation_type", "direct strategy translation")
        rec.setdefault("translation_rankable", True)
        rec.setdefault("entry_template", "tsmom_close_confirmed")
        rec.setdefault("exit_template", "fixed_hold")
        rec.setdefault("stop_template", "scheduled_rebalance")
        rec.setdefault("regime_activation", "intended_regime" if str(rec.get("parent_regime_gate", "")).strip() else "all_context_diagnostic")
        rec.setdefault("regime_variant", rec.get("regime_activation", "all_context_diagnostic"))
        rec.setdefault("side", "long")
        rec.setdefault("threshold", 0.0)
        rec.setdefault("stop_bps", 150.0)
        rec.setdefault("definition_kind", rec.get("variant_name", "redesigned"))
        if not str(rec.get("definition_id", "") or "").strip():
            rec["definition_id"] = str(rec.get("candidate_definition_id", "") or f"redesigned_tsmom__{i:03d}")
        if not str(rec.get("lookback_bars", "") or "").strip() or str(rec.get("lookback_bars")).lower() in {"nan", "none"}:
            if str(rec.get("lookback_4h_bars", "") or "").strip() and str(rec.get("lookback_4h_bars")).lower() not in {"nan", "none"}:
                rec["lookback_bars"] = int(round(safe_float(rec.get("lookback_4h_bars"), 0) * 48))
            else:
                rec["lookback_bars"] = int(round(safe_float(rec.get("lookback_days"), 40) * 24 * 12))
        if not str(rec.get("hold_bars", "") or "").strip() or str(rec.get("hold_bars")).lower() in {"nan", "none"}:
            rec["hold_bars"] = parse_interval_to_5m_bars(rec.get("hold_interval") or rec.get("rebalance_interval"), default_bars=288)
        rec["prelaunch_eligible"] = True
        rec["prelaunch_exclusion_reason"] = ""
        rec["preservation_state"] = "pending_compute"
        rec["evidence_level"] = "level_1_generator_support"
        rec["manifest_source_path"] = str(path)
        rec["kraken_data_root"] = str(resolve_path(getattr(ctx.args, "kraken_data_root", str(DEFAULT_KRAKEN_DATA_ROOT))))
        rec["uses_external_candidate_definition_manifest"] = True
        engine = ENGINES.get(str(rec.get("family_engine_id")), ENGINES["scheduled_tsmom_engine"])
        rows.append(identity_enriched_record(rec, engine))
    out = pd.DataFrame(rows)
    if out["parameter_vector_hash"].astype(str).str.strip().isin({"", "nan", "None"}).any():
        raise RuntimeError("candidate definition manifest contains blank parameter_vector_hash after enrichment")
    dup = out[out.duplicated("parameter_vector_hash", keep=False)]
    if not dup.empty:
        raise RuntimeError("candidate definition manifest contains duplicate parameter_vector_hash rows")
    return out


def stage_prelaunch_contract_eligibility_gate(ctx: Context) -> None:
    if str(getattr(ctx.args, "candidate_definition_manifest", "") or "").strip():
        eligible = load_candidate_definition_manifest(ctx, ctx.args.candidate_definition_manifest)
        if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
            write_pre_run_parameter_lineage_gate(
                ctx,
                eligible,
                context="external_candidate_definition_manifest_prelaunch",
                fail_closed=True,
            )
        write_csv(ctx.run_root / "prelaunch/translation_key_uniqueness_audit.csv", [{
            "status": "pass",
            "detail": "external_candidate_definition_manifest_used",
            "candidate_definition_manifest": ctx.args.candidate_definition_manifest,
        }])
        write_csv(ctx.run_root / "prelaunch/post_merge_definition_identity_audit.csv", [{
            "context": "external_candidate_definition_manifest",
            "status": "pass",
            "definition_rows": int(len(eligible)),
            "duplicate_parameter_vector_hash_rows": 0,
        }])
        write_csv(ctx.run_root / "prelaunch/prelaunch_contract_eligibility_audit.csv", eligible)
        write_csv(ctx.run_root / "prelaunch/excluded_nonrankable_contracts.csv", [])
        write_csv(ctx.run_root / "prelaunch/eligible_definition_manifest.csv", eligible)
        write_text(ctx.run_root / "prelaunch/eligibility_gate_report.md", "\n".join([
            "# Prelaunch Contract Eligibility Gate",
            "",
            f"External candidate definition manifest: `{ctx.args.candidate_definition_manifest}`",
            f"Eligible definitions: `{len(eligible)}`",
            "Old v0 TSMOM definitions were not used by this prelaunch path.",
        ]) + "\n")
        return
    defs, translations, _, _ = load_engine_wave_source_manifests(ctx)
    trans_cols = [
        "hypothesis_id", "family_engine_id", "priority_lane", "current_data_tier", "required_data_tier",
        "current_testability", "forward_capture_upgrade_path", "translation_type", "translation_rankable",
        "source_family", "translated_engine", "translation_reason",
    ]
    if not translations.empty:
        collapsed_translations, _ = collapse_translation_manifest(
            translations[[c for c in trans_cols if c in translations.columns]].copy(),
            ctx.run_root / "prelaunch/translation_key_uniqueness_audit.csv",
        )
        merged = defs.merge(
            collapsed_translations[[c for c in trans_cols if c in collapsed_translations.columns]],
            on=["hypothesis_id", "family_engine_id"],
            how="left",
            suffixes=("", "_translation"),
            validate="many_to_one",
        )
    else:
        write_csv(ctx.run_root / "prelaunch/translation_key_uniqueness_audit.csv", [{"status": "pass", "detail": "no_translation_manifest"}])
        merged = defs.copy()
    allowed_lanes = {
        "kraken_tier1_ready",
        "compiled_for_future_full_sweep",
        "compiled_tier1_redesign",
        "priority_tier1_full_train_candidate",
        "priority_tier1_with_caps",
        "compiled_tier1_with_analytics_cap",
        "kraken_tier1_with_caps",
    }
    allowed_priority = {"", "nan", "priority_tier1_full_train_candidate", "priority_tier1_with_caps"}
    rankable_audit: list[dict[str, Any]] = []
    excluded: list[dict[str, Any]] = []
    for _, row in merged.iterrows():
        rec = row.to_dict()
        reasons: list[str] = []
        lane = str(row.get("allowed_lane", "")).strip()
        priority_lane = str(row.get("priority_lane", "")).strip()
        text = " ".join(str(row.get(c, "")) for c in ["allowed_lane", "priority_lane", "family", "archetype", "entry_template", "exit_template", "stop_template", "definition_kind", "translation_type", "translation_reason"]).lower()
        if lane not in allowed_lanes:
            reasons.append(f"allowed_lane_not_rankable:{lane}")
        if priority_lane.lower() not in allowed_priority:
            reasons.append(f"priority_lane_not_rankable:{priority_lane}")
        if any(k in text for k in ["not_compilable_current_translation", "needs_live_capture_substitute", "forward_capture_sidecar", "event_ledger_first", "candidate_library_only", "not_kraken_viable"]):
            reasons.append("nonrankable_or_sidecar_lane")
        if any(k in text for k in ["touch", "passive", "same-bar target-first", "same_bar_target_first", "raw orb", "listing", "liquidation sequencing", "liquidation_sequence", "microstructure"]):
            reasons.append("forbidden_execution_semantics")
        if "close_confirmed" not in str(row.get("entry_template", "")).lower():
            reasons.append("missing_close_confirmed_next_bar_entry")
        if str(row.get("translation_rankable", "True")).lower() in {"false", "0", "no"}:
            reasons.append("translation_rankable_conflicts_with_data_tier")
        if str(row.get("translation_type", "")).lower().startswith("direct"):
            translated = str(row.get("translated_engine", row.get("family_engine_id", "")))
            if translated and translated != str(row.get("family_engine_id", "")):
                reasons.append("direct_translation_engine_mismatch")
        if str(row.get("data_cap", "")).lower() in {"needs_live_capture_substitute", "live_capture_required"}:
            reasons.append("data_cap_requires_live_capture")
        rec["prelaunch_eligible"] = not reasons
        rec["prelaunch_exclusion_reason"] = ";".join(reasons)
        rec["preservation_state"] = "pending_compute" if not reasons else preservation_state_for_exclusion(";".join(reasons))
        rec["evidence_level"] = "level_1_generator_support"
        rankable_audit.append(rec)
        if reasons:
            excluded.append(rec)
    audit_df = deduplicate_definition_manifest(
        pd.DataFrame(rankable_audit),
        context="prelaunch_contract_eligibility",
        audit_path=ctx.run_root / "prelaunch/post_merge_definition_identity_audit.csv",
    )
    eligible = audit_df[parse_bool_series(audit_df["prelaunch_eligible"], default=False, strict=True)].copy() if not audit_df.empty else pd.DataFrame()
    write_csv(ctx.run_root / "prelaunch/prelaunch_contract_eligibility_audit.csv", audit_df)
    write_csv(ctx.run_root / "prelaunch/excluded_nonrankable_contracts.csv", excluded)
    write_csv(ctx.run_root / "prelaunch/eligible_definition_manifest.csv", eligible)
    write_text(ctx.run_root / "prelaunch/eligibility_gate_report.md", "\n".join([
        "# Prelaunch Contract Eligibility Gate",
        "",
        f"Source root: `{engine_wave_source_root(ctx)}`",
        f"Definitions audited: `{len(audit_df)}`",
        f"Eligible definitions: `{len(eligible)}`",
        f"Excluded non-rankable/current-translation rows: `{len(excluded)}`",
        "Excluded rows are preservation states, not hypothesis or family rejection.",
    ]) + "\n")
    if eligible.empty:
        raise RuntimeError("prelaunch eligibility gate found zero eligible definitions")


CANARY_ECONOMIC_IDENTITY_FIELDS = (
    "family_engine_id",
    "parameter_vector_hash",
    "side",
    "lookback_bars",
    "hold_bars",
    "stop_bps",
    "threshold",
    "entry_template",
    "exit_template",
    "stop_template",
    "regime_activation",
    "row_semantics",
    "selected_symbol_universe_hash",
    "pit_universe_hash",
)


def canary_economic_identity_key(row: Mapping[str, Any]) -> str:
    parts: list[str] = []
    for field in CANARY_ECONOMIC_IDENTITY_FIELDS:
        value = row.get(field, "")
        if field in {"selected_symbol_universe_hash", "pit_universe_hash"} and not str(value).strip():
            value = row.get("selected_symbol_universe", "")
        parts.append(f"{field}={str(value).strip()}")
    return stable_hash(*parts, n=32)


def deduplicate_tsmom_canary_definitions(defs: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if defs.empty:
        return defs.copy(), pd.DataFrame(), pd.DataFrame()
    enriched: list[dict[str, Any]] = []
    for _, row in defs.iterrows():
        rec = row.to_dict()
        engine = ENGINES.get(str(rec.get("family_engine_id", "scheduled_tsmom_engine")), ENGINES["scheduled_tsmom_engine"])
        enriched.append(identity_enriched_record(rec, engine))
    work = pd.DataFrame(enriched)
    bad_hash = work["parameter_vector_hash"].astype(str).str.strip().isin({"", "nan", "None"})
    bad_json = work["parameter_vector_json"].astype(str).str.strip().isin({"", "nan", "None"})
    if bool(bad_hash.any() or bad_json.any()):
        raise RuntimeError("TSMOM canary semantic dedup requires nonblank parameter_vector_hash and parameter_vector_json")
    work["canary_economic_identity_key"] = [canary_economic_identity_key(r.to_dict()) for _, r in work.iterrows()]
    audit_rows: list[dict[str, Any]] = []
    alias_rows: list[dict[str, Any]] = []
    keep_idx: list[int] = []
    for key, group in work.groupby("canary_economic_identity_key", sort=False):
        primary = group.iloc[0]
        keep_idx.append(int(primary.name))
        status = "unique" if len(group) == 1 else "semantic_duplicate_collapsed"
        audit_rows.append({
            "canary_economic_identity_key": key,
            "row_count": int(len(group)),
            "primary_candidate_definition_id": primary.get("candidate_definition_id", primary.get("definition_id", "")),
            "primary_definition_id": primary.get("definition_id", ""),
            "primary_hypothesis_id": primary.get("hypothesis_id", ""),
            "parameter_vector_hash": primary.get("parameter_vector_hash", ""),
            "parameter_vector_json": primary.get("parameter_vector_json", ""),
            "status": status,
            "action": "keep_primary" if len(group) == 1 else "keep_primary_record_aliases",
        })
        if len(group) > 1:
            for _, alias in group.iloc[1:].iterrows():
                alias_rows.append({
                    "canary_economic_identity_key": key,
                    "primary_candidate_definition_id": primary.get("candidate_definition_id", primary.get("definition_id", "")),
                    "primary_definition_id": primary.get("definition_id", ""),
                    "primary_hypothesis_id": primary.get("hypothesis_id", ""),
                    "alias_candidate_definition_id": alias.get("candidate_definition_id", alias.get("definition_id", "")),
                    "alias_definition_id": alias.get("definition_id", ""),
                    "alias_hypothesis_id": alias.get("hypothesis_id", ""),
                    "primary_parameter_vector_hash": primary.get("parameter_vector_hash", ""),
                    "primary_parameter_vector_json": primary.get("parameter_vector_json", ""),
                    "alias_parameter_vector_hash": alias.get("parameter_vector_hash", ""),
                    "alias_parameter_vector_json": alias.get("parameter_vector_json", ""),
                    "parameter_vector_hash": alias.get("parameter_vector_hash", ""),
                    "alias_status": "semantic_duplicate_alias_not_selected",
                })
    deduped = work.loc[keep_idx].copy().reset_index(drop=True)
    return deduped, pd.DataFrame(alias_rows), pd.DataFrame(audit_rows)


def select_tsmom_canary_definitions(defs: pd.DataFrame, limit: int) -> pd.DataFrame:
    if defs.empty or limit <= 0:
        return defs.head(0).copy()
    work, _, _ = deduplicate_tsmom_canary_definitions(defs)
    if "parameter_vector_hash" not in work.columns:
        work["parameter_vector_hash"] = ""
    selected_idx: list[int] = []

    def add_first(mask: pd.Series) -> None:
        nonlocal selected_idx
        if len(selected_idx) >= limit:
            return
        sub = work[mask & ~work.index.isin(selected_idx)]
        if not sub.empty:
            selected_idx.append(int(sub.index[0]))

    definition_kind = work.get("definition_kind", pd.Series("", index=work.index)).astype(str).str.lower()
    hyp = work.get("hypothesis_id", pd.Series("", index=work.index)).astype(str)
    family = work.get("family", pd.Series("", index=work.index)).astype(str).str.lower()
    regime = work.get("regime_activation", pd.Series("", index=work.index)).astype(str).str.lower()
    for kind in ["conservative", "plain_baseline", "normal", "aggressive"]:
        add_first(definition_kind.eq(kind))
    add_first(regime.eq("intended_regime"))
    add_first(hyp.eq("H02"))
    add_first(hyp.eq("A4") | family.str.contains("tsmom", case=False, regex=False))
    for idx in work.index:
        if len(selected_idx) >= limit:
            break
        if int(idx) not in selected_idx:
            selected_idx.append(int(idx))
    out = work.loc[selected_idx].drop_duplicates(["definition_id", "parameter_vector_hash"]).head(limit).copy()
    return out


def stage_engine_wave_plan_freeze(ctx: Context) -> None:
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        stage_family_engine_contracts(ctx)
        stage_tsmom_retest_universe_fanout(ctx)
    else:
        stage_panel_build(ctx)
        stage_family_engine_contracts(ctx)
        stage_family_universe_fanout_repair(ctx)
    eligible = read_csv_safe(ctx.run_root / "prelaunch/eligible_definition_manifest.csv")
    excluded = read_csv_safe(ctx.run_root / "prelaunch/excluded_nonrankable_contracts.csv")
    _, _, v0, wave_plan = load_engine_wave_source_manifests(ctx)
    if eligible.empty:
        raise RuntimeError("missing eligible definition manifest before wave plan freeze")
    plan_rows: list[dict[str, Any]] = []
    wave_defs: list[pd.DataFrame] = []
    budget_rows: list[dict[str, Any]] = []
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        engine_order = ["scheduled_tsmom_engine"]
    elif getattr(ctx.args, "family_list", ""):
        wanted = {x.strip() for x in str(ctx.args.family_list).split(",") if x.strip()}
        engine_order = [e for e in ENGINE_WAVE_ORDER if e in wanted]
    else:
        engine_order = list(ENGINE_WAVE_ORDER)
    if not engine_order:
        raise RuntimeError("engine wave plan has zero requested engines after family-list/profile filtering")
    for order, engine_id in enumerate(engine_order, start=1):
        src_wave = wave_plan[wave_plan.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)] if not wave_plan.empty else pd.DataFrame()
        src_v0 = v0[v0.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq(engine_id)] if not v0.empty else pd.DataFrame()
        planned = int(safe_float(src_wave["planned_definitions"].iloc[0], 0)) if not src_wave.empty else int(safe_float(src_v0["planned_definitions"].iloc[0], 0)) if not src_v0.empty else 0
        planned = planned or len(eligible[eligible["family_engine_id"].astype(str).eq(engine_id)])
        if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
            if is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
                default_limit = 3
            elif ctx.args.canary_selection_mode == "ultra_canary":
                default_limit = 5
            elif ctx.args.canary_selection_mode == "full_wave":
                default_limit = planned
            else:
                default_limit = 20
            planned = min(planned, int(getattr(ctx.args, "max_wave_definitions", 0) or default_limit))
        if ctx.args.smoke:
            planned = min(planned, 2)
        engine_eligible = deduplicate_definition_manifest(
            eligible[eligible["family_engine_id"].astype(str).eq(engine_id)].copy(),
            context=f"engine_wave_plan_{engine_id}",
            audit_path=ctx.run_root / "engine_wave" / f"{engine_id}_definition_duplicate_audit.csv",
        )
        sub = engine_eligible.head(planned).copy()
        if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")) and engine_id == "scheduled_tsmom_engine":
            deduped_all, alias_map, duplicate_audit = deduplicate_tsmom_canary_definitions(engine_eligible)
            write_csv(ctx.run_root / "canary/semantic_duplicate_selection_audit.csv", duplicate_audit)
            write_csv(ctx.run_root / "canary/canary_alias_mapping.csv", alias_map)
            write_csv(ctx.run_root / "canary/deduplicated_canary_definition_manifest.csv", deduped_all)
            sub = select_tsmom_canary_definitions(engine_eligible, planned)
        wave_id = f"{engine_id}__wave_001"
        if not sub.empty:
            sub["engine_wave_id"] = wave_id
            sub["engine_wave_order"] = order
            wave_defs.append(sub)
        b = ENGINE_WAVE_MATERIALIZATION_BUDGETS[engine_id]
        mat_budget = min(int(b["materialization_budget"]), int(len(sub)))
        audit_budget = min(int(b["audit_sample_budget"]), max(0, int(len(sub))))
        if ctx.args.smoke:
            mat_budget = min(mat_budget, 2)
            audit_budget = min(audit_budget, 1)
        elif is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
            fast_default = is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", ""))
            mat_budget = min(mat_budget, int(getattr(ctx.args, "canary_materialization_budget", 0) or (3 if fast_default or ctx.args.canary_selection_mode == "ultra_canary" else 10)))
            audit_budget = min(audit_budget, int(getattr(ctx.args, "canary_audit_sample_budget", 0) or (3 if fast_default or ctx.args.canary_selection_mode == "ultra_canary" else 5)))
        budget_rows.append({
            "engine_wave_id": wave_id,
            "family_engine_id": engine_id,
            "aggregate_definition_count": int(len(sub)),
            "materialization_budget": mat_budget,
            "near_miss_budget": mat_budget,
            "audit_sample_budget": audit_budget,
            "max_local_output_size_gb": ctx.args.max_output_gb,
            "archive_policy": "copy_after_hash_verification_only",
            "budget_is_event_cap": False,
        })
        plan_rows.append({
            "engine_wave_id": wave_id,
            "family_engine_id": engine_id,
            "engine_wave_order": order,
            "planned_definitions_from_v0": planned,
            "eligible_definitions": int(len(sub)),
            "runtime_hours_estimate": safe_float(src_wave["runtime_hours_estimate"].iloc[0], np.nan) if not src_wave.empty else safe_float(src_v0["runtime_hours_estimate"].iloc[0], np.nan) if not src_v0.empty else np.nan,
            "materialization_budget": mat_budget,
            "audit_sample_budget": audit_budget,
            "wave_status": "pending" if len(sub) else "skipped_no_eligible_definitions",
        })
    defs = pd.concat(wave_defs, ignore_index=True) if wave_defs else pd.DataFrame()
    write_csv(ctx.run_root / "engine_wave/engine_wave_execution_plan.csv", plan_rows)
    write_csv(ctx.run_root / "engine_wave/wave_definition_manifest.csv", defs)
    write_csv(ctx.run_root / "engine_wave/per_wave_materialization_budget.csv", budget_rows)
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        write_csv(ctx.run_root / "engine_wave/tsmom_retest_materialization_budget.csv", [
            {**r, "profile": ctx.args.phase_profile}
            for r in budget_rows
            if r.get("family_engine_id") == "scheduled_tsmom_engine"
        ])
    if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
        canary_defs = defs[defs.get("family_engine_id", pd.Series(dtype=str)).astype(str).eq("scheduled_tsmom_engine")].copy() if not defs.empty else pd.DataFrame()
        write_csv(ctx.run_root / "canary/tsmom_canary_definition_manifest.csv", canary_defs)
        write_text(ctx.run_root / "canary/tsmom_canary_budget_report.md", "\n".join([
            "# TSMOM Canary Budget Report",
            "",
            f"Selection mode: `{ctx.args.canary_selection_mode}`",
            f"Max wave definitions: `{getattr(ctx.args, 'max_wave_definitions', 0) or 'profile_default'}`",
            f"Definitions selected: `{len(canary_defs)}`",
            "Limits apply to candidate definitions only.",
            "Event sampling: `forbidden`.",
            "Symbol cap: `forbidden outside smoke`.",
            "Definition budgets do not cap events inside a selected definition, portfolio exposure, or max positions.",
        ]) + "\n")
        write_text(ctx.run_root / "canary/tsmom_canary_selection_rationale.md", "# TSMOM Canary Selection Rationale\n\nThe canary uses deterministic coverage-oriented definition selection: conservative, normal/plain, aggressive, intended-regime, H02, and A4/TSMOM-family rows are preferred where eligible, with duplicate parameter vectors removed.\n")
    pending = []
    planned_ids = set(defs.get("definition_id", pd.Series(dtype=str)).astype(str)) if not defs.empty else set()
    for _, r in eligible.iterrows():
        if str(r.get("definition_id", "")) not in planned_ids:
            pending.append({**r.to_dict(), "pending_reason": "eligible_but_outside_v0_engine_wave_definition_budget", "candidate_status": "pending_compute"})
    for _, r in excluded.iterrows():
        pending.append({**r.to_dict(), "pending_reason": r.get("prelaunch_exclusion_reason", ""), "candidate_status": r.get("preservation_state", "candidate_library_only")})
    write_csv(ctx.run_root / "engine_wave/pending_compute_manifest.csv", pending)
    write_csv(ctx.run_root / "mechanics/account_fee_scenario_manifest.csv", ENGINE_WAVE_FEE_SCENARIOS)
    write_text(ctx.run_root / "mechanics/fee_source_and_effective_period_report.md", "# Fee Source And Effective Period\n\n`kraken_current_account_zero_fee` is `operator_attested_current_account_state`, not a permanent venue rule. Fee-reversion scenarios are always reported alongside zero-fee results. Zero fees do not remove slippage, spread, funding, mark/liquidation, lifecycle, or adverse-wick stress.\n")
    write_text(ctx.run_root / "engine_wave/per_wave_output_budget_report.md", "# Per-Wave Output Budget\n\nMaterialization budgets cap selected candidates only. They are not event caps and unmaterialized definitions remain `pending_materialization` or `pending_compute`.\n")
    write_text(ctx.run_root / "engine_wave/engine_wave_order_rationale.md", "# Engine Wave Order Rationale\n\nOrder: scheduled TSMOM, liquid continuation, prior-high reclaim, compression breakout, retest/reclaim, funding/crowding, session/calendar. The first five are the most immediately bar-compatible Kraken Tier-1 families; funding/session are included but more cap-sensitive.\n")
    write_text(ctx.run_root / "engine_wave/wave_failure_policy.md", "# Wave Failure Policy\n\n- Prelaunch eligibility failure stops before waves.\n- Aggregate/materialized mismatch stops with `repair_wave_component_next`.\n- Invalid controls or self-match leakage stops with `repair_wave_component_next`.\n- Weak candidate results publish and continue.\n- Candidate-level zero controls cap that candidate; systemic zero controls stop the wave.\n- `STOP_AFTER_CURRENT_ENGINE_WAVE` finishes, publishes, archives, then exits cleanly.\n")


