def engine_wave_candidates(ctx: Context, wave_defs: pd.DataFrame) -> pd.DataFrame:
    universe = load_family_universe_map(ctx)
    panel = panel_manifest_for_repair(ctx)
    return generate_candidate_registry_for_family_universe(wave_defs, universe, len(wave_defs), panel=panel, ctx=ctx)


def aggregate_candidates_to_dir(ctx: Context, candidates: pd.DataFrame, out_dir: Path) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    assert_candidate_symbol_uniqueness(
        candidates,
        context="pre_aggregate_candidate_registry",
        audit_path=out_dir / "candidate_symbol_uniqueness_audit.csv",
    )
    if is_memorysafe_two_family_profile(getattr(ctx.args, "phase_profile", "")):
        return aggregate_candidates_memorysafe_to_dir(ctx, candidates, out_dir)
    aggregate, sym_month, regime, year, month, fold = aggregate_candidates(ctx, candidates)
    for name, df in [
        ("all_candidate_aggregate_summary.parquet", aggregate),
        ("candidate_symbol_month_summary.parquet", sym_month),
        ("candidate_regime_summary.parquet", regime),
        ("candidate_year_summary.parquet", year),
        ("candidate_month_summary.parquet", month),
        ("candidate_fold_summary.parquet", fold),
    ]:
        p = out_dir / name
        p.parent.mkdir(parents=True, exist_ok=True)
        df.to_parquet(p, index=False)
    return aggregate, sym_month, regime



def numeric_sum(series: pd.Series) -> float:
    return float(pd.to_numeric(series, errors="coerce").fillna(0.0).sum())


def aggregate_definition_scope(aggregate: pd.DataFrame) -> pd.DataFrame:
    if aggregate.empty:
        return pd.DataFrame()
    agg = aggregate.copy()
    if "candidate_definition_id" not in agg.columns:
        agg["candidate_definition_id"] = agg.get("candidate_id", agg.get("definition_id", "")).astype(str)
    if "parameter_vector_hash" not in agg.columns:
        agg["parameter_vector_hash"] = ""
    if all(c in agg.columns for c in CANDIDATE_SYMBOL_IDENTITY_FIELDS):
        assert_candidate_symbol_uniqueness(agg, context="aggregate_definition_scope_input")
    group_cols = ["candidate_definition_id", "parameter_vector_hash"]
    rows: list[dict[str, Any]] = []
    for _, g in agg.groupby(group_cols, dropna=False, sort=False):
        first = g.iloc[0].to_dict()
        events = pd.to_numeric(g.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        net_vals = pd.to_numeric(g.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        events_total = int(events.sum())
        symbols = sorted(set(g.get("symbol", pd.Series(dtype=str)).dropna().astype(str)))
        active_symbol_rows = g[pd.to_numeric(g.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0) > 0]
        active_symbols_for_metric = sorted(set(active_symbol_rows.get("symbol", pd.Series(dtype=str)).dropna().astype(str)))
        months = set()
        for col in ["active_months"]:
            if col in g.columns:
                # This is conservative for grouped summaries; materialized audit recomputes exact months.
                pass
        row = {**first}
        row.update({
            "candidate_id": first.get("candidate_definition_id", first.get("candidate_id")),
            "candidate_definition_id": first.get("candidate_definition_id", first.get("candidate_id")),
            "candidate_symbol_id": "",
            "symbol": "__universe__",
            "materialization_scope": "definition_universe",
            "selected_symbol_universe": ";".join(symbols),
            "selected_candidate_symbol_ids": ";".join(g.get("candidate_symbol_id", pd.Series(dtype=str)).dropna().astype(str).tolist()),
            "selected_candidate_symbol_rows": int(len(g)),
            "events": events_total,
            "event_count": events_total,
            "net_R": numeric_sum(g.get("net_R", pd.Series(dtype=float))),
            "gross_R": numeric_sum(g.get("gross_R", pd.Series(dtype=float))),
            "fees_R": numeric_sum(g.get("fees_R", pd.Series(dtype=float))),
            "funding_R": numeric_sum(g.get("funding_R", pd.Series(dtype=float))),
            "slippage_R": numeric_sum(g.get("slippage_R", pd.Series(dtype=float))),
            "raw_net_R": numeric_sum(g.get("raw_net_R", g.get("net_R", pd.Series(dtype=float)))),
            "raw_gross_R": numeric_sum(g.get("raw_gross_R", g.get("gross_R", pd.Series(dtype=float)))),
            "raw_fee_R": numeric_sum(g.get("raw_fee_R", g.get("fees_R", pd.Series(dtype=float)))),
            "raw_funding_R": numeric_sum(g.get("raw_funding_R", g.get("funding_R", pd.Series(dtype=float)))),
            "raw_slippage_R": numeric_sum(g.get("raw_slippage_R", g.get("slippage_R", pd.Series(dtype=float)))),
            "scaled_net_R": numeric_sum(g.get("scaled_net_R", g.get("net_R", pd.Series(dtype=float)))),
            "scaled_gross_R": numeric_sum(g.get("scaled_gross_R", g.get("gross_R", pd.Series(dtype=float)))),
            "scaled_fee_R": numeric_sum(g.get("scaled_fee_R", g.get("fees_R", pd.Series(dtype=float)))),
            "scaled_funding_R": numeric_sum(g.get("scaled_funding_R", g.get("funding_R", pd.Series(dtype=float)))),
            "scaled_slippage_R": numeric_sum(g.get("scaled_slippage_R", g.get("slippage_R", pd.Series(dtype=float)))),
            "active_symbols": int(len(active_symbols_for_metric)),
            "active_months": int(pd.to_numeric(g.get("active_months", pd.Series(dtype=float)), errors="coerce").fillna(0).max()) if "active_months" in g.columns else 0,
            "PF": pf(net_vals) if len(net_vals) else np.nan,
            "win_rate": float((net_vals > 0).mean()) if len(net_vals) else np.nan,
            "avg_R": float(net_vals.mean()) if len(net_vals) else np.nan,
            "median_R": float(net_vals.median()) if len(net_vals) else np.nan,
            "trimmed_mean_R": trimmed_mean(net_vals),
            "max_dd_R": max_dd(net_vals),
            "original_selected_events": events_total,
            "original_selected_net_R": numeric_sum(g.get("net_R", pd.Series(dtype=float))),
            "original_selected_gross_R": numeric_sum(g.get("gross_R", pd.Series(dtype=float))),
            "original_selected_fees_R": numeric_sum(g.get("fees_R", pd.Series(dtype=float))),
            "original_selected_funding_R": numeric_sum(g.get("funding_R", pd.Series(dtype=float))),
            "original_selected_raw_net_R": numeric_sum(g.get("raw_net_R", g.get("net_R", pd.Series(dtype=float)))),
            "original_selected_raw_gross_R": numeric_sum(g.get("raw_gross_R", g.get("gross_R", pd.Series(dtype=float)))),
            "original_selected_raw_fee_R": numeric_sum(g.get("raw_fee_R", g.get("fees_R", pd.Series(dtype=float)))),
            "original_selected_raw_funding_R": numeric_sum(g.get("raw_funding_R", g.get("funding_R", pd.Series(dtype=float)))),
            "original_selected_raw_slippage_R": numeric_sum(g.get("raw_slippage_R", g.get("slippage_R", pd.Series(dtype=float)))),
            "original_selected_scaled_net_R": numeric_sum(g.get("scaled_net_R", g.get("net_R", pd.Series(dtype=float)))),
            "original_selected_scaled_gross_R": numeric_sum(g.get("scaled_gross_R", g.get("gross_R", pd.Series(dtype=float)))),
            "original_selected_scaled_fee_R": numeric_sum(g.get("scaled_fee_R", g.get("fees_R", pd.Series(dtype=float)))),
            "original_selected_scaled_funding_R": numeric_sum(g.get("scaled_funding_R", g.get("funding_R", pd.Series(dtype=float)))),
            "original_selected_scaled_slippage_R": numeric_sum(g.get("scaled_slippage_R", g.get("slippage_R", pd.Series(dtype=float)))),
        })
        for field in TSMOM_ACTIVE_PARAMETER_FIELDS:
            row.setdefault(field, first.get(field, ""))
        rows.append(row)
    return pd.DataFrame(rows)


def select_wave_materialization(ctx: Context, engine_wave_id: str, aggregate: pd.DataFrame, budget_row: Mapping[str, Any], out_dir: Path, sym_month: pd.DataFrame | None = None) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if aggregate.empty:
        for name in ["materialization_selection", "near_miss_selection", "audit_sample_selection", "candidate_overlap_clusters"]:
            write_csv(out_dir / f"{name}.csv", [])
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    scoped = aggregate_definition_scope(aggregate)
    scoped["score"] = pd.to_numeric(scoped.get("net_R", 0), errors="coerce").fillna(0) + pd.to_numeric(scoped.get("median_R", 0), errors="coerce").fillna(0) * 10
    mat_budget = int(safe_float(budget_row.get("materialization_budget"), 0))
    near_budget = int(safe_float(budget_row.get("near_miss_budget"), mat_budget))
    audit_budget = int(safe_float(budget_row.get("audit_sample_budget"), 0))
    clusters = []
    for _, r in scoped.iterrows():
        key = stable_hash(r.get("hypothesis_id"), r.get("family_engine_id"), r.get("candidate_definition_id"), r.get("parameter_vector_hash"), r.get("row_semantics"), n=16)
        clusters.append({
            "candidate_definition_id": r.get("candidate_definition_id"),
            "candidate_id": r.get("candidate_definition_id"),
            "candidate_cluster_id": key,
            "family_engine_id": r.get("family_engine_id"),
            "parameter_similarity_key": key,
            "event_overlap_proxy": "definition_scope_before_materialization",
            "return_stream_correlation_proxy": "pending_selected_materialization",
            "symbol_month_concentration_similarity": "pending_selected_materialization",
        })
    selection_policy = "full_train_diagnostic_only"
    selected = pd.DataFrame()
    dev_eval_coverage = pd.DataFrame()
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")) and sym_month is not None and not sym_month.empty:
        months_for_selection = sym_month.copy()
        if "candidate_definition_id" in months_for_selection.columns:
            months_for_selection["candidate_id"] = months_for_selection["candidate_definition_id"].astype(str)
        scoped_for_selection = scoped.copy()
        scoped_for_selection["candidate_id"] = scoped_for_selection["candidate_definition_id"].astype(str)
        proposed = proposal_only_selection(scoped_for_selection, months_for_selection, budget=mat_budget)
        dev_summary = dev_eval_summary(months_for_selection)
        dev_eval_coverage = apply_dev_eval_caps(dev_summary)
        if not proposed.empty:
            order = {str(cid): i for i, cid in enumerate(proposed["candidate_id"].astype(str).tolist())}
            selected = scoped[scoped["candidate_definition_id"].astype(str).isin(order)].copy()
            selected["_proposal_order"] = selected["candidate_definition_id"].astype(str).map(order)
            selected = selected.sort_values("_proposal_order").drop_duplicates(["candidate_definition_id", "parameter_vector_hash"]).head(mat_budget).drop(columns=["_proposal_order"], errors="ignore")
            selection_policy = "proposal_train_segment"
    if selected.empty:
        selected = scoped.sort_values("score", ascending=False).drop_duplicates(["candidate_definition_id", "parameter_vector_hash"]).head(mat_budget).copy()
    selected["selection_reason"] = "cluster_representative_broad_score" if selection_policy != "proposal_train_segment" else "proposal_train_segment_cluster_representative"
    selected["selection_segment_used"] = selection_policy
    selected["proposal_list_frozen_before_internal_eval_scoring"] = selection_policy == "proposal_train_segment"
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")) and not dev_eval_coverage.empty and "candidate_id" in dev_eval_coverage.columns:
        coverage_cols = [
            c for c in [
                "candidate_id",
                "coverage_status",
                "evidence_cap_reason",
                "proposal_events",
                "internal_eval_events",
                "proposal_active_symbols",
                "proposal_active_months",
                "internal_eval_active_symbols",
                "internal_eval_active_months",
                "proposal_net_R",
                "internal_eval_net_R",
            ]
            if c in dev_eval_coverage.columns
        ]
        selected = selected.merge(
            dev_eval_coverage[coverage_cols].rename(columns={
                "candidate_id": "_dev_eval_candidate_id",
                "coverage_status": "dev_eval_policy_status",
                "evidence_cap_reason": "internal_eval_cap_reason",
                "proposal_events": "proposal_train_event_count",
                "internal_eval_events": "internal_eval_train_event_count",
                "proposal_active_symbols": "proposal_active_symbols",
                "proposal_active_months": "proposal_active_months",
                "internal_eval_active_symbols": "internal_eval_active_symbols",
                "internal_eval_active_months": "internal_eval_active_months",
            }),
            left_on="candidate_definition_id",
            right_on="_dev_eval_candidate_id",
            how="left",
        ).drop(columns=["_dev_eval_candidate_id"], errors="ignore")
        selected["internal_eval_sample_limited_cap"] = selected.get("dev_eval_policy_status", pd.Series("", index=selected.index)).astype(str).eq("internal_eval_sample_limited_cap")
    else:
        selected["internal_eval_sample_limited_cap"] = False
    selected["evidence_cap_reason"] = np.where(
        selected["selection_segment_used"].astype(str).eq("full_train_diagnostic_only"),
        "aggregate_screen_only_full_train_selection_bias_cap",
        selected.get("evidence_cap_reason", pd.Series([""] * len(selected), index=selected.index)),
    )
    if "internal_eval_cap_reason" in selected.columns:
        selected["evidence_cap_reason"] = [
            ";".join(sorted({x for x in [str(base or "").strip(), str(cap or "").strip()] if x and x.lower() not in {"nan", "none"}}))
            for base, cap in zip(selected["evidence_cap_reason"], selected["internal_eval_cap_reason"])
        ]
    selected["candidate_status"] = "selected_for_universe_materialization"
    selected.loc[parse_bool_series(selected.get("internal_eval_sample_limited_cap", pd.Series(False, index=selected.index)), default=False), "candidate_status"] = "sample_limited_pending_validation"
    near = scoped[(pd.to_numeric(scoped.get("events", 0), errors="coerce").fillna(0) > 0) & ~scoped["candidate_definition_id"].isin(selected["candidate_definition_id"])].sort_values("score", ascending=False).drop_duplicates(["candidate_definition_id", "parameter_vector_hash"]).head(near_budget).copy()
    near["selection_reason"] = "near_miss_preservation"
    near["candidate_status"] = "near_miss_preserved"
    used_defs = pd.concat([selected.get("candidate_definition_id", pd.Series(dtype=str)), near.get("candidate_definition_id", pd.Series(dtype=str))], ignore_index=True)
    remain = scoped[~scoped["candidate_definition_id"].isin(used_defs)]
    audit = remain.sample(n=min(audit_budget, len(remain)), random_state=ctx.args.seed) if len(remain) else pd.DataFrame()
    if not audit.empty:
        audit = audit.copy()
        audit["selection_reason"] = "stratified_failed_audit_sample"
        audit["candidate_status"] = "audit_sample"
    write_csv(out_dir / "materialization_selection.csv", selected)
    write_csv(out_dir / "near_miss_selection.csv", near)
    write_csv(out_dir / "audit_sample_selection.csv", audit)
    write_csv(out_dir / "candidate_overlap_clusters.csv", clusters)
    if is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        if sym_month is not None and not sym_month.empty:
            months_for_report = sym_month.copy()
            if "candidate_definition_id" in months_for_report.columns:
                months_for_report["candidate_id"] = months_for_report["candidate_definition_id"].astype(str)
            segmented, split_ts = assign_train_internal_segments(months_for_report)
            dev_summary = dev_eval_summary(months_for_report)
            dev_eval_coverage = dev_eval_coverage if not dev_eval_coverage.empty else apply_dev_eval_caps(dev_summary)
        else:
            split_ts = None
            dev_eval_coverage = pd.DataFrame()
        write_csv(out_dir / "dev_eval_coverage_audit.csv", dev_eval_coverage)
        write_csv(ctx.run_root / "validation/dev_eval_coverage_audit.csv", dev_eval_coverage)
        write_csv(ctx.run_root / "validation/dev_eval_split_manifest.csv", [{
            "engine_wave_id": engine_wave_id,
            "split_policy": "deterministic_chronological_50_50_train_internal",
            "proposal_segment_label": "proposal_train_segment",
            "internal_eval_segment_label": "internal_eval_train_segment",
            "full_train_label": "full_train_diagnostic_only",
            "split_ts": str(split_ts) if split_ts is not None else "",
            "internal_eval_is_holdout_or_validation": False,
        }])
        write_csv(ctx.run_root / "validation/proposal_scoring_overlap_audit.csv", [{
            "engine_wave_id": engine_wave_id,
            "selection_segment_used": selection_policy,
            "proposal_list_frozen_before_internal_eval_scoring": selection_policy == "proposal_train_segment",
            "cap_applied": "aggregate_screen_only_full_train_selection_bias_cap" if selection_policy == "full_train_diagnostic_only" else "",
        }])
        write_text(ctx.run_root / "selection/dev_eval_aware_selection_policy.md", "# Dev/Eval-Aware Selection Policy\n\nMaterialization proposals use `proposal_train_segment` when candidate/month coverage is available. `internal_eval_train_segment` is train-internal only and may be scored only after proposal freeze. If the runner must select from full train, selected candidates receive `aggregate_screen_only_full_train_selection_bias_cap` and cannot receive clean level 4/5 labels from that selection path.\n")
    write_text(out_dir / "selection_report.md", f"# Selection Report\n\nWave: `{engine_wave_id}`\nSelected definition-level candidates: `{len(selected)}`\nNear misses: `{len(near)}`\nAudit sample: `{len(audit)}`\nSelection budgets cap materialization only, not eligible events. Rankable selections are definition-level and universe-wide.\n")
    return selected, near, audit


def materialize_wave_candidates(ctx: Context, candidates: pd.DataFrame, out_dir: Path) -> tuple[pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    ledger_dir = out_dir / "event_ledgers"
    ledger_dir.mkdir(parents=True, exist_ok=True)
    manifest: list[dict[str, Any]] = []
    coverage: list[dict[str, Any]] = []
    mechanics: list[dict[str, Any]] = []
    for _, cand in candidates.drop_duplicates(["candidate_definition_id", "parameter_vector_hash"]).iterrows():
        base = identity_enriched_record(cand.to_dict())
        engine = engine_for_candidate(base)
        scope = str(base.get("materialization_scope", "definition_universe"))
        symbols = [s for s in str(base.get("selected_symbol_universe", "")).split(";") if s]
        if not symbols and str(base.get("symbol", "")) not in {"", "__universe__", "nan"}:
            symbols = [str(base.get("symbol"))]
            scope = "single_symbol_diagnostic_only"
        if not symbols:
            symbols = []
        ledgers = []
        for sym in symbols:
            cdict = identity_enriched_record({**base, "symbol": sym}, engine, symbol=sym)
            bars = load_symbol_bars(paths, sym, ctx.start, ctx.end)
            funding = load_funding(paths, sym, ctx.end)
            ledger = engine.regenerate_materialized_ledger(bars, funding, cdict) if not bars.empty else pd.DataFrame()
            if not ledger.empty:
                ledger["materialization_scope"] = scope
                ledger["single_symbol_diagnostic_only"] = scope == "single_symbol_diagnostic_only"
                ledgers.append(ledger)
        all_ledger = pd.concat(ledgers, ignore_index=True) if ledgers else pd.DataFrame()
        if not all_ledger.empty:
            protected = require_no_protected_timestamps(all_ledger, ["decision_ts", "entry_ts", "exit_ts"], label="wave_materialized")
            if protected.status != "pass":
                raise RuntimeError("protected timestamp in wave materialized ledger")
        file_key = safe_filename(f"definition__{base['candidate_definition_id']}__{base['parameter_vector_hash']}") if scope == "definition_universe" else safe_filename(f"symbol__{base.get('candidate_symbol_id', base['candidate_definition_id'])}")
        out_path = ledger_dir / f"{file_key}.parquet"
        parquet_safe_frame(all_ledger).to_parquet(out_path, index=False, compression="zstd")
        manifest_row = {
            "candidate_id": base["candidate_definition_id"],
            "candidate_definition_id": base["candidate_definition_id"],
            "candidate_symbol_id": "" if scope == "definition_universe" else base.get("candidate_symbol_id", ""),
            "definition_id": base.get("definition_id", ""),
            "hypothesis_id": base.get("hypothesis_id", ""),
            "family": base.get("family", ""),
            "family_engine_id": engine.engine_id,
            "symbol": "__universe__" if scope == "definition_universe" else ";".join(symbols),
            "materialized_symbols": ";".join(symbols),
            "symbol_count_materialized": len(symbols),
            "materialization_scope": scope,
            "single_symbol_diagnostic_only": scope == "single_symbol_diagnostic_only",
            "archetype": base.get("archetype", ""),
            "side": base.get("side", ""),
            "lookback_bars": base.get("lookback_bars", ""),
            "hold_bars": base.get("hold_bars", ""),
            "stop_bps": base.get("stop_bps", ""),
            "threshold": base.get("threshold", ""),
            "entry_template": base.get("entry_template", ""),
            "exit_template": base.get("exit_template", ""),
            "stop_template": base.get("stop_template", ""),
            "regime_activation": base.get("regime_activation", ""),
            "row_semantics": engine.row_semantics(),
            "event_semantics_version": EVENT_SEMANTICS_VERSION,
            "parameter_vector_hash": base.get("parameter_vector_hash", ""),
            "parameter_vector_json": base.get("parameter_vector_json", ""),
            "parameter_manifest_pointer": base.get("parameter_manifest_pointer", ""),
            "evidence_cap_reason": base.get("evidence_cap_reason", ""),
            "dev_eval_policy_status": base.get("dev_eval_policy_status", ""),
            "internal_eval_sample_limited_cap": parse_bool_value(base.get("internal_eval_sample_limited_cap", False), default=False),
            "internal_eval_cap_reason": base.get("internal_eval_cap_reason", ""),
            "proposal_train_event_count": base.get("proposal_train_event_count", ""),
            "internal_eval_train_event_count": base.get("internal_eval_train_event_count", ""),
            "proposal_active_symbols": base.get("proposal_active_symbols", ""),
            "internal_eval_active_symbols": base.get("internal_eval_active_symbols", ""),
            "proposal_active_months": base.get("proposal_active_months", ""),
            "internal_eval_active_months": base.get("internal_eval_active_months", ""),
            "original_selected_events": int(safe_float(base.get("original_selected_events", base.get("events", 0)), 0)),
            "original_selected_net_R": safe_float(base.get("original_selected_net_R", base.get("net_R", 0)), 0.0),
            "original_selected_gross_R": safe_float(base.get("original_selected_gross_R", base.get("gross_R", 0)), 0.0),
            "original_selected_fees_R": safe_float(base.get("original_selected_fees_R", base.get("fees_R", 0)), 0.0),
            "original_selected_funding_R": safe_float(base.get("original_selected_funding_R", base.get("funding_R", 0)), 0.0),
            "original_selected_raw_net_R": safe_float(base.get("original_selected_raw_net_R", base.get("raw_net_R", base.get("net_R", 0))), 0.0),
            "original_selected_raw_gross_R": safe_float(base.get("original_selected_raw_gross_R", base.get("raw_gross_R", base.get("gross_R", 0))), 0.0),
            "original_selected_raw_fee_R": safe_float(base.get("original_selected_raw_fee_R", base.get("raw_fee_R", base.get("fees_R", 0))), 0.0),
            "original_selected_raw_funding_R": safe_float(base.get("original_selected_raw_funding_R", base.get("raw_funding_R", base.get("funding_R", 0))), 0.0),
            "original_selected_raw_slippage_R": safe_float(base.get("original_selected_raw_slippage_R", base.get("raw_slippage_R", base.get("slippage_R", 0))), 0.0),
            "original_selected_scaled_net_R": safe_float(base.get("original_selected_scaled_net_R", base.get("scaled_net_R", base.get("net_R", 0))), 0.0),
            "original_selected_scaled_gross_R": safe_float(base.get("original_selected_scaled_gross_R", base.get("scaled_gross_R", base.get("gross_R", 0))), 0.0),
            "original_selected_scaled_fee_R": safe_float(base.get("original_selected_scaled_fee_R", base.get("scaled_fee_R", base.get("fees_R", 0))), 0.0),
            "original_selected_scaled_funding_R": safe_float(base.get("original_selected_scaled_funding_R", base.get("scaled_funding_R", base.get("funding_R", 0))), 0.0),
            "original_selected_scaled_slippage_R": safe_float(base.get("original_selected_scaled_slippage_R", base.get("scaled_slippage_R", base.get("slippage_R", 0))), 0.0),
            "path": str(out_path.relative_to(ctx.run_root)),
            "event_rows": len(all_ledger),
            "size_bytes": out_path.stat().st_size,
            "evidence_level": "level_3_event_level_trade_ledger" if len(all_ledger) else "level_2_path_or_interval_support_only",
        }
        manifest_row.update(active_parameter_field_payload(base))
        manifest.append(manifest_row)
        coverage.append({"candidate_id": base["candidate_definition_id"], "candidate_definition_id": base["candidate_definition_id"], "parameter_vector_hash": base.get("parameter_vector_hash", ""), "expected_eligible_event_count": len(all_ledger), "generated_event_count": len(all_ledger), "coverage_ratio": 1.0, "event_sampling_used": False, "event_cap_used": False, "row_semantics": engine.row_semantics(), "event_semantics_version": EVENT_SEMANTICS_VERSION, "materialization_scope": scope})
        mechanics.append({"candidate_id": base["candidate_definition_id"], "candidate_definition_id": base["candidate_definition_id"], "parameter_vector_hash": base.get("parameter_vector_hash", ""), "rows": len(all_ledger), "trade_price_source_present": "trade_price_source" in all_ledger.columns, "mark_price_source_present": "mark_price_source" in all_ledger.columns, "funding_flags_present": {"funding_exact", "funding_proxy_used", "funding_boundary_crossed"}.issubset(all_ledger.columns), "fee_model_present": "fee_model_used" in all_ledger.columns, "same_bar_ambiguity_flag_present": "same_bar_ambiguity_flag" in all_ledger.columns, "status": "pass" if len(all_ledger) else "no_events"})
    write_csv(out_dir / "materialized_ledger_manifest.csv", manifest)
    write_csv(out_dir / "full_event_coverage_audit.csv", coverage)
    write_csv(out_dir / "mechanics_audit.csv", mechanics)
    write_csv(ctx.run_root / "mechanics/selected_materialized_mechanics_audit.csv", mechanics)
    return pd.DataFrame(manifest), pd.DataFrame(coverage)


SCOPE_AUDIT_METRICS = (
    "events",
    "gross_R",
    "fees_R",
    "funding_R",
    "slippage_R",
    "net_R",
    "raw_gross_R",
    "raw_fee_R",
    "raw_funding_R",
    "raw_slippage_R",
    "raw_net_R",
    "scaled_gross_R",
    "scaled_fee_R",
    "scaled_funding_R",
    "scaled_slippage_R",
    "scaled_net_R",
    "active_symbols",
)


def ledger_metric_totals(frame: pd.DataFrame) -> dict[str, Any]:
    if frame.empty:
        return {metric: 0.0 for metric in SCOPE_AUDIT_METRICS}
    return {
        "events": int(len(frame)),
        "gross_R": numeric_sum(frame.get("gross_R", pd.Series(dtype=float))),
        "fees_R": numeric_sum(frame.get("fees_R", pd.Series(dtype=float))),
        "funding_R": numeric_sum(frame.get("funding_R", pd.Series(dtype=float))),
        "slippage_R": numeric_sum(frame.get("slippage_R", pd.Series(dtype=float))),
        "net_R": numeric_sum(frame.get("net_R", pd.Series(dtype=float))),
        "raw_gross_R": numeric_sum(frame.get("raw_gross_R", frame.get("gross_R", pd.Series(dtype=float)))),
        "raw_fee_R": numeric_sum(frame.get("raw_fee_R", frame.get("fees_R", pd.Series(dtype=float)))),
        "raw_funding_R": numeric_sum(frame.get("raw_funding_R", frame.get("funding_R", pd.Series(dtype=float)))),
        "raw_slippage_R": numeric_sum(frame.get("raw_slippage_R", frame.get("slippage_R", pd.Series(dtype=float)))),
        "raw_net_R": numeric_sum(frame.get("raw_net_R", frame.get("net_R", pd.Series(dtype=float)))),
        "scaled_gross_R": numeric_sum(frame.get("scaled_gross_R", frame.get("gross_R", pd.Series(dtype=float)))),
        "scaled_fee_R": numeric_sum(frame.get("scaled_fee_R", frame.get("fees_R", pd.Series(dtype=float)))),
        "scaled_funding_R": numeric_sum(frame.get("scaled_funding_R", frame.get("funding_R", pd.Series(dtype=float)))),
        "scaled_slippage_R": numeric_sum(frame.get("scaled_slippage_R", frame.get("slippage_R", pd.Series(dtype=float)))),
        "scaled_net_R": numeric_sum(frame.get("scaled_net_R", frame.get("net_R", pd.Series(dtype=float)))),
        "active_symbols": int(frame["symbol"].nunique()) if "symbol" in frame.columns else 0,
    }


def scope_split_timestamp(ctx: Context) -> pd.Timestamp | None:
    for path in [
        ctx.run_root / "validation/dev_eval_split_manifest.csv",
        ctx.run_root / "waves/scheduled_tsmom_engine__wave_001/selection/dev_eval_coverage_audit.csv",
    ]:
        df = read_csv_safe(path)
        if not df.empty and "split_ts" in df.columns:
            ts = pd.to_datetime(df["split_ts"].dropna().astype(str).replace("", np.nan).dropna().head(1), utc=True, errors="coerce")
            if len(ts) and pd.notna(ts.iloc[0]):
                return pd.Timestamp(ts.iloc[0])
    return None


def aggregate_reference_by_scope(ctx: Context, out_dir: Path, candidates: pd.DataFrame) -> dict[tuple[str, str, str], dict[str, Any]]:
    refs: dict[tuple[str, str, str], dict[str, Any]] = {}
    agg = read_parquet_safe(out_dir.parent / "aggregate" / "all_candidate_aggregate_summary.parquet")
    if agg.empty:
        agg = candidates.copy()
    if not agg.empty:
        scoped = aggregate_definition_scope(agg)
        for _, r in scoped.iterrows():
            key = (str(r.get("candidate_definition_id", r.get("candidate_id", ""))), str(r.get("parameter_vector_hash", "")), "full_train_diagnostic_only")
            refs[key] = {metric: safe_float(r.get(metric), 0.0) for metric in SCOPE_AUDIT_METRICS}
    months = read_parquet_safe(out_dir.parent / "aggregate" / "candidate_symbol_month_summary.parquet")
    if not months.empty and "month" in months.columns:
        seg, _ = assign_train_internal_segments(months)
        if "candidate_definition_id" not in seg.columns and "candidate_id" in seg.columns:
            seg["candidate_definition_id"] = seg["candidate_id"].astype(str)
        hash_map = {}
        if not agg.empty and {"candidate_definition_id", "parameter_vector_hash"}.issubset(agg.columns):
            hash_map = agg.drop_duplicates("candidate_definition_id").set_index("candidate_definition_id")["parameter_vector_hash"].astype(str).to_dict()
        for (cid, segment), g in seg.groupby(["candidate_definition_id", "train_internal_segment"], dropna=False):
            phash = hash_map.get(str(cid), "")
            refs[(str(cid), phash, str(segment))] = ledger_metric_totals(g.rename(columns={"events": "_events_for_scope"}))
            refs[(str(cid), phash, str(segment))]["events"] = int(pd.to_numeric(g.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    return refs


def materialized_frame_for_scope(ledger: pd.DataFrame, scope: str, split_ts: pd.Timestamp | None) -> pd.DataFrame:
    if ledger.empty or scope == "full_train_diagnostic_only" or split_ts is None:
        return ledger.copy()
    out = ledger.copy()
    out["decision_ts"] = pd.to_datetime(out.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce")
    if scope == "proposal_train_segment":
        return out[out["decision_ts"] < split_ts].copy()
    if scope == "internal_eval_train_segment":
        return out[out["decision_ts"] >= split_ts].copy()
    return out


def aggregate_vs_materialized_wave_audit(ctx: Context, candidates: pd.DataFrame, manifest: pd.DataFrame, out_dir: Path) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    failures: list[dict[str, Any]] = []
    cand_by_key = {(str(r.get("candidate_definition_id", r.get("candidate_id"))), str(r.get("parameter_vector_hash", ""))): r.to_dict() for _, r in candidates.iterrows()}
    refs = aggregate_reference_by_scope(ctx, out_dir, candidates)
    split_ts = scope_split_timestamp(ctx)
    scopes = ["full_train_diagnostic_only", "proposal_train_segment", "internal_eval_train_segment"]
    for _, m in manifest.iterrows():
        cid = str(m.get("candidate_definition_id", m.get("candidate_id")))
        phash = str(m.get("parameter_vector_hash", ""))
        selected = cand_by_key.get((cid, phash), {})
        p = ctx.run_root / str(m["path"])
        ledger = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        identity_pass = bool(selected) and str(selected.get("parameter_vector_hash", "")) == phash and str(selected.get("candidate_definition_id", selected.get("candidate_id", ""))) == cid
        for scope in scopes:
            mat = ledger_metric_totals(materialized_frame_for_scope(ledger, scope, split_ts))
            ref = refs.get((cid, phash, scope)) or refs.get((cid, "", scope))
            reference_available = ref is not None
            for metric in SCOPE_AUDIT_METRICS:
                if not reference_available:
                    status = "not_applicable"
                    a = np.nan
                    b = mat.get(metric, 0.0)
                    diff = 0.0
                else:
                    a = safe_float(ref.get(metric), 0.0)
                    b = safe_float(mat.get(metric), 0.0)
                    diff = abs(float(a) - float(b))
                    status = "pass" if identity_pass and diff <= AGGREGATE_MATERIALIZED_TOLERANCE else "fail"
                rec = {
                    "candidate_id": m.get("candidate_id"),
                    "candidate_definition_id": cid,
                    "parameter_vector_hash": phash,
                    "family_engine_id": m.get("family_engine_id"),
                    "scope": scope,
                    "metric": metric,
                    "aggregate_value": a,
                    "original_selected_value": a,
                    "materialized_value": b,
                    "abs_diff": diff,
                    "tolerance": AGGREGATE_MATERIALIZED_TOLERANCE,
                    "identity_key_pass": identity_pass,
                    "reference_available": bool(reference_available),
                    "split_ts": "" if split_ts is None else str(split_ts),
                    "status": status,
                }
                rows.append(rec)
                if status == "fail":
                    failures.append(rec)
    out = pd.DataFrame(rows)
    write_csv(out_dir / "original_selected_vs_materialized_audit.csv", out)
    write_csv(out_dir / "scope_aware_aggregate_vs_materialized.csv", out)
    write_csv(out_dir / "aggregate_vs_materialized_recompute.csv", out)
    write_csv(ctx.run_root / "audit/scope_aware_aggregate_vs_materialized.csv", out)
    id_cols = ["candidate_definition_id", "parameter_vector_hash", "family_engine_id", "identity_key_pass"]
    write_csv(out_dir / "aggregate_materialized_identity_key_audit.csv", out[id_cols].drop_duplicates() if not out.empty else out)
    scope_cols = ["candidate_definition_id", "parameter_vector_hash", "materialization_scope", "symbol_count_materialized", "event_rows"]
    write_csv(out_dir / "materialization_scope_audit.csv", manifest[scope_cols] if not manifest.empty and set(scope_cols).issubset(manifest.columns) else manifest)
    write_text(out_dir / "scope_aware_aggregate_materialized_audit_policy.md", "# Scope-Aware Aggregate/Materialized Audit Policy\n\nAggregate/materialized checks compare like-for-like scopes only: `proposal_train_segment`, `internal_eval_train_segment`, and `full_train_diagnostic_only`. Raw and scaled R components are compared separately. Proposal-selected rows are never compared against an unrestricted full-train materialized ledger.\n")
    write_text(out_dir / "reproducibility_audit_report.md", f"# Reproducibility Audit\n\nRows checked: `{len(rows)}`\nFailures: `{len(failures)}`\nCompared aggregate metrics to regenerated materialized ledgers by identical candidate definition, parameter hash, and train-internal scope.\n")
    return out


def control_contract_field_audit(controls: pd.DataFrame) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    required = ["control_event_id", "control_symbol", "control_decision_ts", "matched_candidate_id", "matching_basis", "source_window_id", "feature_source_ts"]
    for col in required:
        missing = col not in controls.columns
        blank = 0 if missing or controls.empty else int((controls[col].isna() | controls[col].astype(str).str.strip().isin({"", "nan", "None"})).sum())
        rows.append({"check": f"required_field_{col}", "status": "fail" if missing or blank else "pass", "bad_rows": blank, "detail": "missing" if missing else "present"})
    if not controls.empty and "control_event_id" in controls.columns:
        dup = int(controls["control_event_id"].astype(str).duplicated().sum())
        rows.append({"check": "unique_control_event_id", "status": "fail" if dup else "pass", "bad_rows": dup, "detail": "global_control_event_id_uniqueness"})
    if {"control_symbol", "symbol"}.issubset(controls.columns):
        bad = int((controls["control_symbol"].astype(str) != controls["symbol"].astype(str)).sum())
        rows.append({"check": "control_symbol_alias_matches_symbol", "status": "fail" if bad else "pass", "bad_rows": bad, "detail": "alias_equality"})
    if {"control_decision_ts", "decision_ts"}.issubset(controls.columns):
        a = pd.to_datetime(controls["control_decision_ts"], utc=True, errors="coerce")
        b = pd.to_datetime(controls["decision_ts"], utc=True, errors="coerce")
        bad = int((a != b).sum())
        rows.append({"check": "control_decision_ts_alias_matches_decision_ts", "status": "fail" if bad else "pass", "bad_rows": bad, "detail": "alias_equality"})
    if {"feature_source_ts", "control_decision_ts"}.issubset(controls.columns):
        src = pd.to_datetime(controls["feature_source_ts"], utc=True, errors="coerce")
        dec = pd.to_datetime(controls["control_decision_ts"], utc=True, errors="coerce")
        bad = int((src.notna() & dec.notna() & (src > dec)).sum())
        rows.append({"check": "feature_source_ts_lte_control_decision_ts", "status": "fail" if bad else "pass", "bad_rows": bad, "detail": "pit_control_features"})
    if "self_match" in controls.columns:
        bad = int(parse_bool_series(controls["self_match"], default=True).sum())
        rows.append({"check": "no_self_match_leakage", "status": "fail" if bad else "pass", "bad_rows": bad, "detail": "control_event_not_candidate_event"})
    return pd.DataFrame(rows)


def ts_maybe(series_or_value: Any) -> pd.Series:
    return pd.to_datetime(series_or_value, utc=True, errors="coerce")


def theoretical_tsmom_event_max(candidate: Mapping[str, Any], symbol_count: int, decision_start: pd.Timestamp, decision_end: pd.Timestamp) -> int:
    if symbol_count <= 0 or pd.isna(decision_start) or pd.isna(decision_end) or decision_end <= decision_start:
        return 0
    cadence_bars = max(1, interval_bars_for_candidate(candidate, "scheduled_tsmom_engine"))
    cadence = pd.Timedelta(minutes=5 * cadence_bars)
    intervals = int(math.floor((ts_utc(decision_end) - ts_utc(decision_start)) / cadence)) + 1
    return max(0, intervals) * int(symbol_count)


def tsmom_event_count_theoretical_vs_actual(events: pd.DataFrame, definitions: pd.DataFrame, windows: pd.DataFrame | None = None) -> pd.DataFrame:
    if definitions.empty:
        return pd.DataFrame()
    rows: list[dict[str, Any]] = []
    ev = events.copy()
    if not ev.empty and "decision_ts" in ev.columns:
        ev["decision_ts"] = ts_maybe(ev["decision_ts"])
    for _, d in definitions.iterrows():
        cid = str(d.get("candidate_definition_id", d.get("candidate_id", d.get("definition_id", ""))))
        phash = str(d.get("parameter_vector_hash", ""))
        sub = ev[ev.get("candidate_definition_id", pd.Series(dtype=str)).astype(str).eq(cid)] if not ev.empty else pd.DataFrame()
        if phash and not sub.empty and "parameter_vector_hash" in sub.columns:
            sub = sub[sub["parameter_vector_hash"].astype(str).eq(phash)]
        symbol_count = int(sub["symbol"].nunique()) if "symbol" in sub.columns and not sub.empty else int(safe_float(d.get("expected_symbol_count", 0), 0))
        if symbol_count <= 0 and isinstance(d.get("selected_symbol_universe", ""), str):
            symbol_count = len([s for s in str(d.get("selected_symbol_universe")).split(";") if s])
        if windows is not None and not windows.empty:
            window_iter = windows.iterrows()
        else:
            start = sub["decision_ts"].min() if not sub.empty and "decision_ts" in sub.columns else pd.NaT
            end = sub["decision_ts"].max() if not sub.empty and "decision_ts" in sub.columns else pd.NaT
            window_iter = [(0, {"window_label": "observed_materialized_span", "decision_start": start, "decision_end": end})]
        for _, w in window_iter:
            ds = ts_utc(w.get("decision_start")) if pd.notna(w.get("decision_start")) else pd.NaT
            de = ts_utc(w.get("decision_end")) if pd.notna(w.get("decision_end")) else pd.NaT
            scope = sub
            if not scope.empty and pd.notna(ds) and pd.notna(de):
                scope = scope[(scope["decision_ts"] >= ds) & (scope["decision_ts"] <= de)]
            actual = int(len(scope))
            theoretical = theoretical_tsmom_event_max(d, max(symbol_count, int(scope["symbol"].nunique()) if "symbol" in scope.columns and not scope.empty else 0), ds, de) if pd.notna(ds) and pd.notna(de) else actual
            cadence_bars = max(1, interval_bars_for_candidate(d, "scheduled_tsmom_engine"))
            min_spacing_min = np.nan
            max_decisions_per_symbol_day = 0
            if not scope.empty and {"symbol", "decision_ts"}.issubset(scope.columns):
                spacings = []
                for _, sg in scope.sort_values("decision_ts").groupby("symbol"):
                    diffs = sg["decision_ts"].diff().dropna().dt.total_seconds() / 60.0
                    spacings.extend(diffs.tolist())
                min_spacing_min = float(np.nanmin(spacings)) if spacings else np.nan
                tmp = scope.copy()
                tmp["day"] = tmp["decision_ts"].dt.strftime("%Y-%m-%d")
                max_decisions_per_symbol_day = int(tmp.groupby(["symbol", "day"]).size().max()) if len(tmp) else 0
            fires_every_5m = bool(math.isfinite(min_spacing_min) and min_spacing_min <= 5.0 and cadence_bars > 1)
            status = "fail" if actual > theoretical or fires_every_5m else "pass"
            rows.append({
                "candidate_definition_id": cid,
                "parameter_vector_hash": phash,
                "window_label": w.get("window_label", "window"),
                "decision_start": "" if pd.isna(ds) else str(ds),
                "decision_end": "" if pd.isna(de) else str(de),
                "symbol_count": int(symbol_count),
                "rebalance_cadence_bars": cadence_bars,
                "rebalance_cadence_minutes": cadence_bars * 5,
                "theoretical_max_events": int(theoretical),
                "actual_events": actual,
                "actual_exceeds_theoretical": bool(actual > theoretical),
                "min_decision_spacing_minutes": min_spacing_min,
                "max_decisions_per_symbol_day": max_decisions_per_symbol_day,
                "daily_8h_4h_fires_every_5m": fires_every_5m,
                "status": status,
            })
    return pd.DataFrame(rows)


def tsmom_overlap_audit_frame(events: pd.DataFrame) -> pd.DataFrame:
    if events.empty:
        return pd.DataFrame([{"status": "pass", "overlapping_interval_count": 0, "overlapping_exposure_accounting_cap": False}])
    ev = events.copy()
    ev["entry_ts"] = ts_maybe(ev.get("entry_ts", ev.get("decision_ts", pd.Series(dtype=str))))
    ev["exit_interval_end_ts"] = ts_maybe(ev.get("exit_interval_end_ts", ev.get("exit_ts", pd.Series(dtype=str))))
    rows: list[dict[str, Any]] = []
    for (cid, phash, sym), g in ev.sort_values("entry_ts").groupby(["candidate_definition_id", "parameter_vector_hash", "symbol"], dropna=False):
        overlaps = 0
        max_open = 0
        points: list[tuple[pd.Timestamp, int]] = []
        last_end = pd.NaT
        for _, r in g.iterrows():
            start = r["entry_ts"]
            end = r["exit_interval_end_ts"]
            if pd.notna(start) and pd.notna(last_end) and start < last_end:
                overlaps += 1
            if pd.notna(end) and (pd.isna(last_end) or end > last_end):
                last_end = end
            if pd.notna(start):
                points.append((start, 1))
            if pd.notna(end):
                points.append((end, -1))
        open_count = 0
        for _, delta in sorted(points, key=lambda x: (x[0], x[1])):
            open_count += delta
            max_open = max(max_open, open_count)
        rows.append({
            "candidate_definition_id": cid,
            "parameter_vector_hash": phash,
            "symbol": sym,
            "rows": int(len(g)),
            "overlapping_interval_count": int(overlaps),
            "max_simultaneous_intervals": int(max_open),
            "overlapping_exposure_accounting_cap": bool(overlaps > 0 or max_open > 1),
            "status": "fail" if overlaps > 0 or max_open > 1 else "pass",
        })
    return pd.DataFrame(rows)


def event_row_binding_audit(events: pd.DataFrame, required: Sequence[str], audit_name: str) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    for col in required:
        missing = col not in events.columns
        blank = 0 if missing or events.empty else int(events[col].isna().sum() + events[col].astype(str).str.strip().isin({"", "nan", "None"}).sum())
        blank_allowed = col.endswith("missing_action") or col.endswith("label_cap_reason")
        rows.append({"audit": audit_name, "field": col, "missing": bool(missing), "blank_rows": int(blank), "blank_allowed_when_gate_passes": bool(blank_allowed), "rows": int(len(events)), "status": "fail" if missing or (blank and not blank_allowed) else "pass"})
    if {"feature_source_ts", "decision_ts"}.issubset(events.columns):
        src = ts_maybe(events["feature_source_ts"])
        dec = ts_maybe(events["decision_ts"])
        bad = int((src.notna() & dec.notna() & (src > dec)).sum())
        rows.append({"audit": audit_name, "field": "feature_source_ts_lte_decision_ts", "missing": False, "blank_rows": bad, "rows": int(len(events)), "status": "fail" if bad else "pass"})
    return pd.DataFrame(rows)


def funding_r_sanity_audit_frame(events: pd.DataFrame) -> pd.DataFrame:
    if events.empty:
        return pd.DataFrame([{"status": "pass", "rows": 0, "mean_abs_funding_R_per_event": 0.0, "hard_block": False}])
    ev = events.copy()
    funding = pd.to_numeric(ev.get("raw_funding_R", ev.get("funding_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
    gross = pd.to_numeric(ev.get("raw_gross_R", ev.get("gross_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0).abs()
    exact_count = pd.to_numeric(ev.get("funding_boundary_count_exact", pd.Series(0, index=ev.index)), errors="coerce").fillna(0)
    proxy_count = pd.to_numeric(ev.get("funding_boundary_count_proxy", pd.Series(0, index=ev.index)), errors="coerce").fillna(0)
    boundary_count = exact_count + proxy_count
    mean_abs = float(funding.abs().mean()) if len(funding) else 0.0
    ratio = float(funding.abs().sum() / max(1e-12, gross.sum())) if len(gross) else 0.0
    warning = mean_abs > 0.25
    hard = mean_abs > 1.0
    return pd.DataFrame([{
        "rows": int(len(ev)),
        "funding_boundary_count_total": int(boundary_count.sum()),
        "exact_boundary_count": int(exact_count.sum()),
        "proxy_boundary_count": int(proxy_count.sum()),
        "exact_share": float((exact_count > 0).mean()),
        "proxy_share": float((proxy_count > 0).mean()),
        "mean_abs_funding_R_per_event": mean_abs,
        "funding_R_abs_to_gross_R_abs_ratio": ratio,
        "warning_abs_mean_funding_R_gt_0_25R": bool(warning),
        "hard_block_abs_mean_funding_R_gt_1R": bool(hard),
        "status": "fail" if hard else "pass",
    }])


def write_run_level_tsmom_convenience_audits(ctx: Context, materialized_events: pd.DataFrame, definitions: pd.DataFrame) -> None:
    """Emit root-level audit files expected by redesigned canary review tooling."""
    count_audit = tsmom_event_count_theoretical_vs_actual(materialized_events, definitions)
    overlap = tsmom_overlap_audit_frame(materialized_events)
    funding_binding = event_row_binding_audit(
        materialized_events,
        ["funding_gate", "funding_gate_status", "funding_gate_pass", "funding_feature_source_ts", "funding_exact_available", "funding_missing_action", "funding_label_cap_reason"],
        "funding_gate_event_row_binding",
    )
    parent_binding = event_row_binding_audit(
        materialized_events,
        ["parent_regime_gate", "parent_gate_status", "parent_gate_pass", "parent_gate_feature_source_ts", "parent_btc_feature_source_ts", "parent_eth_feature_source_ts", "parent_gate_missing_action"],
        "parent_gate_event_row_binding",
    )
    vol_binding = event_row_binding_audit(
        materialized_events,
        ["vol_scale", "vol_target", "vol_target_status", "raw_net_R", "scaled_net_R", "raw_gross_R", "scaled_gross_R", "raw_fee_R", "scaled_fee_R", "raw_funding_R", "scaled_funding_R"],
        "vol_target_event_row_binding",
    )
    funding_sanity = funding_r_sanity_audit_frame(materialized_events)
    if not materialized_events.empty:
        boundary_cols = [c for c in ["candidate_definition_id", "parameter_vector_hash", "symbol", "event_id", "funding_boundary_count_exact", "funding_boundary_count_proxy", "funding_schedule_source", "raw_funding_R", "funding_R"] if c in materialized_events.columns]
        boundary = materialized_events[boundary_cols].copy() if boundary_cols else pd.DataFrame()
    else:
        boundary = pd.DataFrame()
    write_csv(ctx.run_root / "semantics/tsmom_event_count_sanity_audit.csv", count_audit)
    write_csv(ctx.run_root / "semantics/tsmom_event_count_theoretical_vs_actual.csv", count_audit)
    write_csv(ctx.run_root / "semantics/tsmom_overlap_audit.csv", overlap)
    write_csv(ctx.run_root / "funding/funding_gate_event_row_binding_audit.csv", funding_binding)
    write_csv(ctx.run_root / "regime/parent_gate_event_row_binding_audit.csv", parent_binding)
    write_csv(ctx.run_root / "sizing/vol_target_event_row_binding_audit.csv", vol_binding)
    write_csv(ctx.run_root / "funding/funding_r_sanity_audit.csv", funding_sanity)
    write_csv(ctx.run_root / "funding/funding_boundary_count_audit.csv", boundary)
    write_text(ctx.run_root / "audit/run_level_convenience_audit_output_report.md", "\n".join([
        "# Run-Level Convenience Audit Output Report",
        "",
        "Root-level convenience audit files were emitted from the materialized selected/audit ledgers for redesigned TSMOM canary review.",
        "These copies do not change gate logic and do not create strategy evidence.",
        "",
        f"Materialized event rows audited: `{len(materialized_events)}`",
        f"Definitions/audit manifest rows: `{len(definitions)}`",
    ]) + "\n")


def build_wave_controls(ctx: Context, manifest: pd.DataFrame, out_dir: Path) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    controls_parts: list[pd.DataFrame] = []
    summary_parts: list[pd.DataFrame] = []
    zero_rows: list[dict[str, Any]] = []
    leakage_rows: list[dict[str, Any]] = []
    cap_rows: list[dict[str, Any]] = []
    diagnostic_mode = str(getattr(ctx.args, "control_mode", "evidence")) == "diagnostic" or is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", ""))
    diagnostic_max_candidates = int(getattr(ctx.args, "control_diagnostic_max_candidates", 0) or 0)
    diagnostic_max_controls = int(getattr(ctx.args, "control_diagnostic_max_controls_per_candidate", 0) or 0)
    diagnostic_timeout = int(getattr(ctx.args, "control_diagnostic_timeout_sec", 0) or 0)
    deadline = time.monotonic() + diagnostic_timeout if diagnostic_mode and diagnostic_timeout > 0 else None
    diagnostic_audit_rows: list[dict[str, Any]] = []
    manifest_iter = manifest.copy()
    if diagnostic_mode and diagnostic_max_candidates > 0:
        manifest_iter = manifest_iter.head(diagnostic_max_candidates).copy()
    skipped_by_diagnostic_candidate_limit = max(0, len(manifest) - len(manifest_iter)) if diagnostic_mode else 0
    for _, m in manifest_iter.iterrows():
        p = ctx.run_root / str(m["path"])
        ledger = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        if ledger.empty:
            zero_rows.append({"candidate_id": m.get("candidate_id"), "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id")), "controls_row_count": 0, "zero_control_reason": "no_candidate_events", "zero_control_status": "candidate_level_cap"})
            continue
        engine = ENGINES.get(str(m.get("family_engine_id", ledger["family_engine_id"].iloc[0] if "family_engine_id" in ledger.columns else "")), ScheduledTsmomEngine())
        controls_for_manifest: list[pd.DataFrame] = []
        summary_for_manifest: list[pd.DataFrame] = []
        zero_reasons: list[str] = []
        diag_for_manifest: list[dict[str, Any]] = []
        retained_for_candidate = 0
        for sym, sym_ledger in ledger.groupby("symbol", sort=False):
            if diagnostic_mode and diagnostic_max_controls > 0 and retained_for_candidate >= diagnostic_max_controls:
                break
            cdict = identity_enriched_record(m.to_dict(), engine, symbol=str(sym))
            cdict["symbol"] = str(sym)
            cdict["materialization_scope"] = m.get("materialization_scope", "definition_universe")
            bars = load_symbol_bars(paths, str(sym), ctx.start, ctx.end)
            funding = load_funding(paths, str(sym), ctx.end)
            remaining = max(0, diagnostic_max_controls - retained_for_candidate) if diagnostic_mode and diagnostic_max_controls > 0 else None
            controls, summary, diag = build_real_null_controls(
                cdict,
                engine,
                bars,
                funding,
                sym_ledger,
                nulls_per_event=ctx.args.nulls_per_event,
                retention_limit=remaining,
                diagnostic_fast_limit=remaining if diagnostic_mode and remaining else None,
                deadline_monotonic=deadline,
            )
            if diagnostic_mode and not controls.empty:
                controls = controls.copy()
                controls["control_mode"] = "diagnostic"
                controls["control_evidence_label"] = "control_diagnostic_only_not_evidence"
            retained_for_candidate += int(len(controls))
            diag_for_manifest.append(diag)
            if not controls.empty:
                controls_for_manifest.append(controls)
                controls_parts.append(controls)
            if not summary.empty:
                if diagnostic_mode:
                    summary = summary.copy()
                    summary["control_mode"] = "diagnostic"
                    summary["control_evidence_label"] = "control_diagnostic_only_not_evidence"
                    summary["final_evidence_eligible_by_control_cap"] = False
                summary_for_manifest.append(summary)
                summary_parts.append(summary)
            if diag.get("zero_control_reason", ""):
                zero_reasons.append(str(diag.get("zero_control_reason")))
        manifest_controls = pd.concat(controls_for_manifest, ignore_index=True) if controls_for_manifest else pd.DataFrame()
        manifest_summary = pd.concat(summary_for_manifest, ignore_index=True) if summary_for_manifest else pd.DataFrame()
        z_reason = ";".join(sorted(set(zero_reasons)))
        zero_rows.append({"candidate_id": m.get("candidate_id"), "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id")), "controls_row_count": len(manifest_controls), "zero_control_reason": z_reason, "zero_control_status": "candidate_level_cap" if z_reason and manifest_controls.empty else "ok_nonzero"})
        self_matches = int(parse_bool_series(manifest_controls.get("self_match", pd.Series(dtype=bool)), default=True).sum()) if not manifest_controls.empty else 0
        leakage_rows.append({"candidate_id": m.get("candidate_id"), "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id")), "control_rows": len(manifest_controls), "self_match_rows": self_matches, "status": "pass" if self_matches == 0 else "fail"})
        total_available = int(sum(int(d.get("total_matched_controls_available", 0) or 0) for d in diag_for_manifest))
        total_raw = int(sum(int(d.get("total_raw_null_opportunities", d.get("total_matched_controls_available", 0)) or 0) for d in diag_for_manifest))
        eligible_after_purge = int(sum(int(d.get("eligible_after_purge_embargo", 0) or 0) for d in diag_for_manifest))
        eligible_after_purge_lower_bound = int(sum(int(d.get("eligible_after_purge_embargo_lower_bound", d.get("eligible_after_purge_embargo", 0)) or 0) for d in diag_for_manifest))
        removed_cap = int(sum(int(d.get("controls_removed_by_cap", 0) or 0) for d in diag_for_manifest))
        removed_cap_lower_bound = int(sum(int(d.get("controls_removed_by_cap_lower_bound", d.get("controls_removed_by_cap", 0)) or 0) for d in diag_for_manifest))
        removed_purge = int(sum(int(d.get("controls_removed_by_interval_purge", 0) or 0) for d in diag_for_manifest))
        removed_embargo = int(sum(int(d.get("controls_removed_by_embargo", 0) or 0) for d in diag_for_manifest))
        full_purge_counts_complete = bool(all(parse_bool_value(d.get("full_purge_counts_complete", True), default=False) for d in diag_for_manifest)) if diag_for_manifest else False
        diagnostic_partial = bool(any(parse_bool_value(d.get("diagnostic_partial_purge", False), default=False) or parse_bool_value(d.get("diagnostic_timeout_hit", False), default=False) for d in diag_for_manifest))
        cap_applied = bool(removed_cap > 0 or diagnostic_partial)
        if diagnostic_partial:
            cap_method = "diagnostic_partial_retention_after_purge"
            cap_scope = "diagnostic_only_not_evidence"
        elif cap_applied:
            cap_method = "deterministic_time_stratified_even_spacing"
            cap_scope = "benchmark_only_until_predeclared_for_evidence"
        else:
            cap_method = "all_controls"
            cap_scope = "diagnostic_only_not_evidence" if diagnostic_mode else "evidence_eligible_all_controls"
        cap_rows.append({
            "candidate_id": m.get("candidate_id"),
            "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id")),
            "total_raw_null_opportunities": total_raw,
            "total_matched_controls_available": total_available,
            "total_matched_controls_before_cap": total_available,
            "removed_by_interval_overlap": removed_purge,
            "removed_by_embargo": removed_embargo,
            "eligible_after_purge_embargo": eligible_after_purge,
            "eligible_after_purge_embargo_lower_bound": eligible_after_purge_lower_bound,
            "full_purge_counts_complete": full_purge_counts_complete,
            "controls_retained": int(len(manifest_controls)),
            "controls_removed_by_interval_purge": removed_purge,
            "controls_removed_by_embargo": removed_embargo,
            "controls_removed_by_cap": removed_cap,
            "controls_removed_by_cap_lower_bound": removed_cap_lower_bound,
            "retained_after_cap": int(len(manifest_controls)),
            "cap_applied": cap_applied,
            "cap_method": cap_method,
            "cap_seed": ctx.args.seed if cap_applied else "",
            "random_seed": ctx.args.seed,
            "stratification_basis": "time_order_even_spacing;row_semantics;symbol" if (cap_applied or diagnostic_mode) else "not_applicable",
            "cap_scope": cap_scope,
            "final_evidence_eligible": bool(total_available > 0 and not cap_applied and not diagnostic_mode and full_purge_counts_complete),
            "cap_evidence_eligible": bool(total_available > 0 and not cap_applied and not diagnostic_mode and full_purge_counts_complete),
            "control_mode": "diagnostic" if diagnostic_mode else "evidence",
            "diagnostic_only_not_evidence": bool(diagnostic_mode),
            "diagnostic_retention_partial": bool(diagnostic_partial),
            "diagnostic_timeout_hit": bool(any(parse_bool_value(d.get("diagnostic_timeout_hit", False), default=False) for d in diag_for_manifest)),
            "diagnostic_candidate_limit": diagnostic_max_candidates if diagnostic_mode else "",
            "diagnostic_controls_per_candidate_limit": diagnostic_max_controls if diagnostic_mode else "",
            "diagnostic_timeout_sec": diagnostic_timeout if diagnostic_mode else "",
        })
        diagnostic_audit_rows.append({
            "candidate_id": m.get("candidate_id"),
            "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id")),
            "control_mode": "diagnostic" if diagnostic_mode else "evidence",
            "diagnostic_only_not_evidence": bool(diagnostic_mode),
            "controls_retained": int(len(manifest_controls)),
            "candidate_limit_applied": bool(diagnostic_mode and diagnostic_max_candidates > 0),
            "controls_per_candidate_limit": diagnostic_max_controls if diagnostic_mode else "",
            "timeout_sec": diagnostic_timeout if diagnostic_mode else "",
            "full_purge_counts_complete": full_purge_counts_complete,
            "eligible_after_purge_embargo_lower_bound": eligible_after_purge_lower_bound,
            "diagnostic_retention_partial": bool(diagnostic_partial),
            "purge_before_retention": True,
            "required_schema_preserved": True,
        })
    controls_df = pd.concat(controls_parts, ignore_index=True) if controls_parts else pd.DataFrame()
    summary_df = pd.concat(summary_parts, ignore_index=True) if summary_parts else pd.DataFrame()
    ledger_dir = out_dir / "control_ledger"
    ledger_dir.mkdir(parents=True, exist_ok=True)
    if not controls_df.empty:
        controls_df.to_parquet(ledger_dir / "control_ledger.parquet", index=False, compression="zstd")
    write_csv(out_dir / "control_summary.csv", summary_df)
    write_csv(out_dir / "control_zero_row_diagnostics.csv", zero_rows)
    write_csv(out_dir / "control_self_match_leakage_audit.csv", leakage_rows)
    write_csv(out_dir / "control_cap_diagnostics.csv", cap_rows)
    write_csv(out_dir / "diagnostic_control_accounting_audit.csv", cap_rows)
    if skipped_by_diagnostic_candidate_limit:
        diagnostic_audit_rows.append({
            "candidate_id": "__skipped_by_diagnostic_candidate_limit__",
            "candidate_definition_id": "__skipped_by_diagnostic_candidate_limit__",
            "control_mode": "diagnostic",
            "diagnostic_only_not_evidence": True,
            "controls_retained": 0,
            "candidate_limit_applied": True,
            "skipped_candidates": int(skipped_by_diagnostic_candidate_limit),
            "purge_before_retention": True,
            "required_schema_preserved": True,
        })
    write_csv(out_dir / "control_diagnostic_mode_audit.csv", diagnostic_audit_rows)
    write_text(out_dir / "control_retention_policy_report.md", "\n".join([
        "# Control Retention Policy",
        "",
        "Evidence-mode controls retain all controls produced by the real-null matcher unless a future run predeclares deterministic stratified retention.",
        "Diagnostic-mode controls are bounded by explicit diagnostic CLI limits, purge/embargo before retention, and are labeled `control_diagnostic_only_not_evidence`.",
        "No pseudo-controls or other candidate ledgers are used as controls.",
        f"Control mode: `{getattr(ctx.args, 'control_mode', 'evidence')}`",
    ]) + "\n")
    result = validate_control_rows(controls_df, allow_empty=True)
    field_audit = control_contract_field_audit(controls_df)
    write_csv(out_dir / "control_contract_field_audit.csv", field_audit)
    hard_fail = result.status != "pass" or (not field_audit.empty and bool(field_audit["status"].astype(str).eq("fail").any()))
    write_text(out_dir / "control_audit_report.md", f"# Control Audit\n\nStatus: `{'fail' if hard_fail else 'pass'}`\nEvidence contract status: `{result.status}`\nViolations: `{result.violations}`\nControls are real row-semantics-matched nulls and materialized-only.\n")
    write_text(out_dir / "control_schema_repair_report.md", "# Control Schema Repair Report\n\nRequired evidence-contract aliases are written while preserving original event fields (`event_id`, `symbol`, `decision_ts`).\n")
    return controls_df, summary_df, pd.DataFrame(zero_rows), pd.DataFrame(leakage_rows)

def run_wave_stress_context_stability(ctx: Context, manifest: pd.DataFrame, wave_dirs: Mapping[str, Path]) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    stress_rows: list[pd.DataFrame] = []
    fee_rows: list[dict[str, Any]] = []
    context_rows: list[dict[str, Any]] = []
    stability_rows: list[dict[str, Any]] = []
    concentration_rows: list[dict[str, Any]] = []
    loso_rows: list[dict[str, Any]] = []
    lomo_rows: list[dict[str, Any]] = []
    for _, m in manifest.iterrows():
        p = ctx.run_root / str(m["path"])
        if not p.exists():
            continue
        ev = pd.read_parquet(p)
        if ev.empty:
            continue
        ev = ev.copy()
        ev["decision_ts"] = pd.to_datetime(ev["decision_ts"], utc=True, errors="coerce")
        ev["month"] = ev["decision_ts"].dt.strftime("%Y-%m")
        engine = ENGINES.get(str(ev["family_engine_id"].iloc[0]), ScheduledTsmomEngine())
        stress = engine.run_family_specific_stress(ev)
        if not stress.empty:
            stress["candidate_id"] = m["candidate_id"]
            stress_rows.append(stress)
        net = pd.to_numeric(ev["net_R"], errors="coerce").fillna(0)
        fee_base = pd.to_numeric(ev.get("fees_R", pd.Series(index=ev.index, dtype=float)), errors="coerce").fillna(0)
        for scenario in ENGINE_WAVE_FEE_SCENARIOS:
            if scenario["fee_scenario"] == "kraken_current_account_zero_fee":
                fee_adj = -float(fee_base.sum())
            elif scenario["fee_scenario"] == "fee_reversion_partial":
                fee_adj = -float(fee_base.sum()) * 0.5
            elif scenario["fee_scenario"] == "slippage_only_zero_fee":
                fee_adj = -float(fee_base.sum())
            else:
                fee_adj = 0.0
            fee_rows.append({**scenario, "candidate_id": m["candidate_id"], "events": len(ev), "net_R_after_fee_scenario": float(net.sum() + fee_adj), "slippage_spread_funding_mark_lifecycle_stress_still_required": True})
        dom_symbol = float(ev["symbol"].value_counts(normalize=True).iloc[0]) if "symbol" in ev.columns and len(ev) else np.nan
        dom_month = float(ev["month"].value_counts(normalize=True).iloc[0]) if len(ev) else np.nan
        dom_regime = float(ev.get("regime_label", pd.Series(["unknown"] * len(ev))).astype(str).value_counts(normalize=True).iloc[0]) if len(ev) else np.nan
        concentration_rows.append({"candidate_id": m["candidate_id"], "active_symbols": int(ev["symbol"].nunique()), "active_months": int(ev["month"].nunique()), "dominant_symbol_share": dom_symbol, "dominant_month_share": dom_month, "dominant_regime_share": dom_regime, "tier_a_b_c_contribution": "not_available_in_current_panel", "top_1pct_winner_removed_net_R": float(net[net < net.quantile(0.99)].sum()) if len(net) >= 100 else np.nan, "top_5pct_winner_removed_net_R": float(net[net < net.quantile(0.95)].sum()) if len(net) >= 20 else np.nan})
        for sym, g in ev.groupby("symbol"):
            loso_rows.append({"candidate_id": m["candidate_id"], "removed_symbol": sym, "remaining_net_R": float(pd.to_numeric(ev[ev["symbol"] != sym]["net_R"], errors="coerce").sum()), "removed_event_count": len(g)})
        for month, g in ev.groupby("month"):
            lomo_rows.append({"candidate_id": m["candidate_id"], "removed_month": month, "remaining_net_R": float(pd.to_numeric(ev[ev["month"] != month]["net_R"], errors="coerce").sum()), "removed_event_count": len(g)})
        context_rows.append({"candidate_id": m["candidate_id"], "inside_regime_net_R": float(net.sum()), "outside_regime_net_R": "not_applicable_current_wave", "active_months": int(ev["month"].nunique()), "dominant_month_share": dom_month})
        dev = ev[ev["decision_ts"] < DEV_EVAL_SPLIT]
        internal = ev[ev["decision_ts"] >= DEV_EVAL_SPLIT]
        stability_rows.append({
            "candidate_id": m["candidate_id"],
            "dev_events": len(dev),
            "internal_eval_events": len(internal),
            "dev_net_R": float(pd.to_numeric(dev.get("net_R", pd.Series(dtype=float)), errors="coerce").sum()),
            "internal_eval_net_R": float(pd.to_numeric(internal.get("net_R", pd.Series(dtype=float)), errors="coerce").sum()),
            "evidence_level": "level_4_control_tested_train_only_pending_stability" if len(dev) and len(internal) else "level_3_materialized_pending_controls",
            "stability_artifact_basis": "train_internal_split_only_not_wf_cpcv",
            "wf_cpcv_neighborhood_pass": False,
        })
    stress_df = pd.concat(stress_rows, ignore_index=True) if stress_rows else pd.DataFrame()
    write_csv(wave_dirs["stress"] / "stress_summary.csv", stress_df)
    write_csv(wave_dirs["stress"] / "fee_scenario_stress_summary.csv", fee_rows)
    write_csv(wave_dirs["context"] / "context_summary.csv", context_rows)
    write_csv(wave_dirs["validation"] / "stability_summary.csv", stability_rows)
    write_csv(wave_dirs["concentration"] / "concentration_summary.csv", concentration_rows)
    write_csv(wave_dirs["concentration"] / "leave_one_symbol_out.csv", loso_rows)
    write_csv(wave_dirs["concentration"] / "leave_one_month_out.csv", lomo_rows)
    return stress_df, pd.DataFrame(context_rows), pd.DataFrame(stability_rows), pd.DataFrame(concentration_rows)


def collect_wave_evidence_cap_audit(
    ctx: Context,
    wave_dirs: Mapping[str, Path],
    manifest: pd.DataFrame,
    selected: pd.DataFrame,
    control_summary: pd.DataFrame,
    stability: pd.DataFrame,
) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    mechanics_dir = wave_dirs["root"] / "mechanics"
    mechanics_dir.mkdir(parents=True, exist_ok=True)
    control_cap = read_csv_safe(wave_dirs["controls"] / "control_cap_diagnostics.csv")
    interval_purge = read_csv_safe(wave_dirs["controls"] / "interval_overlap_purge_audit.csv")
    selected_caps = {}
    if not selected.empty:
        for _, r in selected.iterrows():
            selected_caps[str(r.get("candidate_definition_id", r.get("candidate_id")))] = str(r.get("evidence_cap_reason", ""))
    control_ids = set(control_summary.get("candidate_id", pd.Series(dtype=str)).astype(str)) if not control_summary.empty else set()
    stability_ids = set(stability.get("candidate_id", pd.Series(dtype=str)).astype(str)) if not stability.empty else set()
    for _, m in manifest.iterrows():
        cid = str(m.get("candidate_definition_id", m.get("candidate_id")))
        reasons: set[str] = set()
        p = ctx.run_root / str(m.get("path", ""))
        ev = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        if ev.empty:
            reasons.add("missing_materialized_event_ledger")
        else:
            if any_true(ev.get("funding_proxy_used", pd.Series(dtype=bool)), default=False):
                reasons.add("funding_proxy_cap")
            funding_label = ev.get("funding_label_cap_reason", pd.Series(dtype=str)).astype(str)
            if bool(funding_label.str.strip().replace({"nan": "", "None": "", "none": ""}).ne("").any()):
                reasons.add("funding_proxy_selection_cap")
            slippage = pd.to_numeric(ev.get("slippage_R", pd.Series(index=ev.index, dtype=float)), errors="coerce")
            if len(slippage) and bool(slippage.fillna(0.0).eq(0.0).all()):
                reasons.add("base_no_slippage_event_ledger_requires_stress")
            if any_true(ev.get("mark_proxy_used", pd.Series(dtype=bool)), default=False):
                reasons.add("mark_missing_or_incomplete")
            if any_true(ev.get("same_bar_ambiguity_flag", pd.Series(dtype=bool)), default=False):
                reasons.add("same_bar_ambiguity_cap")
            index_source = ev.get("index_price_source", pd.Series(dtype=str)).astype(str)
            if bool(index_source.eq("unavailable").any()):
                reasons.add("mark_liquidation_diagnostic_only_cap")
            mark_liq = ev.get("mark_liquidation_flag", pd.Series(dtype=bool))
            if len(mark_liq) and not all_true(mark_liq, default=False):
                reasons.add("mark_liquidation_diagnostic_only_cap")
            label_cap = ";".join(ev.get("label_cap_reason", pd.Series(dtype=str)).dropna().astype(str).tolist())
            if "kraken_survivorship_lifecycle_cap" in label_cap:
                reasons.add("kraken_survivorship_lifecycle_cap")
            if "mark_missing_or_incomplete" in label_cap:
                reasons.add("mark_missing_or_incomplete")
            if "funding_missing_adverse_proxy" in label_cap:
                reasons.add("funding_proxy_cap")
        key_col = "candidate_definition_id" if "candidate_definition_id" in control_cap.columns else "candidate_id"
        ccap = control_cap[control_cap.get(key_col, pd.Series(dtype=str)).astype(str).eq(cid)] if not control_cap.empty else pd.DataFrame()
        if not ccap.empty:
            if any_true(ccap.get("cap_applied", pd.Series(dtype=bool)), default=True) and not all_true(ccap.get("final_evidence_eligible", pd.Series([False])), default=False):
                reasons.add("control_cap_benchmark_only_or_not_evidence_eligible")
            if any_true(ccap.get("diagnostic_only_not_evidence", pd.Series(dtype=bool)), default=False):
                reasons.add("control_diagnostic_only_not_evidence")
        elif cid in control_ids:
            reasons.add("control_cap_reporting_incomplete")
        csum = control_summary[control_summary.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(cid)] if not control_summary.empty else pd.DataFrame()
        if not csum.empty and bool(csum.get("control_evidence_label", pd.Series(dtype=str)).astype(str).eq("control_diagnostic_only_not_evidence").any()):
            reasons.add("control_diagnostic_only_not_evidence")
        purge = interval_purge[interval_purge.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(cid)] if not interval_purge.empty else pd.DataFrame()
        if not purge.empty and bool(purge.get("purge_status", pd.Series(dtype=str)).astype(str).eq("fail").any()):
            reasons.add("interval_overlap_purge_failed")
        if selected_caps.get(cid):
            reasons.add(selected_caps[cid])
        manifest_cap = str(m.get("evidence_cap_reason", "") or "").strip()
        if manifest_cap and manifest_cap.lower() not in {"nan", "none"}:
            reasons.add(manifest_cap)
        if cid in control_ids:
            stab = stability[stability.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(cid)] if not stability.empty else pd.DataFrame()
            if stab.empty or not any_true(stab.get("wf_cpcv_neighborhood_pass", pd.Series([False])), default=False):
                reasons.add("parameter_neighborhood_or_fold_support_missing")
        requested = "level_4_event_ledger_plus_real_controls" if cid in control_ids else "level_3_event_level_trade_ledger"
        mechanics_cap_active = bool(reasons)
        if mechanics_cap_active and cid in control_ids:
            evidence_level_contract = "level_4_event_ledger_plus_real_controls__mechanics_capped"
            candidate_status = "control_tested_but_mechanics_capped_pending_replay"
        elif mechanics_cap_active:
            evidence_level_contract = "level_3_event_level_trade_ledger_capped"
            candidate_status = "materialized_mechanics_capped_pending_replay"
        elif cid in control_ids:
            evidence_level_contract = requested
            candidate_status = "train_only_candidate_pending_validation"
        else:
            evidence_level_contract = requested
            candidate_status = "materialized_pending_controls"
        rows.append({
            "candidate_id": cid,
            "candidate_definition_id": cid,
            "requested_evidence_level": requested,
            "evidence_level_contract": evidence_level_contract,
            "clean_evidence_allowed": not mechanics_cap_active,
            "mechanics_cap_active": mechanics_cap_active,
            "label_cap_reason": ";".join(sorted(r for r in reasons if r)),
            "candidate_status": candidate_status,
        })
    audit = pd.DataFrame(rows)
    write_csv(mechanics_dir / "evidence_cap_application_audit.csv", audit)
    write_csv(ctx.run_root / "mechanics/evidence_cap_application_audit.csv", audit)
    return audit



CURRENT_STATE_PRECEDENCE = {
    "blocked_by_wave_component_issue": 100,
    "train_only_candidate_pending_validation": 90,
    "control_tested_but_mechanics_capped_pending_replay": 80,
    "materialized_mechanics_capped_pending_replay": 70,
    "materialized_pending_controls": 60,
    "sample_limited_pending_controls": 55,
    "near_miss_preserved": 40,
    "pending_compute": 20,
    "candidate_library_only": 10,
}


def deduplicate_candidate_library_current_state(rows: Sequence[Mapping[str, Any]]) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    history = pd.DataFrame(list(rows))
    if history.empty:
        audit = pd.DataFrame([{"check": "candidate_library_current_state_unique", "status": "pass", "duplicate_current_rows": 0, "history_rows": 0}])
        return history.copy(), history.copy(), audit
    for col in ["candidate_definition_id", "parameter_vector_hash", "candidate_library_state"]:
        if col not in history.columns:
            history[col] = ""
    history["_state_precedence"] = history["candidate_library_state"].astype(str).map(CURRENT_STATE_PRECEDENCE).fillna(0).astype(int)
    history["_history_sequence"] = np.arange(len(history))
    key_cols = ["candidate_definition_id", "parameter_vector_hash"]
    history["status_history_key"] = history[key_cols].astype(str).agg("::".join, axis=1)
    current = history.sort_values(["_state_precedence", "_history_sequence"], ascending=[False, True]).drop_duplicates(key_cols, keep="first").copy()
    duplicates_before = int(history.duplicated(key_cols, keep=False).sum())
    duplicates_after = int(current.duplicated(key_cols, keep=False).sum())
    audit = pd.DataFrame([{
        "check": "candidate_library_current_state_unique",
        "status": "fail" if duplicates_after else "pass",
        "duplicate_input_rows": duplicates_before,
        "duplicate_current_rows": duplicates_after,
        "history_rows": int(len(history)),
        "current_rows": int(len(current)),
        "action": "current_state_collapsed_by_candidate_definition_id_and_parameter_vector_hash",
    }])
    current = current.drop(columns=["_state_precedence", "_history_sequence"], errors="ignore")
    history = history.drop(columns=["_state_precedence", "_history_sequence"], errors="ignore")
    return current, history, audit


def positive_evidence_gate_for_candidate(
    *,
    cid: str,
    hard_gate_pass: bool,
    cap_row: Mapping[str, Any] | None,
    control_cap: pd.DataFrame,
    control_summary: pd.DataFrame,
    gate: Mapping[str, Any],
) -> tuple[bool, list[str]]:
    reasons: list[str] = []
    if not hard_gate_pass:
        reasons.append("wave_hard_gate_not_passed")
    if not cap_row:
        reasons.append("missing_mechanics_cap_audit")
    else:
        if not parse_bool_value(cap_row.get("clean_evidence_allowed", False), default=False):
            reasons.append("mechanics_or_label_cap_active")
        if parse_bool_value(cap_row.get("mechanics_cap_active", True), default=True):
            reasons.append("mechanics_cap_active")
        cap_reason = str(cap_row.get("label_cap_reason", "")).strip()
        if cap_reason:
            reasons.append(cap_reason)
    if parse_bool_value(gate.get("diagnostic_controls_not_evidence", False), default=False):
        reasons.append("diagnostic_controls_not_evidence")
    cand_cap = control_cap[control_cap.get("candidate_definition_id", pd.Series(dtype=str)).astype(str).eq(str(cid))] if not control_cap.empty else pd.DataFrame()
    if cand_cap.empty:
        reasons.append("missing_control_cap_diagnostics")
    else:
        final_eligible = parse_bool_series(cand_cap.get("final_evidence_eligible", pd.Series(False, index=cand_cap.index)), default=False)
        cap_evidence = parse_bool_series(cand_cap.get("cap_evidence_eligible", pd.Series(False, index=cand_cap.index)), default=False)
        if not bool(final_eligible.all() and cap_evidence.all()):
            reasons.append("control_cap_not_final_evidence_eligible")
        if parse_bool_series(cand_cap.get("diagnostic_only_not_evidence", pd.Series(False, index=cand_cap.index)), default=False).any():
            reasons.append("control_diagnostic_only_not_evidence")
        if not parse_bool_series(cand_cap.get("full_purge_counts_complete", pd.Series(True, index=cand_cap.index)), default=False).all():
            reasons.append("control_purge_counts_partial")
    cand_control = control_summary[control_summary.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(str(cid))] if not control_summary.empty else pd.DataFrame()
    if cand_control.empty:
        reasons.append("missing_control_summary")
    elif cand_control.astype(str).apply(lambda c: c.str.contains("control_diagnostic_only_not_evidence", case=False, regex=False)).any().any():
        reasons.append("diagnostic_control_summary_not_evidence")
    clean = not reasons
    return clean, sorted(set(r for r in reasons if r))


def write_wave_analysis_ready(ctx: Context, engine_wave_id: str, wave_dirs: Mapping[str, Path], aggregate: pd.DataFrame, selected: pd.DataFrame, near: pd.DataFrame, manifest: pd.DataFrame, control_summary: pd.DataFrame, stress: pd.DataFrame, context: pd.DataFrame, stability: pd.DataFrame, zero_diag: pd.DataFrame, gate: Mapping[str, Any]) -> None:
    analysis = wave_dirs["analysis"]
    analysis.mkdir(parents=True, exist_ok=True)
    write_csv(analysis / "aggregate_summary.csv", aggregate.head(5000))
    write_csv(analysis / "selected_materialized_summary.csv", selected)
    write_csv(analysis / "control_summary.csv", control_summary)
    merged_stress = pd.concat([stress.assign(summary_type="stress") if not stress.empty else pd.DataFrame(), context.assign(summary_type="context") if not context.empty else pd.DataFrame(), stability.assign(summary_type="stability") if not stability.empty else pd.DataFrame()], ignore_index=True, sort=False)
    write_csv(analysis / "stress_context_stability_summary.csv", merged_stress)
    write_csv(analysis / "near_miss_summary.csv", near)
    scope_summary = []
    if not manifest.empty:
        for _, r in manifest.iterrows():
            scope = str(r.get("materialization_scope", "definition_universe"))
            scope_summary.append({
                "candidate_id": r.get("candidate_id"),
                "candidate_definition_id": r.get("candidate_definition_id", r.get("candidate_id")),
                "parameter_vector_hash": r.get("parameter_vector_hash", ""),
                "materialization_scope": scope,
                "strategy_candidate_scope": "candidate_symbol_diagnostic_only" if scope == "single_symbol_diagnostic_only" else "definition_level_universe_wide_candidate",
                "symbol_count_materialized": r.get("symbol_count_materialized", 0),
                "event_rows": r.get("event_rows", 0),
                "can_be_treated_as_strategy_candidate": scope == "definition_universe",
            })
    write_csv(analysis / "materialization_scope_summary.csv", scope_summary)
    hard_gate_pass = str(gate.get("wave_gate_status", "")) == "pass"
    library_rows = []
    selected_ids = set(selected.get("candidate_definition_id", selected.get("candidate_id", pd.Series(dtype=str))).astype(str)) if not selected.empty else set()
    control_ids = set(control_summary.get("candidate_id", pd.Series(dtype=str)).astype(str)) if not control_summary.empty else set()
    zero_ids = set(zero_diag[zero_diag.get("zero_control_status", pd.Series(dtype=str)).astype(str).eq("candidate_level_cap")].get("candidate_id", pd.Series(dtype=str)).astype(str)) if not zero_diag.empty else set()
    selected_caps = {}
    if not selected.empty:
        for _, r in selected.iterrows():
            selected_caps[str(r.get("candidate_definition_id", r.get("candidate_id")))] = str(r.get("evidence_cap_reason", ""))
    wave_root = wave_dirs.get("root", analysis.parent)
    cap_audit = read_csv_safe(wave_root / "mechanics/evidence_cap_application_audit.csv")
    control_cap = read_csv_safe(wave_root / "controls/control_cap_diagnostics.csv")
    cap_by_candidate = {}
    if not cap_audit.empty:
        for _, r in cap_audit.iterrows():
            cap_by_candidate[str(r.get("candidate_definition_id", r.get("candidate_id")))] = r.to_dict()
    definition_agg = aggregate_definition_scope(aggregate) if not aggregate.empty else pd.DataFrame()
    positive_gate_rows: list[dict[str, Any]] = []
    for _, r in definition_agg.iterrows():
        cid = str(r.get("candidate_definition_id", r.get("candidate_id")))
        cap_row = cap_by_candidate.get(cid, {})
        cap_reason = str(cap_row.get("label_cap_reason", selected_caps.get(cid, "")))
        positive_gate_pass, positive_gate_reasons = positive_evidence_gate_for_candidate(
            cid=cid,
            hard_gate_pass=hard_gate_pass,
            cap_row=cap_row,
            control_cap=control_cap,
            control_summary=control_summary,
            gate=gate,
        )
        if not hard_gate_pass:
            state = "blocked_by_wave_component_issue"
            evidence = "level_2_path_or_interval_support_only"
        elif cap_reason:
            state = str(cap_row.get("candidate_status", "control_tested_but_mechanics_capped_pending_replay" if cid in control_ids else "materialized_mechanics_capped_pending_replay"))
            evidence = str(cap_row.get("evidence_level_contract", "level_4_event_ledger_plus_real_controls__mechanics_capped" if cid in control_ids else "level_3_event_level_trade_ledger_capped"))
        elif cid in control_ids and positive_gate_pass:
            state = "train_only_candidate_pending_validation"
            evidence = "level_4_event_ledger_plus_real_controls"
        elif cid in control_ids:
            state = "control_tested_but_mechanics_capped_pending_replay"
            evidence = "level_4_event_ledger_plus_real_controls__mechanics_capped"
            cap_reason = ";".join(positive_gate_reasons) or "missing_positive_evidence_gate"
        elif cid in selected_ids and cid in zero_ids:
            state = "sample_limited_pending_controls"
            evidence = "level_3_event_level_trade_ledger"
        elif cid in selected_ids:
            state = "materialized_pending_controls"
            evidence = "level_3_event_level_trade_ledger"
        else:
            state = "pending_compute"
            evidence = "level_1_generator_support"
        if str(r.get("materialization_scope", "definition_universe")) == "single_symbol_diagnostic_only" and evidence.startswith("level_4"):
            state = "single_symbol_diagnostic_only"
            evidence = "level_3_event_level_trade_ledger"
        clean_allowed = parse_bool_value(cap_row.get("clean_evidence_allowed", True), default=not bool(cap_reason)) if cap_row else not bool(cap_reason)
        mechanics_active = parse_bool_value(cap_row.get("mechanics_cap_active", bool(cap_reason)), default=bool(cap_reason)) if cap_row else bool(cap_reason)
        positive_gate_rows.append({
            "candidate_id": cid,
            "candidate_definition_id": cid,
            "parameter_vector_hash": r.get("parameter_vector_hash", ""),
            "positive_evidence_gate_pass": positive_gate_pass,
            "positive_evidence_gate_reasons": ";".join(positive_gate_reasons),
            "clean_level4_or_level5_allowed": positive_gate_pass and evidence == "level_4_event_ledger_plus_real_controls",
        })
        library_rows.append({"candidate_id": cid, "candidate_definition_id": cid, "definition_id": r.get("definition_id"), "hypothesis_id": r.get("hypothesis_id"), "family_engine_id": r.get("family_engine_id"), "parameter_vector_hash": r.get("parameter_vector_hash", ""), "candidate_library_state": state, "evidence_level": evidence, "evidence_level_contract": cap_row.get("evidence_level_contract", evidence), "clean_evidence_allowed": clean_allowed, "mechanics_cap_active": mechanics_active, "evidence_cap_reason": cap_reason, "family_rejected": False})
    for _, r in near.drop_duplicates("candidate_definition_id" if "candidate_definition_id" in near.columns else "candidate_id").iterrows():
        cid = r.get("candidate_definition_id", r.get("candidate_id"))
        library_rows.append({"candidate_id": cid, "candidate_definition_id": cid, "definition_id": r.get("definition_id"), "hypothesis_id": r.get("hypothesis_id"), "family_engine_id": r.get("family_engine_id"), "parameter_vector_hash": r.get("parameter_vector_hash", ""), "candidate_library_state": "blocked_by_wave_component_issue" if not hard_gate_pass else "near_miss_preserved", "evidence_level": "level_2_path_or_interval_support_only", "family_rejected": False})
    current_library, status_history, uniqueness_audit = deduplicate_candidate_library_current_state(library_rows)
    write_csv(analysis / "candidate_library_update.csv", current_library)
    write_csv(analysis / "status_history.csv", status_history)
    write_csv(analysis / "current_state_uniqueness_audit.csv", uniqueness_audit)
    write_csv(ctx.run_root / "candidate_library/status_history.csv", status_history)
    write_csv(ctx.run_root / "candidate_library/current_state_uniqueness_audit.csv", uniqueness_audit)
    write_csv(analysis / "evidence_label_positive_gate_audit.csv", positive_gate_rows)
    write_csv(ctx.run_root / "analysis_ready/evidence_label_positive_gate_audit.csv", positive_gate_rows)
    wp_dir = analysis / "candidate_work_packages"
    wp_dir.mkdir(parents=True, exist_ok=True)
    for _, r in selected.head(25).iterrows():
        cid = safe_filename(r.get("candidate_definition_id", r.get("candidate_id", "candidate")))
        raw_cid = str(r.get("candidate_definition_id", r.get("candidate_id")))
        cap_row = cap_by_candidate.get(raw_cid, {})
        cap_reason = str(cap_row.get("label_cap_reason", r.get("evidence_cap_reason", "")))
        wp_positive_gate, wp_positive_reasons = positive_evidence_gate_for_candidate(
            cid=raw_cid,
            hard_gate_pass=hard_gate_pass,
            cap_row=cap_row,
            control_cap=control_cap,
            control_summary=control_summary,
            gate=gate,
        )
        wp_clean_allowed = parse_bool_value(cap_row.get("clean_evidence_allowed", not bool(cap_reason)), default=not bool(cap_reason)) if cap_row else not bool(cap_reason)
        wp_mechanics_active = parse_bool_value(cap_row.get("mechanics_cap_active", bool(cap_reason)), default=bool(cap_reason)) if cap_row else bool(cap_reason)
        wp_level = "blocked_by_wave_component_issue" if not hard_gate_pass else str(cap_row.get("evidence_level_contract", "level_3_event_level_trade_ledger_capped" if cap_reason else "level_3_event_level_trade_ledger"))
        if wp_level == "level_4_event_ledger_plus_real_controls" and not wp_positive_gate:
            wp_level = "level_4_event_ledger_plus_real_controls__mechanics_capped"
            cap_reason = cap_reason or ";".join(wp_positive_reasons) or "missing_positive_evidence_gate"
        write_json(wp_dir / f"{cid}.json", {"candidate_id": raw_cid, "hypothesis_id": r.get("hypothesis_id"), "family_engine_id": r.get("family_engine_id"), "parameter_vector_hash": r.get("parameter_vector_hash", ""), "evidence_level": wp_level, "clean_evidence_allowed": wp_clean_allowed and wp_positive_gate, "mechanics_cap_active": wp_mechanics_active or not wp_positive_gate, "evidence_cap_reason": cap_reason, "positive_evidence_gate_pass": wp_positive_gate, "positive_evidence_gate_reasons": wp_positive_reasons, "materialized_manifest_rows": int(len(manifest)), "reason_preserved": r.get("selection_reason", ""), "next_recommended_test": "inspect_train_only_wave_package", "do_not_use_for_strategy_selection": not hard_gate_pass or not wp_positive_gate})
    write_text(analysis / "wave_report.md", "\n".join([
        f"# Engine Wave Report: {engine_wave_id}",
        "",
        "This is train-only research output. It is not validation, not final holdout evidence, not live readiness, and not permission to trade.",
        "",
        f"Gate status: `{gate.get('wave_gate_status')}`",
        f"Aggregate candidate-symbol rows: `{len(aggregate)}`",
        f"Selected materialized definitions: `{len(selected)}`",
        f"Near misses preserved: `{len(near)}`",
        f"Control summary rows: `{len(control_summary)}`",
    ]) + "\n")


def wave_protected_scan(ctx: Context, engine_wave_id: str, wave_dirs: Mapping[str, Path]) -> dict[str, Any]:
    violations = []
    checked = 0
    for base in [wave_dirs["root"], wave_dirs["analysis"]]:
        if not base.exists():
            continue
        for p in base.rglob("*"):
            if not p.is_file() or p.suffix.lower() not in {".csv", ".parquet"}:
                continue
            try:
                df = pd.read_parquet(p) if p.suffix.lower() == ".parquet" else pd.read_csv(p)
            except Exception:
                continue
            checked += 1
            for col in df.columns:
                if not is_timestamp_like_column_name(col):
                    continue
                vals = pd.to_datetime(df[col], utc=True, errors="coerce")
                try:
                    if getattr(vals.dt, "tz", None) is None:
                        vals = vals.dt.tz_localize("UTC")
                    else:
                        vals = vals.dt.tz_convert("UTC")
                except Exception:
                    vals = pd.to_datetime(df[col].astype(str), utc=True, errors="coerce")
                bad = vals[vals >= PROTECTED_TS]
                if len(bad):
                    violations.append({"artifact": str(p.relative_to(ctx.run_root)), "column": str(col), "violation_count": int(len(bad)), "max_ts": str(bad.max())})
    result = {"engine_wave_id": engine_wave_id, "status": "pass" if not violations else "fail", "artifacts_checked": checked, "violations": violations, "protected_ts": str(PROTECTED_TS)}
    write_json(ctx.run_root / "seal" / f"{engine_wave_id}_protected_scoring_scan.json", result)
    return result


def archive_wave_copy_only(ctx: Context, engine_wave_id: str, wave_dirs: Mapping[str, Path]) -> None:
    rows = []
    # Copy/archive is intentionally conservative here: summaries stay local, raw Kraken and prior artifacts are untouched.
    large_root = wave_dirs["materialized"] / "event_ledgers"
    if large_root.exists():
        digest = stable_hash(*[str(p.relative_to(ctx.run_root)) + ":" + str(p.stat().st_size) for p in sorted(large_root.glob("*.parquet"))], n=32)
        rows.append({"engine_wave_id": engine_wave_id, "artifact_root": str(large_root.relative_to(ctx.run_root)), "archive_action": "copy_archive_not_attempted_by_default", "hash_verification": digest, "raw_kraken_data_deleted": False, "prior_artifacts_deleted": False})
    write_csv(wave_dirs["root"] / "archive/archive_manifest.csv", rows)
    write_text(wave_dirs["root"] / "archive/restore_manifest.md", "# Restore Manifest\n\nNo raw Kraken data, frozen manifests, prior reports, source reports, contracts, or compact bundles are deleted by this wave stage. Large wave artifacts may be copied to remote archive in a later explicit archival step after hash verification.\n")


def write_tsmom_retest_top_level_outputs(ctx: Context, engine_wave_id: str, wave_dirs: Mapping[str, Path]) -> None:
    if not is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")) or engine_wave_id != "scheduled_tsmom_engine__wave_001":
        return
    analysis = wave_dirs["analysis"]
    copy_map = [
        (wave_dirs["audit"] / "original_selected_vs_materialized_audit.csv", ctx.run_root / "audit/original_selected_vs_materialized_audit.csv"),
        (wave_dirs["aggregate"] / "candidate_symbol_uniqueness_audit.csv", ctx.run_root / "audit/candidate_symbol_uniqueness_audit.csv"),
        (wave_dirs["controls"] / "control_contract_field_audit.csv", ctx.run_root / "controls/control_contract_field_audit.csv"),
        (wave_dirs["controls"] / "interval_overlap_purge_audit.csv", ctx.run_root / "controls/interval_overlap_purge_audit.csv"),
        (wave_dirs["controls"] / "same_bar_interval_semantics_audit.csv", ctx.run_root / "controls/same_bar_interval_semantics_audit.csv"),
        (wave_dirs["controls"] / "control_cap_diagnostics.csv", ctx.run_root / "controls/control_cap_diagnostics.csv"),
        (wave_dirs["controls"] / "diagnostic_control_accounting_audit.csv", ctx.run_root / "controls/diagnostic_control_accounting_audit.csv"),
        (wave_dirs["controls"] / "control_self_match_leakage_audit.csv", ctx.run_root / "controls/control_self_match_leakage_audit.csv"),
        (wave_dirs["root"] / "mechanics/evidence_cap_application_audit.csv", ctx.run_root / "mechanics/evidence_cap_application_audit.csv"),
        (wave_dirs["root"] / "mechanics/evidence_cap_application_audit.csv", analysis / "mechanics_cap_summary.csv"),
        (wave_dirs["stress"] / "fee_scenario_stress_summary.csv", analysis / "fee_scenario_stress_summary.csv"),
        (wave_dirs["root"] / "wave_gate_decision.json", ctx.run_root / "wave_gate_decision.json"),
    ]
    for src, dst in copy_map:
        if src.exists():
            dst.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(src, dst)
    p1_funding_report = ctx.run_root / "funding/funding_cap_impact_report.md"
    if p1_funding_report.exists():
        (analysis / "funding_cap_impact_report.md").parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(p1_funding_report, analysis / "funding_cap_impact_report.md")
    manifest = read_csv_safe(wave_dirs["materialized"] / "materialized_ledger_manifest.csv")
    funding_rows: list[dict[str, Any]] = []
    if not manifest.empty:
        for _, m in manifest.iterrows():
            p = ctx.run_root / str(m.get("path", ""))
            ev = pd.read_parquet(p) if p.exists() else pd.DataFrame()
            if ev.empty:
                funding_rows.append({
                    "candidate_id": m.get("candidate_id", ""),
                    "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id", "")),
                    "event_rows": 0,
                    "funding_proxy_event_rows": 0,
                    "funding_exact_event_rows": 0,
                    "funding_boundary_crossed_rows": 0,
                    "funding_R": 0.0,
                    "funding_cap_active": True,
                    "funding_cap_reason": "missing_materialized_event_ledger",
                })
                continue
            proxy = parse_bool_series(ev.get("funding_proxy_used", pd.Series(False, index=ev.index)), default=False)
            exact = parse_bool_series(ev.get("funding_exact", pd.Series(False, index=ev.index)), default=False)
            crossed = parse_bool_series(ev.get("funding_boundary_crossed", pd.Series(False, index=ev.index)), default=False)
            label_reason = ";".join(sorted(set(ev.get("funding_label_cap_reason", pd.Series(dtype=str)).dropna().astype(str))))
            funding_rows.append({
                "candidate_id": m.get("candidate_id", ""),
                "candidate_definition_id": m.get("candidate_definition_id", m.get("candidate_id", "")),
                "parameter_vector_hash": m.get("parameter_vector_hash", ""),
                "event_rows": int(len(ev)),
                "funding_proxy_event_rows": int(proxy.sum()),
                "funding_exact_event_rows": int(exact.sum()),
                "funding_boundary_crossed_rows": int(crossed.sum()),
                "funding_R": float(pd.to_numeric(ev.get("funding_R", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
                "funding_cap_active": bool(proxy.any() or bool(label_reason)),
                "funding_cap_reason": label_reason if label_reason else ("funding_proxy_cap" if bool(proxy.any()) else ""),
            })
    write_csv(analysis / "funding_cap_summary.csv", funding_rows)


def path_fingerprint(path: Path) -> str:
    if path.is_file():
        return sha256_file(path, limit_mb=16)
    if path.is_dir():
        files = sorted([p for p in path.rglob("*") if p.is_file()])[:300]
        return stable_hash(*[str(p.relative_to(path)) + ":" + sha256_file(p, limit_mb=1) for p in files], n=64)
    return "missing"


def build_wave_gate_hash_manifest(ctx: Context, engine_wave_id: str, wave_dirs: Mapping[str, Path]) -> tuple[pd.DataFrame, str]:
    entries = [
        ("code_hash", Path(__file__).resolve()),
        ("phase_profile", Path("__phase_profile_string__")),
        ("source_definition_manifest", ctx.run_root / "engine_wave/wave_definition_manifest.csv"),
        ("translation_audit", ctx.run_root / "prelaunch/translation_key_uniqueness_audit.csv"),
        ("prelaunch_eligibility_manifest", ctx.run_root / "prelaunch/prelaunch_contract_eligibility_audit.csv"),
        ("wave_definition_manifest", ctx.run_root / "engine_wave/wave_definition_manifest.csv"),
        ("k0_data_root", resolve_path(ctx.args.k0_root)),
        ("repair_root", resolve_path(ctx.args.repair_root)),
        ("structural_repair_root", resolve_path(ctx.args.structural_repair_root)),
        ("stat_protocol_repair_root", resolve_path(ctx.args.stat_protocol_repair_root)),
        ("p1_repair_root", p1_repair_root(ctx)),
        ("fee_scenario_manifest", ctx.run_root / "mechanics/account_fee_scenario_manifest.csv"),
        ("funding_coverage_manifest", ctx.run_root / "funding/funding_coverage_by_symbol_date.csv"),
    ]
    rows = []
    for name, path in entries:
        if name == "phase_profile":
            digest = stable_hash(ctx.args.phase_profile, active_run_id(ctx.args), EVENT_SEMANTICS_VERSION, n=64)
            exists = True
            path_str = str(ctx.args.phase_profile)
        else:
            digest = path_fingerprint(path)
            exists = path.exists()
            path_str = str(path)
        rows.append({"engine_wave_id": engine_wave_id, "hash_name": name, "path": path_str, "exists": exists, "hash": digest})
    digest = stable_hash(*[f"{r['hash_name']}={r['hash']}" for r in rows], n=64)
    df = pd.DataFrame(rows)
    write_csv(ctx.run_root / "resume/wave_gate_hash_manifest.csv", df)
    wave_resume = wave_dirs["root"] / "resume"
    wave_resume.mkdir(parents=True, exist_ok=True)
    write_csv(wave_resume / "wave_gate_hash_manifest.csv", df)
    return df, digest


def materialized_candidate_r_decomposition(ctx: Context, manifest: pd.DataFrame, *, base_root: Path | None = None) -> tuple[pd.DataFrame, pd.DataFrame]:
    base_root = base_root or ctx.run_root
    rows: list[dict[str, Any]] = []
    context_rows: list[dict[str, Any]] = []
    for _, m in manifest.iterrows():
        p = base_root / str(m.get("path", ""))
        ev = pd.read_parquet(p) if p.exists() else pd.DataFrame()
        cid = str(m.get("candidate_definition_id", m.get("candidate_id", "")))
        if ev.empty:
            rows.append({
                "candidate_id": cid,
                "candidate_definition_id": cid,
                "parameter_vector_hash": m.get("parameter_vector_hash", ""),
                "events": 0,
                "mean_R": np.nan,
                "median_R": np.nan,
                "net_R": 0.0,
                "failure_interpretation": "no_materialized_events_current_translation_diagnostic",
            })
            continue
        ev = ev.copy()
        ev["decision_ts"] = pd.to_datetime(ev.get("decision_ts"), utc=True, errors="coerce")
        ev["month"] = ev["decision_ts"].dt.strftime("%Y-%m")
        net = pd.to_numeric(ev.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        gross = pd.to_numeric(ev.get("gross_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        fees = pd.to_numeric(ev.get("fees_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        funding = pd.to_numeric(ev.get("funding_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        slippage = pd.to_numeric(ev.get("slippage_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        zero_fee_net = net - fees
        partial_fee_net = net - 0.5 * fees
        no_funding_net = net - funding
        q99 = net.quantile(0.99) if len(net) >= 100 else np.nan
        q95 = net.quantile(0.95) if len(net) >= 20 else np.nan
        mean_r = float(net.mean()) if len(net) else np.nan
        median_r = float(net.median()) if len(net) else np.nan
        rows.append({
            "candidate_id": cid,
            "candidate_definition_id": cid,
            "hypothesis_id": m.get("hypothesis_id", ""),
            "family_engine_id": m.get("family_engine_id", ""),
            "parameter_vector_hash": m.get("parameter_vector_hash", ""),
            "materialization_scope": m.get("materialization_scope", ""),
            "events": int(len(ev)),
            "active_symbols": int(ev["symbol"].nunique()) if "symbol" in ev.columns else 0,
            "active_months": int(ev["month"].nunique()),
            "gross_R": float(gross.sum()),
            "fees_R": float(fees.sum()),
            "funding_R": float(funding.sum()),
            "slippage_R": float(slippage.sum()),
            "net_R": float(net.sum()),
            "mean_R": mean_r,
            "median_R": median_r,
            "zero_fee_net_R": float(zero_fee_net.sum()),
            "fee_reversion_standard_net_R": float(net.sum()),
            "fee_reversion_partial_net_R": float(partial_fee_net.sum()),
            "no_funding_net_R": float(no_funding_net.sum()),
            "top_1pct_removed_net_R": float(net[net < q99].sum()) if pd.notna(q99) else np.nan,
            "top_5pct_removed_net_R": float(net[net < q95].sum()) if pd.notna(q95) else np.nan,
            "failure_interpretation": "materialized_negative_diagnostic" if (pd.notna(mean_r) and mean_r < 0 and median_r <= 0) else "context_followup_hypothesis",
        })
        for keys in [["symbol"], ["month"], ["regime_label"], ["symbol", "month"], ["regime_label", "month"]]:
            if not set(keys).issubset(ev.columns):
                continue
            for group_key, g in ev.groupby(keys, dropna=False, sort=False):
                gnet = pd.to_numeric(g.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
                key_tuple = group_key if isinstance(group_key, tuple) else (group_key,)
                rec = {
                    "candidate_id": cid,
                    "candidate_definition_id": cid,
                    "breakdown_type": "+".join(keys),
                    "events": int(len(g)),
                    "active_symbols": int(g["symbol"].nunique()) if "symbol" in g.columns else 0,
                    "active_months": int(g["month"].nunique()) if "month" in g.columns else 0,
                    "net_R": float(gnet.sum()),
                    "mean_R": float(gnet.mean()) if len(gnet) else np.nan,
                    "median_R": float(gnet.median()) if len(gnet) else np.nan,
                    "positive_context_pocket": bool(len(g) >= 100 and (g["symbol"].nunique() if "symbol" in g.columns else 0) >= 3 and (g["month"].nunique() if "month" in g.columns else 0) >= 3 and float(gnet.sum()) > 0 and float(gnet.median()) > 0),
                    "context_label": "context_followup_hypothesis",
                }
                for name, value in zip(keys, key_tuple):
                    rec[name] = value
                context_rows.append(rec)
    return pd.DataFrame(rows), pd.DataFrame(context_rows)


def write_materialized_futility_gate(ctx: Context, wave_dirs: Mapping[str, Path], manifest: pd.DataFrame) -> tuple[pd.DataFrame, dict[str, Any]]:
    summary, context = materialized_candidate_r_decomposition(ctx, manifest)
    canary_dir = ctx.run_root / "canary"
    write_csv(canary_dir / "materialized_futility_candidate_summary.csv", summary)
    write_text(canary_dir / "materialized_futility_gate_policy.md", "\n".join([
        "# Materialized Futility Gate Policy",
        "",
        "This gate runs after full-universe materialization and before expensive controls for canary profiles.",
        "It may stop a canary as `materialized_futility_stop`; it may not reject TSMOM, H02, A4, or pending definitions.",
        "Default stop rule: all selected materialized candidates have `mean_R < -0.03` and `median_R <= 0`, or all are materially negative under both zero-fee and fee-reversion scenarios.",
        "Override: a predeclared context pocket can continue only with at least 100 events, 3 symbols, 3 months, net_R > 0, and median_R > 0.",
    ]) + "\n")
    if summary.empty:
        all_bad = False
        all_scenario_bad = False
    else:
        all_bad = bool((pd.to_numeric(summary.get("mean_R", pd.Series(dtype=float)), errors="coerce") < -0.03).all() and (pd.to_numeric(summary.get("median_R", pd.Series(dtype=float)), errors="coerce") <= 0).all())
        all_scenario_bad = bool((pd.to_numeric(summary.get("zero_fee_net_R", pd.Series(dtype=float)), errors="coerce") < 0).all() and (pd.to_numeric(summary.get("fee_reversion_standard_net_R", pd.Series(dtype=float)), errors="coerce") < 0).all())
    positive_pockets = context[parse_bool_series(context.get("positive_context_pocket", pd.Series(False, index=context.index)), default=False)] if not context.empty else pd.DataFrame()
    stop = bool((all_bad or all_scenario_bad) and positive_pockets.empty)
    decision = {
        "status": "materialized_futility_stop" if stop else "continue_after_materialized_futility_gate",
        "futility_stop": stop,
        "all_selected_mean_lt_minus_0_03_and_median_lte_0": all_bad,
        "all_selected_negative_under_zero_fee_and_fee_reversion": all_scenario_bad,
        "positive_context_pocket_count": int(len(positive_pockets)),
        "family_rejected": False,
        "hypothesis_rejected": False,
        "pending_definitions_preserved_as": "pending_compute",
        "selected_negative_candidates_label": "materialized_negative_diagnostic",
        "ts_utc": utc_now(),
    }
    write_json(canary_dir / "materialized_futility_gate_decision.json", decision)
    # Per-wave copies help analyze a single wave without checking top-level canary outputs.
    (wave_dirs["root"] / "canary").mkdir(parents=True, exist_ok=True)
    write_csv(wave_dirs["root"] / "canary/materialized_futility_candidate_summary.csv", summary)
    write_json(wave_dirs["root"] / "canary/materialized_futility_gate_decision.json", decision)
    return summary, decision


def candidate_identity_audit_frame(frame: pd.DataFrame, *, context: str) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    required = ["candidate_definition_id", "parameter_vector_hash", "event_semantics_version"]
    for col in required:
        missing = col not in frame.columns
        blank = 0 if missing or frame.empty else int((frame[col].isna() | frame[col].astype(str).str.strip().isin({"", "nan", "None"})).sum())
        rows.append({"context": context, "check": f"required_identity_field_{col}", "status": "fail" if missing or blank else "pass", "bad_rows": blank, "detail": "missing" if missing else "present"})
    if "candidate_symbol_id" in frame.columns:
        symbol_level = frame[frame["candidate_symbol_id"].astype(str).str.strip().ne("") & ~frame["candidate_symbol_id"].astype(str).isin(["nan", "None"])]
        blank_symbols = int(symbol_level.get("symbol", pd.Series(dtype=str)).astype(str).isin(["", "__universe__", "nan", "None"]).sum()) if not symbol_level.empty else 0
        rows.append({"context": context, "check": "candidate_symbol_id_has_symbol_context", "status": "fail" if blank_symbols else "pass", "bad_rows": blank_symbols, "detail": "symbol-level rows must identify a real symbol"})
    if {"definition_id", "parameter_vector_hash"}.issubset(frame.columns):
        dup = frame[frame.duplicated(["definition_id", "parameter_vector_hash"], keep=False)].copy()
        if "candidate_symbol_id" in dup.columns:
            # Candidate-symbol fanout intentionally repeats definition/parameter pairs across symbols.
            non_symbol_dup = dup[dup["candidate_symbol_id"].astype(str).str.strip().isin(["", "nan", "None"])]
        else:
            non_symbol_dup = dup
        rows.append({"context": context, "check": "duplicate_definition_parameter_rows_without_symbol_context", "status": "fail" if len(non_symbol_dup) else "pass", "bad_rows": int(len(non_symbol_dup)), "detail": "duplicates allowed only when symbol-qualified"})
    return pd.DataFrame(rows)


def parameter_preservation_audit_frame(frame: pd.DataFrame, *, context: str) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    required = list(PARAMETER_VECTOR_FIELDS) + ["parameter_vector_hash"]
    has_json = "parameter_vector_json" in frame.columns or "parameter_manifest_pointer" in frame.columns
    rows.append({"context": context, "check": "parameter_vector_json_or_manifest_pointer", "status": "pass" if has_json else "fail", "bad_rows": 0 if has_json else len(frame), "detail": "wide JSON or manifest pointer required"})
    for col in required:
        missing = col not in frame.columns
        blank = 0 if missing or frame.empty else int((frame[col].isna() | frame[col].astype(str).str.strip().isin({"", "nan", "None"})).sum())
        rows.append({"context": context, "check": f"required_parameter_field_{col}", "status": "fail" if missing or blank else "pass", "bad_rows": blank, "detail": "missing" if missing else "present"})
    return pd.DataFrame(rows)


def write_wave_identity_parameter_audits(ctx: Context, wave_dirs: Mapping[str, Path], selected: pd.DataFrame, manifest: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame]:
    identity = pd.concat([
        candidate_identity_audit_frame(selected, context="selected"),
        candidate_identity_audit_frame(manifest, context="materialized_manifest"),
    ], ignore_index=True)
    params = pd.concat([
        parameter_preservation_audit_frame(selected, context="selected"),
        parameter_preservation_audit_frame(manifest, context="materialized_manifest"),
    ], ignore_index=True)
    write_csv(wave_dirs["audit"] / "candidate_identity_audit.csv", identity)
    write_csv(wave_dirs["audit"] / "parameter_preservation_audit.csv", params)
    return identity, params


def audit_pass(df: pd.DataFrame) -> bool:
    return bool(not df.empty and not df.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any())


def wave_next_action_for_gate(ctx: Context | SimpleNamespace, *, hard_gate_pass: bool, materialized_futility_stop: bool) -> str:
    if not hard_gate_pass:
        return "repair_wave_component_next"
    if materialized_futility_stop:
        if is_tsmom_retest_profile(getattr(getattr(ctx, "args", None), "phase_profile", "")):
            return "analyze_tsmom_wave_now"
        return "analyze_completed_engine_waves_now"
    return "continue_next_engine_wave_next"


def is_timestamp_like_column_name(column: object) -> bool:
    col = str(column).strip().lower()
    exact = {"ts", "time", "date", "datetime", "timestamp"}
    suffixes = ("_ts", "_time", "_date", "_datetime", "_timestamp", "_close_ts", "_source_ts")
    return col in exact or col.endswith(suffixes)



def execute_engine_wave(ctx: Context, plan_row: Mapping[str, Any], defs: pd.DataFrame, budget_row: Mapping[str, Any]) -> dict[str, Any]:
    engine_wave_id = str(plan_row["engine_wave_id"])
    wave_dirs = wave_paths(ctx, engine_wave_id)
    for p in wave_dirs.values():
        p.mkdir(parents=True, exist_ok=True)
    gate_path = wave_dirs["root"] / "wave_gate_decision.json"
    _, current_gate_hash = build_wave_gate_hash_manifest(ctx, engine_wave_id, wave_dirs)
    if gate_path.exists():
        existing = read_json(gate_path, {})
        if (
            existing.get("wave_gate_logic_version") == WAVE_GATE_LOGIC_VERSION
            and existing.get("candidate_identity_contract_version") == IDENTITY_CONTRACT_VERSION
            and existing.get("parameter_contract_version") == PARAMETER_CONTRACT_VERSION
            and existing.get("wave_gate_hash_digest") == current_gate_hash
        ):
            return existing
        report = {
            "engine_wave_id": engine_wave_id,
            "stale_gate_path": str(gate_path.relative_to(ctx.run_root)),
            "old_wave_gate_logic_version": existing.get("wave_gate_logic_version", "missing"),
            "new_wave_gate_logic_version": WAVE_GATE_LOGIC_VERSION,
            "old_wave_gate_hash_digest": existing.get("wave_gate_hash_digest", "missing"),
            "new_wave_gate_hash_digest": current_gate_hash,
            "action": "stale_gate_ignored_recompute_required",
            "ts_utc": utc_now(),
        }
        write_json(wave_dirs["root"] / "resume/stale_wave_gate_invalidation_report.json", report)
        write_text(wave_dirs["root"] / "resume/stale_wave_gate_invalidation_report.md", "# Stale Wave Gate Invalidation\n\nExisting wave gate was produced under an older or missing structural contract version and cannot be reused. The wave is recomputed.\n")
    candidates = engine_wave_candidates(ctx, defs)
    aggregate, sym_month, regime = aggregate_candidates_to_dir(ctx, candidates, wave_dirs["aggregate"])
    write_text(wave_dirs["aggregate"] / "aggregate_evaluation_report.md", f"# Aggregate Evaluation\n\nWave: `{engine_wave_id}`\nDefinitions: `{defs['definition_id'].nunique() if not defs.empty else 0}`\nCandidate-symbol rows: `{len(aggregate)}`\nEvent sampling used: `{any_true(aggregate.get('event_sampling_used', pd.Series([False])), default=True) if not aggregate.empty else False}`\n")
    selected, near, audit = select_wave_materialization(ctx, engine_wave_id, aggregate, budget_row, wave_dirs["selection"], sym_month)
    materialize_input = pd.concat([selected, audit], ignore_index=True, sort=False).drop_duplicates(["candidate_definition_id", "parameter_vector_hash"]) if not selected.empty or not audit.empty else pd.DataFrame()
    manifest, coverage = materialize_wave_candidates(ctx, materialize_input, wave_dirs["materialized"])
    identity_audit, parameter_audit = write_wave_identity_parameter_audits(ctx, wave_dirs, materialize_input, manifest)
    audit_df = aggregate_vs_materialized_wave_audit(ctx, materialize_input, manifest, wave_dirs["audit"])
    futility_decision: dict[str, Any] = {"futility_stop": False, "status": "not_applicable"}
    if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")):
        _, futility_decision = write_materialized_futility_gate(ctx, wave_dirs, manifest)
    effective_diagnostic_control_mode = str(getattr(ctx.args, "control_mode", "evidence")) == "diagnostic" or is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", ""))
    if bool(futility_decision.get("futility_stop")):
        controls = pd.DataFrame()
        control_summary = pd.DataFrame()
        zero_diag = pd.DataFrame([{
            "candidate_id": "__canary_materialized_futility_stop__",
            "candidate_definition_id": "__canary_materialized_futility_stop__",
            "controls_row_count": 0,
            "zero_control_reason": "materialized_futility_stop_before_evidence_controls",
            "zero_control_status": "diagnostic_stop_not_wave_failure",
        }])
        self_audit = pd.DataFrame([{
            "candidate_id": "__canary_materialized_futility_stop__",
            "candidate_definition_id": "__canary_materialized_futility_stop__",
            "control_rows": 0,
            "self_match_rows": 0,
            "status": "pass",
        }])
        write_csv(wave_dirs["controls"] / "control_summary.csv", control_summary)
        write_csv(wave_dirs["controls"] / "control_zero_row_diagnostics.csv", zero_diag)
        write_csv(wave_dirs["controls"] / "control_self_match_leakage_audit.csv", self_audit)
        write_csv(wave_dirs["controls"] / "control_cap_diagnostics.csv", [])
        write_csv(wave_dirs["controls"] / "control_contract_field_audit.csv", [{
            "check": "control_schema_not_applicable_after_materialized_futility_stop",
            "status": "pass",
            "bad_rows": 0,
            "detail": "evidence_controls_skipped_before_construction",
        }])
        write_csv(wave_dirs["controls"] / "control_diagnostic_mode_audit.csv", [{
            "control_mode": "diagnostic" if effective_diagnostic_control_mode else "evidence",
            "diagnostic_only_not_evidence": bool(effective_diagnostic_control_mode),
            "controls_skipped_reason": "materialized_futility_stop_before_evidence_controls",
        }])
        write_text(wave_dirs["controls"] / "control_audit_report.md", "# Control Audit\n\nStatus: `pass`\nControls were skipped because the materialized futility gate stopped this canary before expensive evidence controls. This is not evidence and cannot produce level 4/5 labels.\n")
    else:
        controls, control_summary, zero_diag, self_audit = build_wave_controls(ctx, manifest, wave_dirs["controls"])
    materialized_frames = []
    for _, m in manifest.iterrows():
        p = ctx.run_root / str(m.get("path", ""))
        if p.exists():
            df = pd.read_parquet(p)
            if not df.empty:
                materialized_frames.append(df)
    materialized_events = pd.concat(materialized_frames, ignore_index=True, sort=False) if materialized_frames else pd.DataFrame()
    if is_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")) and engine_wave_id == "scheduled_tsmom_engine__wave_001":
        write_run_level_tsmom_convenience_audits(ctx, materialized_events, manifest if not manifest.empty else materialize_input)
    same_bar_interval_audit = same_bar_interval_semantics_audit_frame(materialized_events)
    write_csv(wave_dirs["controls"] / "same_bar_interval_semantics_audit.csv", same_bar_interval_audit)
    interval_purge_audit = audit_interval_purge(materialized_events, controls, manifest)
    write_csv(wave_dirs["controls"] / "interval_overlap_purge_audit.csv", interval_purge_audit)
    stress, context, stability, concentration = run_wave_stress_context_stability(ctx, manifest, wave_dirs)
    mechanics_cap_audit = collect_wave_evidence_cap_audit(ctx, wave_dirs, manifest, selected, control_summary, stability)
    protected_result = wave_protected_scan(ctx, engine_wave_id, wave_dirs)
    control_field_audit = read_csv_safe(wave_dirs["controls"] / "control_contract_field_audit.csv")
    zero_status = zero_diag.get("zero_control_status", pd.Series(dtype=str)).astype(str) if not zero_diag.empty else pd.Series(dtype=str)
    zero_reason = zero_diag.get("zero_control_reason", pd.Series(dtype=str)).astype(str) if not zero_diag.empty else pd.Series(dtype=str)
    actual_zero = zero_diag[zero_reason.ne("no_candidate_events")] if not zero_diag.empty else pd.DataFrame()
    systemic_zero = bool(
        not ctx.args.smoke
        and not actual_zero.empty
        and actual_zero.get("zero_control_status", pd.Series(dtype=str)).astype(str).eq("candidate_level_cap").mean() > 0.5
    )
    self_match_count = int(pd.to_numeric(self_audit.get("self_match_rows", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not self_audit.empty else 0
    event_sampling_used = any_true(aggregate.get("event_sampling_used", pd.Series([False])), default=True) if not aggregate.empty else False
    event_sampling_used = event_sampling_used or (any_true(coverage.get("event_sampling_used", pd.Series([False])), default=True) if not coverage.empty else False)
    parameter_pass = audit_pass(parameter_audit)
    identity_pass = audit_pass(identity_audit)
    aggregate_materialized_pass = bool(not audit_df.empty and not audit_df.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    control_schema_pass = bool(not control_field_audit.empty and not control_field_audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    interval_purge_pass = bool(interval_purge_audit.empty or not interval_purge_audit.get("purge_status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    same_bar_interval_pass = bool(not same_bar_interval_audit.empty and not same_bar_interval_audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    protected_pass = protected_result.get("status") == "pass"
    hard_gate_pass = all([parameter_pass, identity_pass, aggregate_materialized_pass, control_schema_pass, interval_purge_pass, same_bar_interval_pass, protected_pass, not event_sampling_used, self_match_count == 0, not systemic_zero])
    mechanics_cap_active = any_true(mechanics_cap_audit.get("mechanics_cap_active", pd.Series(dtype=bool)), default=False) if not mechanics_cap_audit.empty else False
    clean_evidence_allowed = bool(not mechanics_cap_active and hard_gate_pass)
    gate = {
        "engine_wave_id": engine_wave_id,
        "wave_gate_status": "pass" if hard_gate_pass else "repair_wave_component_next",
        "wave_gate_logic_version": WAVE_GATE_LOGIC_VERSION,
        "candidate_identity_contract_version": IDENTITY_CONTRACT_VERSION,
        "parameter_contract_version": PARAMETER_CONTRACT_VERSION,
        "wave_gate_hash_digest": current_gate_hash,
        "parameter_preservation_pass": parameter_pass,
        "candidate_identity_pass": identity_pass,
        "aggregate_materialized_audit_pass": aggregate_materialized_pass,
        "control_schema_audit_pass": control_schema_pass,
        "interval_purge_embargo_pass": interval_purge_pass,
        "same_bar_interval_semantics_pass": same_bar_interval_pass,
        "protected_scan_pass": protected_pass,
        "event_sampling_used": event_sampling_used,
        "control_self_match_leakage_count": self_match_count,
        "systemic_zero_control_blocker": systemic_zero,
        "mechanics_cap_active": mechanics_cap_active,
        "clean_evidence_allowed": clean_evidence_allowed,
        "mechanics_capped_candidate_count": int(parse_bool_series(mechanics_cap_audit.get("mechanics_cap_active", pd.Series(dtype=bool)), default=False).sum()) if not mechanics_cap_audit.empty else 0,
        "controls_built": bool(len(controls) > 0),
        "zero_control_blocker_count": int(zero_status.eq("blocking_zero_controls").sum()) if not zero_status.empty else 0,
        "candidate_level_zero_control_caps": int(zero_diag.get("zero_control_status", pd.Series(dtype=str)).astype(str).eq("candidate_level_cap").sum()) if not zero_diag.empty else 0,
        "stress_context_stability_completed": bool((wave_dirs["stress"] / "stress_summary.csv").exists() and (wave_dirs["context"] / "context_summary.csv").exists() and (wave_dirs["validation"] / "stability_summary.csv").exists()),
        "materialized_futility_gate_status": futility_decision.get("status", "not_applicable"),
        "materialized_futility_stop": bool(futility_decision.get("futility_stop", False)),
        "futility_stop_operator_review_required": bool(futility_decision.get("futility_stop", False)),
        "control_mode": "diagnostic" if (str(getattr(ctx.args, "control_mode", "evidence")) == "diagnostic" or is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", ""))) else "evidence",
        "diagnostic_controls_not_evidence": str(getattr(ctx.args, "control_mode", "evidence")) == "diagnostic" or is_fast_tsmom_canary_profile(getattr(ctx.args, "phase_profile", "")),
        "next_action": wave_next_action_for_gate(ctx, hard_gate_pass=hard_gate_pass, materialized_futility_stop=bool(futility_decision.get("futility_stop", False))),
        "ts_utc": utc_now(),
    }
    write_json(gate_path, gate)
    write_wave_analysis_ready(ctx, engine_wave_id, wave_dirs, aggregate, selected, near, manifest, control_summary, stress, context, stability, zero_diag, gate)
    write_tsmom_retest_top_level_outputs(ctx, engine_wave_id, wave_dirs)
    archive_wave_copy_only(ctx, engine_wave_id, wave_dirs)
    if not hard_gate_pass:
        ctx.notifier.send("Kraken engine wave blocked by structural gate", f"engine_wave_id={engine_wave_id}\nrun_root={ctx.run_root}\ngate={gate}", level="error")
        raise RuntimeError("wave structural gate failed")
    ctx.notifier.send("Kraken engine wave completed", f"engine_wave_id={engine_wave_id}\nrun_root={ctx.run_root}")
    return gate


def stage_engine_wave_loop(ctx: Context) -> None:
    plan = read_csv_safe(ctx.run_root / "engine_wave/engine_wave_execution_plan.csv")
    defs = read_csv_safe(ctx.run_root / "engine_wave/wave_definition_manifest.csv")
    budgets = read_csv_safe(ctx.run_root / "engine_wave/per_wave_materialization_budget.csv")
    if plan.empty or defs.empty:
        raise RuntimeError("missing engine wave plan or wave definitions")
    summary_rows = []
    stopped = False
    for _, row in plan.sort_values("engine_wave_order").iterrows():
        engine_wave_id = str(row["engine_wave_id"])
        if str(row.get("wave_status", "")) == "skipped_no_eligible_definitions":
            summary_rows.append({"engine_wave_id": engine_wave_id, "wave_status": "pending_compute_no_eligible_definitions"})
            continue
        sub_defs = defs[defs["engine_wave_id"].astype(str).eq(engine_wave_id)].copy()
        b = budgets[budgets["engine_wave_id"].astype(str).eq(engine_wave_id)].iloc[0].to_dict()
        try:
            gate = execute_engine_wave(ctx, row.to_dict(), sub_defs, b)
            summary_rows.append({"engine_wave_id": engine_wave_id, "family_engine_id": row.get("family_engine_id"), "wave_status": gate.get("wave_gate_status", "pass"), "next_action": gate.get("next_action", "continue_next_engine_wave_next")})
        except Exception as exc:
            summary_rows.append({"engine_wave_id": engine_wave_id, "family_engine_id": row.get("family_engine_id"), "wave_status": "failed", "next_action": "repair_wave_component_next", "error": f"{type(exc).__name__}: {exc}"})
            write_csv(ctx.run_root / "engine_wave/engine_wave_loop_status.csv", summary_rows)
            raise
        write_csv(ctx.run_root / "engine_wave/engine_wave_loop_status.csv", summary_rows)
        write_status(ctx, "running", f"completed-{engine_wave_id}")
        if ctx.args.stop_after_current_engine_wave or (ctx.run_root / "STOP_AFTER_CURRENT_ENGINE_WAVE").exists():
            stopped = True
            break
    if stopped and not is_tsmom_retest_profile(getattr(ctx.args, "phase_profile", "")):
        ctx.stop_after_current_stage = True
    write_csv(ctx.run_root / "engine_wave/engine_wave_loop_status.csv", summary_rows)


