def stage_cross_wave_summary(ctx: Context) -> None:
    loop = read_csv_safe(ctx.run_root / "engine_wave/engine_wave_loop_status.csv")
    rows = []
    lib_rows = []
    pending_rows = []
    plan = read_csv_safe(ctx.run_root / "engine_wave/engine_wave_execution_plan.csv")
    for _, r in plan.iterrows():
        wave_id = str(r.get("engine_wave_id"))
        gate = read_json(ctx.run_root / "waves" / wave_id / "wave_gate_decision.json", {})
        status = gate.get("wave_gate_status", "pending")
        rows.append({"engine_wave_id": wave_id, "family_engine_id": r.get("family_engine_id"), "wave_status": status, "analysis_ready_path": str((ctx.run_root / "analysis_ready" / wave_id).relative_to(ctx.run_root))})
        update = read_csv_safe(ctx.run_root / "analysis_ready" / wave_id / "candidate_library_update.csv")
        if not update.empty:
            lib_rows.extend(update.to_dict("records"))
        elif status == "pending":
            pending_rows.append({"engine_wave_id": wave_id, "family_engine_id": r.get("family_engine_id"), "pending_reason": "not_run_or_stopped_before_wave"})
    pending_manifest = read_csv_safe(ctx.run_root / "engine_wave/pending_compute_manifest.csv")
    if not pending_manifest.empty:
        pending_rows.extend(pending_manifest.to_dict("records"))
    write_csv(ctx.run_root / "cross_wave/cross_wave_summary.csv", rows)
    write_csv(ctx.run_root / "cross_wave/candidate_library_update.csv", lib_rows)
    write_csv(ctx.run_root / "cross_wave/pending_compute_update.csv", pending_rows)


