def stage_wave001_quarantine(ctx: Context) -> None:
    old_run = failed_wave_run_root(ctx)
    old_wave = failed_wave_root(ctx)
    invalidated = []
    for rel, cls in [
        ("aggregate", "level_1_or_2_support_only_pending_repair"),
        ("materialized", "invalid_materialization_parameter_mismatch"),
        ("controls", "invalid_control_schema_failed"),
        ("analysis_ready/scheduled_tsmom_engine__wave_001", "do_not_use_for_strategy_selection"),
    ]:
        base = old_wave / rel if rel in {"aggregate", "materialized", "controls"} else old_run / rel
        if base.exists():
            for p in sorted(base.rglob("*")):
                if p.is_file():
                    invalidated.append({"artifact": str(p), "classification": cls, "delete_artifact": False})
    write_csv(ctx.run_root / "quarantine/wave001_invalidated_artifacts.csv", invalidated)
    old_lib = read_csv_safe(old_run / "analysis_ready/scheduled_tsmom_engine__wave_001/candidate_library_update.csv")
    downgrades = []
    for _, r in old_lib.iterrows():
        old_level = str(r.get("evidence_level", ""))
        old_state = str(r.get("candidate_library_state", ""))
        new_state = "blocked_by_wave_component_issue"
        new_level = "level_2_path_or_interval_support_only"
        downgrades.append({**r.to_dict(), "old_candidate_library_state": old_state, "old_evidence_level": old_level, "candidate_library_state": new_state, "evidence_level": new_level, "downgrade_reason": "wave001_parameter_mismatch_and_control_schema_failure"})
    write_csv(ctx.run_root / "quarantine/wave001_candidate_label_downgrade.csv", downgrades)
    write_text(ctx.run_root / "quarantine/wave001_quarantine_report.md", "\n".join([
        "# Wave 001 Quarantine Report",
        "",
        f"Reference run: `{old_run}`",
        f"Failed wave: `{old_wave}`",
        "All stopped Wave 1 artifacts are classified as debug/infrastructure only. No artifacts are deleted.",
        "Aggregate rows are level 1/2 support pending repair; materialized rows are invalid due parameter mismatch; controls are invalid due schema failure; candidate work packages are do-not-use for strategy selection.",
    ]) + "\n")


def stage_candidate_identity_contract_repair(ctx: Context) -> None:
    schema = {
        "contract_version": IDENTITY_CONTRACT_VERSION,
        "definition_level_required": ["candidate_definition_id", "definition_id", "hypothesis_id", "family_engine_id", "parameter_vector_hash", "engine_contract_hash", "event_semantics_version", "symbol_universe_hash"],
        "symbol_level_required": ["candidate_symbol_id", "candidate_definition_id", "symbol", "symbol_lifecycle_interval_id", "symbol_universe_membership_ts"],
        "rankable_scope": "definition_level_universe_wide",
        "single_symbol_scope": "single_symbol_diagnostic_only",
    }
    write_json(ctx.run_root / "contracts/candidate_identity_schema.json", schema)
    write_text(ctx.run_root / "contracts/candidate_identity_contract.md", "# Candidate Identity Contract\n\nRankable candidates use `candidate_definition_id` across the eligible PIT universe. Symbol-level rows require `candidate_symbol_id` and are diagnostics unless explicitly aggregated back to the definition-level universe. `candidate_id` must not be used ambiguously.\n")
    frames = []
    old_run = failed_wave_run_root(ctx)
    for rel, name in [
        ("engine_wave/wave_definition_manifest.csv", "old_wave_definition_manifest"),
        ("waves/scheduled_tsmom_engine__wave_001/selection/materialization_selection.csv", "old_selection"),
        ("waves/scheduled_tsmom_engine__wave_001/materialized/materialized_ledger_manifest.csv", "old_materialized_manifest"),
    ]:
        df = read_csv_safe(old_run / rel)
        if not df.empty:
            frames.append(candidate_identity_audit_frame(df, context=name))
    audit = pd.concat(frames, ignore_index=True) if frames else pd.DataFrame()
    write_csv(ctx.run_root / "audit/candidate_identity_audit.csv", audit)


