def stage_materialization_and_audit_repair(ctx: Context) -> None:
    old_run = failed_wave_run_root(ctx)
    old_sel = read_csv_safe(old_run / "waves/scheduled_tsmom_engine__wave_001/selection/materialization_selection.csv")
