    if not old_sel.empty and not old_manifest.empty:
        merged = old_sel.head(25).merge(old_manifest[[c for c in ["candidate_id", "event_rows", "parameter_vector_hash", "lookback_bars", "hold_bars", "stop_bps", "threshold"] if c in old_manifest.columns]], on="candidate_id", how="left", suffixes=("_selected", "_materialized"))
        for _, r in merged.iterrows():
            rows.append({"candidate_id": r.get("candidate_id"), "selected_events": r.get("events"), "materialized_events": r.get("event_rows"), "selected_net_R": r.get("net_R"), "selected_parameter_vector_hash": r.get("parameter_vector_hash_selected", r.get("parameter_vector_hash")), "materialized_parameter_vector_hash": r.get("parameter_vector_hash_materialized", "missing"), "status": "fail_expected_old_artifact"})
    write_csv(ctx.run_root / "audit/original_selected_vs_materialized_audit.csv", rows)
    write_csv(ctx.run_root / "audit/aggregate_materialized_identity_key_audit.csv", rows)
    write_csv(ctx.run_root / "audit/materialization_scope_audit.csv", [{"scope": "definition_universe", "status": "repaired_code_path_requires_universe_materialization"}, {"scope": "single_symbol_diagnostic_only", "status": "diagnostic_only_not_universe_evidence"}])


