def stage_resume_invalidation_repair(ctx: Context) -> None:
    old_run = failed_wave_run_root(ctx)
    old_gate = read_json(old_run / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json", {})
    stale = old_gate.get("wave_gate_logic_version") != WAVE_GATE_LOGIC_VERSION or old_gate.get("candidate_identity_contract_version") != IDENTITY_CONTRACT_VERSION or old_gate.get("parameter_contract_version") != PARAMETER_CONTRACT_VERSION
    report = {"old_gate_path": str(old_run / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json"), "old_wave_gate_status": old_gate.get("wave_gate_status", "missing"), "stale_gate_detected": bool(stale), "required_action": "invalidate_old_gate_and_rerun_wave" if stale else "gate_reusable", "wave_gate_logic_version": WAVE_GATE_LOGIC_VERSION, "candidate_identity_contract_version": IDENTITY_CONTRACT_VERSION, "parameter_contract_version": PARAMETER_CONTRACT_VERSION}
    write_json(ctx.run_root / "resume/stale_wave_gate_invalidation_report.json", report)
    write_text(ctx.run_root / "resume/stale_wave_gate_invalidation_report.md", f"# Stale Wave Gate Invalidation Report\n\nStale gate detected: `{stale}`. Old Wave 1 gate cannot be reused after this structural repair unless all contract versions match.\n")
    write_text(ctx.run_root / "resume/resume_invalidation_policy.md", "# Resume Invalidation Policy\n\n`--resume` must not accept wave gates produced under older code, identity contracts, parameter contracts, or gate logic. Stale gates are ignored and affected waves must rerun.\n")


