def stage_structural_repair_dependency_check(ctx: Context) -> bool:
    root = structural_repair_root(ctx)
    decision = read_json(root / "decision_summary.json", {})
    checks = [
        ("candidate_identity_contract", root / "contracts/candidate_identity_contract.md", decision.get("candidate_identity_repaired")),
        ("parameter_vector_contract", root / "contracts/parameter_vector_contract.md", decision.get("parameter_preservation_repaired")),
        ("original_selected_aggregate_vs_materialized_audit", root / "audit/original_selected_vs_materialized_audit.csv", decision.get("aggregate_materialized_audit_repaired")),
        ("control_schema_repair", root / "controls/control_schema_repair_report.md", decision.get("control_schema_repaired")),
        ("wave_gate_fail_closed_repair", root / "gate/wave_gate_fail_closed_contract.json", decision.get("wave_gate_fail_closed_repaired")),
        ("resume_invalidation_repair", root / "resume/stale_wave_gate_invalidation_report.md", decision.get("resume_stale_gate_invalidation_repaired")),
    ]
    rows = []
    ok = True
    for name, path, decision_flag in checks:
        passed = bool(path.exists() and decision_flag is True)
        ok = ok and passed
        rows.append({"dependency": name, "path": str(path), "artifact_exists": path.exists(), "decision_flag": decision_flag, "status": "pass" if passed else "fail"})
    write_csv(ctx.run_root / "preflight/structural_repair_dependency_check.csv", rows)
    write_text(ctx.run_root / "preflight/structural_repair_dependency_check.md", "\n".join([
        "# Structural Repair Dependency Check",
        "",
        f"Structural repair root: `{root}`",
        f"Overall status: `{'pass' if ok else 'fail'}`",
        "",
        "This statistical protocol phase is repair-only and depends on the structural repair contracts. A missing or failed dependency blocks this phase before protocol changes run.",
    ] + [f"- {r['dependency']}: `{r['status']}`" for r in rows]) + "\n")
    return ok


