def stage_repaired_dependency_check(ctx: Context) -> bool:
    structural_root = structural_repair_root(ctx)
    stat_root = stat_protocol_repair_root(ctx)
    p1_root = p1_repair_root(ctx)
    require_p1 = requires_p1_dependency_profile(getattr(ctx.args, "phase_profile", ""))
    structural_decision = read_json(structural_root / "decision_summary.json", {})
    stat_decision = read_json(stat_root / "decision_summary.json", {})
    p1_decision = read_json(p1_root / "decision_summary.json", {})
    p1_gate = read_json(p1_root / "gate/rerun_readiness_gate.json", {})
    checks = [
        ("structural_root_exists", structural_root, structural_root.exists(), "structural"),
        ("structural_decision_complete", structural_root / "decision_summary.json", structural_decision.get("status") == "complete", "structural"),
        ("structural_candidate_identity", structural_root / "contracts/candidate_identity_contract.md", structural_decision.get("candidate_identity_repaired") is True, "structural"),
        ("structural_parameter_preservation", structural_root / "contracts/parameter_vector_contract.md", structural_decision.get("parameter_preservation_repaired") is True, "structural"),
        ("structural_original_selected_audit", structural_root / "audit/original_selected_vs_materialized_audit.csv", structural_decision.get("aggregate_materialized_audit_repaired") is True, "structural"),
        ("structural_control_schema", structural_root / "controls/control_schema_repair_report.md", structural_decision.get("control_schema_repaired") is True, "structural"),
        ("structural_fail_closed_gate", structural_root / "gate/wave_gate_fail_closed_contract.json", structural_decision.get("wave_gate_fail_closed_repaired") is True, "structural"),
        ("structural_resume_invalidation", structural_root / "resume/stale_wave_gate_invalidation_report.md", structural_decision.get("resume_stale_gate_invalidation_repaired") is True, "structural"),
        ("stat_root_exists", stat_root, stat_root.exists(), "stat_protocol"),
        ("stat_decision_complete", stat_root / "decision_summary.json", stat_decision.get("status") == "complete", "stat_protocol"),
        ("stat_structural_dependency", stat_root / "preflight/structural_repair_dependency_check.md", stat_decision.get("structural_dependency_pass") is True, "stat_protocol"),
        ("stat_dev_eval", stat_root / "validation/dev_eval_split_manifest.csv", stat_decision.get("dev_eval_repair") is True, "stat_protocol"),
        ("stat_interval_purge", stat_root / "controls/interval_overlap_purge_policy.md", stat_decision.get("interval_purge_repair") is True, "stat_protocol"),
        ("stat_control_cap", stat_root / "controls/control_cap_diagnostics.csv", stat_decision.get("control_cap_repair") is True, "stat_protocol"),
        ("stat_mechanics_cap", stat_root / "mechanics/evidence_cap_application_audit.csv", stat_decision.get("mechanics_cap_policy") is True, "stat_protocol"),
        ("stat_funding_exactness", stat_root / "funding/funding_exactness_summary.csv", stat_decision.get("funding_exactness_classification") is True, "stat_protocol"),
    ]
    if require_p1:
        checks.extend([
        ("p1_root_exists", p1_root, p1_root.exists(), "p1_protocol"),
        ("p1_decision_complete", p1_root / "decision_summary.json", p1_decision.get("status") == "complete", "p1_protocol"),
        ("p1_unresolved_p0_zero", p1_root / "gate/rerun_readiness_gate.json", int(p1_gate.get("unresolved_p0_count", 999)) == 0, "p1_protocol"),
        ("p1_unresolved_p1_zero", p1_root / "gate/rerun_readiness_gate.json", int(p1_gate.get("unresolved_p1_count", 999)) == 0, "p1_protocol"),
        ("p1_mechanics_label_fixed", p1_root / "mechanics/evidence_cap_application_audit.csv", p1_decision.get("P1_MECH_LABEL_001_fixed") is True, "p1_protocol"),
        ("p1_fee_formula_fixed", p1_root / "mechanics/fee_formula_policy.md", p1_decision.get("P1_FEE_FORMULA_001_fixed") is True, "p1_protocol"),
        ("p1_funding_proxy_fixed", p1_root / "funding/funding_exactness_code_audit.csv", p1_decision.get("P1_FUNDING_PROXY_001_fixed") is True, "p1_protocol"),
        ("p1_control_cap_fixed", p1_root / "controls/control_cap_truthfulness_audit.csv", p1_decision.get("P1_CTRL_CAP_001_fixed") is True, "p1_protocol"),
        ("p1_multiple_testing_fixed", p1_root / "validation/multiple_testing_label_gate_audit.csv", p1_decision.get("P1_STAT_MTEST_001_fixed") is True, "p1_protocol"),
        ("p2_mark_lifecycle_active_cap", p1_root / "mechanics/mark_liquidation_lifecycle_audit.csv", str(p1_decision.get("P2_MARK_LIFECYCLE_001_status", "")) == "active_cap", "p1_protocol"),
        ])
    rows = []
    ok = True
    for name, path, decision_pass, group in checks:
        exists = path.exists()
        passed = bool(exists and decision_pass)
        ok = ok and passed
        rows.append({
            "dependency_group": group,
            "dependency": name,
            "path": str(path),
            "artifact_exists": exists,
            "decision_flag_pass": bool(decision_pass),
            "status": "pass" if passed else "fail",
        })
    write_csv(ctx.run_root / "preflight/repaired_dependency_check.csv", rows)
    if require_p1:
        ok = consume_p1_dependency_artifacts(ctx) and ok
    write_text(ctx.run_root / "preflight/repaired_dependency_check.md", "\n".join([
        "# Repaired Dependency Check",
        "",
        f"Structural repair root: `{structural_root}`",
        f"Stat-protocol repair root: `{stat_root}`",
        f"P1 protocol repair root: `{p1_root}`",
        f"Overall status: `{'pass' if ok else 'fail'}`",
        "",
        "Structural repair `next_operator_decision` is not used as a failure condition when the explicit repair booleans pass.",
        "The TSMOM retest stops before wave execution if any required structural, stat, or P1 repair artifact or decision flag is missing.",
        "",
    ] + [f"- {r['dependency_group']} / {r['dependency']}: `{r['status']}`" for r in rows]) + "\n")
    return ok


