    ("fee_model_audit", "mechanics/fee_model_audit.csv", True),
    ("fee_formula_policy", "mechanics/fee_formula_policy.md", True),
    ("account_fee_scenario_manifest", "mechanics/account_fee_scenario_manifest.csv", True),
    ("mechanics_cap_label_policy", "mechanics/mechanics_cap_label_policy.md", True),
    ("mark_lifecycle_active_cap_policy", "mechanics/mark_lifecycle_active_cap_policy.md", True),
    ("mark_liquidation_lifecycle_audit", "mechanics/mark_liquidation_lifecycle_audit.csv", True),
    ("funding_boundary_policy", "funding/funding_boundary_policy.md", True),
