def stage_p2_resume_config_hash_repair(ctx: Context) -> None:
    write_text(ctx.run_root / "resume/frozen_config_hash_policy.md", "# Frozen Config Hash Policy\n\nWave gate reuse requires matching gate logic, identity contract, parameter contract, code hash, phase profile hash, source definition manifest hash, translation audit hash, prelaunch eligibility hash, wave definition hash, K0/root hashes, repair-root hashes, fee scenario manifest hash, and funding coverage manifest hash.\n")
    dummy_wave_dirs = {"root": ctx.run_root / "resume/policy_probe"}
    dummy_wave_dirs["root"].mkdir(parents=True, exist_ok=True)
    _, digest = build_wave_gate_hash_manifest(ctx, "policy_probe", dummy_wave_dirs)
    old_run = failed_wave_run_root(ctx)
    old_gate = read_json(old_run / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json", {})
    stale = old_gate.get("wave_gate_hash_digest") != digest
    report = {"old_gate_path": str(old_run / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json"), "old_wave_gate_hash_digest": old_gate.get("wave_gate_hash_digest", "missing"), "current_policy_probe_hash_digest": digest, "stale_gate_detected": bool(stale), "required_action": "invalidate_old_gate_and_rerun_wave" if stale else "gate_reusable"}
    write_json(ctx.run_root / "resume/stale_wave_gate_invalidation_report.json", report)
    write_text(ctx.run_root / "resume/stale_wave_gate_invalidation_report.md", f"# Stale Wave Gate Invalidation Report\n\nStale gate detected: `{stale}`. Gate reuse now requires frozen source/config/data hash agreement.\n")


