    source = active_prior_benchmark_root(ctx.args)
    prior = read_csv_safe(source / "controls/control_cap_diagnostics.csv")
    if prior.empty:
        prior = read_csv_safe(source / "waves/scheduled_tsmom_engine__wave_001/controls/control_cap_diagnostics.csv")
