        for _, r in prior.iterrows():
            diagnostic = parse_bool_value(r.get("diagnostic_only_not_evidence", str(r.get("control_mode", "")).lower() == "diagnostic"), default=False)
            partial = parse_bool_value(r.get("diagnostic_retention_partial", r.get("diagnostic_partial_purge", False)), default=False) or parse_bool_value(r.get("diagnostic_timeout_hit", False), default=False)
