def month_start(series: pd.Series) -> pd.Series:
    return pd.to_datetime(series.astype(str) + "-01", utc=True, errors="coerce")


def assign_train_internal_segments(months: pd.DataFrame) -> tuple[pd.DataFrame, pd.Timestamp | None]:
    if months.empty or "month" not in months.columns:
        return months.copy(), None
    out = months.copy()
    out["_month_start"] = month_start(out["month"])
    valid = sorted(out["_month_start"].dropna().unique())
    if not valid:
        out["train_internal_segment"] = "full_train_diagnostic_only"
        return out, None
    split_idx = max(1, len(valid) // 2)
    split_ts = pd.Timestamp(valid[split_idx]).tz_convert("UTC") if split_idx < len(valid) else pd.Timestamp(valid[-1]).tz_convert("UTC")
    out["train_internal_segment"] = np.where(out["_month_start"] < split_ts, "proposal_train_segment", "internal_eval_train_segment")
    return out, split_ts


def dev_eval_summary(months: pd.DataFrame, regimes: pd.DataFrame | None = None) -> pd.DataFrame:
    if months.empty:
        return pd.DataFrame()
    seg, _ = assign_train_internal_segments(months)
    rows: list[dict[str, Any]] = []
    for cid, g in seg.groupby("candidate_id", dropna=False):
        for segment in ["proposal_train_segment", "internal_eval_train_segment"]:
            sub = g[g["train_internal_segment"].astype(str).eq(segment)]
            events = int(pd.to_numeric(sub.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
            active_symbols = int(sub[sub.get("events", pd.Series(dtype=float)).astype(float) > 0]["symbol"].nunique()) if "symbol" in sub.columns and not sub.empty else 0
            active_months = int(sub[sub.get("events", pd.Series(dtype=float)).astype(float) > 0]["month"].nunique()) if "month" in sub.columns and not sub.empty else 0
            net = float(pd.to_numeric(sub.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
            tier_labels = tier_representations(sub.get("symbol", pd.Series(dtype=str))) if "symbol" in sub.columns else ""
            rows.append({"candidate_id": cid, "train_internal_segment": segment, "events": events, "net_R": net, "active_symbols": active_symbols, "active_months": active_months, "tier_representation": tier_labels})
    return pd.DataFrame(rows)


def tier_representations(symbols: pd.Series) -> str:
    vals = sorted(set(symbols.dropna().astype(str)))
    tiers = set()
    major = {"PF_XBTUSD", "PF_ETHUSD", "PF_SOLUSD"}
    for s in vals:
        if s in major:
            tiers.add("Tier_A")
        elif s.startswith("PF_"):
            tiers.add("Tier_B_or_C")
    return ";".join(sorted(tiers))


def proposal_only_selection(aggregate: pd.DataFrame, months: pd.DataFrame, budget: int = 25) -> pd.DataFrame:
    if aggregate.empty or months.empty:
        return pd.DataFrame()
    seg, _ = assign_train_internal_segments(months)
    proposal = seg[seg["train_internal_segment"].astype(str).eq("proposal_train_segment")].copy()
    score = proposal.groupby("candidate_id", dropna=False).agg(proposal_events=("events", "sum"), proposal_net_R=("net_R", "sum")).reset_index()
    meta_cols = [c for c in ["candidate_id", "definition_id", "hypothesis_id", "family", "family_engine_id", "row_semantics"] if c in aggregate.columns]
    meta = aggregate[meta_cols].drop_duplicates("candidate_id") if meta_cols else pd.DataFrame()
    out = score.merge(meta, on="candidate_id", how="left").sort_values(["proposal_net_R", "proposal_events"], ascending=False).head(budget).copy()
    out["selection_segment_used"] = "proposal_train_segment"
    out["candidate_status"] = "proposed_from_train_internal_segment_only"
    return out


def apply_dev_eval_caps(summary: pd.DataFrame, regimes: pd.DataFrame | None = None, min_events: int = 20, min_symbols: int = 2, min_months: int = 2) -> pd.DataFrame:
    if summary.empty:
        return pd.DataFrame()
    piv = summary.pivot_table(index="candidate_id", columns="train_internal_segment", values=["events", "active_symbols", "active_months", "net_R"], aggfunc="first").fillna(0)
    rows = []
    for cid in piv.index:
        get = lambda field, seg: safe_float(piv.get((field, seg), pd.Series({cid: 0})).loc[cid], 0.0) if (field, seg) in piv.columns else 0.0
        ie_events = get("events", "internal_eval_train_segment")
        ie_symbols = get("active_symbols", "internal_eval_train_segment")
        ie_months = get("active_months", "internal_eval_train_segment")
        cap = ie_events < min_events or ie_symbols < min_symbols or ie_months < min_months
        rows.append({
            "candidate_id": cid,
            "proposal_events": int(get("events", "proposal_train_segment")),
            "internal_eval_events": int(ie_events),
            "proposal_net_R": get("net_R", "proposal_train_segment"),
            "internal_eval_net_R": get("net_R", "internal_eval_train_segment"),
            "proposal_active_symbols": int(get("active_symbols", "proposal_train_segment")),
            "proposal_active_months": int(get("active_months", "proposal_train_segment")),
            "internal_eval_active_symbols": int(ie_symbols),
            "internal_eval_active_months": int(ie_months),
            "coverage_status": "internal_eval_sample_limited_cap" if cap else "pass",
            "evidence_cap_reason": "internal_eval_sample_limited_cap" if cap else "",
        })
    return pd.DataFrame(rows)


def stage_dev_eval_selection_repair(ctx: Context) -> None:
    aggregate = load_stopped_wave_aggregate(ctx)
    months = load_stopped_wave_months(ctx)
    regimes = load_stopped_wave_regimes(ctx)
    segmented, split_ts = assign_train_internal_segments(months)
    summary = dev_eval_summary(months, regimes)
    coverage = apply_dev_eval_caps(summary, regimes)
    proposed = proposal_only_selection(aggregate, months, budget=25 if ctx.args.smoke else 100)
    old_selected = read_csv_safe(stopped_wave_root(ctx) / "selection/materialization_selection.csv")
    overlap_rows = []
    old_ids = set(old_selected.get("candidate_id", pd.Series(dtype=str)).astype(str)) if not old_selected.empty else set()
    proposed_ids = set(proposed.get("candidate_id", pd.Series(dtype=str)).astype(str)) if not proposed.empty else set()
    for cid in sorted(old_ids | proposed_ids):
        overlap_rows.append({
            "candidate_id": cid,
            "selected_by_old_full_train_policy": cid in old_ids,
            "selected_by_repaired_proposal_policy": cid in proposed_ids,
            "selection_segment_used": "full_train_diagnostic_only" if cid in old_ids else "proposal_train_segment",
            "cap_applied": "aggregate_screen_only_full_train_selection_bias_cap" if cid in old_ids else "",
            "proposal_list_frozen_before_internal_eval_scoring": True,
        })
    write_csv(ctx.run_root / "validation/dev_eval_split_manifest.csv", [{
        "split_policy": "deterministic_chronological_50_50_train_internal",
        "proposal_segment_label": "proposal_train_segment",
        "internal_eval_segment_label": "internal_eval_train_segment",
        "full_train_label": "full_train_diagnostic_only",
        "split_ts": str(split_ts) if split_ts is not None else "",
        "internal_eval_is_holdout_or_validation": False,
    }])
    write_csv(ctx.run_root / "selection/dev_eval_aware_proposal_candidates.csv", proposed)
    write_csv(ctx.run_root / "validation/proposal_scoring_overlap_audit.csv", overlap_rows)
    write_csv(ctx.run_root / "validation/dev_eval_coverage_audit.csv", coverage)
    balance = coverage["coverage_status"].value_counts().to_dict() if not coverage.empty else {}
    write_text(ctx.run_root / "validation/dev_eval_segment_balance_report.md", "\n".join([
        "# Dev/Eval Segment Balance Report",
        "",
        "The internal eval segment is train-internal only. It is not final validation and not holdout evidence.",
        f"Split timestamp: `{split_ts}`",
        f"Coverage status counts: `{balance}`",
    ]) + "\n")
    write_text(ctx.run_root / "selection/dev_eval_aware_selection_policy.md", "# Dev/Eval-Aware Selection Policy\n\nMaterialization proposals may use only `proposal_train_segment`. `internal_eval_train_segment` is train-internal and may be scored only after the proposal list is frozen. `full_train_diagnostic_only` is reported only after labels are frozen and must not alter candidate selection. Any historical full-train-selected candidate receives `aggregate_screen_only_full_train_selection_bias_cap`.\n")
    write_text(ctx.run_root / "validation/sparse_family_dev_eval_fallback_policy.md", "# Sparse Family Dev/Eval Fallback Policy\n\nIf a candidate or family cannot support train-internal proposal/eval separation, preserve it as `sample_limited_mechanism_pending_validation`. Sparse support is not family rejection and cannot receive level 4/5 evidence labels.\n")


def stage_multiple_testing_and_cluster_policy(ctx: Context) -> None:
    aggregate = load_stopped_wave_aggregate(ctx)
    if aggregate.empty:
        aggregate = read_csv_safe(ctx.run_root / "selection/dev_eval_aware_proposal_candidates.csv")
    rows = []
    family_rows = []
    if not aggregate.empty:
        cols = [c for c in ["family_engine_id", "hypothesis_id", "row_semantics", "definition_id"] if c in aggregate.columns]
        key_cols = [c for c in ["family_engine_id", "hypothesis_id", "row_semantics"] if c in aggregate.columns]
        agg = aggregate.copy()
        agg["candidate_cluster_id"] = [stable_hash(*(str(r.get(c, "")) for c in key_cols), n=16) for _, r in agg.iterrows()]
        for cid, g in agg.groupby("candidate_cluster_id", dropna=False):
            rows.append({"candidate_cluster_id": cid, "family_engine_id": g.get("family_engine_id", pd.Series([""])).iloc[0], "hypothesis_id": g.get("hypothesis_id", pd.Series([""])).iloc[0], "row_semantics": g.get("row_semantics", pd.Series([""])).iloc[0], "cluster_member_count": len(g), "cluster_representative_allowed_for_deeper_validation": True, "single_sharp_point_label_blocked": True})
        for fam, g in agg.groupby("family_engine_id", dropna=False) if "family_engine_id" in agg.columns else []:
            family_rows.append({"family_engine_id": fam, "candidate_rows": len(g), "effective_trial_count": int(g["candidate_cluster_id"].nunique()), "family_multiplicity_burden": "high" if len(g) > 100 else "medium", "level5_requires_neighborhood_or_fold_stability": True})
    write_csv(ctx.run_root / "validation/candidate_overlap_clusters.csv", rows)
    write_csv(ctx.run_root / "validation/family_multiple_testing_manifest.csv", family_rows)
    write_csv(ctx.run_root / "validation/family_effective_trial_count.csv", family_rows)
    write_text(ctx.run_root / "validation/parameter_neighborhood_policy.md", "# Parameter Neighborhood Policy\n\nSingle sharp parameter points cannot receive level 5 evidence. Cluster representatives may be selected for deeper validation; nonmaterialized cluster members remain `pending_materialization` or `pending_compute`.\n")
    write_text(ctx.run_root / "validation/evidence_label_multiple_testing_gate.md", "# Evidence Label Multiple-Testing Gate\n\nLevel 5 requires parameter-neighborhood or fold/stability support. Family-level effective trial counts must be reported before ranking. The report must not use best-candidate language for isolated points.\n")


def engine_embargo_bars(engine_id: str, hold_bars: int | float | str) -> int:
    h = int(max(1, safe_float(hold_bars, 1)))
    fixed = {
        "scheduled_tsmom_engine": h,
        "liquid_continuation_breakout_engine": h,
        "prior_high_reclaim_engine": h,
        "compression_breakout_engine": h,
        "retest_reclaim_lifecycle_engine": max(h, 24),
        "funding_crowding_engine": max(h, 96),
        "session_calendar_engine": max(h, 24),
    }
    return fixed.get(engine_id, h)


def interval_overlap_mask(a_start: pd.Series, a_end: pd.Series, b_start: pd.Series, b_end: pd.Series) -> pd.Series:
    return (a_start <= b_end) & (b_start <= a_end)


def audit_interval_purge(events: pd.DataFrame, controls: pd.DataFrame, meta: pd.DataFrame | None = None) -> pd.DataFrame:
    if events.empty or controls.empty:
        return pd.DataFrame()
    ev = events.copy()
    ctrl = controls.copy()
    for df in [ev, ctrl]:
        for col in ["decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts", "effective_exit_ts_for_purge", "interval_end_ts", "candidate_window_end"]:
            if col in df.columns:
                df[col] = pd.to_datetime(df[col], utc=True, errors="coerce")
    ev_start = ev.get("entry_ts", ev.get("decision_ts"))
    ev_end = interval_end_series(ev, ev_start)
    ev = ev.assign(_ev_start=ev_start, _ev_end=ev_end)
    rows = []
    for cid, cgrp in ctrl.groupby("matched_candidate_id", dropna=False):
        egrp = ev[ev.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(str(cid))]
        if egrp.empty:
            continue
        engine_id = str(egrp.get("family_engine_id", pd.Series([""])).iloc[0])
        hold_bars = egrp.get("hold_bars", pd.Series([0])).iloc[0] if "hold_bars" in egrp.columns else 0
        embargo = pd.Timedelta(minutes=5 * engine_embargo_bars(engine_id, hold_bars))
        checked = len(cgrp)
        removed_overlap = 0
        removed_embargo = 0
        for _, c in cgrp.iterrows():
            c_start = pd.to_datetime(c.get("entry_ts", c.get("control_decision_ts", c.get("decision_ts"))), utc=True, errors="coerce")
            c_end = pd.to_datetime(
                c.get("effective_exit_ts_for_purge", c.get("exit_interval_end_ts", c.get("interval_end_ts", c.get("candidate_window_end", c.get("exit_ts", c_start))))),
                utc=True,
                errors="coerce",
            )
            same_symbol = egrp[egrp.get("symbol", pd.Series(dtype=str)).astype(str).eq(str(c.get("control_symbol", c.get("symbol", ""))))]
            if same_symbol.empty or pd.isna(c_start) or pd.isna(c_end):
                continue
            overlap = bool(((same_symbol["_ev_start"] <= c_end) & (c_start <= same_symbol["_ev_end"])).any())
            embargo_hit = bool(((same_symbol["_ev_start"] - embargo <= c_end) & (c_start <= same_symbol["_ev_end"] + embargo)).any())
            removed_overlap += int(overlap)
            removed_embargo += int((not overlap) and embargo_hit)
        rows.append({"candidate_id": cid, "controls_checked": checked, "controls_removed_by_interval_overlap": removed_overlap, "controls_removed_by_embargo": removed_embargo, "controls_retained_after_purge": max(0, checked - removed_overlap - removed_embargo), "embargo_minutes": embargo.total_seconds() / 60, "purge_status": "fail" if removed_overlap or removed_embargo else "pass"})
    return pd.DataFrame(rows)


def same_bar_interval_semantics_audit_frame(events: pd.DataFrame) -> pd.DataFrame:
    if events.empty:
        return pd.DataFrame([{
            "check": "same_bar_interval_semantics",
            "status": "pass",
            "event_rows": 0,
            "raw_zero_length_rows": 0,
            "effective_zero_length_rows": 0,
            "same_bar_adverse_stop_rows": 0,
            "detail": "empty_event_ledger",
        }])
    work = events.copy()
    for col in ["entry_ts", "exit_ts", "exit_interval_end_ts", "effective_exit_ts_for_purge", "candidate_window_end"]:
        if col in work.columns:
            work[col] = pd.to_datetime(work[col], utc=True, errors="coerce")
    entry = pd.to_datetime(work.get("entry_ts", pd.Series(pd.NaT, index=work.index)), utc=True, errors="coerce")
    raw_exit = pd.to_datetime(work.get("exit_ts", pd.Series(pd.NaT, index=work.index)), utc=True, errors="coerce")
    effective_exit = interval_end_series(work, raw_exit)
    same_bar_stop = parse_bool_series(work.get("same_bar_adverse_stop_interval_cap", pd.Series(False, index=work.index)), default=False)
    raw_zero = entry.notna() & raw_exit.notna() & (raw_exit <= entry)
    effective_zero = entry.notna() & effective_exit.notna() & (effective_exit <= entry)
    return pd.DataFrame([{
        "check": "same_bar_interval_semantics",
        "status": "fail" if int((effective_zero & same_bar_stop).sum()) else "pass",
        "event_rows": int(len(work)),
        "raw_zero_length_rows": int(raw_zero.sum()),
        "effective_zero_length_rows": int(effective_zero.sum()),
        "same_bar_adverse_stop_rows": int(same_bar_stop.sum()),
        "same_bar_rows_with_nonzero_effective_interval": int((raw_zero & same_bar_stop & ~effective_zero).sum()),
        "detail": "same-bar adverse stops use exit_interval_end_ts/effective_exit_ts_for_purge for purge, embargo, and funding windows",
    }])


def stage_interval_overlap_control_purge_repair(ctx: Context) -> None:
    root = stopped_wave_root(ctx)
    manifest = read_csv_safe(root / "materialized/materialized_ledger_manifest.csv")
    controls = read_parquet_safe(root / "controls/control_ledger/control_ledger.parquet")
    ledgers = []
    for _, m in manifest.head(50 if ctx.args.smoke else len(manifest)).iterrows():
        p = stopped_engine_wave_run_root(ctx) / str(m.get("path", ""))
        if p.exists():
            df = read_parquet_safe(p)
            if not df.empty:
                ledgers.append(df)
    events = pd.concat(ledgers, ignore_index=True, sort=False) if ledgers else pd.DataFrame()
    audit = audit_interval_purge(events, controls, manifest)
    write_csv(ctx.run_root / "controls/interval_overlap_purge_audit.csv", audit)
    write_text(ctx.run_root / "controls/interval_overlap_purge_policy.md", "# Interval Overlap Purge Policy\n\nControls must be real matched null windows. Same-symbol controls are removed if their interval overlaps a candidate interval, candidate max holding horizon, or engine-specific embargo buffer. Removed rows are counted by overlap and embargo reason; missing purge diagnostics block level 4 evidence.\n")
    write_text(ctx.run_root / "controls/embargo_policy_by_engine.yaml", "\n".join([
        "scheduled_tsmom_engine: max_candidate_hold_horizon",
        "liquid_continuation_breakout_engine: max_candidate_hold_horizon",
        "prior_high_reclaim_engine: max_candidate_hold_horizon",
        "compression_breakout_engine: max_candidate_hold_horizon",
        "retest_reclaim_lifecycle_engine: max(max_candidate_hold_horizon, 24_bars)",
        "funding_crowding_engine: max(max_candidate_hold_horizon, 96_bars)",
        "session_calendar_engine: max(max_candidate_hold_horizon, 24_bars)",
    ]) + "\n")


def stage_control_cap_reporting_repair(ctx: Context) -> None:
    root = stopped_wave_root(ctx)
    controls = read_parquet_safe(root / "controls/control_ledger/control_ledger.parquet")
    summary = read_csv_safe(root / "controls/control_summary.csv")
    purge = read_csv_safe(ctx.run_root / "controls/interval_overlap_purge_audit.csv")
    rows = []
    if not summary.empty:
        for _, r in summary.iterrows():
            cid = r.get("candidate_id")
            c = controls[controls.get("matched_candidate_id", pd.Series(dtype=str)).astype(str).eq(str(cid))] if not controls.empty else pd.DataFrame()
            p = purge[purge.get("candidate_id", pd.Series(dtype=str)).astype(str).eq(str(cid))] if not purge.empty else pd.DataFrame()
            available = int(len(c))
            removed_overlap = int(pd.to_numeric(p.get("controls_removed_by_interval_overlap", pd.Series([0])), errors="coerce").fillna(0).sum()) if not p.empty else 0
            removed_embargo = int(pd.to_numeric(p.get("controls_removed_by_embargo", pd.Series([0])), errors="coerce").fillna(0).sum()) if not p.empty else 0
            removed_purge = removed_overlap + removed_embargo
            retained = min(max(0, available - removed_purge), 5000)
            cap_applied = available > 5000
            rows.append({"candidate_id": cid, "total_matched_controls_before_cap": available, "controls_retained": retained, "controls_removed_by_interval_purge": removed_purge, "controls_removed_by_embargo": removed_embargo, "controls_removed_by_cap": max(0, available - removed_purge - retained), "cap_applied": cap_applied, "cap_method": "deterministic_stratified_by_symbol_month_regime" if cap_applied else "all_controls", "cap_seed": ctx.args.seed if cap_applied else "", "stratification_basis": "symbol;month;regime;row_semantics", "cap_scope": "benchmark_only_until_predeclared_for_evidence" if cap_applied else "evidence_eligible_all_controls", "level4_allowed_by_cap_reporting": not cap_applied})
    write_csv(ctx.run_root / "controls/control_cap_diagnostics.csv", rows)
    contradictory = any(bool(r.get("cap_applied")) and str(r.get("cap_method")) == "" for r in rows)
    write_text(ctx.run_root / "controls/control_retention_policy_report.md", f"# Control Retention Policy Report\n\nContradictory cap diagnostics: `{contradictory}`\nFor evidence, retained-control caps require deterministic stratification and full available/retained/removed reporting. Missing or contradictory diagnostics block level 4.\n")


def materialized_sample_from_stopped_wave(ctx: Context, limit: int = 20) -> pd.DataFrame:
    root = stopped_wave_root(ctx)
    manifest = read_csv_safe(root / "materialized/materialized_ledger_manifest.csv")
    frames = []
    for _, m in manifest.head(limit).iterrows():
        p = stopped_engine_wave_run_root(ctx) / str(m.get("path", ""))
        if p.exists():
            df = read_parquet_safe(p)
            if not df.empty:
                frames.append(df)
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def apply_evidence_cap_gate(row: Mapping[str, Any]) -> tuple[str, str]:
    reasons = []
    if parse_bool_value(row.get("interval_purge_failed", False), default=False):
        reasons.append("interval_overlap_purge_failed")
    if parse_bool_value(row.get("control_cap_missing_or_contradictory", False), default=False):
        reasons.append("control_cap_reporting_incomplete")
    if parse_bool_value(row.get("funding_proxy_used", False), default=False) or str(row.get("funding_exactness", "")).startswith("proxy"):
        reasons.append("funding_proxy_cap")
    if safe_float(row.get("slippage_R"), 0.0) == 0.0:
        reasons.append("base_no_slippage_event_ledger_requires_stress")
    if parse_bool_value(row.get("mark_liquidation_diagnostic_only", False), default=False):
        reasons.append("mark_liquidation_diagnostic_only_cap")
    if reasons:
        requested = str(row.get("requested_evidence_level", "level_4_event_ledger_plus_real_controls"))
        if requested.startswith("level_4"):
            return "level_4_event_ledger_plus_real_controls__mechanics_capped", ";".join(sorted(set(reasons)))
        return "level_3_event_level_trade_ledger_capped", ";".join(sorted(set(reasons)))
    return str(row.get("requested_evidence_level", "level_4_event_ledger_plus_real_controls")), ""


def stage_mechanics_cap_and_fee_model_repair(ctx: Context) -> None:
    ev = materialized_sample_from_stopped_wave(ctx, limit=5 if ctx.args.smoke else 25)
    rows = []
    if not ev.empty:
        for cid, g in ev.groupby("candidate_id", dropna=False):
            slippage_zero = bool((pd.to_numeric(g.get("slippage_R", pd.Series(dtype=float)), errors="coerce").fillna(0) == 0).all()) if "slippage_R" in g.columns else True
            funding_proxy = any_true(g.get("funding_proxy_used", pd.Series([False])), default=True) if "funding_proxy_used" in g.columns else True
            mark_diag = bool(str(g.get("index_price_source", pd.Series(["unavailable"])).iloc[0]) == "unavailable")
            label, cap = apply_evidence_cap_gate({"funding_proxy_used": funding_proxy, "slippage_R": 0.0 if slippage_zero else -0.01, "mark_liquidation_diagnostic_only": mark_diag, "requested_evidence_level": "level_4_event_ledger_plus_real_controls"})
            rows.append({"candidate_id": cid, "slippage_zero_base": slippage_zero, "funding_proxy_used": funding_proxy, "mark_liquidation_diagnostic_only": mark_diag, "clean_level4_allowed": cap == "", "evidence_level_after_caps": label, "evidence_cap_reason": cap})
    write_csv(ctx.run_root / "mechanics/evidence_cap_application_audit.csv", rows)
    write_csv(ctx.run_root / "mechanics/fee_model_audit.csv", [
        {"fee_scenario": "kraken_current_account_zero_fee", "maker_fee_bps": 0, "taker_fee_bps": 0, "fee_source": "operator_attested_current_account_state", "permanent_assumption": False},
        {"fee_scenario": "fee_reversion_standard", "maker_fee_bps": "standard_public_or_configured", "taker_fee_bps": "standard_public_or_configured", "fee_source": "fallback_public_baseline_or_existing_artifact", "permanent_assumption": False},
        {"fee_scenario": "fee_reversion_partial", "maker_fee_bps": 0, "taker_fee_bps": "partial_standard", "fee_source": "stress_scenario", "permanent_assumption": False},
        {"fee_scenario": "slippage_only_zero_fee", "maker_fee_bps": 0, "taker_fee_bps": 0, "fee_source": "stress_scenario", "permanent_assumption": False},
    ])
    write_csv(ctx.run_root / "mechanics/slippage_model_audit.csv", [{"base_slippage_R_zero_requires_stress": True, "cap_label": "base_no_slippage_event_ledger_requires_stress"}])
    write_csv(ctx.run_root / "mechanics/mark_liquidation_model_audit.csv", [{"mark_liquidation_model_scope": "diagnostic_only_unless_mark_path_and_sizing_support_liquidation", "liquidation_safety_claim_allowed": False}])
    write_text(ctx.run_root / "mechanics/mechanics_cap_policy.md", "# Mechanics Cap Policy\n\nZero-slippage base ledgers, proxy funding, diagnostic-only mark/liquidation modeling, and zero-fee-only assumptions are label-active caps. They do not alter signal generation, but they prevent clean level 4/5 labels until stress/reversion diagnostics pass.\n")
    write_text(ctx.run_root / "mechanics/funding_proxy_policy.md", "# Funding Proxy Policy\n\nProxy funding cannot support clean evidence labels. Funding-crossing rows require exact funding or explicit adverse funding stress. No-funding diagnostics are diagnostic only.\n")
    write_text(ctx.run_root / "mechanics/fee_scenario_label_policy.md", "# Fee Scenario Label Policy\n\nZero-fee may describe the operator-attested current Kraken account state only. Candidate reports must also include fee reversion, partial reversion, and slippage-only zero-fee scenarios; zero-fee does not remove slippage, funding, mark/liquidation, lifecycle, or adverse path stress.\n")


def stage_funding_exactness_classification(ctx: Context) -> None:
    data_root = resolve_path(ctx.args.kraken_data_root)
    funding_dir = data_root / "parquet/funding"
    rows = []
    for p in sorted(funding_dir.glob("*.parquet"))[:20 if ctx.args.smoke else 10000]:
        df = read_parquet_safe(p)
        if df.empty:
            continue
        ts = pd.to_datetime(df.get("timestamp", pd.Series(dtype=str)), utc=True, errors="coerce").dropna()
        symbol = str(df.get("venue_symbol", pd.Series([p.stem.split('_')[0]])).dropna().astype(str).iloc[0]) if "venue_symbol" in df.columns and not df["venue_symbol"].dropna().empty else p.stem.split("_")[0]
        earliest = ts.min() if len(ts) else pd.NaT
        latest = ts.max() if len(ts) else pd.NaT
        pre_start_gap = bool(pd.notna(earliest) and earliest > ctx.start)
        rows.append({"symbol": symbol, "earliest_funding_ts": str(earliest), "latest_funding_ts": str(latest), "funding_rows": int(len(ts)), "covers_full_train_window": not pre_start_gap and pd.notna(latest), "funding_exactness_class": "partial_exact_with_proxy_needed" if pre_start_gap else "exact_for_train_window", "proxy_required_before_earliest": pre_start_gap})
    out = pd.DataFrame(rows)
    write_csv(ctx.run_root / "funding/funding_coverage_by_symbol_date.csv", out)
    summary = out["funding_exactness_class"].value_counts().reset_index().rename(columns={"index": "funding_exactness_class", "funding_exactness_class": "symbol_count"}) if not out.empty else pd.DataFrame()
    write_csv(ctx.run_root / "funding/funding_exactness_summary.csv", summary)
    write_csv(ctx.run_root / "funding/exact_funding_subperiod_diagnostic.csv", out.assign(result_scope="exact_funding_only_subperiod_diagnostic_not_selection"))
    write_text(ctx.run_root / "funding/funding_cap_impact_report.md", "# Funding Cap Impact Report\n\nReport full-period proxy-adjusted, exact-funding-only subperiod, no-funding diagnostic-only, and adverse-funding stress views. Exact-funding-only subperiod diagnostics cannot drive selection when they create recency bias.\n")


def stage_tests_and_smoke(ctx: Context) -> None:
    if getattr(getattr(ctx, "args", None), "phase_profile", "") == TSMOM_REDESIGNED_EXECUTION_BINDING_AUDIT_PHASE_PROFILE:
        stage_execution_binding_tests_and_smoke(ctx)
        return
    write_text(ctx.run_root / "tests/stat_protocol_tests_and_smoke_plan.md", "# Statistical Protocol Tests And Smoke\n\nExternal verification must run py_compile, unit tests, statistical protocol repair smoke, and v0 tranche compatibility smoke. This stage records required commands only and does not launch real waves.\n")


def read_text_safe(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8", errors="replace")
    except Exception:
        return ""


def stage_repaired_benchmark_rerun(ctx: Context) -> None:
    bench, projection, audit = run_repaired_engine_benchmark(ctx)
    write_csv(ctx.run_root / "benchmark/repaired_engine_benchmark_summary.csv", bench)
    write_csv(ctx.run_root / "benchmark/repaired_runtime_projection_by_engine.csv", projection)
    write_csv(ctx.run_root / "benchmark/repaired_aggregate_materialized_probe_audit.csv", audit)
    total_hours = float(pd.to_numeric(projection.get("projected_hours", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not projection.empty else float("inf")
    failures = int((audit.get("status", pd.Series(dtype=str)) == "fail").sum()) if not audit.empty else 1
    defs = read_csv_safe(ctx.run_root / "budget/repaired_candidate_definition_budget_manifest.csv")
    missing = sorted(set(REQUIRED_RANKABLE_ENGINES) - set(defs.get("family_engine_id", pd.Series(dtype=str)).astype(str))) if not defs.empty else list(REQUIRED_RANKABLE_ENGINES)
    mcs_exists = (ctx.run_root / "benchmark/materialization_controls_stress_benchmark.csv").exists()
    scoring_scan = read_json(ctx.run_root / "seal/protected_scoring_artifact_scan.json", {"status": "missing"})
    gate_blockers = []
    if total_hours > 168:
        gate_blockers.append("projected_runtime_gt_168h")
    if missing:
        gate_blockers.append("required_rankable_engine_zero_definitions")
    if failures:
        gate_blockers.append("aggregate_materialized_probe_audit_fails")
    if scoring_scan.get("status") != "pass":
        gate_blockers.append("protected_scoring_or_event_timestamp_violation")
    if not mcs_exists:
        gate_blockers.append("materialization_controls_stress_benchmark_missing")
    status = "go" if not gate_blockers else "no_go"
    analysis = {
        "gate_status": status,
        "gate_blockers": gate_blockers,
        "planned_candidate_definitions": int(len(defs)),
        "projected_aggregate_evaluation_hours": total_hours,
        "projected_runtime_bucket": "above_168_hours" if total_hours > 168 else ("under_168_hours" if total_hours > 96 else "under_96_hours"),
        "all_required_engines_have_definitions": not bool(missing),
        "aggregate_materialized_audit_pass": failures == 0,
        "protected_scoring_event_scan_pass": scoring_scan.get("status") == "pass",
        "materialization_controls_stress_benchmark_exists": mcs_exists,
        "event_sampling_used": False,
    }
    write_json(ctx.run_root / "benchmark/repaired_full_budget_projection_analysis.json", analysis)
    write_text(ctx.run_root / "benchmark/repaired_operator_go_no_go_after_engine_benchmark.md", "\n".join([
        "# Repaired Operator Go/No-Go After Engine Benchmark",
        "",
        f"Status: `{status}`",
        f"Projected aggregate runtime hours: `{total_hours:.3f}`",
        f"Projected runtime bucket: `{analysis['projected_runtime_bucket']}`",
        f"Aggregate/materialized mismatch: `{failures > 0}`",
        f"Gate blockers: `{gate_blockers}`",
        "This gate is for a repaired priority tranche. It does not authorize a full aggregate sweep.",
    ]) + "\n")


def stage_operator_go_no_go_report(ctx: Context) -> None:
    analysis = read_json(ctx.run_root / "benchmark/repaired_full_budget_projection_analysis.json", {})
    coverage = read_csv_safe(ctx.run_root / "budget/required_engine_coverage_audit.csv")
    universe = read_csv_safe(ctx.run_root / "universe/family_candidate_symbol_counts.csv")
    mcs = read_csv_safe(ctx.run_root / "benchmark/materialization_controls_stress_benchmark.csv")
    missing_engines = coverage[coverage.get("status", pd.Series(dtype=str)).astype(str) != "pass"]["family_engine_id"].astype(str).tolist() if not coverage.empty else list(REQUIRED_RANKABLE_ENGINES)
    if missing_engines:
        decision = "repair_candidate_compiler_next"
    elif universe.empty or bool((pd.to_numeric(universe.get("after_symbol_count", pd.Series(dtype=float)), errors="coerce").fillna(0) <= 0).any()):
        decision = "repair_universe_fanout_next"
    elif mcs.empty:
        decision = "repair_materialization_controls_next"
    elif safe_float(analysis.get("projected_aggregate_evaluation_hours"), float("inf")) > 168:
        decision = "repair_engine_vectorization_next"
    elif analysis.get("gate_status") == "go":
        decision = "launch_priority_tranche_next"
    else:
        decision = "blocked_by_protocol_issue"
    report = [
        "# Operator Go/No-Go Report",
        "",
        f"Recommended next decision: `{decision}`",
        f"Repaired gate status: `{analysis.get('gate_status', 'missing')}`",
        f"Projected aggregate runtime hours: `{safe_float(analysis.get('projected_aggregate_evaluation_hours'), float('nan')):.3f}`",
        f"Required engines with definitions: `{len(REQUIRED_RANKABLE_ENGINES) - len(missing_engines)}/{len(REQUIRED_RANKABLE_ENGINES)}`",
        "",
        "If the broader full pass remains too slow, run the repaired priority tranche first. Unrun definitions remain `pending_compute`.",
    ]
    write_text(ctx.run_root / "decision/operator_go_no_go_report.md", "\n".join(report) + "\n")
    write_json(ctx.run_root / "decision/operator_go_no_go_decision.json", {"next_operator_decision": decision, "analysis": analysis, "missing_engines": missing_engines, "ts_utc": utc_now()})


def stage_analysis_ready(ctx: Context) -> None:
    aggregate = pd.read_parquet(ctx.run_root / "coarse/all_candidate_aggregate_summary.parquet") if (ctx.run_root / "coarse/all_candidate_aggregate_summary.parquet").exists() else pd.DataFrame()
    selected = read_csv_safe(ctx.run_root / "selection/materialization_selection.csv")
    near = read_csv_safe(ctx.run_root / "selection/near_miss_selection.csv")
    evidence_rows = []
    for _, r in aggregate.iterrows():
        level = r.get("evidence_level", "level_1_generator_support")
        status = r.get("candidate_status", "aggregate_screen_only_current_translation_weak")
        if not selected.empty and r.get("candidate_id") in set(selected["candidate_id"]):
            level = "level_3_event_level_trade_ledger"
            status = "materialized_candidate_pending_controls"
        evidence_rows.append({"candidate_id": r.get("candidate_id"), "family_engine_id": r.get("family_engine_id"), "evidence_level": level, "candidate_status": status, "row_semantics": r.get("row_semantics")})
    write_csv(ctx.run_root / "analysis_ready/evidence_level_assignment.csv", evidence_rows)
    write_csv(ctx.run_root / "candidate_library/aggregate_first_candidate_status_update.csv", evidence_rows)
    write_csv(ctx.run_root / "analysis_ready/completed_wave_manifest.csv", [{"wave_id": "aggregate_first", "aggregate_summary": "coarse/all_candidate_aggregate_summary.parquet", "selected": len(selected), "near_misses": len(near)}])
    if not aggregate.empty:
        write_csv(ctx.run_root / "analysis_ready/aggregate_first_aggregate_summary.csv", aggregate.head(5000))
    write_csv(ctx.run_root / "analysis_ready/aggregate_first_selected_materialized_summary.csv", selected)
    write_csv(ctx.run_root / "analysis_ready/aggregate_first_near_miss_summary.csv", near)
    write_text(ctx.run_root / "analysis_ready/aggregate_first_next_suggestions.md", "# Aggregate-First Next Suggestions\n\nUse selected materialized candidates with controls/stress support for the next train-only package. Aggregate-only candidates remain non-final.\n")


def remote_enabled(ctx: Context) -> tuple[bool, str, str]:
    requested = ctx.args.remote_archive_enabled
    remote = ctx.args.remote_name
    if ctx.args.smoke and requested is None:
        return False, remote, "disabled_by_default_for_smoke"
    if requested is False:
        return False, remote, "disabled_by_cli"
    if shutil.which("rclone") is None:
        return False, remote, "rclone_missing"
    check = subprocess.run(["rclone", "listremotes"], capture_output=True, text=True)
    if check.returncode != 0 or f"{remote}:" not in check.stdout:
        return False, remote, "remote_missing"
    return True, remote, "enabled"


def stage_remote_archive(ctx: Context) -> None:
    enabled, remote, reason = remote_enabled(ctx)
    rows = []
    target_dir = ctx.run_root / "remote_archive"
    target_dir.mkdir(parents=True, exist_ok=True)
    large_dir = ctx.run_root / "materialized/event_ledgers"
    if large_dir.exists():
        archive = target_dir / "selected_materialized_ledgers.tar.gz"
        subprocess.run(["tar", "-czf", str(archive), "-C", str(ctx.run_root), "materialized/event_ledgers"], check=True)
        rows.append({"local_archive": str(archive), "size_bytes": archive.stat().st_size, "upload_status": "not_attempted", "remote_path": ""})
        if enabled:
            remote_path = ctx.args.remote_archive_path or f"kraken_family_engine_aggregate_first_sweep/{ctx.run_root.name}/"
            dest = f"{remote}:{remote_path}"
            try:
                cp = subprocess.run(["rclone", "copy", str(archive), dest, "--retries", "5", "--low-level-retries", "10"], capture_output=True, text=True, timeout=300)
                rows[-1].update({"upload_status": "passed" if cp.returncode == 0 else "failed", "remote_path": dest, "stderr_tail": cp.stderr[-1000:]})
            except subprocess.TimeoutExpired as exc:
                rows[-1].update({"upload_status": "failed_timeout", "remote_path": dest, "stderr_tail": str(exc)[-1000:]})
                write_text(ctx.run_root / "remote_archive/remote_upload_failure_report.md", f"# Remote Upload Failure\n\nStatus: `failed_timeout`\nRemote path: `{dest}`\nTimeout seconds: `300`\n")
    write_csv(ctx.run_root / "remote_archive/remote_archive_manifest.csv", rows)
    write_csv(ctx.run_root / "remote_archive/remote_upload_verification.csv", rows)
    write_text(ctx.run_root / "remote_archive/rclone_status_report.md", f"# Rclone Status\n\nEnabled: `{enabled}`\nRemote: `{remote}`\nReason: `{reason}`\n")
    write_text(ctx.run_root / "remote_archive/restore_from_drive_instructions.md", "# Restore From Drive\n\nUse `rclone copy <remote_path> <local_dir>` and extract the archive under the run root.\n")


