def stage_materialized_futility_gate_repair(ctx: Context) -> None:
    summary = read_csv_safe(ctx.run_root / "diagnostics/selected_candidate_r_decomposition.csv")
    context = read_csv_safe(ctx.run_root / "diagnostics/selected_candidate_context_breakdown.csv")
    write_text(ctx.run_root / "canary/materialized_futility_gate_policy.md", "\n".join([
        "# Materialized Futility Gate Policy",
        "",
        "Runs after materialized full-universe ledgers and before expensive controls in canary profiles.",
        "It can stop a canary as `materialized_futility_stop`; it cannot reject TSMOM, H02, A4, or pending definitions.",
        "Stop if all selected candidates have `mean_R < -0.03` and `median_R <= 0`, or all are materially negative under zero-fee and fee-reversion scenarios, unless a context pocket has >=100 events, >=3 symbols, >=3 months, net_R > 0, and median_R > 0.",
    ]) + "\n")
    if summary.empty:
        all_bad = False
        scenario_bad = False
    else:
        all_bad = bool((pd.to_numeric(summary.get("mean_R", pd.Series(dtype=float)), errors="coerce") < -0.03).all() and (pd.to_numeric(summary.get("median_R", pd.Series(dtype=float)), errors="coerce") <= 0).all())
        scenario_bad = bool((pd.to_numeric(summary.get("zero_fee_net_R", pd.Series(dtype=float)), errors="coerce") < 0).all() and (pd.to_numeric(summary.get("fee_reversion_standard_net_R", pd.Series(dtype=float)), errors="coerce") < 0).all())
    positive = context[parse_bool_series(context.get("positive_context_pocket", pd.Series(False, index=context.index)), default=False)] if not context.empty else pd.DataFrame()
    stop = bool((all_bad or scenario_bad) and positive.empty)
    decision = {
        "status": "materialized_futility_stop" if stop else "continue_after_materialized_futility_gate",
        "futility_stop": stop,
        "all_selected_mean_lt_minus_0_03_and_median_lte_0": all_bad,
        "all_selected_negative_under_zero_fee_and_fee_reversion": scenario_bad,
        "positive_context_pocket_count": int(len(positive)),
        "family_rejected": False,
        "hypothesis_rejected": False,
        "pending_definitions_preserved_as": "pending_compute",
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "canary/materialized_futility_gate_decision.json", decision)
    write_csv(ctx.run_root / "canary/materialized_futility_candidate_summary.csv", summary)


