    write_text(ctx.run_root / "performance/control_hotspot_report.md", "# Control Hotspot Report\n\nMain runtime hotspot remains real-null enumeration/path realization. Diagnostic mode limits candidates and retained controls after purge/embargo for schema and runtime checks only.\n")


