def policy_hashes_for_definition(rec: Mapping[str, Any]) -> dict[str, str]:
    universe_hash = policy_hash("universe", {**TSMOM_UNIVERSE_POLICY, "selected_policy": rec.get("universe_policy", "")})
    parent_hash = policy_hash("parent_regime", {**TSMOM_PARENT_GATE_POLICY, "selected_gate": rec.get("parent_regime_gate", "")})
    funding_hash = policy_hash("funding_gate", {**TSMOM_FUNDING_GATE_POLICY, "selected_gate": rec.get("funding_gate", "")})
    vol_hash = policy_hash("vol_target", {**TSMOM_VOL_TARGET_POLICY, "vol_target": rec.get("vol_target", ""), "vol_window_days": rec.get("vol_window_days", "")})
    side_hash = policy_hash("side_semantics", {**TSMOM_SIDE_SEMANTICS_POLICY, "selected_side": rec.get("side", "")})
    return {
        "universe_policy_hash": universe_hash,
        "parent_regime_policy_hash": parent_hash,
        "funding_gate_policy_hash": funding_hash,
        "vol_target_sizing_policy_hash": vol_hash,
        "side_semantics_policy_hash": side_hash,
    }


