def tsmom_vol_scale_policy_bounds() -> tuple[float, float]:
    min_scale = safe_float(TSMOM_VOL_TARGET_POLICY.get("min_scale"), np.nan)
    max_scale = safe_float(TSMOM_VOL_TARGET_POLICY.get("max_scale"), np.nan)
    if not (math.isfinite(min_scale) and math.isfinite(max_scale) and min_scale > 0 and max_scale >= min_scale):
        raise RuntimeError("invalid TSMOM vol-target scale bounds in policy")
    return float(min_scale), float(max_scale)


def policy_hashes_for_definition_v4(rec: Mapping[str, Any]) -> dict[str, str]:
    min_scale, max_scale = tsmom_vol_scale_policy_bounds()
    universe_hash = policy_hash("universe_v4", {
        **TSMOM_UNIVERSE_POLICY,
        "version": rec.get("universe_policy_version", "tsmom_universe_policy_v4_vol_lineage_20260705"),
        "selected_policy": rec.get("universe_policy", ""),
        "top_major_target_size": rec.get("top_major_target_size", TSMOM_TOP_MAJOR_UNIVERSE_LIMIT),
        "tier_ab_target_size": rec.get("tier_ab_target_size", TSMOM_TIER_AB_UNIVERSE_LIMIT),
    })
    parent_hash = policy_hash("parent_regime_v4", {**TSMOM_PARENT_GATE_POLICY, "selected_gate": rec.get("parent_regime_gate", "")})
    funding_hash = policy_hash("funding_gate_v4", {**TSMOM_FUNDING_GATE_POLICY, "selected_gate": rec.get("funding_gate", "")})
    vol_hash = policy_hash("vol_target_v4", {
        **TSMOM_VOL_TARGET_POLICY,
        "vol_target": rec.get("vol_target", ""),
        "vol_window_days": rec.get("vol_window_days", ""),
        "vol_scale_min": min_scale,
        "vol_scale_max": max_scale,
    })
    side_hash = policy_hash("side_semantics_v4", {**TSMOM_SIDE_SEMANTICS_POLICY, "selected_side": rec.get("side", "")})
    return {
        "universe_policy_hash": universe_hash,
        "parent_regime_policy_hash": parent_hash,
        "funding_gate_policy_hash": funding_hash,
        "vol_target_sizing_policy_hash": vol_hash,
        "side_semantics_policy_hash": side_hash,
    }


def fresh_parameter_json_hash(candidate: Mapping[str, Any], engine: FamilyEngine | None = None) -> tuple[str, str]:
    payload = parameter_vector_dict(candidate, engine)
    text = canonical_json(payload)
    return text, hashlib.sha256(text.encode("utf-8")).hexdigest()[:24]


def redesigned_tsmom_v4_rows(kind: str) -> pd.DataFrame:
    source = TSMOM_UNIVERSE_BINDING_REPAIR_V2_ROOT / "redesign" / f"tsmom_redesigned_{kind}_canary_definitions_v3.csv"
    base = read_csv_safe(source) if source.exists() else redesigned_tsmom_v3_rows(kind)
    min_scale, max_scale = tsmom_vol_scale_policy_bounds()
    rows: list[dict[str, Any]] = []
    engine = ENGINES["scheduled_tsmom_engine"]
    for _, row in base.iterrows():
        rec = row.to_dict()
        rec["vol_scale_min"] = min_scale
        rec["vol_scale_max"] = max_scale
        rec["universe_policy_version"] = "tsmom_universe_policy_v4_vol_lineage_20260705"
        rec["top_major_target_size"] = rec.get("top_major_target_size", TSMOM_TOP_MAJOR_UNIVERSE_LIMIT)
        rec["tier_ab_target_size"] = rec.get("tier_ab_target_size", TSMOM_TIER_AB_UNIVERSE_LIMIT)
        rec.update(policy_hashes_for_definition_v4(rec))
        rec["family_engine_id"] = "scheduled_tsmom_engine"
        rec["row_semantics"] = "position_interval"
        rec["event_semantics_version"] = EVENT_SEMANTICS_VERSION
        rec["parameter_vector_json"], rec["parameter_vector_hash"] = fresh_parameter_json_hash(rec, engine)
        rows.append(rec)
    return pd.DataFrame(rows)


def redesigned_v4_manifest_path(ctx: Context, kind: str) -> Path:
    return ctx.run_root / "redesign" / f"tsmom_redesigned_{kind}_canary_definitions_v4.csv"


def parameter_json_payload(text: object) -> dict[str, Any]:
    if not isinstance(text, str) or not text.strip():
        return {}
    try:
        payload = json.loads(text)
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def pre_run_parameter_lineage_gate_frame(frame: pd.DataFrame, *, context: str) -> pd.DataFrame:
    required_fields = [
        "candidate_definition_id",
        "parameter_vector_hash",
        "parameter_vector_json",
        "vol_scale_min",
        "vol_scale_max",
        "universe_policy_hash",
        "parent_regime_policy_hash",
        "funding_gate_policy_hash",
        "vol_target_sizing_policy_hash",
        "side_semantics_policy_hash",
    ]
    rows: list[dict[str, Any]] = []
    for col in required_fields:
        missing = col not in frame.columns
        blank = len(frame) if missing else int(frame[col].isna().sum() + frame[col].astype(str).str.strip().isin({"", "nan", "None", "NaN"}).sum())
        rows.append({
            "context": context,
            "check": f"required_field_{col}",
            "status": "fail" if missing or blank else "pass",
            "bad_rows": int(blank),
            "detail": "missing_column" if missing else ("blank_values" if blank else "present_nonblank"),
        })
    if frame.empty:
        rows.append({"context": context, "check": "manifest_non_empty", "status": "fail", "bad_rows": 0, "detail": "no rows"})
        return pd.DataFrame(rows)
    min_policy, max_policy = tsmom_vol_scale_policy_bounds()
    payload_missing = 0
    hash_mismatch = 0
    bounds_mismatch = 0
    policy_payload_missing = 0
    duplicate_hash_rows = int(frame["parameter_vector_hash"].astype(str).duplicated(keep=False).sum()) if "parameter_vector_hash" in frame.columns else len(frame)
    for _, row in frame.iterrows():
        payload = parameter_json_payload(row.get("parameter_vector_json", ""))
        if not payload:
            payload_missing += 1
        for key in ["vol_scale_min", "vol_scale_max", "universe_policy_hash", "parent_regime_policy_hash", "funding_gate_policy_hash", "vol_target_sizing_policy_hash", "side_semantics_policy_hash"]:
            if key not in payload or str(payload.get(key, "")).strip() in {"", "nan", "None", "NaN"}:
                policy_payload_missing += 1
                break
        observed_hash = str(row.get("parameter_vector_hash", "") or "")
        if payload and hashlib.sha256(str(row.get("parameter_vector_json", "")).encode("utf-8")).hexdigest()[:24] != observed_hash:
            hash_mismatch += 1
        row_min = safe_float(row.get("vol_scale_min"), np.nan)
        row_max = safe_float(row.get("vol_scale_max"), np.nan)
        payload_min = safe_float(payload.get("vol_scale_min"), np.nan)
        payload_max = safe_float(payload.get("vol_scale_max"), np.nan)
        if not (
            math.isclose(row_min, min_policy, rel_tol=0, abs_tol=1e-12)
            and math.isclose(row_max, max_policy, rel_tol=0, abs_tol=1e-12)
            and math.isclose(payload_min, min_policy, rel_tol=0, abs_tol=1e-12)
            and math.isclose(payload_max, max_policy, rel_tol=0, abs_tol=1e-12)
        ):
            bounds_mismatch += 1
    rows.extend([
        {"context": context, "check": "parameter_json_parses", "status": "fail" if payload_missing else "pass", "bad_rows": payload_missing, "detail": "parameter_vector_json must be parseable JSON"},
        {"context": context, "check": "parameter_json_contains_policy_hashes_and_vol_bounds", "status": "fail" if policy_payload_missing else "pass", "bad_rows": policy_payload_missing, "detail": "hash lineage fields must be inside parameter_vector_json"},
        {"context": context, "check": "parameter_hash_matches_parameter_json", "status": "fail" if hash_mismatch else "pass", "bad_rows": hash_mismatch, "detail": "parameter_vector_hash is sha256(parameter_vector_json)[:24]"},
        {"context": context, "check": "vol_scale_bounds_match_active_policy", "status": "fail" if bounds_mismatch else "pass", "bad_rows": bounds_mismatch, "detail": f"expected {min_policy}..{max_policy}"},
        {"context": context, "check": "unique_parameter_vector_hash", "status": "fail" if duplicate_hash_rows else "pass", "bad_rows": duplicate_hash_rows, "detail": "deduplicated economic definitions required"},
    ])
    return pd.DataFrame(rows)


def write_pre_run_parameter_lineage_gate(ctx: Context, frame: pd.DataFrame, *, context: str, fail_closed: bool) -> pd.DataFrame:
    audit = pre_run_parameter_lineage_gate_frame(frame, context=context)
    write_text(ctx.run_root / "gate/pre_run_parameter_lineage_gate_policy.md", "\n".join([
        "# Pre-Run Parameter Lineage Gate Policy",
        "",
        "Future redesigned TSMOM canary profiles must run this gate before aggregate evaluation or materialization.",
        "Required fields include `vol_scale_min`, `vol_scale_max`, all policy hashes, `parameter_vector_json`, and `parameter_vector_hash`.",
        "The hash must be `sha256(parameter_vector_json)[:24]`, and the JSON must include the active policy hashes and vol-scale bounds.",
        "Missing `vol_scale_min` or `vol_scale_max` fails in prelaunch, before expensive execution.",
    ]) + "\n")
    write_csv(ctx.run_root / "gate/pre_run_parameter_lineage_gate_audit.csv", audit)
    failed = bool(not audit.empty and audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    if fail_closed and failed:
        failed_checks = audit[audit["status"].astype(str).eq("fail")]["check"].astype(str).tolist()
        raise RuntimeError(f"pre-run parameter lineage gate failed: {failed_checks}")
    return audit


def validate_redesigned_tsmom_manifest(df: pd.DataFrame) -> pd.DataFrame:
    required = [
        "candidate_definition_id", "hypothesis_id", "side", "liquidity_tier", "universe_policy", "bar_timeframe",
        "lookback_days", "lookback_4h_bars", "rebalance_interval", "hold_interval", "vol_window_days",
        "vol_target", "parent_regime_gate", "funding_gate", "fee_scenario_handling", "parameter_vector_hash",
        "why_this_definition",
    ]
    rows: list[dict[str, Any]] = []
    for col in required:
        missing = col not in df.columns
        blank = len(df) if missing else int(df[col].isna().sum() + df[col].astype(str).str.strip().isin({"", "nan", "None"}).sum())
        rows.append({"check": f"required_field_{col}", "status": "fail" if missing or blank else "pass", "bad_rows": blank})
    dup = int(df.duplicated("parameter_vector_hash", keep=False).sum()) if "parameter_vector_hash" in df.columns else len(df)
    rows.append({"check": "duplicate_parameter_vector_hash", "status": "fail" if dup else "pass", "bad_rows": dup})
    churn = 0
    if {"lookback_days", "hold_interval"}.issubset(df.columns):
        for _, r in df.iterrows():
            hold_bars = parse_interval_to_5m_bars(r.get("hold_interval"), default_bars=288)
            if safe_float(r.get("lookback_days"), 0.0) < 1 or hold_bars < 48:
                churn += 1
    rows.append({"check": "no_5m_churn_labeled_as_redesigned_tsmom", "status": "fail" if churn else "pass", "bad_rows": churn})
    return pd.DataFrame(rows)


