def stage_tsmom_universe_selection_audit(ctx: Context) -> None:
    root = latest_fast_canary_root()
    selected = read_csv_safe(root / "analysis_ready/scheduled_tsmom_engine__wave_001/selected_materialized_summary.csv")
    panel = tsmom_selected_panel(root)
    symbols = selected_universe_symbols(selected)
    verdict = infer_tsmom_universe_ordering(symbols, panel)
    panel_work = panel.copy()
    if not panel_work.empty and "symbol" in panel_work.columns:
        panel_work["bar_rows"] = pd.to_numeric(panel_work.get("bar_rows", 0), errors="coerce").fillna(0)
        panel_work["funding_rows"] = pd.to_numeric(panel_work.get("funding_rows", 0), errors="coerce").fillna(0)
        panel_work = panel_work.sort_values(["bar_rows", "funding_rows", "symbol"], ascending=[False, False, True]).copy()
        panel_work["pit_liquidity_rank"] = np.arange(1, len(panel_work) + 1)
        panel_by_symbol = panel_work.set_index("symbol", drop=False)
    else:
        panel_by_symbol = pd.DataFrame()
    rows: list[dict[str, Any]] = []
    for pos, sym in enumerate(symbols, start=1):
        rec = {"symbol": sym}
        if not panel_by_symbol.empty and sym in panel_by_symbol.index:
            p = panel_by_symbol.loc[sym]
            if isinstance(p, pd.DataFrame):
                p = p.iloc[0]
            rec.update({
                "bar_rows": p.get("bar_rows", ""),
                "funding_rows": p.get("funding_rows", ""),
                "panel_status": p.get("status", "available"),
                "pit_liquidity_rank": p.get("pit_liquidity_rank", ""),
            })
        rows.append({
            "selected_position": pos,
            **rec,
            "selected": True,
            "ordering_basis": verdict["ordering_basis"],
            "pit_liquidity_based": verdict["pit_liquidity_based"],
        })
    expected = tsmom_expected_major_audit(symbols, panel_work)
    write_csv(ctx.run_root / "universe/tsmom_selected_universe_audit.csv", rows)
    write_csv(ctx.run_root / "universe/tsmom_liquid_universe_expected_vs_actual.csv", expected)
    classification = "diagnostic_only_wrong_universe_possible" if (verdict["alphabetical_or_truncated"] or not verdict["pit_liquidity_based"]) else "pit_liquidity_universe_plausible"
    write_json(ctx.run_root / "universe/tsmom_universe_verdict.json", {**verdict, "latest_fast_canary_classification": classification})
    write_text(ctx.run_root / "universe/tsmom_universe_selection_report.md", "\n".join([
        "# TSMOM Universe Selection Audit",
        "",
        f"Selected symbols: `{len(symbols)}`",
        f"Ordering basis: `{verdict['ordering_basis']}`",
        f"Alphabetical/truncated: `{verdict['alphabetical_or_truncated']}`",
        f"PIT-liquidity based: `{verdict['pit_liquidity_based']}`",
        f"Latest fast canary classification: `{classification}`",
        "",
        "If the selected universe is alphabetical, truncated, or not a real PIT-liquidity universe, the latest R values are not TSMOM-family evidence.",
    ]) + "\n")


