def stage_selected_candidate_loss_decomposition_audit(ctx: Context) -> None:
    root = latest_fast_canary_root()
    manifest = read_csv_safe(root / "waves/scheduled_tsmom_engine__wave_001/materialized/materialized_ledger_manifest.csv")
    summary, context = materialized_candidate_r_decomposition(ctx, manifest, base_root=root)
    fee = read_csv_safe(root / "analysis_ready/scheduled_tsmom_engine__wave_001/fee_scenario_stress_summary.csv")
    funding = read_csv_safe(root / "analysis_ready/scheduled_tsmom_engine__wave_001/funding_cap_summary.csv")
    if not fee.empty:
        fee_pivot = fee.pivot_table(index="candidate_id", columns="fee_scenario", values="net_R_after_fee_scenario", aggfunc="first").reset_index()
        summary = summary.merge(fee_pivot, on="candidate_id", how="left")
    if not funding.empty:
        summary = summary.merge(funding[[c for c in ["candidate_id", "funding_proxy_event_rows", "funding_exact_event_rows", "funding_boundary_crossed_rows", "funding_cap_active"] if c in funding.columns]], on="candidate_id", how="left")
    if not context.empty:
        context["post_hoc_use_allowed"] = False
        context["allowed_followup_label"] = "context_followup_hypothesis"
    write_csv(ctx.run_root / "diagnostics/tsmom_selected_loss_decomposition.csv", summary)
    write_csv(ctx.run_root / "diagnostics/tsmom_symbol_month_regime_breakdown.csv", context)
    fee_driven = bool(not summary.empty and (pd.to_numeric(summary.get("fees_R", pd.Series(dtype=float)), errors="coerce").abs() > pd.to_numeric(summary.get("gross_R", pd.Series(dtype=float)), errors="coerce").abs()).any())
    funding_driven = bool(not summary.empty and (pd.to_numeric(summary.get("funding_R", pd.Series(dtype=float)), errors="coerce").abs() > 0).any())
    zero_fee_changes_short = bool(not summary.empty and (pd.to_numeric(summary.get("zero_fee_net_R", pd.Series(dtype=float)), errors="coerce") > 0).any())
    positive_context = context[parse_bool_series(context.get("positive_context_pocket", pd.Series(False, index=context.index)), default=False)] if not context.empty else pd.DataFrame()
    write_text(ctx.run_root / "diagnostics/tsmom_loss_interpretation.md", "\n".join([
        "# TSMOM Selected Loss Interpretation",
        "",
        f"Selected candidates decomposed: `{len(summary)}`",
        f"Losses fee-driven: `{fee_driven}`",
        f"Funding proxy/material funding impact present: `{funding_driven}`",
        f"Zero-fee scenario materially changes at least one selected variant: `{zero_fee_changes_short}`",
        f"Post-hoc positive pockets meeting override thresholds: `{len(positive_context)}`",
        "",
        "Positive pockets found after the canary are labeled only `context_followup_hypothesis`. No filter may be added because it made the failed canary look better.",
    ]) + "\n")


def stage_current_translation_classification(ctx: Context) -> None:
    universe = read_json(ctx.run_root / "universe/tsmom_universe_verdict.json", {})
    params = read_json(ctx.run_root / "parameters/tsmom_parameter_time_unit_verdict.json", {})
    decomp = read_csv_safe(ctx.run_root / "diagnostics/tsmom_selected_loss_decomposition.csv")
    rows: list[dict[str, Any]] = []
    for _, r in decomp.iterrows():
        labels = []
        if universe.get("latest_fast_canary_classification") == "diagnostic_only_wrong_universe_possible":
            labels.append("diagnostic_only_wrong_universe_possible")
        if params.get("latest_fast_canary_classification") == "diagnostic_only_short_horizon_translation":
            labels.append("diagnostic_only_short_horizon_translation")
        if safe_float(r.get("net_R"), 0.0) < 0:
            labels.append("current_translation_weak")
        if safe_float(r.get("zero_fee_net_R"), safe_float(r.get("kraken_current_account_zero_fee"), 0.0)) > 0 and safe_float(r.get("fee_reversion_standard_net_R"), safe_float(r.get("fee_reversion_standard"), -1.0)) < 0:
            labels.append("zero_fee_current_account_sleeve_candidate")
        if not labels:
            labels.append("pending_redesign")
        rows.append({
            "candidate_id": r.get("candidate_id", ""),
            "candidate_definition_id": r.get("candidate_definition_id", ""),
            "hypothesis_id": r.get("hypothesis_id", ""),
            "current_translation_status": ";".join(dict.fromkeys(labels)),
            "family_status": "pending_redesign",
            "family_rejected": False,
            "post_hoc_rescue_allowed": False,
        })
    if not rows:
        rows.append({"candidate_id": "", "candidate_definition_id": "", "hypothesis_id": "", "current_translation_status": "pending_redesign", "family_status": "pending_redesign", "family_rejected": False, "post_hoc_rescue_allowed": False})
    write_csv(ctx.run_root / "classification/current_tsmom_translation_status.csv", rows)
    write_csv(ctx.run_root / "classification/tsmom_candidate_library_update.csv", rows)
    write_text(ctx.run_root / "classification/tsmom_family_preservation_report.md", "\n".join([
        "# TSMOM Family Preservation Report",
        "",
        "The latest fast-canary current translations are classified without rejecting TSMOM, H02, A4, or pending definitions.",
        "Family status: `pending_redesign`.",
        "No bad current translation is evidence against slower liquid-major TSMOM.",
    ]) + "\n")


