def stage_per_definition_pit_universe_policy_repair(ctx: Context) -> None:
    panel = panel_manifest_for_repair(ctx)
    ultra = redesigned_tsmom_v2_rows("ultra")
    policy_rows: list[dict[str, Any]] = []
    expected_rows: list[dict[str, Any]] = []
    turnover_rows: list[dict[str, Any]] = []
    checkpoints = universe_checkpoints(ctx, panel)
    for _, r in ultra.iterrows():
        cid = str(r.get("candidate_definition_id", ""))
        prev: set[str] | None = None
        total_changes = 0
        counts: list[int] = []
        for label, ts in checkpoints:
            symbols, audit = tsmom_policy_symbols_at_checkpoint(r.to_dict(), panel, ts)
            counts.append(len(symbols))
            current = set(symbols)
            if prev is not None:
                total_changes += len(current.symmetric_difference(prev))
            prev = current
            policy_rows.append({
                "candidate_definition_id": cid,
                "checkpoint_label": label,
                "checkpoint_ts": ts.isoformat(),
                "universe_policy": r.get("universe_policy", ""),
                "selected_symbols": ";".join(symbols),
                "selected_symbol_count": len(symbols),
                "ranking_source": "proxy_bar_coverage_funding_rows",
                "liquidity_proxy_universe_cap": True,
                "status": "pass" if symbols else "fail_no_symbols",
            })
            for major in REDESIGNED_EXPECTED_MAJORS:
                row = audit[audit["symbol"].astype(str).eq(major)]
                if row.empty:
                    expected_rows.append({
                        "candidate_definition_id": cid,
                        "checkpoint_label": label,
                        "checkpoint_ts": ts.isoformat(),
                        "symbol": major,
                        "eligible_at_checkpoint": False,
                        "included_at_checkpoint": False,
                        "inclusion_exclusion_reason": "symbol_missing_from_panel",
                    })
                else:
                    rec = row.iloc[0]
                    expected_rows.append({
                        "candidate_definition_id": cid,
                        "checkpoint_label": label,
                        "checkpoint_ts": ts.isoformat(),
                        "symbol": major,
                        "eligible_at_checkpoint": bool(rec.get("eligible", False)),
                        "included_at_checkpoint": bool(rec.get("included", False)),
                        "inclusion_exclusion_reason": rec.get("inclusion_exclusion_reason", ""),
                    })
        turnover_rows.append({
            "candidate_definition_id": cid,
            "universe_policy": r.get("universe_policy", ""),
            "universe_recomputation_cadence": "train_start_quarterly_liquidity_checkpoints_final_pre_holdout",
            "checkpoint_count": len(checkpoints),
            "average_symbol_count": float(np.mean(counts)) if counts else 0.0,
            "symbol_count_min": min(counts) if counts else 0,
            "symbol_count_max": max(counts) if counts else 0,
            "membership_change_count_across_checkpoints": total_changes,
            "average_symbols_added_removed_per_checkpoint": total_changes / max(1, len(checkpoints) - 1),
            "event_count_materiality_status": "estimated_in_dry_run",
        })
    write_text(ctx.run_root / "universe/expected_major_anchor_policy.md", "\n".join([
        "# Expected Major Anchor Policy",
        "",
        "`pit_liquidity_top_majors` treats expected majors as anchor candidates only when they are PIT lifecycle-safe and have required bars at the checkpoint.",
        "The policy never forces inclusion for unlisted, inactive, delisted, stale/corrupt, or unavailable-bar symbols.",
        "`pit_liquidity_tier_ab` ranks by PIT liquidity proxy and audits major inclusion/exclusion without forcing majors outside the declared policy.",
        "Official quote/notional liquidity is not present in the current panel, so the universe carries `liquidity_proxy_universe_cap`.",
    ]) + "\n")
    write_csv(ctx.run_root / "universe/expected_major_checkpoint_audit.csv", expected_rows)
    write_csv(ctx.run_root / "universe/tsmom_universe_turnover_audit.csv", turnover_rows)
    write_csv(ctx.run_root / "universe/redesigned_ultra_pit_universe_by_date_v2.csv", policy_rows)


