        {"field": "universe_policy", "consumed": True, "consumed_by": "generate_candidate_registry_for_family_universe(tsmom_policy_symbol_union)", "use_scope": "per-definition PIT universe", "report_only": False, "launch_blocker": False, "detail": "per-definition universe policy bound"},
        {"field": "side", "consumed": True, "consumed_by": "ScheduledTsmomEngine.build_candidate_masks/event_from_address", "use_scope": "direction and diagnostic caps", "report_only": False, "launch_blocker": False, "detail": "long_flat and short_diagnostic explicitly supported"},
        {"field": "parent_regime_gate", "consumed": True, "consumed_by": "event_from_address/evaluate_parent_regime_gate", "use_scope": "entry filter with completed 4h parent bars", "report_only": False, "launch_blocker": False, "detail": "warmup skips gated entries"},
