def stage_strict_bool_parsing_repair(ctx: Context) -> None:
    source = Path(__file__).read_text(encoding="utf-8").splitlines()
    rows = []
    for lineno, line in enumerate(source, start=1):
        if ".astype(bool)" in line or "parse_bool_" in line or "any_true(" in line or "all_true(" in line:
            literal_reference = "\".astype(bool)\"" in line or "Remaining unsafe `.astype(bool)`" in line
            unsafe = ".astype(bool)" in line and "parse_bool_series" not in line and not literal_reference
            rows.append({"line": lineno, "text": line.strip(), "status": "remaining_unsafe_astype_bool" if unsafe else "strict_bool_parser_or_safe_usage"})
    write_csv(ctx.run_root / "audit/bool_gate_usage_scan.csv", rows)
    write_text(ctx.run_root / "audit/bool_parsing_repair_report.md", "# Bool Parsing Repair Report\n\nGate, cap, and evidence paths use explicit token parsing for booleans. Accepted true tokens are `true,1,yes,y`; accepted false tokens are `false,0,no,n`. Unknown values use caller-specified conservative defaults or raise in strict parser tests.\n")


