def collect_manifest_ledgers(run_root: Path, manifest: pd.DataFrame | None = None) -> pd.DataFrame:
    if manifest is None or manifest.empty:
        manifest = read_csv_safe(run_root / "waves/scheduled_tsmom_engine__wave_001/materialized/materialized_ledger_manifest.csv")
    frames: list[pd.DataFrame] = []
    for _, m in manifest.iterrows():
        p = run_root / str(m.get("path", ""))
        if p.exists():
            try:
                df = pd.read_parquet(p)
            except Exception:
                df = pd.DataFrame()
            if not df.empty:
                frames.append(df)
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def stage_failed_ultra_canary_ingest(ctx: Context) -> None:
    root = failed_redesigned_ultra_v3_root(ctx)
    decision = read_json(root / "decision_summary.json", {})
    gate = read_json(root / "waves/scheduled_tsmom_engine__wave_001/wave_gate_decision.json", read_json(root / "wave_gate_decision.json", {}))
    manifest = read_csv_safe(root / "waves/scheduled_tsmom_engine__wave_001/materialized/materialized_ledger_manifest.csv")
    futility = read_json(root / "canary/materialized_futility_gate_decision.json", {})
    audit = read_csv_safe(root / "audit/original_selected_vs_materialized_audit.csv")
    defs = read_csv_safe(root / "engine_wave/wave_definition_manifest.csv")
    aggregate = read_csv_safe(root / "coarse/all_candidate_aggregate_summary.csv")
    if aggregate.empty:
        aggregate = read_parquet_safe(root / "waves/scheduled_tsmom_engine__wave_001/aggregate/all_candidate_aggregate_summary.parquet")
    summary_rows = [{
        "failed_run_root": str(root),
        "decision_status": decision.get("status", ""),
        "next_operator_decision": decision.get("next_operator_decision", ""),
        "wave_gate_status": gate.get("wave_gate_status", ""),
        "aggregate_materialized_audit_pass": gate.get("aggregate_materialized_audit_pass", ""),
        "parameter_preservation_pass": gate.get("parameter_preservation_pass", ""),
        "candidate_identity_pass": gate.get("candidate_identity_pass", ""),
        "materialized_futility_stop": futility.get("futility_stop", gate.get("materialized_futility_stop", "")),
        "definitions": int(defs["candidate_definition_id"].nunique()) if not defs.empty and "candidate_definition_id" in defs.columns else int(len(defs)),
        "aggregate_rows": int(len(aggregate)),
        "materialized_candidates": int(len(manifest)),
        "audit_fail_rows": int(audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").sum()) if not audit.empty else 0,
        "classification": "diagnostic_infrastructure_only_not_strategy_evidence",
    }]
    write_csv(ctx.run_root / "ingest/failed_redesigned_ultra_summary.csv", summary_rows)
    if getattr(getattr(ctx, "args", None), "phase_profile", "") == TSMOM_ULTRA_LINEAGE_FUTILITY_TRIAGE_PHASE_PROFILE:
        write_csv(ctx.run_root / "ingest/failed_ultra_canary_summary.csv", summary_rows)
    write_text(ctx.run_root / "ingest/failed_redesigned_ultra_interpretation.md", "\n".join([
        "# Failed Redesigned Ultra Canary Interpretation",
        "",
        f"Source root: `{root}`",
        "",
        "This source run is diagnostic/infrastructure only. Its negative materialized candidates and failed audit do not reject TSMOM as a family.",
        "The repair phase uses it only to identify event-semantics, binding, scope, and funding/accounting defects.",
    ]) + "\n")
    if getattr(getattr(ctx, "args", None), "phase_profile", "") == TSMOM_ULTRA_LINEAGE_FUTILITY_TRIAGE_PHASE_PROFILE:
        write_text(ctx.run_root / "ingest/failed_ultra_canary_interpretation.md", "\n".join([
            "# Failed Ultra Canary Interpretation",
            "",
            f"Source root: `{root}`",
            "",
            "This failed retry is diagnostic/infrastructure input only. It is not strategy evidence, not validation, and not a family rejection.",
            "The lineage/futility triage uses it to decide whether the current ultra definition set merits rerun after v4 lineage repair.",
        ]) + "\n")


