def stage_vol_scale_lineage_contract_repair(ctx: Context) -> None:
    ultra_v3 = read_csv_safe(TSMOM_UNIVERSE_BINDING_REPAIR_V2_ROOT / "redesign/tsmom_redesigned_ultra_canary_definitions_v3.csv")
    standard_v3 = read_csv_safe(TSMOM_UNIVERSE_BINDING_REPAIR_V2_ROOT / "redesign/tsmom_redesigned_standard_canary_definitions_v3.csv")
    ultra_v4 = redesigned_tsmom_v4_rows("ultra")
    standard_v4 = redesigned_tsmom_v4_rows("standard")
    write_csv(redesigned_v4_manifest_path(ctx, "ultra"), ultra_v4)
    write_csv(redesigned_v4_manifest_path(ctx, "standard"), standard_v4)
    policy_rows: list[dict[str, Any]] = []
    for kind, df in [("ultra", ultra_v4), ("standard", standard_v4)]:
        for _, r in df.iterrows():
            policy_rows.append({
                "manifest_kind": kind,
                "candidate_definition_id": r.get("candidate_definition_id", ""),
                "parameter_vector_hash": r.get("parameter_vector_hash", ""),
                "vol_scale_min": r.get("vol_scale_min", ""),
                "vol_scale_max": r.get("vol_scale_max", ""),
                "universe_policy_hash": r.get("universe_policy_hash", ""),
                "parent_regime_policy_hash": r.get("parent_regime_policy_hash", ""),
                "funding_gate_policy_hash": r.get("funding_gate_policy_hash", ""),
                "vol_target_sizing_policy_hash": r.get("vol_target_sizing_policy_hash", ""),
                "side_semantics_policy_hash": r.get("side_semantics_policy_hash", ""),
            })
    write_csv(ctx.run_root / "redesign/tsmom_redesigned_policy_hash_manifest.csv", policy_rows)
    hash_rows: list[dict[str, Any]] = []
    for kind, old, new in [("ultra", ultra_v3, ultra_v4), ("standard", standard_v3, standard_v4)]:
        if old.empty:
            old = redesigned_tsmom_v3_rows(kind)
        old_by_id = old.set_index("candidate_definition_id", drop=False) if "candidate_definition_id" in old.columns and not old.empty else pd.DataFrame()
        for _, r in new.iterrows():
            cid = str(r.get("candidate_definition_id", ""))
            old_hash = ""
            old_json_contains_bounds = False
            if not old_by_id.empty and cid in old_by_id.index:
                old_row = old_by_id.loc[cid]
                if isinstance(old_row, pd.DataFrame):
                    old_row = old_row.iloc[0]
                old_hash = str(old_row.get("parameter_vector_hash", ""))
                old_payload = parameter_json_payload(old_row.get("parameter_vector_json", ""))
                old_json_contains_bounds = "vol_scale_min" in old_payload and "vol_scale_max" in old_payload
            hash_rows.append({
                "manifest_kind": kind,
                "candidate_definition_id": cid,
                "old_v3_parameter_vector_hash": old_hash,
                "new_v4_parameter_vector_hash": r.get("parameter_vector_hash", ""),
                "hash_changed": bool(old_hash and old_hash != str(r.get("parameter_vector_hash", ""))),
                "old_json_contains_vol_scale_bounds": bool(old_json_contains_bounds),
                "new_json_contains_vol_scale_bounds": bool({"vol_scale_min", "vol_scale_max"}.issubset(parameter_json_payload(r.get("parameter_vector_json", "")).keys())),
                "status": "pass" if (not old_hash or old_hash != str(r.get("parameter_vector_hash", ""))) else "fail",
            })
    write_csv(ctx.run_root / "lineage/parameter_hash_change_audit.csv", hash_rows)
    required = list(PARAMETER_VECTOR_FIELDS) + ["parameter_vector_hash", "parameter_vector_json"]
    req_rows = []
    for kind, df in [("ultra", ultra_v4), ("standard", standard_v4)]:
        for col in required:
            missing = col not in df.columns
            blank = len(df) if missing else int(df[col].isna().sum() + df[col].astype(str).str.strip().isin({"", "nan", "None", "NaN"}).sum())
            req_rows.append({"manifest_kind": kind, "required_field": col, "status": "fail" if missing or blank else "pass", "bad_rows": int(blank)})
    write_csv(ctx.run_root / "lineage/parameter_contract_required_fields_audit.csv", req_rows)
    write_text(ctx.run_root / "lineage/vol_scale_lineage_repair_report.md", "\n".join([
        "# Vol-Scale Lineage Repair Report",
        "",
        "V4 manifests were written as immutable new artifacts. V3 manifests were not mutated.",
        "V4 rows include `vol_scale_min=0.25` and `vol_scale_max=2.0` in wide columns and inside `parameter_vector_json`.",
        "The refreshed `parameter_vector_hash` includes vol-scale bounds plus universe, parent, funding, vol-target, and side policy hashes.",
        "",
        f"Ultra v4 path: `{redesigned_v4_manifest_path(ctx, 'ultra')}`",
        f"Standard v4 path: `{redesigned_v4_manifest_path(ctx, 'standard')}`",
    ]) + "\n")


