def write_optimisation_completion_audit(ctx: Context) -> pd.DataFrame:
    rows = []
    for req in cache_foundation_required_artifacts():
        rel = req["required_artifact_or_behavior"]
        path = ctx.run_root / rel
        implemented = path.exists() or rel in {"audit/optimisation_plan_completion_audit.csv", "audit/optimisation_plan_deviation_report.md"}
        deferred = rel == "prior_high_cache_deferred_report.md" and implemented
        blocking = "deferred_scalar_safe" if deferred else ("pass" if implemented else "blocking_missing")
        rows.append({
            **req,
            "implemented": implemented,
            "verified": implemented,
            "artifact_path": str(path.relative_to(ctx.run_root)),
            "test_name_or_gate": "cache_foundation_smoke_or_stage_gate",
            "deferred": deferred,
            "defer_reason": "prior-high cache not enabled until exactness is proven; prior-high remains scalar-safe" if deferred else "",
            "blocking_status": blocking,
        })
    df = pd.DataFrame(rows)
    write_csv(ctx.run_root / "audit/optimisation_plan_completion_audit.csv", df)
    missing = df[df["blocking_status"].astype(str).eq("blocking_missing")]
    write_text(ctx.run_root / "audit/optimisation_plan_deviation_report.md", "\n".join([
        "# Optimisation Plan Deviation Report",
        "",
        f"Source: `{optimisation_plan_path()}`",
        f"Missing non-deferred requirements: `{len(missing)}`",
        "",
        "Prior-high cache generation may be deferred only when `prior_high_cache_deferred_report.md` exists and prior-high remains scalar-safe.",
    ] + ([*missing["required_artifact_or_behavior"].astype(str).map(lambda x: f"- `{x}`").tolist()] if not missing.empty else ["No non-deferred deviations."])) + "\n")
    return df


def tmux_session_active(session: str) -> bool:
    try:
        subprocess.check_call(["tmux", "has-session", "-t", session], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        return True
    except Exception:
        return False


def maybe_stop_active_run_at_boundary(ctx: Context, active_root: Path) -> dict[str, Any]:
    session = "kraken_two_family_memorysafe_20260706"
    tsmom_done = (active_root / "stage_status/tsmom-v4-v5-aggregate-screen.done").exists()
    later_markers = [
        active_root / "stage_status/tsmom-targeted-materialization-if-nonfutile.done",
        active_root / "stage_status/prior-high-family-contract-and-manifest-v1.done",
        active_root / "stage_status/prior-high-reclaim-mechanical-canary.done",
    ]
    later_started = any(p.exists() for p in later_markers)
    active = tmux_session_active(session)
    action = "not_stopped_current_stage_incomplete"
    if tsmom_done and active and not later_started:
        try:
            subprocess.check_call(["tmux", "send-keys", "-t", session, "C-c"])
            action = "sent_ctrl_c_after_tsmom_aggregate_boundary"
        except Exception as exc:
            action = f"stop_failed:{type(exc).__name__}"
    elif tsmom_done and not active:
        action = "already_inactive_after_tsmom_aggregate"
    elif later_started:
        action = "too_late_later_stage_marker_present"
    return {
        "active_run_root": str(active_root),
        "tmux_session": session,
        "tmux_active": active,
        "tsmom_aggregate_done": tsmom_done,
        "later_stage_marker_present": later_started,
        "action": action,
        "active_run_modified_in_place": False,
    }


