def stage_cache_contracts_and_leak_boundary(ctx: Context) -> None:
    write_text(ctx.run_root / "contracts/cache_class_contract.md", """# Cache Class Contract

Decision-input caches include calendars, universe membership, ranks, signals, parent/funding gates, vol scale, and prior-high features. Every decision-input row must satisfy `feature_available_ts <= decision_ts`.

Outcome caches include interval returns and execution outcomes. Outcome caches may use data after `decision_ts`, but only after `selected_event_keys` are frozen and hashed.
""")
    write_text(ctx.run_root / "contracts/decision_input_cache_schema.yaml", """required_columns:
  - decision_ts
  - feature_available_ts
  - valid_asof
invariant: feature_available_ts <= decision_ts
forbidden_fields:
  - raw_net_R
  - exit_price
  - future_path
""")
    write_text(ctx.run_root / "contracts/outcome_cache_schema.yaml", """required_columns:
  - symbol_id
  - decision_ts
  - interval_policy_hash
  - entry_ts
  - exit_ts
  - raw_net_R
allowed_after_freeze_only: true
""")
    write_text(ctx.run_root / "contracts/leak_boundary_policy.md", """# Leak Boundary Policy

Safe aggregate flow:
1. Build selected event keys from decision-input caches only.
2. Freeze and hash selected event keys.
3. Join outcome caches.
4. Compute raw and scaled R.
5. Aggregate.

Any access to outcome fields during universe, ranking, signal, gate, tuning, or pre-freeze control construction fails closed.
""")
    access = pd.DataFrame([
        {"cache_class": "decision_input", "access_phase": "selection", "selected_event_keys_frozen": False},
        {"cache_class": "outcome", "access_phase": "aggregate_after_freeze", "selected_event_keys_frozen": True},
    ])
    write_csv(ctx.run_root / "audit/outcome_cache_access_fixture.csv", access)
    write_csv(ctx.run_root / "audit/outcome_cache_selection_leak_audit.csv", assert_outcome_cache_not_used_pre_freeze(access))


def active_cache_definition_sample(ctx: Context, n: int = 4) -> pd.DataFrame:
    v4 = load_standard_v4_manifest_for_pretriage(ctx).head(max(1, n // 2)).copy()
    v6 = build_tsmom_v6_curated_manifest().head(max(1, n - len(v4))).copy()
    return pd.concat([v4, v6], ignore_index=True, sort=False)


def stage_candidate_registry_and_shard_manifest(ctx: Context) -> None:
    code_hash = sha256_file(Path(__file__))
    config_hash = stable_hash(ctx.args.phase_profile, ctx.start, ctx.end, ctx.args.seed, n=32)
    input_hash = stable_hash(read_json(ctx.run_root / "preflight/input_manifest.json", {}), n=32)
    train_hash = stable_hash(ctx.start, ctx.end, n=32)
    rows = []
    defs = active_cache_definition_sample(ctx, 4)
    for _, d in defs.iterrows():
        row = {
            "run_id": active_run_id(ctx.args),
            "candidate_definition_id": d.get("candidate_definition_id", d.get("definition_id", "")),
            "candidate_symbol_id": f"{d.get('candidate_definition_id', d.get('definition_id', 'd'))}__SAMPLE",
            "family": d.get("family", "TSMOM"),
            "symbol_id": "PF_XBTUSD",
            "symbol": "PF_XBTUSD",
            "parameter_vector_hash": d.get("parameter_vector_hash", ""),
            "definition_hash": stable_hash(d.to_dict(), n=32),
            "universe_policy_hash": d.get("universe_policy_hash", stable_hash(d.get("universe_policy", ""), n=24)),
            "rank_policy_hash": d.get("rank_policy_hash", stable_hash(d.get("rank_top_n", ""), d.get("rank_metric", ""), n=24)),
            "signal_policy_hash": d.get("signal_policy_hash", stable_hash(d.get("lookback_days", d.get("lookback_bars", "")), d.get("side", ""), n=24)),
            "parent_gate_policy_hash": d.get("parent_regime_policy_hash", d.get("parent_gate_policy_hash", "")),
            "funding_gate_policy_hash": d.get("funding_gate_policy_hash", ""),
            "vol_scale_policy_hash": d.get("vol_target_sizing_policy_hash", d.get("vol_scale_policy_hash", "")),
            "interval_policy_hash": stable_hash(d.get("hold_interval", d.get("hold_bars", "")), d.get("rebalance_interval", ""), n=24),
            "feature_policy_hash": stable_hash(d.get("lookback_days", ""), d.get("bar_timeframe", ""), n=24),
            "event_semantics_version": EVENT_SEMANTICS_VERSION,
            "code_hash": code_hash,
            "config_hash": config_hash,
            "input_manifest_hash": input_hash,
            "train_window_hash": train_hash,
            "status": "registry_sample_only",
        }
        row["candidate_identity_hash"] = build_candidate_identity_hash(row)
        rows.append(row)
    registry = pd.DataFrame(rows)
    write_text(ctx.run_root / "registry/candidate_registry_schema.md", "# Candidate Registry Schema\n\nThe registry is authoritative before aggregate evaluation and includes candidate, symbol, policy, code/config/input, train-window, and identity hashes.\n")
    write_csv(ctx.run_root / "registry/candidate_registry_sample.csv", registry)
    write_text(ctx.run_root / "shards/shard_manifest_schema.json", json.dumps({
        "required": ["path", "row_count", "content_hash", "hash_basis", "code_hash", "config_hash", "input_manifest_hash"],
        "hash_basis": "canonical sorted row content, not parquet metadata",
    }, indent=2) + "\n")
    write_text(ctx.run_root / "shards/resume_protocol.md", "# Shard Resume Protocol\n\nResume accepts only shards with valid manifests, matching code/config/input hashes, and unique candidate identity hashes. Path-only shards and hash mismatches fail closed.\n")
    shard_df = registry[["candidate_identity_hash", "symbol_id", "candidate_definition_id"]].copy()
    temp = ctx.run_root / "shards/tmp/sample_registry.parquet"
    final = ctx.run_root / "shards/sample_registry.parquet"
    manifest = write_atomic_shard(temp, final, shard_df, {"code_hash": code_hash, "config_hash": config_hash, "input_manifest_hash": input_hash}, sort_keys=["candidate_identity_hash"])
    validation = validate_shard_manifest(final.with_suffix(final.suffix + ".manifest.json"), expected={"code_hash": code_hash})
    write_json(ctx.run_root / "shards/sample_registry_shard_manifest.json", manifest)
    write_json(ctx.run_root / "shards/sample_registry_shard_validation.json", validation)
    if validation.get("status") != "pass":
        raise RuntimeError("sample shard validation failed")


