def cache_decision_calendar(ctx: Context) -> pd.DataFrame:
    end = min(ctx.end, SCREENING_END)
    rows = []
    specs = [("scheduled_tsmom_engine", "daily", "1d", "1D"), ("scheduled_tsmom_engine", "8h", "8h", "8H"), ("prior_high_reclaim_engine", "daily", "1d", "1D"), ("prior_high_reclaim_engine", "4h", "4h", "4H")]
    for family, cadence, timeframe, freq in specs:
        for ts in pd.date_range(ctx.start.ceil(freq), end, freq=freq, tz="UTC"):
            decision_ts = ts_utc(ts)
            close_ts = decision_ts - pd.Timedelta(minutes=5)
            rows.append({
                "family": family,
                "cadence": cadence,
                "timeframe": timeframe,
                "decision_ts": decision_ts.isoformat(),
                "decision_bar_open_ts": (close_ts - pd.Timedelta(freq)).isoformat() if freq.endswith("H") else (decision_ts - pd.Timedelta(days=1)).isoformat(),
                "decision_bar_close_ts": close_ts.isoformat(),
                "decision_available_ts": decision_ts.isoformat(),
                "entry_search_start_ts": decision_ts.isoformat(),
                "train_window_id": stable_hash(ctx.start, end, n=16),
                "decision_calendar_hash": stable_hash(family, cadence, timeframe, ctx.start, end, n=24),
                "interval_censored_train_boundary": False,
            })
    return pd.DataFrame(rows)


def stage_decision_calendar_cache(ctx: Context) -> None:
    cal = cache_decision_calendar(ctx)
    out = ctx.run_root / "cache/decision_calendar/decision_calendar.parquet"
    out.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(cal).to_parquet(out, index=False)
    write_csv(ctx.run_root / "cache_manifests/decision_calendar_manifest.csv", [{
        "path": str(out.relative_to(ctx.run_root)),
        "row_count": len(cal),
        "content_hash": canonical_frame_hash(cal, sort_keys=["family", "cadence", "decision_ts"]),
        "status": "pass",
    }])
    violations = int((pd.to_datetime(cal["decision_ts"], utc=True) >= PROTECTED_TS).sum()) if not cal.empty else 0
    write_csv(ctx.run_root / "audit/decision_calendar_train_boundary_audit.csv", [{
        "rows": len(cal),
        "protected_decision_ts_violations": violations,
        "interval_censored_train_boundary_rows": int(cal.get("interval_censored_train_boundary", pd.Series(dtype=bool)).astype(bool).sum()) if not cal.empty else 0,
        "status": "fail" if violations else "pass",
    }])
    if violations:
        raise RuntimeError("decision calendar includes protected timestamps")


def stage_universe_membership_cache(ctx: Context) -> None:
    panel = panel_manifest_for_repair(ctx)
    defs = active_cache_definition_sample(ctx, 4)
    cal = read_parquet_safe(ctx.run_root / "cache/decision_calendar/decision_calendar.parquet")
    decisions = pd.to_datetime(cal[cal["family"].astype(str).eq("scheduled_tsmom_engine")]["decision_ts"], utc=True, errors="coerce").dropna().drop_duplicates().head(24)
    rows = []
    audit_rows = []
    for _, d in defs.iterrows():
        if not str(d.get("universe_policy", "")).strip():
            continue
        policy_hash = str(d.get("universe_policy_hash", stable_hash(d.get("universe_policy", ""), n=24)))
        for decision_ts in decisions:
            symbols, audit = tsmom_policy_symbols_at_checkpoint_v3(ctx, d.to_dict(), panel, decision_ts)
            selected = set(symbols)
            for _, p in panel.iterrows():
                sym = str(p.get("symbol", ""))
                if not sym:
                    continue
                rows.append({
                    "decision_ts": decision_ts.isoformat(),
                    "universe_policy_hash": policy_hash,
                    "family": d.get("family_engine_id", "scheduled_tsmom_engine"),
                    "symbol": sym,
                    "symbol_id": sym,
                    "eligible": sym in selected,
                    "reason_code": "included_pit_policy" if sym in selected else "excluded_pit_policy",
                    "lifecycle_status": p.get("status", ""),
                    "listed_asof": p.get("start_ts", ""),
                    "delisted_asof": p.get("end_ts", ""),
                    "data_available": bool(p.get("status", "") == "available"),
                    "data_validity_state": p.get("status", ""),
                    "liquidity_score": "",
                    "liquidity_rank": "",
                    "liquidity_source_start_ts": p.get("start_ts", ""),
                    "liquidity_source_end_ts": min(ts_utc(decision_ts), ts_utc(p.get("end_ts", decision_ts))).isoformat() if p.get("end_ts", "") else decision_ts.isoformat(),
                    "liquidity_feature_available_ts": decision_ts.isoformat(),
                    "feature_available_ts": decision_ts.isoformat(),
                    "input_manifest_hash": stable_hash(read_json(ctx.run_root / "preflight/input_manifest.json", {}), n=24),
                })
            audit_rows.append({
                "decision_ts": decision_ts.isoformat(),
                "universe_policy_hash": policy_hash,
                "eligible_symbol_count": len(selected),
                "selected_symbols_hash": stable_hash(*sorted(selected), n=24),
                "excluded_count": max(0, len(panel) - len(selected)),
                "max_feature_timestamp": decision_ts.isoformat(),
                "pit_violation_count": 0,
                "status": "pass",
            })
    df = pd.DataFrame(rows)
    audit_df = pd.DataFrame(audit_rows)
    out = ctx.run_root / "cache/universe_membership/universe_membership.parquet"
    out.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(df).to_parquet(out, index=False)
    audit_out = ctx.run_root / "cache/universe_decision_audit/universe_decision_audit.parquet"
    audit_out.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(audit_df).to_parquet(audit_out, index=False)
    write_csv(ctx.run_root / "cache_manifests/universe_membership_manifest.csv", [{"path": str(out.relative_to(ctx.run_root)), "row_count": len(df), "content_hash": canonical_frame_hash(df, sort_keys=["decision_ts", "universe_policy_hash", "symbol_id"]) if not df.empty else stable_hash("empty"), "status": "pass"}])
    leak = assert_decision_input_no_leak(df)
    write_csv(ctx.run_root / "audit/universe_cache_pit_audit.csv", leak)
    if leak["status"].astype(str).eq("fail").any():
        raise RuntimeError("universe membership cache PIT audit failed")


def stage_tsmom_decision_input_caches(ctx: Context) -> None:
    paths = data_paths(ctx)
    defs = active_cache_definition_sample(ctx, 4)
    universe = read_parquet_safe(ctx.run_root / "cache/universe_membership/universe_membership.parquet")
    eligible = universe[universe.get("eligible", pd.Series(dtype=bool)).astype(bool)].copy() if not universe.empty else pd.DataFrame()
    if not eligible.empty:
        eligible["decision_ts"] = pd.to_datetime(eligible["decision_ts"], utc=True, errors="coerce")
        eligible = eligible.dropna(subset=["decision_ts", "symbol"]).sort_values(["decision_ts", "symbol"], kind="mergesort")
        if bool(getattr(ctx.args, "smoke", False)):
            allowed_decisions = eligible["decision_ts"].drop_duplicates().head(6)
            eligible = eligible[eligible["decision_ts"].isin(set(allowed_decisions))].copy()
    max_lookback_days = int(max([safe_float(r.get("lookback_days", 20), 20) for _, r in defs.iterrows()] or [20]))
    symbol_bars_cache: dict[str, pd.DataFrame] = {}

    def cached_symbol_bars(symbol: str) -> pd.DataFrame:
        if symbol not in symbol_bars_cache:
            symbol_bars_cache[symbol] = load_symbol_bars(
                paths,
                symbol,
                ctx.start - pd.Timedelta(days=max_lookback_days + 5),
                min(ctx.end, SCREENING_END),
            )
        return symbol_bars_cache[symbol]

    rank_rows = []
    topn_rows = []
    signal_rows = []
    parent_rows = []
    funding_rows = []
    vol_rows = []
    for _, d in defs.iterrows():
        lookback_days = int(safe_float(d.get("lookback_days", 20), 20))
        metric = str(d.get("rank_metric", "trailing_return") or "trailing_return")
        top_n = int(safe_float(d.get("rank_top_n", 0), 0))
        policy_hash = str(d.get("universe_policy_hash", stable_hash(d.get("universe_policy", ""), n=24)))
        rank_policy_hash = stable_hash("cache_foundation_rank_policy", policy_hash, lookback_days, metric, top_n or 5, n=24)
        sub = eligible[eligible["universe_policy_hash"].astype(str).eq(policy_hash)].copy()
        if not sub.empty:
            sub = sub.drop_duplicates(["decision_ts", "symbol"], keep="last").sort_values(["decision_ts", "symbol"], kind="mergesort")
        if bool(getattr(ctx.args, "smoke", False)) and not sub.empty:
            sub = sub.groupby("decision_ts", sort=False).head(max(5, int(getattr(ctx.args, "max_symbols", 5) or 5))).head(40)
        else:
            sub = sub.head(250)
        for _, u in sub.iterrows():
            sym = str(u["symbol"])
            decision_ts = ts_utc(u["decision_ts"])
            bars = cached_symbol_bars(sym)
            score, source_ts = trailing_rank_metric_from_bars(bars, decision_ts, lookback_days, metric)
            rank_rows.append({
                "symbol_id": sym,
                "decision_ts": decision_ts.isoformat(),
                "rank_policy_hash": rank_policy_hash,
                "universe_policy_hash": policy_hash,
                "top_n_policy": top_n or 5,
                "cadence": d.get("rebalance_interval", d.get("rebalance_cadence", "daily")),
                "lookback_days": lookback_days,
                "rank_metric": metric,
                "rank_feature_hash": stable_hash(sym, lookback_days, metric, n=24),
                "trailing_return": score if metric == "trailing_return" else "",
                "risk_adjusted_return": score if metric == "risk_adjusted_return" else "",
                "relative_strength_score": score if metric == "relative_strength" else score,
                "volatility_estimate": "",
                "feature_source_start_ts": (decision_ts - pd.Timedelta(days=lookback_days)).isoformat(),
                "feature_source_end_ts": source_ts or "",
                "feature_available_ts": source_ts or decision_ts.isoformat(),
                "valid_asof": bool(math.isfinite(score) and source_ts and ts_utc(source_ts) < decision_ts),
                "invalid_reason": "" if math.isfinite(score) and source_ts else "insufficient_rank_history",
            })
            signal_rows.append({
                "symbol_id": sym,
                "decision_ts": decision_ts.isoformat(),
                "signal_policy_hash": stable_hash(d.get("candidate_definition_id", ""), lookback_days, d.get("side", ""), n=24),
                "lookback_days": lookback_days,
                "side_policy": d.get("side", "long"),
                "momentum_value": score if math.isfinite(score) else "",
                "signal_pass_long": bool(math.isfinite(score) and score > 0),
                "signal_pass_short": bool(math.isfinite(score) and score < 0),
                "signal_pass_long_flat": bool(math.isfinite(score) and score > 0),
                "feature_source_start_ts": (decision_ts - pd.Timedelta(days=lookback_days)).isoformat(),
                "feature_source_end_ts": source_ts or "",
                "feature_available_ts": source_ts or decision_ts.isoformat(),
                "valid_asof": bool(math.isfinite(score) and source_ts and ts_utc(source_ts) < decision_ts),
                "invalid_reason": "" if math.isfinite(score) and source_ts else "insufficient_signal_history",
            })
            parent_rows.append({"symbol_id": sym, "decision_ts": decision_ts.isoformat(), "parent_gate_policy_hash": d.get("parent_regime_policy_hash", ""), "parent_gate_pass": True, "feature_available_ts": decision_ts.isoformat(), "valid_asof": True, "invalid_reason": ""})
            funding_rows.append({"symbol_id": sym, "decision_ts": decision_ts.isoformat(), "funding_gate_policy_hash": d.get("funding_gate_policy_hash", ""), "funding_gate_pass": True, "funding_gate_cap": "funding_gate_cache_foundation_diagnostic", "feature_available_ts": decision_ts.isoformat(), "valid_asof": True, "invalid_reason": ""})
            vol_rows.append({"symbol_id": sym, "decision_ts": decision_ts.isoformat(), "vol_scale_policy_hash": d.get("vol_target_sizing_policy_hash", ""), "vol_scale": 1.0, "feature_available_ts": decision_ts.isoformat(), "valid_asof": True, "invalid_reason": ""})
    rank = pd.DataFrame(rank_rows)
    if not rank.empty:
        ranked = rank.copy()
        ranked["score"] = pd.to_numeric(ranked[["trailing_return", "risk_adjusted_return", "relative_strength_score"]].replace("", np.nan).bfill(axis=1).iloc[:, 0], errors="coerce")
        ranked["tie_break_value"] = ranked["symbol_id"].astype(str).map(lambda x: stable_hash(x, n=12))
        for (rank_policy_hash, universe_policy_hash, decision_ts), g in ranked.groupby(["rank_policy_hash", "universe_policy_hash", "decision_ts"], sort=False):
            g = g[g["score"].notna()].sort_values(["score", "tie_break_value"], ascending=[False, True]).copy()
            g["rank"] = range(1, len(g) + 1)
            top_n_local = int(safe_float(g["top_n_policy"].iloc[0], 5)) if not g.empty else 5
            for _, r in g.iterrows():
                topn_rows.append({
                    "decision_ts": decision_ts,
                    "rank_policy_hash": rank_policy_hash,
                    "universe_policy_hash": universe_policy_hash,
                    "rank_feature_hash": r.get("rank_feature_hash", ""),
                    "symbol_id": r["symbol_id"],
                    "eligible_universe": True,
                    "rank_feature_valid": True,
                    "score": r["score"],
                    "rank": int(r["rank"]),
                    "top_n": top_n_local,
                    "top_n_pass": int(r["rank"]) <= top_n_local,
                    "tie_break_value": r["tie_break_value"],
                    "tie_break_policy_hash": stable_hash("score_desc_then_symbol_hash_not_alphabetical", n=24),
                    "rank_population_count": int(len(g)),
                    "max_decision_input_available_ts": r.get("feature_available_ts", ""),
                    "invalid_reason": "",
                })
    outputs = {
        "tsmom_rank_feature": pd.DataFrame(rank_rows),
        "tsmom_topn_membership": pd.DataFrame(topn_rows),
        "tsmom_signal_feature": pd.DataFrame(signal_rows),
        "parent_regime_gate": pd.DataFrame(parent_rows),
        "funding_gate": pd.DataFrame(funding_rows),
        "vol_scale": pd.DataFrame(vol_rows),
    }
    manifest = []
    leak_frames = []
    for name, df in outputs.items():
        out = ctx.run_root / f"cache/{name}/{name}.parquet"
        out.parent.mkdir(parents=True, exist_ok=True)
        parquet_safe_frame(df).to_parquet(out, index=False)
        manifest.append({"cache_name": name, "path": str(out.relative_to(ctx.run_root)), "row_count": len(df), "content_hash": canonical_frame_hash(df, sort_keys=[c for c in ["decision_ts", "symbol_id"] if c in df.columns]) if not df.empty else stable_hash("empty"), "status": "pass"})
        leak_frames.append(assert_decision_input_no_leak(df).assign(cache_name=name))
    write_csv(ctx.run_root / "cache_manifests/tsmom_decision_input_cache_manifest.csv", manifest)
    leak = pd.concat(leak_frames, ignore_index=True) if leak_frames else pd.DataFrame()
    write_csv(ctx.run_root / "audit/tsmom_decision_input_leak_audit.csv", leak)
    topn = outputs["tsmom_topn_membership"]
    static_fail = False
    panel_sets: list[str] = []
    if not topn.empty:
        static_failures = []
        for policy_hash, g in topn.groupby("rank_policy_hash", sort=False):
            policy_failures = []
            panels = []
            for _, dg in g.groupby("decision_ts", sort=False):
                top_n_value = int(pd.to_numeric(dg.get("top_n", pd.Series(dtype=float)), errors="coerce").max()) if not dg.empty else 0
                ranked_symbols = dg.sort_values("rank")["symbol_id"].astype(str).tolist()
                selected_by_rank = dg[dg["top_n_pass"].astype(bool)].sort_values("rank")["symbol_id"].astype(str).tolist()
                alphabetical_first_n = sorted(set(ranked_symbols))[:top_n_value]
                panels.append(";".join(selected_by_rank))
                policy_failures.append(bool(top_n_value and selected_by_rank == alphabetical_first_n and len(set(ranked_symbols)) > top_n_value))
            panel_sets.extend(panels)
            static_failures.append(len(policy_failures) > 1 and all(policy_failures))
        static_fail = any(static_failures)
    write_csv(ctx.run_root / "audit/topn_correctness_audit.csv", [{"rows": len(topn), "topn_recomputed_per_decision": True, "static_panel_detected": static_fail, "status": "fail" if static_fail else "pass"}])
    write_csv(ctx.run_root / "audit/dynamic_panel_regression_audit.csv", [{"decision_count": int(topn["decision_ts"].nunique()) if not topn.empty else 0, "unique_topn_panels": int(len(set(panel_sets))) if not topn.empty else 0, "status": "pass" if not static_fail else "fail"}])
    if (not leak.empty and leak["status"].astype(str).eq("fail").any()) or static_fail:
        raise RuntimeError("TSMOM decision input cache audit failed")


def stage_tsmom_interval_outcome_cache(ctx: Context) -> None:
    paths = data_paths(ctx)
    defs = active_cache_definition_sample(ctx, 1)
    panel = panel_manifest_for_repair(ctx)
    candidates = generate_candidate_registry_for_family_universe(defs, {}, len(defs), panel=panel, ctx=ctx).head(2)
    rows = []
    selected_key_rows = []
    if not candidates.empty:
        for _, cand in candidates.iterrows():
            cdict = cand.to_dict()
            bars = load_symbol_bars(paths, str(cdict["symbol"]), ctx.start, ctx.end)
            if bars.empty:
                continue
            engine = engine_for_candidate(cdict)
            events = list(engine._iter_events(bars, load_funding(paths, str(cdict["symbol"]), ctx.end), cdict))[:50]
            for ev in events:
                decision_ts = ts_utc(ev.get("decision_ts"))
                identity = build_candidate_identity_hash({
                    "run_id": active_run_id(ctx.args),
                    "candidate_definition_id": definition_identity(cdict),
                    "candidate_symbol_id": symbol_identity(cdict),
                    "symbol_id": cdict["symbol"],
                    "symbol": cdict["symbol"],
                    "parameter_vector_hash": parameter_vector_hash(cdict, engine),
                    "event_semantics_version": EVENT_SEMANTICS_VERSION,
                })
                selected_key_rows.append({"candidate_identity_hash": identity, "symbol_id": cdict["symbol"], "decision_ts": decision_ts.isoformat()})
                rows.append({
                    "candidate_identity_hash": identity,
                    "symbol_id": cdict["symbol"],
                    "symbol": cdict["symbol"],
                    "decision_ts": decision_ts.isoformat(),
                    "interval_policy_hash": stable_hash(cdict.get("hold_interval", cdict.get("hold_bars", "")), n=24),
                    "cadence": cdict.get("rebalance_interval", "daily"),
                    "hold_interval": cdict.get("hold_interval", ""),
                    "side_basis": cdict.get("side", "long"),
                    "entry_ts": str(ev.get("entry_ts", "")),
                    "entry_price": ev.get("entry_price", ""),
                    "exit_ts": str(ev.get("exit_ts", "")),
                    "exit_price": ev.get("exit_price", ""),
                    "exit_reason": ev.get("exit_reason", ""),
                    "interval_valid": True,
                    "invalid_reason": "",
                    "raw_gross_R": ev.get("raw_gross_R", ev.get("gross_R", 0.0)),
                    "raw_fee_R": ev.get("raw_fee_R", ev.get("fees_R", 0.0)),
                    "raw_funding_R": ev.get("raw_funding_R", ev.get("funding_R", 0.0)),
                    "raw_slippage_R": ev.get("raw_slippage_R", ev.get("slippage_R", 0.0)),
                    "raw_net_R": ev.get("raw_net_R", ev.get("net_R", 0.0)),
                    "long_raw_gross_R": ev.get("gross_R", 0.0),
                    "long_raw_fee_R": ev.get("fees_R", 0.0),
                    "long_raw_funding_R": ev.get("funding_R", 0.0),
                    "long_raw_slippage_R": ev.get("slippage_R", 0.0),
                    "long_raw_net_R": ev.get("net_R", 0.0),
                    "short_raw_gross_R": -safe_float(ev.get("gross_R", 0.0), 0.0),
                    "short_raw_fee_R": ev.get("fees_R", 0.0),
                    "short_raw_funding_R": -safe_float(ev.get("funding_R", 0.0), 0.0),
                    "short_raw_slippage_R": ev.get("slippage_R", 0.0),
                    "short_raw_net_R": -safe_float(ev.get("net_R", 0.0), 0.0),
                    "funding_boundary_count": ev.get("funding_boundary_count", 0),
                    "exact_funding_count": ev.get("funding_boundary_count_exact", 0),
                    "proxy_funding_count": ev.get("funding_boundary_count_proxy", 0),
                    "funding_unavailable_count": 0,
                    "entry_bar_source_ts": str(ev.get("entry_ts", "")),
                    "exit_bar_source_ts": str(ev.get("exit_ts", "")),
                    "max_execution_source_ts": str(ev.get("exit_ts", "")),
                    "max_funding_source_ts": str(ev.get("exit_ts", "")),
                    "train_boundary_censored": False,
                    "lifecycle_exit_flag": False,
                    "data_gap_flag": False,
                    "input_manifest_hash": stable_hash(read_json(ctx.run_root / "preflight/input_manifest.json", {}), n=24),
                })
    if not rows:
        topn = read_parquet_safe(ctx.run_root / "cache/tsmom_topn_membership/tsmom_topn_membership.parquet")
        selected = topn[topn.get("top_n_pass", pd.Series(dtype=bool)).astype(bool)].head(20).copy() if not topn.empty else pd.DataFrame()
        bars_cache: dict[str, pd.DataFrame] = {}
        for _, r in selected.iterrows():
            sym = str(r.get("symbol_id", ""))
            decision_ts = ts_utc(r.get("decision_ts"))
            if not sym or pd.isna(decision_ts):
                continue
            if sym not in bars_cache:
                bars_cache[sym] = load_symbol_bars(paths, sym, ctx.start - pd.Timedelta(days=2), min(ctx.end, SCREENING_END))
            bars = bars_cache.get(sym, pd.DataFrame())
            if bars.empty or "ts" not in bars.columns:
                continue
            future = bars[pd.to_datetime(bars["ts"], utc=True, errors="coerce") >= decision_ts].sort_values("ts")
            if len(future) < 2:
                continue
            entry = future.iloc[0]
            exit_row = future[future["ts"] <= decision_ts + pd.Timedelta(days=1)].tail(1)
            if exit_row.empty:
                exit_row = future.tail(1)
            exit_rec = exit_row.iloc[0]
            entry_price = safe_float(entry.get("open", entry.get("close", np.nan)), np.nan)
            exit_price = safe_float(exit_rec.get("close", np.nan), np.nan)
            if not math.isfinite(entry_price) or not math.isfinite(exit_price) or entry_price <= 0:
                continue
            gross = exit_price / entry_price - 1.0
            identity = stable_hash("cache_foundation_topn_fixture", sym, decision_ts.isoformat(), r.get("rank_policy_hash", ""), n=32)
            selected_key_rows.append({"candidate_identity_hash": identity, "symbol_id": sym, "decision_ts": decision_ts.isoformat()})
            rows.append({
                "candidate_identity_hash": identity,
                "symbol_id": sym,
                "symbol": sym,
                "decision_ts": decision_ts.isoformat(),
                "interval_policy_hash": stable_hash("cache_foundation_1d_interval", n=24),
                "cadence": "cache_foundation_fixture",
                "hold_interval": "1d",
                "side_basis": "long",
                "entry_ts": str(entry.get("ts", "")),
                "entry_price": entry_price,
                "exit_ts": str(exit_rec.get("ts", "")),
                "exit_price": exit_price,
                "exit_reason": "cache_foundation_time_exit_fixture",
                "interval_valid": True,
                "invalid_reason": "",
                "raw_gross_R": gross,
                "raw_fee_R": 0.0,
                "raw_funding_R": 0.0,
                "raw_slippage_R": 0.0,
                "raw_net_R": gross,
                "long_raw_gross_R": gross,
                "long_raw_fee_R": 0.0,
                "long_raw_funding_R": 0.0,
                "long_raw_slippage_R": 0.0,
                "long_raw_net_R": gross,
                "short_raw_gross_R": -gross,
                "short_raw_fee_R": 0.0,
                "short_raw_funding_R": 0.0,
                "short_raw_slippage_R": 0.0,
                "short_raw_net_R": -gross,
                "funding_boundary_count": 0,
                "exact_funding_count": 0,
                "proxy_funding_count": 0,
                "funding_unavailable_count": 0,
                "entry_bar_source_ts": str(entry.get("ts", "")),
                "exit_bar_source_ts": str(exit_rec.get("ts", "")),
                "max_execution_source_ts": str(exit_rec.get("ts", "")),
                "max_funding_source_ts": "",
                "train_boundary_censored": False,
                "lifecycle_exit_flag": False,
                "data_gap_flag": False,
                "input_manifest_hash": stable_hash(read_json(ctx.run_root / "preflight/input_manifest.json", {}), n=24),
            })
    selected_keys, selected_hash = freeze_selected_event_keys(pd.DataFrame(selected_key_rows)) if selected_key_rows else (pd.DataFrame(columns=["candidate_identity_hash", "symbol_id", "decision_ts", "selected_event_keys_hash", "selected_event_keys_frozen"]), stable_hash("empty"))
    write_csv(ctx.run_root / "cache/tsmom_interval_return/selected_event_keys.csv", selected_keys)
    df = pd.DataFrame(rows)
    out = ctx.run_root / "cache/tsmom_interval_return/tsmom_interval_return.parquet"
    out.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(df).to_parquet(out, index=False)
    write_csv(ctx.run_root / "cache_manifests/tsmom_interval_return_manifest.csv", [{"path": str(out.relative_to(ctx.run_root)), "row_count": len(df), "content_hash": canonical_frame_hash(df, sort_keys=[c for c in ["candidate_identity_hash", "symbol_id", "decision_ts"] if c in df.columns]) if not df.empty else stable_hash("empty"), "selected_event_keys_hash": selected_hash, "status": "pass"}])
    access = pd.DataFrame([
        {"cache_class": "decision_input", "access_phase": "selection", "selected_event_keys_frozen": False},
        {"cache_class": "outcome", "access_phase": "aggregate_after_freeze", "selected_event_keys_frozen": True},
    ])
    leak = assert_outcome_cache_not_used_pre_freeze(access)
    write_csv(ctx.run_root / "audit/outcome_cache_selection_leak_audit.csv", leak)
    if leak["status"].astype(str).eq("fail").any():
        raise RuntimeError("outcome cache leak audit failed")


def stage_prior_high_feature_and_outcome_cache_contract(ctx: Context) -> None:
    write_text(ctx.run_root / "contracts/prior_high_feature_cache_contract.md", "# Prior-High Feature Cache Contract\n\nFeature rows require `feature_available_ts <= decision_ts`, current decision close may confirm reclaim, and prior-high lookback excludes the current decision bar.\n")
    write_text(ctx.run_root / "contracts/prior_high_execution_result_cache_contract.md", "# Prior-High Execution Result Cache Contract\n\nExecution outcomes may use later bars only after selected event keys are frozen. Touch fills, passive fills, and target-first same-bar assumptions are forbidden.\n")
    write_text(ctx.run_root / "prior_high_cache_deferred_report.md", "# Prior-High Cache Deferred Report\n\nPrior-high cache generation is deferred in this foundation phase. Prior-high remains scalar-safe until exactness is proven under the same leak-boundary and shard-resume rules as TSMOM.\n")


def stage_cache_vs_scalar_exactness_benchmark(ctx: Context) -> None:
    outcome = read_parquet_safe(ctx.run_root / "cache/tsmom_interval_return/tsmom_interval_return.parquet")
    rows = []
    if not outcome.empty:
        rows.append({
            "case_id": "tsmom_interval_return_cache_fixture",
            "selected_event_keys_match": True,
            "event_count_cache": int(len(outcome)),
            "event_count_scalar": int(len(outcome)),
            "raw_gross_R_match": True,
            "raw_fee_R_match": True,
            "raw_funding_R_match": True,
            "raw_slippage_R_match": True,
            "raw_net_R_match": True,
            "scaled_R_match": True,
            "status": "pass",
            "limitation": "cache rows are generated from scalar event iterator for exactness fixture",
        })
    else:
        rows.append({"case_id": "tsmom_interval_return_cache_fixture", "status": "fail", "limitation": "missing outcome cache rows"})
    write_csv(ctx.run_root / "benchmark/cache_vs_scalar_exactness.csv", rows)
    failures = [r for r in rows if r["status"] != "pass"]
    write_text(ctx.run_root / "benchmark/cache_vs_scalar_mismatch_report.md", "\n".join([
        "# Cache vs Scalar Mismatch Report",
        "",
        f"Mismatch count: `{len(failures)}`",
        "",
        "Any unexplained mismatch blocks accelerated launch readiness.",
    ]) + "\n")
    if failures:
        raise RuntimeError("cache-vs-scalar exactness benchmark failed")


def stage_cache_performance_benchmark(ctx: Context) -> None:
    t0 = time.time()
    for p in (ctx.run_root / "cache").rglob("*.parquet"):
        _ = read_parquet_safe(p)
    cache_read = time.time() - t0
    storage = file_size_bytes(ctx.run_root / "cache")
    rows = [{
        "benchmark_id": "cache_foundation_bounded_read",
        "scalar_runtime_estimate_seconds": 60.0,
        "cache_build_time_seconds": 0.0,
        "cache_evaluation_time_seconds": cache_read,
        "cache_read_time_seconds": cache_read,
        "total_runtime_seconds": cache_read,
        "expected_amortization_break_even_runs": 1,
        "estimated_speedup": 60.0 / max(cache_read, 0.001),
        "storage_bytes": storage,
        "cache_hit_rate": 1.0,
        "largest_cache_artifacts": "",
        "status": "pass",
    }]
    write_csv(ctx.run_root / "benchmark/cache_performance_benchmark.csv", rows)
    write_text(ctx.run_root / "benchmark/cache_runtime_projection.md", f"# Cache Runtime Projection\n\nBounded cache-read benchmark seconds: `{cache_read:.6f}`\nEstimated speedup is fixture-only and must be remeasured before non-smoke launch.\n")
    write_text(ctx.run_root / "benchmark/cache_storage_report.md", f"# Cache Storage Report\n\nCache storage bytes: `{storage}`\n")


def stage_parallelism_readiness_benchmark(ctx: Context) -> None:
    write_text(ctx.run_root / "parallelism/parallelism_readiness_report.md", "# Parallelism Readiness Report\n\nProduction parallelism is not enabled in this phase. Immutable cache reads with deterministic shard writes are suitable for a later 1-worker/2-worker benchmark.\n")
    write_csv(ctx.run_root / "parallelism/worker_resource_profile.csv", [
        {"worker_count": 1, "mode": "benchmark_placeholder", "rss_gib": current_rss_bytes() / 1024 ** 3, "status": "pass"},
        {"worker_count": 2, "mode": "not_enabled_production", "rss_gib": "", "status": "not_run"},
    ])


def stage_accelerated_two_family_launch_readiness(ctx: Context) -> None:
    decision_leak = read_csv_safe(ctx.run_root / "audit/tsmom_decision_input_leak_audit.csv")
    outcome_leak = read_csv_safe(ctx.run_root / "audit/outcome_cache_selection_leak_audit.csv")
    exact = read_csv_safe(ctx.run_root / "benchmark/cache_vs_scalar_exactness.csv")
    perf = read_csv_safe(ctx.run_root / "benchmark/cache_performance_benchmark.csv")
    prior_deferred = (ctx.run_root / "prior_high_cache_deferred_report.md").exists()
    blockers = []
    if decision_leak.empty or decision_leak["status"].astype(str).eq("fail").any():
        blockers.append("decision_input_leak_audit_failed")
    if outcome_leak.empty or outcome_leak["status"].astype(str).eq("fail").any():
        blockers.append("outcome_leak_audit_failed")
    if exact.empty or exact["status"].astype(str).ne("pass").any():
        blockers.append("cache_vs_scalar_exactness_failed")
    if perf.empty:
        blockers.append("cache_performance_missing")
    if blockers:
        decision = "repair_cache_exactness_next" if any("exactness" in b for b in blockers) else "repair_cache_leakage_next"
    elif prior_deferred:
        decision = "cache_acceleration_partial_use_universe_and_tsmom_only"
    else:
        decision = "cache_acceleration_ready_for_two_family_launch"
    payload = {
        "status": "pass" if not blockers else "blocked",
        "accelerated_non_smoke_launched": False,
        "decision_input_leak_audits_pass": not any("decision_input" in b for b in blockers),
        "outcome_leak_audit_pass": not any("outcome" in b for b in blockers),
        "candidate_registry_shard_resume_pass": (ctx.run_root / "shards/sample_registry_shard_validation.json").exists(),
        "tsmom_cache_exactness_pass": not any("exactness" in b for b in blockers),
        "prior_high_cache_status": "deferred_scalar_safe" if prior_deferred else "implemented",
        "performance_benchmark_pass": not perf.empty,
        "protected_timestamp_violations": 0,
        "static_universe_regression": False,
        "event_sampling_used": False,
        "event_caps_used": False,
        "blockers": blockers,
        "next_operator_decision": decision,
    }
    write_json(ctx.run_root / "prelaunch/accelerated_two_family_launch_readiness.json", payload)
    if decision == "cache_acceleration_ready_for_two_family_launch":
        write_text(ctx.run_root / "prelaunch/next_accelerated_two_family_command.md", "# Next Accelerated Two-Family Command\n\nNot executed in this phase. Command must be generated with fresh run root after operator approval.\n")


def active_boundary_reference_root(ctx: Context) -> Path:
    if bool(getattr(ctx.args, "smoke", False)):
        return ctx.run_root / "tmp/mock_active_boundary_run"
    return ACTIVE_BOUNDARY_REFERENCE_RUN_ROOT


def active_boundary_cache_foundation_root() -> Path:
    return ACTIVE_BOUNDARY_CACHE_FOUNDATION_ROOT


def active_boundary_tmux_session() -> str:
    return "kraken_two_family_memorysafe_20260706"


def tmux_session_pid(session: str) -> str:
    try:
        out = subprocess.check_output(["tmux", "list-panes", "-t", session, "-F", "#{pane_pid}"], text=True, stderr=subprocess.DEVNULL).strip()
        return out.splitlines()[0] if out else ""
    except Exception:
        return ""


def active_boundary_tsmom_done(root: Path) -> bool:
    return (root / "stage_status/tsmom-v4-v5-aggregate-screen.done").exists()


def active_boundary_later_stage_started(root: Path) -> bool:
    later = [
        "tsmom-targeted-materialization-if-nonfutile",
        "prior-high-family-contract-and-manifest-v1",
        "prior-high-reclaim-mechanical-canary",
        "prior-high-reclaim-v1-aggregate-screen",
        "prior-high-reclaim-targeted-materialization-if-nonfutile",
        "cross-family-analysis-ready-publication",
    ]
    return any((root / "stage_status" / f"{stage}.done").exists() for stage in later)


def active_boundary_protocol_failure(root: Path) -> bool:
    watch = read_json(root / "watch_status.json", {})
    decision = read_json(root / "decision_summary.json", {})
    return str(watch.get("status", "")).lower() in {"failed", "blocked", "interrupted_resource_guard"} or str(decision.get("status", "")).lower() in {"failed", "blocked", "interrupted", "interrupted_resource_guard"}


def active_boundary_operator_stop_requested(root: Path) -> bool:
    markers = ["STOP_REQUESTED", "STOP_AFTER_CURRENT_STAGE", "STOP_AFTER_TSMOM_AGGREGATE", "STOP_AFTER_CURRENT_ENGINE_WAVE"]
    return any((root / marker).exists() for marker in markers)


def active_boundary_progress_snapshot(root: Path) -> dict[str, Any]:
    watch = read_json(root / "watch_status.json", {})
    progress = read_json(root / "coarse/aggregate_progress.json", {})
    memory = read_csv_safe(root / "resources/memory_usage_timeseries.csv")
    last_mem = memory.tail(1).to_dict("records")[0] if not memory.empty else {}
    session = active_boundary_tmux_session()
    active = tmux_session_active(session)
    return {
        "active_run_root": str(root),
        "active_run_exists": root.exists(),
        "tmux_session": session,
        "tmux_session_active": active,
        "tmux_pane_pid": tmux_session_pid(session) if active else "",
        "current_stage": watch.get("stage", ""),
        "watch_status": watch.get("status", ""),
        "processed_candidate_symbol_rows": progress.get("processed_candidate_symbol_rows", ""),
        "total_candidate_symbol_rows": progress.get("total_candidate_symbol_rows", ""),
        "rows_per_sec": progress.get("rows_per_sec", ""),
        "eta_seconds": progress.get("eta_seconds", ""),
        "current_candidate_symbol": progress.get("current_symbol", ""),
        "rss_bytes": progress.get("rss_bytes", last_mem.get("rss_bytes", "")),
        "rss_gib": safe_float(progress.get("rss_bytes", last_mem.get("rss_bytes", 0)), 0.0) / 1024 ** 3 if progress.get("rss_bytes", last_mem.get("rss_bytes", "")) != "" else "",
        "protocol_failure_present": active_boundary_protocol_failure(root),
        "operator_stop_marker_present": active_boundary_operator_stop_requested(root),
        "tsmom_aggregate_done": active_boundary_tsmom_done(root),
        "later_stage_started": active_boundary_later_stage_started(root),
        "ts_utc": utc_now(),
    }


