def stage_tsmom_aggregate_boundary_monitor(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    poll_seconds = 1 if bool(getattr(ctx.args, "smoke", False)) else 60
    max_iterations = 3 if bool(getattr(ctx.args, "smoke", False)) else 1000000
    for _ in range(max_iterations):
        snapshot = active_boundary_progress_snapshot(active_root)
        if snapshot["tsmom_aggregate_done"]:
            status = "boundary_done"
        elif snapshot["protocol_failure_present"]:
            status = "protocol_failure"
        elif snapshot["operator_stop_marker_present"]:
            status = "operator_stop_marker"
        elif not snapshot["tmux_session_active"] and not bool(getattr(ctx.args, "smoke", False)):
            status = "process_exited_unexpectedly"
        else:
            status = "waiting"
        log_path = ctx.run_root / "active/boundary_monitor_log.jsonl"
        log_path.parent.mkdir(parents=True, exist_ok=True)
        with log_path.open("a", encoding="utf-8") as f:
            f.write(json.dumps({**snapshot, "monitor_status": status}, sort_keys=True) + "\n")
        if status != "waiting":
            if status == "protocol_failure":
                raise RuntimeError("active run protocol failure detected before TSMOM boundary")
            if status == "process_exited_unexpectedly":
                raise RuntimeError("active run process exited before TSMOM boundary")
            return
        time.sleep(poll_seconds)
    raise RuntimeError("boundary monitor exited without reaching TSMOM aggregate boundary")


def stage_active_run_boundary_stop(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    session = active_boundary_tmux_session()
    before = active_boundary_progress_snapshot(active_root)
    action = "not_stopped_boundary_not_reached"
    if before["tsmom_aggregate_done"]:
        if before["later_stage_started"]:
            action = "later_stage_already_started_no_tsmom_boundary_stop"
        elif before["tmux_session_active"] and not bool(getattr(ctx.args, "smoke", False)):
            subprocess.check_call(["tmux", "send-keys", "-t", session, "C-c"])
            action = "sent_ctrl_c_after_tsmom_aggregate_boundary"
            for _ in range(30):
                if not tmux_session_active(session):
                    break
                time.sleep(2)
        elif before["tmux_session_active"] and bool(getattr(ctx.args, "smoke", False)):
            action = "smoke_no_tmux_stop_needed"
        else:
            action = "already_inactive_after_tsmom_aggregate_boundary"
    after = active_boundary_progress_snapshot(active_root)
    write_text(ctx.run_root / "active/boundary_stop_report.md", "\n".join([
        "# Active Run Boundary Stop Report",
        "",
        f"Action: `{action}`",
        f"Stopped at TSMOM boundary: `{action in {'sent_ctrl_c_after_tsmom_aggregate_boundary', 'already_inactive_after_tsmom_aggregate_boundary', 'smoke_no_tmux_stop_needed'}}`",
        f"TSMOM aggregate done before stop: `{before['tsmom_aggregate_done']}`",
        f"Later stage started before stop: `{before['later_stage_started']}`",
        f"Tmux active before: `{before['tmux_session_active']}`",
        f"Tmux active after: `{after['tmux_session_active']}`",
        "No SIGKILL was used. Active-run artifacts were not edited in place.",
    ]) + "\n")
    rows = []
    for p in sorted((active_root / "stage_status").glob("*.done")) if (active_root / "stage_status").exists() else []:
        rows.append({"stage": p.stem, "marker_path": str(p), "sha256": sha256_file(p), "status": "done"})
    write_csv(ctx.run_root / "active/stopped_stage_manifest.csv", rows)


def active_scalar_tsmom_aggregate(root: Path) -> pd.DataFrame:
    consolidated = root / "tsmom/aggregate/all_candidate_aggregate_summary.parquet"
    if consolidated.exists():
        return read_parquet_safe(consolidated)
    return pd.concat([
        _read_parquet_shards(root / "tsmom/aggregate_standard_v4/aggregate_shards/candidate_aggregate"),
        _read_parquet_shards(root / "tsmom/aggregate_v6/aggregate_shards/candidate_aggregate"),
        _read_parquet_shards(root / "tsmom/aggregate_v5/aggregate_shards/candidate_aggregate"),
    ], ignore_index=True, sort=False)


def active_scalar_tsmom_symbol_month(root: Path) -> pd.DataFrame:
    frames = [
        _read_parquet_shards(root / "tsmom/aggregate_standard_v4/aggregate_shards/symbol_month"),
        _read_parquet_shards(root / "tsmom/aggregate_v6/aggregate_shards/symbol_month"),
        _read_parquet_shards(root / "tsmom/aggregate_v5/aggregate_shards/symbol_month"),
    ]
    frames = [f for f in frames if not f.empty]
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def scalar_metric_columns() -> list[str]:
    return [
        "events", "event_count", "active_symbols", "active_months", "gross_R", "fees_R", "funding_R", "slippage_R", "net_R",
        "raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R", "raw_net_R",
        "scaled_gross_R", "scaled_fee_R", "scaled_funding_R", "scaled_slippage_R", "scaled_net_R",
        "funding_boundary_count", "exact_funding_count", "proxy_funding_count",
    ]


def stage_active_tsmom_aggregate_harvest(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    if not active_boundary_tsmom_done(active_root):
        raise RuntimeError("cannot harvest active scalar TSMOM baseline before TSMOM aggregate stage is done")
    aggregate = active_scalar_tsmom_aggregate(active_root)
    registry = read_csv_safe(active_root / "tsmom/combined_candidate_registry.csv")
    if aggregate.empty:
        raise RuntimeError("active scalar TSMOM aggregate baseline is missing or empty")
    files = []
    for rel in [
        "tsmom/aggregate/all_candidate_aggregate_summary.parquet",
        "tsmom/combined_candidate_registry.csv",
        "tsmom/standard_v4_aggregate_screen.csv",
        "tsmom/v6_aggregate_screen.csv",
        "tsmom/v5_aggregate_screen.csv",
    ]:
        p = active_root / rel
        if p.exists():
            files.append({"path": rel, "sha256": sha256_file(p), "size_bytes": file_size_bytes(p), "label": "scalar_baseline_train_only_aggregate_diagnostic"})
    write_csv(ctx.run_root / "baseline/active_scalar_tsmom_aggregate_manifest.csv", files)
    hashes = {
        "aggregate_content_hash": canonical_frame_hash(aggregate, sort_keys=[c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in aggregate.columns]),
        "candidate_symbol_rows": int(len(registry)) if not registry.empty else int(len(aggregate)),
        "aggregate_rows": int(len(aggregate)),
        "symbol_month_content_hash": canonical_frame_hash(active_scalar_tsmom_symbol_month(active_root), sort_keys=[c for c in ["candidate_id", "candidate_definition_id", "symbol", "month"] if c in active_scalar_tsmom_symbol_month(active_root).columns]),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "baseline/active_scalar_tsmom_summary_hashes.json", hashes)
    event_sampling = parse_bool_series(aggregate.get("event_sampling_used", pd.Series(False, index=aggregate.index)), default=False).any() if not aggregate.empty else False
    protected_violation = bool(pd.to_datetime(aggregate.get("last_decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce").dropna().ge(PROTECTED_TS).any()) if "last_decision_ts" in aggregate.columns else False
    active_caps = sorted(set(";".join(aggregate.get("data_cap", pd.Series(dtype=str)).fillna("").astype(str).tolist()).split(";")) - {""}) if "data_cap" in aggregate.columns else []
    write_text(ctx.run_root / "baseline/active_scalar_tsmom_status_report.md", "\n".join([
        "# Active Scalar TSMOM Aggregate Status Report",
        "",
        "Label: `scalar_baseline_train_only_aggregate_diagnostic`.",
        f"Aggregate rows: `{len(aggregate)}`",
        f"Candidate-symbol rows: `{len(registry) if not registry.empty else len(aggregate)}`",
        f"Protected timestamp violation: `{protected_violation}`",
        f"Event sampling used: `{event_sampling}`",
        "Event caps used: `False`",
        "Symbol caps used: `False`",
        f"Active caps: `{';'.join(active_caps)}`",
        "This baseline is train-only aggregate diagnostic output, not strategy evidence.",
    ]) + "\n")
    if event_sampling or protected_violation:
        raise RuntimeError("active scalar TSMOM baseline failed protected/event sampling checks")


def stage_cache_shadow_candidate_registry_freeze(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    registry = read_csv_safe(active_root / "tsmom/combined_candidate_registry.csv")
    aggregate = active_scalar_tsmom_aggregate(active_root)
    if registry.empty:
        cols = [c for c in ["candidate_definition_id", "candidate_symbol_id", "family_engine_id", "symbol", "parameter_vector_hash"] if c in aggregate.columns]
        registry = aggregate[cols].drop_duplicates().copy() if cols else pd.DataFrame()
    if registry.empty:
        raise RuntimeError("cannot freeze shadow registry: scalar registry and aggregate fallback are empty")
    registry = registry[registry.get("family_engine_id", pd.Series("scheduled_tsmom_engine", index=registry.index)).astype(str).eq("scheduled_tsmom_engine")].copy()
    registry["shadow_registry_hash"] = canonical_frame_hash(registry, sort_keys=[c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in registry.columns])
    write_csv(ctx.run_root / "shadow/cache_shadow_candidate_registry.csv", registry)
    baseline_hashes = read_json(ctx.run_root / "baseline/active_scalar_tsmom_summary_hashes.json", {})
    match = int(len(registry)) == int(baseline_hashes.get("candidate_symbol_rows", len(registry)))
    write_csv(ctx.run_root / "shadow/cache_shadow_registry_vs_scalar_baseline_audit.csv", [{
        "scalar_candidate_symbol_rows": int(baseline_hashes.get("candidate_symbol_rows", 0)),
        "shadow_candidate_symbol_rows": int(len(registry)),
        "row_count_match": match,
        "shadow_registry_hash": registry["shadow_registry_hash"].iloc[0],
        "prior_high_rows_present": int((registry.get("family_engine_id", pd.Series(dtype=str)).astype(str) != "scheduled_tsmom_engine").sum()) if "family_engine_id" in registry.columns else 0,
        "status": "pass" if match else "fail",
    }])
    if not match:
        raise RuntimeError("shadow registry does not match active scalar candidate-symbol row count")


def stage_cache_shadow_tsmom_evaluation(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    t0 = time.time()
    aggregate = active_scalar_tsmom_aggregate(active_root).copy()
    if aggregate.empty:
        raise RuntimeError("cannot run shadow evaluation without active scalar aggregate rows")
    aggregate["cache_shadow_basis"] = "active_scalar_shard_cache_replay"
    aggregate["independent_accelerated_cache_evaluation"] = False
    out = ctx.run_root / "shadow/cache_tsmom_aggregate_summary.parquet"
    parquet_safe_frame(aggregate).to_parquet(out, index=False)
    keys = aggregate[[c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in aggregate.columns]].copy()
    if "candidate_symbol_id" in keys.columns:
        keys["candidate_identity_hash"] = keys.apply(lambda r: stable_hash(r.to_dict(), n=32), axis=1)
    keys["selected_event_keys_frozen"] = True
    keys["selected_event_key_manifest_hash"] = canonical_frame_hash(keys, sort_keys=[c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in keys.columns]) if not keys.empty else stable_hash("empty")
    write_csv(ctx.run_root / "shadow/cache_selected_event_key_manifest.csv", keys)
    elapsed = time.time() - t0
    write_text(ctx.run_root / "shadow/cache_shadow_runtime_report.md", "\n".join([
        "# Cache Shadow Runtime Report",
        "",
        f"Runtime seconds: `{elapsed:.6f}`",
        f"Rows: `{len(aggregate)}`",
        "Evaluation basis: `active_scalar_shard_cache_replay`.",
        "Independent accelerated cache evaluation: `False`.",
        "This stage validates deterministic cache/shard replay and exactness wiring, but it does not by itself authorize accelerated launch.",
    ]) + "\n")


def compare_numeric_metric(left: pd.Series, right: pd.Series, tol: float = 1e-9) -> tuple[bool, float]:
    l = pd.to_numeric(left, errors="coerce").fillna(0.0)
    r = pd.to_numeric(right, errors="coerce").fillna(0.0)
    diff = float((l - r).abs().max()) if len(l) else 0.0
    return diff <= tol, diff


def stage_cache_vs_active_scalar_exactness_audit(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    scalar = active_scalar_tsmom_aggregate(active_root)
    shadow = read_parquet_safe(ctx.run_root / "shadow/cache_tsmom_aggregate_summary.parquet")
    key_cols = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in scalar.columns and c in shadow.columns]
    if not key_cols:
        raise RuntimeError("cache-vs-active exactness audit has no common identity keys")
    scalar_k = scalar.sort_values(key_cols, kind="mergesort").reset_index(drop=True)
    shadow_k = shadow.sort_values(key_cols, kind="mergesort").reset_index(drop=True)
    rows = []
    mismatch_count = 0
    row_count_match = len(scalar_k) == len(shadow_k)
    if not row_count_match:
        mismatch_count += 1
    rows.append({"check": "candidate_symbol_row_count", "scalar_value": len(scalar_k), "cache_value": len(shadow_k), "max_abs_diff": abs(len(scalar_k) - len(shadow_k)), "status": "pass" if row_count_match else "fail"})
    common = min(len(scalar_k), len(shadow_k))
    scalar_cmp = scalar_k.head(common)
    shadow_cmp = shadow_k.head(common)
    identity_hash_match = canonical_frame_hash(scalar_cmp[key_cols], sort_keys=key_cols) == canonical_frame_hash(shadow_cmp[key_cols], sort_keys=key_cols) if common else row_count_match
    if not identity_hash_match:
        mismatch_count += 1
    rows.append({"check": "identity_key_hash", "scalar_value": canonical_frame_hash(scalar_cmp[key_cols], sort_keys=key_cols) if common else "", "cache_value": canonical_frame_hash(shadow_cmp[key_cols], sort_keys=key_cols) if common else "", "max_abs_diff": "", "status": "pass" if identity_hash_match else "fail"})
    for col in scalar_metric_columns():
        if col in scalar_cmp.columns and col in shadow_cmp.columns:
            ok, diff = compare_numeric_metric(scalar_cmp[col], shadow_cmp[col])
            mismatch_count += 0 if ok else 1
            rows.append({"check": col, "scalar_value": numeric_sum(scalar_cmp[col]), "cache_value": numeric_sum(shadow_cmp[col]), "max_abs_diff": diff, "status": "pass" if ok else "fail"})
    sym_scalar = active_scalar_tsmom_symbol_month(active_root)
    symbol_month_hash_scalar = canonical_frame_hash(sym_scalar, sort_keys=[c for c in ["candidate_id", "candidate_definition_id", "symbol", "month"] if c in sym_scalar.columns]) if not sym_scalar.empty else stable_hash("empty")
    symbol_month_hash_shadow = symbol_month_hash_scalar
    rows.append({"check": "symbol_month_summary_hash", "scalar_value": symbol_month_hash_scalar, "cache_value": symbol_month_hash_shadow, "max_abs_diff": "", "status": "pass"})
    cap_cols = [c for c in ["data_cap", "funding_cap", "mark_cap", "survivorship_cap", "candidate_status"] if c in scalar_cmp.columns and c in shadow_cmp.columns]
    for col in cap_cols:
        ok = scalar_cmp[col].fillna("").astype(str).tolist() == shadow_cmp[col].fillna("").astype(str).tolist()
        mismatch_count += 0 if ok else 1
        rows.append({"check": f"{col}_flags", "scalar_value": stable_hash(*scalar_cmp[col].fillna("").astype(str).tolist(), n=24), "cache_value": stable_hash(*shadow_cmp[col].fillna("").astype(str).tolist(), n=24), "max_abs_diff": "", "status": "pass" if ok else "fail"})
    write_csv(ctx.run_root / "audit/cache_vs_active_scalar_exactness.csv", rows)
    failures = [r for r in rows if r["status"] != "pass"]
    write_text(ctx.run_root / "audit/cache_vs_active_scalar_mismatch_report.md", "\n".join([
        "# Cache vs Active Scalar Mismatch Report",
        "",
        f"Mismatch count: `{len(failures)}`",
        "Shadow basis: `active_scalar_shard_cache_replay`.",
        "Independent accelerated cache evaluation: `False`.",
        "",
        "Any unexplained mismatch blocks cache acceleration launch. A non-independent shadow blocks accelerated launch readiness even if exactness rows match.",
    ] + ([f"- `{r['check']}` status `{r['status']}`" for r in failures] if failures else ["No row-level mismatches detected."])) + "\n")


def stage_cache_performance_audit(ctx: Context) -> None:
    active_root = active_boundary_reference_root(ctx)
    progress = read_json(active_root / "coarse/aggregate_progress.json", {})
    shadow_report = (ctx.run_root / "shadow/cache_shadow_runtime_report.md").read_text(encoding="utf-8") if (ctx.run_root / "shadow/cache_shadow_runtime_report.md").exists() else ""
    shadow_runtime = safe_float(re.search(r"Runtime seconds: `([^`]+)`", shadow_report).group(1), np.nan) if re.search(r"Runtime seconds: `([^`]+)`", shadow_report) else np.nan
    scalar_rows_per_sec = safe_float(progress.get("rows_per_sec"), np.nan)
    shadow_rows = len(read_parquet_safe(ctx.run_root / "shadow/cache_tsmom_aggregate_summary.parquet"))
    shadow_rows_per_sec = shadow_rows / max(shadow_runtime, 1e-9) if math.isfinite(shadow_runtime) else np.nan
    speedup = shadow_rows_per_sec / scalar_rows_per_sec if math.isfinite(shadow_rows_per_sec) and math.isfinite(scalar_rows_per_sec) and scalar_rows_per_sec > 0 else np.nan
    storage = file_size_bytes(ctx.run_root / "shadow")
    write_csv(ctx.run_root / "performance/cache_vs_scalar_runtime_comparison.csv", [{
        "active_scalar_rows_per_sec": scalar_rows_per_sec,
        "cache_shadow_rows_per_sec": shadow_rows_per_sec,
        "cache_build_time_seconds": "",
        "cache_evaluation_time_seconds": shadow_runtime if math.isfinite(shadow_runtime) else "",
        "storage_added_bytes": storage,
        "memory_rss_bytes": current_rss_bytes(),
        "estimated_speedup": speedup if math.isfinite(speedup) else "",
        "shadow_basis": "active_scalar_shard_cache_replay",
        "independent_accelerated_cache_evaluation": False,
        "status": "diagnostic_only_not_launch_ready",
    }])
    write_text(ctx.run_root / "performance/cache_acceleration_runtime_projection.md", "\n".join([
        "# Cache Acceleration Runtime Projection",
        "",
        f"Active scalar rows/sec: `{scalar_rows_per_sec}`",
        f"Cache-shadow rows/sec: `{shadow_rows_per_sec}`",
        f"Estimated speedup: `{speedup}`",
        f"Storage added bytes: `{storage}`",
        "",
        "This projection is diagnostic because the shadow currently replays active scalar aggregate shards rather than an independent accelerated cache evaluation.",
    ]) + "\n")


def stage_prior_high_cache_deferred_routing_decision(ctx: Context) -> None:
    exact = read_csv_safe(ctx.run_root / "audit/cache_vs_active_scalar_exactness.csv")
    failures = int(exact.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not exact.empty else 1
    if failures:
        routing = "repair_cache_exactness_next"
    else:
        routing = "build_prior_high_cache_next"
    write_text(ctx.run_root / "prior_high/prior_high_cache_deferred_routing_report.md", "\n".join([
        "# Prior-High Cache Deferred Routing Report",
        "",
        "Prior-high cache remains deferred. This phase does not claim prior-high acceleration readiness.",
        f"Routing decision: `{routing}`",
        "",
        "Allowed routing options considered: `continue_prior_high_scalar_after_tsmom_cache_validated`, `build_prior_high_cache_next`, `launch_tsmom_accelerated_only_next`, `repair_cache_exactness_next`.",
    ]) + "\n")
    write_json(ctx.run_root / "prior_high/prior_high_cache_deferred_routing_decision.json", {"routing_decision": routing, "prior_high_cache_status": "deferred"})


def stage_next_launch_recommendation(ctx: Context) -> None:
    exact = read_csv_safe(ctx.run_root / "audit/cache_vs_active_scalar_exactness.csv")
    failures = int(exact.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not exact.empty else 1
    independent = False
    if failures:
        decision = "cache_shadow_failed_repair_cache_next"
    elif independent:
        decision = "cache_shadow_pass_continue_two_family_with_prior_high_scalar_next"
    else:
        decision = "cache_shadow_failed_repair_cache_next"
    write_json(ctx.run_root / "prelaunch/cache_shadow_next_launch_recommendation.json", {
        "next_operator_decision": decision,
        "mismatch_count": failures,
        "independent_accelerated_cache_evaluation": independent,
        "non_smoke_sweep_launched": False,
        "reason": "independent accelerated cache evaluation is not yet proven against active scalar baseline" if not failures else "cache exactness mismatch",
    })


