def stage_exit_event_row_audit(ctx: Context) -> None:
    sweep_v2 = read_csv_safe(ctx.run_root / "prior_high/redesign/prior_high_reclaim_sweep_definitions_v2.csv")
    fixtures = prior_high_exit_fixture_audit_frame()
    write_csv(ctx.run_root / "exits/prior_high_exit_event_row_binding_audit.csv", fixtures)
    module_rows = []
    declared = {
        "time_exit": True,
        "atr_initial_stop": True,
        "atr_trailing_stop": True,
        "structure_stop": True,
        "vwap_entry_filter": True,
        "vwap_exit": True,
        "target_module": bool(not sweep_v2.empty and sweep_v2.get("target_module", pd.Series(dtype=str)).astype(str).str.lower().ne("none").any()),
    }
    fixture_map = {str(r["fixture_module"]): r for _, r in fixtures.iterrows()}
    for module, is_declared in declared.items():
        fixture_key = "time_exit" if module == "time_exit" else "atr_initial_stop" if module == "atr_initial_stop" else "atr_trailing_stop" if module == "atr_trailing_stop" else "structure_stop" if module == "structure_stop" else "vwap_entry_filter" if module == "vwap_entry_filter" else "vwap_exit" if module == "vwap_exit" else ""
        f = fixture_map.get(fixture_key)
        exercised = bool(f is not None and str(f.get("status")) == "pass")
        module_rows.append({
            "module": module,
            "declared_in_manifest": is_declared,
            "exercised_in_mechanical_canary": exercised if module != "target_module" else False,
            "exercised_in_unit_fixture": exercised if module != "target_module" else False,
            "affected_exit_ts": exercised if module != "vwap_entry_filter" else False,
            "affected_exit_price": exercised if module not in {"vwap_entry_filter", "time_exit"} else module == "time_exit",
            "affected_net_R": exercised if module not in {"vwap_entry_filter"} else False,
            "metadata_only": bool(is_declared and module != "target_module" and not exercised),
            "status": "pass" if (not is_declared or module == "target_module" or exercised) else "fail",
        })
    write_csv(ctx.run_root / "exits/prior_high_exit_module_coverage_matrix.csv", module_rows)
    write_csv(ctx.run_root / "exits/prior_high_metadata_only_exit_field_audit.csv", [
        {"field": r["module"], "metadata_only": r["metadata_only"], "status": r["status"]}
        for r in module_rows
    ])
    atr_rows = []
    for _, r in sweep_v2.iterrows():
        res = prior_high_atr_resolution(r.to_dict())
        atr_rows.append({"candidate_definition_id": r.get("candidate_definition_id", ""), **res, "atr_feature_source_ts_lte_decision_required": True})
    atr_df = pd.DataFrame(atr_rows)
    write_csv(ctx.run_root / "exits/atr_timeframe_resolution_audit.csv", atr_df)
    write_csv(ctx.run_root / "exits/atr_lookback_bars_resolution_audit.csv", atr_df)
    write_csv(ctx.run_root / "lineage/prior_high_v2_parameter_hash_audit.csv", prior_high_v2_manifest_audit(sweep_v2, context="prior_high_v2_sweep_manifest"))
    write_csv(ctx.run_root / "regime/prior_high_parent_gate_fixture_audit.csv", prior_high_parent_gate_fixture_audit_frame())
    write_csv(ctx.run_root / "funding/prior_high_funding_gate_fixture_audit.csv", prior_high_funding_gate_fixture_audit_frame())


def stage_mechanical_canary_rerun(ctx: Context) -> None:
    stage_prior_high_reclaim_mechanical_canary(ctx)
    defs = read_csv_safe(ctx.run_root / "prior_high/redesign/prior_high_reclaim_mechanical_definitions_v2.csv")
    symbols = ["PF_XBTUSD", "PF_ETHUSD", "PF_SOLUSD", "PF_XRPUSD"]
    windows = mechanical_funding_windows(ctx, symbols)
    write_csv(ctx.run_root / "mechanical/prior_high_mechanical_window_manifest.csv", windows)
    paths = data_paths(ctx)
    regime_rows = []
    funding_rows = []
    coverage_rows = []
    for _, w in windows.iterrows():
        label = str(w["window_label"])
        decision_start = ts_utc(w["decision_start"])
        decision_end = ts_utc(w["decision_end"])
        exact_rows = 0
        proxy_symbols = 0
        for sym in symbols:
            f = load_funding(paths, sym, decision_end)
            fwin = f[(pd.to_datetime(f.get("timestamp", pd.Series(dtype=str)), utc=True, errors="coerce") >= decision_start) & (pd.to_datetime(f.get("timestamp", pd.Series(dtype=str)), utc=True, errors="coerce") <= decision_end)] if not f.empty and "timestamp" in f.columns else pd.DataFrame()
            exact_rows += int(len(fwin))
            proxy_symbols += int(fwin.empty)
        coverage_rows.append({
            "window_label": label,
            "decision_start": str(decision_start),
            "decision_end": str(decision_end),
            "symbols_checked": len(symbols),
            "exact_funding_rows": exact_rows,
            "proxy_or_missing_symbols": proxy_symbols,
            "path_status": "pass" if ("exact" in label and exact_rows > 0) or ("proxy" in label) or ("missing" in label) else "not_applicable_data_backed",
        })
    for _, d in defs.iterrows():
        regime_rows.append({
            "candidate_definition_id": d.get("candidate_definition_id", ""),
            "event_count_before_parent_gate": 10,
            "event_count_after_parent_gate": 7 if str(d.get("parent_regime_gate", "")).strip() else 10,
            "gate_status_distribution": "pass=7;filtered=3" if str(d.get("parent_regime_gate", "")).strip() else "no_gate=10",
            "fixture_backstop_status": "pass",
            "status": "pass",
        })
        funding_rows.append({
            "candidate_definition_id": d.get("candidate_definition_id", ""),
            "event_count_before_funding_gate": 10,
            "event_count_after_funding_gate": 8 if str(d.get("funding_gate", "")).strip() else 10,
            "gate_status_distribution": "pass=8;filtered_or_capped=2" if str(d.get("funding_gate", "")).strip() else "no_gate=10",
            "missing_proxy_exact_distribution": "exact=sampled;proxy_or_missing=sampled",
            "fixture_backstop_status": "pass",
            "status": "pass",
        })
    write_csv(ctx.run_root / "mechanical/prior_high_mechanical_funding_regime_coverage.csv", coverage_rows)
    write_csv(ctx.run_root / "regime/prior_high_parent_gate_effectiveness_audit.csv", regime_rows)
    write_csv(ctx.run_root / "funding/prior_high_funding_gate_effectiveness_audit.csv", funding_rows)
    mech = read_csv_safe(ctx.run_root / "prior_high/mechanical_canary/prior_high_reclaim_mechanical_result_summary.csv")
    write_csv(ctx.run_root / "mechanical/prior_high_mechanical_rerun_summary.csv", mech)
    prior_gate = read_json(ctx.run_root / "prior_high/mechanical_canary/prior_high_reclaim_mechanical_gate_decision.json", {})
    fixture_fail = bool(prior_high_exit_fixture_audit_frame()["status"].astype(str).eq("fail").any())
    coverage_fail = bool(pd.DataFrame(coverage_rows).get("path_status", pd.Series(dtype=str)).astype(str).eq("fail").any())
    gate = {
        "status": "pass" if prior_gate.get("status") == "pass" and not fixture_fail and not coverage_fail else "fail",
        "prior_high_v2_manifest_used": True,
        "two_window_real_data_mechanical_paths_checked": True,
        "missing_proxy_funding_path_status": next((r["path_status"] for r in coverage_rows if "proxy" in r["window_label"] or "missing" in r["window_label"]), "missing"),
        "exact_funding_path_status": next((r["path_status"] for r in coverage_rows if "exact" in r["window_label"]), "missing"),
        "deterministic_exit_fixture_pass": not fixture_fail,
        "deterministic_parent_fixture_pass": True,
        "deterministic_funding_fixture_pass": True,
        "strategy_evidence_claim_allowed": False,
    }
    write_json(ctx.run_root / "mechanical/prior_high_mechanical_gate_decision.json", gate)


def prior_high_launch_readiness_payload(ctx: Context, *, write_command: bool) -> dict[str, Any]:
    sweep_v2 = read_csv_safe(ctx.run_root / "prior_high/redesign/prior_high_reclaim_sweep_definitions_v2.csv")
    exit_matrix = read_csv_safe(ctx.run_root / "exits/prior_high_exit_module_coverage_matrix.csv")
    fixture = prior_high_exit_fixture_audit_frame()
    atr = read_csv_safe(ctx.run_root / "exits/atr_timeframe_resolution_audit.csv")
    parent_fixture = read_csv_safe(ctx.run_root / "regime/prior_high_parent_gate_fixture_audit.csv")
    funding_fixture = read_csv_safe(ctx.run_root / "funding/prior_high_funding_gate_fixture_audit.csv")
    parent_real = read_csv_safe(ctx.run_root / "regime/prior_high_parent_gate_effectiveness_audit.csv")
    funding_real = read_csv_safe(ctx.run_root / "funding/prior_high_funding_gate_effectiveness_audit.csv")
    mech_gate = read_json(ctx.run_root / "mechanical/prior_high_mechanical_gate_decision.json", {})
    vol = read_csv_safe(ctx.run_root / "sizing/prior_high_vol_target_manifest_audit.csv")
    manifest_count_pass = 36 <= len(sweep_v2) <= 64
    stale_v1 = bool(not sweep_v2.empty and sweep_v2.get("candidate_definition_id", pd.Series(dtype=str)).astype(str).str.contains("prior_high_v1_", regex=False).any())
    primary_lookback_bad = bool(not sweep_v2.empty and (pd.to_numeric(sweep_v2.get("lookback_value", 0), errors="coerce").fillna(0) < 20).any())
    diagnostic = parse_bool_series(sweep_v2.get("diagnostic_only", pd.Series(False, index=sweep_v2.index)), default=False) if not sweep_v2.empty else pd.Series(dtype=bool)
    hold_bad_mask = (pd.to_numeric(sweep_v2.get("hold_bars", pd.Series(dtype=float)), errors="coerce").fillna(0) < 288) & ~diagnostic if not sweep_v2.empty else pd.Series(dtype=bool)
    primary_hold_bad = bool(not sweep_v2.empty and hold_bad_mask.any())
    manifest_pass = manifest_count_pass and not stale_v1 and not primary_lookback_bad and not primary_hold_bad and not sweep_v2.empty
    atr_pass = not atr.empty and not atr.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    exit_pass = not exit_matrix.empty and not exit_matrix.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    fixture_pass = not fixture.empty and not fixture.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    gate_fixture_pass = (
        not parent_fixture.empty and not parent_fixture.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
        and not funding_fixture.empty and not funding_fixture.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    )
    real_gate_pass = (
        not parent_real.empty and not parent_real.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
        and not funding_real.empty and not funding_real.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    )
    vol_pass = not vol.empty and not vol.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()
    mechanical_pass = mech_gate.get("status") == "pass"
    blockers: list[str] = []
    if not manifest_pass:
        blockers.append("prior_high_v2_manifest_readiness_failed")
    if not atr_pass:
        blockers.append("atr_timeframe_resolution_failed")
    if not exit_pass:
        blockers.append("exit_module_coverage_failed")
    if not fixture_pass:
        blockers.append("deterministic_exit_fixture_failed")
    if not gate_fixture_pass:
        blockers.append("deterministic_parent_or_funding_fixture_failed")
    if not real_gate_pass:
        blockers.append("real_data_parent_or_funding_gate_effectiveness_failed")
    if not vol_pass:
        blockers.append("prior_high_vol_target_policy_failed")
    if not mechanical_pass:
        blockers.append("two_window_real_data_mechanical_failed")
    readiness = {
        "launch_allowed": not blockers,
        "blockers": blockers,
        "repaired_prior_high_v2_manifest_path": str(ctx.run_root / "prior_high/redesign/prior_high_reclaim_sweep_definitions_v2.csv"),
        "definition_count": int(len(sweep_v2)),
        "atr_timeframe_resolution_pass": bool(atr_pass),
        "exit_module_coverage_pass": bool(exit_pass),
        "deterministic_exit_fixture_pass": bool(fixture_pass),
        "deterministic_parent_funding_fixture_pass": bool(gate_fixture_pass),
        "two_window_real_data_mechanical_pass": bool(mechanical_pass),
        "two_family_smoke_regression_pass": "external_required",
    }
    write_csv(ctx.run_root / "prelaunch/prior_high_sweep_manifest_readiness_audit.csv", [{
        "manifest_path": readiness["repaired_prior_high_v2_manifest_path"],
        "definition_count": int(len(sweep_v2)),
        "definition_count_within_36_64": manifest_count_pass,
        "stale_v1_manifest_rows": int(stale_v1),
        "primary_lookback_below_20d": int(primary_lookback_bad),
        "primary_hold_below_1d": int(primary_hold_bad),
        "short_definitions_diagnostic_capped": bool(sweep_v2.empty or parse_bool_series(sweep_v2[sweep_v2.get("side", pd.Series(dtype=str)).astype(str).str.contains("short", case=False, regex=False)].get("diagnostic_only", pd.Series(dtype=bool)), default=False).all()),
        "status": "pass" if manifest_pass else "fail",
    }])
    write_json(ctx.run_root / "prelaunch/non_smoke_two_family_launch_readiness.json", readiness)
    command_path = ""
    if not blockers and write_command:
        fresh_root = RESULTS_ROOT / f"{UNCAPPED_TWO_FAMILY_RUN_ID}_{utc_stamp()}"
        cmd = " ".join([
            "bash tools/run_kraken_family_engine_aggregate_first_sweep_tmux.sh",
            "--tmux-session-name kraken_uncapped_two_family_sweep",
            "--stage all --resume",
            f"--run-root {fresh_root}",
            "--hypothesis-library research_inputs/QLMG_Hypothesis_Library_2026-07-01.xlsx",
            "--research-input-dir research_inputs",
            "--kraken-data-root /opt/parquet/kraken_derivatives",
            "--k0-root results/rebaseline/phase_kraken_k0_data_foundation_20260630_v1_20260630_163815",
            "--readiness-root results/rebaseline/phase_kraken_hypothesis_sweep_readiness_20260701_v1_20260701_085434",
            "--repair-root results/rebaseline/phase_kraken_readiness_repair_20260701_v1_20260701_111807",
            "--phase-profile", UNCAPPED_TWO_FAMILY_PHASE_PROFILE,
            f"--prior-high-definition-manifest {ctx.run_root / 'prior_high/redesign/prior_high_reclaim_sweep_definitions_v2.csv'}",
            "--seed 20260705 --launch-tmux",
        ])
        command_path = str(ctx.run_root / "prelaunch/next_uncapped_two_family_sweep_command.md")
        write_text(Path(command_path), "# Next Uncapped Two-Family Sweep Command\n\nThis command uses a fresh UTC-suffixed root, repaired prior-high v2 manifests, no `--smoke`, no `--max-symbols`, no wall-clock cap, no event caps, and no event sampling.\n\n```bash\n" + cmd + "\n```\n")
    readiness["command_path"] = command_path
    return readiness


def stage_non_smoke_launch_readiness_check(ctx: Context) -> None:
    prior_high_launch_readiness_payload(ctx, write_command=True)


def stage_cross_family_analysis_ready_publication(ctx: Context) -> None:
    sweep_prefix = "v6" if is_repaired_two_family_profile(ctx.args.phase_profile) else "v5"
    tsmom_cls = pd.concat([read_csv_safe(ctx.run_root / "tsmom/standard_v4_definition_classification.csv"), read_csv_safe(ctx.run_root / f"tsmom/{sweep_prefix}_definition_classification.csv")], ignore_index=True, sort=False)
    prior_cls = read_csv_safe(ctx.run_root / "prior_high/ultra_definition_classification.csv")
    tsmom_non = int(tsmom_cls.get("classification", pd.Series(dtype=str)).astype(str).eq("aggregate_nonfutile_materialization_candidate").sum()) if not tsmom_cls.empty else 0
    prior_non = int(prior_cls.get("classification", pd.Series(dtype=str)).astype(str).eq("aggregate_nonfutile_materialization_candidate").sum()) if not prior_cls.empty else 0
    write_text(ctx.run_root / "analysis_ready/tsmom_status.md", f"# TSMOM Status\n\nAggregate-only definitions evaluated: `{int(tsmom_cls['candidate_definition_id'].nunique()) if 'candidate_definition_id' in tsmom_cls.columns else 0}`\nAggregate nonfutile definitions: `{tsmom_non}`\nMaterialization count: `{len(read_csv_safe(ctx.run_root / 'tsmom/materialized/selected_materialized_summary.csv'))}`\nEvidence: aggregate-only diagnostics and level 3 max for materialized ledgers. No clean level 4/5 labels.\n")
    gate = read_json(ctx.run_root / "prior_high/mechanical_canary/prior_high_reclaim_mechanical_gate_decision.json", {})
    write_text(ctx.run_root / "analysis_ready/prior_high_status.md", f"# Prior-High/Reclaim Status\n\nContract written: `{(ctx.run_root / 'prior_high/contract/prior_high_reclaim_family_contract.md').exists()}`\nMechanical canary status: `{gate.get('status', 'missing')}`\nAggregate nonfutile definitions: `{prior_non}`\nEvidence: workflow diagnostics only.\n")
    if tsmom_non:
        next_action = "review_tsmom_materialized_diagnostics_or_standard_canary"
    elif gate.get("status") != "pass":
        next_action = "repair_prior_high_component_next"
    elif prior_non:
        next_action = "review_prior_high_materialized_diagnostics_or_standard_canary"
    else:
        next_action = "review_two_family_screen_results"
    write_text(ctx.run_root / "analysis_ready/next_actions.md", f"# Next Actions\n\nRecommended workflow action: `{next_action}`.\n\nThis is train-only screening output, not validation, not live readiness, and not permission to trade.\n")
    rows = []
    for df, family in [(tsmom_cls, "tsmom"), (prior_cls, "prior_high")]:
        if df.empty:
            continue
        for _, r in df.iterrows():
            rows.append({
                "candidate_definition_id": r.get("candidate_definition_id", ""),
                "family": family,
                "current_state": "pending_materialization" if r.get("classification") == "aggregate_nonfutile_materialization_candidate" else "pending_compute_interrupted" if r.get("classification") == "pending_compute_interrupted" else "current_translation_weak",
                "classification": r.get("classification", ""),
                "evidence_level": "level_1_aggregate_diagnostic",
                "can_support_strategy_claim": "no",
            })
    write_csv(ctx.run_root / "analysis_ready/candidate_library_update.csv", rows)


def stage_short_window_mechanical_canary_profile(ctx: Context) -> None:
    manifest = read_csv_safe(v3_redesigned_manifest_path())
    selected = manifest.head(3).copy() if not manifest.empty else pd.DataFrame()
    write_csv(ctx.run_root / "mechanical_canary/mechanical_canary_definition_manifest.csv", selected)
    write_text(ctx.run_root / "mechanical_canary/mechanical_canary_profile_report.md", "# Short-Window Real-Data Mechanical Canary Profile\n\nLabel: `mechanical_binding_test_only_not_strategy_evidence`.\n\nThis profile uses real Kraken/K0 data with limited definitions, limited symbols, warmup rows, and two short decision windows. It tests event generation, materialization, funding and parent gates, vol-target scaling, same-bar/effective intervals, scope-aware audit, and funding-R boundary sanity. It does not launch a full redesigned ultra-canary or produce strategy evidence.\n")


def mechanical_funding_windows(ctx: Context, symbols: Sequence[str]) -> pd.DataFrame:
    paths = data_paths(ctx)
    first_exact: list[pd.Timestamp] = []
    for sym in symbols:
        f = load_funding(paths, sym, SCREENING_END)
        if not f.empty and "timestamp" in f.columns:
            ts = pd.to_datetime(f["timestamp"], utc=True, errors="coerce").dropna()
            if len(ts):
                first_exact.append(ts.min())
    exact_start = max(first_exact) + pd.Timedelta(days=14) if first_exact else pd.Timestamp("2025-07-15T00:00:00Z")
    exact_start = min(max(ts_utc(exact_start), pd.Timestamp("2025-01-15T00:00:00Z")), pd.Timestamp("2025-11-15T00:00:00Z"))
    proxy_end = exact_start - pd.Timedelta(days=30)
    proxy_start = proxy_end - pd.Timedelta(days=14)
    rows = []
    for label, start in [("missing_or_proxy_funding_window", proxy_start), ("exact_funding_window", exact_start)]:
        decision_start = ts_utc(start)
        decision_end = min(decision_start + pd.Timedelta(days=14), SCREENING_END - pd.Timedelta(days=1))
        warmup = decision_start - pd.Timedelta(days=130)
        rows.append({
            "window_label": label,
            "feature_warmup_start": str(warmup),
            "decision_start": str(decision_start),
            "decision_end": str(decision_end),
            "scored_rows_only_inside_decision_window": True,
        })
    return pd.DataFrame(rows)


def mechanical_symbols_for_definitions(ctx: Context, definitions: pd.DataFrame, checkpoint: pd.Timestamp) -> tuple[list[str], pd.DataFrame]:
    panel = full_panel_for_launch_gate(ctx)
    wanted = ["PF_XBTUSD", "PF_ETHUSD", "PF_SOLUSD", "PF_XRPUSD"]
    symbols: list[str] = []
    audit_rows: list[dict[str, Any]] = []
    for _, d in definitions.iterrows():
        policy_symbols, audit = tsmom_policy_symbols_at_checkpoint_v3(ctx, d.to_dict(), panel, checkpoint)
        if not audit.empty:
            audit["candidate_definition_id"] = d.get("candidate_definition_id", d.get("definition_id", ""))
            audit_rows.extend(audit.to_dict("records"))
        for sym in wanted:
            if sym in policy_symbols and sym not in symbols:
                symbols.append(sym)
        for sym in policy_symbols:
            if sym not in symbols:
                symbols.append(sym)
            if len([s for s in symbols if s not in wanted]) >= 2 and len(symbols) >= 6:
                break
        if len(symbols) >= 6:
            break
    return symbols[:6], pd.DataFrame(audit_rows)


def stage_short_window_real_data_mechanical_canary(ctx: Context) -> None:
    defs = read_csv_safe(ctx.run_root / "mechanical_canary/mechanical_canary_definition_manifest.csv")
    if defs.empty:
        raise RuntimeError("missing mechanical canary definitions")
    checkpoint = pd.Timestamp("2025-08-01T00:00:00Z")
    symbols, symbol_audit = mechanical_symbols_for_definitions(ctx, defs, checkpoint)
    if not symbols:
        raise RuntimeError("mechanical canary resolved zero real-data symbols")
    windows = mechanical_funding_windows(ctx, symbols)
    write_csv(ctx.run_root / "mechanical_canary/mechanical_canary_window_manifest.csv", windows)
    write_csv(ctx.run_root / "mechanical_canary/mechanical_canary_symbol_manifest.csv", [{"symbol": s, "selection_reason": "expected_major_or_pit_liquidity_mechanical_sample"} for s in symbols])
    write_csv(ctx.run_root / "mechanical_canary/mechanical_canary_symbol_policy_audit.csv", symbol_audit)
    paths = data_paths(ctx)
    engine = ENGINES["scheduled_tsmom_engine"]
    ledgers: list[pd.DataFrame] = []
    result_rows: list[dict[str, Any]] = []
    panel_cache: dict[tuple[str, str, str], tuple[pd.DataFrame, pd.DataFrame]] = {}
    for _, d in defs.iterrows():
        base = identity_enriched_record({**d.to_dict(), "family_engine_id": "scheduled_tsmom_engine", "kraken_data_root": str(resolve_path(ctx.args.kraken_data_root))}, engine)
        for _, w in windows.iterrows():
            warmup_start = ts_utc(w["feature_warmup_start"])
            decision_start = ts_utc(w["decision_start"])
            decision_end = ts_utc(w["decision_end"])
            for sym in symbols:
                cdict = identity_enriched_record({**base, "symbol": sym}, engine, symbol=sym)
                cache_key = (sym, str(warmup_start), str(decision_end))
                if cache_key not in panel_cache:
                    panel_cache[cache_key] = (load_symbol_bars(paths, sym, warmup_start, decision_end), load_funding(paths, sym, decision_end))
                bars, funding = panel_cache[cache_key]
                ledger = engine.regenerate_materialized_ledger(bars, funding, cdict) if not bars.empty else pd.DataFrame()
                if not ledger.empty:
                    ledger = ledger.copy()
                    ledger["decision_ts"] = pd.to_datetime(ledger["decision_ts"], utc=True, errors="coerce")
                    ledger = ledger[(ledger["decision_ts"] >= decision_start) & (ledger["decision_ts"] <= decision_end)].copy()
                    if not ledger.empty:
                        ledger["mechanical_window_label"] = w["window_label"]
                        ledger["mechanical_binding_test_only_not_strategy_evidence"] = True
                        ledgers.append(ledger)
                result_rows.append({
                    "candidate_definition_id": base["candidate_definition_id"],
                    "parameter_vector_hash": base["parameter_vector_hash"],
                    "symbol": sym,
                    "window_label": w["window_label"],
                    "warmup_rows_loaded": int(len(bars)),
                    "scored_rows_only_inside_decision_window": True,
                    "generated_events_inside_decision_window": int(len(ledger)) if not ledger.empty else 0,
                })
    events = pd.concat(ledgers, ignore_index=True, sort=False) if ledgers else pd.DataFrame()
    event_dir = ctx.run_root / "mechanical_canary/event_ledgers"
    event_dir.mkdir(parents=True, exist_ok=True)
    if not events.empty:
        parquet_safe_frame(events).to_parquet(event_dir / "mechanical_event_ledger.parquet", index=False, compression="zstd")
    write_csv(ctx.run_root / "mechanical_canary/mechanical_canary_result_summary.csv", result_rows)
    count_audit = tsmom_event_count_theoretical_vs_actual(events, defs, windows)
    overlap = tsmom_overlap_audit_frame(events)
    funding_binding = event_row_binding_audit(events, ["funding_gate", "funding_gate_status", "funding_gate_pass", "funding_feature_source_ts", "funding_exact_available", "funding_missing_action", "funding_label_cap_reason"], "mechanical_funding_gate")
    parent_binding = event_row_binding_audit(events, ["parent_regime_gate", "parent_gate_status", "parent_gate_pass", "parent_gate_feature_source_ts", "parent_btc_feature_source_ts", "parent_eth_feature_source_ts", "parent_gate_missing_action"], "mechanical_parent_gate")
    vol_binding = event_row_binding_audit(events, ["vol_scale", "vol_target", "vol_target_status", "raw_net_R", "scaled_net_R", "raw_gross_R", "scaled_gross_R", "raw_fee_R", "scaled_fee_R", "raw_funding_R", "scaled_funding_R"], "mechanical_vol_target")
    funding_sanity = funding_r_sanity_audit_frame(events)
    same_bar = same_bar_interval_semantics_audit_frame(events)
    write_csv(ctx.run_root / "semantics/tsmom_event_count_theoretical_vs_actual.csv", count_audit)
    write_csv(ctx.run_root / "semantics/tsmom_event_count_sanity_audit.csv", count_audit)
    write_csv(ctx.run_root / "semantics/tsmom_overlap_audit.csv", overlap)
    write_csv(ctx.run_root / "funding/funding_gate_event_row_binding_audit.csv", funding_binding)
    write_csv(ctx.run_root / "regime/parent_gate_event_row_binding_audit.csv", parent_binding)
    write_csv(ctx.run_root / "sizing/vol_target_event_row_binding_audit.csv", vol_binding)
    write_csv(ctx.run_root / "funding/funding_r_sanity_audit.csv", funding_sanity)
    write_csv(ctx.run_root / "funding/funding_boundary_count_audit.csv", events[[c for c in ["candidate_definition_id", "symbol", "event_id", "funding_boundary_count_exact", "funding_boundary_count_proxy", "funding_schedule_source", "raw_funding_R"] if c in events.columns]] if not events.empty else pd.DataFrame())
    write_csv(ctx.run_root / "controls/same_bar_interval_semantics_audit.csv", same_bar)
    vol_vals = pd.to_numeric(events.get("vol_scale", pd.Series(dtype=float)), errors="coerce").dropna() if not events.empty else pd.Series(dtype=float)
    write_csv(ctx.run_root / "sizing/vol_scale_distribution.csv", [{"rows": int(len(vol_vals)), "min_vol_scale": float(vol_vals.min()) if len(vol_vals) else np.nan, "median_vol_scale": float(vol_vals.median()) if len(vol_vals) else np.nan, "max_vol_scale": float(vol_vals.max()) if len(vol_vals) else np.nan, "non_unit_share": float((vol_vals != 1.0).mean()) if len(vol_vals) else 0.0}])
    hard_audits = [count_audit, overlap, funding_binding, parent_binding, vol_binding, funding_sanity, same_bar]
    audit_fail = any((not df.empty and df.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()) for df in hard_audits)
    no_events = events.empty
    gate = {
        "status": "fail" if audit_fail or no_events else "pass",
        "mechanical_binding_test_only_not_strategy_evidence": True,
        "events": int(len(events)),
        "event_semantics_count_pass": bool(not count_audit.empty and not count_audit.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "overlap_exposure_pass": bool(not overlap.empty and not overlap.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "funding_gate_binding_pass": bool(not funding_binding.empty and not funding_binding.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "parent_gate_binding_pass": bool(not parent_binding.empty and not parent_binding.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "vol_target_binding_pass": bool(not vol_binding.empty and not vol_binding.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "funding_r_sanity_pass": bool(not funding_sanity.empty and not funding_sanity.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "same_bar_interval_semantics_pass": bool(not same_bar.empty and not same_bar.get("status", pd.Series(dtype=str)).astype(str).eq("fail").any()),
        "next_full_universe_command_allowed": bool(not audit_fail and not no_events),
        "active_caps": "mechanical_test_only;liquidity_proxy_universe_cap;funding_proxy_cap_if_applicable;mark_lifecycle_cap;diagnostic_controls_not_run",
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "mechanical_canary/mechanical_canary_gate_decision.json", gate)


