def tsmom_decision_calendar_specs_from_registry(candidates: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    if candidates.empty:
        return pd.DataFrame()
    rows: dict[str, dict[str, Any]] = {}
    for _, rec in candidates.iterrows():
        cdict = rec.to_dict()
        fields = tsmom_calendar_policy_fields(cdict)
        cache_hash = tsmom_calendar_hash_for_candidate(ctx, cdict)
        rows.setdefault(cache_hash, {
            "calendar_hash": cache_hash,
            **fields,
            "candidate_definition_count": 0,
            "candidate_symbol_row_count": 0,
        })
        rows[cache_hash]["candidate_symbol_row_count"] += 1
    if "candidate_definition_id" in candidates.columns:
        for cache_hash, g in candidates.groupby(candidates.apply(lambda r: tsmom_calendar_hash_for_candidate(ctx, r.to_dict()), axis=1), dropna=False):
            rows[str(cache_hash)]["candidate_definition_count"] = int(g["candidate_definition_id"].astype(str).nunique())
    return pd.DataFrame(rows.values()).sort_values("calendar_hash", kind="mergesort").reset_index(drop=True)


