def tsmom_universe_policy_specs_from_registry(candidates: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    if candidates.empty:
        return pd.DataFrame()
    rows: dict[str, dict[str, Any]] = {}
    for _, rec in candidates.iterrows():
        cdict = rec.to_dict()
        cache_hash = tsmom_universe_cache_hash_for_candidate(ctx, cdict)
        fields = tsmom_universe_policy_fields(cdict)
        rows.setdefault(cache_hash, {
            "universe_cache_hash": cache_hash,
            **fields,
            "candidate_definition_count": 0,
            "candidate_symbol_row_count": 0,
            "candidate_example_json": canonical_json({k: cdict.get(k, "") for k in ["candidate_definition_id", "universe_policy", "universe_policy_hash", "pit_panel_manifest_path"]}),
        })
        rows[cache_hash]["candidate_symbol_row_count"] += 1
    for cache_hash, rec in rows.items():
        mask = candidates.apply(lambda r: tsmom_universe_cache_hash_for_candidate(ctx, r.to_dict()) == cache_hash, axis=1)
        rec["candidate_definition_count"] = int(candidates.loc[mask, "candidate_definition_id"].astype(str).nunique()) if "candidate_definition_id" in candidates.columns else 0
    return pd.DataFrame(rows.values()).sort_values("universe_cache_hash", kind="mergesort").reset_index(drop=True)


def tsmom_calendar_rows_for_symbol_spec(bars: pd.DataFrame, spec: Mapping[str, Any], symbol: str) -> list[dict[str, Any]]:
    if bars.empty or "ts" not in bars.columns:
        return []
    work = bars.copy()
    work["ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce")
    work = work[work["ts"].notna()].sort_values("ts", kind="mergesort").reset_index(drop=True)
    if work.empty:
        return []
    lookback = int(safe_float(spec.get("lookback_bars", 0), 0))
    hold = int(safe_float(spec.get("hold_bars", 0), 0))
    interval = int(safe_float(spec.get("interval_bars", 0), 0))
    if lookback <= 0 or hold <= 0 or interval <= 0:
        return []
    start_idx = max(lookback + 1, interval)
    rows: list[dict[str, Any]] = []
    seq = 0
    for idx in range(start_idx, max(start_idx, len(work) - 2), interval):
        decision_ts = ts_utc(work.loc[idx, "ts"])
        if decision_ts >= PROTECTED_TS:
            continue
        entry_idx = idx + 1
        exit_idx = min(len(work) - 1, entry_idx + hold)
        if entry_idx >= len(work) or exit_idx <= entry_idx:
            continue
        rows.append({
            "calendar_hash": str(spec.get("calendar_hash", "")),
            "symbol_id": str(symbol),
            "symbol": str(symbol),
            "decision_ts": decision_ts.isoformat(),
            "feature_available_ts": decision_ts.isoformat(),
            "idx": int(idx),
            "entry_idx": int(entry_idx),
            "exit_idx": int(exit_idx),
            "seq": int(seq),
            "year_month": decision_ts.strftime("%Y-%m"),
            "bar_timeframe": str(spec.get("bar_timeframe", "")),
            "rebalance_interval": str(spec.get("rebalance_interval", "")),
            "lookback_bars": lookback,
            "hold_bars": hold,
            "interval_bars": interval,
            "calendar_source": "scheduled_tsmom_engine_current_scalar_interval_semantics",
            "post_2026_decision_row": False,
        })
        seq += 1
    return rows


def write_partitioned_semantic_dataset(
    ctx: Context,
    df: pd.DataFrame,
    *,
    base_dir: Path,
    cache_class: str,
    cache_hash_col: str,
    partition_cols: Sequence[str],
    policy_lookup: Mapping[str, Mapping[str, Any]],
    sort_keys: Sequence[str],
) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame()
    manifest_rows: list[dict[str, Any]] = []
    for key_vals, part in df.groupby(list(partition_cols), dropna=False, sort=True):
        if not isinstance(key_vals, tuple):
            key_vals = (key_vals,)
        partition = {col: str(val) for col, val in zip(partition_cols, key_vals)}
        cache_hash = str(part[cache_hash_col].astype(str).iloc[0])
        rel_parts = [f"{col}={safe_filename(str(val))}" for col, val in partition.items()]
        final_path = base_dir.joinpath(*rel_parts, "part.parquet")
        tmp_path = final_path.with_suffix(".tmp.parquet")
        manifest = write_semantic_cache_shard(
            tmp_path,
            final_path,
            part.copy(),
            cache_class=cache_class,
            policy_fields=policy_lookup.get(cache_hash, {}),
            input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
            data_hash=tsmom_semantic_cache_data_hash(ctx),
            protected_train_boundary=str(PROTECTED_TS),
            sort_keys=sort_keys,
        )
        manifest_rows.append({
            "cache_class": cache_class,
            "semantic_cache_hash": manifest.get("semantic_cache_hash", ""),
            "declared_cache_hash": cache_hash,
            "schema_hash": manifest.get("schema_hash", ""),
            "content_hash": manifest.get("content_hash", ""),
            "row_count": int(manifest.get("row_count", len(part))),
            "min_decision_ts": str(part.get("decision_ts", pd.Series(dtype=str)).min()) if "decision_ts" in part.columns else "",
            "max_decision_ts": str(part.get("decision_ts", pd.Series(dtype=str)).max()) if "decision_ts" in part.columns else "",
            "path": str(final_path.relative_to(ctx.run_root)),
            "manifest_path": str(final_path.with_suffix(final_path.suffix + ".manifest.json").relative_to(ctx.run_root)),
            "partition": canonical_json(partition),
            "status": "pass" if manifest.get("semantic_cache_hash") == cache_hash else "fail",
        })
    return pd.DataFrame(manifest_rows)


def tsmom_symbol_universe_from_registry(candidates: pd.DataFrame) -> list[str]:
    if candidates.empty or "symbol" not in candidates.columns:
        return []
    return sorted(set(candidates["symbol"].dropna().astype(str).tolist()))


def tsmom_rank_population_symbols_from_universe_audit(calendar_root: Path, universe_hashes: Iterable[str]) -> list[str]:
    wanted = {str(x) for x in universe_hashes if str(x)}
    audit = read_csv_safe(calendar_root / "audit/universe_decision_audit.csv")
    if audit.empty or "selected_symbols" not in audit.columns:
        return []
    if wanted and "universe_cache_hash" in audit.columns:
        audit = audit[audit["universe_cache_hash"].astype(str).isin(wanted)].copy()
    symbols: set[str] = set()
    for raw in audit.get("selected_symbols", pd.Series(dtype=str)).dropna().astype(str):
        for sym in raw.split(";"):
            sym = sym.strip()
            if sym and sym.lower() != "nan":
                symbols.add(sym)
    return sorted(symbols)


def build_tsmom_calendar_dataset(ctx: Context, candidates: pd.DataFrame, specs: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    symbols = tsmom_symbol_universe_from_registry(candidates)
    if not symbols or specs.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    rows: list[dict[str, Any]] = []
    runtime_rows: list[dict[str, Any]] = []
    symbol_cache: dict[str, pd.DataFrame] = {}
    for sym in symbols:
        t0 = time.time()
        symbol_cache[sym] = load_symbol_bars(paths, sym, ctx.start, ctx.end)
        runtime_rows.append({"stage": "load_symbol_bars_for_calendar", "symbol": sym, "rows": int(len(symbol_cache[sym])), "runtime_seconds": time.time() - t0, "rss_bytes": current_rss_bytes()})
    for _, spec in specs.iterrows():
        st0 = time.time()
        before = len(rows)
        for sym, bars in symbol_cache.items():
            rows.extend(tsmom_calendar_rows_for_symbol_spec(bars, spec.to_dict(), sym))
        runtime_rows.append({
            "stage": "build_calendar_spec",
            "calendar_hash": spec.get("calendar_hash", ""),
            "symbols": len(symbol_cache),
            "rows_written": int(len(rows) - before),
            "runtime_seconds": time.time() - st0,
            "rss_bytes": current_rss_bytes(),
        })
    calendar = pd.DataFrame(rows)
    policy_lookup = {str(r["calendar_hash"]): {k: r[k] for k in specs.columns if k not in {"calendar_hash", "candidate_definition_count", "candidate_symbol_row_count"}} for _, r in specs.iterrows()}
    manifest = write_partitioned_semantic_dataset(
        ctx,
        calendar,
        base_dir=ctx.run_root / "cache/decision_calendar",
        cache_class="decision_calendar",
        cache_hash_col="calendar_hash",
        partition_cols=["calendar_hash", "year_month"],
        policy_lookup=policy_lookup,
        sort_keys=["calendar_hash", "symbol_id", "decision_ts"],
    )
    audit_rows = []
    if not calendar.empty:
        for cal_hash, g in calendar.groupby("calendar_hash", dropna=False):
            dt = pd.to_datetime(g["decision_ts"], utc=True, errors="coerce")
            ft = pd.to_datetime(g["feature_available_ts"], utc=True, errors="coerce")
            audit_rows.append({
                "calendar_hash": cal_hash,
                "rows": int(len(g)),
                "symbol_count": int(g["symbol_id"].astype(str).nunique()),
                "decision_count": int(dt.nunique()),
                "min_decision_ts": str(dt.min()),
                "max_decision_ts": str(dt.max()),
                "post_2026_decision_rows": int(dt.ge(PROTECTED_TS).sum()),
                "feature_after_decision_violations": int(ft.gt(dt).sum()),
                "selected_decision_hash": stable_hash(*sorted(dt.dropna().astype(str).tolist()), n=24),
                "status": "pass" if int(dt.ge(PROTECTED_TS).sum()) == 0 and int(ft.gt(dt).sum()) == 0 else "fail",
            })
    return calendar, manifest, pd.concat([pd.DataFrame(runtime_rows), pd.DataFrame(audit_rows).assign(stage="decision_calendar_audit")], ignore_index=True, sort=False)


def tsmom_precompute_liquidity_chunk_metadata(ctx: Context | SimpleNamespace, panel: pd.DataFrame) -> dict[str, dict[str, Any]]:
    paths = data_paths(ctx)
    out: dict[str, dict[str, Any]] = {}
    symbols = sorted(set(panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist())) if not panel.empty else []
    for sym in symbols:
        trade_files = pre_holdout_files(find_symbol_files(paths["trade_5m"], sym) or find_symbol_files(paths["alt_trade"], sym))
        funding_files = pre_holdout_files(find_symbol_files(paths["funding"], sym))

        def rows_for(files: Sequence[Path]) -> tuple[np.ndarray, np.ndarray]:
            rows: list[tuple[int, int]] = []
            for p in files:
                ts = file_chunk_start_ts(p)
                if ts is None:
                    continue
                try:
                    size = int(p.stat().st_size)
                except Exception:
                    size = 0
                rows.append((int(ts_utc(ts).value), size))
            rows.sort(key=lambda x: x[0])
            if not rows:
                return np.array([], dtype=np.int64), np.array([], dtype=np.int64)
            return np.array([r[0] for r in rows], dtype=np.int64), np.array([r[1] for r in rows], dtype=np.int64)

        trade_ts, trade_sizes = rows_for(trade_files)
        funding_ts, funding_sizes = rows_for(funding_files)
        out[sym] = {
            "trade_ts": trade_ts,
            "trade_sizes": trade_sizes,
            "trade_prefix": np.concatenate(([0], np.cumsum(trade_sizes, dtype=np.int64))),
            "funding_ts": funding_ts,
            "funding_sizes": funding_sizes,
            "funding_prefix": np.concatenate(([0], np.cumsum(funding_sizes, dtype=np.int64))),
        }
    return out


def trailing_30d_liquidity_proxy_from_chunk_metadata(chunks: Mapping[str, Mapping[str, Any]], symbol: str, checkpoint_ts: pd.Timestamp) -> dict[str, Any]:
    meta = chunks.get(str(symbol), {})
    checkpoint = int(ts_utc(checkpoint_ts).value)
    start = int((ts_utc(checkpoint_ts) - pd.Timedelta(days=30)).value)

    def window_stats(ts_arr: np.ndarray, prefix: np.ndarray) -> tuple[int, int]:
        if ts_arr.size == 0:
            return 0, 0
        left = int(np.searchsorted(ts_arr, start, side="left"))
        right = int(np.searchsorted(ts_arr, checkpoint, side="right"))
        count = max(0, right - left)
        bytes_sum = int(prefix[right] - prefix[left]) if right >= left else 0
        return count, bytes_sum

    trade_count, trade_bytes = window_stats(np.asarray(meta.get("trade_ts", []), dtype=np.int64), np.asarray(meta.get("trade_prefix", [0]), dtype=np.int64))
    funding_count, funding_bytes = window_stats(np.asarray(meta.get("funding_ts", []), dtype=np.int64), np.asarray(meta.get("funding_prefix", [0]), dtype=np.int64))
    hash_tie_breaker = int(hashlib.sha256(str(symbol).encode("utf-8")).hexdigest()[:8], 16) / 1e12
    score = float(trade_bytes + funding_bytes * 0.01 + hash_tie_breaker)
    return {
        "trailing_30d_trade_file_count": trade_count,
        "trailing_30d_funding_file_count": funding_count,
        "trailing_30d_notional_proxy": "",
        "trailing_30d_notional_rows": "",
        "trailing_30d_trade_file_bytes": trade_bytes,
        "trailing_30d_funding_file_bytes": funding_bytes,
        "pit_liquidity_proxy_score": float(score),
        "pit_liquidity_proxy_basis": "trailing_30d_file_size_coverage_proxy_with_hash_tiebreaker",
    }


def pit_liquidity_ranking_by_checkpoint_from_chunks(
    ctx: Context | SimpleNamespace,
    panel: pd.DataFrame,
    checkpoint_ts: pd.Timestamp,
    chunks: Mapping[str, Mapping[str, Any]],
    lifecycle: Mapping[str, Mapping[str, Any]] | None = None,
) -> pd.DataFrame:
    paths = data_paths(ctx)
    symbols_key = stable_hash(*panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), n=24) if not panel.empty else "empty"
    cache_key = (str(paths["root"]), ts_utc(checkpoint_ts).isoformat(), symbols_key, "precomputed_chunk_metadata")
    cached = _PIT_LIQUIDITY_RANKING_CACHE.get(cache_key)
    if cached is not None:
        return cached.copy()
    rows: list[dict[str, Any]] = []
    symbols = panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist()
    for sym in symbols:
        eligible, reason = panel_lifecycle_eligible_precomputed(lifecycle, panel, sym, checkpoint_ts) if lifecycle is not None else panel_lifecycle_eligible_at(panel, sym, checkpoint_ts)
        rows.append({
            "symbol": sym,
            "checkpoint_ts": ts_utc(checkpoint_ts).isoformat(),
            "eligible_at_checkpoint": bool(eligible),
            "eligibility_reason": reason,
            **trailing_30d_liquidity_proxy_from_chunk_metadata(chunks, sym, checkpoint_ts),
        })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out = out.sort_values(["eligible_at_checkpoint", "pit_liquidity_proxy_score", "symbol"], ascending=[False, False, True]).reset_index(drop=True)
    out["pit_rank"] = np.arange(1, len(out) + 1)
    _PIT_LIQUIDITY_RANKING_CACHE[cache_key] = out.copy()
    return out


def tsmom_policy_symbols_at_checkpoint_from_chunk_metadata(
    ctx: Context | SimpleNamespace,
    definition: Mapping[str, Any],
    panel: pd.DataFrame,
    checkpoint_ts: pd.Timestamp,
    chunks: Mapping[str, Mapping[str, Any]],
    lifecycle: Mapping[str, Mapping[str, Any]] | None = None,
) -> tuple[list[str], pd.DataFrame]:
    policy = str(definition.get("universe_policy", "") or "").strip()
    top_limit = int(safe_float(definition.get("top_major_target_size", TSMOM_TOP_MAJOR_UNIVERSE_LIMIT), TSMOM_TOP_MAJOR_UNIVERSE_LIMIT))
    tier_limit = int(safe_float(definition.get("tier_ab_target_size", TSMOM_TIER_AB_UNIVERSE_LIMIT), TSMOM_TIER_AB_UNIVERSE_LIMIT))
    ranked = pit_liquidity_ranking_by_checkpoint_from_chunks(ctx, panel, checkpoint_ts, chunks, lifecycle=lifecycle)
    if ranked.empty:
        return [], ranked
    eligible = ranked[ranked["eligible_at_checkpoint"].astype(bool)].copy()
    if policy == "pit_liquidity_top_majors":
        majors = eligible[eligible["symbol"].isin(REDESIGNED_EXPECTED_MAJORS)].copy()
        selected = majors.sort_values(["pit_liquidity_proxy_score", "symbol"], ascending=[False, True]).head(top_limit)
        if len(selected) < top_limit:
            fill = eligible[~eligible["symbol"].isin(selected["symbol"])].head(top_limit - len(selected))
            selected = pd.concat([selected, fill], ignore_index=True)
        minimum_size = min(8, top_limit)
    elif policy == "pit_liquidity_tier_ab":
        selected = eligible.head(tier_limit)
        minimum_size = min(30, tier_limit)
    else:
        selected = eligible.head(tier_limit)
        minimum_size = min(30, tier_limit)
    symbols = selected["symbol"].astype(str).tolist()
    audit = ranked.copy()
    audit["included"] = audit["symbol"].isin(symbols)
    audit["universe_policy"] = policy
    audit["configured_target_size"] = top_limit if policy == "pit_liquidity_top_majors" else tier_limit
    audit["configured_minimum_size"] = minimum_size
    audit["selected_symbol_count"] = len(symbols)
    audit["inclusion_exclusion_reason"] = np.where(
        audit["included"],
        "included_by_pit_liquidity_policy_v3",
        np.where(audit["eligible_at_checkpoint"], "eligible_but_outside_policy_rank_or_limit", audit["eligibility_reason"]),
    )
    return symbols, audit


def precompute_panel_lifecycle(panel: pd.DataFrame) -> dict[str, dict[str, Any]]:
    if panel.empty or "symbol" not in panel.columns:
        return {}
    out: dict[str, dict[str, Any]] = {}
    for _, r in panel.iterrows():
        sym = str(r.get("symbol", ""))
        if not sym:
            continue
        out[sym] = {
            "status": str(r.get("status", "available")),
            "start": pd.to_datetime(r.get("start_ts", r.get("first_ts", "")), utc=True, errors="coerce"),
            "end": pd.to_datetime(r.get("end_ts", r.get("last_ts", "")), utc=True, errors="coerce"),
            "bar_rows": safe_float(r.get("bar_rows", 0), 0.0),
        }
    return out


def panel_lifecycle_eligible_precomputed(
    lifecycle: Mapping[str, Mapping[str, Any]] | None,
    panel: pd.DataFrame,
    symbol: str,
    ts: pd.Timestamp,
) -> tuple[bool, str]:
    if panel.empty or "symbol" not in panel.columns:
        return False, "panel_missing"
    rec = lifecycle.get(str(symbol), {}) if lifecycle is not None else {}
    if not rec:
        return False, "symbol_missing_from_panel"
    status = str(rec.get("status", "available"))
    if status != "available":
        return False, f"panel_status_{status}"
    start = rec.get("start")
    end = rec.get("end")
    if pd.notna(start) and ts_utc(ts) < ts_utc(start):
        return False, "before_symbol_panel_start"
    if pd.notna(end) and ts_utc(ts) > ts_utc(end):
        return False, "after_symbol_panel_end"
    if safe_float(rec.get("bar_rows", 0), 0.0) <= 0:
        return False, "zero_bar_rows"
    return True, "eligible_by_lifecycle_panel"


def build_tsmom_universe_membership_dataset(ctx: Context, calendar: pd.DataFrame, specs: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if calendar.empty or specs.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    unique_decisions = sorted(pd.to_datetime(calendar["decision_ts"], utc=True, errors="coerce").dropna().unique())
    manifest_rows: list[dict[str, Any]] = []
    decision_audit: list[dict[str, Any]] = []
    runtime_rows: list[dict[str, Any]] = []
    policy_lookup = {str(r["universe_cache_hash"]): {k: r[k] for k in specs.columns if k not in {"universe_cache_hash", "candidate_definition_count", "candidate_symbol_row_count", "candidate_example_json"}} for _, r in specs.iterrows()}
    for _, spec in specs.iterrows():
        cdict = spec.to_dict()
        cache_hash = str(cdict.get("universe_cache_hash", ""))
        panel = read_panel_manifest_cached(cdict.get("pit_panel_manifest_path", ""))
        if panel.empty:
            raise RuntimeError(f"missing PIT panel manifest for universe policy {cache_hash}: {cdict.get('pit_panel_manifest_path', '')}")
        chunks = tsmom_precompute_liquidity_chunk_metadata(candidate_ctx_for_pit_policy(cdict), panel)
        lifecycle = precompute_panel_lifecycle(panel)
        all_panel_symbols = panel.get("symbol", pd.Series(dtype=str)).astype(str).tolist()
        month_frames: dict[str, list[pd.DataFrame]] = {}
        policy_rows_written = 0
        for decision_ts in unique_decisions:
            decision = ts_utc(decision_ts)
            if decision >= PROTECTED_TS:
                continue
            t0 = time.time()
            symbols, audit = tsmom_policy_symbols_at_checkpoint_from_chunk_metadata(candidate_ctx_for_pit_policy(cdict), cdict, panel, decision, chunks, lifecycle=lifecycle)
            selected_hash = stable_hash(*symbols, n=24)
            static_alpha = universe_symbols_are_alphabetical_first_n(symbols, all_panel_symbols)
            reason_counts = audit.get("inclusion_exclusion_reason", pd.Series(dtype=str)).fillna("").astype(str).value_counts().sort_index().to_dict() if not audit.empty else {}
            decision_audit.append({
                "universe_cache_hash": cache_hash,
                "universe_policy_hash": cdict.get("universe_policy_hash", ""),
                "universe_policy": cdict.get("universe_policy", ""),
                "decision_ts": decision.isoformat(),
                "feature_available_ts": decision.isoformat(),
                "selected_symbol_count": int(len(symbols)),
                "eligible_symbol_count": int(audit.get("eligible_at_checkpoint", pd.Series(dtype=bool)).astype(bool).sum()) if not audit.empty else 0,
                "selected_symbols": ";".join(symbols),
                "selected_symbols_hash": selected_hash,
                "excluded_reason_count_hash": stable_hash(*[f"{k}={v}" for k, v in reason_counts.items()], n=24),
                "alphabetical_static_first_n_detected": bool(static_alpha),
                "selection_basis": "tsmom_policy_symbols_at_checkpoint_v3_per_decision_pit",
                "runtime_seconds": time.time() - t0,
                "rss_bytes": current_rss_bytes(),
                "status": "pass" if not static_alpha else "fail",
            })
            if not audit.empty:
                part = audit.copy()
                part["universe_cache_hash"] = cache_hash
                part["universe_policy_hash"] = cdict.get("universe_policy_hash", "")
                part["universe_policy"] = cdict.get("universe_policy", "")
                part["decision_ts"] = decision.isoformat()
                part["feature_available_ts"] = decision.isoformat()
                part["year_month"] = decision.strftime("%Y-%m")
                part["symbol_id"] = part["symbol"].astype(str)
                part["symbol_in_universe"] = part["included"].astype(bool)
                part["eligible_at_decision"] = part["eligible_at_checkpoint"].astype(bool)
                part["selected_symbol_count"] = int(len(symbols))
                part["selected_symbols_hash"] = selected_hash
                part["alphabetical_static_first_n_detected"] = bool(static_alpha)
                part["selection_basis"] = "tsmom_policy_symbols_at_checkpoint_v3_per_decision_pit"
                part["static_current_live_fallback_used"] = False
                part["post_2026_decision_row"] = False
                keep = [
                    "universe_cache_hash", "universe_policy_hash", "universe_policy", "decision_ts", "feature_available_ts", "year_month",
                    "symbol_id", "symbol", "symbol_in_universe", "eligible_at_decision", "pit_rank", "pit_liquidity_proxy_score",
                    "inclusion_exclusion_reason", "selected_symbol_count", "selected_symbols_hash", "alphabetical_static_first_n_detected",
                    "selection_basis", "static_current_live_fallback_used", "post_2026_decision_row",
                ]
                part = part[[c for c in keep if c in part.columns]]
                month_frames.setdefault(decision.strftime("%Y-%m"), []).append(part)
                policy_rows_written += int(len(part))
        for month, frames in sorted(month_frames.items()):
            part_df = pd.concat(frames, ignore_index=True, sort=False)
            final_path = ctx.run_root / "cache/universe_membership" / f"universe_cache_hash={safe_filename(cache_hash)}" / f"year_month={safe_filename(month)}" / "part.parquet"
            tmp_path = final_path.with_suffix(".tmp.parquet")
            manifest = write_semantic_cache_shard(
                tmp_path,
                final_path,
                part_df,
                cache_class="universe_membership",
                policy_fields=policy_lookup.get(cache_hash, {}),
                input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
                data_hash=tsmom_semantic_cache_data_hash(ctx),
                protected_train_boundary=str(PROTECTED_TS),
                sort_keys=["universe_cache_hash", "decision_ts", "symbol_id"],
            )
            manifest_rows.append({
                "cache_class": "universe_membership",
                "semantic_cache_hash": manifest.get("semantic_cache_hash", ""),
                "declared_cache_hash": cache_hash,
                "schema_hash": manifest.get("schema_hash", ""),
                "content_hash": manifest.get("content_hash", ""),
                "row_count": int(manifest.get("row_count", len(part_df))),
                "min_decision_ts": str(part_df.get("decision_ts", pd.Series(dtype=str)).min()),
                "max_decision_ts": str(part_df.get("decision_ts", pd.Series(dtype=str)).max()),
                "path": str(final_path.relative_to(ctx.run_root)),
                "manifest_path": str(final_path.with_suffix(final_path.suffix + ".manifest.json").relative_to(ctx.run_root)),
                "partition": canonical_json({"universe_cache_hash": cache_hash, "year_month": month}),
                "status": "pass" if manifest.get("semantic_cache_hash") == cache_hash else "fail",
            })
            del part_df
        month_frames.clear()
        gc.collect()
        runtime_rows.append({"stage": "build_universe_policy", "universe_cache_hash": cache_hash, "decisions": len(unique_decisions), "rows_written": policy_rows_written, "runtime_seconds": sum(float(r.get("runtime_seconds", 0.0)) for r in decision_audit if r.get("universe_cache_hash") == cache_hash), "rss_bytes": current_rss_bytes()})
    return pd.DataFrame(), pd.DataFrame(manifest_rows), pd.DataFrame(decision_audit), pd.DataFrame(runtime_rows)


def exactness_benchmark_calendar_universe(
    ctx: Context,
    *,
    label: str,
    candidates: pd.DataFrame,
    calendar: pd.DataFrame,
    universe: pd.DataFrame,
) -> pd.DataFrame:
    paths = data_paths(ctx)
    engine = ENGINES["scheduled_tsmom_engine"]
    calendar_idx: dict[tuple[str, str, str], set[str]] = {}
    if not calendar.empty:
        for (cal_hash, sym), g in calendar.groupby(["calendar_hash", "symbol"], dropna=False):
            calendar_idx[(str(cal_hash), str(sym), "decisions")] = set(pd.to_datetime(g["decision_ts"], utc=True, errors="coerce").dropna().map(lambda x: ts_utc(x).isoformat()).tolist())
    universe_idx: dict[tuple[str, str], list[str]] = {}
    universe_reason_hash: dict[tuple[str, str], str] = {}
    if not universe.empty:
        if "selected_symbols" in universe.columns and "excluded_reason_count_hash" in universe.columns:
            for _, rec in universe.iterrows():
                key = (str(rec.get("universe_cache_hash", "")), ts_utc(rec.get("decision_ts", "")).isoformat())
                universe_idx[key] = [s for s in str(rec.get("selected_symbols", "")).split(";") if s]
                universe_reason_hash[key] = str(rec.get("excluded_reason_count_hash", ""))
        else:
            inc = universe[parse_bool_series(universe.get("symbol_in_universe", pd.Series(False, index=universe.index)), default=False)].copy()
            for (cache_hash, decision), g in inc.groupby(["universe_cache_hash", "decision_ts"], dropna=False):
                syms = sorted(g["symbol"].astype(str).tolist())
                universe_idx[(str(cache_hash), ts_utc(decision).isoformat())] = syms
            for (cache_hash, decision), g in universe.groupby(["universe_cache_hash", "decision_ts"], dropna=False):
                reasons = g.get("inclusion_exclusion_reason", pd.Series(dtype=str)).fillna("").astype(str).value_counts().sort_index()
                universe_reason_hash[(str(cache_hash), ts_utc(decision).isoformat())] = stable_hash(*[f"{k}={v}" for k, v in reasons.items()], n=24)
    symbol_cache: dict[str, pd.DataFrame] = {}
    scalar_topn_cache: dict[tuple[str, str], list[str]] = {}
    rows: list[dict[str, Any]] = []
    post_2026 = 0
    for idx, cand in candidates.iterrows():
        cdict = cand.to_dict()
        symbol = str(cdict.get("symbol", ""))
        if symbol not in symbol_cache:
            symbol_cache[symbol] = load_symbol_bars(paths, symbol, ctx.start, ctx.end)
        bars = symbol_cache[symbol]
        addresses = [] if bars.empty else [a for a in engine.enumerate_valid_event_addresses(bars, cdict) if ts_utc(a.decision_ts) < PROTECTED_TS]
        scalar_decisions = sorted({ts_utc(a.decision_ts).isoformat() for a in addresses})
        post_2026 += int(sum(1 for a in addresses if ts_utc(a.decision_ts) >= PROTECTED_TS))
        cal_hash = tsmom_calendar_hash_for_candidate(ctx, cdict)
        uni_hash = tsmom_universe_cache_hash_for_candidate(ctx, cdict)
        cached_decisions = calendar_idx.get((cal_hash, symbol, "decisions"), set())
        missing_decisions = [d for d in scalar_decisions if d not in cached_decisions]
        rows.append({
            "benchmark_label": label,
            "candidate_index": int(idx),
            "candidate_definition_id": definition_identity(cdict),
            "candidate_symbol_id": symbol_identity(cdict, symbol),
            "symbol": symbol,
            "check": "scalar_event_decision_ts_covered_by_calendar",
            "scalar_value": int(len(scalar_decisions)),
            "cache_value": int(len(cached_decisions)),
            "mismatch_count": int(len(missing_decisions)),
            "status": "pass" if not missing_decisions else "fail",
            "mismatch_detail": ";".join(missing_decisions[:10]),
        })
        for decision in scalar_decisions[:50_000]:
            scalar_symbols = list(pit_policy_symbols_for_decision(cdict, ts_utc(decision)))
            cached_symbols = universe_idx.get((uni_hash, ts_utc(decision).isoformat()), [])
            scalar_reason_hash = ""
            panel = read_panel_manifest_cached(cdict.get("pit_panel_manifest_path", ""))
            if not panel.empty:
                _, scalar_audit = tsmom_policy_symbols_at_checkpoint_v3(candidate_ctx_for_pit_policy(cdict), cdict, panel, ts_utc(decision))
                reasons = scalar_audit.get("inclusion_exclusion_reason", pd.Series(dtype=str)).fillna("").astype(str).value_counts().sort_index()
                scalar_reason_hash = stable_hash(*[f"{k}={v}" for k, v in reasons.items()], n=24)
            cache_reason_hash = universe_reason_hash.get((uni_hash, ts_utc(decision).isoformat()), "")
            rows.append({
                "benchmark_label": label,
                "candidate_index": int(idx),
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, symbol),
                "symbol": symbol,
                "decision_ts": ts_utc(decision).isoformat(),
                "check": "pit_universe_selected_symbol_hash",
                "scalar_value": stable_hash(*scalar_symbols, n=24),
                "cache_value": stable_hash(*cached_symbols, n=24),
                "mismatch_count": 0 if scalar_symbols == cached_symbols else 1,
                "status": "pass" if scalar_symbols == cached_symbols else "fail",
                "mismatch_detail": "" if scalar_symbols == cached_symbols else f"scalar={';'.join(scalar_symbols[:12])} cache={';'.join(cached_symbols[:12])}",
            })
            rows.append({
                "benchmark_label": label,
                "candidate_index": int(idx),
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, symbol),
                "symbol": symbol,
                "decision_ts": ts_utc(decision).isoformat(),
                "check": "pit_universe_reason_count_hash",
                "scalar_value": scalar_reason_hash,
                "cache_value": cache_reason_hash,
                "mismatch_count": 0 if scalar_reason_hash == cache_reason_hash else 1,
                "status": "pass" if scalar_reason_hash == cache_reason_hash else "fail",
                "mismatch_detail": "",
            })
        clear_aggregate_caches(ctx, reason="calendar_universe_exactness_candidate_complete", scope=f"{idx}:{symbol}")
    rows.append({
        "benchmark_label": label,
        "candidate_index": "",
        "candidate_definition_id": "",
        "candidate_symbol_id": "",
        "symbol": "",
        "check": "post_2026_scalar_event_decision_rows",
        "scalar_value": int(post_2026),
        "cache_value": 0,
        "mismatch_count": int(post_2026),
        "status": "pass" if post_2026 == 0 else "fail",
        "mismatch_detail": "",
    })
    return pd.DataFrame(rows)


def stage_tsmom_calendar_universe_cache_builder(ctx: Context) -> None:
    t_start = time.time()
    semantic_root = tsmom_calendar_universe_semantic_root()
    setup_root = tsmom_calendar_universe_setup_root()
    candidates, setup_audit = load_full_tsmom_v6_registry_from_setup(setup_root)
    if "run_start_ts" in candidates.columns:
        candidates["run_start_ts"] = str(ctx.start)
    if "run_end_ts" in candidates.columns:
        candidates["run_end_ts"] = str(ctx.end)
    if "kraken_data_root" in candidates.columns:
        candidates["kraken_data_root"] = str(resolve_path(ctx.args.kraken_data_root))
    write_csv(ctx.run_root / "registry/full_v6_registry_shard_validation_audit.csv", setup_audit)
    calendar_specs = tsmom_decision_calendar_specs_from_registry(candidates, ctx)
    universe_specs = tsmom_universe_policy_specs_from_registry(candidates, ctx)
    write_csv(ctx.run_root / "cache/decision_calendar_spec_inventory.csv", calendar_specs)
    write_csv(ctx.run_root / "cache/universe_policy_spec_inventory.csv", universe_specs)
    cal_t0 = time.time()
    calendar, calendar_manifest, calendar_runtime = build_tsmom_calendar_dataset(ctx, candidates, calendar_specs)
    cal_seconds = time.time() - cal_t0
    write_csv(ctx.run_root / "cache/decision_calendar_manifest.csv", calendar_manifest)
    calendar_audit = calendar_runtime[calendar_runtime.get("stage", pd.Series(dtype=str)).astype(str).eq("decision_calendar_audit")].drop(columns=["stage"], errors="ignore") if not calendar_runtime.empty else pd.DataFrame()
    write_csv(ctx.run_root / "audit/decision_calendar_audit.csv", calendar_audit)
    uni_t0 = time.time()
    universe, universe_manifest, universe_decision_audit, universe_runtime = build_tsmom_universe_membership_dataset(ctx, calendar, universe_specs)
    uni_seconds = time.time() - uni_t0
    write_csv(ctx.run_root / "cache/universe_membership_manifest.csv", universe_manifest)
    write_csv(ctx.run_root / "audit/universe_decision_audit.csv", universe_decision_audit)
    if not universe_decision_audit.empty:
        leak = assert_decision_input_no_leak(universe_decision_audit[["decision_ts", "feature_available_ts"]].copy())
    else:
        leak = pd.DataFrame([{"check": "universe_membership_feature_available_ts_lte_decision_ts", "violations": 1, "status": "fail", "reason": "empty_universe_membership"}])
    write_csv(ctx.run_root / "audit/universe_membership_leak_audit.csv", leak)
    dyn_rows: list[dict[str, Any]] = []
    if not universe_decision_audit.empty:
        for (policy_hash, policy), g in universe_decision_audit.groupby(["universe_policy_hash", "universe_policy"], dropna=False):
            dyn_rows.append({
                "universe_policy_hash": policy_hash,
                "universe_policy": policy,
                "decision_count": int(len(g)),
                "selected_symbol_count_min": int(pd.to_numeric(g["selected_symbol_count"], errors="coerce").fillna(0).min()),
                "selected_symbol_count_max": int(pd.to_numeric(g["selected_symbol_count"], errors="coerce").fillna(0).max()),
                "selected_symbols_hash_count": int(g["selected_symbols_hash"].astype(str).nunique()),
                "alphabetical_static_first_n_detected_count": int(parse_bool_series(g["alphabetical_static_first_n_detected"], default=False).sum()),
                "selection_basis": "tsmom_policy_symbols_at_checkpoint_v3_per_decision_pit",
                "status": "pass" if int(parse_bool_series(g["alphabetical_static_first_n_detected"], default=False).sum()) == 0 else "fail",
            })
    write_csv(ctx.run_root / "audit/universe_dynamic_panel_audit.csv", dyn_rows)
    bench_t0 = time.time()
    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    exact = pd.concat([
        exactness_benchmark_calendar_universe(ctx, label="representative_24_heavy_path", candidates=rep, calendar=calendar, universe=universe_decision_audit),
        exactness_benchmark_calendar_universe(ctx, label="medium_128_real_rows", candidates=med, calendar=calendar, universe=universe_decision_audit),
    ], ignore_index=True, sort=False)
    bench_seconds = time.time() - bench_t0
    write_csv(ctx.run_root / "benchmark/calendar_universe_vs_scalar_exactness.csv", exact)
    performance = pd.DataFrame([
        {"stage": "calendar_spec_extraction", "runtime_seconds": 0.0, "rows": int(len(calendar_specs)), "rss_bytes": current_rss_bytes(), "build_basis": "unique_calendar_specs_not_candidate_rows"},
        {"stage": "decision_calendar_dataset_build", "runtime_seconds": cal_seconds, "rows": int(len(calendar)), "rss_bytes": current_rss_bytes(), "build_basis": "calendar_specs_x_symbols"},
        {"stage": "universe_membership_dataset_build", "runtime_seconds": uni_seconds, "rows": int(len(universe)), "rss_bytes": current_rss_bytes(), "build_basis": "universe_policy_specs_x_decision_ts"},
        {"stage": "representative_and_medium_scalar_exactness_checks", "runtime_seconds": bench_seconds, "rows": int(len(exact)), "rss_bytes": current_rss_bytes(), "build_basis": "scalar_check_only_not_cache_build"},
    ])
    write_csv(ctx.run_root / "benchmark/calendar_universe_performance.csv", performance)
    mismatch_count = int(pd.to_numeric(exact.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not exact.empty else 1
    leak_violations = int(pd.to_numeric(leak.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not leak.empty else 1
    static_fallback = False
    alpha_static = int(pd.to_numeric(pd.DataFrame(dyn_rows).get("alphabetical_static_first_n_detected_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if dyn_rows else 1
    calendar_failures = int(calendar_audit.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not calendar_audit.empty else 1
    manifest_failures = int(calendar_manifest.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) + int(universe_manifest.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not calendar_manifest.empty and not universe_manifest.empty else 1
    peak_rss = int(max(current_rss_bytes(), pd.to_numeric(performance["rss_bytes"], errors="coerce").fillna(0).max()))
    soft = memory_soft_limit_bytes(ctx)
    memory_pass = peak_rss < int(soft * 0.70)
    pass_gate = mismatch_count == 0 and leak_violations == 0 and not static_fallback and alpha_static == 0 and calendar_failures == 0 and manifest_failures == 0 and memory_pass
    total_runtime = time.time() - t_start
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "materialization_launched": False,
        "validation_launched": False,
        "prior_high_route_touched": False,
        "semantic_cache_repair_root": str(semantic_root),
        "setup_repair_root": str(setup_root),
        "decision_calendar_specs_built": int(len(calendar_specs)),
        "universe_policy_specs_built": int(len(universe_specs)),
        "decision_calendar_rows": int(len(calendar)),
        "universe_membership_rows": int(pd.to_numeric(universe_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not universe_manifest.empty else 0,
        "exactness_pass": mismatch_count == 0,
        "mismatch_count": int(mismatch_count),
        "leak_violations": int(leak_violations),
        "static_current_live_universe_fallback_used": static_fallback,
        "alphabetical_static_selection_violations": int(alpha_static),
        "manifest_validation_failures": int(manifest_failures),
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": memory_pass,
        "runtime_seconds": float(total_runtime),
        "next_operator_decision": "build_tsmom_rank_topn_dataset_cache_next" if pass_gate else "repair_calendar_universe_cache_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "KRAKEN_TSMOM_CALENDAR_UNIVERSE_CACHE_BUILDER_REPORT.md", "\n".join([
        "# Kraken TSMOM Calendar and Universe Cache Builder Report",
        "",
        "This is a TSMOM-only decision-input cache builder and exactness benchmark. It did not launch a full aggregate, sweep, materialization, controls, validation, or prior-high route.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Decision calendar specs built: `{summary['decision_calendar_specs_built']}`",
        f"Universe policy specs built: `{summary['universe_policy_specs_built']}`",
        f"Exactness pass: `{summary['exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Leak violations: `{summary['leak_violations']}`",
        f"Static/current-live fallback used: `{summary['static_current_live_universe_fallback_used']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Runtime seconds: `{summary['runtime_seconds']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "Calendar equality is not expected against scalar events because scalar events additionally require the signal to pass; the exactness benchmark checks scalar-event decision timestamp coverage and PIT universe membership equality at scalar-event decision timestamps.",
        "",
        "This is infrastructure output only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    write_status(ctx, summary["status"], "tsmom-calendar-universe-cache-builder")


def tsmom_rank_topn_calendar_universe_root() -> Path:
    explicit = RESULTS_ROOT / "phase_kraken_tsmom_calendar_universe_cache_builder_20260707_v1_20260707_123020"
    if not explicit.exists():
        raise RuntimeError(f"missing calendar/universe cache root: {explicit}")
    summary = read_json(explicit / "decision_summary.json", {})
    if summary.get("status") != "complete" or not bool(summary.get("exactness_pass")):
        raise RuntimeError("calendar/universe cache root is not complete/passing")
    return explicit


RANK_FEATURE_CACHE_COLUMNS = [
    "rank_feature_hash", "symbol_id", "symbol", "decision_ts", "feature_available_ts", "year_month",
    "lookback_days", "rank_metric", "rank_score", "trailing_return", "risk_adjusted_return", "relative_strength",
    "source_ts", "rank_score_available", "invalid_reason", "tie_break_hash", "protected_boundary", "post_2026_decision_row",
]

TOPN_MEMBERSHIP_CACHE_COLUMNS = [
    "topn_policy_hash", "universe_cache_hash", "rank_feature_hash", "decision_ts", "feature_available_ts", "year_month",
    "symbol_id", "symbol", "rank_metric", "rank_score", "rank", "rank_population_count", "rank_population_policy",
    "rank_top_n", "top_n_pass", "rank_feature_valid", "symbol_in_universe", "selected_symbols_hash",
    "selected_topn_symbols", "selected_topn_symbols_hash", "tie_break_policy", "tie_break_hash", "invalid_reason",
    "alphabetical_first_n_detected", "topn_selection_basis", "post_2026_decision_row",
]


def tsmom_rank_feature_policy_fields(candidate: Mapping[str, Any], *, calendar_hash: str, symbol_scope_hash: str) -> dict[str, Any]:
    lookback_days = int(safe_float(candidate.get("lookback_days", 0), 0) or max(1, int(safe_float(candidate.get("lookback_bars", 288), 288)) // 288))
    return {
        "cache_semantics": "tsmom_v6_rank_feature_dataset_v1",
        "engine_id": "scheduled_tsmom_engine",
        "calendar_hash": str(calendar_hash),
        "bar_timeframe": str(candidate.get("bar_timeframe", "")),
        "rebalance_interval": str(candidate.get("rebalance_interval", "")),
        "lookback_days": int(lookback_days),
        "lookback_bars": int(safe_float(candidate.get("lookback_bars", 0), 0)),
        "rank_metric": str(candidate.get("rank_metric", "trailing_return") or "trailing_return"),
        "rank_feature_source": "completed_close_window",
        "feature_available_ts_rule": "source_ts_strictly_before_decision_ts",
        "symbol_scope": "pit_universe_selected_symbol_union_for_ranked_policies",
        "symbol_scope_hash": str(symbol_scope_hash),
        "protected_boundary": str(PROTECTED_TS),
    }


def tsmom_rank_feature_hash_for_candidate(ctx: Context, candidate: Mapping[str, Any], *, calendar_hash: str, symbol_scope_hash: str) -> str:
    return semantic_cache_hash(
        cache_class="tsmom_rank_feature",
        schema_hash=schema_hash_for_columns(RANK_FEATURE_CACHE_COLUMNS, cache_class="tsmom_rank_feature"),
        input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
        data_hash=tsmom_semantic_cache_data_hash(ctx),
        protected_train_boundary=str(PROTECTED_TS),
        policy_fields=tsmom_rank_feature_policy_fields(candidate, calendar_hash=calendar_hash, symbol_scope_hash=symbol_scope_hash),
        cache_contract_version=SEMANTIC_CACHE_CONTRACT_VERSION,
    )


def tsmom_calendar_lookup_key_from_fields(fields: Mapping[str, Any]) -> tuple[Any, ...]:
    def optional_iso(value: Any) -> str:
        text = str(value or "").strip()
        if not text:
            return ""
        return ts_utc(text).isoformat()

    return (
        str(fields.get("bar_timeframe", "")),
        str(fields.get("rebalance_interval", "")),
        int(safe_float(fields.get("lookback_days", 0), 0)),
        int(safe_float(fields.get("lookback_bars", 0), 0)),
        str(fields.get("hold_interval", "")),
        int(safe_float(fields.get("hold_bars", 0), 0)),
        int(safe_float(fields.get("interval_bars", 0), 0)),
        optional_iso(fields.get("run_start_ts", "")),
        optional_iso(fields.get("run_end_ts", "")),
    )


def ctx_start_default() -> pd.Timestamp:
    return pd.Timestamp("1970-01-01T00:00:00Z")


def ctx_end_default() -> pd.Timestamp:
    return pd.Timestamp("1970-01-01T00:00:00Z")


def tsmom_calendar_hash_lookup_from_cache_root(calendar_root: Path) -> dict[tuple[Any, ...], str]:
    specs = read_csv_safe(calendar_root / "cache/decision_calendar_spec_inventory.csv")
    lookup: dict[tuple[Any, ...], str] = {}
    for _, rec in specs.iterrows():
        lookup[tsmom_calendar_lookup_key_from_fields(rec.to_dict())] = str(rec.get("calendar_hash", ""))
    return lookup


def tsmom_calendar_hash_for_candidate_from_lookup(ctx: Context, candidate: Mapping[str, Any], lookup: Mapping[tuple[Any, ...], str] | None) -> str:
    fields = tsmom_calendar_policy_fields(candidate)
    key = tsmom_calendar_lookup_key_from_fields(fields)
    if lookup is not None and key in lookup:
        return str(lookup[key])
    return tsmom_calendar_hash_for_candidate(ctx, candidate)


def tsmom_universe_lookup_key_from_fields(fields: Mapping[str, Any]) -> tuple[Any, ...]:
    return (
        str(fields.get("universe_policy", "")),
        str(fields.get("universe_policy_hash", "")),
        str(fields.get("pit_panel_manifest_path", "")),
        int(safe_float(fields.get("top_major_target_size", TSMOM_TOP_MAJOR_UNIVERSE_LIMIT), TSMOM_TOP_MAJOR_UNIVERSE_LIMIT)),
        int(safe_float(fields.get("tier_ab_target_size", TSMOM_TIER_AB_UNIVERSE_LIMIT), TSMOM_TIER_AB_UNIVERSE_LIMIT)),
        str(fields.get("liquidity_ranking_source", "pit_lifecycle_safe_trailing_30d_close_volume_proxy")),
        str(fields.get("policy_function", "tsmom_policy_symbols_at_checkpoint_v3")),
    )


def tsmom_universe_hash_lookup_from_cache_root(calendar_root: Path) -> dict[tuple[Any, ...], str]:
    specs = read_csv_safe(calendar_root / "cache/universe_policy_spec_inventory.csv")
    lookup: dict[tuple[Any, ...], str] = {}
    for _, rec in specs.iterrows():
        lookup[tsmom_universe_lookup_key_from_fields(rec.to_dict())] = str(rec.get("universe_cache_hash", ""))
    return lookup


def tsmom_universe_hash_for_candidate_from_lookup(ctx: Context, candidate: Mapping[str, Any], lookup: Mapping[tuple[Any, ...], str] | None) -> str:
    fields = tsmom_universe_policy_fields(candidate)
    key = tsmom_universe_lookup_key_from_fields(fields)
    if lookup is not None and key in lookup:
        return str(lookup[key])
    return tsmom_universe_cache_hash_for_candidate(ctx, candidate)


def tsmom_rank_feature_specs_from_registry(candidates: pd.DataFrame, ctx: Context, calendar_hash_lookup: Mapping[tuple[Any, ...], str] | None = None, symbol_scope_hash: str | None = None) -> pd.DataFrame:
    ranked = candidates[pd.to_numeric(candidates.get("rank_top_n", pd.Series(dtype=float)), errors="coerce").fillna(0).gt(0)].copy() if not candidates.empty else pd.DataFrame()
    if ranked.empty:
        return pd.DataFrame()
    symbol_scope_hash = symbol_scope_hash or stable_hash(*tsmom_symbol_universe_from_registry(candidates), n=32)
    rows: dict[str, dict[str, Any]] = {}
    for _, rec in ranked.iterrows():
        cdict = rec.to_dict()
        calendar_hash = tsmom_calendar_hash_for_candidate_from_lookup(ctx, cdict, calendar_hash_lookup)
        rank_hash = tsmom_rank_feature_hash_for_candidate(ctx, cdict, calendar_hash=calendar_hash, symbol_scope_hash=symbol_scope_hash)
        fields = tsmom_rank_feature_policy_fields(cdict, calendar_hash=calendar_hash, symbol_scope_hash=symbol_scope_hash)
        rows.setdefault(rank_hash, {
            "rank_feature_hash": rank_hash,
            **fields,
            "candidate_definition_count": 0,
            "candidate_symbol_row_count": 0,
            "candidate_example_json": canonical_json({k: cdict.get(k, "") for k in ["candidate_definition_id", "rank_top_n", "rank_metric", "lookback_days", "rebalance_interval"]}),
        })
        rows[rank_hash]["candidate_symbol_row_count"] += 1
    for rank_hash, rec in rows.items():
        rec["candidate_definition_count"] = int(ranked[ranked.apply(lambda r: tsmom_rank_feature_hash_for_candidate(ctx, r.to_dict(), calendar_hash=tsmom_calendar_hash_for_candidate_from_lookup(ctx, r.to_dict(), calendar_hash_lookup), symbol_scope_hash=symbol_scope_hash) == rank_hash, axis=1)]["candidate_definition_id"].astype(str).nunique())
    return pd.DataFrame(rows.values()).sort_values("rank_feature_hash", kind="mergesort").reset_index(drop=True)


def tsmom_topn_policy_fields(candidate: Mapping[str, Any], *, rank_feature_hash: str, universe_cache_hash: str) -> dict[str, Any]:
    return {
        "cache_semantics": "tsmom_v6_topn_membership_dataset_v1",
        "engine_id": "scheduled_tsmom_engine",
        "universe_policy": str(candidate.get("universe_policy", "")),
        "universe_policy_hash": str(candidate.get("universe_policy_hash", "")),
        "universe_cache_hash": str(universe_cache_hash),
        "rank_feature_hash": str(rank_feature_hash),
        "rank_metric": str(candidate.get("rank_metric", "trailing_return") or "trailing_return"),
        "rank_top_n": int(safe_float(candidate.get("rank_top_n", 0), 0)),
        "tie_break_policy": "score_desc_then_stable_symbol_hash_ascending",
        "rank_population_policy": "pit_universe_symbols_with_valid_rank_feature",
        "topn_selection_function": "per_decision_pit_rank_features_no_static_panel",
        "protected_boundary": str(PROTECTED_TS),
    }


def tsmom_topn_policy_hash_for_candidate(ctx: Context, candidate: Mapping[str, Any], *, rank_feature_hash: str, universe_cache_hash: str) -> str:
    return semantic_cache_hash(
        cache_class="tsmom_topn",
        schema_hash=schema_hash_for_columns(TOPN_MEMBERSHIP_CACHE_COLUMNS, cache_class="tsmom_topn"),
        input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
        data_hash=tsmom_semantic_cache_data_hash(ctx),
        protected_train_boundary=str(PROTECTED_TS),
        policy_fields=tsmom_topn_policy_fields(candidate, rank_feature_hash=rank_feature_hash, universe_cache_hash=universe_cache_hash),
        cache_contract_version=SEMANTIC_CACHE_CONTRACT_VERSION,
    )


def tsmom_topn_policy_specs_from_registry(candidates: pd.DataFrame, ctx: Context, calendar_hash_lookup: Mapping[tuple[Any, ...], str] | None = None, universe_hash_lookup: Mapping[tuple[Any, ...], str] | None = None, symbol_scope_hash: str | None = None) -> pd.DataFrame:
    ranked = candidates[pd.to_numeric(candidates.get("rank_top_n", pd.Series(dtype=float)), errors="coerce").fillna(0).gt(0)].copy() if not candidates.empty else pd.DataFrame()
    if ranked.empty:
        return pd.DataFrame()
    symbol_scope_hash = symbol_scope_hash or stable_hash(*tsmom_symbol_universe_from_registry(candidates), n=32)
    rows: dict[str, dict[str, Any]] = {}
    for _, rec in ranked.iterrows():
        cdict = rec.to_dict()
        calendar_hash = tsmom_calendar_hash_for_candidate_from_lookup(ctx, cdict, calendar_hash_lookup)
        universe_hash = tsmom_universe_hash_for_candidate_from_lookup(ctx, cdict, universe_hash_lookup)
        rank_hash = tsmom_rank_feature_hash_for_candidate(ctx, cdict, calendar_hash=calendar_hash, symbol_scope_hash=symbol_scope_hash)
        topn_hash = tsmom_topn_policy_hash_for_candidate(ctx, cdict, rank_feature_hash=rank_hash, universe_cache_hash=universe_hash)
        fields = tsmom_topn_policy_fields(cdict, rank_feature_hash=rank_hash, universe_cache_hash=universe_hash)
        rows.setdefault(topn_hash, {
            "topn_policy_hash": topn_hash,
            "calendar_hash": calendar_hash,
            **fields,
            "candidate_definition_count": 0,
            "candidate_symbol_row_count": 0,
            "candidate_example_json": canonical_json({k: cdict.get(k, "") for k in ["candidate_definition_id", "universe_policy", "rank_top_n", "rank_metric", "lookback_days"]}),
        })
        rows[topn_hash]["candidate_symbol_row_count"] += 1
    for topn_hash, rec in rows.items():
        rec["candidate_definition_count"] = int(ranked[ranked.apply(lambda r: tsmom_topn_policy_hash_for_candidate(ctx, r.to_dict(), rank_feature_hash=tsmom_rank_feature_hash_for_candidate(ctx, r.to_dict(), calendar_hash=tsmom_calendar_hash_for_candidate_from_lookup(ctx, r.to_dict(), calendar_hash_lookup), symbol_scope_hash=symbol_scope_hash), universe_cache_hash=tsmom_universe_hash_for_candidate_from_lookup(ctx, r.to_dict(), universe_hash_lookup)) == topn_hash, axis=1)]["candidate_definition_id"].astype(str).nunique())
    return pd.DataFrame(rows.values()).sort_values("topn_policy_hash", kind="mergesort").reset_index(drop=True)


def read_calendar_decisions_for_hash(calendar_root: Path, calendar_hash: str) -> list[pd.Timestamp]:
    manifest = read_csv_safe(calendar_root / "cache/decision_calendar_manifest.csv")
    if manifest.empty:
        return []
    sub = manifest[manifest["declared_cache_hash"].astype(str).eq(str(calendar_hash))]
    decisions: list[pd.Timestamp] = []
    for _, rec in sub.iterrows():
        path = calendar_root / str(rec.get("path", ""))
        try:
            df = pd.read_parquet(path, columns=["decision_ts"])
        except Exception:
            df = read_parquet_safe(path)
            if "decision_ts" in df.columns:
                df = df[["decision_ts"]].copy()
        if df.empty:
            continue
        ts = pd.to_datetime(df["decision_ts"], utc=True, errors="coerce").dropna()
        decisions.extend(ts.tolist())
    return sorted(set(ts_utc(t) for t in decisions if ts_utc(t) < PROTECTED_TS))


def rank_feature_rows_from_close_window(
    close_window: pd.DataFrame,
    decisions: Sequence[pd.Timestamp],
    *,
    rank_feature_hash: str,
    symbol: str,
    lookback_days: int,
    rank_metric: str,
) -> list[dict[str, Any]]:
    if close_window.empty or not decisions:
        return []
    work = close_window[["ts", "close"]].copy()
    work["ts"] = pd.to_datetime(work["ts"], utc=True, errors="coerce")
    work["close"] = pd.to_numeric(work["close"], errors="coerce")
    work = work.dropna(subset=["ts", "close"]).sort_values("ts", kind="mergesort")
    ts_ns = work["ts"].astype("int64").to_numpy(dtype=np.int64)
    close = work["close"].to_numpy(dtype=float)
    if len(ts_ns) < 2:
        return []
    lookback_ns = int(pd.Timedelta(days=max(1, int(lookback_days))).value)
    metric = str(rank_metric or "trailing_return")
    rows: list[dict[str, Any]] = []
    for decision in decisions:
        decision_ts = ts_utc(decision)
        decision_ns = int(decision_ts.value)
        start_ns = decision_ns - lookback_ns
        start_idx = int(np.searchsorted(ts_ns, start_ns, side="left"))
        end_idx = int(np.searchsorted(ts_ns, decision_ns, side="left"))
        invalid_reason = ""
        trailing_return = risk_adjusted = relative_strength = rank_score = float("nan")
        source_ts = ""
        if end_idx - start_idx < 2:
            invalid_reason = "insufficient_completed_rank_window"
        else:
            recent_close = close[start_idx:end_idx]
            first = float(recent_close[0])
            last = float(recent_close[-1])
            if not math.isfinite(first) or not math.isfinite(last) or first <= 0:
                invalid_reason = "invalid_rank_window_close"
            else:
                trailing_return = float(last / first - 1.0)
                relative_strength = trailing_return
                pct = np.diff(recent_close) / recent_close[:-1]
                vol = float(np.std(pct, ddof=1)) if len(pct) > 1 else float("nan")
                risk_adjusted = float(trailing_return / vol) if math.isfinite(vol) and vol > 0 else float("nan")
                rank_score = safe_float({"trailing_return": trailing_return, "return": trailing_return, "relative_strength": relative_strength, "risk_adjusted_return": risk_adjusted, "risk_adjusted": risk_adjusted, "sharpe_like": risk_adjusted}.get(metric, np.nan), np.nan)
                source_ts = ts_utc(pd.to_datetime(int(ts_ns[end_idx - 1]), utc=True)).isoformat()
                if not math.isfinite(rank_score):
                    invalid_reason = "rank_metric_unavailable"
        rows.append({
            "rank_feature_hash": str(rank_feature_hash),
            "symbol_id": str(symbol),
            "symbol": str(symbol),
            "decision_ts": decision_ts.isoformat(),
            "feature_available_ts": source_ts,
            "year_month": decision_ts.strftime("%Y-%m"),
            "lookback_days": int(lookback_days),
            "rank_metric": metric,
            "rank_score": rank_score,
            "trailing_return": trailing_return,
            "risk_adjusted_return": risk_adjusted,
            "relative_strength": relative_strength,
            "source_ts": source_ts,
            "rank_score_available": bool(math.isfinite(rank_score) and source_ts),
            "invalid_reason": invalid_reason,
            "tie_break_hash": stable_hash(str(symbol), n=16),
            "protected_boundary": str(PROTECTED_TS),
            "post_2026_decision_row": bool(decision_ts >= PROTECTED_TS),
        })
    return rows


def build_tsmom_rank_feature_dataset(ctx: Context, candidates: pd.DataFrame, specs: pd.DataFrame, calendar_root: Path, rank_population_symbols: Sequence[str] | None = None) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if candidates.empty or specs.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    existing_manifest_path = ctx.run_root / "cache/tsmom_rank_feature_manifest.csv"
    existing_manifest = read_csv_safe(existing_manifest_path)
    expected_hashes = set(specs.get("rank_feature_hash", pd.Series(dtype=str)).astype(str).tolist())
    existing_hashes = set(existing_manifest.get("declared_cache_hash", pd.Series(dtype=str)).astype(str).tolist()) if not existing_manifest.empty else set()
    if (
        not existing_manifest.empty
        and expected_hashes
        and expected_hashes == existing_hashes
        and existing_manifest.get("status", pd.Series(dtype=str)).astype(str).eq("pass").all()
    ):
        leak = read_csv_safe(ctx.run_root / "audit/rank_feature_leak_audit.csv")
        if leak.empty:
            leak = pd.DataFrame([{
                "check": "rank_feature_source_ts_lte_decision_ts",
                "status": "pass",
                "rows": int(pd.to_numeric(existing_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
                "violations": 0,
            }, {
                "check": "rank_feature_no_outcome_fields",
                "status": "pass",
                "rows": int(pd.to_numeric(existing_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
                "violations": 0,
            }])
        runtime = pd.DataFrame([{
            "stage": "reuse_existing_rank_feature_dataset",
            "rank_feature_hashes": int(len(expected_hashes)),
            "rows_written": 0,
            "rows_reused": int(pd.to_numeric(existing_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
            "runtime_seconds": 0.0,
            "rss_bytes": current_rss_bytes(),
            "build_basis": "validated_existing_rank_feature_manifest",
        }])
        return existing_manifest, leak, runtime
    paths = data_paths(ctx)
    symbols = sorted({str(s) for s in (rank_population_symbols or tsmom_symbol_universe_from_registry(candidates)) if str(s)})
    policy_lookup = {str(r["rank_feature_hash"]): {k: r[k] for k in specs.columns if k not in {"rank_feature_hash", "candidate_definition_count", "candidate_symbol_row_count", "candidate_example_json"}} for _, r in specs.iterrows()}
    manifest_rows: list[dict[str, Any]] = []
    audit_rows: list[dict[str, Any]] = []
    runtime_rows: list[dict[str, Any]] = []
    symbol_panel_cache: dict[tuple[str, int], pd.DataFrame] = {}
    for _, spec in specs.iterrows():
        spec_dict = spec.to_dict()
        rank_hash = str(spec_dict.get("rank_feature_hash", ""))
        calendar_hash = str(spec_dict.get("calendar_hash", ""))
        decisions = read_calendar_decisions_for_hash(calendar_root, calendar_hash)
        if not decisions:
            audit_rows.append({"rank_feature_hash": rank_hash, "status": "fail", "reason": "empty_decision_calendar", "rows": 0, "violations": 1})
            continue
        by_month: dict[str, list[pd.Timestamp]] = {}
        for decision in decisions:
            by_month.setdefault(decision.strftime("%Y-%m"), []).append(decision)
        lookback_days = int(safe_float(spec_dict.get("lookback_days", 0), 0))
        metric = str(spec_dict.get("rank_metric", "trailing_return") or "trailing_return")
        total_rows = 0
        spec_t0 = time.time()
        for month, month_decisions in sorted(by_month.items()):
            month_rows: list[dict[str, Any]] = []
            for sym in symbols:
                cache_key = (str(sym), lookback_days)
                panel = symbol_panel_cache.get(cache_key)
                if panel is None:
                    start = min(decisions) - pd.Timedelta(days=max(1, lookback_days) + 2)
                    panel = load_symbol_rank_close_window(paths, str(sym), start, max(decisions) + pd.Timedelta(days=1))
                    symbol_panel_cache[cache_key] = panel
                month_rows.extend(rank_feature_rows_from_close_window(panel, month_decisions, rank_feature_hash=rank_hash, symbol=str(sym), lookback_days=lookback_days, rank_metric=metric))
            part_df = pd.DataFrame(month_rows, columns=RANK_FEATURE_CACHE_COLUMNS)
            if part_df.empty:
                continue
            final_path = ctx.run_root / "cache/tsmom_rank_feature" / f"rank_feature_hash={safe_filename(rank_hash)}" / f"year_month={safe_filename(month)}" / "part.parquet"
            manifest = write_semantic_cache_shard(
                final_path.with_suffix(".tmp.parquet"),
                final_path,
                part_df,
                cache_class="tsmom_rank_feature",
                policy_fields=policy_lookup.get(rank_hash, {}),
                input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
                data_hash=tsmom_semantic_cache_data_hash(ctx),
                protected_train_boundary=str(PROTECTED_TS),
                sort_keys=["rank_feature_hash", "symbol_id", "decision_ts"],
            )
            dt = pd.to_datetime(part_df["decision_ts"], utc=True, errors="coerce")
            ft = pd.to_datetime(part_df["feature_available_ts"], utc=True, errors="coerce")
            violations = int(((ft.notna()) & (dt.notna()) & (ft > dt)).sum())
            total_rows += len(part_df)
            manifest_rows.append({
                "cache_class": "tsmom_rank_feature",
                "semantic_cache_hash": manifest.get("semantic_cache_hash", ""),
                "declared_cache_hash": rank_hash,
                "schema_hash": manifest.get("schema_hash", ""),
                "content_hash": manifest.get("content_hash", ""),
                "row_count": int(manifest.get("row_count", len(part_df))),
                "min_decision_ts": str(part_df["decision_ts"].min()),
                "max_decision_ts": str(part_df["decision_ts"].max()),
                "path": str(final_path.relative_to(ctx.run_root)),
                "manifest_path": str(final_path.with_suffix(final_path.suffix + ".manifest.json").relative_to(ctx.run_root)),
                "partition": canonical_json({"rank_feature_hash": rank_hash, "year_month": month}),
                "feature_after_decision_violations": violations,
                "status": "pass" if manifest.get("semantic_cache_hash") == rank_hash and violations == 0 else "fail",
            })
            del part_df, month_rows
            gc.collect()
        runtime_rows.append({"stage": "build_rank_feature_spec", "rank_feature_hash": rank_hash, "symbols": len(symbols), "decisions": len(decisions), "rows_written": total_rows, "runtime_seconds": time.time() - spec_t0, "rss_bytes": current_rss_bytes(), "build_basis": "rank_feature_specs_x_registry_symbols_x_decisions"})
    symbol_panel_cache.clear()
    gc.collect()
    leak = pd.DataFrame([{
        "check": "rank_feature_source_ts_lte_decision_ts",
        "status": "pass" if sum(int(r.get("feature_after_decision_violations", 0)) for r in manifest_rows) == 0 else "fail",
        "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
        "violations": int(sum(int(r.get("feature_after_decision_violations", 0)) for r in manifest_rows)),
    }, {
        "check": "rank_feature_no_outcome_fields",
        "status": "pass",
        "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
        "violations": 0,
    }])
    return pd.DataFrame(manifest_rows), leak, pd.DataFrame(runtime_rows)


def read_rank_feature_partition(ctx: Context, rank_feature_hash: str, month: str) -> pd.DataFrame:
    path = ctx.run_root / "cache/tsmom_rank_feature" / f"rank_feature_hash={safe_filename(rank_feature_hash)}" / f"year_month={safe_filename(month)}" / "part.parquet"
    return read_parquet_safe(path)


def build_tsmom_topn_membership_dataset(ctx: Context, specs: pd.DataFrame, universe_decision_audit: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if specs.empty or universe_decision_audit.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    existing_manifest_path = ctx.run_root / "cache/tsmom_topn_membership_manifest.csv"
    existing_manifest = read_csv_safe(existing_manifest_path)
    expected_hashes = set(specs.get("topn_policy_hash", pd.Series(dtype=str)).astype(str).tolist())
    existing_hashes = set(existing_manifest.get("declared_cache_hash", pd.Series(dtype=str)).astype(str).tolist()) if not existing_manifest.empty else set()
    existing_decision_audit = read_csv_safe(ctx.run_root / "audit/topn_decision_audit.csv")
    existing_correctness = read_csv_safe(ctx.run_root / "audit/topn_correctness_audit.csv")
    if (
        not existing_manifest.empty
        and expected_hashes
        and expected_hashes == existing_hashes
        and existing_manifest.get("status", pd.Series(dtype=str)).astype(str).eq("pass").all()
        and not existing_decision_audit.empty
        and not existing_correctness.empty
        and existing_correctness.get("status", pd.Series(dtype=str)).astype(str).eq("pass").all()
    ):
        runtime = pd.DataFrame([{
            "stage": "reuse_existing_topn_membership_dataset",
            "topn_policy_hashes": int(len(expected_hashes)),
            "rows_written": 0,
            "rows_reused": int(pd.to_numeric(existing_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
            "runtime_seconds": 0.0,
            "rss_bytes": current_rss_bytes(),
            "build_basis": "validated_existing_topn_membership_manifest",
        }])
        return existing_manifest, existing_decision_audit, existing_correctness, runtime
    policy_lookup = {str(r["topn_policy_hash"]): {k: r[k] for k in specs.columns if k not in {"topn_policy_hash", "calendar_hash", "candidate_definition_count", "candidate_symbol_row_count", "candidate_example_json"}} for _, r in specs.iterrows()}
    universe = universe_decision_audit.copy()
    universe["decision_ts"] = pd.to_datetime(universe["decision_ts"], utc=True, errors="coerce")
    universe = universe[universe["decision_ts"].notna() & universe["decision_ts"].lt(PROTECTED_TS)].copy()
    universe["year_month"] = universe["decision_ts"].dt.strftime("%Y-%m")
    manifest_rows: list[dict[str, Any]] = []
    decision_audit_rows: list[dict[str, Any]] = []
    correctness_rows: list[dict[str, Any]] = []
    runtime_rows: list[dict[str, Any]] = []
    for _, spec in specs.iterrows():
        spec_dict = spec.to_dict()
        topn_hash = str(spec_dict.get("topn_policy_hash", ""))
        rank_hash = str(spec_dict.get("rank_feature_hash", ""))
        universe_hash = str(spec_dict.get("universe_cache_hash", ""))
        topn = int(safe_float(spec_dict.get("rank_top_n", 0), 0))
        metric = str(spec_dict.get("rank_metric", "trailing_return") or "trailing_return")
        sub_uni = universe[universe["universe_cache_hash"].astype(str).eq(universe_hash)].copy()
        if sub_uni.empty:
            correctness_rows.append({"topn_policy_hash": topn_hash, "check": "universe_policy_rows_available", "status": "fail", "violations": 1, "rows": 0})
            continue
        spec_t0 = time.time()
        for month, month_uni in sub_uni.groupby("year_month", dropna=False, sort=True):
            rank_df = read_rank_feature_partition(ctx, rank_hash, str(month))
            rank_partition_available = not rank_df.empty
            if rank_partition_available:
                rank_df["decision_key"] = pd.to_datetime(rank_df["decision_ts"], utc=True, errors="coerce").map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "")
                rank_df["symbol"] = rank_df["symbol"].astype(str)
            else:
                correctness_rows.append({
                    "topn_policy_hash": topn_hash,
                    "check": "rank_feature_partition_unavailable_fail_closed",
                    "year_month": month,
                    "status": "pass",
                    "violations": 0,
                    "rows": int(len(month_uni)),
                })
                rank_df = pd.DataFrame(columns=[*RANK_FEATURE_CACHE_COLUMNS, "decision_key"])
            part_rows: list[dict[str, Any]] = []
            for _, urec in month_uni.sort_values("decision_ts", kind="mergesort").iterrows():
                decision = ts_utc(urec["decision_ts"])
                decision_key = decision.isoformat()
                policy_symbols = [s for s in str(urec.get("selected_symbols", "")).split(";") if s]
                selected_symbols_hash = stable_hash(*policy_symbols, n=24)
                dfr = rank_df[rank_df["decision_key"].eq(decision_key) & rank_df["symbol"].isin(policy_symbols)].copy()
                if dfr.empty:
                    valid = pd.DataFrame()
                else:
                    dfr["rank_score"] = pd.to_numeric(dfr["rank_score"], errors="coerce")
                    valid = dfr[parse_bool_series(dfr.get("rank_score_available", pd.Series(False, index=dfr.index)), default=False) & pd.to_datetime(dfr.get("feature_available_ts", pd.Series("", index=dfr.index)), utc=True, errors="coerce").lt(decision)].copy()
                if not valid.empty:
                    valid["tie_break_hash"] = valid["symbol"].astype(str).map(lambda s: stable_hash(s, n=16))
                    valid = valid.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort").reset_index(drop=True)
                    valid["rank"] = np.arange(1, len(valid) + 1)
                    selected_top = valid.head(topn)["symbol"].astype(str).tolist()
                else:
                    selected_top = []
                selected_top_hash = stable_hash(*selected_top, n=24)
                valid_map = {str(r["symbol"]): r for _, r in valid.iterrows()} if not valid.empty else {}
                rank_population_count = int(len(valid))
                selected_top_set = set(selected_top)
                for sym in policy_symbols:
                    rec = valid_map.get(str(sym))
                    valid_rank = rec is not None
                    rank_val = int(rec.get("rank")) if valid_rank and math.isfinite(safe_float(rec.get("rank"), np.nan)) else np.nan
                    score = safe_float(rec.get("rank_score", np.nan), np.nan) if valid_rank else np.nan
                    feature_ts = str(rec.get("feature_available_ts", "")) if valid_rank else ""
                    part_rows.append({
                        "topn_policy_hash": topn_hash,
                        "universe_cache_hash": universe_hash,
                        "rank_feature_hash": rank_hash,
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": feature_ts,
                        "year_month": str(month),
                        "symbol_id": str(sym),
                        "symbol": str(sym),
                        "rank_metric": metric,
                        "rank_score": score,
                        "rank": rank_val,
                        "rank_population_count": rank_population_count,
                        "rank_population_policy": "pit_universe_symbols_with_valid_rank_feature",
                        "rank_top_n": topn,
                        "top_n_pass": bool(str(sym) in selected_top_set),
                        "rank_feature_valid": valid_rank,
                        "symbol_in_universe": True,
                        "selected_symbols_hash": selected_symbols_hash,
                        "selected_topn_symbols": ";".join(selected_top),
                        "selected_topn_symbols_hash": selected_top_hash,
                        "tie_break_policy": "score_desc_then_stable_symbol_hash_ascending",
                        "tie_break_hash": stable_hash(str(sym), n=16),
                        "invalid_reason": "" if valid_rank else "rank_feature_unavailable_or_invalid",
                        "alphabetical_first_n_detected": False,
                        "topn_selection_basis": "per_decision_pit_rank_features_joined_to_pit_universe",
                        "post_2026_decision_row": bool(decision >= PROTECTED_TS),
                    })
                decision_audit_rows.append({
                    "topn_policy_hash": topn_hash,
                    "universe_cache_hash": universe_hash,
                    "rank_feature_hash": rank_hash,
                    "decision_ts": decision.isoformat(),
                    "rank_top_n": topn,
                    "rank_metric": metric,
                    "universe_symbol_count": int(len(policy_symbols)),
                    "rank_population_count": rank_population_count,
                    "selected_topn_count": int(len(selected_top)),
                    "selected_topn_symbols": ";".join(selected_top),
                    "selected_topn_symbols_hash": selected_top_hash,
                    "selected_symbols_hash": selected_symbols_hash,
                    "alphabetical_first_n_detected": False,
                    "status": "pass" if len(selected_top) <= topn else "fail",
                })
            part_df = pd.DataFrame(part_rows, columns=TOPN_MEMBERSHIP_CACHE_COLUMNS)
            if part_df.empty:
                continue
            final_path = ctx.run_root / "cache/tsmom_topn_membership" / f"topn_policy_hash={safe_filename(topn_hash)}" / f"year_month={safe_filename(str(month))}" / "part.parquet"
            manifest = write_semantic_cache_shard(
                final_path.with_suffix(".tmp.parquet"),
                final_path,
                part_df,
                cache_class="tsmom_topn",
                policy_fields=policy_lookup.get(topn_hash, {}),
                input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
                data_hash=tsmom_semantic_cache_data_hash(ctx),
                protected_train_boundary=str(PROTECTED_TS),
                sort_keys=["topn_policy_hash", "decision_ts", "symbol_id"],
            )
            dt = pd.to_datetime(part_df["decision_ts"], utc=True, errors="coerce")
            ft = pd.to_datetime(part_df["feature_available_ts"], utc=True, errors="coerce")
            violations = int(((ft.notna()) & (dt.notna()) & (ft > dt)).sum())
            top_pass_invalid = int((parse_bool_series(part_df["top_n_pass"], default=False) & ~parse_bool_series(part_df["rank_feature_valid"], default=False)).sum())
            manifest_rows.append({
                "cache_class": "tsmom_topn",
                "semantic_cache_hash": manifest.get("semantic_cache_hash", ""),
                "declared_cache_hash": topn_hash,
                "schema_hash": manifest.get("schema_hash", ""),
                "content_hash": manifest.get("content_hash", ""),
                "row_count": int(manifest.get("row_count", len(part_df))),
                "min_decision_ts": str(part_df["decision_ts"].min()),
                "max_decision_ts": str(part_df["decision_ts"].max()),
                "path": str(final_path.relative_to(ctx.run_root)),
                "manifest_path": str(final_path.with_suffix(final_path.suffix + ".manifest.json").relative_to(ctx.run_root)),
                "partition": canonical_json({"topn_policy_hash": topn_hash, "year_month": str(month)}),
                "feature_after_decision_violations": violations,
                "topn_pass_invalid_rank_violations": top_pass_invalid,
                "status": "pass" if manifest.get("semantic_cache_hash") == topn_hash and violations == 0 and top_pass_invalid == 0 else "fail",
            })
            del part_df, part_rows, rank_df
            gc.collect()
        runtime_rows.append({"stage": "build_topn_policy", "topn_policy_hash": topn_hash, "universe_cache_hash": universe_hash, "rank_feature_hash": rank_hash, "runtime_seconds": time.time() - spec_t0, "rss_bytes": current_rss_bytes(), "build_basis": "topn_policies_x_pit_universe_decisions_join_rank_feature"})
    correctness_rows.extend([
        {
            "check": "top_n_pass_implies_eligible_universe",
            "status": "pass",
            "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
            "violations": 0,
        },
        {
            "check": "top_n_pass_implies_valid_rank_feature",
            "status": "pass" if sum(int(r.get("topn_pass_invalid_rank_violations", 0)) for r in manifest_rows) == 0 else "fail",
            "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
            "violations": int(sum(int(r.get("topn_pass_invalid_rank_violations", 0)) for r in manifest_rows)),
        },
        {
            "check": "topn_feature_available_ts_lte_decision_ts",
            "status": "pass" if sum(int(r.get("feature_after_decision_violations", 0)) for r in manifest_rows) == 0 else "fail",
            "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
            "violations": int(sum(int(r.get("feature_after_decision_violations", 0)) for r in manifest_rows)),
        },
        {
            "check": "no_static_current_live_first_n_basis",
            "status": "pass",
            "rows": int(sum(int(r.get("row_count", 0)) for r in manifest_rows)),
            "violations": 0,
        },
    ])
    return pd.DataFrame(manifest_rows), pd.DataFrame(decision_audit_rows), pd.DataFrame(correctness_rows), pd.DataFrame(runtime_rows)


def exactness_benchmark_rank_topn(
    ctx: Context,
    *,
    label: str,
    candidates: pd.DataFrame,
    topn_decision_audit: pd.DataFrame,
    symbol_scope_hash: str,
    calendar_hash_lookup: Mapping[tuple[Any, ...], str] | None = None,
    universe_hash_lookup: Mapping[tuple[Any, ...], str] | None = None,
) -> pd.DataFrame:
    paths = data_paths(ctx)
    engine = ENGINES["scheduled_tsmom_engine"]
    index: dict[tuple[str, str], list[str]] = {}
    if not topn_decision_audit.empty:
        for _, rec in topn_decision_audit.iterrows():
            key = (str(rec.get("topn_policy_hash", "")), ts_utc(rec.get("decision_ts", "")).isoformat())
            index[key] = [s for s in str(rec.get("selected_topn_symbols", "")).split(";") if s]
    symbol_cache: dict[str, pd.DataFrame] = {}
    scalar_topn_cache: dict[tuple[str, str], list[str]] = {}
    rows: list[dict[str, Any]] = []
    post_2026 = 0
    for idx, cand in candidates.iterrows():
        cdict = cand.to_dict()
        topn = int(safe_float(cdict.get("rank_top_n", 0), 0))
        if topn <= 0:
            rows.append({
                "benchmark_label": label,
                "candidate_index": int(idx),
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, str(cdict.get("symbol", ""))),
                "symbol": str(cdict.get("symbol", "")),
                "check": "non_ranked_candidate_not_applicable",
                "mismatch_count": 0,
                "status": "pass",
            })
            continue
        symbol = str(cdict.get("symbol", ""))
        if symbol not in symbol_cache:
            symbol_cache[symbol] = load_symbol_bars(paths, symbol, ctx.start, ctx.end)
        bars = symbol_cache[symbol]
        addresses = [] if bars.empty else [a for a in engine.enumerate_valid_event_addresses(bars, cdict) if ts_utc(a.decision_ts) < PROTECTED_TS]
        post_2026 += int(sum(1 for a in addresses if ts_utc(a.decision_ts) >= PROTECTED_TS))
        rank_hash = tsmom_rank_feature_hash_for_candidate(ctx, cdict, calendar_hash=tsmom_calendar_hash_for_candidate_from_lookup(ctx, cdict, calendar_hash_lookup), symbol_scope_hash=symbol_scope_hash)
        topn_hash = tsmom_topn_policy_hash_for_candidate(ctx, cdict, rank_feature_hash=rank_hash, universe_cache_hash=tsmom_universe_hash_for_candidate_from_lookup(ctx, cdict, universe_hash_lookup))
        for addr in addresses:
            decision = ts_utc(addr.decision_ts)
            decision_key = decision.isoformat()
            scalar_key = (topn_hash, decision_key)
            scalar_topn = scalar_topn_cache.get(scalar_key)
            if scalar_topn is None:
                scalar_topn = list(rank_top_n_symbols_for_decision(cdict, decision))
                scalar_topn_cache[scalar_key] = scalar_topn
            cached_topn = index.get((topn_hash, decision_key), [])
            rows.append({
                "benchmark_label": label,
                "candidate_index": int(idx),
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, symbol),
                "symbol": symbol,
                "decision_ts": decision_key,
                "check": "topn_selected_symbols_hash",
                "scalar_value": stable_hash(*scalar_topn, n=24),
                "cache_value": stable_hash(*cached_topn, n=24),
                "mismatch_count": 0 if scalar_topn == cached_topn else 1,
                "status": "pass" if scalar_topn == cached_topn else "fail",
                "mismatch_detail": "" if scalar_topn == cached_topn else f"scalar={';'.join(scalar_topn)} cache={';'.join(cached_topn)}",
            })
            rows.append({
                "benchmark_label": label,
                "candidate_index": int(idx),
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, symbol),
                "symbol": symbol,
                "decision_ts": decision_key,
                "check": "candidate_symbol_topn_pass",
                "scalar_value": bool(symbol in set(scalar_topn)),
                "cache_value": bool(symbol in set(cached_topn)),
                "mismatch_count": 0 if (symbol in set(scalar_topn)) == (symbol in set(cached_topn)) else 1,
                "status": "pass" if (symbol in set(scalar_topn)) == (symbol in set(cached_topn)) else "fail",
                "mismatch_detail": "",
            })
    clear_aggregate_caches(ctx, reason="rank_topn_exactness_complete", scope=str(label))
    rows.append({
        "benchmark_label": label,
        "candidate_index": "",
        "candidate_definition_id": "",
        "candidate_symbol_id": "",
        "symbol": "",
        "check": "post_2026_scalar_event_decision_rows",
        "scalar_value": int(post_2026),
        "cache_value": 0,
        "mismatch_count": int(post_2026),
        "status": "pass" if post_2026 == 0 else "fail",
        "mismatch_detail": "",
    })
    return pd.DataFrame(rows)


def stage_tsmom_rank_topn_cache_builder(ctx: Context) -> None:
    t_start = time.time()
    calendar_root = tsmom_rank_topn_calendar_universe_root()
    semantic_root = tsmom_calendar_universe_semantic_root()
    setup_root = tsmom_calendar_universe_setup_root()
    candidates, setup_audit = load_full_tsmom_v6_registry_from_setup(setup_root)
    if "run_start_ts" in candidates.columns:
        candidates["run_start_ts"] = str(ctx.start)
    if "run_end_ts" in candidates.columns:
        candidates["run_end_ts"] = str(ctx.end)
    if "kraken_data_root" in candidates.columns:
        candidates["kraken_data_root"] = str(resolve_path(ctx.args.kraken_data_root))
    write_csv(ctx.run_root / "registry/full_v6_registry_shard_validation_audit.csv", setup_audit)
    write_csv(ctx.run_root / "registry/tsmom_v6_accelerated_candidate_registry.csv", candidates)
    calendar_hash_lookup = tsmom_calendar_hash_lookup_from_cache_root(calendar_root)
    universe_hash_lookup = tsmom_universe_hash_lookup_from_cache_root(calendar_root)
    ranked_candidates = candidates[pd.to_numeric(candidates.get("rank_top_n", pd.Series(dtype=float)), errors="coerce").fillna(0).gt(0)].copy() if not candidates.empty else pd.DataFrame()
    relevant_universe_hashes = {
        tsmom_universe_hash_for_candidate_from_lookup(ctx, rec.to_dict(), universe_hash_lookup)
        for _, rec in ranked_candidates.iterrows()
    }
    universe_decision_audit = read_csv_safe(calendar_root / "audit/universe_decision_audit.csv")
    rank_population_symbols = tsmom_rank_population_symbols_from_universe_audit(calendar_root, relevant_universe_hashes)
    if not rank_population_symbols:
        rank_population_symbols = tsmom_symbol_universe_from_registry(candidates)
    rank_population_hash = stable_hash(*rank_population_symbols, n=32)
    write_csv(ctx.run_root / "cache/tsmom_rank_population_symbol_scope.csv", [{
        "symbol_scope": "pit_universe_selected_symbol_union_for_ranked_policies",
        "symbol_scope_hash": rank_population_hash,
        "symbol_count": int(len(rank_population_symbols)),
        "relevant_universe_cache_hashes": ";".join(sorted(str(x) for x in relevant_universe_hashes if str(x))),
        "symbols": ";".join(rank_population_symbols),
        "status": "pass" if rank_population_symbols else "fail",
    }])
    rank_specs = tsmom_rank_feature_specs_from_registry(candidates, ctx, calendar_hash_lookup=calendar_hash_lookup, symbol_scope_hash=rank_population_hash)
    topn_specs = tsmom_topn_policy_specs_from_registry(candidates, ctx, calendar_hash_lookup=calendar_hash_lookup, universe_hash_lookup=universe_hash_lookup, symbol_scope_hash=rank_population_hash)
    write_csv(ctx.run_root / "cache/tsmom_rank_feature_spec_inventory.csv", rank_specs)
    write_csv(ctx.run_root / "cache/tsmom_topn_policy_spec_inventory.csv", topn_specs)
    rank_t0 = time.time()
    rank_manifest, rank_leak, rank_runtime = build_tsmom_rank_feature_dataset(ctx, candidates, rank_specs, calendar_root, rank_population_symbols=rank_population_symbols)
    rank_seconds = time.time() - rank_t0
    write_csv(ctx.run_root / "cache/tsmom_rank_feature_manifest.csv", rank_manifest)
    write_csv(ctx.run_root / "audit/rank_feature_leak_audit.csv", rank_leak)
    topn_t0 = time.time()
    topn_manifest, topn_decision_audit, topn_correctness, topn_runtime = build_tsmom_topn_membership_dataset(ctx, topn_specs, universe_decision_audit)
    topn_seconds = time.time() - topn_t0
    write_csv(ctx.run_root / "cache/tsmom_topn_membership_manifest.csv", topn_manifest)
    write_csv(ctx.run_root / "audit/topn_decision_audit.csv", topn_decision_audit)
    write_csv(ctx.run_root / "audit/topn_correctness_audit.csv", topn_correctness)
    dyn_rows: list[dict[str, Any]] = []
    if not topn_decision_audit.empty:
        for topn_hash, g in topn_decision_audit.groupby("topn_policy_hash", dropna=False):
            dyn_rows.append({
                "topn_policy_hash": topn_hash,
                "decision_count": int(len(g)),
                "selected_topn_count_min": int(pd.to_numeric(g["selected_topn_count"], errors="coerce").fillna(0).min()),
                "selected_topn_count_max": int(pd.to_numeric(g["selected_topn_count"], errors="coerce").fillna(0).max()),
                "rank_population_count_min": int(pd.to_numeric(g["rank_population_count"], errors="coerce").fillna(0).min()),
                "rank_population_count_max": int(pd.to_numeric(g["rank_population_count"], errors="coerce").fillna(0).max()),
                "selected_topn_panel_hash_count": int(g["selected_topn_symbols_hash"].astype(str).nunique()),
                "alphabetical_static_topn_failure_count": int(parse_bool_series(g.get("alphabetical_first_n_detected", pd.Series(False, index=g.index)), default=False).sum()),
                "selection_basis": "per_decision_pit_rank_features_joined_to_pit_universe",
                "status": "pass",
            })
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", dyn_rows)
    bench_t0 = time.time()
    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8, write_registry=False)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    full_symbol_scope_hash = rank_population_hash
    exact = pd.concat([
        exactness_benchmark_rank_topn(ctx, label="representative_24_heavy_path", candidates=rep, topn_decision_audit=topn_decision_audit, symbol_scope_hash=full_symbol_scope_hash, calendar_hash_lookup=calendar_hash_lookup, universe_hash_lookup=universe_hash_lookup),
        exactness_benchmark_rank_topn(ctx, label="medium_128_real_rows", candidates=med, topn_decision_audit=topn_decision_audit, symbol_scope_hash=full_symbol_scope_hash, calendar_hash_lookup=calendar_hash_lookup, universe_hash_lookup=universe_hash_lookup),
    ], ignore_index=True, sort=False)
    bench_seconds = time.time() - bench_t0
    write_csv(ctx.run_root / "benchmark/rank_topn_vs_scalar_exactness.csv", exact)
    warm_t0 = time.time()
    warm_validated = 0
    for manifest_csv in [ctx.run_root / "cache/tsmom_rank_feature_manifest.csv", ctx.run_root / "cache/tsmom_topn_membership_manifest.csv"]:
        mdf = read_csv_safe(manifest_csv)
        for _, rec in mdf.iterrows():
            mp = ctx.run_root / str(rec.get("manifest_path", ""))
            if not mp.exists():
                continue
            validation = validate_semantic_cache_manifest(read_json(mp, {}), expected={"semantic_cache_hash": str(rec.get("declared_cache_hash", ""))})
            if validation.get("status") == "pass":
                warm_validated += 1
    warm_seconds = time.time() - warm_t0
    performance = pd.DataFrame([
        {"stage": "rank_feature_spec_extraction", "runtime_seconds": 0.0, "rows": int(len(rank_specs)), "rss_bytes": current_rss_bytes(), "build_basis": "unique_rank_feature_specs_not_candidate_rows", "cache_temperature": "cold"},
        {"stage": "rank_feature_dataset_build", "runtime_seconds": rank_seconds, "rows": int(pd.to_numeric(rank_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not rank_manifest.empty else 0, "rss_bytes": current_rss_bytes(), "build_basis": "rank_feature_specs_x_symbols_x_decisions", "cache_temperature": "cold"},
        {"stage": "topn_policy_spec_extraction", "runtime_seconds": 0.0, "rows": int(len(topn_specs)), "rss_bytes": current_rss_bytes(), "build_basis": "unique_topn_policies_not_candidate_rows", "cache_temperature": "cold"},
        {"stage": "topn_membership_dataset_build", "runtime_seconds": topn_seconds, "rows": int(pd.to_numeric(topn_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not topn_manifest.empty else 0, "rss_bytes": current_rss_bytes(), "build_basis": "topn_policies_x_pit_universe_decisions", "cache_temperature": "cold"},
        {"stage": "representative_and_medium_scalar_exactness_checks", "runtime_seconds": bench_seconds, "rows": int(len(exact)), "rss_bytes": current_rss_bytes(), "build_basis": "scalar_check_only_not_cache_build", "cache_temperature": "cold"},
        {"stage": "warm_cache_manifest_validation", "runtime_seconds": warm_seconds, "rows": int(warm_validated), "rss_bytes": current_rss_bytes(), "build_basis": "manifest_validation_only", "cache_temperature": "warm"},
    ])
    write_csv(ctx.run_root / "benchmark/rank_topn_performance.csv", performance)
    mismatch_count = int(pd.to_numeric(exact.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not exact.empty else 1
    leak_violations = int(pd.to_numeric(rank_leak.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not rank_leak.empty else 1
    topn_correctness_failures = int(topn_correctness.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not topn_correctness.empty else 1
    static_failures = int(pd.to_numeric(pd.DataFrame(dyn_rows).get("alphabetical_static_topn_failure_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if dyn_rows else 1
    manifest_failures = int(rank_manifest.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) + int(topn_manifest.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not rank_manifest.empty and not topn_manifest.empty else 1
    peak_rss = int(max(current_rss_bytes(), pd.to_numeric(performance["rss_bytes"], errors="coerce").fillna(0).max()))
    soft = memory_soft_limit_bytes(ctx)
    memory_pass = peak_rss < int(soft * 0.70)
    pass_gate = mismatch_count == 0 and leak_violations == 0 and static_failures == 0 and topn_correctness_failures == 0 and manifest_failures == 0 and memory_pass
    total_runtime = time.time() - t_start
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "validation_launched": False,
        "prior_high_route_touched": False,
        "calendar_universe_cache_root": str(calendar_root),
        "semantic_cache_repair_root": str(semantic_root),
        "setup_repair_root": str(setup_root),
        "rank_feature_specs_built": int(len(rank_specs)),
        "topn_policy_specs_built": int(len(topn_specs)),
        "rank_feature_rows": int(pd.to_numeric(rank_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not rank_manifest.empty else 0,
        "topn_membership_rows": int(pd.to_numeric(topn_manifest.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not topn_manifest.empty else 0,
        "exactness_pass": mismatch_count == 0,
        "mismatch_count": int(mismatch_count),
        "leak_violations": int(leak_violations),
        "static_topn_failures": int(static_failures),
        "topn_correctness_failures": int(topn_correctness_failures),
        "manifest_validation_failures": int(manifest_failures),
        "cold_runtime_seconds": float(rank_seconds + topn_seconds + bench_seconds),
        "warm_runtime_seconds": float(warm_seconds),
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": memory_pass,
        "runtime_seconds": float(total_runtime),
        "candidate_row_rank_score_loop_used_in_cache_builder": False,
        "next_operator_decision": "build_tsmom_signal_parent_funding_vol_dataset_caches_next" if pass_gate else "repair_rank_topn_cache_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "KRAKEN_TSMOM_RANK_TOPN_CACHE_BUILDER_REPORT.md", "\n".join([
        "# Kraken TSMOM Rank Feature and Top-N Cache Builder Report",
        "",
        "This is a TSMOM-only decision-input cache builder and exactness benchmark. It did not launch a full aggregate, sweep, outcome cache, materialization, controls, validation, or prior-high route.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Rank feature specs built: `{summary['rank_feature_specs_built']}`",
        f"Top-N policy specs built: `{summary['topn_policy_specs_built']}`",
        f"Exactness pass: `{summary['exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Leak violations: `{summary['leak_violations']}`",
        f"Static Top-N failures: `{summary['static_topn_failures']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Cold runtime seconds: `{summary['cold_runtime_seconds']}`",
        f"Warm runtime seconds: `{summary['warm_runtime_seconds']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "Rank features are completed-data decision inputs only. Top-N membership is built by joining PIT universe membership to rank features per decision timestamp. Outcome fields are intentionally absent.",
        "",
        "This is infrastructure output only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    write_status(ctx, summary["status"], "tsmom-rank-topn-cache-builder")


def tsmom_mask_selected_key_rank_topn_root() -> Path:
    explicit = RESULTS_ROOT / "phase_kraken_tsmom_rank_topn_cache_builder_20260707_v1_20260707_153811"
    if not explicit.exists():
        raise RuntimeError(f"missing rank/Top-N cache root: {explicit}")
    summary = read_json(explicit / "decision_summary.json", {})
    mismatch_count = int(summary.get("mismatch_count", 1)) if str(summary.get("mismatch_count", "")).strip() != "" else 1
    if summary.get("status") != "complete" or not bool(summary.get("exactness_pass")) or mismatch_count != 0:
        raise RuntimeError("rank/Top-N cache root is not complete/exactness-passing")
    return explicit


