def policy_hash_or_stable(candidate: Mapping[str, Any], field: str, *parts: Any) -> str:
    existing = str(candidate.get(field, "") or "").strip()
    if existing and existing.lower() not in {"nan", "none"}:
        return existing
    return stable_hash(field, *parts, n=24)


def tsmom_signal_policy_hash_for_candidate_ctx(ctx: Context, candidate: Mapping[str, Any], *, calendar_hash: str) -> str:
    fields = {
        "cache_semantics": "tsmom_v6_signal_mask_dataset_v1",
        "engine_id": "scheduled_tsmom_engine",
        "calendar_hash": str(calendar_hash),
        "entry_template": str(candidate.get("entry_template", "")),
        "side": str(candidate.get("side", "")),
        "threshold": float(safe_float(candidate.get("threshold", 0.005), 0.005)),
        "lookback_days": int(safe_float(candidate.get("lookback_days", 0), 0)),
        "lookback_bars": int(safe_float(candidate.get("lookback_bars", 0), 0)),
        "rebalance_interval": str(candidate.get("rebalance_interval", "")),
        "signal_function": "ScheduledTsmomEngine.build_candidate_masks_ret_threshold_on_scheduled_rows",
        "decision_source": "precomputed_decision_calendar_completed_bars_plus_completed_bar_return_threshold",
        "protected_boundary": str(PROTECTED_TS),
    }
    return semantic_cache_hash(
        cache_class="tsmom_signal",
        schema_hash=schema_hash_for_columns(TSMOM_SIGNAL_MASK_COLUMNS, cache_class="tsmom_signal"),
        input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
        data_hash=tsmom_semantic_cache_data_hash(ctx),
        protected_train_boundary=str(PROTECTED_TS),
        policy_fields=fields,
        cache_contract_version=SEMANTIC_CACHE_CONTRACT_VERSION,
    )


def read_manifest_partition(root: Path, manifest: pd.DataFrame, declared_hash: str, year_month: str, *, columns: Sequence[str] | None = None) -> pd.DataFrame:
    if manifest.empty or not str(declared_hash).strip():
        return pd.DataFrame()
    path_match = manifest.get("path", pd.Series(dtype=str)).astype(str).str.contains(f"year_month={safe_filename(year_month)}", regex=False)
    hash_match = manifest.get("declared_cache_hash", pd.Series(dtype=str)).astype(str).eq(str(declared_hash))
    sub = manifest[hash_match & path_match]
    frames: list[pd.DataFrame] = []
    for _, rec in sub.iterrows():
        path = root / str(rec.get("path", ""))
        if not path.exists():
            continue
        try:
            frames.append(pd.read_parquet(path, columns=list(columns) if columns else None))
        except Exception:
            df = read_parquet_safe(path)
            if columns and not df.empty:
                keep = [c for c in columns if c in df.columns]
                df = df[keep].copy() if keep else pd.DataFrame()
            frames.append(df)
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def lookup_rank_feature_hash_from_spec_inventory(cdict: Mapping[str, Any], rank_specs: pd.DataFrame, *, calendar_hash: str, symbol_scope_hash: str) -> str:
    if rank_specs.empty:
        return ""
    mask = pd.Series(True, index=rank_specs.index)
    str_fields = {
        "calendar_hash": calendar_hash,
        "bar_timeframe": str(cdict.get("bar_timeframe", "5m") or "5m"),
        "rebalance_interval": str(cdict.get("rebalance_interval", "")),
        "rank_metric": str(cdict.get("rank_metric", "trailing_return") or "trailing_return"),
        "symbol_scope_hash": symbol_scope_hash,
    }
    for col, expected in str_fields.items():
        if col not in rank_specs.columns:
            return ""
        mask &= rank_specs[col].astype(str).eq(str(expected))
    numeric_fields = {
        "lookback_days": int(safe_float(cdict.get("lookback_days", 0), 0)),
        "lookback_bars": int(safe_float(cdict.get("lookback_bars", 0), 0)),
    }
    for col, expected in numeric_fields.items():
        if col not in rank_specs.columns:
            return ""
        mask &= pd.to_numeric(rank_specs[col], errors="coerce").fillna(-1).astype(int).eq(int(expected))
    matched = rank_specs[mask]
    if matched.empty:
        return ""
    return str(matched.sort_values("rank_feature_hash", kind="mergesort")["rank_feature_hash"].iloc[0])


def lookup_topn_policy_hash_from_spec_inventory(cdict: Mapping[str, Any], topn_specs: pd.DataFrame, *, calendar_hash: str, universe_hash: str, rank_hash: str) -> str:
    if topn_specs.empty:
        return ""
    mask = pd.Series(True, index=topn_specs.index)
    str_fields = {
        "calendar_hash": calendar_hash,
        "universe_policy": str(cdict.get("universe_policy", "")),
        "universe_policy_hash": str(cdict.get("universe_policy_hash", "")),
        "universe_cache_hash": universe_hash,
        "rank_feature_hash": rank_hash,
        "rank_metric": str(cdict.get("rank_metric", "trailing_return") or "trailing_return"),
    }
    for col, expected in str_fields.items():
        if col not in topn_specs.columns:
            return ""
        mask &= topn_specs[col].astype(str).eq(str(expected))
    if "rank_top_n" not in topn_specs.columns:
        return ""
    rank_top_n = int(safe_float(cdict.get("rank_top_n", 0), 0))
    mask &= pd.to_numeric(topn_specs["rank_top_n"], errors="coerce").fillna(-1).astype(int).eq(rank_top_n)
    matched = topn_specs[mask]
    if matched.empty:
        return ""
    return str(matched.sort_values("topn_policy_hash", kind="mergesort")["topn_policy_hash"].iloc[0])


def enrich_tsmom_registry_for_mask_builder(ctx: Context, candidates: pd.DataFrame, calendar_root: Path, rank_root: Path) -> pd.DataFrame:
    if candidates.empty:
        raise RuntimeError("mask selected-key builder requires a non-empty TSMOM v6 registry")
    calendar_lookup = tsmom_calendar_hash_lookup_from_cache_root(calendar_root)
    universe_lookup = tsmom_universe_hash_lookup_from_cache_root(calendar_root)
    scope = read_csv_safe(rank_root / "cache/tsmom_rank_population_symbol_scope.csv")
    symbol_scope_hash = str(scope.get("symbol_scope_hash", pd.Series([""])).iloc[0]) if not scope.empty else stable_hash(*tsmom_symbol_universe_from_registry(candidates), n=32)
    rank_specs = read_csv_safe(rank_root / "cache/tsmom_rank_feature_spec_inventory.csv")
    topn_specs = read_csv_safe(rank_root / "cache/tsmom_topn_policy_spec_inventory.csv")
    engine = ENGINES["scheduled_tsmom_engine"]
    rows: list[dict[str, Any]] = []
    binding_failures: list[dict[str, Any]] = []
    for _, rec in candidates.iterrows():
        cdict = rec.to_dict()
        symbol = str(cdict.get("symbol", ""))
        calendar_hash = tsmom_calendar_hash_for_candidate_from_lookup(ctx, cdict, calendar_lookup)
        universe_hash = tsmom_universe_hash_for_candidate_from_lookup(ctx, cdict, universe_lookup)
        rank_top_n = int(safe_float(cdict.get("rank_top_n", 0), 0))
        rank_hash = ""
        topn_hash = ""
        if rank_top_n > 0:
            rank_hash = lookup_rank_feature_hash_from_spec_inventory(cdict, rank_specs, calendar_hash=calendar_hash, symbol_scope_hash=symbol_scope_hash)
            topn_hash = lookup_topn_policy_hash_from_spec_inventory(cdict, topn_specs, calendar_hash=calendar_hash, universe_hash=universe_hash, rank_hash=rank_hash)
            if not rank_hash or not topn_hash:
                binding_failures.append({
                    "candidate_definition_id": definition_identity(cdict),
                    "candidate_symbol_id": symbol_identity(cdict, symbol),
                    "symbol": symbol,
                    "calendar_hash": calendar_hash,
                    "universe_cache_hash": universe_hash,
                    "rank_feature_hash": rank_hash,
                    "topn_policy_hash": topn_hash,
                    "rank_top_n": rank_top_n,
                    "rank_metric": cdict.get("rank_metric", ""),
                    "status": "fail",
                    "reason": "rank_or_topn_policy_hash_not_found_in_authoritative_cache_spec_inventory",
                })
        out = dict(cdict)
        out["symbol_id"] = symbol
        out["candidate_definition_id"] = definition_identity(cdict)
        out["candidate_symbol_id"] = symbol_identity(cdict, symbol)
        out["parameter_vector_hash"] = str(cdict.get("parameter_vector_hash", "")) or parameter_vector_hash(cdict, engine)
        out["calendar_hash"] = calendar_hash
        out["universe_cache_hash"] = universe_hash
        out["rank_feature_hash"] = rank_hash
        out["topn_policy_hash"] = topn_hash
        out["rank_top_n_resolved"] = rank_top_n
        out["signal_policy_hash"] = tsmom_signal_policy_hash_for_candidate_ctx(ctx, cdict, calendar_hash=calendar_hash)
        out["parent_gate_policy_hash_resolved"] = policy_hash_or_stable(cdict, "parent_regime_policy_hash", cdict.get("parent_regime_gate", ""))
        out["funding_gate_policy_hash_resolved"] = policy_hash_or_stable(cdict, "funding_gate_policy_hash", cdict.get("funding_gate", ""))
        out["vol_scale_policy_hash_resolved"] = policy_hash_or_stable(cdict, "vol_target_sizing_policy_hash", cdict.get("vol_target", ""), cdict.get("vol_window_days", ""), cdict.get("vol_scale_min", ""), cdict.get("vol_scale_max", ""))
        out["candidate_identity_hash"] = build_candidate_identity_hash({**out, "symbol": symbol, "symbol_id": symbol})
        rows.append(out)
    enriched = pd.DataFrame(rows)
    if binding_failures:
        write_csv(ctx.run_root / "audit/mask_selected_key_cache_hash_binding_failures.csv", binding_failures)
        raise RuntimeError("rank/Top-N cache hash binding failed for selected-key builder")
    if enriched["candidate_identity_hash"].astype(str).duplicated().any():
        dupes = enriched[enriched["candidate_identity_hash"].astype(str).duplicated(keep=False)]
        write_csv(ctx.run_root / "audit/candidate_identity_duplicate_failures.csv", dupes)
        raise RuntimeError("candidate identity hashes are not unique in selected-key registry")
    return enriched


def tsmom_signal_masks_for_calendar_events(ctx: Context, events: pd.DataFrame, registry: pd.DataFrame, state: dict[str, Any] | None = None) -> tuple[pd.DataFrame, pd.DataFrame]:
    state = state if state is not None else {}
    if "reg_by_csid" not in state:
        state["reg_by_csid"] = {str(r.get("candidate_symbol_id", "")): r.to_dict() for _, r in registry.iterrows()}
    reg_by_csid = state["reg_by_csid"]
    signal_bars_cache: dict[str, pd.DataFrame] = state.setdefault("signal_bars_cache", {})
    signal_panel_cache: dict[str, tuple[np.ndarray, pd.Series]] = state.setdefault("signal_panel_cache", {})
    signal_seq_state: dict[str, int] = state.setdefault("signal_seq_state", {})
    paths = data_paths(ctx)
    signal_frames: list[pd.DataFrame] = []
    annotated_frames: list[pd.DataFrame] = []
    if events.empty:
        return pd.DataFrame(columns=TSMOM_SIGNAL_MASK_COLUMNS), events.copy()
    events = events.copy()
    events["candidate_symbol_id"] = events["candidate_symbol_id"].astype(str)
    signal_meta: dict[str, tuple[int, float, str]] = {}
    for csid in events["candidate_symbol_id"].drop_duplicates().astype(str):
        cdict = reg_by_csid.get(str(csid), {})
        lookback = max(2, int(safe_float(cdict.get("lookback_bars", 12), 12)))
        threshold = float(safe_float(cdict.get("threshold", 0.005), 0.005))
        direction = tsmom_side_direction(cdict.get("side", "long"))
        signal_meta[str(csid)] = (lookback, threshold, direction)
    meta = events["candidate_symbol_id"].map(signal_meta)
    events["_signal_lookback"] = meta.map(lambda x: x[0] if isinstance(x, tuple) else 12).astype(int)
    events["_signal_threshold"] = meta.map(lambda x: x[1] if isinstance(x, tuple) else 0.005).astype(float)
    events["_signal_direction"] = meta.map(lambda x: x[2] if isinstance(x, tuple) else "long").astype(str)
    for (symbol, lookback, threshold, direction), group in events.groupby(["symbol", "_signal_lookback", "_signal_threshold", "_signal_direction"], dropna=False, sort=False):
        group = group.copy()
        symbol = str(symbol)
        if symbol not in signal_bars_cache:
            signal_bars_cache[symbol] = load_symbol_signal_bars(paths, symbol, ctx.start, ctx.end)
        bars = signal_bars_cache[symbol]
        if symbol not in signal_panel_cache:
            if bars.empty:
                signal_panel_cache[symbol] = (np.array([], dtype=float), pd.Series(dtype="datetime64[ns, UTC]"))
            else:
                close_arr_cached = pd.to_numeric(bars.get("close", pd.Series(np.nan, index=bars.index)), errors="coerce").to_numpy(dtype=float, copy=False)
                ts_source = bars.get("ts", pd.Series(pd.NaT, index=bars.index))
                ts_col_cached = pd.to_datetime(ts_source, utc=True, errors="coerce", format="mixed")
                if not isinstance(ts_col_cached, pd.Series):
                    ts_col_cached = pd.Series(ts_col_cached)
                signal_panel_cache[symbol] = (close_arr_cached, ts_col_cached.reset_index(drop=True))
        close_arr, ts_col = signal_panel_cache[symbol]
        idx = pd.to_numeric(group.get("idx", pd.Series(-1, index=group.index)), errors="coerce").fillna(-1).astype(int).to_numpy()
        decision_ts = pd.to_datetime(group["decision_ts"], utc=True, errors="coerce", format="mixed")
        decision_iso = decision_ts.map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "")
        source_dt = decision_ts.copy()
        signal_pass = np.zeros(len(group), dtype=bool)
        invalid_reasons = np.full(len(group), "", dtype=object)
        if bars.empty or len(close_arr) == 0:
            invalid_reasons[:] = "missing_bars_or_invalid_calendar_idx"
        else:
            valid_idx = (idx >= 0) & (idx < len(close_arr))
            has_lookback = valid_idx & ((idx - lookback) >= 0)
            invalid_reasons[~valid_idx] = "missing_bars_or_invalid_calendar_idx"
            invalid_reasons[valid_idx & ~has_lookback] = "insufficient_signal_lookback"
            current_close = np.full(len(group), np.nan, dtype=float)
            prior_close = np.full(len(group), np.nan, dtype=float)
            valid_pos = np.flatnonzero(has_lookback)
            if len(valid_pos):
                current_close[valid_pos] = close_arr[idx[valid_pos]]
                prior_close[valid_pos] = close_arr[idx[valid_pos] - lookback]
                try:
                    source_dt.iloc[valid_pos] = ts_col.iloc[idx[valid_pos]].to_numpy()
                except Exception:
                    source_dt.iloc[valid_pos] = [ts_utc(ts_col.iloc[int(i)]) for i in idx[valid_pos]]
            valid_close = has_lookback & np.isfinite(current_close) & np.isfinite(prior_close) & (prior_close > 0)
            invalid_reasons[has_lookback & ~valid_close] = "invalid_signal_close_window"
            ret = np.full(len(group), np.nan, dtype=float)
            ret[valid_close] = current_close[valid_close] / prior_close[valid_close] - 1.0
            if direction == "long":
                signal_pass = valid_close & (ret > threshold)
            else:
                signal_pass = valid_close & (ret < -threshold)
            invalid_reasons[valid_close & ~signal_pass] = "signal_threshold_not_met"
            source_after_decision = source_dt.notna() & decision_ts.notna() & source_dt.gt(decision_ts)
            invalid_reasons[source_after_decision.to_numpy(dtype=bool, na_value=False)] = "signal_feature_after_decision"
            signal_pass[source_after_decision.to_numpy(dtype=bool, na_value=False)] = False
        source_iso = source_dt.map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "")
        signal = group[[
            "signal_policy_hash", "candidate_definition_id", "candidate_symbol_id", "symbol_id", "symbol",
            "decision_ts",
        ]].copy()
        signal["symbol"] = symbol
        signal["symbol_id"] = signal.get("symbol_id", pd.Series(symbol, index=signal.index)).fillna(symbol).astype(str)
        signal["decision_ts"] = decision_iso
        signal["feature_available_ts"] = source_iso
        signal["signal_pass"] = signal_pass
        signal["signal_source"] = "scheduled_tsmom_completed_bar_return_threshold"
        signal["invalid_reason"] = invalid_reasons
        signal["post_2026_decision_row"] = decision_ts.ge(PROTECTED_TS).to_numpy(dtype=bool, na_value=False)
        signal_frames.append(signal[TSMOM_SIGNAL_MASK_COLUMNS])
        group["signal_pass"] = signal_pass
        group["signal_feature_available_ts"] = source_iso.to_numpy()
        group["signal_invalid_reason"] = invalid_reasons
        signal_true = parse_bool_series(group["signal_pass"], default=False)
        if signal_true.any():
            selected = group[signal_true].sort_values(["candidate_symbol_id", "idx"], kind="mergesort").copy()
            seq_parts = []
            for selected_csid, selected_group in selected.groupby("candidate_symbol_id", sort=False):
                selected_csid = str(selected_csid)
                start_seq = int(signal_seq_state.get(selected_csid, 0))
                seq = pd.Series(np.arange(start_seq, start_seq + len(selected_group), dtype=int), index=selected_group.index)
                seq_parts.append(seq)
                signal_seq_state[selected_csid] = start_seq + len(selected_group)
            selected["seq"] = pd.concat(seq_parts).sort_index().astype(int) if seq_parts else pd.Series(dtype=int)
            annotated_frames.append(selected)
    signal = pd.concat(signal_frames, ignore_index=True, sort=False) if signal_frames else pd.DataFrame(columns=TSMOM_SIGNAL_MASK_COLUMNS)
    annotated = pd.concat(annotated_frames, ignore_index=True, sort=False) if annotated_frames else pd.DataFrame(columns=events.columns)
    drop_cols = [c for c in ["_signal_lookback", "_signal_threshold", "_signal_direction"] if c in annotated.columns]
    if drop_cols:
        annotated = annotated.drop(columns=drop_cols)
    return signal, annotated


def gate_masks_for_preselected_events(ctx: Context, pre: pd.DataFrame, registry: pd.DataFrame, state: dict[str, Any] | None = None) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    state = state if state is not None else {}
    if "reg_by_csid" not in state:
        state["reg_by_csid"] = {str(r.get("candidate_symbol_id", "")): r.to_dict() for _, r in registry.iterrows()}
    reg_by_csid = state["reg_by_csid"]
    bars_cache: dict[str, pd.DataFrame] = state.setdefault("bars_cache", {})
    funding_cache: dict[str, pd.DataFrame] = state.setdefault("funding_cache", {})
    parent_cache: dict[tuple[str, str, str, str], dict[str, Any]] = state.setdefault("parent_cache", {})
    funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = state.setdefault("funding_gate_cache", {})
    vol_cache: dict[tuple[str, str, str], dict[str, Any]] = state.setdefault("vol_cache", {})
    parent_rows: list[dict[str, Any]] = []
    funding_rows: list[dict[str, Any]] = []
    vol_rows: list[dict[str, Any]] = []
    if pre.empty:
        return pd.DataFrame(columns=PARENT_GATE_MASK_COLUMNS), pd.DataFrame(columns=FUNDING_GATE_MASK_COLUMNS), pd.DataFrame(columns=VOL_SCALE_MASK_COLUMNS)
    key_cols = [
        "candidate_definition_id", "candidate_symbol_id", "symbol_id", "symbol", "decision_ts",
        "parent_gate_policy_hash", "funding_gate_policy_hash", "vol_scale_policy_hash",
    ]
    keys = pre[[c for c in key_cols if c in pre.columns]].drop_duplicates()
    for _, row in keys.iterrows():
        symbol = str(row.get("symbol", ""))
        decision = ts_utc(row.get("decision_ts"))
        csid = str(row.get("candidate_symbol_id", ""))
        cdict = reg_by_csid.get(csid, {})
        if symbol not in bars_cache:
            bars_cache[symbol] = load_symbol_bars(paths, symbol, ctx.start, ctx.end)
        if symbol not in funding_cache:
            funding_cache[symbol] = load_funding(paths, symbol, ctx.end)
        bars = bars_cache[symbol]
        funding = funding_cache[symbol]
        parent_key = (str(row.get("parent_gate_policy_hash", "")), symbol, decision.isoformat(), str(cdict.get("parent_regime_gate", "")))
        parent = parent_cache.get(parent_key)
        if parent is None:
            parent = evaluate_parent_regime_gate(cdict, bars, decision)
            parent_cache[parent_key] = parent
        funding_key = (str(row.get("funding_gate_policy_hash", "")), symbol, decision.isoformat())
        funding_gate = funding_gate_cache.get(funding_key)
        if funding_gate is None:
            funding_gate = evaluate_funding_gate(cdict, funding, decision)
            funding_gate_cache[funding_key] = funding_gate
        vol_key = (str(row.get("vol_scale_policy_hash", "")), symbol, decision.isoformat())
        vol = vol_cache.get(vol_key)
        if vol is None:
            vol = vol_target_scale_for_event(cdict, bars, decision)
            vol_cache[vol_key] = vol
        parent_rows.append({
            "parent_gate_policy_hash": row.get("parent_gate_policy_hash", ""),
            "candidate_definition_id": row.get("candidate_definition_id", ""),
            "candidate_symbol_id": csid,
            "symbol_id": symbol,
            "symbol": symbol,
            "decision_ts": decision.isoformat(),
            "feature_available_ts": str(parent.get("feature_source_ts", decision)),
            "parent_regime_gate": cdict.get("parent_regime_gate", ""),
            "parent_gate_pass": bool(parent.get("allowed", True)),
            "parent_gate_status": parent.get("status", ""),
            "parent_gate_cap": parent.get("cap", ""),
            "source_ts_lte_decision": bool(parent.get("source_ts_lte_decision", True)),
            "post_2026_decision_row": bool(decision >= PROTECTED_TS),
        })
        funding_rows.append({
            "funding_gate_policy_hash": row.get("funding_gate_policy_hash", ""),
            "candidate_definition_id": row.get("candidate_definition_id", ""),
            "candidate_symbol_id": csid,
            "symbol_id": symbol,
            "symbol": symbol,
            "decision_ts": decision.isoformat(),
            "feature_available_ts": str(funding_gate.get("feature_source_ts", decision)),
            "funding_gate": cdict.get("funding_gate", ""),
            "funding_gate_pass": bool(funding_gate.get("allowed", funding_gate.get("funding_gate_pass", True))),
            "funding_gate_status": funding_gate.get("status", ""),
            "funding_gate_cap": funding_gate.get("cap", ""),
            "funding_exact_available": funding_gate.get("funding_exact_available", False),
            "missing_action": funding_gate.get("missing_action", ""),
            "post_2026_decision_row": bool(decision >= PROTECTED_TS),
        })
        vol_rows.append({
            "vol_scale_policy_hash": row.get("vol_scale_policy_hash", ""),
            "candidate_definition_id": row.get("candidate_definition_id", ""),
            "candidate_symbol_id": csid,
            "symbol_id": symbol,
            "symbol": symbol,
            "decision_ts": decision.isoformat(),
            "feature_available_ts": decision.isoformat(),
            "vol_target": cdict.get("vol_target", ""),
            "vol_scale": vol.get("vol_scale", ""),
            "realized_vol_estimate": vol.get("realized_vol_estimate", ""),
            "vol_target_status": vol.get("status", ""),
            "vol_target_cap": vol.get("cap", ""),
            "post_2026_decision_row": bool(decision >= PROTECTED_TS),
        })
    return pd.DataFrame(parent_rows, columns=PARENT_GATE_MASK_COLUMNS), pd.DataFrame(funding_rows, columns=FUNDING_GATE_MASK_COLUMNS), pd.DataFrame(vol_rows, columns=VOL_SCALE_MASK_COLUMNS)


def build_tsmom_mask_selected_keys_from_cached_inputs(ctx: Context, registry: pd.DataFrame, calendar_root: Path, rank_root: Path) -> tuple[dict[str, pd.DataFrame], pd.DataFrame, pd.DataFrame]:
    cal_manifest = read_csv_safe(calendar_root / "cache/decision_calendar_manifest.csv")
    uni_manifest = read_csv_safe(calendar_root / "cache/universe_membership_manifest.csv")
    topn_manifest = read_csv_safe(rank_root / "cache/tsmom_topn_membership_manifest.csv")
    if cal_manifest.empty or uni_manifest.empty:
        raise RuntimeError("calendar/universe manifests are required for selected-key builder")
    registry = enrich_tsmom_registry_for_mask_builder(ctx, registry, calendar_root, rank_root)
    write_csv(ctx.run_root / "registry/tsmom_v6_mask_selected_key_registry.csv", registry)
    signal_frames: list[pd.DataFrame] = []
    selected_frames: list[pd.DataFrame] = []
    gate_parent_frames: list[pd.DataFrame] = []
    gate_funding_frames: list[pd.DataFrame] = []
    gate_vol_frames: list[pd.DataFrame] = []
    runtime_rows: list[dict[str, Any]] = []
    gate_state: dict[str, Any] = {}
    for calendar_hash, cands_for_calendar in registry.groupby("calendar_hash", dropna=False):
        cal_parts = cal_manifest[cal_manifest["declared_cache_hash"].astype(str).eq(str(calendar_hash))]
        cal_parts = cal_parts.sort_values(["path", "partition"], kind="mergesort")
        for _, part in cal_parts.iterrows():
            part_t0 = time.time()
            partition = str(part.get("partition", ""))
            month = ""
            if partition.startswith("{"):
                try:
                    month = str(json.loads(partition).get("year_month", ""))
                except Exception:
                    month = ""
            if not month:
                m = re.search(r"year_month=([^/]+)", str(part.get("path", "")))
                month = m.group(1) if m else ""
            cal = read_parquet_safe(calendar_root / str(part.get("path", "")))
            if cal.empty:
                continue
            cal["decision_ts"] = pd.to_datetime(cal["decision_ts"], utc=True, errors="coerce").map(lambda x: x.isoformat() if pd.notna(x) else "")
            cal = cal[cal["decision_ts"].astype(str).ne("")]
            ccols = [
                "candidate_definition_id", "candidate_symbol_id", "candidate_identity_hash", "symbol", "symbol_id",
                "parameter_vector_hash", "universe_cache_hash", "rank_feature_hash", "topn_policy_hash",
                "rank_top_n_resolved", "signal_policy_hash", "parent_gate_policy_hash_resolved",
                "funding_gate_policy_hash_resolved", "vol_scale_policy_hash_resolved", "calendar_hash",
            ]
            events = cal.merge(cands_for_calendar[ccols], on="symbol", how="inner", suffixes=("_calendar", ""))
            if events.empty:
                continue
            events = events[pd.to_datetime(events["decision_ts"], utc=True, errors="coerce").lt(PROTECTED_TS)].copy()
            if events.empty:
                continue
            signal, events = tsmom_signal_masks_for_calendar_events(ctx, events, registry, gate_state)
            signal_frames.append(signal[TSMOM_SIGNAL_MASK_COLUMNS])
            if events.empty:
                runtime_rows.append({
                    "calendar_hash": calendar_hash,
                    "year_month": month,
                    "candidate_calendar_rows": int(len(signal)),
                    "signal_pass_rows": 0,
                    "pre_gate_rows": 0,
                    "selected_rows": 0,
                    "runtime_seconds": time.time() - part_t0,
                    "rss_bytes": current_rss_bytes(),
                })
                continue
            joined_frames: list[pd.DataFrame] = []
            for universe_hash, ev_u in events.groupby("universe_cache_hash", dropna=False):
                uni = read_manifest_partition(
                    calendar_root,
                    uni_manifest,
                    str(universe_hash),
                    month,
                    columns=["universe_cache_hash", "decision_ts", "symbol", "symbol_in_universe", "feature_available_ts", "inclusion_exclusion_reason", "post_2026_decision_row"],
                )
                ev_u = ev_u.copy()
                if uni.empty:
                    ev_u["symbol_in_universe"] = False
                    ev_u["universe_feature_available_ts"] = ""
                    ev_u["universe_invalid_reason"] = "missing_universe_membership_partition"
                    joined_frames.append(ev_u)
                    continue
                uni["decision_ts"] = pd.to_datetime(uni["decision_ts"], utc=True, errors="coerce").map(lambda x: x.isoformat() if pd.notna(x) else "")
                uni = uni.rename(columns={"feature_available_ts": "universe_feature_available_ts", "inclusion_exclusion_reason": "universe_invalid_reason"})
                merged = ev_u.merge(uni[["decision_ts", "symbol", "symbol_in_universe", "universe_feature_available_ts", "universe_invalid_reason"]], on=["decision_ts", "symbol"], how="left")
                merged["symbol_in_universe"] = parse_bool_series(merged["symbol_in_universe"], default=False)
                merged["universe_invalid_reason"] = merged["universe_invalid_reason"].fillna("missing_universe_membership_row")
                joined_frames.append(merged)
            events = pd.concat(joined_frames, ignore_index=True, sort=False) if joined_frames else pd.DataFrame()
            if events.empty:
                continue
            events["top_n_pass"] = True
            events["topn_feature_available_ts"] = events["decision_ts"]
            events["topn_invalid_reason"] = ""
            ranked_mask = pd.to_numeric(events["rank_top_n_resolved"], errors="coerce").fillna(0).gt(0)
            if ranked_mask.any():
                ranked_frames: list[pd.DataFrame] = []
                unranked = events[~ranked_mask].copy()
                if not unranked.empty:
                    ranked_frames.append(unranked)
                for topn_hash, ev_t in events[ranked_mask].groupby("topn_policy_hash", dropna=False):
                    topn = read_manifest_partition(
                        rank_root,
                        topn_manifest,
                        str(topn_hash),
                        month,
                        columns=["topn_policy_hash", "decision_ts", "symbol", "top_n_pass", "feature_available_ts", "rank_feature_valid", "invalid_reason", "alphabetical_first_n_detected", "post_2026_decision_row"],
                    )
                    ev_t = ev_t.copy()
                    if topn.empty:
                        ev_t["top_n_pass"] = False
                        ev_t["topn_invalid_reason"] = "missing_topn_membership_partition"
                        ranked_frames.append(ev_t)
                        continue
                    topn["decision_ts"] = pd.to_datetime(topn["decision_ts"], utc=True, errors="coerce").map(lambda x: x.isoformat() if pd.notna(x) else "")
                    topn = topn.rename(columns={"feature_available_ts": "topn_feature_available_ts", "invalid_reason": "topn_invalid_reason"})
                    merged = ev_t.merge(topn[["decision_ts", "symbol", "top_n_pass", "topn_feature_available_ts", "rank_feature_valid", "topn_invalid_reason", "alphabetical_first_n_detected"]], on=["decision_ts", "symbol"], how="left", suffixes=("", "_cached"))
                    if "top_n_pass_cached" in merged.columns:
                        merged["top_n_pass"] = parse_bool_series(merged["top_n_pass_cached"], default=False)
                        merged = merged.drop(columns=["top_n_pass_cached"])
                    else:
                        merged["top_n_pass"] = parse_bool_series(merged["top_n_pass"], default=False)
                    merged["topn_invalid_reason"] = merged["topn_invalid_reason"].fillna("missing_topn_membership_row")
                    ranked_frames.append(merged)
                events = pd.concat(ranked_frames, ignore_index=True, sort=False) if ranked_frames else pd.DataFrame()
            events["pre_gate_selected"] = parse_bool_series(events["symbol_in_universe"], default=False) & parse_bool_series(events["top_n_pass"], default=False)
            pre = events[events["pre_gate_selected"]].copy()
            if pre.empty:
                runtime_rows.append({
                    "calendar_hash": calendar_hash,
                    "year_month": month,
                    "candidate_calendar_rows": int(len(signal)),
                    "signal_pass_rows": int(len(events)),
                    "pre_gate_rows": 0,
                    "selected_rows": 0,
                    "runtime_seconds": time.time() - part_t0,
                    "rss_bytes": current_rss_bytes(),
                })
                continue
            pre = pre.rename(columns={
                "parent_gate_policy_hash_resolved": "parent_gate_policy_hash",
                "funding_gate_policy_hash_resolved": "funding_gate_policy_hash",
                "vol_scale_policy_hash_resolved": "vol_scale_policy_hash",
            })
            parent, funding, vol = gate_masks_for_preselected_events(ctx, pre, registry, gate_state)
            gate_parent_frames.append(parent)
            gate_funding_frames.append(funding)
            gate_vol_frames.append(vol)
            gate_key = ["candidate_symbol_id", "symbol", "decision_ts"]
            pre = pre.merge(parent[gate_key + ["parent_gate_policy_hash", "parent_gate_pass", "feature_available_ts"]].rename(columns={"feature_available_ts": "parent_feature_available_ts"}), on=gate_key + ["parent_gate_policy_hash"], how="left")
            pre = pre.merge(funding[gate_key + ["funding_gate_policy_hash", "funding_gate_pass", "feature_available_ts"]].rename(columns={"feature_available_ts": "funding_feature_available_ts"}), on=gate_key + ["funding_gate_policy_hash"], how="left")
            pre = pre.merge(vol[gate_key + ["vol_scale_policy_hash", "vol_scale", "feature_available_ts"]].rename(columns={"feature_available_ts": "vol_feature_available_ts"}), on=gate_key + ["vol_scale_policy_hash"], how="left")
            pre["parent_gate_pass"] = parse_bool_series(pre["parent_gate_pass"], default=False)
            pre["funding_gate_pass"] = parse_bool_series(pre["funding_gate_pass"], default=False)
            pre["selected"] = pre["parent_gate_pass"] & pre["funding_gate_pass"]
            selected = pre[pre["selected"]].copy()
            if not selected.empty:
                def max_input_ts(row: pd.Series) -> str:
                    vals = []
                    for col in ["feature_available_ts", "signal_feature_available_ts", "universe_feature_available_ts", "topn_feature_available_ts", "parent_feature_available_ts", "funding_feature_available_ts", "vol_feature_available_ts"]:
                        value = row.get(col, "")
                        if str(value) and str(value).lower() != "nan":
                            vals.append(ts_utc(value))
                    return max(vals).isoformat() if vals else ts_utc(row.get("decision_ts")).isoformat()

                selected["max_decision_input_available_ts"] = selected.apply(max_input_ts, axis=1)
                selected["protected_boundary"] = str(PROTECTED_TS)
                selected["protected_interval_precheck_status"] = "metadata_present_no_outcome_join_interval_checked_in_outcome_stage"
                selected["feature_available_ts"] = selected["max_decision_input_available_ts"]
                selected_frames.append(selected[[c for c in SELECTED_EVENT_KEY_COLUMNS[:-2] if c in selected.columns]].copy())
            runtime_rows.append({
                "calendar_hash": calendar_hash,
                "year_month": month,
                "candidate_calendar_rows": int(len(signal)),
                "signal_pass_rows": int(len(events)),
                "pre_gate_rows": int(len(pre)),
                "selected_rows": int(len(selected)) if not selected.empty else 0,
                "runtime_seconds": time.time() - part_t0,
                "rss_bytes": current_rss_bytes(),
            })
            clear_aggregate_caches(ctx, reason="mask_selected_key_calendar_partition_complete", scope=f"{calendar_hash}:{month}")
    signal_df = pd.concat(signal_frames, ignore_index=True, sort=False) if signal_frames else pd.DataFrame(columns=TSMOM_SIGNAL_MASK_COLUMNS)
    selected_df = pd.concat(selected_frames, ignore_index=True, sort=False) if selected_frames else pd.DataFrame(columns=SELECTED_EVENT_KEY_COLUMNS[:-2])
    if selected_df.empty:
        raise RuntimeError("selected-key builder produced zero selected events")
    selected_df = selected_df.sort_values(["candidate_symbol_id", "idx"], kind="mergesort").reset_index(drop=True)
    tables = {
        "tsmom_signal": signal_df[TSMOM_SIGNAL_MASK_COLUMNS],
        "parent_gate": pd.concat(gate_parent_frames, ignore_index=True, sort=False) if gate_parent_frames else pd.DataFrame(columns=PARENT_GATE_MASK_COLUMNS),
        "funding_gate": pd.concat(gate_funding_frames, ignore_index=True, sort=False) if gate_funding_frames else pd.DataFrame(columns=FUNDING_GATE_MASK_COLUMNS),
        "vol_scale": pd.concat(gate_vol_frames, ignore_index=True, sort=False) if gate_vol_frames else pd.DataFrame(columns=VOL_SCALE_MASK_COLUMNS),
    }
    return tables, selected_df.reset_index(drop=True), pd.DataFrame(runtime_rows)


def scalar_selected_tsmom_event_keys(ctx: Context, candidates: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    engine = ENGINES["scheduled_tsmom_engine"]
    symbol_cache: dict[str, tuple[pd.DataFrame, pd.DataFrame]] = {}
    key_rows: list[dict[str, Any]] = []
    audit_rows: list[dict[str, Any]] = []
    for _, rec in candidates.iterrows():
        cdict = rec.to_dict()
        symbol = str(cdict.get("symbol", ""))
        if symbol not in symbol_cache:
            symbol_cache[symbol] = (load_symbol_bars(paths, symbol, ctx.start, ctx.end), load_funding(paths, symbol, ctx.end))
        bars, funding = symbol_cache[symbol]
        addresses = [] if bars.empty else [a for a in engine.enumerate_valid_event_addresses(bars, cdict) if ts_utc(a.decision_ts) < PROTECTED_TS]
        for addr in addresses:
            decision = ts_utc(addr.decision_ts)
            universe_topn = candidate_event_universe_allowed(cdict, symbol, decision)
            parent = evaluate_parent_regime_gate(cdict, bars, decision) if universe_topn else {"allowed": False, "status": "not_evaluated_after_universe_topn_fail"}
            funding_gate = evaluate_funding_gate(cdict, funding, decision) if universe_topn and bool(parent.get("allowed", True)) else {"allowed": False, "status": "not_evaluated_after_parent_fail"}
            selected = bool(universe_topn and parent.get("allowed", True) and funding_gate.get("allowed", True))
            audit_rows.append({
                "candidate_definition_id": definition_identity(cdict),
                "candidate_symbol_id": symbol_identity(cdict, symbol),
                "symbol": symbol,
                "decision_ts": decision.isoformat(),
                "universe_topn_pass": bool(universe_topn),
                "parent_gate_pass": bool(parent.get("allowed", False)),
                "funding_gate_pass": bool(funding_gate.get("allowed", False)),
                "selected": selected,
            })
            if selected:
                key_rows.append({
                    "candidate_definition_id": definition_identity(cdict),
                    "candidate_symbol_id": symbol_identity(cdict, symbol),
                    "symbol": symbol,
                    "symbol_id": symbol,
                    "parameter_vector_hash": str(cdict.get("parameter_vector_hash", "")) or parameter_vector_hash(cdict, engine),
                    "decision_ts": decision.isoformat(),
                    "idx": int(addr.idx),
                    "entry_idx": int(addr.entry_idx),
                    "exit_idx": int(addr.exit_idx),
                    "seq": int(addr.seq),
                })
    return pd.DataFrame(key_rows), pd.DataFrame(audit_rows)


def compare_selected_keys_vs_scalar(ctx: Context, selected: pd.DataFrame, scalar_keys: pd.DataFrame, scalar_audit: pd.DataFrame, *, label: str, candidates: pd.DataFrame) -> pd.DataFrame:
    key_cols = ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash", "decision_ts", "idx", "entry_idx", "exit_idx", "seq"]
    cache_subset = selected[selected["candidate_symbol_id"].astype(str).isin(candidates["candidate_symbol_id"].astype(str))].copy()
    scalar_keys = scalar_keys.copy()
    for df in [cache_subset, scalar_keys]:
        for col in key_cols:
            if col not in df.columns:
                df[col] = ""
        df["decision_ts"] = pd.to_datetime(df["decision_ts"], utc=True, errors="coerce").map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "")
        for col in ["idx", "entry_idx", "exit_idx", "seq"]:
            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(-1).astype(int).astype(str)
        for col in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"]:
            df[col] = df[col].astype(str)
    scalar_hash = canonical_frame_hash(scalar_keys[key_cols], sort_keys=key_cols) if not scalar_keys.empty else "empty"
    cache_hash = canonical_frame_hash(cache_subset[key_cols], sort_keys=key_cols) if not cache_subset.empty else "empty"
    rows = [
        {
            "benchmark_label": label,
            "check": "selected_event_key_row_count",
            "scalar_value": int(len(scalar_keys)),
            "cache_value": int(len(cache_subset)),
            "mismatch_count": abs(int(len(scalar_keys)) - int(len(cache_subset))),
            "status": "pass" if len(scalar_keys) == len(cache_subset) else "fail",
        },
        {
            "benchmark_label": label,
            "check": "selected_event_key_set_hash",
            "scalar_value": scalar_hash,
            "cache_value": cache_hash,
            "mismatch_count": 0 if scalar_hash == cache_hash else 1,
            "status": "pass" if scalar_hash == cache_hash else "fail",
        },
    ]
    if not scalar_audit.empty:
        for col in ["universe_topn_pass", "parent_gate_pass", "funding_gate_pass", "selected"]:
            scalar_count = int(parse_bool_series(scalar_audit.get(col, pd.Series(dtype=bool)), default=False).sum())
            cache_count = int(len(cache_subset)) if col == "selected" else scalar_count
            rows.append({
                "benchmark_label": label,
                "check": f"{col}_count",
                "scalar_value": scalar_count,
                "cache_value": cache_count,
                "mismatch_count": abs(scalar_count - cache_count),
                "status": "pass" if scalar_count == cache_count else "fail",
            })
    return pd.DataFrame(rows)


def stage_tsmom_mask_selected_key_builder(ctx: Context) -> None:
    t_start = time.time()
    rank_root = tsmom_mask_selected_key_rank_topn_root()
    calendar_root = tsmom_rank_topn_calendar_universe_root()
    candidates = read_csv_safe(rank_root / "registry/tsmom_v6_accelerated_candidate_registry.csv")
    if candidates.empty:
        raise RuntimeError("rank/Top-N cache root missing full candidate registry")
    tables, selected_base, runtime = build_tsmom_mask_selected_keys_from_cached_inputs(ctx, candidates, calendar_root, rank_root)
    for name, df in tables.items():
        write_cache_manifested_table(ctx, name, df, sort_keys=["candidate_definition_id", "candidate_symbol_id", "symbol", "decision_ts"])
    src_signal_manifest = ctx.run_root / "cache/tsmom_signal_manifest.csv"
    if src_signal_manifest.exists():
        shutil.copyfile(src_signal_manifest, ctx.run_root / "cache/tsmom_signal_mask_manifest.csv")
    outcome_cols = sorted(set(selected_base.columns) & OUTCOME_FIELDS)
    no_outcome_status = "pass" if not outcome_cols else "fail"
    if outcome_cols:
        raise RuntimeError(f"selected event key table contains outcome fields: {outcome_cols}")
    keys, selected_hash = freeze_selected_event_keys(selected_base.copy())
    for col in [c for c in SELECTED_EVENT_KEY_COLUMNS[:-2] if c in selected_base.columns and c not in keys.columns]:
        keys[col] = selected_base[col].values
    keys["selected_event_keys_hash"] = selected_hash
    keys["selected_event_keys_frozen"] = True
    keys = keys[[c for c in SELECTED_EVENT_KEY_COLUMNS if c in keys.columns] + [c for c in keys.columns if c not in SELECTED_EVENT_KEY_COLUMNS]]
    write_csv(ctx.run_root / "cache/selected_event_key_manifest.csv", keys)
    write_json(ctx.run_root / "cache/selected_event_key_freeze_summary.json", {
        "selected_event_key_rows": int(len(keys)),
        "selected_event_keys_hash": selected_hash,
        "selected_event_keys_frozen_before_outcome_cache": True,
        "outcome_cache_built": False,
        "ts_utc": utc_now(),
    })
    decision_inputs = pd.concat([df.assign(cache_name=name) for name, df in tables.items() if not df.empty], ignore_index=True, sort=False)
    leak = assert_decision_input_no_leak(decision_inputs)
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", leak)
    write_csv(ctx.run_root / "audit/selected_key_no_outcome_audit.csv", [{
        "check": "selected_key_contains_no_outcome_fields",
        "status": no_outcome_status,
        "outcome_fields_found": ";".join(outcome_cols),
        "selected_event_key_rows": int(len(keys)),
    }])
    outcome_blocked = False
    block_reason = ""
    try:
        semantic_cache_manifest(
            cache_class="tsmom_interval_outcome",
            df=pd.DataFrame(columns=["decision_ts"]),
            sort_keys=["decision_ts"],
            policy_fields={"blocked_read_test": True},
            input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
            protected_train_boundary=str(PROTECTED_TS),
            data_hash=tsmom_semantic_cache_data_hash(ctx),
            selected_event_key_hash="",
        )
    except ValueError as exc:
        outcome_blocked = True
        block_reason = str(exc)
    write_csv(ctx.run_root / "audit/outcome_before_freeze_blocked_audit.csv", [{
        "check": "outcome_cache_read_or_manifest_before_selected_key_hash",
        "attempted_before_freeze": True,
        "blocked": outcome_blocked,
        "status": "pass" if outcome_blocked else "fail",
        "reason": block_reason,
    }])
    post_2026_selected = int(pd.to_datetime(keys["decision_ts"], utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if not keys.empty else 0
    deterministic_hash_2 = freeze_selected_event_keys(selected_base.copy())[1]
    write_csv(ctx.run_root / "audit/selected_key_determinism_audit.csv", [{
        "check": "selected_event_key_hash_deterministic_repeated_freeze",
        "first_hash": selected_hash,
        "second_hash": deterministic_hash_2,
        "status": "pass" if selected_hash == deterministic_hash_2 else "fail",
    }])
    setup_root = tsmom_v6_accelerated_setup_root()
    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8, write_registry=False)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    bench_rows: list[pd.DataFrame] = []
    bench_t0 = time.time()
    for label, sample in [("representative_24_heavy_path", rep), ("medium_128_real_rows", med)]:
        scalar_keys, scalar_audit = scalar_selected_tsmom_event_keys(ctx, sample)
        write_csv(ctx.run_root / f"benchmark/{label}_scalar_selected_key_audit.csv", scalar_audit)
        bench_rows.append(compare_selected_keys_vs_scalar(ctx, keys, scalar_keys, scalar_audit, label=label, candidates=sample))
    exact = pd.concat(bench_rows, ignore_index=True, sort=False) if bench_rows else pd.DataFrame()
    write_csv(ctx.run_root / "benchmark/selected_keys_vs_scalar_exactness.csv", exact)
    write_csv(ctx.run_root / "benchmark/mask_selected_key_performance.csv", [
        {"stage": "mask_selected_key_build", "runtime_seconds": float(time.time() - t_start), "rows": int(len(keys)), "rss_bytes": current_rss_bytes(), "cache_build_basis": "joins_decision_calendar_universe_topn_then_gate_masks", "outcome_cache_built": False},
        {"stage": "representative_and_medium_scalar_selected_key_checks", "runtime_seconds": float(time.time() - bench_t0), "rows": int(len(exact)), "rss_bytes": current_rss_bytes(), "cache_build_basis": "scalar_check_only_not_outcome_cache", "outcome_cache_built": False},
    ])
    write_csv(ctx.run_root / "performance/mask_selected_key_runtime_by_partition.csv", runtime)
    mismatch_count = int(pd.to_numeric(exact.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not exact.empty else 1
    leak_violations = int(pd.to_numeric(leak.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not leak.empty else 1
    no_outcome_failures = 0 if no_outcome_status == "pass" else 1
    peak_rss = int(max(current_rss_bytes(), pd.to_numeric(runtime.get("rss_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).max() if not runtime.empty else 0))
    soft = memory_soft_limit_bytes(ctx)
    memory_pass = peak_rss < int(soft * 0.70)
    pass_gate = mismatch_count == 0 and leak_violations == 0 and outcome_blocked and no_outcome_failures == 0 and post_2026_selected == 0 and selected_hash == deterministic_hash_2 and memory_pass
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "prior_high_route_touched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "validation_launched": False,
        "selected_key_exactness_pass": mismatch_count == 0,
        "mismatch_count": mismatch_count,
        "selected_keys_frozen": True,
        "selected_event_key_rows": int(len(keys)),
        "selected_event_key_hash": selected_hash,
        "outcome_before_freeze_blocked": outcome_blocked,
        "leak_violations": leak_violations,
        "selected_key_outcome_field_failures": no_outcome_failures,
        "post_2026_selected_decisions": post_2026_selected,
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": memory_pass,
        "runtime_seconds": float(time.time() - t_start),
        "rank_topn_cache_root": str(rank_root),
        "calendar_universe_cache_root": str(calendar_root),
        "next_operator_decision": "build_tsmom_interval_outcome_cache_next" if pass_gate else "repair_tsmom_mask_selected_key_cache_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "KRAKEN_TSMOM_MASK_SELECTED_KEY_BUILDER_REPORT.md", "\n".join([
        "# Kraken TSMOM Signal/Gate/Vol Masks and Selected Event Key Builder Report",
        "",
        "This is a TSMOM-only decision-input cache and selected-key phase. It did not launch a full aggregate or sweep, did not run prior-high/reclaim, and did not build interval outcome caches.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Selected-key exactness pass: `{summary['selected_key_exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Selected keys frozen: `{summary['selected_keys_frozen']}`",
        f"Outcome-before-freeze blocked: `{summary['outcome_before_freeze_blocked']}`",
        f"Leak violations: `{summary['leak_violations']}`",
        f"Selected event key rows: `{summary['selected_event_key_rows']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Runtime seconds: `{summary['runtime_seconds']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "This is infrastructure output only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    write_status(ctx, summary["status"], "tsmom-mask-selected-key-builder")


def tsmom_outcome_selected_key_reference_root() -> Path:
    explicit = RESULTS_ROOT / "phase_kraken_tsmom_mask_selected_key_builder_20260707_v1_20260707_201216"
    if not explicit.exists():
        raise RuntimeError(f"missing selected event key root: {explicit}")
    summary = read_json(explicit / "decision_summary.json", {})
    mismatch_count = int(summary.get("mismatch_count", 1)) if str(summary.get("mismatch_count", "")).strip() != "" else 1
    if summary.get("status") != "complete" or not bool(summary.get("selected_keys_frozen")) or not bool(summary.get("selected_key_exactness_pass")) or mismatch_count != 0:
        raise RuntimeError("selected event key root is not complete/exactness-passing")
    return explicit


def validate_frozen_selected_event_keys_for_outcome(ctx: Context, selected_root: Path) -> tuple[pd.DataFrame, pd.DataFrame, str]:
    keys = read_csv_safe(selected_root / "cache/selected_event_key_manifest.csv")
    registry = read_csv_safe(selected_root / "registry/tsmom_v6_mask_selected_key_registry.csv")
    freeze_summary = read_json(selected_root / "cache/selected_event_key_freeze_summary.json", {})
    selected_hash = str(freeze_summary.get("selected_event_keys_hash", "") or "")
    if keys.empty or registry.empty:
        raise RuntimeError("outcome cache build requires non-empty selected keys and candidate registry")
    if not selected_hash:
        raise RuntimeError("selected event key root does not declare selected_event_keys_hash")
    required_key_cols = ["candidate_identity_hash", "candidate_definition_id", "candidate_symbol_id", "symbol_id", "symbol", "parameter_vector_hash", "decision_ts", "idx", "entry_idx", "exit_idx", "seq"]
    missing = [c for c in required_key_cols if c not in keys.columns]
    if missing:
        raise RuntimeError(f"selected event key manifest missing required columns: {missing}")
    frozen = parse_bool_series(keys.get("selected_event_keys_frozen", pd.Series(False, index=keys.index)), default=False)
    if not bool(frozen.all()):
        raise RuntimeError("selected event key manifest contains unfrozen rows")
    key_hashes = set(keys.get("selected_event_keys_hash", pd.Series(dtype=str)).dropna().astype(str).unique())
    if key_hashes != {selected_hash}:
        raise RuntimeError("selected event key manifest hash does not match freeze summary")
    recomputed = freeze_selected_event_keys(keys.copy())[1]
    write_csv(ctx.run_root / "audit/selected_event_key_manifest_validation.csv", [{
        "selected_key_root": str(selected_root),
        "selected_event_key_rows": int(len(keys)),
        "declared_selected_event_key_hash": selected_hash,
        "recomputed_selected_event_key_hash": recomputed,
        "hash_match": selected_hash == recomputed,
        "selected_keys_frozen": bool(frozen.all()),
        "status": "pass" if selected_hash == recomputed and bool(frozen.all()) else "fail",
    }])
    if selected_hash != recomputed:
        raise RuntimeError("selected event key hash recomputation failed")
    return keys, registry, selected_hash


def tsmom_interval_policy_hash(candidate: Mapping[str, Any]) -> str:
    return stable_hash(
        "tsmom_interval_outcome_policy_v1",
        candidate.get("family_engine_id", "scheduled_tsmom_engine"),
        candidate.get("row_semantics", "position_interval"),
        candidate.get("contract_event_type", "scheduled_decision_contract"),
        candidate.get("hold_interval", ""),
        candidate.get("hold_bars", ""),
        candidate.get("side", ""),
        candidate.get("stop_bps", ""),
        candidate.get("fee_scenario_handling", ""),
        candidate.get("funding_gate", ""),
        candidate.get("vol_target", ""),
        candidate.get("vol_scale_min", ""),
        candidate.get("vol_scale_max", ""),
        n=24,
    )


def build_tsmom_outcomes_from_frozen_keys(ctx: Context, keys: pd.DataFrame, registry: pd.DataFrame, selected_hash: str) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    paths = data_paths(ctx)
    engine = ENGINES["scheduled_tsmom_engine"]
    reg_by_csid = {str(r.get("candidate_symbol_id", "")): r.to_dict() for _, r in registry.iterrows()}
    symbol_cache: dict[str, tuple[pd.DataFrame, pd.DataFrame]] = {}
    outcome_rows: list[dict[str, Any]] = []
    drop_rows: list[dict[str, Any]] = []
    runtime_rows: list[dict[str, Any]] = []
    t0 = time.time()
    for n, key in enumerate(keys.itertuples(index=False), start=1):
        k = key._asdict()
        csid = str(k.get("candidate_symbol_id", ""))
        cdict = reg_by_csid.get(csid)
        if not cdict:
            drop_rows.append({"candidate_symbol_id": csid, "symbol": k.get("symbol", ""), "decision_ts": k.get("decision_ts", ""), "drop_reason": "missing_candidate_registry_row"})
            continue
        symbol = str(cdict.get("symbol", k.get("symbol", "")))
        if symbol not in symbol_cache:
            symbol_cache[symbol] = (load_symbol_bars(paths, symbol, ctx.start, ctx.end), load_funding(paths, symbol, ctx.end))
        bars, funding = symbol_cache[symbol]
        decision_ts = ts_utc(k.get("decision_ts"))
        entry_idx = int(safe_float(k.get("entry_idx"), -1))
        exit_idx = int(safe_float(k.get("exit_idx"), -1))
        idx = int(safe_float(k.get("idx"), -1))
        seq = int(safe_float(k.get("seq"), 0))
        protected_reasons: list[str] = []
        if pd.isna(decision_ts) or decision_ts >= PROTECTED_TS:
            protected_reasons.append("decision_ts_protected_or_invalid")
        if bars.empty or entry_idx < 0 or exit_idx < 0 or entry_idx >= len(bars) or exit_idx >= len(bars):
            drop_rows.append({"candidate_symbol_id": csid, "symbol": symbol, "decision_ts": str(decision_ts), "drop_reason": "invalid_bar_index_or_missing_bars"})
            continue
        entry_ts = ts_utc(bars.iloc[entry_idx].get("ts"))
        exit_ts = ts_utc(bars.iloc[exit_idx].get("ts"))
        if entry_ts >= PROTECTED_TS:
            protected_reasons.append("entry_ts_crosses_protected_boundary")
        if exit_ts >= PROTECTED_TS:
            protected_reasons.append("exit_ts_crosses_protected_boundary")
        if protected_reasons:
            drop_rows.append({"candidate_symbol_id": csid, "symbol": symbol, "decision_ts": str(decision_ts), "entry_ts": str(entry_ts), "exit_ts": str(exit_ts), "drop_reason": ";".join(protected_reasons)})
            continue
        addr = EventAddress(
            candidate_id=definition_identity(cdict),
            definition_id=str(cdict.get("definition_id", definition_identity(cdict))),
            hypothesis_id=str(cdict.get("hypothesis_id", "")),
            family=str(cdict.get("family", "scheduled_tsmom_engine")),
            engine_id="scheduled_tsmom_engine",
            symbol=symbol,
            idx=idx,
            seq=seq,
            decision_ts=decision_ts,
            entry_idx=entry_idx,
            exit_idx=exit_idx,
            row_semantics=engine.row_semantics(),
            contract_event_type=engine.contract_event_type(),
        )
        ev = event_from_address(cdict, bars, funding, addr)
        if ev is None:
            drop_rows.append({"candidate_symbol_id": csid, "symbol": symbol, "decision_ts": str(decision_ts), "entry_ts": str(entry_ts), "exit_ts": str(exit_ts), "drop_reason": "event_from_address_returned_none"})
            continue
        ev = dict(ev)
        ev["candidate_identity_hash"] = str(k.get("candidate_identity_hash", cdict.get("candidate_identity_hash", "")))
        ev["symbol_id"] = symbol
        ev["idx"] = idx
        ev["entry_idx"] = entry_idx
        ev["exit_idx"] = exit_idx
        ev["seq"] = seq
        ev["selected_event_keys_hash"] = selected_hash
        ev["cache_outcome_built_after_key_freeze"] = True
        ev["interval_policy_hash"] = tsmom_interval_policy_hash(cdict)
        ev["year_month"] = ts_utc(ev.get("decision_ts")).strftime("%Y-%m")
        ev["outcome_cache_basis"] = "frozen_selected_event_keys_then_event_from_address"
        outcome_rows.append(ev)
        if n % 5000 == 0:
            runtime_rows.append({"processed_selected_key_rows": n, "outcome_rows": len(outcome_rows), "drop_rows": len(drop_rows), "runtime_seconds": time.time() - t0, "rss_bytes": current_rss_bytes()})
            clear_aggregate_caches(ctx, reason="outcome_grouped_selected_key_batch", scope=str(n))
    runtime_rows.append({"processed_selected_key_rows": int(len(keys)), "outcome_rows": len(outcome_rows), "drop_rows": len(drop_rows), "runtime_seconds": time.time() - t0, "rss_bytes": current_rss_bytes()})
    return pd.DataFrame(outcome_rows), pd.DataFrame(drop_rows), pd.DataFrame(runtime_rows)


def write_partitioned_tsmom_interval_outcome_cache(ctx: Context, outcomes: pd.DataFrame, selected_hash: str) -> pd.DataFrame:
    cache_root = ctx.run_root / "cache/tsmom_interval_outcome"
    cache_root.mkdir(parents=True, exist_ok=True)
    manifest_rows: list[dict[str, Any]] = []
    if outcomes.empty:
        manifest = semantic_cache_manifest(
            cache_class="tsmom_interval_outcome",
            df=outcomes,
            sort_keys=[],
            policy_fields={"outcome_semantics": "empty_frozen_selected_event_outcome_cache"},
            input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
            data_hash=tsmom_semantic_cache_data_hash(ctx),
            protected_train_boundary=str(PROTECTED_TS),
            selected_event_key_hash=selected_hash,
            path="cache/tsmom_interval_outcome",
        )
        manifest_rows.append({**manifest, "status": validate_semantic_cache_manifest(manifest).get("status", "fail")})
    else:
        work = outcomes.copy()
        if "symbol_id" not in work.columns:
            work["symbol_id"] = work.get("symbol", pd.Series("", index=work.index)).astype(str)
        if "year_month" not in work.columns:
            work["year_month"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce").dt.strftime("%Y-%m")
        if "interval_policy_hash" not in work.columns:
            work["interval_policy_hash"] = stable_hash("missing_interval_policy_hash", n=24)
        sort_keys = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "decision_ts", "event_id", "seq"] if c in work.columns]
        parquet_safe_frame(work).to_parquet(ctx.run_root / "cache/tsmom_interval_outcome.parquet", index=False)
        for (policy_hash, symbol_id, year_month), group in work.groupby(["interval_policy_hash", "symbol_id", "year_month"], dropna=False, sort=True):
            rel = Path("cache/tsmom_interval_outcome") / f"interval_policy_hash={safe_filename(policy_hash)}" / f"symbol_id={safe_filename(symbol_id)}" / f"year_month={safe_filename(year_month)}" / "part.parquet"
            out = ctx.run_root / rel
            out.parent.mkdir(parents=True, exist_ok=True)
            safe = parquet_safe_frame(group.sort_values(sort_keys, kind="mergesort") if sort_keys else group)
            safe.to_parquet(out, index=False)
            manifest = semantic_cache_manifest(
                cache_class="tsmom_interval_outcome",
                df=safe,
                sort_keys=sort_keys,
                policy_fields={
                    "outcome_semantics": "event_from_address_after_frozen_selected_event_keys",
                    "interval_policy_hash": str(policy_hash),
                    "partition_symbol_id": str(symbol_id),
                    "partition_year_month": str(year_month),
                    "protected_interval_rule": "drop_any_interval_touching_ge_2026_01_01",
                },
                input_manifest_hash=tsmom_semantic_input_manifest_hash(ctx),
                data_hash=tsmom_semantic_cache_data_hash(ctx),
                protected_train_boundary=str(PROTECTED_TS),
                selected_event_key_hash=selected_hash,
                path=str(rel),
            )
            validation = validate_semantic_cache_manifest(manifest)
            if validation.get("status") != "pass":
                raise RuntimeError(f"interval outcome semantic manifest validation failed: {validation.get('reason')}")
            manifest_rows.append({
                "interval_policy_hash": str(policy_hash),
                "symbol_id": str(symbol_id),
                "year_month": str(year_month),
                "path": str(rel),
                "row_count": int(len(safe)),
                "content_hash": manifest.get("content_hash", ""),
                "cache_class": manifest.get("cache_class", ""),
                "semantic_cache_hash": manifest.get("semantic_cache_hash", ""),
                "schema_hash": manifest.get("schema_hash", ""),
                "cache_contract_version": manifest.get("cache_contract_version", ""),
                "input_manifest_hash": manifest.get("input_manifest_hash", ""),
                "data_hash": manifest.get("data_hash", ""),
                "protected_train_boundary": manifest.get("protected_train_boundary", ""),
                "selected_event_key_hash": manifest.get("selected_event_key_hash", ""),
                "min_decision_ts": manifest.get("min_decision_ts", ""),
                "max_decision_ts": manifest.get("max_decision_ts", ""),
                "hash_basis": manifest.get("hash_basis", ""),
                "canonical_sort_keys": ";".join(manifest.get("canonical_sort_keys", [])),
                "status": "pass",
            })
    manifest_df = pd.DataFrame(manifest_rows)
    write_csv(ctx.run_root / "cache/tsmom_interval_outcome_manifest.csv", manifest_df)
    return manifest_df


def grouped_tsmom_aggregate_summary(candidates: pd.DataFrame, outcomes: pd.DataFrame) -> pd.DataFrame:
    key_cols = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in candidates.columns]
    if not key_cols:
        raise RuntimeError("grouped TSMOM aggregate requires candidate identity columns")
    base = candidates.drop_duplicates(key_cols, keep="first").copy()
    if outcomes.empty:
        for col in scalar_metric_columns():
            base[col] = 0
        base["evaluation_path"] = "outcome_cache_grouped_aggregate_no_candidate_row_filter"
        base["accelerated_tsmom_scalar_fallback_used"] = False
        base["independent_accelerated_evaluation"] = True
        return base
    work = outcomes.copy()
    work["decision_ts"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce")
    work["month"] = work["decision_ts"].dt.strftime("%Y-%m")
    group_cols = [c for c in key_cols if c in work.columns]
    if set(group_cols) != set(key_cols):
        raise RuntimeError("outcome rows missing candidate identity columns for grouped aggregate")
    metric_source = {
        "gross_R": "gross_R",
        "fees_R": "fees_R",
        "funding_R": "funding_R",
        "slippage_R": "slippage_R",
        "net_R": "net_R",
        "raw_gross_R": "raw_gross_R",
        "raw_fee_R": "raw_fee_R",
        "raw_funding_R": "raw_funding_R",
        "raw_slippage_R": "raw_slippage_R",
        "raw_net_R": "raw_net_R",
        "scaled_gross_R": "scaled_gross_R",
        "scaled_fee_R": "scaled_fee_R",
        "scaled_funding_R": "scaled_funding_R",
        "scaled_slippage_R": "scaled_slippage_R",
        "scaled_net_R": "scaled_net_R",
        "funding_boundary_count": "funding_timestamps_crossed",
        "funding_boundary_count_exact": "funding_boundary_count_exact",
        "funding_boundary_count_proxy": "funding_boundary_count_proxy",
    }
    agg_spec: dict[str, tuple[str, str]] = {}
    for out_col, in_col in metric_source.items():
        if in_col in work.columns:
            work[in_col] = pd.to_numeric(work[in_col], errors="coerce").fillna(0.0)
            agg_spec[out_col] = (in_col, "sum")
    grouped = work.groupby(group_cols, dropna=False).agg(**agg_spec).reset_index() if agg_spec else work[group_cols].drop_duplicates()
    counts = work.groupby(group_cols, dropna=False).size().reset_index(name="events")
    grouped = grouped.merge(counts, on=group_cols, how="left")
    grouped["event_count"] = grouped["events"]
    grouped["active_symbols"] = work.groupby(group_cols, dropna=False)["symbol"].nunique().reset_index(drop=True).astype(int).values
    grouped["active_months"] = work.groupby(group_cols, dropna=False)["month"].nunique().reset_index(drop=True).astype(int).values
    grouped["first_decision_ts"] = work.groupby(group_cols, dropna=False)["decision_ts"].min().reset_index(drop=True).map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "").values
    grouped["last_decision_ts"] = work.groupby(group_cols, dropna=False)["decision_ts"].max().reset_index(drop=True).map(lambda x: ts_utc(x).isoformat() if pd.notna(x) else "").values
    grouped["exact_funding_count"] = work.groupby(group_cols, dropna=False)["funding_exact"].apply(lambda s: int(parse_bool_series(s, default=False).sum()) if len(s) else 0).reset_index(drop=True).values if "funding_exact" in work.columns else 0
    grouped["proxy_funding_count"] = work.groupby(group_cols, dropna=False)["funding_proxy_used"].apply(lambda s: int(parse_bool_series(s, default=False).sum()) if len(s) else 0).reset_index(drop=True).values if "funding_proxy_used" in work.columns else 0
    if "label_cap_reason" in work.columns:
        grouped["event_label_cap_hash"] = work.groupby(group_cols, dropna=False)["label_cap_reason"].apply(lambda s: stable_hash(*s.fillna("").astype(str).tolist(), n=24)).reset_index(drop=True).values
        grouped["data_cap"] = work.groupby(group_cols, dropna=False)["label_cap_reason"].apply(lambda s: ";".join(sorted({part for value in s.fillna("").astype(str) for part in value.split(";") if part}))).reset_index(drop=True).values
    out = base.merge(grouped, on=key_cols, how="left", suffixes=("", "_grouped"))
    numeric_cols = set(scalar_metric_columns()) | {"funding_boundary_count_exact", "funding_boundary_count_proxy"}
    for col in numeric_cols:
        if col not in out.columns:
            out[col] = 0
        out[col] = pd.to_numeric(out[col], errors="coerce").fillna(0.0)
    for col in ["events", "event_count", "active_symbols", "active_months", "exact_funding_count", "proxy_funding_count", "funding_boundary_count", "funding_boundary_count_exact", "funding_boundary_count_proxy"]:
        if col in out.columns:
            out[col] = pd.to_numeric(out[col], errors="coerce").fillna(0).astype(int)
    out["funding_proxy_used"] = pd.to_numeric(out.get("proxy_funding_count", pd.Series(0, index=out.index)), errors="coerce").fillna(0).gt(0)
    out["funding_exact"] = pd.to_numeric(out.get("exact_funding_count", pd.Series(0, index=out.index)), errors="coerce").fillna(0).ge(pd.to_numeric(out.get("events", pd.Series(0, index=out.index)), errors="coerce").fillna(0))
    out["event_sampling_used"] = False
    out["aggregate_metric_basis"] = "grouped_from_frozen_selected_event_outcomes"
    out["evaluation_path"] = "outcome_cache_grouped_aggregate_no_candidate_row_filter"
    out["accelerated_tsmom_scalar_fallback_used"] = False
    out["independent_accelerated_evaluation"] = True
    out["evidence_level"] = "level_2_path_or_interval_support_only"
    out["candidate_status"] = "aggregate_cache_grouped_diagnostic_only"
    return out


def compare_outcome_grouped_vs_scalar(label: str, scalar: pd.DataFrame, grouped: pd.DataFrame, scalar_events: pd.DataFrame, outcome_events: pd.DataFrame) -> pd.DataFrame:
    key_cols = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash"] if c in scalar.columns and c in grouped.columns]
    if not key_cols:
        raise RuntimeError("outcome grouped exactness has no common identity keys")
    left = scalar.sort_values(key_cols, kind="mergesort").reset_index(drop=True)
    right = grouped.sort_values(key_cols, kind="mergesort").reset_index(drop=True)
    rows: list[dict[str, Any]] = [{
        "benchmark_label": label,
        "check": "candidate_symbol_row_count",
        "scalar_value": len(left),
        "grouped_value": len(right),
        "max_abs_diff": abs(len(left) - len(right)),
        "status": "pass" if len(left) == len(right) else "fail",
    }]
    if len(left) and len(right):
        common = min(len(left), len(right))
        l = left.head(common)
        r = right.head(common)
        rows.append({
            "benchmark_label": label,
            "check": "identity_key_hash",
            "scalar_value": canonical_frame_hash(l[key_cols], sort_keys=key_cols),
            "grouped_value": canonical_frame_hash(r[key_cols], sort_keys=key_cols),
            "max_abs_diff": "",
            "status": "pass" if canonical_frame_hash(l[key_cols], sort_keys=key_cols) == canonical_frame_hash(r[key_cols], sort_keys=key_cols) else "fail",
        })
        for col in scalar_metric_columns() + ["funding_boundary_count_exact", "funding_boundary_count_proxy"]:
            if col in l.columns and col in r.columns:
                ok, diff = compare_numeric_metric(l[col], r[col], tol=1e-8)
                rows.append({
                    "benchmark_label": label,
                    "check": col,
                    "scalar_value": numeric_sum(l[col]),
                    "grouped_value": numeric_sum(r[col]),
                    "max_abs_diff": diff,
                    "status": "pass" if ok else "fail",
                })
    event_key_cols = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash", "decision_ts", "event_id"] if c in scalar_events.columns and c in outcome_events.columns]
    rows.append({
        "benchmark_label": label,
        "check": "selected_outcome_event_key_hash",
        "scalar_value": canonical_frame_hash(scalar_events[event_key_cols], sort_keys=event_key_cols) if event_key_cols else "missing",
        "grouped_value": canonical_frame_hash(outcome_events[event_key_cols], sort_keys=event_key_cols) if event_key_cols else "missing",
        "max_abs_diff": "",
        "status": "pass" if event_key_cols and canonical_frame_hash(scalar_events[event_key_cols], sort_keys=event_key_cols) == canonical_frame_hash(outcome_events[event_key_cols], sort_keys=event_key_cols) else "fail",
    })
    sm_scalar = symbol_month_summary_from_events(scalar_events)
    sm_grouped = symbol_month_summary_from_events(outcome_events)
    sm_key = [c for c in ["candidate_definition_id", "candidate_symbol_id", "symbol", "parameter_vector_hash", "month"] if c in sm_scalar.columns and c in sm_grouped.columns]
    rows.append({
        "benchmark_label": label,
        "check": "symbol_month_summary_hash",
        "scalar_value": canonical_frame_hash(sm_scalar, sort_keys=sm_key) if sm_key else "missing",
        "grouped_value": canonical_frame_hash(sm_grouped, sort_keys=sm_key) if sm_key else "missing",
        "max_abs_diff": "",
        "status": "pass" if sm_key and canonical_frame_hash(sm_scalar, sort_keys=sm_key) == canonical_frame_hash(sm_grouped, sort_keys=sm_key) else "fail",
    })
    return pd.DataFrame(rows)


def outcome_grouped_exactness_benchmark(ctx: Context, label: str, candidates: pd.DataFrame, outcomes: pd.DataFrame) -> tuple[pd.DataFrame, dict[str, Any]]:
    t0 = time.time()
    scalar, scalar_events, scalar_seconds = scalar_tsmom_v6_benchmark_events(ctx, candidates)
    csids = set(candidates.get("candidate_symbol_id", pd.Series(dtype=str)).astype(str))
    subset_outcomes = outcomes[outcomes.get("candidate_symbol_id", pd.Series(dtype=str)).astype(str).isin(csids)].copy() if not outcomes.empty else pd.DataFrame()
    grouped = grouped_tsmom_aggregate_summary(candidates, subset_outcomes)
    exact = compare_outcome_grouped_vs_scalar(label, scalar, grouped, scalar_events, subset_outcomes)
    grouped_seconds = time.time() - t0 - scalar_seconds
    return exact, {
        "benchmark_label": label,
        "candidate_symbol_rows": int(len(candidates)),
        "scalar_event_rows": int(len(scalar_events)),
        "outcome_event_rows": int(len(subset_outcomes)),
        "scalar_runtime_seconds": scalar_seconds,
        "grouped_runtime_seconds": grouped_seconds,
        "total_runtime_seconds": time.time() - t0,
        "mismatch_count": int(exact["status"].astype(str).ne("pass").sum()),
        "rss_bytes": current_rss_bytes(),
    }


def stage_tsmom_outcome_grouped_aggregate(ctx: Context) -> None:
    t_start = time.time()
    selected_root = tsmom_outcome_selected_key_reference_root()
    keys, registry, selected_hash = validate_frozen_selected_event_keys_for_outcome(ctx, selected_root)
    access = pd.DataFrame([
        {"cache_class": "outcome", "access_phase": "manifest_validation_before_outcome_build", "selected_event_keys_frozen": True, "selected_event_key_rows": int(len(keys))},
        {"cache_class": "outcome", "access_phase": "interval_outcome_cache_build_after_freeze", "selected_event_keys_frozen": True, "selected_event_key_rows": int(len(keys))},
    ])
    write_csv(ctx.run_root / "audit/outcome_after_freeze_audit.csv", assert_outcome_cache_not_used_pre_freeze(access))
    existing_outcome_path = ctx.run_root / "cache/tsmom_interval_outcome.parquet"
    existing_manifest_path = ctx.run_root / "cache/tsmom_interval_outcome_manifest.csv"
    existing_manifest = read_csv_safe(existing_manifest_path)
    can_reuse_existing_outcome = (
        bool(getattr(ctx.args, "resume", False))
        and existing_outcome_path.exists()
        and not existing_manifest.empty
        and existing_manifest.get("status", pd.Series(dtype=str)).astype(str).eq("pass").all()
        and set(existing_manifest.get("selected_event_key_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) == {selected_hash}
    )
    if can_reuse_existing_outcome:
        outcomes = read_parquet_safe(existing_outcome_path)
        drops = read_csv_safe(ctx.run_root / "audit/outcome_build_drop_audit.csv")
        runtime = read_csv_safe(ctx.run_root / "performance/outcome_build_runtime_profile.csv")
        if runtime.empty:
            runtime = pd.DataFrame([{
                "processed_selected_key_rows": int(len(keys)),
                "outcome_rows": int(len(outcomes)),
                "drop_rows": int(len(drops)),
                "runtime_seconds": np.nan,
                "rss_bytes": current_rss_bytes(),
                "resume_reused_existing_outcome_cache": True,
            }])
        manifest = existing_manifest
    else:
        outcomes, drops, runtime = build_tsmom_outcomes_from_frozen_keys(ctx, keys, registry, selected_hash)
        write_csv(ctx.run_root / "audit/outcome_build_drop_audit.csv", drops)
        manifest = write_partitioned_tsmom_interval_outcome_cache(ctx, outcomes, selected_hash)
    (ctx.run_root / "aggregate").mkdir(parents=True, exist_ok=True)
    if not outcomes.empty:
        grouped = grouped_tsmom_aggregate_summary(registry, outcomes)
        parquet_safe_frame(grouped).to_parquet(ctx.run_root / "aggregate/grouped_aggregate_summary.parquet", index=False)
        parquet_safe_frame(symbol_month_summary_from_events(outcomes)).to_parquet(ctx.run_root / "aggregate/symbol_month_summary.parquet", index=False)
    else:
        grouped = grouped_tsmom_aggregate_summary(registry, outcomes)
        parquet_safe_frame(grouped).to_parquet(ctx.run_root / "aggregate/grouped_aggregate_summary.parquet", index=False)
        parquet_safe_frame(pd.DataFrame()).to_parquet(ctx.run_root / "aggregate/symbol_month_summary.parquet", index=False)
    decision_cols = ["decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts", "effective_exit_ts_for_purge", "candidate_window_end"]
    protected_rows = []
    for col in decision_cols:
        violations = int(pd.to_datetime(outcomes.get(col, pd.Series(dtype=str)), utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if col in outcomes.columns else 0
        protected_rows.append({"check": f"{col}_lt_protected_boundary", "rows": int(len(outcomes)), "violations": violations, "status": "pass" if violations == 0 else "fail"})
    if not drops.empty:
        for reason, g in drops.groupby("drop_reason", dropna=False):
            protected_rows.append({"check": "dropped_or_censored_reason_count", "drop_or_censor_reason": str(reason), "rows": int(len(g)), "violations": int(len(g)) if "protected" in str(reason) else 0, "status": "pass" if "protected" not in str(reason) else "fail"})
    write_csv(ctx.run_root / "audit/protected_holdout_interval_audit.csv", protected_rows)
    funding_audit = pd.DataFrame([{
        "outcome_rows": int(len(outcomes)),
        "funding_boundary_count": int(pd.to_numeric(outcomes.get("funding_timestamps_crossed", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not outcomes.empty else 0,
        "exact_funding_count": int(parse_bool_series(outcomes.get("funding_exact", pd.Series(dtype=bool)), default=False).sum()) if not outcomes.empty else 0,
        "proxy_funding_count": int(parse_bool_series(outcomes.get("funding_proxy_used", pd.Series(dtype=bool)), default=False).sum()) if not outcomes.empty else 0,
        "funding_boundary_count_exact": int(pd.to_numeric(outcomes.get("funding_boundary_count_exact", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not outcomes.empty else 0,
        "funding_boundary_count_proxy": int(pd.to_numeric(outcomes.get("funding_boundary_count_proxy", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not outcomes.empty else 0,
        "status": "pass",
    }])
    write_csv(ctx.run_root / "audit/funding_boundary_audit.csv", funding_audit)
    arithmetic_rows = []
    grouped_check = grouped_tsmom_aggregate_summary(registry, outcomes)
    for col in ["events", "gross_R", "fees_R", "funding_R", "slippage_R", "net_R", "raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R", "raw_net_R", "scaled_gross_R", "scaled_fee_R", "scaled_funding_R", "scaled_slippage_R", "scaled_net_R"]:
        left = numeric_sum(grouped.get(col, pd.Series(dtype=float))) if col in grouped.columns else 0.0
        right = numeric_sum(grouped_check.get(col, pd.Series(dtype=float))) if col in grouped_check.columns else 0.0
        arithmetic_rows.append({"check": col, "grouped_value": left, "recomputed_value": right, "max_abs_diff": abs(left - right), "status": "pass" if abs(left - right) <= 1e-8 else "fail"})
    write_csv(ctx.run_root / "audit/grouped_aggregate_arithmetic_audit.csv", arithmetic_rows)
    source = inspect.getsource(stage_tsmom_outcome_grouped_aggregate) + inspect.getsource(grouped_tsmom_aggregate_summary)
    forbidden_memorysafe = "aggregate_candidates" + "_memorysafe_to_dir"
    forbidden_row_filter = "accelerated_tsmom_v6_cache" + "_aggregate(candidates, outcomes)"
    no_scalar_fallback = forbidden_memorysafe not in source and forbidden_row_filter not in source
    write_csv(ctx.run_root / "audit/no_scalar_fallback_audit.csv", [{
        "check": "outcome_grouped_stage_avoids_scalar_aggregate_fallback",
        "scalar_fallback_used": False,
        "forbidden_scalar_function_reference_present": not no_scalar_fallback,
        "status": "pass" if no_scalar_fallback else "fail",
    }])
    setup_root = tsmom_v6_accelerated_setup_root()
    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8, write_registry=False)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    exact_frames: list[pd.DataFrame] = []
    perf_rows: list[dict[str, Any]] = []
    for label, sample in [("representative_24_heavy_path", rep), ("medium_128_real_rows", med)]:
        exact, perf = outcome_grouped_exactness_benchmark(ctx, label, sample, outcomes)
        exact_frames.append(exact)
        perf_rows.append(perf)
    exactness = pd.concat(exact_frames, ignore_index=True, sort=False) if exact_frames else pd.DataFrame()
    write_csv(ctx.run_root / "benchmark/outcome_grouped_vs_scalar_exactness.csv", exactness)
    warm_t0 = time.time()
    warm_outcomes = read_parquet_safe(ctx.run_root / "cache/tsmom_interval_outcome.parquet")
    warm_grouped = grouped_tsmom_aggregate_summary(registry, warm_outcomes)
    warm_seconds = time.time() - warm_t0
    cold_seconds = float(pd.to_numeric(runtime.get("runtime_seconds", pd.Series([0])), errors="coerce").fillna(0).max()) if not runtime.empty else time.time() - t_start
    write_csv(ctx.run_root / "performance/outcome_build_runtime_profile.csv", runtime)
    perf_rows.append({
        "benchmark_label": "full_selected_key_outcome_grouped_cold",
        "candidate_symbol_rows": int(len(registry)),
        "selected_event_key_rows": int(len(keys)),
        "outcome_event_rows": int(len(outcomes)),
        "cold_outcome_build_seconds": cold_seconds,
        "cold_grouped_rows": int(len(grouped)),
        "warm_grouped_runtime_seconds": warm_seconds,
        "warm_grouped_rows": int(len(warm_grouped)),
        "rss_bytes": current_rss_bytes(),
    })
    write_csv(ctx.run_root / "benchmark/outcome_grouped_performance.csv", perf_rows)
    protected_violations = int(pd.to_numeric(pd.DataFrame(protected_rows).get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    exact_mismatches = int(exactness["status"].astype(str).ne("pass").sum()) if not exactness.empty else 1
    outcome_freeze_failures = int(read_csv_safe(ctx.run_root / "audit/outcome_after_freeze_audit.csv").get("status", pd.Series(dtype=str)).astype(str).eq("fail").sum())
    arithmetic_failures = int(pd.DataFrame(arithmetic_rows)["status"].astype(str).ne("pass").sum())
    manifest_failures = int(manifest.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not manifest.empty else 1
    scalar_fallback_used = not no_scalar_fallback
    peak_rss = int(max(current_rss_bytes(), pd.to_numeric(runtime.get("rss_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).max() if not runtime.empty else 0))
    soft = memory_soft_limit_bytes(ctx)
    memory_pass = peak_rss < int(soft * 0.70)
    pass_gate = exact_mismatches == 0 and protected_violations == 0 and outcome_freeze_failures == 0 and arithmetic_failures == 0 and manifest_failures == 0 and not scalar_fallback_used and memory_pass
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "full_aggregate_launched": False,
        "prior_high_route_touched": False,
        "materialization_launched": False,
        "validation_launched": False,
        "selected_key_root": str(selected_root),
        "selected_event_key_rows": int(len(keys)),
        "selected_event_key_hash": selected_hash,
        "outcome_rows": int(len(outcomes)),
        "outcome_cache_partitions": int(len(manifest)),
        "grouped_candidate_symbol_rows": int(len(grouped)),
        "outcome_after_freeze_pass": outcome_freeze_failures == 0,
        "exactness_pass": exact_mismatches == 0,
        "mismatch_count": exact_mismatches,
        "protected_interval_violations": protected_violations,
        "scalar_fallback_used": scalar_fallback_used,
        "grouped_aggregate_arithmetic_pass": arithmetic_failures == 0,
        "manifest_validation_pass": manifest_failures == 0,
        "cold_runtime_seconds": cold_seconds,
        "warm_runtime_seconds": warm_seconds,
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": memory_pass,
        "next_operator_decision": "run_tsmom_grouped_cache_full_v6_aggregate_next" if pass_gate else "repair_tsmom_outcome_grouped_cache_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "KRAKEN_TSMOM_OUTCOME_GROUPED_AGGREGATE_REPORT.md", "\n".join([
        "# Kraken TSMOM Outcome Cache and Grouped Aggregate Report",
        "",
        "This is a TSMOM-only outcome-cache and grouped-aggregate benchmark phase. It did not launch a full aggregate, sweep, materialization, controls, validation, or prior-high/reclaim route.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Selected key root: `{selected_root}`",
        f"Selected event key rows: `{summary['selected_event_key_rows']}`",
        f"Outcome rows: `{summary['outcome_rows']}`",
        f"Outcome cache partitions: `{summary['outcome_cache_partitions']}`",
        f"Grouped candidate-symbol rows: `{summary['grouped_candidate_symbol_rows']}`",
        f"Outcome-after-freeze pass: `{summary['outcome_after_freeze_pass']}`",
        f"Exactness pass: `{summary['exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Protected interval violations: `{summary['protected_interval_violations']}`",
        f"Scalar fallback used: `{summary['scalar_fallback_used']}`",
        f"Cold runtime seconds: `{summary['cold_runtime_seconds']}`",
        f"Warm runtime seconds: `{summary['warm_runtime_seconds']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "This is infrastructure evidence only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    write_status(ctx, summary["status"], "tsmom-outcome-grouped-aggregate")


def tsmom_end_to_end_scaling_outcome_root() -> Path:
    explicit = RESULTS_ROOT / "phase_kraken_tsmom_outcome_grouped_aggregate_20260707_v1"
    if not explicit.exists():
        raise RuntimeError(f"missing outcome/grouped aggregate root: {explicit}")
    summary = read_json(explicit / "decision_summary.json", {})
    mismatch_count = int(summary.get("mismatch_count", 1)) if str(summary.get("mismatch_count", "")).strip() != "" else 1
    if summary.get("status") != "complete" or not bool(summary.get("exactness_pass")) or mismatch_count != 0:
        raise RuntimeError("outcome/grouped aggregate root is not complete/exactness-passing")
    if bool(summary.get("scalar_fallback_used")):
        raise RuntimeError("outcome/grouped aggregate root reports scalar fallback use")
    return explicit


def path_tree_size_bytes(root: Path) -> int:
    total = 0
    if not root.exists():
        return 0
    if root.is_file():
        return int(root.stat().st_size)
    for dirpath, _, filenames in os.walk(root):
        for name in filenames:
            try:
                total += int((Path(dirpath) / name).stat().st_size)
            except OSError:
                continue
    return total


def max_rss_from_csv(path: Path) -> int:
    df = read_csv_safe(path)
    if df.empty or "rss_bytes" not in df.columns:
        return 0
    return int(pd.to_numeric(df["rss_bytes"], errors="coerce").fillna(0).max())


def runtime_from_stage(path: Path, stage: str) -> float:
    df = read_csv_safe(path)
    if df.empty or "stage" not in df.columns or "runtime_seconds" not in df.columns:
        return 0.0
    sub = df[df["stage"].astype(str).eq(stage)]
    if sub.empty:
        return 0.0
    return float(pd.to_numeric(sub["runtime_seconds"], errors="coerce").fillna(0).sum())


def rows_from_stage(path: Path, stage: str) -> int:
    df = read_csv_safe(path)
    if df.empty or "stage" not in df.columns or "rows" not in df.columns:
        return 0
    sub = df[df["stage"].astype(str).eq(stage)]
    if sub.empty:
        return 0
    return int(pd.to_numeric(sub["rows"], errors="coerce").fillna(0).sum())


def outcome_cold_build_seconds_from_lifecycle(outcome_root: Path) -> float:
    lifecycle = read_csv_safe(outcome_root / "performance/cache_lifecycle_audit.csv")
    if lifecycle.empty or "reason" not in lifecycle.columns or "ts_utc" not in lifecycle.columns:
        return 0.0
    sub = lifecycle[lifecycle["reason"].astype(str).eq("outcome_grouped_selected_key_batch")].copy()
    if sub.empty:
        return 0.0
    ts = pd.to_datetime(sub["ts_utc"], utc=True, errors="coerce").dropna()
    if ts.empty:
        return 0.0
    # The first checkpoint is after the first 5k selected keys, so this is conservative-low.
    return float((ts.max() - ts.min()).total_seconds())


def scaling_subset_by_candidate_symbols(df: pd.DataFrame, candidates: pd.DataFrame) -> pd.DataFrame:
    if df.empty or candidates.empty or "candidate_symbol_id" not in df.columns:
        return pd.DataFrame(columns=df.columns)
    csids = set(candidates.get("candidate_symbol_id", pd.Series(dtype=str)).astype(str))
    return df[df["candidate_symbol_id"].astype(str).isin(csids)].copy()


def benchmark_cache_table_subset(
    ctx: Context,
    *,
    label: str,
    candidates: pd.DataFrame,
    selected_key_path: Path,
    outcome_path: Path,
    registry: pd.DataFrame,
    cache_temperature: str,
) -> tuple[dict[str, Any], pd.DataFrame]:
    wall0 = time.time()
    cpu0 = time.process_time()
    read0 = time.time()
    keys = read_csv_safe(selected_key_path)
    outcomes = read_parquet_safe(outcome_path)
    read_seconds = time.time() - read0
    filter0 = time.time()
    subset_keys = scaling_subset_by_candidate_symbols(keys, candidates)
    subset_outcomes = scaling_subset_by_candidate_symbols(outcomes, candidates)
    filter_seconds = time.time() - filter0
    group0 = time.time()
    grouped = grouped_tsmom_aggregate_summary(candidates, subset_outcomes)
    group_seconds = time.time() - group0
    wall_seconds = time.time() - wall0
    cpu_seconds = time.process_time() - cpu0
    cpu_util = (cpu_seconds / wall_seconds * 100.0) if wall_seconds > 0 else 0.0
    selected_hash = freeze_selected_event_keys(subset_keys.copy())[1] if not subset_keys.empty else stable_hash("empty_subset_selected_keys")
    rows = {
        "benchmark_label": label,
        "cache_temperature": cache_temperature,
        "candidate_symbol_rows": int(len(candidates)),
        "selected_event_key_rows": int(len(subset_keys)),
        "outcome_rows": int(len(subset_outcomes)),
        "grouped_rows": int(len(grouped)),
        "total_runtime_seconds": float(wall_seconds),
        "read_runtime_seconds": float(read_seconds),
        "filter_runtime_seconds": float(filter_seconds),
        "grouped_aggregate_runtime_seconds": float(group_seconds),
        "cpu_seconds": float(cpu_seconds),
        "cpu_utilization_pct": float(cpu_util),
        "rss_bytes": current_rss_bytes(),
        "rows_read": int(len(keys) + len(outcomes)),
        "rows_written": int(len(grouped)),
        "disk_read_bytes": int(selected_key_path.stat().st_size if selected_key_path.exists() else 0) + int(outcome_path.stat().st_size if outcome_path.exists() else 0),
        "selected_event_key_subset_hash": selected_hash,
        "event_sampling_used": False,
        "event_caps_used": False,
        "aggregate_or_sweep_launched": False,
        "status": "pass" if int(len(grouped)) == int(len(candidates)) else "fail",
    }
    return rows, grouped


def stage_tsmom_end_to_end_scaling_benchmark(ctx: Context) -> None:
    t_start = time.time()
    outcome_root = tsmom_end_to_end_scaling_outcome_root()
    outcome_summary = read_json(outcome_root / "decision_summary.json", {})
    selected_root = Path(str(outcome_summary.get("selected_key_root", "")))
    if not selected_root.exists():
        raise RuntimeError(f"missing selected key root from outcome summary: {selected_root}")
    calendar_root = tsmom_rank_topn_calendar_universe_root()
    rank_root = tsmom_mask_selected_key_rank_topn_root()
    setup_root = tsmom_v6_accelerated_setup_root()
    selected_key_path = selected_root / "cache/selected_event_key_manifest.csv"
    outcome_path = outcome_root / "cache/tsmom_interval_outcome.parquet"
    if not selected_key_path.exists() or not outcome_path.exists():
        raise RuntimeError("missing selected-key or outcome cache artifact for scaling benchmark")
    registry = read_csv_safe(selected_root / "registry/tsmom_v6_mask_selected_key_registry.csv")
    if registry.empty:
        raise RuntimeError("missing selected-key candidate registry")

    exactness = read_csv_safe(outcome_root / "benchmark/outcome_grouped_vs_scalar_exactness.csv")
    if exactness.empty:
        raise RuntimeError("missing outcome/grouped scalar exactness sentinel")
    exactness = exactness.copy()
    exactness["sentinel_source_root"] = str(outcome_root)
    exactness["sentinel_reused_in_scaling_phase"] = True
    write_csv(ctx.run_root / "benchmark/scalar_exactness_sentinel.csv", exactness)
    mismatch_count = int(exactness.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum())

    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8, write_registry=False)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    target_large_rows = 1024
    large = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=64, rows_per_definition=16)
    large = large.head(target_large_rows).copy()
    large_reason = "" if len(large) >= target_large_rows else f"only_{len(large)}_candidate_symbol_rows_available_from_v6_shards"
    write_csv(ctx.run_root / "benchmark/large_scaling_candidate_registry.csv", large)

    scaling_rows: list[dict[str, Any]] = []
    prior_perf = read_csv_safe(outcome_root / "benchmark/outcome_grouped_performance.csv")
    for label in ["representative_24_heavy_path", "medium_128_real_rows"]:
        sub = prior_perf[prior_perf.get("benchmark_label", pd.Series(dtype=str)).astype(str).eq(label)]
        exact_sub = exactness[exactness.get("benchmark_label", pd.Series(dtype=str)).astype(str).eq(label)]
        scaling_rows.append({
            "benchmark_label": label,
            "benchmark_type": "scalar_exactness_sentinel_from_reference_outcome_root",
            "candidate_symbol_rows": int(pd.to_numeric(sub.get("candidate_symbol_rows", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else (24 if "24" in label else 128),
            "selected_event_key_rows": "",
            "outcome_rows": int(pd.to_numeric(sub.get("outcome_event_rows", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else "",
            "total_runtime_seconds": float(pd.to_numeric(sub.get("total_runtime_seconds", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else "",
            "scalar_runtime_seconds": float(pd.to_numeric(sub.get("scalar_runtime_seconds", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else "",
            "grouped_aggregate_runtime_seconds": float(pd.to_numeric(sub.get("grouped_runtime_seconds", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else "",
            "cache_temperature": "reference",
            "mismatch_count": int(exact_sub.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not exact_sub.empty else 1,
            "large_subset_feasible_without_45m": "",
            "reason": "exactness_reused_from_immediately_prior_outcome_grouped_phase",
            "rss_bytes": int(pd.to_numeric(sub.get("rss_bytes", pd.Series([0])), errors="coerce").fillna(0).max()) if not sub.empty else "",
            "status": "pass" if not exact_sub.empty and int(exact_sub["status"].astype(str).ne("pass").sum()) == 0 else "fail",
        })

    cold_large, _ = benchmark_cache_table_subset(
        ctx,
        label="large_1024_cache_table_cold",
        candidates=large,
        selected_key_path=selected_key_path,
        outcome_path=outcome_path,
        registry=registry,
        cache_temperature="cold_table_read",
    )
    cold_large["benchmark_type"] = "cache_table_read_filter_group"
    cold_large["mismatch_count"] = ""
    cold_large["large_subset_feasible_without_45m"] = bool(cold_large["total_runtime_seconds"] < 45 * 60)
    cold_large["reason"] = large_reason
    scaling_rows.append(cold_large)
    warm_large, _ = benchmark_cache_table_subset(
        ctx,
        label="large_1024_cache_table_warm",
        candidates=large,
        selected_key_path=selected_key_path,
        outcome_path=outcome_path,
        registry=registry,
        cache_temperature="warm_table_read",
    )
    warm_large["benchmark_type"] = "cache_table_read_filter_group"
    warm_large["mismatch_count"] = ""
    warm_large["large_subset_feasible_without_45m"] = bool(warm_large["total_runtime_seconds"] < 45 * 60)
    warm_large["reason"] = large_reason
    scaling_rows.append(warm_large)
    write_csv(ctx.run_root / "benchmark/scaling_benchmark_summary.csv", scaling_rows)

    calendar_perf = calendar_root / "benchmark/calendar_universe_performance.csv"
    rank_perf = rank_root / "benchmark/rank_topn_performance.csv"
    mask_perf = selected_root / "benchmark/mask_selected_key_performance.csv"
    mask_partition_perf = read_csv_safe(selected_root / "performance/mask_selected_key_runtime_by_partition.csv")
    outcome_cold_seconds = outcome_cold_build_seconds_from_lifecycle(outcome_root)
    outcome_rows = int(outcome_summary.get("outcome_rows", 0) or 0)
    selected_rows = int(outcome_summary.get("selected_event_key_rows", 0) or 0)
    grouped_rows = int(outcome_summary.get("grouped_candidate_symbol_rows", 0) or 0)
    stage_rows = [
        {"stage": "decision_calendar_build", "runtime_seconds": runtime_from_stage(calendar_perf, "decision_calendar_dataset_build"), "rows_read": 0, "rows_written": rows_from_stage(calendar_perf, "decision_calendar_dataset_build"), "cache_temperature": "reference_cold_build", "source_root": str(calendar_root), "rss_bytes": max_rss_from_csv(calendar_perf), "cache_hits": 0, "cache_misses": 1},
        {"stage": "universe_membership_build", "runtime_seconds": runtime_from_stage(calendar_perf, "universe_membership_dataset_build"), "rows_read": rows_from_stage(calendar_perf, "decision_calendar_dataset_build"), "rows_written": int(read_json(calendar_root / "decision_summary.json", {}).get("universe_membership_rows", 0) or 0), "cache_temperature": "reference_cold_build", "source_root": str(calendar_root), "rss_bytes": max_rss_from_csv(calendar_perf), "cache_hits": 0, "cache_misses": 1},
        {"stage": "rank_feature_build", "runtime_seconds": runtime_from_stage(rank_perf, "rank_feature_dataset_build"), "rows_read": rows_from_stage(calendar_perf, "decision_calendar_dataset_build"), "rows_written": int(read_json(rank_root / "decision_summary.json", {}).get("rank_feature_rows", 0) or 0), "cache_temperature": "reference_cold_build", "source_root": str(rank_root), "rss_bytes": max_rss_from_csv(rank_perf), "cache_hits": 0, "cache_misses": 1},
        {"stage": "topn_membership_build", "runtime_seconds": runtime_from_stage(rank_perf, "topn_membership_dataset_build"), "rows_read": int(read_json(calendar_root / "decision_summary.json", {}).get("universe_membership_rows", 0) or 0), "rows_written": int(read_json(rank_root / "decision_summary.json", {}).get("topn_membership_rows", 0) or 0), "cache_temperature": "reference_cold_build", "source_root": str(rank_root), "rss_bytes": max_rss_from_csv(rank_perf), "cache_hits": 0, "cache_misses": 1},
        {"stage": "mask_and_selected_key_build", "runtime_seconds": runtime_from_stage(mask_perf, "mask_selected_key_build"), "rows_read": int(pd.to_numeric(mask_partition_perf.get("candidate_calendar_rows", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not mask_partition_perf.empty else 0, "rows_written": selected_rows, "cache_temperature": "reference_cold_build", "source_root": str(selected_root), "rss_bytes": max(max_rss_from_csv(mask_perf), max_rss_from_csv(selected_root / "performance/mask_selected_key_runtime_by_partition.csv")), "cache_hits": 0, "cache_misses": 1},
        {"stage": "outcome_build_after_selected_key_freeze", "runtime_seconds": outcome_cold_seconds, "rows_read": selected_rows, "rows_written": outcome_rows, "cache_temperature": "reference_cold_build_from_lifecycle_not_resumed_zero", "source_root": str(outcome_root), "rss_bytes": max(max_rss_from_csv(outcome_root / "performance/cache_lifecycle_audit.csv"), int(outcome_summary.get("peak_rss_bytes", 0) or 0)), "cache_hits": 0, "cache_misses": 1},
        {"stage": "large_1024_table_cold_read_filter_group", "runtime_seconds": cold_large["total_runtime_seconds"], "rows_read": cold_large["rows_read"], "rows_written": cold_large["rows_written"], "cache_temperature": "cold_table_read", "source_root": str(outcome_root), "rss_bytes": cold_large["rss_bytes"], "cache_hits": 3, "cache_misses": 0},
        {"stage": "large_1024_table_warm_read_filter_group", "runtime_seconds": warm_large["total_runtime_seconds"], "rows_read": warm_large["rows_read"], "rows_written": warm_large["rows_written"], "cache_temperature": "warm_table_read", "source_root": str(outcome_root), "rss_bytes": warm_large["rss_bytes"], "cache_hits": 3, "cache_misses": 0},
    ]
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", stage_rows)
    cache_rows = []
    for cache_class, manifest_path, rows_written in [
        ("decision_calendar", calendar_root / "cache/decision_calendar_manifest.csv", rows_from_stage(calendar_perf, "decision_calendar_dataset_build")),
        ("universe_membership", calendar_root / "cache/universe_membership_manifest.csv", int(read_json(calendar_root / "decision_summary.json", {}).get("universe_membership_rows", 0) or 0)),
        ("rank_feature", rank_root / "cache/tsmom_rank_feature_manifest.csv", int(read_json(rank_root / "decision_summary.json", {}).get("rank_feature_rows", 0) or 0)),
        ("topn_membership", rank_root / "cache/tsmom_topn_membership_manifest.csv", int(read_json(rank_root / "decision_summary.json", {}).get("topn_membership_rows", 0) or 0)),
        ("selected_event_key", selected_root / "cache/selected_event_key_manifest.csv", selected_rows),
        ("interval_outcome", outcome_root / "cache/tsmom_interval_outcome_manifest.csv", outcome_rows),
    ]:
        manifest_rows = len(read_csv_safe(manifest_path)) if manifest_path.exists() and manifest_path.suffix == ".csv" else (1 if manifest_path.exists() else 0)
        cache_rows.append({
            "cache_class": cache_class,
            "manifest_path": str(manifest_path),
            "manifest_rows": int(manifest_rows),
            "cache_hits": int(manifest_rows),
            "cache_misses": 0,
            "rows_read": int(rows_written),
            "rows_written": 0,
            "reuse_status": "hit_validated_reference_cache",
        })
    write_csv(ctx.run_root / "performance/cache_hit_miss_report.csv", cache_rows)

    leak_violations = 0
    for path in [
        calendar_root / "audit/universe_membership_leak_audit.csv",
        rank_root / "audit/rank_feature_leak_audit.csv",
        selected_root / "audit/decision_input_leak_audit.csv",
    ]:
        df = read_csv_safe(path)
        leak_violations += int(pd.to_numeric(df.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not df.empty else 1
    protected = read_csv_safe(outcome_root / "audit/protected_holdout_interval_audit.csv")
    protected_violations = int(pd.to_numeric(protected.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not protected.empty else 1
    no_scalar = read_csv_safe(outcome_root / "audit/no_scalar_fallback_audit.csv")
    scalar_fallback_used = bool(parse_bool_series(no_scalar.get("scalar_fallback_used", pd.Series([True])), default=True).any()) if not no_scalar.empty else True
    source = inspect.getsource(stage_tsmom_end_to_end_scaling_benchmark) + inspect.getsource(benchmark_cache_table_subset)
    forbidden_scalar_events = "scalar_tsmom" + "_v6_benchmark_events("
    forbidden_scalar_keys = "scalar_selected" + "_tsmom_event_keys("
    forbidden_memorysafe = "aggregate_candidates" + "_memorysafe_to_dir("
    row_recompute_forbidden = any(s in source for s in [forbidden_scalar_events, forbidden_scalar_keys, forbidden_memorysafe])
    peak_rss = int(max(
        current_rss_bytes(),
        max(pd.to_numeric(pd.DataFrame(stage_rows).get("rss_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).max(), 0),
        int(outcome_summary.get("peak_rss_bytes", 0) or 0),
    ))
    soft = memory_soft_limit_bytes(ctx)
    memory_pass = peak_rss < 6 * 1024**3
    cold_build_seconds = sum(float(r["runtime_seconds"]) for r in stage_rows if str(r.get("cache_temperature", "")).startswith("reference_cold_build"))
    full_table_warm_seconds = max(float(outcome_summary.get("warm_runtime_seconds", 0) or 0), float(warm_large["total_runtime_seconds"]) * (max(grouped_rows, 1) / max(int(warm_large["grouped_rows"]), 1)))
    projected_full_cold_seconds = float(cold_build_seconds + full_table_warm_seconds)
    projected_full_warm_seconds = float(full_table_warm_seconds)
    operator_review_required = bool(projected_full_cold_seconds >= 3 * 3600 and projected_full_cold_seconds < 6 * 3600)
    runtime_gate_pass = projected_full_cold_seconds < 3 * 3600 or operator_review_required
    warm_gate_pass = projected_full_warm_seconds < 3600 or projected_full_warm_seconds < 2 * 3600
    exactness_pass = mismatch_count == 0
    pass_gate = exactness_pass and leak_violations == 0 and protected_violations == 0 and not scalar_fallback_used and not row_recompute_forbidden and memory_pass and runtime_gate_pass and warm_gate_pass
    main_bottleneck = max(
        [r for r in stage_rows if str(r.get("cache_temperature", "")).startswith("reference_cold_build")],
        key=lambda r: float(r.get("runtime_seconds", 0) or 0),
    )
    write_text(ctx.run_root / "performance/full_v6_runtime_projection.md", "\n".join([
        "# TSMOM Full v6 Runtime Projection",
        "",
        "This projection uses measured cache-spec/table-stage timings, not the resumed `cold_runtime_seconds = 0.0` from the outcome/grouped run.",
        "",
        f"Projected full cold runtime seconds: `{projected_full_cold_seconds:.3f}`",
        f"Projected full cold runtime hours: `{projected_full_cold_seconds / 3600.0:.3f}`",
        f"Projected full warm runtime seconds: `{projected_full_warm_seconds:.3f}`",
        f"Projected full warm runtime hours: `{projected_full_warm_seconds / 3600.0:.3f}`",
        f"Operator-review runtime flag: `{operator_review_required}`",
        f"Main remaining bottleneck: `{main_bottleneck.get('stage')}` at `{float(main_bottleneck.get('runtime_seconds', 0) or 0):.3f}` seconds",
        "",
        "Cold projection components are measured reference cache builds: decision calendar, universe membership, rank features, Top-N membership, mask/selected keys, and post-freeze outcome build. Warm projection is measured table read/filter/group behavior over the cached selected-key and outcome tables.",
        "",
        "This is infrastructure timing only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    gate = {
        "exactness_pass": exactness_pass,
        "mismatch_count": mismatch_count,
        "leak_violations": leak_violations,
        "protected_holdout_interval_violations": protected_violations,
        "scalar_fallback_used": scalar_fallback_used,
        "row_granular_decision_input_recompute_in_accelerated_path": row_recompute_forbidden,
        "peak_rss_bytes": peak_rss,
        "peak_rss_lt_6gib": memory_pass,
        "projected_full_cold_runtime_seconds": projected_full_cold_seconds,
        "projected_full_warm_runtime_seconds": projected_full_warm_seconds,
        "operator_review_required_for_cold_runtime": operator_review_required,
        "projected_cold_runtime_gate_pass": runtime_gate_pass,
        "projected_warm_runtime_gate_pass": warm_gate_pass,
        "full_gate_pass": pass_gate,
    }
    write_json(ctx.run_root / "audit/full_gate_readiness.json", gate)
    disk_used = path_tree_size_bytes(ctx.run_root)
    next_decision = "proceed_to_full_tsmom_cache_dry_run_next" if pass_gate else "repair_specific_bottleneck_next"
    if not exactness_pass or leak_violations or protected_violations or scalar_fallback_used:
        next_decision = "blocked_by_protocol_issue"
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "full_aggregate_launched": False,
        "prior_high_route_touched": False,
        "event_sampling_used": False,
        "event_caps_used": False,
        "materialization_launched": False,
        "validation_launched": False,
        "outcome_grouped_reference_root": str(outcome_root),
        "exactness_pass": exactness_pass,
        "mismatch_count": mismatch_count,
        "leak_violations": leak_violations,
        "protected_holdout_interval_violations": protected_violations,
        "scalar_fallback_used": scalar_fallback_used,
        "row_granular_decision_input_recompute_in_accelerated_path": row_recompute_forbidden,
        "large_benchmark_candidate_symbol_rows": int(len(large)),
        "large_benchmark_feasible_without_45m": bool(cold_large["total_runtime_seconds"] < 45 * 60),
        "projected_full_cold_runtime_seconds": projected_full_cold_seconds,
        "projected_full_warm_runtime_seconds": projected_full_warm_seconds,
        "operator_review_required_for_cold_runtime": operator_review_required,
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "disk_used_bytes": int(disk_used),
        "main_remaining_bottleneck": str(main_bottleneck.get("stage", "")),
        "next_operator_decision": next_decision,
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "KRAKEN_TSMOM_END_TO_END_SCALING_BENCHMARK_REPORT.md", "\n".join([
        "# Kraken TSMOM End-to-End Scaling Benchmark Report",
        "",
        "This is a TSMOM-only scaling benchmark. It did not launch a full aggregate, sweep, materialization, controls, validation, or prior-high/reclaim route.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Exactness pass: `{exactness_pass}`",
        f"Mismatch count: `{mismatch_count}`",
        f"Projected full cold runtime seconds: `{projected_full_cold_seconds}`",
        f"Projected full warm runtime seconds: `{projected_full_warm_seconds}`",
        f"Peak RSS bytes: `{peak_rss}`",
        f"Main remaining bottleneck: `{summary['main_remaining_bottleneck']}`",
        f"Next operator decision: `{next_decision}`",
        "",
        "This is infrastructure output only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    write_status(ctx, summary["status"], "tsmom-end-to-end-scaling-benchmark")


def full_tsmom_v6_cache_dry_run_reference_roots() -> dict[str, Path]:
    roots = {
        "scaling_benchmark": RESULTS_ROOT / "phase_kraken_tsmom_end_to_end_scaling_benchmark_20260707_v1",
        "outcome_grouped": RESULTS_ROOT / "phase_kraken_tsmom_outcome_grouped_aggregate_20260707_v1",
        "selected_key": RESULTS_ROOT / "phase_kraken_tsmom_mask_selected_key_builder_20260707_v1_20260707_201216",
        "rank_topn": RESULTS_ROOT / "phase_kraken_tsmom_rank_topn_cache_builder_20260707_v1_20260707_153811",
        "calendar_universe": RESULTS_ROOT / "phase_kraken_tsmom_calendar_universe_cache_builder_20260707_v1_20260707_123020",
    }
    missing = [f"{name}:{root}" for name, root in roots.items() if not root.exists()]
    if missing:
        raise RuntimeError("missing full TSMOM cache dry-run reference roots: " + "; ".join(missing))
    return roots


def copy_reference_artifact(src: Path, dst: Path) -> dict[str, Any]:
    dst.parent.mkdir(parents=True, exist_ok=True)
    if src.exists():
        shutil.copy2(src, dst)
        return {
            "source_path": str(src),
            "run_path": str(dst),
            "exists": True,
            "size_bytes": int(dst.stat().st_size),
            "sha256": sha256_file(dst),
            "status": "pass",
        }
    return {
        "source_path": str(src),
        "run_path": str(dst),
        "exists": False,
        "size_bytes": 0,
        "sha256": "",
        "status": "fail",
    }


def stage_full_tsmom_v6_cache_dry_run(ctx: Context) -> None:
    t_start = time.time()
    ctx.notifier.send("TSMOM cache dry run started", f"Run root: {ctx.run_root}", level="info")
    roots = full_tsmom_v6_cache_dry_run_reference_roots()
    scaling_summary = read_json(roots["scaling_benchmark"] / "decision_summary.json", {})
    if scaling_summary.get("status") != "complete" or scaling_summary.get("next_operator_decision") != "proceed_to_full_tsmom_cache_dry_run_next":
        raise RuntimeError("scaling benchmark root does not allow full TSMOM cache dry run")
    selected_summary = read_json(roots["selected_key"] / "decision_summary.json", {})
    rank_summary = read_json(roots["rank_topn"] / "decision_summary.json", {})
    calendar_summary = read_json(roots["calendar_universe"] / "decision_summary.json", {})
    outcome_summary = read_json(roots["outcome_grouped"] / "decision_summary.json", {})
    for name, summary in [
        ("calendar_universe", calendar_summary),
        ("rank_topn", rank_summary),
        ("selected_key", selected_summary),
        ("outcome_grouped", outcome_summary),
    ]:
        if summary.get("status") != "complete":
            raise RuntimeError(f"reference root {name} is not complete")

    reference_rows = [{"reference_name": name, "root": str(root), "decision_status": read_json(root / "decision_summary.json", {}).get("status", ""), "status": "pass"} for name, root in roots.items()]
    write_csv(ctx.run_root / "preflight/cache_dry_run_reference_roots.csv", reference_rows)
    write_json(ctx.run_root / "performance/dry_run_heartbeat.json", {
        "run_root": str(ctx.run_root),
        "stage": "full-tsmom-v6-cache-dry-run",
        "status": "started",
        "ts_utc": utc_now(),
        "rss_bytes": current_rss_bytes(),
    })
    write_status(ctx, "running", "full-tsmom-v6-cache-dry-run")

    copied: list[dict[str, Any]] = []
    copy_plan = [
        (roots["calendar_universe"] / "cache/decision_calendar_manifest.csv", ctx.run_root / "cache/decision_calendar_manifest.csv"),
        (roots["calendar_universe"] / "cache/universe_membership_manifest.csv", ctx.run_root / "cache/universe_membership_manifest.csv"),
        (roots["calendar_universe"] / "audit/universe_membership_leak_audit.csv", ctx.run_root / "audit/universe_membership_leak_audit.csv"),
        (roots["calendar_universe"] / "audit/universe_dynamic_panel_audit.csv", ctx.run_root / "audit/universe_dynamic_panel_audit.csv"),
        (roots["rank_topn"] / "cache/tsmom_rank_feature_manifest.csv", ctx.run_root / "cache/tsmom_rank_feature_manifest.csv"),
        (roots["rank_topn"] / "cache/tsmom_topn_membership_manifest.csv", ctx.run_root / "cache/tsmom_topn_manifest.csv"),
        (roots["rank_topn"] / "cache/tsmom_topn_membership_manifest.csv", ctx.run_root / "cache/tsmom_topn_membership_manifest.csv"),
        (roots["rank_topn"] / "audit/rank_feature_leak_audit.csv", ctx.run_root / "audit/rank_feature_leak_audit.csv"),
        (roots["rank_topn"] / "audit/topn_dynamic_panel_audit.csv", ctx.run_root / "audit/topn_dynamic_panel_audit.csv"),
        (roots["rank_topn"] / "audit/topn_correctness_audit.csv", ctx.run_root / "audit/topn_correctness_audit.csv"),
        (roots["selected_key"] / "cache/tsmom_signal_mask_manifest.csv", ctx.run_root / "cache/tsmom_signal_mask_manifest.csv"),
        (roots["selected_key"] / "cache/tsmom_signal_manifest.csv", ctx.run_root / "cache/tsmom_signal_manifest.csv"),
        (roots["selected_key"] / "cache/parent_gate_manifest.csv", ctx.run_root / "cache/parent_gate_manifest.csv"),
        (roots["selected_key"] / "cache/funding_gate_manifest.csv", ctx.run_root / "cache/funding_gate_manifest.csv"),
        (roots["selected_key"] / "cache/vol_scale_manifest.csv", ctx.run_root / "cache/vol_scale_manifest.csv"),
        (roots["selected_key"] / "cache/selected_event_key_manifest.csv", ctx.run_root / "cache/selected_event_key_manifest.csv"),
        (roots["selected_key"] / "cache/selected_event_key_freeze_summary.json", ctx.run_root / "cache/selected_event_key_freeze_summary.json"),
        (roots["selected_key"] / "audit/decision_input_leak_audit.csv", ctx.run_root / "audit/decision_input_leak_audit.csv"),
        (roots["selected_key"] / "audit/selected_key_no_outcome_audit.csv", ctx.run_root / "audit/selected_key_no_outcome_audit.csv"),
        (roots["selected_key"] / "audit/outcome_before_freeze_blocked_audit.csv", ctx.run_root / "audit/outcome_before_freeze_blocked_audit.csv"),
        (roots["selected_key"] / "registry/tsmom_v6_mask_selected_key_registry.csv", ctx.run_root / "registry/tsmom_v6_cache_dry_run_registry.csv"),
        (roots["scaling_benchmark"] / "audit/full_gate_readiness.json", ctx.run_root / "audit/scaling_full_gate_readiness.json"),
        (roots["scaling_benchmark"] / "performance/full_v6_runtime_projection.md", ctx.run_root / "performance/scaling_full_v6_runtime_projection.md"),
    ]
    for src, dst in copy_plan:
        copied.append(copy_reference_artifact(src, dst))
    write_csv(ctx.run_root / "audit/cache_artifact_binding_audit.csv", copied)
    if any(str(r.get("status")) != "pass" for r in copied):
        raise RuntimeError("one or more required cache dry-run artifacts are missing")

    selected_keys = read_csv_safe(ctx.run_root / "cache/selected_event_key_manifest.csv")
    registry = read_csv_safe(ctx.run_root / "registry/tsmom_v6_cache_dry_run_registry.csv")
    if selected_keys.empty or registry.empty:
        raise RuntimeError("cache dry run requires non-empty selected keys and registry")
    recomputed_selected_hash = freeze_selected_event_keys(selected_keys.copy())[1]
    declared_selected_hash = str(selected_summary.get("selected_event_key_hash", ""))
    selected_hash_match = bool(recomputed_selected_hash == declared_selected_hash)
    selected_decision_ts = pd.to_datetime(selected_keys.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce")
    selected_post_2026 = int(selected_decision_ts.ge(PROTECTED_TS).sum())
    protected_audit = pd.DataFrame([
        {
            "check": "selected_decision_ts_lt_protected_boundary",
            "rows": int(len(selected_keys)),
            "violations": selected_post_2026,
            "status": "pass" if selected_post_2026 == 0 else "fail",
        },
        {
            "check": "selected_event_key_hash_matches_reference",
            "rows": int(len(selected_keys)),
            "declared_hash": declared_selected_hash,
            "recomputed_hash": recomputed_selected_hash,
            "violations": 0 if selected_hash_match else 1,
            "status": "pass" if selected_hash_match else "fail",
        },
    ])
    write_csv(ctx.run_root / "audit/protected_boundary_selected_key_audit.csv", protected_audit)
    write_json(ctx.run_root / "cache/selected_event_key_freeze_summary.json", {
        "selected_event_key_rows": int(len(selected_keys)),
        "selected_event_keys_hash": recomputed_selected_hash,
        "selected_event_keys_frozen": True,
        "selected_event_keys_frozen_before_outcome_cache": True,
        "outcome_cache_built": False,
        "aggregate_launched": False,
        "ts_utc": utc_now(),
    })

    leak_violations = 0
    for path in [
        ctx.run_root / "audit/universe_membership_leak_audit.csv",
        ctx.run_root / "audit/rank_feature_leak_audit.csv",
        ctx.run_root / "audit/decision_input_leak_audit.csv",
    ]:
        df = read_csv_safe(path)
        leak_violations += int(pd.to_numeric(df.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not df.empty else 1
    topn_dyn = read_csv_safe(ctx.run_root / "audit/topn_dynamic_panel_audit.csv")
    static_topn_failures = int(pd.to_numeric(topn_dyn.get("alphabetical_static_topn_failure_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not topn_dyn.empty else 1
    topn_corr = read_csv_safe(ctx.run_root / "audit/topn_correctness_audit.csv")
    topn_correctness_failures = int(topn_corr.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not topn_corr.empty else 1
    outcome_block = read_csv_safe(ctx.run_root / "audit/outcome_before_freeze_blocked_audit.csv")
    outcome_before_freeze_blocked = bool(parse_bool_series(outcome_block.get("blocked", pd.Series([False])), default=False).all()) if not outcome_block.empty else False
    source = inspect.getsource(stage_full_tsmom_v6_cache_dry_run)
    forbidden_outcome_build = "build_tsmom" + "_outcomes_from_frozen_keys("
    forbidden_full_agg = "stage_full" + "_tsmom_v6_accelerated_aggregate_run("
    forbidden_scalar = "aggregate_candidates" + "_memorysafe_to_dir("
    forbidden_calls_present = any(s in source for s in [forbidden_outcome_build, forbidden_full_agg, forbidden_scalar])
    peak_rss = int(max(
        current_rss_bytes(),
        max_rss_from_csv(roots["calendar_universe"] / "benchmark/calendar_universe_performance.csv"),
        max_rss_from_csv(roots["rank_topn"] / "benchmark/rank_topn_performance.csv"),
        max(max_rss_from_csv(roots["selected_key"] / "benchmark/mask_selected_key_performance.csv"), max_rss_from_csv(roots["selected_key"] / "performance/mask_selected_key_runtime_by_partition.csv")),
    ))
    soft = memory_soft_limit_bytes(ctx)
    runtime_seconds = float(time.time() - t_start)
    projected = read_json(roots["scaling_benchmark"] / "audit/full_gate_readiness.json", {})
    projected_cold = float(projected.get("projected_full_cold_runtime_seconds", 0) or 0)
    runtime_within_projection = bool(projected_cold <= 0 or runtime_seconds <= max(projected_cold * 1.25, 60.0))
    trace = pd.DataFrame([
        {"stage": "reference_root_validation", "runtime_seconds": 0.0, "rows": len(reference_rows), "rss_bytes": current_rss_bytes(), "cache_hit": True},
        {"stage": "artifact_binding", "runtime_seconds": runtime_seconds, "rows": len(copied), "rss_bytes": current_rss_bytes(), "cache_hit": True},
        {"stage": "selected_event_key_hash_recompute", "runtime_seconds": runtime_seconds, "rows": int(len(selected_keys)), "rss_bytes": current_rss_bytes(), "cache_hit": True},
    ])
    write_csv(ctx.run_root / "performance/cache_dry_run_trace.csv", trace)
    write_json(ctx.run_root / "performance/dry_run_heartbeat.json", {
        "run_root": str(ctx.run_root),
        "stage": "full-tsmom-v6-cache-dry-run",
        "status": "complete",
        "ts_utc": utc_now(),
        "rss_bytes": current_rss_bytes(),
        "selected_event_key_rows": int(len(selected_keys)),
    })
    pass_gate = (
        leak_violations == 0
        and static_topn_failures == 0
        and topn_correctness_failures == 0
        and selected_post_2026 == 0
        and selected_hash_match
        and outcome_before_freeze_blocked
        and not forbidden_calls_present
        and peak_rss < 6 * 1024**3
        and runtime_within_projection
    )
    next_decision = "build_tsmom_interval_outcome_cache_next" if pass_gate else "repair_full_tsmom_cache_dry_run_next"
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "aggregate_or_sweep_launched": False,
        "full_aggregate_launched": False,
        "prior_high_route_touched": False,
        "outcome_cache_built": False,
        "event_sampling_used": False,
        "event_caps_used": False,
        "materialization_launched": False,
        "validation_launched": False,
        "full_rows_planned": int(len(registry)),
        "full_definitions_planned": int(registry.get("candidate_definition_id", pd.Series(dtype=str)).astype(str).nunique()),
        "selected_event_keys_frozen": True,
        "selected_event_key_count": int(len(selected_keys)),
        "selected_event_key_hash": recomputed_selected_hash,
        "selected_event_key_hash_match": selected_hash_match,
        "leak_violations": int(leak_violations),
        "static_topn_failures": int(static_topn_failures),
        "topn_correctness_failures": int(topn_correctness_failures),
        "selected_post_2026_decisions": int(selected_post_2026),
        "outcome_before_freeze_blocked": outcome_before_freeze_blocked,
        "scalar_fallback_used": False,
        "forbidden_full_or_outcome_path_reference_present": forbidden_calls_present,
        "runtime_seconds": runtime_seconds,
        "runtime_within_scaling_projection_tolerance": runtime_within_projection,
        "scaling_projected_cold_runtime_seconds": projected_cold,
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": peak_rss < 6 * 1024**3,
        "telegram_status": ctx.notifier.status,
        "telegram_remote_available": ctx.notifier.remote_available,
        "telegram_alert_events_configured": ["start", "stage_transition", "completion", "failure"],
        "next_operator_decision": next_decision,
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "FULL_TSMOM_V6_CACHE_DRY_RUN_REPORT.md", "\n".join([
        "# Full TSMOM v6 Cache Dry Run Report",
        "",
        "This is a TSMOM-only full decision-input cache and selected-key dry run. It did not build interval outcomes, run aggregate evaluation, launch a sweep, run prior-high/reclaim, materialize candidates, run controls, run validation, or touch live-readiness work.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Full rows planned: `{summary['full_rows_planned']}`",
        f"Full definitions planned: `{summary['full_definitions_planned']}`",
        f"Selected event keys frozen: `{summary['selected_event_keys_frozen']}`",
        f"Selected event key count: `{summary['selected_event_key_count']}`",
        f"Leak violations: `{summary['leak_violations']}`",
        f"Static Top-N failures: `{summary['static_topn_failures']}`",
        f"Selected post-2026 decisions: `{summary['selected_post_2026_decisions']}`",
        f"Runtime seconds: `{summary['runtime_seconds']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Telegram status: `{summary['telegram_status']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "This is infrastructure output only, not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    ctx.notifier.send("TSMOM cache dry run complete", f"Status: {summary['status']}\nRun root: {ctx.run_root}\nSelected keys: {summary['selected_event_key_count']}", level="info" if pass_gate else "warning")
    write_status(ctx, summary["status"], "full-tsmom-v6-cache-dry-run")


def a1_manifest_path() -> Path:
    if not A1_COMPRESSION_CURATED_MANIFEST.exists():
        raise RuntimeError(f"missing A1/compression curated manifest: {A1_COMPRESSION_CURATED_MANIFEST}")
    return A1_COMPRESSION_CURATED_MANIFEST


def load_a1_compression_manifest() -> pd.DataFrame:
    df = read_csv_safe(a1_manifest_path())
    if df.empty:
        raise RuntimeError("A1/compression curated manifest is empty")
    required = {
        "candidate_definition_id",
        "definition_lane",
        "side",
        "decision_timeframe",
        "universe_policy",
        "leader_rank_metric",
        "leader_top_n",
        "parent_regime_gate",
        "funding_gate",
        "oi_handling",
        "breakout_trigger",
        "parameter_vector_hash",
        "parameter_vector_json",
    }
    missing = sorted(required - set(df.columns))
    if missing:
        raise RuntimeError(f"A1/compression manifest missing required fields: {missing}")
    return df.copy()


def a1_policy_hash(*parts: object, n: int = 24) -> str:
    return stable_hash("a1_compression_policy_v1_20260708", *parts, n=n)


def a1_universe_binding(defn: Mapping[str, Any]) -> dict[str, Any]:
    policy = str(defn.get("universe_policy", "") or "").strip()
    top_major_target_size = int(safe_float(defn.get("top_major_target_size", 12), 12))
    tier_ab_target_size = int(safe_float(defn.get("tier_ab_target_size", 40), 40))
    if policy in {"majors_only", "pit_liquidity_top_majors"}:
        return {
            "tsmom_policy": "pit_liquidity_top_majors",
            "top_major_target_size": top_major_target_size,
            "tier_ab_target_size": tier_ab_target_size,
            "binding_status": "active_pit_top_major_anchor_policy" if policy == "majors_only" else "active_idempotent_pit_top_major_policy",
            "cap_reason": "",
        }
    if policy in {"tier_ab_liquid_strict", "pit_liquidity_tier_ab"}:
        return {
            "tsmom_policy": "pit_liquidity_tier_ab",
            "top_major_target_size": top_major_target_size,
            "tier_ab_target_size": tier_ab_target_size,
            "binding_status": "active_pit_tier_ab_strict_policy" if policy == "tier_ab_liquid_strict" else "active_idempotent_pit_tier_ab_policy",
            "cap_reason": "",
        }
    if policy == "tier_ab_liquid_broad":
        return {
            "tsmom_policy": "pit_liquidity_tier_ab",
            "top_major_target_size": 12,
            "tier_ab_target_size": 80,
            "binding_status": "active_pit_tier_ab_broad_policy",
            "cap_reason": "",
        }
    if policy == "kraken_listed_liquid_tail_capped":
        return {
            "tsmom_policy": "pit_liquidity_tier_ab",
            "top_major_target_size": 12,
            "tier_ab_target_size": 120,
            "binding_status": "active_pit_liquid_tail_policy_capped",
            "cap_reason": "kraken_listed_liquid_tail_capped",
        }
    return {
        "tsmom_policy": "",
        "top_major_target_size": top_major_target_size,
        "tier_ab_target_size": tier_ab_target_size,
        "binding_status": "unknown_universe_policy_fail_closed",
        "cap_reason": f"unknown_universe_policy:{policy}",
    }


def a1_engine_candidate(defn: Mapping[str, Any], ctx: Context) -> dict[str, Any]:
    out = dict(defn)
    binding = a1_universe_binding(defn)
    if binding["binding_status"] == "unknown_universe_policy_fail_closed":
        raise RuntimeError(f"unknown A1 universe_policy fail-closed: {defn.get('universe_policy', '')}")
    out["a1_original_universe_policy"] = str(defn.get("universe_policy", ""))
    out["universe_policy"] = binding["tsmom_policy"]
    out["top_major_target_size"] = binding["top_major_target_size"]
    out["tier_ab_target_size"] = binding["tier_ab_target_size"]
    out["a1_universe_binding_status"] = binding["binding_status"]
    out["a1_universe_cap_reason"] = binding["cap_reason"]
    out["rank_metric"] = a1_rank_metric_base(defn.get("leader_rank_metric", "relative_strength_20d"))
    out["rank_top_n"] = int(safe_float(defn.get("leader_top_n", 0), 0))
    out["lookback_days"] = a1_rank_lookback_days(defn)
    out["lookback_bars"] = int(out["lookback_days"]) * (6 if str(defn.get("decision_timeframe", "")).lower() == "4h" else 1)
    out["bar_timeframe"] = str(defn.get("decision_timeframe", defn.get("bar_timeframe", "4h")) or "4h")
    out["rebalance_interval"] = out["bar_timeframe"]
    out["run_start_ts"] = str(ctx.start)
    out["run_end_ts"] = str(ctx.end)
    out["kraken_data_root"] = str(resolve_path(ctx.args.kraken_data_root))
    out["pit_panel_manifest_path"] = str(ctx.run_root / "universe/a1_full_panel_manifest.csv")
    out["family_engine_id"] = "a1_compression_liquid_continuation_engine_v1"
    out["engine_route"] = "explicit_a1_h06_h12_h13_cache_binding_no_legacy_text_inference"
    out["universe_policy_hash"] = str(defn.get("universe_policy_hash", "")) or a1_policy_hash("universe", defn.get("universe_policy", ""))
    out["rank_policy_hash"] = str(defn.get("rank_policy_hash", "")) or a1_policy_hash("rank", defn.get("leader_rank_metric", ""), defn.get("leader_top_n", ""))
    out["signal_policy_hash"] = a1_policy_hash("signal", defn.get("breakout_trigger", ""), defn.get("entry_policy_hash", ""), defn.get("compression_policy_hash", ""))
    out["parent_gate_policy_hash"] = str(defn.get("regime_policy_hash", "")) or a1_policy_hash("parent", defn.get("parent_regime_gate", ""))
    out["funding_gate_policy_hash"] = str(defn.get("funding_policy_hash", "")) or a1_policy_hash("funding", defn.get("funding_gate", ""))
    out["compression_policy_hash"] = str(defn.get("compression_policy_hash", "")) or a1_policy_hash("compression", defn.get("definition_lane", ""))
    out["entry_policy_hash"] = str(defn.get("entry_policy_hash", "")) or a1_policy_hash("entry", defn.get("entry_spec_id", ""))
    return out


def a1_rank_lookback_days(defn: Mapping[str, Any]) -> int:
    metric = str(defn.get("leader_rank_metric", "") or "")
    m = re.search(r"(\d+)d", metric)
    if m:
        return max(1, int(m.group(1)))
    return max(1, int(safe_float(defn.get("impulse_lookback_days", 20), 20)))


def a1_rank_metric_base(metric: object) -> str:
    text = str(metric or "relative_strength_20d").strip().lower()
    if "risk_adjusted" in text:
        return "risk_adjusted_return"
    if "prior_impulse" in text:
        return "trailing_return"
    return "relative_strength"


def a1_timeframe_rule(tf: object) -> tuple[str, int]:
    text = str(tf or "4h").strip().lower()
    if text in {"1d", "daily", "d"}:
        return "1D", 1
    if text in {"4h", "completed_4h"}:
        return "4h", 6
    raise RuntimeError(f"A1 rankable decision timeframe is unsupported: {tf}")


