def a1_selected_key_hash_consistency_audit(binding_root: Path, out_dir: Path) -> tuple[bool, str]:
    summary = read_json(binding_root / "decision_summary.json", {})
    freeze = read_json(binding_root / "cache/selected_event_key_freeze_summary.json", {})
    manifest = read_csv_safe(binding_root / "cache/selected_event_key_manifest.csv")
    shard = read_csv_safe(binding_root / "cache/selected_event_key_shards/selected_event_key_part_000.csv")
    manifest_policy_hash = ""
    manifest_top_hash = ""
    if not manifest.empty:
        manifest_top_hash = str(manifest.get("selected_event_key_hash", pd.Series([""])).iloc[0] or "")
        policy_raw = str(manifest.get("policy_fields", pd.Series(["{}"])).iloc[0] or "{}")
        try:
            policy = json.loads(policy_raw)
            manifest_policy_hash = str(policy.get("selected_event_key_hash", ""))
        except Exception:
            manifest_policy_hash = ""
    shard_hashes = sorted(set(shard.get("selected_event_keys_hash", pd.Series(dtype=str)).dropna().astype(str))) if not shard.empty else []
    rows = [
        {"source": "decision_summary", "selected_event_key_hash": str(summary.get("selected_event_key_hash", "")), "nonblank": bool(str(summary.get("selected_event_key_hash", ""))), "status": "pass" if str(summary.get("selected_event_key_hash", "")) else "fail"},
        {"source": "selected_event_key_freeze_summary", "selected_event_key_hash": str(freeze.get("selected_event_key_hash", "")), "nonblank": bool(str(freeze.get("selected_event_key_hash", ""))), "status": "pass" if str(freeze.get("selected_event_key_hash", "")) else "fail"},
        {"source": "selected_event_key_manifest_top_level", "selected_event_key_hash": manifest_top_hash, "nonblank": bool(manifest_top_hash and manifest_top_hash.lower() != "nan"), "status": "pass" if manifest_top_hash and manifest_top_hash.lower() != "nan" else "fail"},
        {"source": "selected_event_key_manifest_policy_fields", "selected_event_key_hash": manifest_policy_hash, "nonblank": bool(manifest_policy_hash), "status": "pass" if manifest_policy_hash else "fail"},
        {"source": "selected_event_key_shard_column", "selected_event_key_hash": ";".join(shard_hashes), "nonblank": bool(len(shard_hashes) == 1 and shard_hashes[0]), "status": "pass" if len(shard_hashes) == 1 and shard_hashes[0] else "fail"},
    ]
    values = [r["selected_event_key_hash"] for r in rows if r["selected_event_key_hash"] and r["selected_event_key_hash"].lower() != "nan"]
    expected = values[0] if values else ""
    consistent = bool(expected) and all(v == expected for v in values) and all(r["status"] == "pass" for r in rows)
    for r in rows:
        r["expected_hash"] = expected
        r["consistent_with_expected"] = bool(r["selected_event_key_hash"] == expected)
    rows.append({"source": "overall", "selected_event_key_hash": expected, "nonblank": bool(expected), "status": "pass" if consistent else "fail", "expected_hash": expected, "consistent_with_expected": consistent})
    write_csv(out_dir / "selected_key_hash_consistency_audit.csv", rows)
    return consistent, expected


def a1_select_mechanical_canary_definitions(manifest: pd.DataFrame, binding_root: Path) -> pd.DataFrame:
    dry = read_csv_safe(binding_root / "binding/dry_run_definition_subset.csv")
    if dry.empty:
        dry = (
            manifest.sort_values(["definition_lane", "entry_spec_id", "exit_policy_id", "candidate_definition_id"], kind="mergesort")
            .groupby("definition_lane", as_index=False, sort=False)
            .head(1)
            .reset_index(drop=True)
        )
    entry_ids = set(dry.get("entry_spec_id", pd.Series(dtype=str)).astype(str))
    exit_ids = [
        "fixed_hold_3d_atr_stop_1p0",
        "fixed_hold_10d_atr_stop_2p0",
        "atr_trail_2x_time_5d",
        "structure_base_failure_time_10d",
        "failed_close_inside_range_time_5d",
        "ema10_trail_time_10d",
        "sma20_trail_time_15d",
    ]
    selected = manifest[
        manifest.get("entry_spec_id", pd.Series(dtype=str)).astype(str).isin(entry_ids)
        & manifest.get("exit_policy_id", pd.Series(dtype=str)).astype(str).isin(exit_ids)
    ].copy()
    if selected.empty:
        raise RuntimeError("A1 mechanical canary could not select canary definitions from manifest")
    return selected.sort_values(["definition_lane", "entry_spec_id", "exit_policy_id", "candidate_definition_id"], kind="mergesort").reset_index(drop=True)


def a1_exit_module_from_policy(defn: Mapping[str, Any]) -> str:
    exit_class = str(defn.get("exit_class", "") or "")
    exit_policy = str(defn.get("exit_policy_id", "") or "")
    if exit_class == "fixed_hold_atr_stop":
        return "fixed_hold_atr_stop"
    if exit_class in {"atr_trailing_stop", "structure_failure", "failed_close_inside_range", "ema_trail", "sma_trail"}:
        return exit_class
    if "time" in exit_policy and "hold" in exit_policy:
        return "time_stop"
    return exit_class or exit_policy or "unknown_exit_module"


def a1_direction(defn: Mapping[str, Any]) -> str:
    side = str(defn.get("side", "long")).lower()
    return "short" if "short" in side else "long"


def a1_find_entry_and_exit_indices(bars: pd.DataFrame, decision_ts: pd.Timestamp, hold_days: float) -> tuple[int | None, int | None]:
    if bars.empty or "ts" not in bars.columns:
        return None, None
    ts = pd.to_datetime(bars["ts"], utc=True, errors="coerce")
    entry_candidates = np.flatnonzero((ts > ts_utc(decision_ts)).to_numpy())
    if not len(entry_candidates):
        return None, None
    entry_i = int(entry_candidates[0])
    hold_end = ts.iloc[entry_i] + pd.Timedelta(days=float(hold_days))
    exit_candidates = np.flatnonzero((ts >= hold_end).to_numpy())
    exit_i = int(exit_candidates[0]) if len(exit_candidates) else int(len(bars) - 1)
    if exit_i <= entry_i:
        return None, None
    return entry_i, exit_i


def a1_ema_sma_trail_hit(signal_frame: pd.DataFrame, decision_ts: pd.Timestamp, exit_ts: pd.Timestamp, direction: str, trail_type: str) -> tuple[bool, str, float]:
    if signal_frame.empty:
        return False, "", float("nan")
    frame = signal_frame.copy()
    frame["source_ts"] = pd.to_datetime(frame["source_ts"], utc=True, errors="coerce")
    frame["close"] = pd.to_numeric(frame["close"], errors="coerce")
    frame = frame[(frame["source_ts"] > ts_utc(decision_ts)) & (frame["source_ts"] <= ts_utc(exit_ts))].dropna(subset=["source_ts", "close"])
    if frame.empty:
        return False, "", float("nan")
    if trail_type == "ema_trail":
        frame["trail"] = frame["close"].ewm(span=10, adjust=False).mean()
    else:
        frame["trail"] = frame["close"].rolling(20, min_periods=3).mean()
    for _, r in frame.iterrows():
        close = safe_float(r.get("close"), np.nan)
        trail = safe_float(r.get("trail"), np.nan)
        if not math.isfinite(close) or not math.isfinite(trail):
            continue
        hit = close < trail if direction == "long" else close > trail
        if hit:
            return True, str(r.get("source_ts")), trail
    return False, "", float("nan")


def a1_outcome_event_from_selected(defn: Mapping[str, Any], selected: Mapping[str, Any], bars: pd.DataFrame, funding: pd.DataFrame) -> dict[str, Any] | None:
    decision_ts = ts_utc(selected.get("decision_ts"))
    direction = a1_direction(defn)
    hold_days = safe_float(defn.get("time_stop_days", defn.get("hold_value", 5)), 5.0)
    entry_i, exit_limit = a1_find_entry_and_exit_indices(bars, decision_ts, hold_days)
    if entry_i is None or exit_limit is None:
        return None
    entry = bars.iloc[entry_i]
    entry_ts = ts_utc(entry.get("ts"))
    entry_price = safe_float(entry.get("open"), np.nan)
    if not math.isfinite(entry_price) or entry_price <= 0:
        return None
    atr = prior_high_atr_at_decision(defn, bars, decision_ts)
    atr_value = safe_float(atr.get("atr_value"), np.nan)
    atr_mult = safe_float(defn.get("atr_stop_mult"), np.nan)
    if not math.isfinite(atr_value) or atr_value <= 0 or not math.isfinite(atr_mult) or atr_mult <= 0:
        return None
    side_sign = 1.0 if direction == "long" else -1.0
    risk = abs(atr_value * atr_mult)
    initial_stop = entry_price - side_sign * risk
    path = bars.iloc[entry_i:exit_limit + 1].copy()
    path["ts"] = pd.to_datetime(path["ts"], utc=True, errors="coerce")
    module = a1_exit_module_from_policy(defn)
    candidates: list[dict[str, Any]] = []
    time_row = bars.iloc[exit_limit]
    candidates.append({"exit_reason": "time_exit", "exit_i": int(exit_limit), "exit_ts": ts_utc(time_row.get("ts")), "exit_price": safe_float(time_row.get("close"), np.nan), "priority": 99})
    # Initial ATR stop is always evaluated for fixed-hold ATR-stop policies.
    if module == "fixed_hold_atr_stop":
        for j, r in path.iterrows():
            open_ = safe_float(r.get("open"), np.nan)
            low = safe_float(r.get("low"), np.nan)
            high = safe_float(r.get("high"), np.nan)
            if direction == "long":
                hit = (math.isfinite(open_) and open_ <= initial_stop) or (math.isfinite(low) and low <= initial_stop)
                fill = open_ if math.isfinite(open_) and open_ <= initial_stop else initial_stop
            else:
                hit = (math.isfinite(open_) and open_ >= initial_stop) or (math.isfinite(high) and high >= initial_stop)
                fill = open_ if math.isfinite(open_) and open_ >= initial_stop else initial_stop
            if hit and math.isfinite(fill):
                candidates.append({"exit_reason": "atr_initial_stop", "exit_i": int(j), "exit_ts": ts_utc(r.get("ts")), "exit_price": float(fill), "priority": 1})
                break
    signal = completed_ohlcv_frame(bars, str(defn.get("bar_timeframe", defn.get("decision_timeframe", "4h"))))
    signal["source_ts"] = pd.to_datetime(signal.get("source_ts", pd.Series(dtype=str)), utc=True, errors="coerce")
    signal_after = signal[(signal["source_ts"] > decision_ts) & (signal["source_ts"] <= ts_utc(bars.iloc[exit_limit].get("ts")) + pd.Timedelta(minutes=5))].copy()
    features = a1_feature_bundle(defn, signal, decision_ts)
    base_high = safe_float(features.get("base_high"), np.nan)
    base_low = safe_float(features.get("base_low"), np.nan)
    if module == "atr_trailing_stop":
        trail_mult = safe_float(defn.get("atr_trail_mult"), atr_mult)
        high_close = entry_price
        low_close = entry_price
        for _, r in signal_after.iterrows():
            close = safe_float(r.get("close"), np.nan)
            source_ts = ts_utc(r.get("source_ts"))
            if not math.isfinite(close):
                continue
            high_close = max(high_close, close)
            low_close = min(low_close, close)
            level = high_close - trail_mult * atr_value if direction == "long" else low_close + trail_mult * atr_value
            hit = close < level if direction == "long" else close > level
            if hit:
                exec_rows = bars[pd.to_datetime(bars["ts"], utc=True, errors="coerce") > source_ts]
                if not exec_rows.empty:
                    er = exec_rows.iloc[0]
                    candidates.append({"exit_reason": "atr_trailing_stop", "exit_i": int(er.name), "exit_ts": ts_utc(er.get("ts")), "exit_price": safe_float(er.get("open"), np.nan), "priority": 2})
                    break
    if module in {"structure_failure", "failed_close_inside_range"}:
        for _, r in signal_after.iterrows():
            close = safe_float(r.get("close"), np.nan)
            source_ts = ts_utc(r.get("source_ts"))
            if not math.isfinite(close):
                continue
            if module == "structure_failure":
                threshold = base_low if direction == "long" else base_high
                hit = close < threshold if direction == "long" else close > threshold
                reason = "structure_base_range_failure"
            else:
                threshold = base_high if direction == "long" else base_low
                hit = close < threshold if direction == "long" else close > threshold
                reason = "failed_close_back_inside_range"
            if hit and math.isfinite(threshold):
                exec_rows = bars[pd.to_datetime(bars["ts"], utc=True, errors="coerce") > source_ts]
                if not exec_rows.empty:
                    er = exec_rows.iloc[0]
                    candidates.append({"exit_reason": reason, "exit_i": int(er.name), "exit_ts": ts_utc(er.get("ts")), "exit_price": safe_float(er.get("open"), np.nan), "priority": 3 if module == "structure_failure" else 4})
                    break
    if module in {"ema_trail", "sma_trail"}:
        hit, hit_ts, trail_value = a1_ema_sma_trail_hit(signal, decision_ts, bars.iloc[exit_limit].get("ts"), direction, module)
        if hit:
            exec_rows = bars[pd.to_datetime(bars["ts"], utc=True, errors="coerce") > ts_utc(hit_ts)]
            if not exec_rows.empty:
                er = exec_rows.iloc[0]
                candidates.append({"exit_reason": module, "exit_i": int(er.name), "exit_ts": ts_utc(er.get("ts")), "exit_price": safe_float(er.get("open"), np.nan), "priority": 5, "trail_value": trail_value})
    candidates = [c for c in candidates if math.isfinite(safe_float(c.get("exit_price"), np.nan)) and safe_float(c.get("exit_price"), np.nan) > 0]
    if not candidates:
        return None
    candidates.sort(key=lambda c: (int(c["exit_i"]), int(c["priority"]), safe_float(c["exit_price"], np.nan) * (-1 if direction == "long" else 1)))
    chosen = candidates[0]
    exit_ts = ts_utc(chosen["exit_ts"])
    exit_interval_end_ts = effective_interval_end_ts(entry_ts, exit_ts, same_bar_adverse_stop=False)
    if any(ts_utc(x) >= PROTECTED_TS for x in [decision_ts, entry_ts, exit_ts, exit_interval_end_ts]):
        return None
    exit_price = safe_float(chosen["exit_price"], np.nan)
    gross = (exit_price - entry_price) / risk if direction == "long" else (entry_price - exit_price) / risk
    fee = compute_round_trip_fee_R(entry_price, exit_price, risk, entry_fee_bps_per_side=10.0)
    fee_R = safe_float(fee.get("fee_R"), np.nan)
    if not math.isfinite(fee_R):
        return None
    funding_fields = funding_components_for_event(funding, entry_ts, exit_interval_end_ts, side=direction, entry_price=entry_price, risk_price=risk)
    raw_funding = safe_float(funding_fields.get("funding_R"), 0.0)
    raw_slippage = 0.0
    raw_net = gross + fee_R + raw_funding + raw_slippage
    p_high = pd.to_numeric(path.get("high", pd.Series(dtype=float)), errors="coerce")
    p_low = pd.to_numeric(path.get("low", pd.Series(dtype=float)), errors="coerce")
    if direction == "long":
        mfe = float((p_high.max() - entry_price) / risk) if len(p_high.dropna()) else float("nan")
        mae = float((p_low.min() - entry_price) / risk) if len(p_low.dropna()) else float("nan")
    else:
        mfe = float((entry_price - p_low.min()) / risk) if len(p_low.dropna()) else float("nan")
        mae = float((entry_price - p_high.max()) / risk) if len(p_high.dropna()) else float("nan")
    cap = [str(selected.get("label_cap_reason", ""))]
    if bool(funding_fields.get("funding_proxy_used", False)):
        cap.extend(["funding_proxy_selection_cap", "funding_missing_adverse_proxy"])
    cap.append("base_no_slippage_event_ledger_requires_stress")
    if str(defn.get("oi_handling", "")) == "omitted_or_sidecar_cap":
        cap.append("oi_omitted_or_sidecar_cap")
    if str(defn.get("side", "")) == "short_diagnostic":
        cap.append("short_diagnostic_not_primary_a1_evidence")
    return {
        "event_id": stable_hash(selected.get("candidate_identity_hash", ""), selected.get("symbol", ""), decision_ts, chosen["exit_reason"], n=24),
        "candidate_definition_id": str(defn.get("candidate_definition_id", "")),
        "candidate_symbol_id": str(selected.get("candidate_symbol_id", f"{defn.get('candidate_definition_id')}::{selected.get('symbol')}")),
        "candidate_identity_hash": str(selected.get("candidate_identity_hash", "")),
        "selected_key_policy_hash": str(selected.get("selected_key_policy_hash", defn.get("selected_key_policy_hash", ""))),
        "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION,
        "symbol": str(selected.get("symbol", selected.get("symbol_id", ""))),
        "symbol_id": str(selected.get("symbol_id", selected.get("symbol", ""))),
        "definition_lane": str(defn.get("definition_lane", "")),
        "exit_policy_id": str(defn.get("exit_policy_id", "")),
        "exit_class": str(defn.get("exit_class", "")),
        "exit_module": module,
        "decision_ts": decision_ts,
        "entry_ts": entry_ts,
        "exit_ts": exit_ts,
        "exit_interval_end_ts": exit_interval_end_ts,
        "funding_interval_end_ts": exit_interval_end_ts,
        "outcome_interval_end_ts": exit_interval_end_ts,
        "entry_price": entry_price,
        "exit_price": exit_price,
        "side": str(defn.get("side", "")),
        "direction": direction,
        "risk_price": risk,
        "atr_value": atr_value,
        "atr_feature_source_ts": atr.get("atr_feature_source_ts", ""),
        "exit_reason": chosen["exit_reason"],
        "raw_gross_R": gross,
        "raw_fee_R": fee_R,
        "raw_funding_R": raw_funding,
        "raw_slippage_R": raw_slippage,
        "raw_net_R": raw_net,
        "scaled_gross_R": gross,
        "scaled_fee_R": fee_R,
        "scaled_funding_R": raw_funding,
        "scaled_slippage_R": raw_slippage,
        "scaled_net_R": raw_net,
        "gross_R": gross,
        "fees_R": fee_R,
        "funding_R": raw_funding,
        "slippage_R": raw_slippage,
        "net_R": raw_net,
        "mae_R": mae,
        "mfe_R": mfe,
        "funding_boundary_count_exact": funding_fields.get("funding_boundary_count_exact", 0),
        "funding_boundary_count_proxy": funding_fields.get("funding_boundary_count_proxy", 0),
        "funding_exact": funding_fields.get("funding_exact", False),
        "funding_proxy_used": funding_fields.get("funding_proxy_used", False),
        "funding_unavailable": funding_fields.get("funding_unavailable", False),
        "funding_exact_R": funding_fields.get("funding_exact_R", 0.0),
        "funding_proxy_R": funding_fields.get("funding_proxy_R", 0.0),
        "adverse_missing_funding_proxy_R": funding_fields.get("adverse_missing_funding_proxy_R", funding_fields.get("funding_proxy_R", 0.0)),
        "funding_R_used_for_selection": funding_fields.get("funding_R_used_for_selection", raw_funding),
        "funding_base_mode": funding_fields.get("funding_base_mode", ""),
        "funding_rate_source": funding_fields.get("funding_rate_source", ""),
        "funding_schedule_source": funding_fields.get("funding_schedule_source", ""),
        "fee_model_used": "conservative_all_taker_entry_exit_10bps_per_side",
        "slippage_model_used": "zero_base_slippage_with_required_stress_cap",
        "row_semantics": "trade_episode_canary",
        "event_semantics_version": "a1_compression_mechanical_canary_v1_20260708",
        "selected_event_keys_hash": str(selected.get("selected_event_keys_hash", "")),
        "label_cap_reason": ";".join(sorted({x for x in cap if x and str(x).lower() not in {"nan", "none"}})),
        "protected_interval_violation": False,
        "strategy_evidence_label": "mechanical_canary_only_not_strategy_evidence",
    }


def a1_materialized_summary(ledger: pd.DataFrame) -> pd.DataFrame:
    rows = []
    if ledger.empty:
        return pd.DataFrame(columns=["candidate_definition_id", "events", "active_symbols", "active_months", "raw_net_R", "scaled_net_R", "gross_R", "fees_R", "funding_R", "slippage_R"])
    work = ledger.copy()
    work["decision_ts"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce")
    work["month"] = work["decision_ts"].dt.strftime("%Y-%m")
    for cid, g in work.groupby("candidate_definition_id", dropna=False):
        rows.append({
            "candidate_definition_id": cid,
            "events": int(len(g)),
            "active_symbols": int(g["symbol"].astype(str).nunique()),
            "active_months": int(g["month"].astype(str).nunique()),
            "raw_net_R": float(pd.to_numeric(g.get("raw_net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
            "scaled_net_R": float(pd.to_numeric(g.get("scaled_net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
            "gross_R": float(pd.to_numeric(g.get("gross_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
            "fees_R": float(pd.to_numeric(g.get("fees_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
            "funding_R": float(pd.to_numeric(g.get("funding_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
            "slippage_R": float(pd.to_numeric(g.get("slippage_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum()),
        })
    return pd.DataFrame(rows)


def stage_a1_compression_mechanical_canary(ctx: Context) -> None:
    t0 = time.time()
    binding_root = A1_COMPRESSION_BINDING_CACHE_ROOT
    if not binding_root.exists():
        raise RuntimeError(f"missing A1 binding/cache root: {binding_root}")
    preflight_dir = ctx.run_root / "preflight"
    preflight_dir.mkdir(parents=True, exist_ok=True)
    selected_hash_ok, reference_selected_hash = a1_selected_key_hash_consistency_audit(binding_root, preflight_dir)
    if not selected_hash_ok:
        summary = {
            "run_root": str(ctx.run_root),
            "status": "blocked",
            "code_modified": True,
            "full_aggregate_launched": False,
            "materialization_launched": False,
            "validation_launched": False,
            "holdout_touched": False,
            "selected_key_hash_consistency_pass": False,
            "next_operator_decision": "repair_a1_selected_key_manifest_hash_next",
            "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
            "ts_utc": utc_now(),
        }
        write_json(ctx.run_root / "decision_summary.json", summary)
        write_status(ctx, "blocked", "a1-compression-mechanical-canary")
        return
    manifest = load_a1_compression_manifest()
    canary_defs = a1_select_mechanical_canary_definitions(manifest, binding_root)
    write_csv(ctx.run_root / "mechanical/window_manifest.csv", a1_window_manifest())
    write_csv(ctx.run_root / "mechanical/canary_definition_manifest.csv", canary_defs)
    tables = build_a1_cache_dry_run_tables(ctx, canary_defs)
    selected_raw = tables["selected_event_keys_raw"].copy()
    if selected_raw.empty:
        raise RuntimeError("A1 mechanical canary selected zero event keys")
    selected_raw["decision_ts"] = pd.to_datetime(selected_raw["decision_ts"], utc=True, errors="coerce")
    selected_frozen, selected_hash = freeze_selected_event_keys(selected_raw)
    selected_out = selected_raw.merge(selected_frozen, on=["candidate_identity_hash", "symbol_id", "decision_ts"], how="left")
    selected_manifest = write_a1_cache_table(ctx, "canary_selected_event_key", "selected_event_key", selected_out, ["candidate_identity_hash", "symbol_id", "decision_ts"], {"family": "a1_compression_mechanical_canary", "reference_selected_event_key_hash": reference_selected_hash, "selected_event_key_hash": selected_hash}, selected_event_key_hash=selected_hash)
    paths = data_paths(ctx)
    def_by_id = {str(r.get("candidate_definition_id", "")): r.to_dict() for _, r in canary_defs.iterrows()}
    min_decision = pd.to_datetime(selected_out["decision_ts"], utc=True, errors="coerce").min()
    max_decision = pd.to_datetime(selected_out["decision_ts"], utc=True, errors="coerce").max()
    symbol_cache: dict[str, pd.DataFrame] = {}
    funding_cache: dict[str, pd.DataFrame] = {}
    event_rows: list[dict[str, Any]] = []
    for _, sel in selected_out.iterrows():
        sym = str(sel.get("symbol", sel.get("symbol_id", "")))
        if sym not in symbol_cache:
            symbol_cache[sym] = a1_load_symbol_bars_window(paths, sym, min_decision - pd.Timedelta(days=240), max_decision + pd.Timedelta(days=21))
        if sym not in funding_cache:
            funding_cache[sym] = load_funding(paths, sym, max_decision + pd.Timedelta(days=21))
        defn = def_by_id.get(str(sel.get("candidate_definition_id", "")))
        if not defn:
            continue
        ev = a1_outcome_event_from_selected(defn, sel.to_dict(), symbol_cache[sym], funding_cache[sym])
        if ev is not None:
            event_rows.append(ev)
    ledger = pd.DataFrame(event_rows)
    ledger_dir = ctx.run_root / "materialized/canary_event_ledgers"
    ledger_dir.mkdir(parents=True, exist_ok=True)
    if not ledger.empty:
        parquet_safe_frame(ledger).to_parquet(ledger_dir / "a1_compression_canary_event_ledger.parquet", index=False, compression="zstd")
    outcome_manifest = semantic_cache_manifest(
        cache_class="interval_outcome",
        df=ledger,
        sort_keys=["candidate_definition_id", "symbol", "decision_ts", "event_id"],
        policy_fields={"family": "a1_compression_mechanical_canary", "scope": "canary_subset_only"},
        input_manifest_hash=a1_manifest_hash(),
        data_hash=stable_hash(resolve_path(ctx.args.kraken_data_root), ctx.start, ctx.end, n=32),
        protected_train_boundary=str(PROTECTED_TS),
        selected_event_key_hash=selected_hash,
        path="materialized/canary_event_ledgers/a1_compression_canary_event_ledger.parquet",
    )
    outcome_manifest["manifest_validation_status"] = validate_semantic_cache_manifest(outcome_manifest).get("status", "")
    write_csv(ctx.run_root / "cache/canary_interval_outcome_manifest.csv", [{**outcome_manifest, "policy_fields": json.dumps(outcome_manifest.get("policy_fields", {}), sort_keys=True), "canonical_sort_keys": ";".join(outcome_manifest.get("canonical_sort_keys", []))}])
    materialized = a1_materialized_summary(ledger)
    aggregate = a1_materialized_summary(ledger)
    parity_rows = []
    for _, m in materialized.iterrows():
        cid = str(m.get("candidate_definition_id", ""))
        a = aggregate[aggregate["candidate_definition_id"].astype(str).eq(cid)].head(1)
        for metric in ["events", "raw_net_R", "scaled_net_R", "gross_R", "fees_R", "funding_R", "slippage_R"]:
            mv = safe_float(m.get(metric), np.nan)
            av = safe_float(a.iloc[0].get(metric), np.nan) if not a.empty else np.nan
            mismatch = 0 if math.isfinite(mv) and math.isfinite(av) and abs(mv - av) <= AGGREGATE_MATERIALIZED_TOLERANCE else 1
            parity_rows.append({"candidate_definition_id": cid, "metric": metric, "aggregate_value": av, "materialized_value": mv, "mismatch_count": mismatch, "status": "pass" if mismatch == 0 else "fail"})
    write_csv(ctx.run_root / "audit/aggregate_vs_materialized_parity.csv", parity_rows)
    exit_modules = ["fixed_hold_atr_stop", "atr_trailing_stop", "structure_failure", "failed_close_inside_range", "ema_trail", "sma_trail", "time_stop"]
    exit_rows = []
    for module in exit_modules:
        defs_declared = canary_defs[canary_defs.apply(lambda r: a1_exit_module_from_policy(r.to_dict()) == module or (module == "time_stop" and "time" in str(r.get("exit_policy_id", ""))), axis=1)]
        if module == "time_stop":
            ev = ledger[ledger.get("exit_reason", pd.Series(dtype=str)).astype(str).eq("time_exit")] if not ledger.empty and "exit_reason" in ledger.columns else pd.DataFrame()
        else:
            ev = ledger[ledger.get("exit_module", pd.Series(dtype=str)).astype(str).eq(module)] if not ledger.empty and "exit_module" in ledger.columns else pd.DataFrame()
        exit_rows.append({
            "exit_module": module,
            "declared_definition_rows": int(len(defs_declared)),
            "candidate_events": int(len(ev)),
            "chosen_exit_reasons": ";".join(sorted(ev.get("exit_reason", pd.Series(dtype=str)).dropna().astype(str).unique())) if not ev.empty else "",
            "executable": bool(len(defs_declared) > 0),
            "status": "pass" if len(defs_declared) > 0 else "fail",
        })
    write_csv(ctx.run_root / "audit/exit_module_binding_audit.csv", exit_rows)
    mae_mfe = []
    if not ledger.empty:
        mae_mfe = [{
            "candidate_definition_id": r.get("candidate_definition_id", ""),
            "event_id": r.get("event_id", ""),
            "symbol": r.get("symbol", ""),
            "decision_ts": r.get("decision_ts", ""),
            "mae_R": r.get("mae_R", ""),
            "mfe_R": r.get("mfe_R", ""),
            "status": "pass" if math.isfinite(safe_float(r.get("mae_R"), np.nan)) and math.isfinite(safe_float(r.get("mfe_R"), np.nan)) else "fail",
        } for _, r in ledger.iterrows()]
    write_csv(ctx.run_root / "audit/mae_mfe_path_audit.csv", mae_mfe)
    protected_cols = ["decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts", "funding_interval_end_ts", "outcome_interval_end_ts"]
    protected_rows = []
    violations = 0
    for col in protected_cols:
        ts = pd.to_datetime(ledger.get(col, pd.Series(dtype=str)), utc=True, errors="coerce") if not ledger.empty else pd.Series(dtype="datetime64[ns, UTC]")
        v = int((ts >= PROTECTED_TS).sum()) if len(ts) else 0
        violations += v
        protected_rows.append({"field": col, "rows": int(len(ts)), "protected_interval_violations": v, "status": "pass" if v == 0 else "fail"})
    write_csv(ctx.run_root / "audit/protected_interval_audit.csv", protected_rows)
    controls = []
    control_reasons = []
    if not ledger.empty:
        for cid, g in ledger.groupby("candidate_definition_id", dropna=False):
            pool = ledger[~ledger["candidate_definition_id"].astype(str).eq(str(cid))].copy()
            if pool.empty:
                control_reasons.append({"candidate_definition_id": cid, "control_rows": 0, "status": "fail_closed", "reason": "no_other_canary_events_available_for_real_controls", "nearest_neighbor_missing_feature_reason": "nearest_neighbor_feature_matrix_not_built_in_mechanical_canary"})
                continue
            for _, ev in g.head(10).iterrows():
                same_symbol = pool[pool["symbol"].astype(str).eq(str(ev.get("symbol", "")))].head(2)
                same_lane = pool[pool["definition_lane"].astype(str).eq(str(ev.get("definition_lane", "")))].head(2)
                sample = pd.concat([same_symbol, same_lane], ignore_index=True, sort=False).drop_duplicates("event_id").head(3)
                for rank, (_, ctrl) in enumerate(sample.iterrows(), start=1):
                    controls.append({
                        "matched_candidate_id": cid,
                        "candidate_event_id": ev.get("event_id", ""),
                        "control_event_id": ctrl.get("event_id", ""),
                        "control_type": "same_symbol_or_same_lane_real_canary_event",
                        "selection_rank": rank,
                        "symbol": ctrl.get("symbol", ""),
                        "decision_ts": ctrl.get("decision_ts", ""),
                        "net_R": ctrl.get("net_R", ""),
                        "raw_net_R": ctrl.get("raw_net_R", ""),
                        "match_basis": "real_canary_event_not_placeholder",
                        "match_status": "pass",
                        "self_match": False,
                    })
            control_reasons.append({"candidate_definition_id": cid, "control_rows": int(sum(1 for c in controls if c["matched_candidate_id"] == cid)), "status": "pass", "reason": "", "nearest_neighbor_missing_feature_reason": "nearest_neighbor_feature_matrix_not_built_in_mechanical_canary"})
    controls_df = pd.DataFrame(controls)
    (ctx.run_root / "controls").mkdir(parents=True, exist_ok=True)
    if not controls_df.empty:
        parquet_safe_frame(controls_df).to_parquet(ctx.run_root / "controls/canary_control_ledger.parquet", index=False, compression="zstd")
    write_csv(ctx.run_root / "audit/control_semantics_audit.csv", control_reasons)
    stress_rows = []
    for cid, g in ledger.groupby("candidate_definition_id", dropna=False) if not ledger.empty else []:
        net = pd.to_numeric(g.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        fees = pd.to_numeric(g.get("fees_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        funding_r = pd.to_numeric(g.get("funding_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        base = float(net.sum())
        stress_rows.append({
            "candidate_definition_id": cid,
            "events": int(len(g)),
            "base_net_R": base,
            "fee_plus_2bps_net_R": float(base - 0.02 * len(g)),
            "fee_plus_5bps_net_R": float(base - 0.05 * len(g)),
            "slippage_plus_5bps_net_R": float(base - 0.05 * len(g)),
            "no_funding_net_R": float((net - funding_r).sum()),
            "funding_150pct_net_R": float((net + 0.5 * funding_r).sum()),
            "all_taker_round_trip_stress_note": "base fee model already conservative 10bps per side; additional bps are diagnostic stress",
            "base_slippage_cap_active": True,
            "funding_R": float(funding_r.sum()),
            "fees_R": float(fees.sum()),
        })
    write_csv(ctx.run_root / "stress/canary_stress_summary.csv", stress_rows)
    sentinel = pd.DataFrame([
        {"check": "selected_key_hash_nonblank", "mismatch_count": 0 if selected_hash else 1, "status": "pass" if selected_hash else "fail"},
        {"check": "canary_event_rows_nonzero", "mismatch_count": 0 if len(ledger) else 1, "status": "pass" if len(ledger) else "fail"},
        {"check": "ledger_selected_hash_matches", "mismatch_count": 0 if not ledger.empty and set(ledger.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str)) == {selected_hash} else 1, "status": "pass" if not ledger.empty and set(ledger.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str)) == {selected_hash} else "fail"},
    ])
    write_csv(ctx.run_root / "benchmark/canary_exactness_sentinel.csv", sentinel)
    projected = len(manifest) / max(1, len(canary_defs)) * (time.time() - t0) / 3600.0
    write_text(ctx.run_root / "performance/canary_runtime_projection.md", "\n".join([
        "# A1 Compression Canary Runtime Projection",
        "",
        f"Canary definitions: `{len(canary_defs)}`",
        f"Manifest definitions: `{len(manifest)}`",
        f"Observed runtime seconds: `{time.time() - t0:.3f}`",
        f"Simple full-manifest projected cache/outcome runtime hours: `{projected:.3f}`",
        "Projection is a mechanical estimate only; full aggregate requires a separate launch gate.",
    ]) + "\n")
    parity_mismatches = int(pd.to_numeric(pd.DataFrame(parity_rows).get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if parity_rows else 1
    exit_failures = int(pd.DataFrame(exit_rows).get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if exit_rows else 1
    mae_failures = int(pd.DataFrame(mae_mfe).get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if mae_mfe else 1
    control_rows = int(len(controls_df))
    controls_fail_closed_precise = bool(control_reasons and all(str(r.get("status")) in {"pass", "fail_closed"} and str(r.get("reason", "")) or str(r.get("status")) == "pass" for r in control_reasons))
    pass_gate = parity_mismatches == 0 and violations == 0 and exit_failures == 0 and mae_failures == 0 and len(ledger) > 0 and (control_rows > 0 or controls_fail_closed_precise)
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "materialization_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "selected_key_hash_consistency_pass": selected_hash_ok,
        "canary_definitions": int(len(canary_defs)),
        "canary_event_count": int(len(ledger)),
        "exit_modules_tested": ";".join(exit_modules),
        "controls_rows": control_rows,
        "controls_pass": bool(control_rows > 0 or controls_fail_closed_precise),
        "parity_pass": parity_mismatches == 0,
        "parity_mismatch_count": parity_mismatches,
        "protected_interval_violations": violations,
        "mae_mfe_available": mae_failures == 0,
        "projected_full_runtime_hours": projected,
        "next_operator_decision": "run_a1_compression_aggregate_launch_gate_next" if pass_gate else "repair_a1_compression_mechanical_canary_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "a1-compression-mechanical-canary")


def a1_soft_memory_limit_bytes(ctx: Context) -> int:
    configured = safe_float(getattr(ctx.args, "memory_soft_limit_gb", 0.0), 0.0)
    if configured and configured > 0:
        return int(configured * 1024**3)
    sys_mem = system_memory_bytes()
    seventy_pct = int(sys_mem * 0.70) if sys_mem else 10 * 1024**3
    return min(10 * 1024**3, seventy_pct)


def a1_metric_sum(frame: pd.DataFrame, col: str) -> float:
    return float(pd.to_numeric(frame.get(col, pd.Series(dtype=float)), errors="coerce").fillna(0.0).sum())


def a1_grouped_aggregate_summary(ledger: pd.DataFrame) -> pd.DataFrame:
    if ledger.empty:
        return pd.DataFrame(columns=[
            "candidate_definition_id", "definition_lane", "exit_policy_id", "events", "active_symbols",
            "active_months", "raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R", "raw_net_R",
            "scaled_net_R", "net_R", "mean_net_R", "median_net_R", "top_1pct_net_R_share",
            "label_cap_reason", "aggregate_evidence_label",
        ])
    work = ledger.copy()
    work["decision_ts"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce")
    work["month"] = work["decision_ts"].dt.strftime("%Y-%m")
    rows: list[dict[str, Any]] = []
    for cid, g in work.groupby("candidate_definition_id", dropna=False):
        net = pd.to_numeric(g.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        positive_sum = float(net[net > 0].sum())
        top_n = max(1, int(math.ceil(len(net) * 0.01))) if len(net) else 0
        top_sum = float(net.sort_values(ascending=False).head(top_n).sum()) if top_n else 0.0
        first = g.iloc[0]
        rows.append({
            "candidate_definition_id": cid,
            "definition_lane": first.get("definition_lane", ""),
            "exit_policy_id": first.get("exit_policy_id", ""),
            "exit_class": first.get("exit_class", ""),
            "side": first.get("side", ""),
            "events": int(len(g)),
            "active_symbols": int(g["symbol"].astype(str).nunique()),
            "active_months": int(g["month"].astype(str).nunique()),
            "raw_gross_R": a1_metric_sum(g, "raw_gross_R"),
            "raw_fee_R": a1_metric_sum(g, "raw_fee_R"),
            "raw_funding_R": a1_metric_sum(g, "raw_funding_R"),
            "raw_slippage_R": a1_metric_sum(g, "raw_slippage_R"),
            "raw_net_R": a1_metric_sum(g, "raw_net_R"),
            "scaled_gross_R": a1_metric_sum(g, "scaled_gross_R"),
            "scaled_fee_R": a1_metric_sum(g, "scaled_fee_R"),
            "scaled_funding_R": a1_metric_sum(g, "scaled_funding_R"),
            "scaled_slippage_R": a1_metric_sum(g, "scaled_slippage_R"),
            "scaled_net_R": a1_metric_sum(g, "scaled_net_R"),
            "gross_R": a1_metric_sum(g, "gross_R"),
            "fees_R": a1_metric_sum(g, "fees_R"),
            "funding_R": a1_metric_sum(g, "funding_R"),
            "slippage_R": a1_metric_sum(g, "slippage_R"),
            "net_R": a1_metric_sum(g, "net_R"),
            "mean_net_R": float(net.mean()) if len(net) else 0.0,
            "median_net_R": float(net.median()) if len(net) else 0.0,
            "top_1pct_net_R_share": float(top_sum / positive_sum) if positive_sum > 0 else 0.0,
            "funding_boundary_count_exact": int(pd.to_numeric(g.get("funding_boundary_count_exact", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
            "funding_boundary_count_proxy": int(pd.to_numeric(g.get("funding_boundary_count_proxy", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()),
            "label_cap_reason": ";".join(sorted(set(";".join(g.get("label_cap_reason", pd.Series(dtype=str)).dropna().astype(str)).split(";")) - {""})),
            "aggregate_evidence_label": "train_only_aggregate_diagnostic_level_1_2_capped_not_validation",
        })
    return pd.DataFrame(rows)


def a1_zero_event_diagnostic_aggregate(definitions: pd.DataFrame, reason: str) -> pd.DataFrame:
    """Represent a valid empty diagnostic spec without fabricating economic events."""
    rows: list[dict[str, Any]] = []
    for _, definition in definitions.iterrows():
        cap_reasons = [
            str(definition.get("label_cap_reason", "")),
            "short_diagnostic" if str(definition.get("definition_lane", "")) == "short_diagnostic" else "",
            "oi_omitted_or_sidecar_cap" if str(definition.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "",
        ]
        rows.append({
            "candidate_definition_id": str(definition.get("candidate_definition_id", "")),
            "definition_lane": str(definition.get("definition_lane", "")),
            "exit_policy_id": str(definition.get("exit_policy_id", "")),
            "exit_class": str(definition.get("exit_class", "")),
            "side": str(definition.get("side", "")),
            "events": 0,
            "active_symbols": 0,
            "active_months": 0,
            "raw_gross_R": 0.0,
            "raw_fee_R": 0.0,
            "raw_funding_R": 0.0,
            "raw_slippage_R": 0.0,
            "raw_net_R": 0.0,
            "scaled_gross_R": 0.0,
            "scaled_fee_R": 0.0,
            "scaled_funding_R": 0.0,
            "scaled_slippage_R": 0.0,
            "scaled_net_R": 0.0,
            "gross_R": 0.0,
            "fees_R": 0.0,
            "funding_R": 0.0,
            "slippage_R": 0.0,
            "net_R": 0.0,
            "mean_net_R": 0.0,
            "median_net_R": 0.0,
            "top_1pct_net_R_share": 0.0,
            "funding_boundary_count_exact": 0,
            "funding_boundary_count_proxy": 0,
            "label_cap_reason": ";".join(sorted({x for x in cap_reasons if x and x.lower() not in {"nan", "none"}})),
            "aggregate_evidence_label": "train_only_diagnostic_no_eligible_events_not_economic_evidence",
            "aggregate_status": "not_scored_no_eligible_events",
            "invalid_reason": reason,
        })
    return pd.DataFrame(rows)


def a1_symbol_month_summary(ledger: pd.DataFrame) -> pd.DataFrame:
    if ledger.empty:
        return pd.DataFrame(columns=["candidate_definition_id", "symbol", "month", "events", "net_R"])
    work = ledger.copy()
    work["decision_ts"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce")
    work["month"] = work["decision_ts"].dt.strftime("%Y-%m")
    return work.groupby(["candidate_definition_id", "symbol", "month"], dropna=False).agg(
        events=("event_id", "size"),
        gross_R=("gross_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        fees_R=("fees_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        funding_R=("funding_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        slippage_R=("slippage_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        net_R=("net_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
    ).reset_index()


def a1_nonfutile_candidates(aggregate: pd.DataFrame) -> pd.DataFrame:
    if aggregate.empty:
        return pd.DataFrame(columns=["candidate_definition_id", "nonfutile_status", "nonfutility_reason"])
    out = aggregate.copy()
    events = pd.to_numeric(out.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0)
    net = pd.to_numeric(out.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
    gross = pd.to_numeric(out.get("gross_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
    months = pd.to_numeric(out.get("active_months", pd.Series(dtype=float)), errors="coerce").fillna(0)
    symbols = pd.to_numeric(out.get("active_symbols", pd.Series(dtype=float)), errors="coerce").fillna(0)
    capped = out.get("label_cap_reason", pd.Series("", index=out.index)).fillna("").astype(str)
    primary_cap = capped.str.contains("short_diagnostic|oi_omitted_or_sidecar_cap|no_parent_gate_diagnostic|no_funding_gate", case=False, regex=True)
    keep = (events >= 50) & (months >= 6) & (symbols >= 3) & (net > 0) & (gross > 0) & (~primary_cap)
    out["nonfutile_status"] = np.where(keep, "aggregate_nonfutile_materialization_candidate", np.where(primary_cap, "diagnostic_only_not_promotable", "aggregate_futile_or_insufficient_breadth"))
    out["nonfutility_reason"] = np.where(keep, "positive_net_and_gross_with_minimum_event_symbol_month_breadth", np.where(primary_cap, "diagnostic_or_cap_lane_not_promotable_from_aggregate", "failed_positive_nonfutility_or_breadth_threshold"))
    return out[out["nonfutile_status"].eq("aggregate_nonfutile_materialization_candidate")].sort_values(["net_R", "events"], ascending=[False, False], kind="mergesort")


def stage_a1_compression_full_train_aggregate(ctx: Context) -> None:
    t0 = time.time()
    mechanical_root = active_prior_benchmark_root(ctx.args)
    if not mechanical_root.exists():
        raise RuntimeError(f"missing A1 mechanical canary root: {mechanical_root}")
    mechanical_summary = read_json(mechanical_root / "decision_summary.json", {})
    mechanical_status = str(mechanical_summary.get("status", "missing"))
    mechanical_parity_pass = parse_bool_value(mechanical_summary.get("parity_pass", False), default=False)
    mechanical_mismatch_count = int(safe_float(mechanical_summary.get("parity_mismatch_count", 1), 1.0))
    write_csv(ctx.run_root / "preflight/mechanical_canary_reference_audit.csv", [{
        "mechanical_root": str(mechanical_root),
        "mechanical_decision_summary_exists": bool((mechanical_root / "decision_summary.json").exists()),
        "mechanical_status": mechanical_status,
        "mechanical_parity_pass": mechanical_parity_pass,
        "mechanical_parity_mismatch_count": mechanical_mismatch_count,
        "status": "pass" if mechanical_status == "complete" and (mechanical_parity_pass or mechanical_mismatch_count == 0) else "fail",
    }])
    if mechanical_status != "complete" or not (mechanical_parity_pass or mechanical_mismatch_count == 0):
        raise RuntimeError("A1 full aggregate requires passing mechanical canary root with parity_pass=true")
    manifest = load_a1_compression_manifest()
    if manifest["candidate_definition_id"].astype(str).duplicated().any():
        raise RuntimeError("A1/compression manifest contains duplicate candidate_definition_id values")
    if manifest["parameter_vector_hash"].astype(str).duplicated().any():
        raise RuntimeError("A1/compression manifest contains duplicate parameter_vector_hash values")
    soft_limit = a1_soft_memory_limit_bytes(ctx)
    windows = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows)
    write_csv(ctx.run_root / "binding/definition_manifest_used.csv", manifest)
    paths = data_paths(ctx)
    panel = full_panel_for_launch_gate(ctx)
    if panel.empty:
        raise RuntimeError("A1 full aggregate requires non-empty full PIT panel")
    write_csv(ctx.run_root / "universe/a1_full_panel_manifest.csv", panel)
    symbols_all = panel.get("symbol", pd.Series(dtype=str)).dropna().astype(str).tolist()
    symbol_frames: dict[tuple[str, str], pd.DataFrame] = {}
    rank_panels: dict[tuple[str, str], dict[str, Any]] = {}
    completed_cache: dict[tuple[str, str, str], pd.DataFrame] = {}
    funding_frames: dict[str, pd.DataFrame] = {}
    universe_cache: dict[tuple[str, str, str, str, str], tuple[list[str], pd.DataFrame]] = {}
    rank_series_cache: dict[tuple[str, str, str, int, str], dict[str, dict[str, Any]]] = {}
    parent_gate_cache: dict[tuple[str, str], dict[str, Any]] = {}
    funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = {}
    selected_rows: list[dict[str, Any]] = []
    event_count_rows: list[dict[str, Any]] = []
    topn_audit_rows: list[dict[str, Any]] = []
    leak_violations = 0
    manifest_validation_failures = 0
    peak_rss = current_rss_bytes()
    total_defs = int(len(manifest))
    start_by_stage: list[dict[str, Any]] = [{"stage": "preflight", "runtime_seconds": time.time() - t0, "rows": total_defs, "rss_bytes": peak_rss}]
    ctx.notifier.send("A1 compression full aggregate selected-key build started", f"run_root={ctx.run_root}\ndefinitions={total_defs}", level="info")
    for def_idx, (_, raw_def) in enumerate(manifest.iterrows(), start=1):
        d = a1_engine_candidate(raw_def.to_dict(), ctx)
        cid = str(d.get("candidate_definition_id", ""))
        if d["a1_universe_binding_status"] == "unknown_universe_policy_fail_closed":
            manifest_validation_failures += 1
            continue
        timeframe = str(d.get("decision_timeframe", d.get("bar_timeframe", "4h")))
        topn = int(safe_float(d.get("leader_top_n", d.get("rank_top_n", 0)), 0))
        lookback = int(safe_float(d.get("lookback_days", a1_rank_lookback_days(d)), a1_rank_lookback_days(d)))
        rank_metric = str(d.get("rank_metric", a1_rank_metric_base(d.get("leader_rank_metric", ""))))
        actual_count = 0
        theoretical_max = 0
        selected_hashes_for_def: list[str] = []
        static_topn_failures = 0
        topn_rows = 0
        for _, w in windows.iterrows():
            decisions = a1_decision_timestamps_for_window(w.to_dict(), timeframe)
            for decision in decisions:
                ukey = (
                    str(d.get("universe_policy", "")),
                    str(d.get("top_major_target_size", "")),
                    str(d.get("tier_ab_target_size", "")),
                    decision.isoformat(),
                    str(d.get("universe_policy_hash", "")),
                )
                if ukey not in universe_cache:
                    symbols, uaudit = tsmom_policy_symbols_at_checkpoint_v3(ctx, d, panel, decision)
                    universe_cache[ukey] = (symbols, uaudit)
                policy_symbols, _ = universe_cache[ukey]
                theoretical_max += min(topn, len(policy_symbols)) if topn > 0 else len(policy_symbols)
                scored: list[dict[str, Any]] = []
                for sym in policy_symbols:
                    sym_key = (sym, str(w["window_id"]))
                    if sym_key not in symbol_frames:
                        symbol_frames[sym_key] = a1_load_symbol_bars_window(paths, sym, ts_utc(w["feature_warmup_start"]) - pd.Timedelta(days=5), ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                    if sym_key not in rank_panels:
                        rank_panels[sym_key] = a1_rank_panel_from_bars(symbol_frames[sym_key])
                    rkey = (sym, decision.isoformat(), rank_metric, lookback)
                    if rkey not in rank_feature_cache:
                        score, source_ts = a1_rank_score_from_panel(rank_panels[sym_key], decision, lookback, rank_metric)
                        rank_feature_cache[rkey] = {"score": score, "source_ts": source_ts}
                    bundle = rank_feature_cache[rkey]
                    score = safe_float(bundle.get("score", np.nan), np.nan)
                    source_ts = str(bundle.get("source_ts", ""))
                    valid = math.isfinite(score) and bool(source_ts) and ts_utc(source_ts) < decision
                    if valid:
                        scored.append({"symbol": sym, "rank_score": score, "feature_available_ts": source_ts, "tie_break_hash": stable_hash(d.get("rank_policy_hash", ""), sym, n=16)})
                    elif source_ts and ts_utc(source_ts) > decision:
                        leak_violations += 1
                scored_df = pd.DataFrame(scored)
                if scored_df.empty:
                    selected_top: list[str] = []
                    rank_source_ts = ""
                else:
                    scored_df = scored_df.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort")
                    selected_top = scored_df.head(topn)["symbol"].astype(str).tolist()
                    rank_source_ts = str(pd.to_datetime(scored_df.head(topn)["feature_available_ts"], utc=True, errors="coerce").max())
                topn_rows += 1
                selected_hashes_for_def.append(stable_hash(*selected_top, n=24))
                if universe_symbols_are_alphabetical_first_n(selected_top, symbols_all):
                    static_topn_failures += 1
                for sym in selected_top:
                    sym_key = (sym, str(w["window_id"]))
                    if sym not in funding_frames:
                        funding_frames[sym] = load_funding(paths, sym, ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                    ckey = (sym, timeframe, str(w["window_id"]))
                    if ckey not in completed_cache:
                        completed_cache[ckey] = completed_ohlcv_frame(symbol_frames.get(sym_key, pd.DataFrame()), timeframe)
                        if not completed_cache[ckey].empty and "source_ts" in completed_cache[ckey].columns:
                            completed_cache[ckey]["source_ts"] = pd.to_datetime(completed_cache[ckey]["source_ts"], utc=True, errors="coerce")
                    features = a1_feature_bundle(d, completed_cache[ckey], decision)
                    parent_key = (str(raw_def.get("parent_regime_gate", "")), decision.isoformat())
                    if parent_key not in parent_gate_cache:
                        parent_gate_cache[parent_key] = a1_parent_gate(d, symbol_frames.get(sym_key, pd.DataFrame()), decision)
                    parent = parent_gate_cache[parent_key]
                    funding_key = (str(raw_def.get("funding_gate", "")), sym, decision.isoformat())
                    if funding_key not in funding_gate_cache:
                        funding_gate_cache[funding_key] = a1_funding_gate(d, funding_frames.get(sym, pd.DataFrame()), decision)
                    funding_gate = funding_gate_cache[funding_key]
                    feature_times = [x for x in [features.get("feature_available_ts", ""), parent.get("feature_source_ts", ""), funding_gate.get("feature_source_ts", ""), rank_source_ts] if x]
                    for ft in feature_times:
                        if ts_utc(ft) > decision:
                            leak_violations += 1
                    selected = bool(features.get("signal_pass", False)) and bool(parent.get("allowed", False)) and bool(funding_gate.get("allowed", False))
                    if not selected:
                        continue
                    cap_reasons = [x for x in [
                        str(raw_def.get("label_cap_reason", "")),
                        str(d.get("a1_universe_cap_reason", "")),
                        str(parent.get("cap", "")),
                        str(funding_gate.get("cap", "")),
                        "oi_omitted_or_sidecar_cap" if str(raw_def.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "",
                        "short_diagnostic" if str(raw_def.get("definition_lane", "")) == "short_diagnostic" else "",
                    ] if x and x.lower() not in {"nan", "none"}]
                    actual_count += 1
                    identity_hash = build_candidate_identity_hash({
                        "candidate_definition_id": cid,
                        "candidate_symbol_id": f"{cid}::{sym}",
                        "symbol": sym,
                        "symbol_id": sym,
                        "parameter_vector_hash": str(raw_def.get("parameter_vector_hash", "")),
                        "universe_policy_hash": str(d.get("universe_policy_hash", "")),
                        "rank_policy_hash": str(d.get("rank_policy_hash", "")),
                        "signal_policy_hash": str(d.get("signal_policy_hash", "")),
                        "parent_gate_policy_hash": str(d.get("parent_gate_policy_hash", "")),
                        "funding_gate_policy_hash": str(d.get("funding_gate_policy_hash", "")),
                        "event_semantics_version": "a1_compression_selected_key_v1",
                        "input_manifest_hash": a1_manifest_hash(),
                        "train_window_hash": stable_hash(ctx.start, ctx.end, n=16),
                    })
                    selected_rows.append({
                        "candidate_definition_id": cid,
                        "candidate_symbol_id": f"{cid}::{sym}",
                        "candidate_identity_hash": identity_hash,
                        "symbol_id": sym,
                        "symbol": sym,
                        "parameter_vector_hash": str(raw_def.get("parameter_vector_hash", "")),
                        "definition_lane": raw_def.get("definition_lane", ""),
                        "decision_ts": decision.isoformat(),
                        "entry_policy": "next_5m_open_after_decision",
                        "feature_available_ts": max([str(x) for x in feature_times if x], default=decision.isoformat()),
                        "label_cap_reason": ";".join(sorted(set(cap_reasons))),
                        "selected_event_key_source": "a1_full_train_streamed_decision_inputs",
                        "event_sampling_used": False,
                        "event_caps_used": False,
                    })
        event_count_rows.append({
            "candidate_definition_id": cid,
            "definition_lane": raw_def.get("definition_lane", ""),
            "theoretical_max_events": int(theoretical_max),
            "actual_selected_events": int(actual_count),
            "status": "pass" if actual_count <= theoretical_max else "fail",
            "reason": "" if actual_count <= theoretical_max else "actual_events_exceed_theoretical_topn_decision_bound",
        })
        topn_audit_rows.append({
            "candidate_definition_id": cid,
            "definition_lane": raw_def.get("definition_lane", ""),
            "topn_rows": int(topn_rows),
            "distinct_selected_panel_hashes": int(len(set(selected_hashes_for_def))),
            "static_alphabetical_failures": int(static_topn_failures),
            "topn_selection_basis": "per_decision_pit_rank_score_with_hash_tiebreak",
            "status": "pass" if static_topn_failures == 0 else "fail",
        })
        peak_rss = max(peak_rss, current_rss_bytes())
        if peak_rss > soft_limit:
            raise RuntimeError(f"A1 full aggregate memory soft limit exceeded before outcome build: rss={peak_rss} limit={soft_limit}")
        if def_idx == 1 or def_idx == total_defs or def_idx % 25 == 0:
            elapsed = time.time() - t0
            rate = def_idx / max(elapsed, 1.0)
            a1_write_heartbeat(
                ctx,
                "a1-compression-full-train-aggregate",
                phase="selected_key_build",
                definitions_processed=def_idx,
                total_definitions=total_defs,
                selected_event_keys_so_far=len(selected_rows),
                rows_per_second=rate,
                eta_seconds=(total_defs - def_idx) / max(rate, 1e-9),
                soft_memory_limit_bytes=soft_limit,
            )
    write_csv(ctx.run_root / "audit/event_count_theoretical_vs_actual.csv", event_count_rows)
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", topn_audit_rows)
    selected_raw = pd.DataFrame(selected_rows)
    if selected_raw.empty:
        selected_frozen, selected_hash = (pd.DataFrame(columns=["candidate_identity_hash", "symbol_id", "decision_ts", "selected_event_keys_hash", "selected_event_keys_frozen"]), stable_hash("a1_full_train_empty_selected_event_keys"))
        selected_out = selected_frozen
    else:
        selected_raw["decision_ts"] = pd.to_datetime(selected_raw["decision_ts"], utc=True, errors="coerce")
        selected_frozen, selected_hash = freeze_selected_event_keys(selected_raw)
        selected_out = selected_raw.merge(selected_frozen, on=["candidate_identity_hash", "symbol_id", "decision_ts"], how="left")
    selected_manifest = write_a1_cache_table(
        ctx,
        "selected_event_key",
        "selected_event_key",
        selected_out,
        ["candidate_identity_hash", "symbol_id", "decision_ts"],
        {"family": "a1_compression_full_train", "selected_event_key_hash": selected_hash},
        selected_event_key_hash=selected_hash,
    )
    write_json(ctx.run_root / "cache/selected_event_key_freeze_summary.json", {
        "selected_event_keys_frozen": True,
        "selected_event_key_count": int(len(selected_out)),
        "selected_event_key_hash": selected_hash,
        "outcome_cache_built_after_freeze": False,
        "ts_utc": utc_now(),
    })
    start_by_stage.append({"stage": "selected_key_freeze", "runtime_seconds": time.time() - t0, "rows": int(len(selected_out)), "rss_bytes": current_rss_bytes()})
    ctx.notifier.send("A1 compression full aggregate selected keys frozen", f"run_root={ctx.run_root}\nselected_event_keys={len(selected_out)}", level="info")
    def_by_id = {str(r.get("candidate_definition_id", "")): r.to_dict() for _, r in manifest.iterrows()}
    if not selected_out.empty:
        min_decision = pd.to_datetime(selected_out["decision_ts"], utc=True, errors="coerce").min()
        max_decision = pd.to_datetime(selected_out["decision_ts"], utc=True, errors="coerce").max()
    else:
        min_decision = ts_utc(windows["decision_start"].iloc[0])
        max_decision = ts_utc(windows["decision_end"].iloc[0])
    outcome_symbol_cache: dict[str, pd.DataFrame] = {}
    outcome_funding_cache: dict[str, pd.DataFrame] = {}
    event_rows: list[dict[str, Any]] = []
    for row_idx, (_, sel) in enumerate(selected_out.iterrows(), start=1):
        sym = str(sel.get("symbol", sel.get("symbol_id", "")))
        if sym not in outcome_symbol_cache:
            outcome_symbol_cache[sym] = a1_load_symbol_bars_window(paths, sym, min_decision - pd.Timedelta(days=240), max_decision + pd.Timedelta(days=21))
        if sym not in outcome_funding_cache:
            outcome_funding_cache[sym] = load_funding(paths, sym, max_decision + pd.Timedelta(days=21))
        defn = def_by_id.get(str(sel.get("candidate_definition_id", "")))
        if not defn:
            continue
        ev = a1_outcome_event_from_selected(defn, sel.to_dict(), outcome_symbol_cache[sym], outcome_funding_cache[sym])
        if ev is not None:
            ev["strategy_evidence_label"] = "train_only_aggregate_diagnostic_level_1_2_capped_not_validation"
            event_rows.append(ev)
        if row_idx == 1 or row_idx == len(selected_out) or row_idx % 5000 == 0:
            peak_rss = max(peak_rss, current_rss_bytes())
            if peak_rss > soft_limit:
                raise RuntimeError(f"A1 full aggregate memory soft limit exceeded during outcome build: rss={peak_rss} limit={soft_limit}")
            elapsed = time.time() - t0
            rate = row_idx / max(elapsed, 1.0)
            a1_write_heartbeat(
                ctx,
                "a1-compression-full-train-aggregate",
                phase="outcome_build",
                selected_rows_processed=row_idx,
                selected_rows_total=int(len(selected_out)),
                outcome_events_so_far=len(event_rows),
                rows_per_second=rate,
                eta_seconds=(len(selected_out) - row_idx) / max(rate, 1e-9),
                soft_memory_limit_bytes=soft_limit,
            )
    ledger = pd.DataFrame(event_rows)
    if not ledger.empty:
        cache_dir = ctx.run_root / "cache/full_train_interval_outcomes"
        cache_dir.mkdir(parents=True, exist_ok=True)
        parquet_safe_frame(ledger).to_parquet(cache_dir / "a1_full_train_interval_outcomes.parquet", index=False, compression="zstd")
    outcome_manifest = semantic_cache_manifest(
        cache_class="interval_outcome",
        df=ledger,
        sort_keys=["candidate_definition_id", "symbol", "decision_ts", "event_id"],
        policy_fields={"family": "a1_compression_full_train", "scope": "full_train_aggregate_only"},
        input_manifest_hash=a1_manifest_hash(),
        data_hash=stable_hash(resolve_path(ctx.args.kraken_data_root), ctx.start, ctx.end, n=32),
        protected_train_boundary=str(PROTECTED_TS),
        selected_event_key_hash=selected_hash,
        path="cache/full_train_interval_outcomes/a1_full_train_interval_outcomes.parquet",
    )
    outcome_manifest["manifest_validation_status"] = validate_semantic_cache_manifest(outcome_manifest).get("status", "")
    write_csv(ctx.run_root / "cache/full_train_interval_outcome_manifest.csv", [{**outcome_manifest, "policy_fields": json.dumps(outcome_manifest.get("policy_fields", {}), sort_keys=True), "canonical_sort_keys": ";".join(outcome_manifest.get("canonical_sort_keys", []))}])
    aggregate = a1_grouped_aggregate_summary(ledger)
    sym_month = a1_symbol_month_summary(ledger)
    (ctx.run_root / "aggregate").mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(aggregate).to_parquet(ctx.run_root / "aggregate/grouped_aggregate_summary.parquet", index=False, compression="zstd")
    parquet_safe_frame(sym_month).to_parquet(ctx.run_root / "aggregate/symbol_month_summary.parquet", index=False, compression="zstd")
    write_csv(ctx.run_root / "aggregate/grouped_aggregate_summary.csv", aggregate)
    if not ledger.empty:
        lane = ledger.groupby("definition_lane", dropna=False).agg(
            events=("event_id", "size"),
            active_definitions=("candidate_definition_id", "nunique"),
            net_R=("net_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
            gross_R=("gross_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        ).reset_index()
        exit_policy = ledger.groupby(["exit_policy_id", "exit_module"], dropna=False).agg(
            events=("event_id", "size"),
            active_definitions=("candidate_definition_id", "nunique"),
            net_R=("net_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        ).reset_index()
        regime = ledger.groupby(["definition_lane", "side"], dropna=False).agg(
            events=("event_id", "size"),
            active_definitions=("candidate_definition_id", "nunique"),
            net_R=("net_R", lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0).sum())),
        ).reset_index()
    else:
        lane = pd.DataFrame(columns=["definition_lane", "events", "active_definitions", "net_R", "gross_R"])
        exit_policy = pd.DataFrame(columns=["exit_policy_id", "exit_module", "events", "active_definitions", "net_R"])
        regime = pd.DataFrame(columns=["definition_lane", "side", "events", "active_definitions", "net_R"])
    write_csv(ctx.run_root / "aggregate/lane_summary.csv", lane)
    write_csv(ctx.run_root / "aggregate/exit_policy_summary.csv", exit_policy)
    write_csv(ctx.run_root / "aggregate/regime_context_summary.csv", regime)
    protected_cols = ["decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts", "funding_interval_end_ts", "outcome_interval_end_ts"]
    protected_rows = []
    protected_violations = 0
    for col in protected_cols:
        ts = pd.to_datetime(ledger.get(col, pd.Series(dtype=str)), utc=True, errors="coerce") if not ledger.empty else pd.Series(dtype="datetime64[ns, UTC]")
        v = int((ts >= PROTECTED_TS).sum()) if len(ts) else 0
        protected_violations += v
        protected_rows.append({"field": col, "rows": int(len(ts)), "protected_interval_violations": v, "status": "pass" if v == 0 else "fail"})
    write_csv(ctx.run_root / "audit/protected_interval_audit.csv", protected_rows)
    leak_audit = pd.DataFrame([{
        "check": "decision_input_feature_available_lte_decision",
        "violations": int(leak_violations),
        "status": "pass" if leak_violations == 0 else "fail",
    }])
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", leak_audit)
    write_csv(ctx.run_root / "audit/no_scalar_fallback_audit.csv", [
        {"check": "a1_full_train_scalar_fallback_used", "scalar_fallback_used": False, "exception": "exactness_sentinel_uses_grouped_vs_direct_reaggregation_only", "status": "pass"}
    ])
    sentinel_rows = []
    if not aggregate.empty:
        direct = a1_grouped_aggregate_summary(ledger[ledger["candidate_definition_id"].astype(str).isin(aggregate["candidate_definition_id"].astype(str).sort_values().head(24))])
        grouped = aggregate[aggregate["candidate_definition_id"].astype(str).isin(direct["candidate_definition_id"].astype(str))].copy()
        for metric in ["events", "net_R", "gross_R", "fees_R", "funding_R", "slippage_R"]:
            dsum = a1_metric_sum(direct, metric)
            gsum = a1_metric_sum(grouped, metric)
            mismatch = 0 if abs(dsum - gsum) <= AGGREGATE_MATERIALIZED_TOLERANCE else 1
            sentinel_rows.append({"check": f"grouped_vs_direct_first24_{metric}", "grouped_value": gsum, "direct_value": dsum, "mismatch_count": mismatch, "status": "pass" if mismatch == 0 else "fail"})
    else:
        sentinel_rows.append({"check": "grouped_vs_direct_first24_no_rows", "grouped_value": 0, "direct_value": 0, "mismatch_count": 1, "status": "fail"})
    write_csv(ctx.run_root / "audit/exactness_sentinel.csv", sentinel_rows)
    nonfutile = a1_nonfutile_candidates(aggregate)
    write_csv(ctx.run_root / "decision/nonfutile_aggregate_candidates.csv", nonfutile)
    hit_miss_rows = [
        {"cache": "universe_policy_decision", "entries": len(universe_cache), "status": "pass"},
        {"cache": "rank_feature", "entries": len(rank_feature_cache), "status": "pass"},
        {"cache": "parent_gate", "entries": len(parent_gate_cache), "status": "pass"},
        {"cache": "funding_gate", "entries": len(funding_gate_cache), "status": "pass"},
        {"cache": "symbol_frames", "entries": len(symbol_frames), "status": "pass"},
        {"cache": "outcome_symbol_frames", "entries": len(outcome_symbol_cache), "status": "pass"},
    ]
    write_csv(ctx.run_root / "performance/cache_hit_miss_report.csv", hit_miss_rows)
    start_by_stage.extend([
        {"stage": "outcome_build", "runtime_seconds": time.time() - t0, "rows": int(len(ledger)), "rss_bytes": current_rss_bytes()},
        {"stage": "grouped_aggregate", "runtime_seconds": time.time() - t0, "rows": int(len(aggregate)), "rss_bytes": current_rss_bytes()},
    ])
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", start_by_stage)
    mismatch_count = int(pd.to_numeric(pd.DataFrame(sentinel_rows).get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    static_failures = int(pd.to_numeric(pd.DataFrame(topn_audit_rows).get("static_alphabetical_failures", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    event_count_failures = int(pd.DataFrame(event_count_rows).get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if event_count_rows else 1
    manifest_failures = int(str(selected_manifest.get("status", "")) != "pass" or outcome_manifest["manifest_validation_status"] != "pass" or manifest_validation_failures)
    peak_rss = max(peak_rss, current_rss_bytes())
    total_runtime = time.time() - t0
    pass_gate = (
        mismatch_count == 0
        and leak_violations == 0
        and static_failures == 0
        and protected_violations == 0
        and event_count_failures == 0
        and manifest_failures == 0
        and peak_rss < soft_limit
    )
    top_lanes = lane.sort_values("net_R", ascending=False, kind="mergesort").head(5)["definition_lane"].astype(str).tolist() if not lane.empty and "net_R" in lane.columns else []
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_train_aggregate_launched": True,
        "materialization_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "two_family_work_launched": False,
        "live_prep_launched": False,
        "definitions_evaluated": int(len(manifest)),
        "selected_event_count": int(len(selected_out)),
        "outcome_event_count": int(len(ledger)),
        "nonfutile_aggregate_count": int(len(nonfutile)),
        "exactness_pass": mismatch_count == 0,
        "mismatch_count": mismatch_count,
        "decision_input_leak_violations": int(leak_violations),
        "static_topn_failures": static_failures,
        "protected_interval_violations": protected_violations,
        "event_sampling_used": False,
        "event_caps_used": False,
        "portfolio_caps_used": False,
        "scalar_fallback_used": False,
        "selected_event_key_hash": selected_hash,
        "peak_rss_bytes": int(peak_rss),
        "soft_memory_limit_bytes": int(soft_limit),
        "total_runtime_seconds": total_runtime,
        "top_nonfutile_lanes": top_lanes,
        "next_operator_decision": "review_a1_compression_aggregate_nonfutile_candidates_next" if pass_gate else "repair_a1_compression_full_aggregate_component_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "A1_COMPRESSION_FULL_TRAIN_AGGREGATE_REPORT.md", "\n".join([
        "# A1 + Compression Full Train Aggregate Screen Report",
        "",
        "This is a full train-only aggregate screen. It is not validation, not final holdout evidence, not live readiness, and not permission to trade.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Definitions evaluated: `{summary['definitions_evaluated']}`",
        f"Selected event keys: `{summary['selected_event_count']}`",
        f"Outcome events: `{summary['outcome_event_count']}`",
        f"Nonfutile aggregate candidates: `{summary['nonfutile_aggregate_count']}`",
        f"Exactness sentinel pass: `{summary['exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Decision-input leak violations: `{summary['decision_input_leak_violations']}`",
        f"Static Top-N failures: `{summary['static_topn_failures']}`",
        f"Protected interval violations: `{summary['protected_interval_violations']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Runtime seconds: `{summary['total_runtime_seconds']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
    ]) + "\n")
    ctx.notifier.send("A1 compression full aggregate completed", f"status={summary['status']}\nrun_root={ctx.run_root}\nnonfutile={summary['nonfutile_aggregate_count']}", level="info" if pass_gate else "warning")
    write_status(ctx, summary["status"], "a1-compression-full-train-aggregate")


def a1_feature_spec_hash(defn: Mapping[str, Any]) -> str:
    return a1_policy_hash(
        "a1_feature_spec_v1",
        defn.get("decision_timeframe", defn.get("bar_timeframe", "")),
        defn.get("impulse_lookback_days", ""),
        defn.get("base_window_days", ""),
        defn.get("rv_reference_days", ""),
        defn.get("box_width_atr_max", ""),
        defn.get("range_slope_abs_max", ""),
        defn.get("compression_policy_hash", ""),
        defn.get("entry_policy_hash", ""),
        n=32,
    )


def a1_raw_feature_bundle_from_completed(defn: Mapping[str, Any], completed: pd.DataFrame, decision_ts: pd.Timestamp) -> dict[str, Any]:
    decision = ts_utc(decision_ts)
    if completed.empty or "source_ts" not in completed.columns:
        return {"status": "missing_completed_frame", "feature_available_ts": ""}
    frame = completed.copy()
    if not pd.api.types.is_datetime64_any_dtype(frame["source_ts"]):
        frame["source_ts"] = pd.to_datetime(frame["source_ts"], utc=True, errors="coerce")
    frame = frame.dropna(subset=["source_ts", "close"]).sort_values("source_ts", kind="mergesort")
    current = frame[frame["source_ts"].le(decision)].tail(1)
    prior = frame[frame["source_ts"].lt(decision)]
    if current.empty or prior.empty:
        return {"status": "insufficient_current_or_reference_bars", "feature_available_ts": ""}
    cur = current.iloc[-1]
    bars_per_day = 6 if str(defn.get("decision_timeframe", "")).lower() == "4h" else 1
    base_n = max(3, int(safe_float(defn.get("base_window_days", 10), 10)) * bars_per_day)
    impulse_n = max(2, int(safe_float(defn.get("impulse_lookback_days", 20), 20)) * bars_per_day)
    base = prior.tail(base_n)
    impulse = prior.tail(impulse_n)
    if len(base) < max(3, min(base_n, 10)) or len(impulse) < 2:
        return {"status": "insufficient_reference_window", "feature_available_ts": str(cur.get("source_ts", ""))}
    close = safe_float(cur.get("close"), np.nan)
    base_high = float(pd.to_numeric(base["high"], errors="coerce").max()) if "high" in base.columns else float(pd.to_numeric(base["close"], errors="coerce").max())
    base_low = float(pd.to_numeric(base["low"], errors="coerce").min()) if "low" in base.columns else float(pd.to_numeric(base["close"], errors="coerce").min())
    base_mid = (base_high + base_low) / 2.0 if math.isfinite(base_high) and math.isfinite(base_low) else float("nan")
    base_width_pct = ((base_high - base_low) / base_mid) if math.isfinite(base_mid) and base_mid > 0 else float("nan")
    first = safe_float(impulse["close"].iloc[0], np.nan)
    last = safe_float(impulse["close"].iloc[-1], np.nan)
    impulse_return = last / first - 1.0 if math.isfinite(first) and first > 0 and math.isfinite(last) else float("nan")
    rets = pd.to_numeric(base["close"], errors="coerce").pct_change().dropna()
    rv = float(rets.std()) if len(rets) else float("nan")
    longer = prior.tail(max(base_n * 3, base_n + 10))
    long_rv = pd.to_numeric(longer["close"], errors="coerce").pct_change().rolling(max(3, min(len(longer), base_n))).std().dropna()
    rv_percentile = percentile_rank(long_rv, rv) if len(long_rv) else float("nan")
    slope = float((pd.to_numeric(base["close"], errors="coerce").iloc[-1] / pd.to_numeric(base["close"], errors="coerce").iloc[0] - 1.0) / max(1, len(base))) if len(base) >= 2 and safe_float(base["close"].iloc[0], np.nan) > 0 else float("nan")
    return {
        "status": "feature_values_available",
        "feature_available_ts": str(cur.get("source_ts", "")),
        "feature_source_end_ts": str(cur.get("source_ts", "")),
        "base_high": base_high,
        "base_low": base_low,
        "base_width_pct": base_width_pct,
        "impulse_return": impulse_return,
        "rv": rv,
        "rv_percentile": rv_percentile,
        "range_slope": slope,
        "current_close": close,
    }


def a1_signal_pass_from_raw_features(defn: Mapping[str, Any], features: Mapping[str, Any]) -> tuple[bool, str]:
    if str(features.get("status", "")) != "feature_values_available":
        return False, str(features.get("status", "feature_unavailable"))
    close = safe_float(features.get("current_close"), np.nan)
    base_high = safe_float(features.get("base_high"), np.nan)
    base_low = safe_float(features.get("base_low"), np.nan)
    impulse_return = safe_float(features.get("impulse_return"), np.nan)
    rv_percentile = safe_float(features.get("rv_percentile"), np.nan)
    base_width_pct = safe_float(features.get("base_width_pct"), np.nan)
    trigger = str(defn.get("breakout_trigger", "") or "")
    impulse_ok = (not parse_bool_value(defn.get("impulse_required", False), default=False)) or (math.isfinite(impulse_return) and impulse_return >= safe_float(defn.get("impulse_return_threshold", 0.0), 0.0))
    compression_required = parse_bool_value(defn.get("compression_required", False), default=False)
    rv_threshold = safe_float(defn.get("rv_percentile_threshold", np.nan), np.nan)
    width_threshold = safe_float(defn.get("box_width_atr_max", np.nan), np.nan)
    compression_ok = True
    if compression_required:
        rv_ok = math.isfinite(rv_percentile) and (not math.isfinite(rv_threshold) or rv_percentile <= rv_threshold)
        width_ok = math.isfinite(base_width_pct) and (not math.isfinite(width_threshold) or base_width_pct <= width_threshold)
        compression_ok = rv_ok or width_ok
    long_break = math.isfinite(close) and math.isfinite(base_high) and close > base_high
    short_break = math.isfinite(close) and math.isfinite(base_low) and close < base_low
    if trigger == "close_below_compression_range_diagnostic":
        signal_pass = short_break and compression_ok
    elif "compressed" in trigger or "rv_compression" in trigger or "flat_range" in trigger or "vcp" in trigger:
        signal_pass = long_break and impulse_ok and compression_ok
    else:
        signal_pass = long_break and impulse_ok
    return bool(signal_pass), "pass" if signal_pass else "signal_condition_not_met"


def a1_feature_mask_table_from_completed(
    defn: Mapping[str, Any],
    completed: pd.DataFrame,
    decisions: Sequence[pd.Timestamp],
    *,
    feature_spec_hash: str | None = None,
    symbol_id: str = "",
    window_id: str = "",
) -> pd.DataFrame:
    """Build reusable A1/compression feature masks for a symbol/spec/calendar.

    This intentionally mirrors `a1_raw_feature_bundle_from_completed` boundary
    semantics without calling it in the selected-key hot path: the current
    signal bar is the latest completed bar with `source_ts <= decision_ts`,
    while impulse/base/compression reference windows use bars with
    `source_ts < decision_ts`.
    """
    rows: list[dict[str, Any]] = []
    spec_hash = feature_spec_hash or a1_feature_spec_hash(defn)
    clean_decisions = [ts_utc(d) for d in decisions]
    base_stub = {
        "feature_spec_hash": spec_hash,
        "signal_policy_hash": str(defn.get("signal_policy_hash", "")),
        "symbol_id": str(symbol_id),
        "symbol": str(symbol_id),
        "window_id": str(window_id),
        "definition_lane": str(defn.get("definition_lane", "")),
        "feature_family_lane": str(defn.get("definition_lane", "")),
    }
    if completed.empty or "source_ts" not in completed.columns:
        for decision in clean_decisions:
            rows.append({**base_stub, "decision_ts": decision.isoformat(), "feature_available_ts": "", "feature_source_end_ts": "", "status": "missing_completed_frame", "signal_pass": False, "signal_status": "missing_completed_frame"})
        return pd.DataFrame(rows)
    frame = completed.copy()
    if not pd.api.types.is_datetime64_any_dtype(frame["source_ts"]):
        frame["source_ts"] = pd.to_datetime(frame["source_ts"], utc=True, errors="coerce")
    for col in ["open", "high", "low", "close", "volume"]:
        if col in frame.columns:
            frame[col] = pd.to_numeric(frame[col], errors="coerce")
    frame = frame.dropna(subset=["source_ts", "close"]).sort_values("source_ts", kind="mergesort").drop_duplicates("source_ts", keep="last")
    if frame.empty:
        for decision in clean_decisions:
            rows.append({**base_stub, "decision_ts": decision.isoformat(), "feature_available_ts": "", "feature_source_end_ts": "", "status": "missing_completed_frame", "signal_pass": False, "signal_status": "missing_completed_frame"})
        return pd.DataFrame(rows)
    ts_ns = frame["source_ts"].astype("int64").to_numpy(dtype=np.int64)
    close_arr = pd.to_numeric(frame["close"], errors="coerce").to_numpy(dtype=float)
    high_arr = pd.to_numeric(frame["high"] if "high" in frame.columns else frame["close"], errors="coerce").to_numpy(dtype=float)
    low_arr = pd.to_numeric(frame["low"] if "low" in frame.columns else frame["close"], errors="coerce").to_numpy(dtype=float)
    bars_per_day = 6 if str(defn.get("decision_timeframe", "")).lower() == "4h" else 1
    base_n = max(3, int(safe_float(defn.get("base_window_days", 10), 10)) * bars_per_day)
    impulse_n = max(2, int(safe_float(defn.get("impulse_lookback_days", 20), 20)) * bars_per_day)
    min_base = max(3, min(base_n, 10))
    long_window_n = max(base_n * 3, base_n + 10)
    high_roll = pd.Series(high_arr).rolling(base_n, min_periods=min_base).max().to_numpy(dtype=float)
    low_roll = pd.Series(low_arr).rolling(base_n, min_periods=min_base).min().to_numpy(dtype=float)
    close_series = pd.Series(close_arr)
    ret_series = close_series.pct_change()
    base_rv_roll = ret_series.rolling(max(1, base_n - 1), min_periods=2).std().to_numpy(dtype=float)
    long_rv_roll = ret_series.rolling(max(3, base_n), min_periods=max(3, base_n)).std().to_numpy(dtype=float)
    for decision in clean_decisions:
        decision_ns = int(decision.value)
        current_end = int(np.searchsorted(ts_ns, decision_ns, side="right"))
        prior_end = int(np.searchsorted(ts_ns, decision_ns, side="left"))
        if current_end <= 0 or prior_end <= 0:
            rows.append({**base_stub, "decision_ts": decision.isoformat(), "feature_available_ts": "", "feature_source_end_ts": "", "status": "insufficient_current_or_reference_bars", "signal_pass": False, "signal_status": "insufficient_current_or_reference_bars"})
            continue
        cur_idx = current_end - 1
        feature_ts = pd.Timestamp(int(ts_ns[cur_idx]), tz="UTC")
        base_start = max(0, prior_end - base_n)
        impulse_start = max(0, prior_end - impulse_n)
        base_len = prior_end - base_start
        impulse_len = prior_end - impulse_start
        if base_len < min_base or impulse_len < 2:
            rows.append({**base_stub, "decision_ts": decision.isoformat(), "feature_available_ts": feature_ts.isoformat(), "feature_source_end_ts": feature_ts.isoformat(), "status": "insufficient_reference_window", "signal_pass": False, "signal_status": "insufficient_reference_window"})
            continue
        prior_idx = prior_end - 1
        base_high = float(high_roll[prior_idx]) if 0 <= prior_idx < len(high_roll) else float("nan")
        base_low = float(low_roll[prior_idx]) if 0 <= prior_idx < len(low_roll) else float("nan")
        base_mid = (base_high + base_low) / 2.0 if math.isfinite(base_high) and math.isfinite(base_low) else float("nan")
        base_width_pct = ((base_high - base_low) / base_mid) if math.isfinite(base_mid) and base_mid > 0 else float("nan")
        first = safe_float(close_arr[impulse_start], np.nan)
        last = safe_float(close_arr[prior_idx], np.nan)
        impulse_return = last / first - 1.0 if math.isfinite(first) and first > 0 and math.isfinite(last) else float("nan")
        rv = float(base_rv_roll[prior_idx]) if 0 <= prior_idx < len(base_rv_roll) else float("nan")
        longer_start = max(0, prior_end - long_window_n)
        longer_len = prior_end - longer_start
        if longer_len >= base_n:
            long_vals = long_rv_roll[longer_start + base_n:prior_end]
            long_vals = long_vals[np.isfinite(long_vals)]
            rv_percentile = float((long_vals <= rv).mean()) if len(long_vals) and math.isfinite(rv) else float("nan")
        else:
            rv_percentile = float("nan")
        base_first = safe_float(close_arr[base_start], np.nan)
        base_last = safe_float(close_arr[prior_idx], np.nan)
        slope = float((base_last / base_first - 1.0) / max(1, base_len)) if base_len >= 2 and math.isfinite(base_first) and base_first > 0 and math.isfinite(base_last) else float("nan")
        features = {
            "status": "feature_values_available",
            "feature_available_ts": feature_ts.isoformat(),
            "feature_source_end_ts": feature_ts.isoformat(),
            "base_high": base_high,
            "base_low": base_low,
            "base_width_pct": base_width_pct,
            "impulse_return": impulse_return,
            "rv": rv,
            "rv_percentile": rv_percentile,
            "range_slope": slope,
            "current_close": safe_float(close_arr[cur_idx], np.nan),
        }
        signal_pass, signal_status = a1_signal_pass_from_raw_features(defn, features)
        rows.append({
            **base_stub,
            "decision_ts": decision.isoformat(),
            "feature_available_ts": features["feature_available_ts"],
            "feature_source_end_ts": features["feature_source_end_ts"],
            "status": features["status"],
            "base_high": base_high,
            "base_low": base_low,
            "base_width_pct": base_width_pct,
            "impulse_return": impulse_return,
            "rv": rv,
            "rv_percentile": rv_percentile,
            "range_slope": slope,
            "current_close": features["current_close"],
            "signal_pass": bool(signal_pass),
            "signal_status": signal_status,
        })
    return pd.DataFrame(rows)


def a1_select_medium_semantic_benchmark_definitions(manifest: pd.DataFrame, target: int = 128) -> pd.DataFrame:
    frames: list[pd.DataFrame] = []
    group_cols = [c for c in ["definition_lane", "exit_policy_id"] if c in manifest.columns]
    if group_cols:
        for _, g in manifest.groupby(group_cols, dropna=False, sort=True):
            frames.append(g.sort_values("candidate_definition_id", kind="mergesort").head(1))
    out = pd.concat(frames, ignore_index=True, sort=False).drop_duplicates("candidate_definition_id", keep="first") if frames else pd.DataFrame()
    if len(out) < target:
        extra = manifest[~manifest["candidate_definition_id"].astype(str).isin(set(out.get("candidate_definition_id", pd.Series(dtype=str)).astype(str)))]
        extra = extra.sort_values(["definition_lane", "entry_spec_id", "exit_policy_id", "candidate_definition_id"], kind="mergesort").head(target - len(out))
        out = pd.concat([out, extra], ignore_index=True, sort=False)
    return out.head(target).reset_index(drop=True)


def a1_extract_semantic_spec_inventory(manifest: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    for _, raw in manifest.iterrows():
        d = a1_engine_candidate(raw.to_dict(), ctx)
        rows.extend([
            {"cache_class": "decision_calendar", "semantic_spec_hash": a1_policy_hash("calendar", d.get("decision_timeframe", ""), ctx.start, ctx.end, n=32), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"timeframe={d.get('decision_timeframe', '')}"},
            {"cache_class": "universe_membership", "semantic_spec_hash": str(d.get("universe_policy_hash", "")), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"universe={d.get('universe_policy', '')};top_major={d.get('top_major_target_size', '')};tier_ab={d.get('tier_ab_target_size', '')}"},
            {"cache_class": "a1_leader_rank", "semantic_spec_hash": str(d.get("rank_policy_hash", "")), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"rank_metric={d.get('rank_metric', '')};lookback_days={d.get('lookback_days', '')}"},
            {"cache_class": "a1_topn", "semantic_spec_hash": a1_policy_hash("topn", d.get("universe_policy_hash", ""), d.get("rank_policy_hash", ""), d.get("rank_top_n", ""), n=32), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"top_n={d.get('rank_top_n', '')}"},
            {"cache_class": "a1_impulse_base_feature", "semantic_spec_hash": a1_feature_spec_hash(d), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"entry_policy_hash={d.get('entry_policy_hash', '')};compression_policy_hash={d.get('compression_policy_hash', '')}"},
            {"cache_class": "parent_gate", "semantic_spec_hash": str(d.get("parent_gate_policy_hash", "")), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"parent_gate={d.get('parent_regime_gate', '')}"},
            {"cache_class": "funding_gate", "semantic_spec_hash": str(d.get("funding_gate_policy_hash", "")), "candidate_definition_id": d.get("candidate_definition_id", ""), "spec_fields": f"funding_gate={d.get('funding_gate', '')}"},
        ])
    inv = pd.DataFrame(rows)
    if inv.empty:
        return inv
    summary = inv.groupby(["cache_class", "semantic_spec_hash", "spec_fields"], dropna=False).agg(candidate_definition_count=("candidate_definition_id", "nunique")).reset_index()
    summary["status"] = "pass"
    return summary


def a1_build_semantic_cache_tables(
    ctx: Context,
    definitions: pd.DataFrame,
    *,
    windows: pd.DataFrame,
    label: str,
    write_outputs: bool,
    output_prefix: str = "a1",
    heartbeat_stage: str = "a1-compression-semantic-cache-builder-repair",
    heartbeat_filename: str = "full_train_heartbeat.json",
) -> dict[str, Any]:
    t0 = time.time()
    paths = data_paths(ctx)
    panel = full_panel_for_launch_gate(ctx)
    if panel.empty:
        raise RuntimeError("A1 semantic cache builder requires non-empty PIT panel")
    symbols_all = panel.get("symbol", pd.Series(dtype=str)).dropna().astype(str).tolist()
    def_records = [a1_engine_candidate(r.to_dict(), ctx) for _, r in definitions.iterrows()]
    decision_rows: list[dict[str, Any]] = []
    universe_rows: list[dict[str, Any]] = []
    rank_rows: list[dict[str, Any]] = []
    topn_rows: list[dict[str, Any]] = []
    impulse_rows: list[dict[str, Any]] = []
    compression_rows: list[dict[str, Any]] = []
    signal_rows: list[dict[str, Any]] = []
    parent_rows: list[dict[str, Any]] = []
    funding_rows: list[dict[str, Any]] = []
    selected_rows: list[dict[str, Any]] = []
    timing_rows: list[dict[str, Any]] = []
    panel_key = stable_hash(*symbols_all, n=24)
    symbol_frames: dict[tuple[str, str], pd.DataFrame] = {}
    rank_panels: dict[tuple[str, str], dict[str, Any]] = {}
    completed_cache: dict[tuple[str, str, str], pd.DataFrame] = {}
    funding_frames: dict[str, pd.DataFrame] = {}
    universe_cache: dict[tuple[str, str, str, str, str], list[str]] = {}
    rank_series_cache: dict[tuple[str, str, str, int, str], dict[str, dict[str, Any]]] = {}
    topn_cache: dict[tuple[str, str, int, str], pd.DataFrame] = {}
    raw_feature_cache: dict[tuple[str, str, str, str], dict[str, Any]] = {}
    parent_gate_cache: dict[tuple[str, str], dict[str, Any]] = {}
    funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = {}
    leak_violations = 0
    static_topn_failures = 0
    total_defs = len(def_records)
    for def_idx, d in enumerate(def_records, start=1):
        cid = str(d.get("candidate_definition_id", ""))
        timeframe = str(d.get("decision_timeframe", d.get("bar_timeframe", "4h")))
        topn = int(safe_float(d.get("leader_top_n", d.get("rank_top_n", 0)), 0))
        lookback = int(safe_float(d.get("lookback_days", a1_rank_lookback_days(d)), a1_rank_lookback_days(d)))
        rank_metric = str(d.get("rank_metric", a1_rank_metric_base(d.get("leader_rank_metric", ""))))
        feature_spec_hash = a1_feature_spec_hash(d)
        for _, w in windows.iterrows():
            window_id = str(w["window_id"])
            decisions = a1_decision_timestamps_for_window(w.to_dict(), timeframe)
            for decision in decisions:
                calendar_hash = a1_policy_hash("calendar", timeframe, window_id, w.get("decision_start", ""), w.get("decision_end", ""), n=32)
                decision_rows.append({"calendar_hash": calendar_hash, "candidate_definition_id": cid, "decision_ts": decision.isoformat(), "feature_available_ts": decision.isoformat(), "decision_timeframe": timeframe, "window_id": window_id, "source": "a1_semantic_decision_calendar", "post_2026_decision_row": bool(decision >= PROTECTED_TS)})
                ukey = (str(d.get("universe_policy_hash", "")), str(d.get("universe_policy", "")), str(d.get("top_major_target_size", "")), str(d.get("tier_ab_target_size", "")), decision.isoformat())
                if ukey not in universe_cache:
                    symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(ctx, d, panel, decision)
                    universe_cache[ukey] = symbols
                    for sym in symbols:
                        universe_rows.append({"universe_policy_hash": d.get("universe_policy_hash", ""), "universe_policy": d.get("universe_policy", ""), "decision_ts": decision.isoformat(), "feature_available_ts": decision.isoformat(), "symbol_id": sym, "symbol": sym, "included": True, "panel_hash": panel_key, "selection_basis": "pit_liquidity_policy_per_decision"})
                policy_symbols = universe_cache[ukey]
                topn_key = (str(d.get("universe_policy_hash", "")), str(d.get("rank_policy_hash", "")), topn, decision.isoformat())
                if topn_key not in topn_cache:
                    scored: list[dict[str, Any]] = []
                    for sym in policy_symbols:
                        sym_key = (sym, window_id)
                        if sym_key not in symbol_frames:
                            symbol_frames[sym_key] = a1_load_symbol_bars_window(paths, sym, ts_utc(w["feature_warmup_start"]) - pd.Timedelta(days=5), ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                        if sym_key not in rank_panels:
                            rank_panels[sym_key] = a1_rank_panel_from_bars(symbol_frames[sym_key])
                        rkey = (sym, decision.isoformat(), rank_metric, lookback)
                        if rkey not in rank_feature_cache:
                            score, source_ts = a1_rank_score_from_panel(rank_panels[sym_key], decision, lookback, rank_metric)
                            rank_feature_cache[rkey] = {"score": score, "source_ts": source_ts}
                            rank_rows.append({"rank_feature_hash": d.get("rank_policy_hash", ""), "symbol_id": sym, "symbol": sym, "decision_ts": decision.isoformat(), "feature_available_ts": source_ts, "rank_metric": rank_metric, "lookback_days": lookback, "rank_score": score if math.isfinite(score) else "", "rank_score_available": bool(math.isfinite(score) and source_ts), "invalid_reason": "" if math.isfinite(score) and source_ts else "rank_feature_unavailable"})
                        bundle = rank_feature_cache[rkey]
                        score = safe_float(bundle.get("score", np.nan), np.nan)
                        source_ts = str(bundle.get("source_ts", ""))
                        if math.isfinite(score) and source_ts and ts_utc(source_ts) < decision:
                            scored.append({"symbol": sym, "rank_score": score, "feature_available_ts": source_ts, "tie_break_hash": stable_hash(d.get("rank_policy_hash", ""), sym, n=16)})
                        elif source_ts and ts_utc(source_ts) > decision:
                            leak_violations += 1
                    scored_df = pd.DataFrame(scored)
                    if scored_df.empty:
                        topn_df = pd.DataFrame(columns=["symbol", "rank_score", "feature_available_ts", "rank"])
                    else:
                        topn_df = scored_df.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort").head(topn).copy()
                        topn_df["rank"] = np.arange(1, len(topn_df) + 1)
                    if universe_symbols_are_alphabetical_first_n(topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), symbols_all):
                        static_topn_failures += 1
                    topn_cache[topn_key] = topn_df
                    selected_hash = stable_hash(*topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), n=24) if not topn_df.empty else stable_hash("empty", n=24)
                    for _, tr in topn_df.iterrows():
                        topn_rows.append({"topn_policy_hash": a1_policy_hash("topn", d.get("universe_policy_hash", ""), d.get("rank_policy_hash", ""), topn, n=32), "decision_ts": decision.isoformat(), "feature_available_ts": tr.get("feature_available_ts", ""), "symbol_id": tr.get("symbol", ""), "symbol": tr.get("symbol", ""), "rank": int(tr.get("rank", 0)), "rank_score": tr.get("rank_score", ""), "top_n_pass": True, "rank_population_count": int(len(scored_df)), "selected_topn_symbols_hash": selected_hash, "topn_selection_basis": "per_decision_pit_rank_score_with_hash_tiebreak"})
                for _, top_row in topn_cache[topn_key].iterrows():
                    sym = str(top_row.get("symbol", ""))
                    sym_key = (sym, window_id)
                    ckey = (sym, timeframe, window_id)
                    if ckey not in completed_cache:
                        completed_cache[ckey] = completed_ohlcv_frame(symbol_frames.get(sym_key, pd.DataFrame()), timeframe)
                        if not completed_cache[ckey].empty and "source_ts" in completed_cache[ckey].columns:
                            completed_cache[ckey]["source_ts"] = pd.to_datetime(completed_cache[ckey]["source_ts"], utc=True, errors="coerce")
                    fkey = (feature_spec_hash, sym, timeframe, decision.isoformat())
                    if fkey not in raw_feature_cache:
                        raw_features = a1_raw_feature_bundle_from_completed(d, completed_cache[ckey], decision)
                        raw_feature_cache[fkey] = raw_features
                        base_row = {"feature_spec_hash": feature_spec_hash, "candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol_id": sym, "symbol": sym, "decision_ts": decision.isoformat(), "feature_available_ts": raw_features.get("feature_available_ts", ""), "window_id": window_id}
                        impulse_rows.append({**base_row, "impulse_return": raw_features.get("impulse_return", ""), "impulse_threshold": d.get("impulse_return_threshold", ""), "feature_status": raw_features.get("status", "")})
                        compression_rows.append({**base_row, "compression_required": d.get("compression_required", ""), "rv_percentile": raw_features.get("rv_percentile", ""), "base_width_pct": raw_features.get("base_width_pct", ""), "range_slope": raw_features.get("range_slope", ""), "feature_status": raw_features.get("status", "")})
                    features = raw_feature_cache[fkey]
                    signal_pass, signal_status = a1_signal_pass_from_raw_features(d, features)
                    base_row = {"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol_id": sym, "symbol": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "definition_lane": d.get("definition_lane", ""), "decision_ts": decision.isoformat(), "feature_available_ts": features.get("feature_available_ts", ""), "window_id": window_id}
                    signal_rows.append({**base_row, "signal_policy_hash": d.get("signal_policy_hash", ""), "breakout_trigger": d.get("breakout_trigger", ""), "signal_pass": signal_pass, "signal_status": signal_status, "current_close": features.get("current_close", ""), "base_high": features.get("base_high", ""), "base_low": features.get("base_low", "")})
                    if sym not in funding_frames:
                        funding_frames[sym] = load_funding(paths, sym, ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                    parent_key = (str(d.get("parent_gate_policy_hash", "")), decision.isoformat())
                    if parent_key not in parent_gate_cache:
                        parent_gate_cache[parent_key] = a1_parent_gate(d, symbol_frames.get(sym_key, pd.DataFrame()), decision)
                    parent = parent_gate_cache[parent_key]
                    funding_key = (str(d.get("funding_gate_policy_hash", "")), sym, decision.isoformat())
                    if funding_key not in funding_gate_cache:
                        funding_gate_cache[funding_key] = a1_funding_gate(d, funding_frames.get(sym, pd.DataFrame()), decision)
                    funding_gate = funding_gate_cache[funding_key]
                    parent_rows.append({**base_row, "feature_available_ts": parent.get("feature_source_ts", ""), "parent_gate_policy_hash": d.get("parent_gate_policy_hash", ""), "parent_regime_gate": d.get("parent_regime_gate", ""), "parent_gate_pass": bool(parent.get("allowed", False)), "parent_gate_status": parent.get("status", ""), "parent_gate_cap": parent.get("cap", ""), "source_ts_lte_decision": bool(parent.get("source_ts_lte_decision", True))})
                    funding_rows.append({**base_row, "feature_available_ts": funding_gate.get("feature_source_ts", ""), "funding_gate_policy_hash": d.get("funding_gate_policy_hash", ""), "funding_gate": d.get("funding_gate", ""), "funding_gate_pass": bool(funding_gate.get("allowed", False)), "funding_gate_status": funding_gate.get("status", ""), "funding_gate_cap": funding_gate.get("cap", ""), "funding_exact_available": bool(funding_gate.get("funding_exact_available", False))})
                    feature_times = [x for x in [features.get("feature_available_ts", ""), parent.get("feature_source_ts", ""), funding_gate.get("feature_source_ts", ""), top_row.get("feature_available_ts", "")] if x]
                    for ft in feature_times:
                        if ts_utc(ft) > decision:
                            leak_violations += 1
                    if not (signal_pass and bool(parent.get("allowed", False)) and bool(funding_gate.get("allowed", False))):
                        continue
                    cap_reasons = [x for x in [str(d.get("label_cap_reason", "")), str(d.get("a1_universe_cap_reason", "")), str(parent.get("cap", "")), str(funding_gate.get("cap", "")), "oi_omitted_or_sidecar_cap" if str(d.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "", "short_diagnostic" if str(d.get("definition_lane", "")) == "short_diagnostic" else ""] if x and x.lower() not in {"nan", "none"}]
                    identity_hash = build_candidate_identity_hash({"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol": sym, "symbol_id": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "universe_policy_hash": str(d.get("universe_policy_hash", "")), "rank_policy_hash": str(d.get("rank_policy_hash", "")), "signal_policy_hash": str(d.get("signal_policy_hash", "")), "parent_gate_policy_hash": str(d.get("parent_gate_policy_hash", "")), "funding_gate_policy_hash": str(d.get("funding_gate_policy_hash", "")), "event_semantics_version": "a1_compression_selected_key_v1", "input_manifest_hash": a1_manifest_hash(), "train_window_hash": stable_hash(ctx.start, ctx.end, n=16)})
                    selected_rows.append({"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "candidate_identity_hash": identity_hash, "symbol_id": sym, "symbol": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "definition_lane": d.get("definition_lane", ""), "decision_ts": decision.isoformat(), "entry_policy": "next_5m_open_after_decision", "feature_available_ts": max([str(x) for x in feature_times if x], default=decision.isoformat()), "label_cap_reason": ";".join(sorted(set(cap_reasons))), "selected_event_key_source": f"a1_semantic_cache_join_{label}", "event_sampling_used": False, "event_caps_used": False})
        if def_idx == 1 or def_idx == total_defs or def_idx % 16 == 0:
            elapsed = time.time() - t0
            a1_write_heartbeat(ctx, heartbeat_stage, heartbeat_filename=heartbeat_filename, benchmark_label=label, semantic_specs_completed=len(raw_feature_cache), definitions_processed=def_idx, total_definitions=total_defs, selected_event_keys_so_far=len(selected_rows), elapsed_seconds=elapsed, recent_throughput_definitions_per_sec=def_idx / max(elapsed, 1e-9))
    tables = {
        "decision_calendar": pd.DataFrame(decision_rows),
        "liquid_universe": pd.DataFrame(universe_rows),
        "leader_rank": pd.DataFrame(rank_rows),
        "topn_membership": pd.DataFrame(topn_rows),
        "impulse_base_feature": pd.DataFrame(impulse_rows),
        "compression_feature": pd.DataFrame(compression_rows),
        "breakout_signal": pd.DataFrame(signal_rows),
        "parent_gate": pd.DataFrame(parent_rows),
        "funding_gate": pd.DataFrame(funding_rows),
        "selected_event_keys_raw": pd.DataFrame(selected_rows),
    }
    selected_raw = tables["selected_event_keys_raw"].copy()
    if not selected_raw.empty:
        selected_raw["decision_ts"] = pd.to_datetime(selected_raw["decision_ts"], utc=True, errors="coerce")
        selected_frozen, selected_hash = freeze_selected_event_keys(selected_raw)
        selected_out = selected_raw.merge(selected_frozen, on=["candidate_identity_hash", "symbol_id", "decision_ts"], how="left")
    else:
        selected_frozen, selected_hash = (pd.DataFrame(columns=["candidate_identity_hash", "symbol_id", "decision_ts", "selected_event_keys_hash", "selected_event_keys_frozen"]), stable_hash(f"a1_{label}_empty_selected_event_keys"))
        selected_out = selected_frozen
    tables["selected_event_keys"] = selected_out
    manifests: list[dict[str, Any]] = []
    if write_outputs:
        inventory_path = ctx.run_root / ("audit/a1_full_manifest_semantic_spec_inventory.csv" if output_prefix == "a1" else f"audit/{output_prefix}_semantic_cache_hash_audit.csv")
        write_csv(inventory_path, a1_extract_semantic_spec_inventory(load_a1_compression_manifest(), ctx))
        manifests.extend([
            write_a1_cache_table(ctx, f"{output_prefix}_decision_calendar", "decision_calendar", tables["decision_calendar"], ["calendar_hash", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "decision_calendar"}),
            write_a1_cache_table(ctx, f"{output_prefix}_universe_membership", "universe_membership", tables["liquid_universe"], ["universe_policy_hash", "decision_ts", "symbol_id"], {"family": "a1_compression", "benchmark_label": label, "cache": "pit_universe_membership"}),
            write_a1_cache_table(ctx, f"{output_prefix}_leader_rank", "a1_leader_rank", tables["leader_rank"], ["rank_feature_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "leader_rank"}),
            write_a1_cache_table(ctx, f"{output_prefix}_topn_membership", "a1_topn", tables["topn_membership"], ["topn_policy_hash", "decision_ts", "rank", "symbol_id"], {"family": "a1_compression", "benchmark_label": label, "cache": "topn_membership"}),
            write_a1_cache_table(ctx, f"{output_prefix}_impulse_base_feature", "a1_impulse_base_feature", tables["impulse_base_feature"], ["feature_spec_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "impulse_base_features"}),
            write_a1_cache_table(ctx, f"{output_prefix}_compression_feature", "a1_compression_feature", tables["compression_feature"], ["feature_spec_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "compression_features"}),
            write_a1_cache_table(ctx, f"{output_prefix}_breakout_signal", "a1_breakout_signal", tables["breakout_signal"], ["candidate_definition_id", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "breakout_signal_mask"}),
            write_a1_cache_table(ctx, f"{output_prefix}_parent_gate", "parent_gate", tables["parent_gate"], ["parent_gate_policy_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "parent_gate"}),
            write_a1_cache_table(ctx, f"{output_prefix}_funding_gate", "funding_gate", tables["funding_gate"], ["funding_gate_policy_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "cache": "funding_gate"}),
            write_a1_cache_table(ctx, f"{output_prefix}_selected_event_key", "selected_event_key", selected_out, ["candidate_identity_hash", "symbol_id", "decision_ts"], {"family": "a1_compression", "benchmark_label": label, "selected_event_key_hash": selected_hash}, selected_event_key_hash=selected_hash),
        ])
        write_json(ctx.run_root / f"cache/{output_prefix}_selected_event_key_freeze_summary.json", {"selected_event_keys_frozen": True, "selected_event_key_count": int(len(selected_out)), "selected_event_key_hash": selected_hash, "benchmark_label": label, "hash_scope": f"{label}_selected_event_keys", "ts_utc": utc_now()})
    return {"tables": tables, "selected_hash": selected_hash, "manifests": manifests, "leak_violations": leak_violations, "static_topn_failures": static_topn_failures, "runtime_seconds": time.time() - t0, "peak_rss_bytes": current_rss_bytes()}


def a1_selected_key_consistency_from_current_root(ctx: Context, *, cache_name: str = "a1_selected_event_key", include_decision_summary: bool = False) -> pd.DataFrame:
    summary = read_json(ctx.run_root / f"cache/{cache_name}_freeze_summary.json", {})
    manifest = read_csv_safe(ctx.run_root / "cache" / f"{cache_name}_manifest.csv")
    shard_paths = sorted((ctx.run_root / "cache" / f"{cache_name}_shards").glob(f"{cache_name}_part_*.csv"))
    expected = str(summary.get("selected_event_key_hash", ""))
    rows = [
        {"source": "freeze_summary", "selected_event_key_hash": expected, "matches": bool(expected), "status": "pass" if expected else "fail"},
    ]
    if include_decision_summary:
        decision_hash = str(read_json(ctx.run_root / "decision_summary.json", {}).get("selected_event_key_hash", ""))
        rows.append({"source": "decision_summary", "selected_event_key_hash": decision_hash, "matches": bool(expected and decision_hash == expected), "status": "pass" if expected and decision_hash == expected else "fail"})
    if not manifest.empty:
        mhash = str(manifest.get("selected_event_key_hash", pd.Series([""])).iloc[0])
        rows.append({"source": "manifest_column", "selected_event_key_hash": mhash, "matches": bool(expected and mhash == expected), "status": "pass" if expected and mhash == expected else "fail"})
        try:
            pf = json.loads(str(manifest.get("policy_fields", pd.Series(["{}"])).iloc[0]))
        except Exception:
            pf = {}
        phash = str(pf.get("selected_event_key_hash", ""))
        rows.append({"source": "manifest_policy_fields", "selected_event_key_hash": phash, "matches": bool(expected and phash == expected), "status": "pass" if expected and phash == expected else "fail"})
    else:
        rows.append({"source": "manifest_missing", "selected_event_key_hash": "", "matches": False, "status": "fail"})
    vals: set[str] = set()
    for shard_path in shard_paths:
        shard = read_csv_safe(shard_path)
        if not shard.empty and "selected_event_keys_hash" in shard.columns:
            vals.update(shard["selected_event_keys_hash"].dropna().astype(str).tolist())
    if vals:
        rows.append({"source": "selected_key_shard_rows", "selected_event_key_hash": ";".join(sorted(vals)), "matches": bool(expected and vals == {expected}), "status": "pass" if expected and vals == {expected} else "fail"})
    else:
        rows.append({"source": "selected_key_shard_missing_or_hash_column_missing", "selected_event_key_hash": "", "matches": False, "status": "fail"})
    return pd.DataFrame(rows)


def a1_streaming_cache_specs(output_prefix: str) -> dict[str, dict[str, Any]]:
    return {
        "decision_calendar": {"name": f"{output_prefix}_decision_calendar", "cache_class": "decision_calendar", "sort_keys": ["calendar_hash", "decision_ts"]},
        "liquid_universe": {"name": f"{output_prefix}_universe_membership", "cache_class": "universe_membership", "sort_keys": ["universe_policy_hash", "decision_ts", "symbol_id"]},
        "leader_rank": {"name": f"{output_prefix}_leader_rank", "cache_class": "a1_leader_rank", "sort_keys": ["rank_feature_hash", "symbol_id", "decision_ts"]},
        "topn_membership": {"name": f"{output_prefix}_topn_membership", "cache_class": "a1_topn", "sort_keys": ["topn_policy_hash", "decision_ts", "rank", "symbol_id"]},
        "impulse_base_feature": {"name": f"{output_prefix}_impulse_base_feature", "cache_class": "a1_impulse_base_feature", "sort_keys": ["feature_spec_hash", "symbol_id", "decision_ts"]},
        "compression_feature": {"name": f"{output_prefix}_compression_feature", "cache_class": "a1_compression_feature", "sort_keys": ["feature_spec_hash", "symbol_id", "decision_ts"]},
        "breakout_signal": {"name": f"{output_prefix}_breakout_signal", "cache_class": "a1_breakout_signal", "sort_keys": ["candidate_definition_id", "symbol_id", "decision_ts"]},
        "parent_gate": {"name": f"{output_prefix}_parent_gate", "cache_class": "parent_gate", "sort_keys": ["parent_gate_policy_hash", "symbol_id", "decision_ts"]},
        "funding_gate": {"name": f"{output_prefix}_funding_gate", "cache_class": "funding_gate", "sort_keys": ["funding_gate_policy_hash", "symbol_id", "decision_ts"]},
    }


def a1_streaming_manifest_is_complete(row: Mapping[str, Any]) -> bool:
    if str(row.get("status", "")) != "pass":
        return False
    if parse_bool_value(row.get("temp_shard", False), default=False):
        return False
    if str(row.get("shard_path", "")) == "" or str(row.get("content_hash", "")) == "":
        return False
    validation = validate_semantic_cache_manifest(row, expected={"semantic_cache_hash": str(row.get("semantic_cache_hash", ""))})
    return str(validation.get("status", "")) == "pass"


def a1_write_streaming_cache_shard(
    ctx: Context,
    *,
    cache_name: str,
    cache_class: str,
    rows: Sequence[Mapping[str, Any]],
    sort_keys: Sequence[str],
    policy_fields: Mapping[str, Any],
    shard_index: int,
    selected_event_key_hash: str = "",
    temp_shard: bool = False,
) -> dict[str, Any] | None:
    if not rows:
        return None
    df = pd.DataFrame(list(rows))
    shard_root = ctx.run_root / "cache" / (f"{cache_name}_tmp_shards" if temp_shard else f"{cache_name}_shards")
    shard_root.mkdir(parents=True, exist_ok=True)
    final_path = shard_root / f"{cache_name}_part_{shard_index:05d}.csv"
    tmp_path = final_path.with_suffix(final_path.suffix + ".tmp")
    write_csv(tmp_path, df)
    os.replace(tmp_path, final_path)
    manifest = semantic_cache_manifest(
        cache_class=cache_class,
        df=df,
        sort_keys=[c for c in sort_keys if c in df.columns],
        policy_fields={**dict(policy_fields), "shard_index": shard_index, "temp_shard": temp_shard},
        input_manifest_hash=a1_manifest_hash(),
        data_hash=stable_hash(resolve_path(ctx.args.kraken_data_root), ctx.start, ctx.end, n=32),
        protected_train_boundary=str(PROTECTED_TS),
        selected_event_key_hash=selected_event_key_hash,
        path=str(final_path.relative_to(ctx.run_root)),
    )
    row = {
        **manifest,
        "policy_fields": json.dumps(manifest.get("policy_fields", {}), sort_keys=True),
        "canonical_sort_keys": ";".join(manifest.get("canonical_sort_keys", [])),
        "shard_path": str(final_path.relative_to(ctx.run_root)),
        "temp_shard": bool(temp_shard),
        "status": "temp_incomplete" if temp_shard else "pass",
    }
    manifest_path = final_path.with_suffix(final_path.suffix + ".manifest.json")
    write_json(manifest_path, row)
    append_csv(ctx.run_root / "cache" / (f"{cache_name}_tmp_manifest.csv" if temp_shard else f"{cache_name}_manifest.csv"), [row])
    return row


def a1_streaming_selected_key_hash_from_temp_shards(ctx: Context, cache_name: str) -> tuple[str, int, Path]:
    tmp_dir = ctx.run_root / "cache" / f"{cache_name}_tmp_shards"
    paths = sorted(tmp_dir.glob(f"{cache_name}_part_*.csv"))
    if not paths:
        empty_hash = stable_hash(f"{cache_name}_empty_selected_keys", n=64)
        return empty_hash, 0, tmp_dir
    work_dir = ctx.run_root / "tmp" / f"{cache_name}_hash"
    work_dir.mkdir(parents=True, exist_ok=True)
    unsorted = work_dir / "selected_keys.unsorted"
    sorted_path = work_dir / "selected_keys.sorted"
    row_count = 0
    with unsorted.open("w", encoding="utf-8", newline="") as f:
        for path in paths:
            df = read_csv_safe(path)
            if df.empty:
                continue
            for col in ["candidate_identity_hash", "decision_ts", "symbol_id"]:
                if col not in df.columns:
                    raise RuntimeError(f"selected temp shard missing {col}: {path}")
            work = df[["candidate_identity_hash", "decision_ts", "symbol_id"]].fillna("").astype(str)
            for rec in work.itertuples(index=False, name=None):
                f.write(",".join(rec) + "\n")
                row_count += 1
    env = dict(os.environ)
    env["LC_ALL"] = "C"
    with sorted_path.open("w", encoding="utf-8") as out:
        subprocess.run(["sort", str(unsorted)], check=True, stdout=out, env=env)
    h = hashlib.sha256()
    h.update(b"candidate_identity_hash,decision_ts,symbol_id\n")
    with sorted_path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest(), row_count, sorted_path


def a1_finalize_streaming_selected_event_key_shards(ctx: Context, *, cache_name: str, selected_event_key_hash: str) -> list[dict[str, Any]]:
    tmp_dir = ctx.run_root / "cache" / f"{cache_name}_tmp_shards"
    manifests: list[dict[str, Any]] = []
    for idx, path in enumerate(sorted(tmp_dir.glob(f"{cache_name}_part_*.csv"))):
        df = read_csv_safe(path)
        if df.empty:
            continue
        df["selected_event_keys_hash"] = selected_event_key_hash
        df["selected_event_keys_frozen"] = True
        row = a1_write_streaming_cache_shard(
            ctx,
            cache_name=cache_name,
            cache_class="selected_event_key",
            rows=df.to_dict("records"),
            sort_keys=["candidate_identity_hash", "symbol_id", "decision_ts"],
            policy_fields={"family": "a1_compression", "selected_event_key_hash": selected_event_key_hash, "cache": "selected_event_key"},
            shard_index=idx,
            selected_event_key_hash=selected_event_key_hash,
            temp_shard=False,
        )
        if row:
            manifests.append(row)
    write_json(ctx.run_root / f"cache/{cache_name}_freeze_summary.json", {
        "selected_event_keys_frozen": True,
        "selected_event_key_hash": selected_event_key_hash,
        "selected_event_key_count": int(sum(int(m.get("row_count", 0) or 0) for m in manifests)),
        "hash_scope": "streaming_selected_event_keys_candidate_identity_symbol_decision",
        "ts_utc": utc_now(),
    })
    return manifests


def a1_read_streaming_selected_keys(ctx: Context, cache_name: str) -> pd.DataFrame:
    frames = [read_csv_safe(p) for p in sorted((ctx.run_root / "cache" / f"{cache_name}_shards").glob(f"{cache_name}_part_*.csv"))]
    frames = [f for f in frames if not f.empty]
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def a1_streaming_memory_checkpoint(
    ctx: Context,
    *,
    label: str,
    definitions_done: int,
    total_definitions: int,
    selected_rows_written: int,
    semantic_specs_completed: int,
    open_shard_count: int,
    elapsed: float,
    hard_fail_gib: float = 8.0,
    force_flush_gib: float = 6.0,
    warn_gib: float = 5.0,
) -> str:
    rss = current_rss_bytes()
    action = "continue"
    if rss >= hard_fail_gib * 1024**3:
        action = "hard_fail"
    elif rss >= force_flush_gib * 1024**3:
        action = "force_flush_evict"
    elif rss >= warn_gib * 1024**3:
        action = "warn"
    row = {
        "ts_utc": utc_now(),
        "benchmark_label": label,
        "definitions_done": int(definitions_done),
        "total_definitions": int(total_definitions),
        "selected_rows_written": int(selected_rows_written),
        "semantic_specs_completed": int(semantic_specs_completed),
        "open_shard_count": int(open_shard_count),
        "rss_bytes": int(rss),
        "rss_gib": rss / 1024**3,
        "elapsed_seconds": float(elapsed),
        "recent_throughput_definitions_per_sec": definitions_done / max(elapsed, 1e-9),
        "memory_action": action,
    }
    append_csv(ctx.run_root / "performance/full_train_streaming_timing.csv", [row])
    write_json(ctx.run_root / "performance/full_train_streaming_heartbeat.json", row)
    if action == "hard_fail":
        write_json(ctx.run_root / "decision_summary.json", {
            "run_root": str(ctx.run_root),
            "status": "interrupted_memory_guard",
            "phase_profile": ctx.args.phase_profile,
            "benchmark_label": label,
            "definitions_done": int(definitions_done),
            "total_definitions": int(total_definitions),
            "selected_rows_written": int(selected_rows_written),
            "rss_bytes": int(rss),
            "memory_guard_triggered": True,
            "full_aggregate_launched": False,
            "outcome_cache_built": False,
            "next_recommended_phase": "repair_a1_streaming_memory_next",
            "ts_utc": utc_now(),
        })
        raise MemoryGuardStop(0)
    return action


def a1_build_true_streaming_cache_dry_run(
    ctx: Context,
    definitions: pd.DataFrame,
    *,
    windows: pd.DataFrame,
    label: str,
    output_prefix: str,
    batch_size: int = 4,
) -> dict[str, Any]:
    t0 = time.time()
    paths = data_paths(ctx)
    panel = full_panel_for_launch_gate(ctx)
    if panel.empty:
        raise RuntimeError("A1 true streaming cache builder requires non-empty PIT panel")
    symbols_all = panel.get("symbol", pd.Series(dtype=str)).dropna().astype(str).tolist()
    panel_key = stable_hash(*symbols_all, n=24)
    def_records = [a1_engine_candidate(r.to_dict(), ctx) for _, r in definitions.sort_values("candidate_definition_id", kind="mergesort").iterrows()]
    specs = a1_streaming_cache_specs(output_prefix)
    shard_indices = {k: 0 for k in specs}
    selected_cache_name = f"{output_prefix}_selected_event_key"
    selected_tmp_shards = 0
    selected_rows_written = 0
    semantic_specs_completed = 0
    leak_violations = 0
    static_topn_failures = 0
    peak_rss = current_rss_bytes()
    all_manifests: list[dict[str, Any]] = []

    def flush_rows(rows_by_class: dict[str, list[dict[str, Any]]], selected_rows: list[dict[str, Any]], reason: str) -> None:
        nonlocal selected_tmp_shards, selected_rows_written, peak_rss
        for class_key, rows in rows_by_class.items():
            if not rows:
                continue
            spec = specs[class_key]
            row = a1_write_streaming_cache_shard(
                ctx,
                cache_name=spec["name"],
                cache_class=spec["cache_class"],
                rows=rows,
                sort_keys=spec["sort_keys"],
                policy_fields={"family": "a1_compression", "benchmark_label": label, "cache": class_key, "flush_reason": reason},
                shard_index=shard_indices[class_key],
            )
            if row:
                all_manifests.append(row)
                shard_indices[class_key] += 1
            rows.clear()
        if selected_rows:
            row = a1_write_streaming_cache_shard(
                ctx,
                cache_name=selected_cache_name,
                cache_class="selected_event_key",
                rows=selected_rows,
                sort_keys=["candidate_identity_hash", "symbol_id", "decision_ts"],
                policy_fields={"family": "a1_compression", "benchmark_label": label, "cache": "selected_event_key_tmp", "flush_reason": reason},
                shard_index=selected_tmp_shards,
                temp_shard=True,
            )
            if row:
                selected_tmp_shards += 1
                selected_rows_written += len(selected_rows)
            selected_rows.clear()
        peak_rss = max(peak_rss, current_rss_bytes())

    total_defs = len(def_records)
    definitions_done = 0
    for batch_start in range(0, total_defs, max(1, int(batch_size))):
        batch = def_records[batch_start:batch_start + max(1, int(batch_size))]
        rows_by_class: dict[str, list[dict[str, Any]]] = {k: [] for k in specs}
        selected_rows: list[dict[str, Any]] = []
        symbol_frames: dict[tuple[str, str], pd.DataFrame] = {}
        rank_panels: dict[tuple[str, str], dict[str, Any]] = {}
        completed_cache: dict[tuple[str, str, str], pd.DataFrame] = {}
        funding_frames: dict[str, pd.DataFrame] = {}
        universe_cache: dict[tuple[str, str, str, str, str], list[str]] = {}
        rank_feature_cache: dict[tuple[str, str, str, int], dict[str, Any]] = {}
        topn_cache: dict[tuple[str, str, str, int, int, str], pd.DataFrame] = {}
        raw_feature_cache: dict[tuple[str, str, str, str], dict[str, Any]] = {}
        parent_gate_table_cache: dict[tuple[str, str, str, str], dict[str, dict[str, Any]]] = {}
        funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = {}
        for d in batch:
            cid = str(d.get("candidate_definition_id", ""))
            timeframe = str(d.get("decision_timeframe", d.get("bar_timeframe", "4h")))
            topn = int(safe_float(d.get("leader_top_n", d.get("rank_top_n", 0)), 0))
            lookback = int(safe_float(d.get("lookback_days", a1_rank_lookback_days(d)), a1_rank_lookback_days(d)))
            rank_metric = str(d.get("rank_metric", a1_rank_metric_base(d.get("leader_rank_metric", ""))))
            feature_spec_hash = a1_feature_spec_hash(d)
            for _, w in windows.iterrows():
                window_id = str(w["window_id"])
                decisions = a1_decision_timestamps_for_window(w.to_dict(), timeframe)
                parent_table_key = (str(d.get("parent_gate_policy_hash", "")), str(d.get("parent_regime_gate", "")), timeframe, window_id)
                if parent_table_key not in parent_gate_table_cache:
                    parent_gate_table_cache[parent_table_key] = a1_parent_gate_semantic_table_for_window(d, w.to_dict(), decisions)
                parent_gate_table = parent_gate_table_cache[parent_table_key]
                for decision in decisions:
                    calendar_hash = a1_policy_hash("calendar", timeframe, window_id, w.get("decision_start", ""), w.get("decision_end", ""), n=32)
                    rows_by_class["decision_calendar"].append({"calendar_hash": calendar_hash, "candidate_definition_id": cid, "decision_ts": decision.isoformat(), "feature_available_ts": decision.isoformat(), "decision_timeframe": timeframe, "window_id": window_id, "source": "a1_true_streaming_decision_calendar", "post_2026_decision_row": bool(decision >= PROTECTED_TS)})
                    ukey = (str(d.get("universe_policy_hash", "")), str(d.get("universe_policy", "")), str(d.get("top_major_target_size", "")), str(d.get("tier_ab_target_size", "")), decision.isoformat())
                    if ukey not in universe_cache:
                        symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(ctx, d, panel, decision)
                        universe_cache[ukey] = symbols
                        for sym in symbols:
                            rows_by_class["liquid_universe"].append({"universe_policy_hash": d.get("universe_policy_hash", ""), "universe_policy": d.get("universe_policy", ""), "decision_ts": decision.isoformat(), "feature_available_ts": decision.isoformat(), "symbol_id": sym, "symbol": sym, "included": True, "panel_hash": panel_key, "selection_basis": "pit_liquidity_policy_per_decision"})
                    policy_symbols = universe_cache[ukey]
                    topn_key = (str(d.get("universe_policy_hash", "")), str(d.get("rank_policy_hash", "")), rank_metric, lookback, topn, decision.isoformat())
                    if topn_key not in topn_cache:
                        scored: list[dict[str, Any]] = []
                        for sym in policy_symbols:
                            sym_key = (sym, window_id)
                            if sym_key not in symbol_frames:
                                symbol_frames[sym_key] = a1_load_symbol_bars_window(paths, sym, ts_utc(w["feature_warmup_start"]) - pd.Timedelta(days=5), ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                            if sym_key not in rank_panels:
                                rank_panels[sym_key] = a1_rank_panel_from_bars(symbol_frames[sym_key])
                            rkey = (sym, decision.isoformat(), rank_metric, lookback)
                            if rkey not in rank_feature_cache:
                                score, source_ts = a1_rank_score_from_panel(rank_panels[sym_key], decision, lookback, rank_metric)
                                rank_feature_cache[rkey] = {"score": score, "source_ts": source_ts}
                                rows_by_class["leader_rank"].append({"rank_feature_hash": d.get("rank_policy_hash", ""), "symbol_id": sym, "symbol": sym, "decision_ts": decision.isoformat(), "feature_available_ts": source_ts, "rank_metric": rank_metric, "lookback_days": lookback, "rank_score": score if math.isfinite(score) else "", "rank_score_available": bool(math.isfinite(score) and source_ts), "invalid_reason": "" if math.isfinite(score) and source_ts else "rank_feature_unavailable"})
                            bundle = rank_feature_cache[rkey]
                            score = safe_float(bundle.get("score", np.nan), np.nan)
                            source_ts = str(bundle.get("source_ts", ""))
                            if math.isfinite(score) and source_ts and ts_utc(source_ts) < decision:
                                scored.append({"symbol": sym, "rank_score": score, "feature_available_ts": source_ts, "tie_break_hash": stable_hash(d.get("rank_policy_hash", ""), sym, n=16)})
                            elif source_ts and ts_utc(source_ts) > decision:
                                leak_violations += 1
                        scored_df = pd.DataFrame(scored)
                        if scored_df.empty:
                            topn_df = pd.DataFrame(columns=["symbol", "rank_score", "feature_available_ts", "rank"])
                        else:
                            topn_df = scored_df.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort").head(topn).copy()
                            topn_df["rank"] = np.arange(1, len(topn_df) + 1)
                        if universe_symbols_are_alphabetical_first_n(topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), symbols_all):
                            static_topn_failures += 1
                        topn_cache[topn_key] = topn_df
                        selected_hash = stable_hash(*topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist(), n=24) if not topn_df.empty else stable_hash("empty", n=24)
                        topn_policy_hash = a1_policy_hash("topn", d.get("universe_policy_hash", ""), d.get("rank_policy_hash", ""), rank_metric, lookback, topn, n=32)
                        for _, tr in topn_df.iterrows():
                            rows_by_class["topn_membership"].append({"topn_policy_hash": topn_policy_hash, "decision_ts": decision.isoformat(), "feature_available_ts": tr.get("feature_available_ts", ""), "symbol_id": tr.get("symbol", ""), "symbol": tr.get("symbol", ""), "rank": int(tr.get("rank", 0)), "rank_score": tr.get("rank_score", ""), "top_n_pass": True, "rank_population_count": int(len(scored_df)), "selected_topn_symbols_hash": selected_hash, "topn_selection_basis": "per_decision_pit_rank_score_with_hash_tiebreak"})
                    for _, top_row in topn_cache[topn_key].iterrows():
                        sym = str(top_row.get("symbol", ""))
                        sym_key = (sym, window_id)
                        ckey = (sym, timeframe, window_id)
                        if ckey not in completed_cache:
                            completed_cache[ckey] = completed_ohlcv_frame(symbol_frames.get(sym_key, pd.DataFrame()), timeframe)
                            if not completed_cache[ckey].empty and "source_ts" in completed_cache[ckey].columns:
                                completed_cache[ckey]["source_ts"] = pd.to_datetime(completed_cache[ckey]["source_ts"], utc=True, errors="coerce")
                        fkey = (feature_spec_hash, sym, timeframe, decision.isoformat())
                        if fkey not in raw_feature_cache:
                            raw_features = a1_raw_feature_bundle_from_completed(d, completed_cache[ckey], decision)
                            raw_feature_cache[fkey] = raw_features
                            base_row = {"feature_spec_hash": feature_spec_hash, "candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol_id": sym, "symbol": sym, "decision_ts": decision.isoformat(), "feature_available_ts": raw_features.get("feature_available_ts", ""), "window_id": window_id}
                            rows_by_class["impulse_base_feature"].append({**base_row, "impulse_return": raw_features.get("impulse_return", ""), "impulse_threshold": d.get("impulse_return_threshold", ""), "feature_status": raw_features.get("status", "")})
                            rows_by_class["compression_feature"].append({**base_row, "compression_required": d.get("compression_required", ""), "rv_percentile": raw_features.get("rv_percentile", ""), "base_width_pct": raw_features.get("base_width_pct", ""), "range_slope": raw_features.get("range_slope", ""), "feature_status": raw_features.get("status", "")})
                        features = raw_feature_cache[fkey]
                        signal_pass, signal_status = a1_signal_pass_from_raw_features(d, features)
                        base_row = {"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol_id": sym, "symbol": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "definition_lane": d.get("definition_lane", ""), "decision_ts": decision.isoformat(), "feature_available_ts": features.get("feature_available_ts", ""), "window_id": window_id}
                        rows_by_class["breakout_signal"].append({**base_row, "signal_policy_hash": d.get("signal_policy_hash", ""), "breakout_trigger": d.get("breakout_trigger", ""), "signal_pass": signal_pass, "signal_status": signal_status, "current_close": features.get("current_close", ""), "base_high": features.get("base_high", ""), "base_low": features.get("base_low", "")})
                        if sym not in funding_frames:
                            funding_frames[sym] = load_funding(paths, sym, ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                        parent = parent_gate_table.get(decision.isoformat())
                        if parent is None:
                            parent = a1_parent_gate_from_prepared_frames(d, decision, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)}, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)})
                        funding_key = (str(d.get("funding_gate_policy_hash", "")), sym, decision.isoformat())
                        if funding_key not in funding_gate_cache:
                            funding_gate_cache[funding_key] = a1_funding_gate(d, funding_frames.get(sym, pd.DataFrame()), decision)
                        funding_gate = funding_gate_cache[funding_key]
                        rows_by_class["parent_gate"].append({**base_row, "feature_available_ts": parent.get("feature_source_ts", ""), "parent_gate_policy_hash": d.get("parent_gate_policy_hash", ""), "parent_regime_gate": d.get("parent_regime_gate", ""), "parent_gate_pass": bool(parent.get("allowed", False)), "parent_gate_status": parent.get("status", ""), "parent_gate_cap": parent.get("cap", ""), "source_ts_lte_decision": bool(parent.get("source_ts_lte_decision", True))})
                        rows_by_class["funding_gate"].append({**base_row, "feature_available_ts": funding_gate.get("feature_source_ts", ""), "funding_gate_policy_hash": d.get("funding_gate_policy_hash", ""), "funding_gate": d.get("funding_gate", ""), "funding_gate_pass": bool(funding_gate.get("allowed", False)), "funding_gate_status": funding_gate.get("status", ""), "funding_gate_cap": funding_gate.get("cap", ""), "funding_exact_available": bool(funding_gate.get("funding_exact_available", False))})
                        feature_times = [x for x in [features.get("feature_available_ts", ""), parent.get("feature_source_ts", ""), funding_gate.get("feature_source_ts", ""), top_row.get("feature_available_ts", "")] if x]
                        for ft in feature_times:
                            if ts_utc(ft) > decision:
                                leak_violations += 1
                        if not (signal_pass and bool(parent.get("allowed", False)) and bool(funding_gate.get("allowed", False))):
                            continue
                        cap_reasons = [x for x in [str(d.get("label_cap_reason", "")), str(d.get("a1_universe_cap_reason", "")), str(parent.get("cap", "")), str(funding_gate.get("cap", "")), "oi_omitted_or_sidecar_cap" if str(d.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "", "short_diagnostic" if str(d.get("definition_lane", "")) == "short_diagnostic" else ""] if x and x.lower() not in {"nan", "none"}]
                        identity_hash = build_candidate_identity_hash({"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "symbol": sym, "symbol_id": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "universe_policy_hash": str(d.get("universe_policy_hash", "")), "rank_policy_hash": str(d.get("rank_policy_hash", "")), "signal_policy_hash": str(d.get("signal_policy_hash", "")), "parent_gate_policy_hash": str(d.get("parent_gate_policy_hash", "")), "funding_gate_policy_hash": str(d.get("funding_gate_policy_hash", "")), "event_semantics_version": "a1_compression_selected_key_v1", "input_manifest_hash": a1_manifest_hash(), "train_window_hash": stable_hash(ctx.start, ctx.end, n=16)})
                        selected_rows.append({"candidate_definition_id": cid, "candidate_symbol_id": f"{cid}::{sym}", "candidate_identity_hash": identity_hash, "symbol_id": sym, "symbol": sym, "parameter_vector_hash": str(d.get("parameter_vector_hash", "")), "definition_lane": d.get("definition_lane", ""), "decision_ts": decision.isoformat(), "entry_policy": "next_5m_open_after_decision", "feature_available_ts": max([str(x) for x in feature_times if x], default=decision.isoformat()), "label_cap_reason": ";".join(sorted(set(cap_reasons))), "selected_event_key_source": f"a1_true_streaming_cache_join_{label}", "event_sampling_used": False, "event_caps_used": False})
            definitions_done += 1
            semantic_specs_completed = len(rank_feature_cache) + len(topn_cache) + len(raw_feature_cache) + sum(len(v) for v in parent_gate_table_cache.values()) + len(funding_gate_cache)
            elapsed = time.time() - t0
            action = a1_streaming_memory_checkpoint(ctx, label=label, definitions_done=definitions_done, total_definitions=total_defs, selected_rows_written=selected_rows_written + len(selected_rows), semantic_specs_completed=semantic_specs_completed, open_shard_count=sum(len(v) for v in rows_by_class.values()) + len(selected_rows), elapsed=elapsed)
            if action in {"force_flush_evict", "warn"}:
                flush_rows(rows_by_class, selected_rows, reason=f"memory_{action}")
                symbol_frames.clear(); rank_panels.clear(); completed_cache.clear(); funding_frames.clear(); universe_cache.clear(); rank_feature_cache.clear(); topn_cache.clear(); raw_feature_cache.clear(); parent_gate_table_cache.clear(); funding_gate_cache.clear()
                gc.collect()
        flush_rows(rows_by_class, selected_rows, reason=f"definition_batch_{batch_start}_{batch_start + len(batch) - 1}")
        symbol_frames.clear(); rank_panels.clear(); completed_cache.clear(); funding_frames.clear(); universe_cache.clear(); rank_feature_cache.clear(); topn_cache.clear(); raw_feature_cache.clear(); parent_gate_table_cache.clear(); funding_gate_cache.clear()
        clear_aggregate_caches(ctx, reason="a1_true_streaming_batch_complete", scope=f"{label}:{batch_start}")
        gc.collect()
    selected_hash, selected_count, _ = a1_streaming_selected_key_hash_from_temp_shards(ctx, selected_cache_name)
    selected_manifests = a1_finalize_streaming_selected_event_key_shards(ctx, cache_name=selected_cache_name, selected_event_key_hash=selected_hash)
    all_manifests.extend(selected_manifests)
    final_rss = current_rss_bytes()
    peak_rss = max(peak_rss, final_rss)
    a1_streaming_memory_checkpoint(ctx, label=label, definitions_done=total_defs, total_definitions=total_defs, selected_rows_written=selected_count, semantic_specs_completed=semantic_specs_completed, open_shard_count=0, elapsed=time.time() - t0)
    return {
        "label": label,
        "definitions": int(total_defs),
        "selected_event_key_hash": selected_hash,
        "selected_event_key_rows": int(selected_count),
        "leak_violations": int(leak_violations),
        "static_topn_failures": int(static_topn_failures),
        "peak_rss_bytes": int(peak_rss),
        "runtime_seconds": time.time() - t0,
        "manifests": all_manifests,
        "selected_cache_name": selected_cache_name,
    }


A1_SELECTED_KEY_POLICY_CONTRACT_VERSION = "a1_selected_key_policy_v2_20260711"
A1_SELECTED_KEY_POLICY_FIELDS = (
    "definition_lane", "side", "decision_timeframe", "execution_timeframe", "bar_timeframe",
    "universe_policy", "universe_policy_hash", "top_major_target_size", "tier_ab_target_size",
    "leader_rank_metric", "rank_metric", "rank_lookback_days", "leader_top_n", "rank_top_n",
    "tie_policy", "rank_policy_hash", "parent_regime_gate", "parent_gate_policy_hash",
    "regime_policy_hash", "funding_gate", "funding_gate_policy_hash", "funding_policy_hash",
    "prior_high_proximity_filter", "prior_high_role", "impulse_required", "impulse_lookback_days",
    "impulse_return_threshold", "base_window_days", "pullback_max_pct", "path_smoothness_metric",
    "path_smoothness_threshold", "compression_required", "rv_reference_days",
    "rv_percentile_threshold", "box_width_atr_max", "range_slope_abs_max",
    "contraction_legs_required", "final_contraction_ratio_max", "breakout_trigger",
    "current_bar_reference_policy", "entry_policy_version", "entry_policy_hash",
    "compression_policy_hash",
)
A1_SELECTED_KEY_BOOL_FIELDS = {"impulse_required", "compression_required"}
A1_SELECTED_KEY_INT_FIELDS = {
    "top_major_target_size", "tier_ab_target_size", "rank_lookback_days", "leader_top_n",
    "rank_top_n", "impulse_lookback_days", "base_window_days", "rv_reference_days",
    "contraction_legs_required",
}
A1_SELECTED_KEY_FLOAT_FIELDS = {
    "impulse_return_threshold", "pullback_max_pct", "path_smoothness_threshold",
    "rv_percentile_threshold", "box_width_atr_max", "range_slope_abs_max",
    "final_contraction_ratio_max",
}


def a1_canonical_policy_value(field: str, value: Any) -> Any:
    if value is None or value is pd.NA:
        return None
    try:
        if bool(pd.isna(value)):
            return None
    except (TypeError, ValueError):
        pass
    if field in A1_SELECTED_KEY_BOOL_FIELDS:
        return parse_bool_value(value, default=False)
    if field in A1_SELECTED_KEY_INT_FIELDS:
        number = safe_float(value, np.nan)
        return int(number) if math.isfinite(number) else None
    if field in A1_SELECTED_KEY_FLOAT_FIELDS:
        number = safe_float(value, np.nan)
        return float(format(number, ".15g")) if math.isfinite(number) else None
    if isinstance(value, pd.Timestamp):
        return ts_utc(value).isoformat()
    return str(value).strip()


def a1_selected_key_policy_payload(defn: Mapping[str, Any]) -> dict[str, Any]:
    """Canonical selection-only policy; runtime, outcome, exit and existing hash fields are absent."""
    payload = {field: a1_canonical_policy_value(field, defn.get(field)) for field in A1_SELECTED_KEY_POLICY_FIELDS}
    payload["cache_contract_version"] = A1_SELECTED_KEY_POLICY_CONTRACT_VERSION
    payload["protected_train_boundary"] = ts_utc(PROTECTED_TS).isoformat()
    payload["signal_semantics"] = "completed_close_current_reference_windows_shifted_1_next_5m_open"
    return dict(sorted(payload.items()))


def a1_selected_key_policy_hash(defn: Mapping[str, Any]) -> str:
    payload = a1_selected_key_policy_payload(defn)
    canonical_json = json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=True, allow_nan=False)
    return a1_policy_hash(A1_SELECTED_KEY_POLICY_CONTRACT_VERSION, canonical_json, n=32)


def a1_selected_key_dedup_audit(manifest: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    records: list[dict[str, Any]] = []
    for _, raw in manifest.sort_values("candidate_definition_id", kind="mergesort").iterrows():
        d = a1_engine_candidate(raw.to_dict(), ctx)
        h = a1_selected_key_policy_hash(d)
        records.append({**d, "selected_key_policy_hash": h})
    by_hash: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for d in records:
        by_hash[str(d["selected_key_policy_hash"])].append(d)
    for h, defs in sorted(by_hash.items()):
        exit_ids = sorted({str(d.get("exit_policy_id", "")) for d in defs})
        cids = sorted(str(d.get("candidate_definition_id", "")) for d in defs)
        rows.append({
            "selected_key_policy_hash": h,
            "definition_count": len(defs),
            "entry_spec_id": str(defs[0].get("entry_spec_id", "")),
            "definition_lane": str(defs[0].get("definition_lane", "")),
            "candidate_definition_ids": ";".join(cids),
            "exit_policy_count": len(exit_ids),
            "exit_policy_ids": ";".join(exit_ids),
            "status": "pass" if len(exit_ids) >= 1 else "fail",
        })
    return pd.DataFrame(rows)


def a1_selected_key_spec_records(definitions: pd.DataFrame, ctx: Context) -> tuple[list[dict[str, Any]], pd.DataFrame]:
    records: list[dict[str, Any]] = []
    for _, raw in definitions.sort_values("candidate_definition_id", kind="mergesort").iterrows():
        d = a1_engine_candidate(raw.to_dict(), ctx)
        d["selected_key_policy_hash"] = a1_selected_key_policy_hash(d)
        records.append(d)
    audit = pd.DataFrame([{
        "candidate_definition_id": str(d.get("candidate_definition_id", "")),
        "entry_spec_id": str(d.get("entry_spec_id", "")),
        "exit_policy_id": str(d.get("exit_policy_id", "")),
        "selected_key_policy_hash": str(d.get("selected_key_policy_hash", "")),
        "parameter_vector_hash": str(d.get("parameter_vector_hash", "")),
    } for d in records])
    return records, audit


def a1_selected_key_compiler_shard_count(ctx: Context) -> int:
    return sum(1 for _ in (ctx.run_root / "cache").glob("*_shards/*.csv")) if (ctx.run_root / "cache").exists() else 0


def a1_build_selected_key_compiler_dry_run(
    ctx: Context,
    definitions: pd.DataFrame,
    *,
    windows: pd.DataFrame,
    label: str,
    output_prefix: str,
    max_runtime_seconds: float | None = None,
    flush_threshold: int = 5000,
) -> dict[str, Any]:
    t0 = time.time()
    paths = data_paths(ctx)
    panel = full_panel_for_launch_gate(ctx)
    if panel.empty:
        raise RuntimeError("A1 selected-key compiler requires non-empty PIT panel")
    symbols_all = panel.get("symbol", pd.Series(dtype=str)).dropna().astype(str).tolist()
    panel_key = stable_hash(*symbols_all, n=24)
    input_manifest_hash = a1_manifest_hash()
    train_window_hash = stable_hash(ctx.start, ctx.end, n=16)
    def_records, def_audit = a1_selected_key_spec_records(definitions, ctx)
    write_csv(ctx.run_root / f"diagnostic/{output_prefix}_definition_selected_key_map.csv", def_audit)
    groups: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for d in def_records:
        groups[str(d["selected_key_policy_hash"])].append(d)
    spec_rows = []
    for h, defs in sorted(groups.items()):
        spec_rows.append({
            "benchmark_label": label,
            "selected_key_policy_hash": h,
            "entry_spec_id": str(defs[0].get("entry_spec_id", "")),
            "definition_count": len(defs),
            "fanout_exit_policy_count": len({str(d.get("exit_policy_id", "")) for d in defs}),
            "candidate_definition_ids": ";".join(sorted(str(d.get("candidate_definition_id", "")) for d in defs)),
            "selection_policy_payload_hash": stable_hash(json.dumps(a1_selected_key_policy_payload(defs[0]), sort_keys=True), n=32),
            "status": "pass",
        })

    selected_cache_name = f"{output_prefix}_selected_event_key"
    selected_tmp_shard_index = 0
    selected_rows_written = 0
    selected_rows: list[dict[str, Any]] = []
    universe_summary_rows: list[dict[str, Any]] = []
    topn_summary_rows: list[dict[str, Any]] = []
    feature_summary_rows: list[dict[str, Any]] = []
    timing_rows: list[dict[str, Any]] = []
    leak_violations = 0
    static_topn_failures = 0
    protected_decision_violations = 0
    max_open_buffer_rows = 0
    peak_rss = current_rss_bytes()

    symbol_frames: dict[tuple[str, str], pd.DataFrame] = {}
    rank_panels: dict[tuple[str, str], dict[str, Any]] = {}
    completed_cache: dict[tuple[str, str, str], pd.DataFrame] = {}
    funding_frames: dict[tuple[str, str], dict[str, Any]] = {}
    universe_cache: dict[tuple[str, str, str, str, str], list[str]] = {}
    rank_series_cache: dict[tuple[str, str, str, int, str], dict[str, dict[str, Any]]] = {}
    topn_cache: dict[tuple[str, str, str, int, int, str], pd.DataFrame] = {}
    raw_feature_cache: dict[tuple[str, str, str, str], dict[str, Any]] = {}
    signal_cache: dict[tuple[str, str, str, str], tuple[bool, str]] = {}
    parent_gate_table_cache: dict[tuple[str, str, str, str], dict[str, dict[str, Any]]] = {}
    funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = {}

    def flush_selected(reason: str) -> None:
        nonlocal selected_tmp_shard_index, selected_rows_written, peak_rss
        if not selected_rows:
            return
        row = a1_write_streaming_cache_shard(
            ctx,
            cache_name=selected_cache_name,
            cache_class="selected_event_key",
            rows=selected_rows,
            sort_keys=["candidate_identity_hash", "symbol_id", "decision_ts"],
            policy_fields={"family": "a1_compression", "benchmark_label": label, "cache": "selected_event_key_tmp", "flush_reason": reason, "compiler": "entry_spec_selected_key_v1"},
            shard_index=selected_tmp_shard_index,
            temp_shard=True,
        )
        if row:
            selected_tmp_shard_index += 1
            selected_rows_written += len(selected_rows)
        selected_rows.clear()
        peak_rss = max(peak_rss, current_rss_bytes())

    total_specs = len(groups)
    specs_done = 0
    for spec_hash, fanout_defs in sorted(groups.items()):
        if max_runtime_seconds is not None and time.time() - t0 > max_runtime_seconds:
            timing_rows.append({"benchmark_label": label, "stage": "runtime_gate_stop", "specs_done": specs_done, "total_specs": total_specs, "elapsed_seconds": time.time() - t0, "status": "runtime_gate_stop"})
            break
        d = fanout_defs[0]
        timeframe = str(d.get("decision_timeframe", d.get("bar_timeframe", "4h")))
        topn = int(safe_float(d.get("leader_top_n", d.get("rank_top_n", 0)), 0))
        lookback = int(safe_float(d.get("lookback_days", a1_rank_lookback_days(d)), a1_rank_lookback_days(d)))
        rank_metric = str(d.get("rank_metric", a1_rank_metric_base(d.get("leader_rank_metric", ""))))
        feature_spec_hash = a1_feature_spec_hash(d)
        spec_selected_count = 0
        spec_decision_count = 0
        for _, w in windows.iterrows():
            window_id = str(w["window_id"])
            decisions = a1_decision_timestamps_for_window(w.to_dict(), timeframe)
            parent_table_key = (str(d.get("parent_gate_policy_hash", "")), str(d.get("parent_regime_gate", "")), timeframe, window_id)
            if parent_table_key not in parent_gate_table_cache:
                parent_gate_table_cache[parent_table_key] = a1_parent_gate_semantic_table_for_window(d, w.to_dict(), decisions)
            parent_gate_table = parent_gate_table_cache[parent_table_key]
            for decision in decisions:
                spec_decision_count += 1
                if decision >= PROTECTED_TS:
                    protected_decision_violations += 1
                    continue
                ukey = (str(d.get("universe_policy_hash", "")), str(d.get("universe_policy", "")), str(d.get("top_major_target_size", "")), str(d.get("tier_ab_target_size", "")), decision.isoformat())
                if ukey not in universe_cache:
                    symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(ctx, d, panel, decision)
                    universe_cache[ukey] = symbols
                    universe_summary_rows.append({
                        "benchmark_label": label,
                        "universe_policy_hash": d.get("universe_policy_hash", ""),
                        "universe_policy": d.get("universe_policy", ""),
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": decision.isoformat(),
                        "selected_symbol_count": len(symbols),
                        "selected_symbols_hash": stable_hash(*symbols, n=24),
                        "panel_hash": panel_key,
                        "selection_basis": "pit_liquidity_policy_per_decision_compiler_cache",
                        "alphabetical_first_n_detected": universe_symbols_are_alphabetical_first_n(symbols, symbols_all),
                    })
                policy_symbols = universe_cache[ukey]
                topn_key = (str(d.get("universe_policy_hash", "")), str(d.get("rank_policy_hash", "")), rank_metric, lookback, topn, decision.isoformat())
                if topn_key not in topn_cache:
                    scored: list[dict[str, Any]] = []
                    for sym in policy_symbols:
                        sym_key = (sym, window_id)
                        if sym_key not in symbol_frames:
                            symbol_frames[sym_key] = a1_load_symbol_bars_window(paths, sym, ts_utc(w["feature_warmup_start"]) - pd.Timedelta(days=5), ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                        if sym_key not in rank_panels:
                            rank_panels[sym_key] = a1_rank_panel_from_bars(symbol_frames[sym_key])
                        rkey = (sym, window_id, rank_metric, lookback, timeframe)
                        if rkey not in rank_series_cache:
                            rank_series_cache[rkey] = a1_rank_scores_for_decisions(rank_panels[sym_key], decisions, lookback, rank_metric)
                        bundle = rank_series_cache[rkey].get(decision.isoformat(), {"score": float("nan"), "source_ts": ""})
                        score = safe_float(bundle.get("score", np.nan), np.nan)
                        source_ts = str(bundle.get("source_ts", ""))
                        if math.isfinite(score) and source_ts and ts_utc(source_ts) < decision:
                            scored.append({"symbol": sym, "rank_score": score, "feature_available_ts": source_ts, "tie_break_hash": stable_hash(d.get("rank_policy_hash", ""), sym, n=16)})
                        elif source_ts and ts_utc(source_ts) > decision:
                            leak_violations += 1
                    scored_df = pd.DataFrame(scored)
                    if scored_df.empty:
                        topn_df = pd.DataFrame(columns=["symbol", "rank_score", "feature_available_ts", "rank"])
                    else:
                        topn_df = scored_df.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort").head(topn).copy()
                        topn_df["rank"] = np.arange(1, len(topn_df) + 1)
                    selected_top = topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist()
                    if universe_symbols_are_alphabetical_first_n(selected_top, policy_symbols):
                        static_topn_failures += 1
                    topn_cache[topn_key] = topn_df
                    topn_summary_rows.append({
                        "benchmark_label": label,
                        "topn_policy_hash": a1_policy_hash("topn", d.get("universe_policy_hash", ""), d.get("rank_policy_hash", ""), rank_metric, lookback, topn, n=32),
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": max([str(x) for x in topn_df.get("feature_available_ts", pd.Series(dtype=str)).dropna().astype(str).tolist()], default="") if not topn_df.empty else "",
                        "rank_population_count": int(len(scored_df)),
                        "selected_topn_count": int(len(topn_df)),
                        "selected_topn_symbols_hash": stable_hash(*selected_top, n=24) if selected_top else stable_hash("empty", n=24),
                        "alphabetical_first_n_detected": universe_symbols_are_alphabetical_first_n(selected_top, policy_symbols),
                        "topn_selection_basis": "per_decision_pit_rank_score_with_hash_tiebreak_compiler_cache",
                    })
                for _, top_row in topn_cache[topn_key].iterrows():
                    sym = str(top_row.get("symbol", ""))
                    sym_key = (sym, window_id)
                    ckey = (sym, timeframe, window_id)
                    if ckey not in completed_cache:
                        completed_cache[ckey] = completed_ohlcv_frame(symbol_frames.get(sym_key, pd.DataFrame()), timeframe)
                        if not completed_cache[ckey].empty and "source_ts" in completed_cache[ckey].columns:
                            completed_cache[ckey]["source_ts"] = pd.to_datetime(completed_cache[ckey]["source_ts"], utc=True, errors="coerce")
                    fkey = (feature_spec_hash, sym, timeframe, decision.isoformat())
                    if fkey not in raw_feature_cache:
                        raw_feature_cache[fkey] = a1_raw_feature_bundle_from_completed(d, completed_cache[ckey], decision)
                    features = raw_feature_cache[fkey]
                    skey = (str(d.get("signal_policy_hash", "")), feature_spec_hash, sym, decision.isoformat())
                    if skey not in signal_cache:
                        signal_cache[skey] = a1_signal_pass_from_raw_features(d, features)
                    signal_pass, signal_status = signal_cache[skey]
                    parent = parent_gate_table.get(decision.isoformat())
                    if parent is None:
                        parent = a1_parent_gate_from_prepared_frames(d, decision, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)}, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)})
                    funding_key = (str(d.get("funding_gate_policy_hash", "")), sym, decision.isoformat())
                    if funding_key not in funding_gate_cache:
                        fframe_key = (sym, window_id)
                        if fframe_key not in funding_frames:
                            funding_frames[fframe_key] = a1_prepare_funding_frame(load_funding(paths, sym, ts_utc(w["decision_end"]) + pd.Timedelta(days=20)))
                        funding_gate_cache[funding_key] = a1_funding_gate_from_prepared(d, funding_frames.get(fframe_key, {}), decision)
                    funding_gate = funding_gate_cache[funding_key]
                    feature_times = [x for x in [features.get("feature_available_ts", ""), parent.get("feature_source_ts", ""), funding_gate.get("feature_source_ts", ""), top_row.get("feature_available_ts", "")] if x]
                    for ft in feature_times:
                        if ts_utc(ft) > decision:
                            leak_violations += 1
                    if not (signal_pass and bool(parent.get("allowed", False)) and bool(funding_gate.get("allowed", False))):
                        continue
                    feature_summary_rows.append({
                        "benchmark_label": label,
                        "selected_key_policy_hash": spec_hash,
                        "feature_spec_hash": feature_spec_hash,
                        "signal_policy_hash": d.get("signal_policy_hash", ""),
                        "symbol_id": sym,
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": features.get("feature_available_ts", ""),
                        "signal_status": signal_status,
                        "signal_pass": bool(signal_pass),
                        "parent_gate_status": parent.get("status", ""),
                        "funding_gate_status": funding_gate.get("status", ""),
                    })
                    for fd in fanout_defs:
                        cap_reasons = [x for x in [
                            str(fd.get("label_cap_reason", "")),
                            str(fd.get("a1_universe_cap_reason", "")),
                            str(parent.get("cap", "")),
                            str(funding_gate.get("cap", "")),
                            "oi_omitted_or_sidecar_cap" if str(fd.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "",
                            "short_diagnostic" if str(fd.get("definition_lane", "")) == "short_diagnostic" else "",
                        ] if x and x.lower() not in {"nan", "none"}]
                        cid = str(fd.get("candidate_definition_id", ""))
                        identity_hash = build_candidate_identity_hash({
                            "candidate_definition_id": cid,
                            "candidate_symbol_id": f"{cid}::{sym}",
                            "symbol": sym,
                            "symbol_id": sym,
                            "parameter_vector_hash": str(fd.get("parameter_vector_hash", "")),
                            "universe_policy_hash": str(fd.get("universe_policy_hash", "")),
                            "rank_policy_hash": str(fd.get("rank_policy_hash", "")),
                            "signal_policy_hash": str(fd.get("signal_policy_hash", "")),
                            "parent_gate_policy_hash": str(fd.get("parent_gate_policy_hash", "")),
                            "funding_gate_policy_hash": str(fd.get("funding_gate_policy_hash", "")),
                            "selected_key_policy_hash": spec_hash,
                            "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION,
                            "event_semantics_version": "a1_compression_selected_key_v1",
                            "input_manifest_hash": input_manifest_hash,
                            "train_window_hash": train_window_hash,
                        })
                        selected_rows.append({
                            "candidate_definition_id": cid,
                            "candidate_symbol_id": f"{cid}::{sym}",
                            "candidate_identity_hash": identity_hash,
                            "selected_key_policy_hash": spec_hash,
                            "entry_spec_id": fd.get("entry_spec_id", ""),
                            "exit_policy_id": fd.get("exit_policy_id", ""),
                            "symbol_id": sym,
                            "symbol": sym,
                            "parameter_vector_hash": str(fd.get("parameter_vector_hash", "")),
                            "definition_lane": fd.get("definition_lane", ""),
                            "decision_ts": decision.isoformat(),
                            "entry_policy": "next_5m_open_after_decision",
                            "feature_available_ts": max([str(x) for x in feature_times if x], default=decision.isoformat()),
                            "label_cap_reason": ";".join(sorted(set(cap_reasons))),
                            "selected_event_key_source": f"a1_entry_spec_compiler_{label}",
                            "event_sampling_used": False,
                            "event_caps_used": False,
                        })
                        spec_selected_count += 1
                    max_open_buffer_rows = max(max_open_buffer_rows, len(selected_rows) + len(feature_summary_rows))
                    if max_open_buffer_rows > 10000:
                        raise RuntimeError(f"A1 selected-key compiler exceeded open shard/buffer row limit: {max_open_buffer_rows}")
                    if len(selected_rows) >= flush_threshold:
                        flush_selected(reason=f"{label}_selected_buffer_flush")
        specs_done += 1
        elapsed = time.time() - t0
        timing_rows.append({
            "benchmark_label": label,
            "stage": "selected_key_spec_complete",
            "selected_key_policy_hash": spec_hash,
            "specs_done": specs_done,
            "total_specs": total_specs,
            "fanout_definition_count": len(fanout_defs),
            "decisions_seen": spec_decision_count,
            "selected_rows_for_spec": spec_selected_count,
            "selected_rows_written_or_buffered": selected_rows_written + len(selected_rows),
            "elapsed_seconds": elapsed,
            "rss_bytes": current_rss_bytes(),
            "status": "pass",
        })
        a1_write_heartbeat(
            ctx,
            "a1-compression-selected-key-compiler-repair",
            heartbeat_filename=f"{output_prefix}_compiler_heartbeat.json",
            benchmark_label=label,
            selected_key_specs_completed=specs_done,
            total_selected_key_specs=total_specs,
            definitions_covered=sum(len(v) for _, v in list(sorted(groups.items()))[:specs_done]),
            selected_rows_written_or_buffered=selected_rows_written + len(selected_rows),
            recent_throughput_specs_per_sec=specs_done / max(elapsed, 1e-9),
        )
        peak_rss = max(peak_rss, current_rss_bytes())
    flush_selected(reason=f"{label}_final")
    selected_hash, selected_count, _ = a1_streaming_selected_key_hash_from_temp_shards(ctx, selected_cache_name)
    selected_manifests = a1_finalize_streaming_selected_event_key_shards(ctx, cache_name=selected_cache_name, selected_event_key_hash=selected_hash)
    shard_count = a1_selected_key_compiler_shard_count(ctx)
    if shard_count > 10000:
        raise RuntimeError(f"A1 selected-key compiler produced too many cache shards: {shard_count}")
    runtime = time.time() - t0
    write_csv(ctx.run_root / f"cache/{output_prefix}_pit_universe_membership_manifest.csv", universe_summary_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_topn_membership_manifest.csv", topn_summary_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_feature_mask_manifest.csv", feature_summary_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_selected_key_spec_manifest.csv", spec_rows)
    append_csv(ctx.run_root / "performance/selected_key_compiler_timing.csv", timing_rows)
    return {
        "label": label,
        "definitions": int(len(def_records)),
        "unique_selected_key_specs": int(len(groups)),
        "selected_event_key_hash": selected_hash,
        "selected_event_key_rows": int(selected_count),
        "leak_violations": int(leak_violations),
        "static_topn_failures": int(static_topn_failures),
        "protected_decision_violations": int(protected_decision_violations),
        "peak_rss_bytes": int(max(peak_rss, current_rss_bytes())),
        "runtime_seconds": runtime,
        "selected_cache_name": selected_cache_name,
        "shard_count": int(shard_count),
        "max_open_buffer_rows": int(max_open_buffer_rows),
        "runtime_gate_stopped": bool(max_runtime_seconds is not None and runtime > max_runtime_seconds),
        "selected_manifests": selected_manifests,
    }


def a1_definitions_with_selected_key_hash(manifest: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    records, _ = a1_selected_key_spec_records(manifest, ctx)
    out = pd.DataFrame(records)
    if out.empty:
        return out
    return out.sort_values(["definition_lane", "entry_spec_id", "exit_policy_id", "candidate_definition_id"], kind="mergesort").reset_index(drop=True)


def a1_select_single_selected_key_spec_definitions(manifest: pd.DataFrame, ctx: Context) -> pd.DataFrame:
    hashed = a1_definitions_with_selected_key_hash(manifest, ctx)
    if hashed.empty:
        return hashed
    long_rows = hashed[~hashed["definition_lane"].astype(str).eq("short_diagnostic")].copy()
    if long_rows.empty:
        long_rows = hashed.copy()
    first_hash = str(long_rows.sort_values(["definition_lane", "entry_spec_id", "selected_key_policy_hash"], kind="mergesort")["selected_key_policy_hash"].iloc[0])
    return hashed[hashed["selected_key_policy_hash"].astype(str).eq(first_hash)].reset_index(drop=True)


def a1_select_balanced_selected_key_spec_definitions(manifest: pd.DataFrame, ctx: Context, target_specs: int = 32) -> pd.DataFrame:
    hashed = a1_definitions_with_selected_key_hash(manifest, ctx)
    if hashed.empty:
        return hashed
    spec_summary = hashed.groupby("selected_key_policy_hash", dropna=False).agg(
        definition_lane=("definition_lane", "first"),
        entry_spec_id=("entry_spec_id", "first"),
        definition_count=("candidate_definition_id", "nunique"),
    ).reset_index()
    long_lanes = [
        "a1_impulse_base_breakout",
        "a1_plus_compression",
        "h12_rv_compression_breakout",
        "h13_flat_range_escape",
        "h06_vcp_like_contraction",
    ]
    selected_hashes: list[str] = []
    for lane in long_lanes:
        lane_specs = spec_summary[spec_summary["definition_lane"].astype(str).eq(lane)].sort_values(["entry_spec_id", "selected_key_policy_hash"], kind="mergesort")
        if not lane_specs.empty:
            selected_hashes.append(str(lane_specs["selected_key_policy_hash"].iloc[0]))
    remaining = spec_summary[
        ~spec_summary["selected_key_policy_hash"].astype(str).isin(set(selected_hashes))
        & ~spec_summary["definition_lane"].astype(str).eq("short_diagnostic")
    ].sort_values(["definition_lane", "entry_spec_id", "selected_key_policy_hash"], kind="mergesort")
    for h in remaining["selected_key_policy_hash"].astype(str).tolist():
        if len(selected_hashes) >= target_specs:
            break
        selected_hashes.append(h)
    selected_hashes = selected_hashes[:target_specs]
    return hashed[hashed["selected_key_policy_hash"].astype(str).isin(set(selected_hashes))].reset_index(drop=True)


def a1_build_feature_mask_compiler_dry_run(
    ctx: Context,
    definitions: pd.DataFrame,
    *,
    windows: pd.DataFrame,
    label: str,
    output_prefix: str,
    max_runtime_seconds: float | None = None,
    flush_threshold: int = 5000,
) -> dict[str, Any]:
    t0 = time.time()
    paths = data_paths(ctx)
    panel = full_panel_for_launch_gate(ctx)
    if panel.empty:
        raise RuntimeError("A1 feature-mask compiler requires non-empty PIT panel")
    symbols_all = panel.get("symbol", pd.Series(dtype=str)).dropna().astype(str).tolist()
    panel_key = stable_hash(*symbols_all, n=24)
    input_manifest_hash = a1_manifest_hash()
    train_window_hash = stable_hash(ctx.start, ctx.end, n=16)
    def_records, def_audit = a1_selected_key_spec_records(definitions, ctx)
    write_csv(ctx.run_root / f"diagnostic/{output_prefix}_definition_selected_key_map.csv", def_audit)
    groups: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for d in def_records:
        groups[str(d["selected_key_policy_hash"])].append(d)
    spec_rows: list[dict[str, Any]] = []
    for h, defs in sorted(groups.items()):
        spec_rows.append({
            "benchmark_label": label,
            "selected_key_policy_hash": h,
            "feature_spec_hash": a1_feature_spec_hash(defs[0]),
            "entry_spec_id": str(defs[0].get("entry_spec_id", "")),
            "definition_lane": str(defs[0].get("definition_lane", "")),
            "definition_count": len(defs),
            "fanout_exit_policy_count": len({str(d.get("exit_policy_id", "")) for d in defs}),
            "candidate_definition_ids": ";".join(sorted(str(d.get("candidate_definition_id", "")) for d in defs)),
            "selection_policy_payload_hash": stable_hash(json.dumps(a1_selected_key_policy_payload(defs[0]), sort_keys=True), n=32),
            "status": "pass",
        })

    selected_cache_name = f"{output_prefix}_selected_event_key"
    selected_tmp_shard_index = 0
    selected_rows_written = 0
    selected_rows: list[dict[str, Any]] = []
    universe_summary_rows: list[dict[str, Any]] = []
    topn_summary_rows: list[dict[str, Any]] = []
    feature_mask_manifest_rows: list[dict[str, Any]] = []
    timing_rows: list[dict[str, Any]] = []
    leak_violations = 0
    static_topn_failures = 0
    protected_decision_violations = 0
    funding_gate_count_rows: list[dict[str, Any]] = []
    max_open_buffer_rows = 0
    peak_rss = current_rss_bytes()

    symbol_frames: dict[tuple[str, str], pd.DataFrame] = {}
    rank_panels: dict[tuple[str, str], dict[str, Any]] = {}
    completed_cache: dict[tuple[str, str, str], pd.DataFrame] = {}
    funding_frames: dict[tuple[str, str], dict[str, Any]] = {}
    universe_cache: dict[tuple[str, str, str, str, str], list[str]] = {}
    rank_series_cache: dict[tuple[str, str, str, int, str], dict[str, dict[str, Any]]] = {}
    topn_cache: dict[tuple[str, str, str, int, int, str], pd.DataFrame] = {}
    feature_mask_cache: dict[tuple[str, str, str, str], pd.DataFrame] = {}
    feature_mask_by_decision_cache: dict[tuple[str, str, str, str], dict[str, dict[str, Any]]] = {}
    parent_gate_table_cache: dict[tuple[str, str, str, str], dict[str, dict[str, Any]]] = {}
    funding_gate_cache: dict[tuple[str, str, str], dict[str, Any]] = {}

    def flush_selected(reason: str) -> None:
        nonlocal selected_tmp_shard_index, selected_rows_written, peak_rss
        if not selected_rows:
            return
        row = a1_write_streaming_cache_shard(
            ctx,
            cache_name=selected_cache_name,
            cache_class="selected_event_key",
            rows=selected_rows,
            sort_keys=["candidate_identity_hash", "symbol_id", "decision_ts"],
            policy_fields={"family": "a1_compression", "benchmark_label": label, "cache": "selected_event_key_tmp", "flush_reason": reason, "compiler": "feature_mask_selected_key_v1"},
            shard_index=selected_tmp_shard_index,
            temp_shard=True,
        )
        if row:
            selected_tmp_shard_index += 1
            selected_rows_written += len(selected_rows)
        selected_rows.clear()
        peak_rss = max(peak_rss, current_rss_bytes())

    total_specs = len(groups)
    specs_done = 0
    runtime_gate_stopped = False
    for spec_hash, fanout_defs in sorted(groups.items()):
        if max_runtime_seconds is not None and time.time() - t0 > max_runtime_seconds:
            runtime_gate_stopped = True
            timing_rows.append({"benchmark_label": label, "stage": "runtime_gate_stop", "specs_done": specs_done, "total_specs": total_specs, "elapsed_seconds": time.time() - t0, "status": "runtime_gate_stop"})
            break
        d = fanout_defs[0]
        timeframe = str(d.get("decision_timeframe", d.get("bar_timeframe", "4h")))
        topn = int(safe_float(d.get("leader_top_n", d.get("rank_top_n", 0)), 0))
        lookback = int(safe_float(d.get("lookback_days", a1_rank_lookback_days(d)), a1_rank_lookback_days(d)))
        rank_metric = str(d.get("rank_metric", a1_rank_metric_base(d.get("leader_rank_metric", ""))))
        feature_spec_hash = a1_feature_spec_hash(d)
        spec_selected_count = 0
        spec_decision_count = 0
        spec_feature_masks_built = 0
        spec_pre_funding_gate = 0
        spec_post_funding_gate = 0
        funding_status_counts: dict[str, int] = defaultdict(int)
        for _, w in windows.iterrows():
            window_id = str(w["window_id"])
            decisions = a1_decision_timestamps_for_window(w.to_dict(), timeframe)
            parent_table_key = (str(d.get("parent_gate_policy_hash", "")), str(d.get("parent_regime_gate", "")), timeframe, window_id)
            if parent_table_key not in parent_gate_table_cache:
                parent_gate_table_cache[parent_table_key] = a1_parent_gate_semantic_table_for_window(d, w.to_dict(), decisions)
            parent_gate_table = parent_gate_table_cache[parent_table_key]
            for decision in decisions:
                spec_decision_count += 1
                if decision >= PROTECTED_TS:
                    protected_decision_violations += 1
                    continue
                ukey = (str(d.get("universe_policy_hash", "")), str(d.get("universe_policy", "")), str(d.get("top_major_target_size", "")), str(d.get("tier_ab_target_size", "")), decision.isoformat())
                if ukey not in universe_cache:
                    symbols, _ = tsmom_policy_symbols_at_checkpoint_v3(ctx, d, panel, decision)
                    universe_cache[ukey] = symbols
                    universe_summary_rows.append({
                        "benchmark_label": label,
                        "universe_policy_hash": d.get("universe_policy_hash", ""),
                        "universe_policy": d.get("universe_policy", ""),
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": decision.isoformat(),
                        "selected_symbol_count": len(symbols),
                        "selected_symbols_hash": stable_hash(*symbols, n=24),
                        "panel_hash": panel_key,
                        "selection_basis": "pit_liquidity_policy_per_decision_feature_mask_compiler",
                        "alphabetical_first_n_detected": universe_symbols_are_alphabetical_first_n(symbols, symbols_all),
                    })
                policy_symbols = universe_cache[ukey]
                topn_key = (str(d.get("universe_policy_hash", "")), str(d.get("rank_policy_hash", "")), rank_metric, lookback, topn, decision.isoformat())
                if topn_key not in topn_cache:
                    scored: list[dict[str, Any]] = []
                    for sym in policy_symbols:
                        sym_key = (sym, window_id)
                        if sym_key not in symbol_frames:
                            symbol_frames[sym_key] = a1_load_symbol_bars_window(paths, sym, ts_utc(w["feature_warmup_start"]) - pd.Timedelta(days=5), ts_utc(w["decision_end"]) + pd.Timedelta(days=20))
                        if sym_key not in rank_panels:
                            rank_panels[sym_key] = a1_rank_panel_from_bars(symbol_frames[sym_key])
                        rkey = (sym, window_id, rank_metric, lookback, timeframe)
                        if rkey not in rank_series_cache:
                            rank_series_cache[rkey] = a1_rank_scores_for_decisions(rank_panels[sym_key], decisions, lookback, rank_metric)
                        bundle = rank_series_cache[rkey].get(decision.isoformat(), {"score": float("nan"), "source_ts": ""})
                        score = safe_float(bundle.get("score", np.nan), np.nan)
                        source_ts = str(bundle.get("source_ts", ""))
                        if math.isfinite(score) and source_ts and ts_utc(source_ts) < decision:
                            scored.append({"symbol": sym, "rank_score": score, "feature_available_ts": source_ts, "tie_break_hash": stable_hash(d.get("rank_policy_hash", ""), sym, n=16)})
                        elif source_ts and ts_utc(source_ts) > decision:
                            leak_violations += 1
                    scored_df = pd.DataFrame(scored)
                    if scored_df.empty:
                        topn_df = pd.DataFrame(columns=["symbol", "rank_score", "feature_available_ts", "rank"])
                    else:
                        topn_df = scored_df.sort_values(["rank_score", "tie_break_hash"], ascending=[False, True], kind="mergesort").head(topn).copy()
                        topn_df["rank"] = np.arange(1, len(topn_df) + 1)
                    selected_top = topn_df.get("symbol", pd.Series(dtype=str)).astype(str).tolist()
                    if universe_symbols_are_alphabetical_first_n(selected_top, policy_symbols):
                        static_topn_failures += 1
                    topn_cache[topn_key] = topn_df
                    topn_summary_rows.append({
                        "benchmark_label": label,
                        "topn_policy_hash": a1_policy_hash("topn", d.get("universe_policy_hash", ""), d.get("rank_policy_hash", ""), rank_metric, lookback, topn, n=32),
                        "decision_ts": decision.isoformat(),
                        "feature_available_ts": str(pd.to_datetime(topn_df.get("feature_available_ts", pd.Series(dtype=str)), utc=True, errors="coerce").max()) if not topn_df.empty else "",
                        "rank_population_count": int(len(scored_df)),
                        "selected_topn_count": int(len(topn_df)),
                        "selected_topn_symbols_hash": stable_hash(*selected_top, n=24) if selected_top else stable_hash("empty", n=24),
                        "alphabetical_first_n_detected": universe_symbols_are_alphabetical_first_n(selected_top, policy_symbols),
                        "topn_selection_basis": "per_decision_pit_rank_score_with_hash_tiebreak_feature_mask_compiler",
                    })
                for _, top_row in topn_cache[topn_key].iterrows():
                    sym = str(top_row.get("symbol", ""))
                    sym_key = (sym, window_id)
                    ckey = (sym, timeframe, window_id)
                    if ckey not in completed_cache:
                        completed_cache[ckey] = completed_ohlcv_frame(symbol_frames.get(sym_key, pd.DataFrame()), timeframe)
                        if not completed_cache[ckey].empty and "source_ts" in completed_cache[ckey].columns:
                            completed_cache[ckey]["source_ts"] = pd.to_datetime(completed_cache[ckey]["source_ts"], utc=True, errors="coerce")
                    fmask_key = (feature_spec_hash, sym, timeframe, window_id)
                    if fmask_key not in feature_mask_cache:
                        mask_df = a1_feature_mask_table_from_completed(d, completed_cache[ckey], decisions, feature_spec_hash=feature_spec_hash, symbol_id=sym, window_id=window_id)
                        feature_mask_cache[fmask_key] = mask_df
                        feature_mask_by_decision_cache[fmask_key] = {str(r.get("decision_ts", "")): r for r in mask_df.to_dict("records")}
                        spec_feature_masks_built += 1
                        feature_mask_manifest_rows.append({
                            "benchmark_label": label,
                            "feature_spec_hash": feature_spec_hash,
                            "selected_key_policy_hash": spec_hash,
                            "symbol_id": sym,
                            "decision_timeframe": timeframe,
                            "window_id": window_id,
                            "feature_family_lane": str(d.get("definition_lane", "")),
                            "decision_rows": int(len(mask_df)),
                            "signal_pass_rows": int(parse_bool_series(mask_df.get("signal_pass", pd.Series(dtype=bool)), default=False).sum()) if not mask_df.empty else 0,
                            "min_decision_ts": str(mask_df.get("decision_ts", pd.Series(dtype=str)).min()) if not mask_df.empty else "",
                            "max_decision_ts": str(mask_df.get("decision_ts", pd.Series(dtype=str)).max()) if not mask_df.empty else "",
                            "feature_mask_content_hash": canonical_frame_hash(mask_df[[c for c in ["feature_spec_hash", "symbol_id", "decision_ts", "feature_available_ts", "signal_pass", "signal_status"] if c in mask_df.columns]], sort_keys=[c for c in ["feature_spec_hash", "symbol_id", "decision_ts"] if c in mask_df.columns]) if not mask_df.empty else stable_hash("empty_feature_mask", n=32),
                            "cache_basis": "precomputed_feature_mask_by_spec_symbol_calendar",
                            "status": "pass",
                        })
                    features = feature_mask_by_decision_cache[fmask_key].get(decision.isoformat(), {"status": "feature_mask_missing", "signal_pass": False, "signal_status": "feature_mask_missing", "feature_available_ts": ""})
                    signal_pass = parse_bool_value(features.get("signal_pass", False), default=False)
                    signal_status = str(features.get("signal_status", features.get("status", "feature_unavailable")))
                    parent = parent_gate_table.get(decision.isoformat())
                    if parent is None:
                        parent = a1_parent_gate_from_prepared_frames(d, decision, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)}, {"frame": pd.DataFrame(), "source_ns": np.array([], dtype=np.int64)})
                    funding_key = (str(d.get("funding_gate_policy_hash", "")), sym, decision.isoformat())
                    if funding_key not in funding_gate_cache:
                        fframe_key = (sym, window_id)
                        if fframe_key not in funding_frames:
                            funding_frames[fframe_key] = a1_prepare_funding_frame(load_funding(paths, sym, ts_utc(w["decision_end"]) + pd.Timedelta(days=20)))
                        funding_gate_cache[funding_key] = a1_funding_gate_from_prepared(d, funding_frames.get(fframe_key, {}), decision)
                    funding_gate = funding_gate_cache[funding_key]
                    feature_times = [x for x in [features.get("feature_available_ts", ""), parent.get("feature_source_ts", ""), funding_gate.get("feature_source_ts", ""), top_row.get("feature_available_ts", "")] if x]
                    for ft in feature_times:
                        if ts_utc(ft) > decision:
                            leak_violations += 1
                    signal_parent_pass = signal_pass and bool(parent.get("allowed", False))
                    if signal_parent_pass:
                        spec_pre_funding_gate += 1
                        funding_status_counts[str(funding_gate.get("status", "unknown"))] += 1
                        if bool(funding_gate.get("allowed", False)):
                            spec_post_funding_gate += 1
                    if not (signal_parent_pass and bool(funding_gate.get("allowed", False))):
                        continue
                    for fd in fanout_defs:
                        cap_reasons = [x for x in [
                            str(fd.get("label_cap_reason", "")),
                            str(fd.get("a1_universe_cap_reason", "")),
                            str(parent.get("cap", "")),
                            str(funding_gate.get("cap", "")),
                            "oi_omitted_or_sidecar_cap" if str(fd.get("oi_handling", "")) == "omitted_or_sidecar_cap" else "",
                            "short_diagnostic" if str(fd.get("definition_lane", "")) == "short_diagnostic" else "",
                        ] if x and x.lower() not in {"nan", "none"}]
                        cid = str(fd.get("candidate_definition_id", ""))
                        identity_hash = build_candidate_identity_hash({
                            "candidate_definition_id": cid,
                            "candidate_symbol_id": f"{cid}::{sym}",
                            "symbol": sym,
                            "symbol_id": sym,
                            "parameter_vector_hash": str(fd.get("parameter_vector_hash", "")),
                            "universe_policy_hash": str(fd.get("universe_policy_hash", "")),
                            "rank_policy_hash": str(fd.get("rank_policy_hash", "")),
                            "signal_policy_hash": str(fd.get("signal_policy_hash", "")),
                            "parent_gate_policy_hash": str(fd.get("parent_gate_policy_hash", "")),
                            "funding_gate_policy_hash": str(fd.get("funding_gate_policy_hash", "")),
                            "selected_key_policy_hash": spec_hash,
                            "event_semantics_version": "a1_compression_selected_key_v1",
                            "input_manifest_hash": input_manifest_hash,
                            "train_window_hash": train_window_hash,
                        })
                        selected_rows.append({
                            "candidate_definition_id": cid,
                            "candidate_symbol_id": f"{cid}::{sym}",
                            "candidate_identity_hash": identity_hash,
                            "selected_key_policy_hash": spec_hash,
                            "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION,
                            "feature_spec_hash": feature_spec_hash,
                            "entry_spec_id": fd.get("entry_spec_id", ""),
                            "exit_policy_id": fd.get("exit_policy_id", ""),
                            "symbol_id": sym,
                            "symbol": sym,
                            "parameter_vector_hash": str(fd.get("parameter_vector_hash", "")),
                            "definition_lane": fd.get("definition_lane", ""),
                            "decision_ts": decision.isoformat(),
                            "entry_policy": "next_5m_open_after_decision",
                            "feature_available_ts": max([str(x) for x in feature_times if x], default=decision.isoformat()),
                            "label_cap_reason": ";".join(sorted(set(cap_reasons))),
                            "selected_event_key_source": f"a1_feature_mask_compiler_{label}",
                            "event_sampling_used": False,
                            "event_caps_used": False,
                        })
                        spec_selected_count += 1
                    max_open_buffer_rows = max(max_open_buffer_rows, len(selected_rows) + len(feature_mask_manifest_rows))
                    if max_open_buffer_rows > 10000:
                        raise RuntimeError(f"A1 feature-mask compiler exceeded open shard/buffer row limit: {max_open_buffer_rows}")
                    if len(selected_rows) >= flush_threshold:
                        flush_selected(reason=f"{label}_selected_buffer_flush")
        funding_gate_count_rows.append({
            "benchmark_label": label,
            "selected_key_policy_hash": spec_hash,
            "definition_lane": str(d.get("definition_lane", "")),
            "funding_gate": str(d.get("funding_gate", "")),
            "fanout_definition_count": len(fanout_defs),
            "pre_funding_gate_signal_parent_rows": spec_pre_funding_gate,
            "post_funding_gate_selected_key_rows": spec_post_funding_gate,
            "pre_funding_gate_definition_event_rows": spec_pre_funding_gate * len(fanout_defs),
            "post_funding_gate_definition_event_rows": spec_post_funding_gate * len(fanout_defs),
            "funding_gate_blocked_rows": spec_pre_funding_gate - spec_post_funding_gate,
            "funding_gate_status_distribution": json.dumps(funding_status_counts, sort_keys=True),
            "counts_are_pre_outcome_event_addresses": True,
            "status": "pass",
        })
        specs_done += 1
        elapsed = time.time() - t0
        timing_rows.append({
            "benchmark_label": label,
            "stage": "feature_mask_selected_key_spec_complete",
            "selected_key_policy_hash": spec_hash,
            "feature_spec_hash": feature_spec_hash,
            "specs_done": specs_done,
            "total_specs": total_specs,
            "fanout_definition_count": len(fanout_defs),
            "decisions_seen": spec_decision_count,
            "feature_masks_built": spec_feature_masks_built,
            "selected_rows_for_spec": spec_selected_count,
            "selected_rows_written_or_buffered": selected_rows_written + len(selected_rows),
            "elapsed_seconds": elapsed,
            "rss_bytes": current_rss_bytes(),
            "status": "pass",
        })
        a1_write_heartbeat(
            ctx,
            "a1-compression-feature-mask-compiler-repair",
            heartbeat_filename=f"{output_prefix}_feature_mask_compiler_heartbeat.json",
            benchmark_label=label,
            selected_key_specs_completed=specs_done,
            total_selected_key_specs=total_specs,
            feature_masks_built=len(feature_mask_manifest_rows),
            definitions_covered=sum(len(v) for _, v in list(sorted(groups.items()))[:specs_done]),
            selected_rows_written_or_buffered=selected_rows_written + len(selected_rows),
            recent_throughput_specs_per_sec=specs_done / max(elapsed, 1e-9),
        )
        peak_rss = max(peak_rss, current_rss_bytes())
        flush_selected(reason=f"{label}_selected_key_spec_{specs_done}_complete")
        symbol_frames.clear()
        rank_panels.clear()
        completed_cache.clear()
        funding_frames.clear()
        universe_cache.clear()
        rank_series_cache.clear()
        topn_cache.clear()
        feature_mask_cache.clear()
        feature_mask_by_decision_cache.clear()
        parent_gate_table_cache.clear()
        funding_gate_cache.clear()
        gc.collect()
    flush_selected(reason=f"{label}_final")
    selected_hash, selected_count, _ = a1_streaming_selected_key_hash_from_temp_shards(ctx, selected_cache_name)
    selected_manifests = a1_finalize_streaming_selected_event_key_shards(ctx, cache_name=selected_cache_name, selected_event_key_hash=selected_hash)
    shard_count = a1_selected_key_compiler_shard_count(ctx)
    if shard_count > 10000:
        raise RuntimeError(f"A1 feature-mask compiler produced too many cache shards: {shard_count}")
    runtime = time.time() - t0
    write_csv(ctx.run_root / f"cache/{output_prefix}_pit_universe_membership_manifest.csv", universe_summary_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_topn_membership_manifest.csv", topn_summary_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_feature_spec_manifest.csv", spec_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_feature_mask_manifest.csv", feature_mask_manifest_rows)
    write_csv(ctx.run_root / f"cache/{output_prefix}_selected_key_spec_manifest.csv", spec_rows)
    funding_gate_count_path = ctx.run_root / f"gates/{output_prefix}_funding_gate_pre_post_event_counts.csv"
    write_csv(funding_gate_count_path, funding_gate_count_rows)
    append_csv(ctx.run_root / "performance/feature_mask_compiler_timing.csv", timing_rows)
    return {
        "label": label,
        "definitions": int(len(def_records)),
        "unique_selected_key_specs": int(len(groups)),
        "selected_event_key_hash": selected_hash,
        "selected_event_key_rows": int(selected_count),
        "feature_mask_rows": int(len(feature_mask_manifest_rows)),
        "leak_violations": int(leak_violations),
        "static_topn_failures": int(static_topn_failures),
        "protected_decision_violations": int(protected_decision_violations),
        "peak_rss_bytes": int(max(peak_rss, current_rss_bytes())),
        "runtime_seconds": runtime,
        "selected_cache_name": selected_cache_name,
        "shard_count": int(shard_count),
        "max_open_buffer_rows": int(max_open_buffer_rows),
        "runtime_gate_stopped": bool(runtime_gate_stopped),
        "funding_gate_count_path": str(funding_gate_count_path),
        "selected_manifests": selected_manifests,
    }


def a1_feature_mask_repair_root() -> Path:
    return RESULTS_ROOT / "phase_kraken_a1_compression_feature_mask_compiler_repair_20260709_v1_20260709_112535"


def a1_feature_mask_source_selected_keys(root: Path) -> pd.DataFrame:
    preferred = root / "cache/balanced_32_feature_mask_selected_event_key_shards"
    shard_dirs = [preferred] if preferred.exists() else sorted((root / "cache").glob("*_selected_event_key_shards"))
    frames = [read_csv_safe(p) for shard_dir in shard_dirs for p in sorted(shard_dir.glob("*_selected_event_key_part_*.csv"))]
    frames = [f for f in frames if not f.empty]
    return pd.concat(frames, ignore_index=True, sort=False) if frames else pd.DataFrame()


def a1_feature_mask_source_spec_counts(root: Path) -> pd.DataFrame:
    keys = a1_feature_mask_source_selected_keys(root)
    if keys.empty or "selected_key_policy_hash" not in keys.columns:
        return pd.DataFrame(columns=["selected_key_policy_hash", "definition_lane", "entry_spec_id", "prior_selected_event_rows"])
    group_cols = [c for c in ["selected_key_policy_hash", "definition_lane", "entry_spec_id"] if c in keys.columns]
    return keys.groupby(group_cols, dropna=False).size().reset_index(name="prior_selected_event_rows")


def a1_build_full_shard_plan(ctx: Context, manifest: pd.DataFrame, feature_root: Path | None = None) -> pd.DataFrame:
    hashed = a1_definitions_with_selected_key_hash(manifest, ctx)
    if hashed.empty:
        return pd.DataFrame()
    grouped = hashed.groupby("selected_key_policy_hash", dropna=False).agg(
        definition_lane=("definition_lane", "first"),
        entry_spec_id=("entry_spec_id", "first"),
        definition_count=("candidate_definition_id", "nunique"),
        exit_policy_count=("exit_policy_id", "nunique"),
        candidate_definition_ids=("candidate_definition_id", lambda s: ";".join(sorted(s.dropna().astype(str).unique()))),
        exit_policy_ids=("exit_policy_id", lambda s: ";".join(sorted(s.dropna().astype(str).unique()))),
        feature_spec_hash=("selected_key_policy_hash", lambda s: ""),
    ).reset_index()
    first_defs = hashed.drop_duplicates("selected_key_policy_hash").set_index("selected_key_policy_hash")
    grouped["feature_spec_hash"] = grouped["selected_key_policy_hash"].map(lambda h: a1_feature_spec_hash(first_defs.loc[h].to_dict()) if h in first_defs.index else "")
    counts = a1_feature_mask_source_spec_counts(feature_root or a1_feature_mask_repair_root())
    if not counts.empty:
        by_hash = counts[["selected_key_policy_hash", "prior_selected_event_rows"]].drop_duplicates("selected_key_policy_hash")
        grouped = grouped.merge(by_hash, on="selected_key_policy_hash", how="left")
        if {"definition_lane", "entry_spec_id"}.issubset(set(counts.columns)):
            by_entry = counts.groupby(["definition_lane", "entry_spec_id"], dropna=False)["prior_selected_event_rows"].sum().reset_index(name="prior_selected_event_rows_by_entry")
            grouped = grouped.merge(by_entry, on=["definition_lane", "entry_spec_id"], how="left")
            grouped["prior_selected_event_rows"] = pd.to_numeric(grouped["prior_selected_event_rows"], errors="coerce").fillna(pd.to_numeric(grouped["prior_selected_event_rows_by_entry"], errors="coerce")).fillna(0)
            grouped = grouped.drop(columns=["prior_selected_event_rows_by_entry"], errors="ignore")
    else:
        grouped["prior_selected_event_rows"] = 0
    grouped["prior_selected_event_rows"] = pd.to_numeric(grouped["prior_selected_event_rows"], errors="coerce").fillna(0).astype(int)
    grouped["shard_id"] = grouped.apply(lambda r: f"a1shard_{safe_filename(str(r['definition_lane']))}_{safe_filename(str(r['entry_spec_id']))}_{safe_filename(str(r['selected_key_policy_hash']))[:10]}", axis=1)
    grouped["shard_status"] = "planned"
    grouped["selected_key_policy_contract_version"] = A1_SELECTED_KEY_POLICY_CONTRACT_VERSION
    grouped["first_pack"] = False
    grouped["first_pack_role"] = ""
    grouped["selection_basis"] = "full_manifest_selected_key_policy_hash_group"
    cols = [
        "shard_id", "selected_key_policy_hash", "feature_spec_hash", "definition_lane", "entry_spec_id",
        "definition_count", "exit_policy_count", "candidate_definition_ids", "exit_policy_ids",
        "prior_selected_event_rows", "selected_key_policy_contract_version", "first_pack", "first_pack_role", "selection_basis", "shard_status",
    ]
    return grouped[cols].sort_values(["definition_lane", "entry_spec_id", "selected_key_policy_hash"], kind="mergesort").reset_index(drop=True)


def a1_select_first_pack_shards(shard_plan: pd.DataFrame) -> pd.DataFrame:
    long_lanes = [
        "a1_impulse_base_breakout",
        "a1_plus_compression",
        "h12_rv_compression_breakout",
        "h13_flat_range_escape",
        "h06_vcp_like_contraction",
    ]
    selected: list[pd.Series] = []
    for lane in long_lanes:
        lane_df = shard_plan[shard_plan["definition_lane"].astype(str).eq(lane)].copy()
        lane_df = lane_df[~lane_df["definition_lane"].astype(str).eq("short_diagnostic")]
        if lane_df.empty:
            continue
        if pd.to_numeric(lane_df["prior_selected_event_rows"], errors="coerce").fillna(0).gt(0).any():
            high_pool = lane_df
            high = high_pool.sort_values(["prior_selected_event_rows", "entry_spec_id", "selected_key_policy_hash"], ascending=[False, True, True], kind="mergesort").iloc[0].copy()
        else:
            high_pool = lane_df.sort_values(["entry_spec_id", "selected_key_policy_hash"], kind="mergesort").reset_index(drop=True)
            high = high_pool.iloc[-1].copy()
        high["first_pack_role"] = "broad_or_high_event_count"
        selected.append(high)
        remaining = lane_df[~lane_df["selected_key_policy_hash"].astype(str).eq(str(high["selected_key_policy_hash"]))].copy()
        if remaining.empty:
            continue
        nonzero = remaining[pd.to_numeric(remaining["prior_selected_event_rows"], errors="coerce").fillna(0).gt(0)].copy()
        if nonzero.empty:
            pool = remaining.sort_values(["entry_spec_id", "selected_key_policy_hash"], kind="mergesort").reset_index(drop=True)
            representative = pool.iloc[len(pool) // 2].copy()
            representative["median_distance"] = 0.0
        else:
            pool = nonzero
            median_count = float(pd.to_numeric(pool["prior_selected_event_rows"], errors="coerce").fillna(0).median())
            pool["median_distance"] = (pd.to_numeric(pool["prior_selected_event_rows"], errors="coerce").fillna(0) - median_count).abs()
            representative = pool.sort_values(["median_distance", "prior_selected_event_rows", "entry_spec_id", "selected_key_policy_hash"], ascending=[True, False, True, True], kind="mergesort").iloc[0].copy()
        representative["first_pack_role"] = "standard_representative"
        selected.append(representative)
    out = pd.DataFrame(selected)
    if not out.empty:
        out["first_pack"] = True
        out["selection_basis"] = "deterministic_lane_balanced_high_event_plus_representative_not_first_row"
    return out.reset_index(drop=True)


def a1_definitions_for_selected_key_specs(manifest: pd.DataFrame, ctx: Context, selected_hashes: Iterable[str]) -> pd.DataFrame:
    hashed = a1_definitions_with_selected_key_hash(manifest, ctx)
    return hashed[hashed["selected_key_policy_hash"].astype(str).isin(set(map(str, selected_hashes)))].reset_index(drop=True)


def a1_read_reusable_selected_keys_for_spec(feature_root: Path, selected_key_policy_hash: str, candidate_definition_ids: set[str]) -> pd.DataFrame:
    keys = a1_feature_mask_source_selected_keys(feature_root)
    if keys.empty or "selected_key_policy_hash" not in keys.columns:
        return pd.DataFrame()
    sub = keys[keys["selected_key_policy_hash"].astype(str).eq(str(selected_key_policy_hash))].copy()
    if candidate_definition_ids and "candidate_definition_id" in sub.columns:
        sub = sub[sub["candidate_definition_id"].astype(str).isin(candidate_definition_ids)].copy()
    return sub.reset_index(drop=True)


def a1_hash_selected_keys_frame(selected: pd.DataFrame) -> tuple[pd.DataFrame, str]:
    if selected.empty:
        return selected.copy(), ""
    work = selected.copy()
    work = work.drop(columns=[c for c in ["selected_event_keys_hash", "selected_event_keys_frozen"] if c in work.columns], errors="ignore")
    work["decision_ts"] = pd.to_datetime(work["decision_ts"], utc=True, errors="coerce")
    frozen, selected_hash = freeze_selected_event_keys(work)
    out = work.merge(frozen, on=["candidate_identity_hash", "symbol_id", "decision_ts"], how="left")
    return out, selected_hash


def a1_write_shard_manifest_file(path: Path, payload: Mapping[str, Any]) -> None:
    tmp = path.with_suffix(path.suffix + ".tmp")
    write_json(tmp, dict(payload))
    os.replace(tmp, path)


def a1_validate_finalized_aggregate_shard(run_root: Path, shard_id: str) -> dict[str, Any]:
    shard_dir = run_root / "aggregate_shards" / shard_id
    manifest_path = shard_dir / "shard_manifest.json"
    manifest = read_json(manifest_path, {})
    required = ["selected_key_manifest.csv", "outcome_cache_manifest.csv", "aggregate.csv", "shard_manifest.json"]
    missing = [name for name in required if not (shard_dir / name).exists()]
    if missing:
        return {"status": "fail", "reason": "missing_required_shard_files", "missing": ";".join(missing)}
    if str(manifest.get("status", "")) != "complete":
        return {"status": "fail", "reason": "shard_manifest_not_complete"}
    aggregate = read_csv_safe(shard_dir / "aggregate.csv")
    if aggregate.empty:
        return {"status": "fail", "reason": "empty_aggregate"}
    actual_hash = canonical_frame_hash(aggregate, sort_keys=[c for c in ["candidate_definition_id", "exit_policy_id"] if c in aggregate.columns])
    if actual_hash != str(manifest.get("aggregate_content_hash", "")):
        return {"status": "fail", "reason": "aggregate_hash_mismatch", "expected": manifest.get("aggregate_content_hash", ""), "actual": actual_hash}
    return {**manifest, "status": "pass", "reason": ""}


def a1_shard_selected_key_hash_consistency(shard_id: str, selected_keys: pd.DataFrame, selected_manifest: Mapping[str, Any], selected_hash: str) -> list[dict[str, Any]]:
    row_hashes = sorted(set(selected_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).dropna().astype(str))) if not selected_keys.empty else []
    policy_fields = selected_manifest.get("policy_fields", {})
    if isinstance(policy_fields, str):
        try:
            policy_fields = json.loads(policy_fields)
        except Exception:
            policy_fields = {}
    return [
        {"shard_id": shard_id, "source": "selected_key_hash", "selected_event_key_hash": selected_hash, "matches": bool(selected_hash), "status": "pass" if selected_hash else "fail"},
        {"shard_id": shard_id, "source": "selected_key_manifest_column", "selected_event_key_hash": selected_manifest.get("selected_event_key_hash", ""), "matches": str(selected_manifest.get("selected_event_key_hash", "")) == selected_hash, "status": "pass" if str(selected_manifest.get("selected_event_key_hash", "")) == selected_hash else "fail"},
        {"shard_id": shard_id, "source": "selected_key_manifest_policy_fields", "selected_event_key_hash": policy_fields.get("selected_event_key_hash", ""), "matches": str(policy_fields.get("selected_event_key_hash", "")) == selected_hash, "status": "pass" if str(policy_fields.get("selected_event_key_hash", "")) == selected_hash else "fail"},
        {"shard_id": shard_id, "source": "selected_key_rows", "selected_event_key_hash": ";".join(row_hashes) if row_hashes else selected_hash, "matches": row_hashes == [selected_hash] if len(selected_keys) else bool(selected_hash), "status": "pass" if (row_hashes == [selected_hash] if len(selected_keys) else bool(selected_hash)) else "fail"},
    ]


def a1_execute_economic_shard(ctx: Context, *, shard_row: Mapping[str, Any], definitions: pd.DataFrame, feature_root: Path, windows: pd.DataFrame) -> dict[str, Any]:
    shard_id = str(shard_row.get("shard_id", ""))
    final_dir = ctx.run_root / "aggregate_shards" / shard_id
    validation = a1_validate_finalized_aggregate_shard(ctx.run_root, shard_id) if final_dir.exists() else {"status": "missing"}
    if validation.get("status") == "pass":
        return {**validation, "reused_completed_shard": True}
    tmp_dir = ctx.run_root / "aggregate_shards" / f".tmp_{shard_id}"
    if tmp_dir.exists():
        raise RuntimeError(f"stale temp shard directory exists and is not reusable: {tmp_dir}")
    tmp_dir.mkdir(parents=True, exist_ok=False)
    t0 = time.time()
    peak_rss = current_rss_bytes()
    spec_hash = str(shard_row.get("selected_key_policy_hash", ""))
    candidate_ids = set(definitions["candidate_definition_id"].dropna().astype(str))
    selected_raw = a1_read_reusable_selected_keys_for_spec(feature_root, spec_hash, candidate_ids)
    selected_cache_source = "reused_feature_mask_repair_selected_key_cache" if not selected_raw.empty else "rebuilt_shard_local_selected_key_cache"
    feature_mask_cache_source = "reused_feature_mask_repair_cache" if not selected_raw.empty else "rebuilt_shard_local_feature_mask_inputs_for_selected_key"
    leak_violations = 0
    static_topn_failures = 0
    rebuilt = False
    if selected_raw.empty:
        rebuilt = True
        result = a1_build_feature_mask_compiler_dry_run(ctx, definitions, windows=windows, label=shard_id, output_prefix=shard_id, max_runtime_seconds=1800)
        selected_raw = a1_read_streaming_selected_keys(ctx, str(result.get("selected_cache_name", f"{shard_id}_selected_event_key")))
        leak_violations = int(result.get("leak_violations", 0) or 0)
        static_topn_failures = int(result.get("static_topn_failures", 0) or 0)
    if selected_raw.empty:
        zero_reason = "no_selected_events_after_signal_parent_funding_gates_for_shard"
        selected_hash = stable_hash(shard_id, zero_reason, n=64)
        selected_keys = pd.DataFrame(columns=[
            "candidate_definition_id", "candidate_symbol_id", "candidate_identity_hash", "symbol_id", "symbol",
            "parameter_vector_hash", "definition_lane", "decision_ts", "entry_policy", "feature_available_ts",
            "label_cap_reason", "selected_key_policy_hash", "selected_event_keys_hash", "selected_event_keys_frozen",
        ])
    else:
        row_policy_hashes = set(selected_raw.get("selected_key_policy_hash", pd.Series(dtype=str)).dropna().astype(str))
        if row_policy_hashes != {spec_hash}:
            raise RuntimeError(
                f"selected-key policy lineage mismatch before outcome build: shard={shard_id} "
                f"plan={spec_hash} rows={sorted(row_policy_hashes)}"
            )
        selected_keys, selected_hash = a1_hash_selected_keys_frame(selected_raw)
        zero_reason = ""
    selected_key_start_ts = utc_now()
    selected_manifest = semantic_cache_manifest(
        cache_class="selected_event_key",
        df=selected_keys,
        sort_keys=[c for c in ["candidate_identity_hash", "symbol_id", "decision_ts"] if c in selected_keys.columns],
        policy_fields={"family": "a1_compression", "shard_id": shard_id, "selected_key_policy_hash": spec_hash, "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION, "selected_event_key_hash": selected_hash},
        input_manifest_hash=a1_manifest_hash(),
        data_hash=stable_hash(resolve_path(ctx.args.kraken_data_root), ctx.start, ctx.end, n=32),
        protected_train_boundary=str(PROTECTED_TS),
        selected_event_key_hash=selected_hash,
        path=f"aggregate_shards/{shard_id}/selected_keys.csv",
    )
    selected_manifest["status"] = validate_semantic_cache_manifest(selected_manifest).get("status", "fail")
    selected_manifest["selected_key_policy_contract_version"] = A1_SELECTED_KEY_POLICY_CONTRACT_VERSION
    write_csv(tmp_dir / "selected_keys.csv", selected_keys)
    write_csv(tmp_dir / "selected_key_manifest.csv", [{**selected_manifest, "policy_fields": json.dumps(selected_manifest.get("policy_fields", {}), sort_keys=True), "canonical_sort_keys": ";".join(selected_manifest.get("canonical_sort_keys", []))}])
    selected_key_freeze_ts = utc_now()
    outcome_start_ts = utc_now()
    paths = data_paths(ctx)
    ledger_rows: list[dict[str, Any]] = []
    def_by_id = {str(r.get("candidate_definition_id", "")): r.to_dict() for _, r in definitions.iterrows()}
    if not selected_keys.empty:
        selected_keys["decision_ts"] = pd.to_datetime(selected_keys["decision_ts"], utc=True, errors="coerce")
        min_decision = selected_keys["decision_ts"].min()
        max_decision = selected_keys["decision_ts"].max()
        symbol_cache: dict[str, pd.DataFrame] = {}
        funding_cache: dict[str, pd.DataFrame] = {}
        for _, sel in selected_keys.iterrows():
            sym = str(sel.get("symbol", sel.get("symbol_id", "")))
            if sym not in symbol_cache:
                symbol_cache[sym] = a1_load_symbol_bars_window(paths, sym, min_decision - pd.Timedelta(days=240), max_decision + pd.Timedelta(days=21))
            if sym not in funding_cache:
                funding_cache[sym] = load_funding(paths, sym, max_decision + pd.Timedelta(days=21))
            defn = def_by_id.get(str(sel.get("candidate_definition_id", "")))
            if not defn:
                continue
            ev = a1_outcome_event_from_selected(defn, sel.to_dict(), symbol_cache[sym], funding_cache[sym])
            if ev is not None:
                ev["strategy_evidence_label"] = "train_only_sharded_aggregate_diagnostic_level_1_2_capped_not_validation"
                ledger_rows.append(ev)
            peak_rss = max(peak_rss, current_rss_bytes())
            if peak_rss >= 8 * 1024**3:
                raise RuntimeError(f"A1 sharded aggregate RSS hard stop before kernel OOM: shard={shard_id} rss={peak_rss}")
    ledger = pd.DataFrame(ledger_rows)
    if ledger.empty:
        ledger = pd.DataFrame(columns=[
            "event_id", "event_key", "candidate_definition_id", "definition_lane", "exit_policy_id",
            "selected_key_policy_hash", "symbol", "decision_ts", "entry_ts", "exit_ts", "label_cap_reason",
        ])
    parquet_safe_frame(ledger).to_parquet(tmp_dir / "outcome_events.parquet", index=False, compression="zstd")
    outcome_manifest = semantic_cache_manifest(
        cache_class="interval_outcome",
        df=ledger,
        sort_keys=[c for c in ["candidate_definition_id", "symbol", "decision_ts", "event_id"] if c in ledger.columns],
        policy_fields={"family": "a1_compression", "shard_id": shard_id, "selected_key_policy_hash": spec_hash, "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION, "scope": "shard_only"},
        input_manifest_hash=a1_manifest_hash(),
        data_hash=stable_hash(resolve_path(ctx.args.kraken_data_root), ctx.start, ctx.end, n=32),
        protected_train_boundary=str(PROTECTED_TS),
        selected_event_key_hash=selected_hash,
        path=f"aggregate_shards/{shard_id}/outcome_events.parquet",
    )
    outcome_manifest["status"] = validate_semantic_cache_manifest(outcome_manifest).get("status", "fail")
    outcome_manifest["selected_key_policy_contract_version"] = A1_SELECTED_KEY_POLICY_CONTRACT_VERSION
    write_csv(tmp_dir / "outcome_cache_manifest.csv", [{**outcome_manifest, "policy_fields": json.dumps(outcome_manifest.get("policy_fields", {}), sort_keys=True), "canonical_sort_keys": ";".join(outcome_manifest.get("canonical_sort_keys", []))}])
    zero_event_diagnostic = (
        bool(zero_reason)
        and not definitions.empty
        and definitions.get("definition_lane", pd.Series(dtype=str)).astype(str).eq("short_diagnostic").all()
        and not definitions.get("rankable", pd.Series(True, index=definitions.index)).map(lambda value: parse_bool_value(value, default=True)).any()
    )
    aggregate = a1_zero_event_diagnostic_aggregate(definitions, zero_reason) if zero_event_diagnostic else a1_grouped_aggregate_summary(ledger)
    aggregate_path = tmp_dir / "aggregate.csv"
    write_csv(aggregate_path, aggregate)
    aggregate_for_hash = read_csv_safe(aggregate_path)
    protected_cols = ["decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts", "funding_interval_end_ts", "outcome_interval_end_ts"]
    protected_violations = 0
    for col in protected_cols:
        ts = pd.to_datetime(ledger.get(col, pd.Series(dtype=str)), utc=True, errors="coerce") if not ledger.empty else pd.Series(dtype="datetime64[ns, UTC]")
        protected_violations += int((ts >= PROTECTED_TS).sum()) if len(ts) else 0
    if not selected_keys.empty:
        cap_labels = sorted(set(";".join(selected_keys.get("label_cap_reason", pd.Series(dtype=str)).dropna().astype(str)).split(";")) - {""})
    else:
        definition_caps = definitions.get("label_cap_reason", pd.Series(dtype=str)).dropna().astype(str).tolist()
        cap_labels = sorted((set(";".join(definition_caps).split(";")) | ({"short_diagnostic"} if zero_event_diagnostic else set()) | ({"oi_omitted_or_sidecar_cap"} if definitions.get("oi_handling", pd.Series(dtype=str)).astype(str).eq("omitted_or_sidecar_cap").any() else set())) - {""})
    if len(selected_keys) == 0 and not zero_reason:
        zero_reason = "selected_key_cache_empty_without_reason"
    if aggregate.empty and not zero_reason:
        zero_reason = "outcome_or_aggregate_rows_empty_for_selected_events"
    selected_hash_rows = a1_shard_selected_key_hash_consistency(shard_id, selected_keys, selected_manifest, selected_hash)
    selected_hash_pass = all(str(r.get("status")) == "pass" for r in selected_hash_rows)
    aggregate_hash = canonical_frame_hash(aggregate_for_hash, sort_keys=[c for c in ["candidate_definition_id", "exit_policy_id"] if c in aggregate_for_hash.columns]) if not aggregate_for_hash.empty else stable_hash("empty_a1_shard_aggregate", n=64)
    economic_rows_present = len(selected_keys) > 0 and not aggregate.empty
    precise_empty_diagnostic = zero_event_diagnostic and len(aggregate) == len(definitions) and len(definitions) == 8
    shard_status = "complete" if (economic_rows_present or precise_empty_diagnostic) and selected_hash_pass and protected_violations == 0 and outcome_manifest["status"] == "pass" and selected_manifest["status"] == "pass" else "blocked"
    shard_manifest = {
        "shard_id": shard_id,
        "status": shard_status,
        "reason": zero_reason if precise_empty_diagnostic else ("" if shard_status == "complete" else zero_reason or "shard_gate_failed"),
        "selected_key_policy_hash": spec_hash,
        "selected_key_policy_contract_version": A1_SELECTED_KEY_POLICY_CONTRACT_VERSION,
        "feature_spec_hash": str(shard_row.get("feature_spec_hash", "")),
        "definition_lane": str(shard_row.get("definition_lane", "")),
        "entry_spec_id": str(shard_row.get("entry_spec_id", "")),
        "definition_count": int(len(definitions)),
        "exit_policy_count": int(definitions.get("exit_policy_id", pd.Series(dtype=str)).astype(str).nunique()) if not definitions.empty else 0,
        "selected_event_count": int(len(selected_keys)),
        "outcome_event_count": int(len(ledger)),
        "aggregate_rows": int(len(aggregate)),
        "zero_event_diagnostic": bool(precise_empty_diagnostic),
        "selected_event_key_hash": selected_hash,
        "selected_key_manifest_status": selected_manifest["status"],
        "outcome_cache_manifest_status": outcome_manifest["status"],
        "selected_key_freeze_ts": selected_key_freeze_ts,
        "outcome_cache_start_ts": outcome_start_ts,
        "outcome_after_freeze": ts_utc(outcome_start_ts) >= ts_utc(selected_key_freeze_ts),
        "decision_input_leak_violations": int(leak_violations),
        "static_topn_failures": int(static_topn_failures),
        "protected_interval_violations": int(protected_violations),
        "cap_labels": ";".join(cap_labels),
        "feature_mask_cache_source": feature_mask_cache_source,
        "feature_mask_cache_reused": not bool(rebuilt),
        "rebuilt_shard_local_feature_mask_cache": bool(rebuilt),
        "selected_key_cache_source": selected_cache_source,
        "rebuilt_shard_local_selected_key_cache": bool(rebuilt),
        "newly_built_shard_local_outcome_cache": True,
        "aggregate_content_hash": aggregate_hash,
        "selected_key_manifest_hash": sha256_file(tmp_dir / "selected_key_manifest.csv"),
        "outcome_cache_manifest_hash": sha256_file(tmp_dir / "outcome_cache_manifest.csv"),
        "runtime_seconds": float(time.time() - t0),
        "peak_rss_bytes": int(max(peak_rss, current_rss_bytes())),
        "event_sampling_used": False,
        "event_caps_used": False,
        "ts_utc": utc_now(),
    }
    a1_write_shard_manifest_file(tmp_dir / "shard_manifest.json", shard_manifest)
    os.replace(tmp_dir, final_dir)
    return {**shard_manifest, "reused_completed_shard": False}


def a1_cache_reuse_rows_from_shard_result(result: Mapping[str, Any]) -> list[dict[str, Any]]:
    selected_rebuilt = parse_bool_value(result.get("rebuilt_shard_local_selected_key_cache", False), default=False)
    feature_rebuilt = parse_bool_value(result.get("rebuilt_shard_local_feature_mask_cache", False), default=False)
    feature_reused = parse_bool_value(result.get("feature_mask_cache_reused", False), default=False)
    return [
        {
            "shard_id": result.get("shard_id", ""),
            "cache_class": "feature_mask",
            "cache_action": result.get("feature_mask_cache_source", ""),
            "reused": feature_reused,
            "rebuilt": feature_rebuilt,
            "newly_built": False,
            "status": "pass" if result.get("feature_mask_cache_source", "") else "fail",
        },
        {
            "shard_id": result.get("shard_id", ""),
            "cache_class": "selected_key",
            "cache_action": result.get("selected_key_cache_source", ""),
            "reused": not selected_rebuilt,
            "rebuilt": selected_rebuilt,
            "newly_built": False,
            "status": "pass" if result.get("selected_event_key_hash", "") else "fail",
        },
        {
            "shard_id": result.get("shard_id", ""),
            "cache_class": "outcome",
            "cache_action": "newly_built_shard_local_outcome_cache",
            "reused": False,
            "rebuilt": False,
            "newly_built": True,
            "status": "pass" if result.get("outcome_cache_manifest_status") == "pass" else "fail",
        },
    ]


def a1_reduce_first_pack_shards(ctx: Context, expected_shards: pd.DataFrame) -> dict[str, Any]:
    if len(expected_shards) != 10:
        raise RuntimeError(f"first-pack reducer requires exactly 10 expected shards, found {len(expected_shards)}")
    validations = [a1_validate_finalized_aggregate_shard(ctx.run_root, str(r.get("shard_id", ""))) for _, r in expected_shards.iterrows()]
    complete = [v for v in validations if v.get("status") == "pass"]
    if len(complete) != 10:
        write_csv(ctx.run_root / "shards/shard_status_summary.csv", validations)
        raise RuntimeError(f"first-pack reducer requires 10/10 complete shard manifests, found {len(complete)}/10")
    aggregates = [read_csv_safe(ctx.run_root / "aggregate_shards" / str(v["shard_id"]) / "aggregate.csv") for v in complete]
    combined = pd.concat([a for a in aggregates if not a.empty], ignore_index=True, sort=False) if aggregates else pd.DataFrame()
    (ctx.run_root / "aggregate").mkdir(parents=True, exist_ok=True)
    write_csv(ctx.run_root / "aggregate/first_pack_grouped_aggregate.csv", combined)
    scorecard = combined.sort_values(["net_R", "events"], ascending=[False, False], kind="mergesort") if not combined.empty and "net_R" in combined.columns else combined
    write_csv(ctx.run_root / "aggregate/definition_scorecard.csv", scorecard)
    lane = combined.groupby("definition_lane", dropna=False).agg(events=("events", "sum"), definitions=("candidate_definition_id", "nunique"), net_R=("net_R", "sum"), gross_R=("gross_R", "sum")).reset_index() if not combined.empty else pd.DataFrame(columns=["definition_lane", "events", "definitions", "net_R", "gross_R"])
    exit_policy = combined.groupby("exit_policy_id", dropna=False).agg(events=("events", "sum"), definitions=("candidate_definition_id", "nunique"), net_R=("net_R", "sum")).reset_index() if not combined.empty else pd.DataFrame(columns=["exit_policy_id", "events", "definitions", "net_R"])
    attrib_cols = [c for c in ["raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R", "raw_net_R", "scaled_net_R", "gross_R", "fees_R", "funding_R", "slippage_R", "net_R"] if c in combined.columns]
    attribution = combined.groupby("definition_lane", dropna=False)[attrib_cols].sum().reset_index() if not combined.empty and attrib_cols else pd.DataFrame()
    write_csv(ctx.run_root / "aggregate/lane_summary.csv", lane)
    write_csv(ctx.run_root / "aggregate/exit_policy_summary.csv", exit_policy)
    write_csv(ctx.run_root / "aggregate/funding_fee_slippage_attribution.csv", attribution)
    write_csv(ctx.run_root / "shards/shard_status_summary.csv", validations)
    return {
        "completed_shards": len(complete),
        "aggregate_rows": int(len(combined)),
        "event_rows_scored": int(pd.to_numeric(combined.get("events", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not combined.empty else 0,
        "top_line_net_R": float(pd.to_numeric(combined.get("net_R", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not combined.empty else 0.0,
        "top_line_gross_R": float(pd.to_numeric(combined.get("gross_R", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not combined.empty else 0.0,
    }


def stage_a1_compression_production_shard_plan(ctx: Context) -> None:
    t0 = time.time()
    feature_root = a1_feature_mask_repair_root()
    selected_root = RESULTS_ROOT / "phase_kraken_a1_compression_selected_key_compiler_repair_20260709_v1_20260709_084511"
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    for root in [feature_root, selected_root, contract_root]:
        if not root.exists():
            raise RuntimeError(f"missing A1 sharded aggregate reference root: {root}")
    manifest = load_a1_compression_manifest()
    plan = a1_build_full_shard_plan(ctx, manifest, feature_root)
    if int(len(plan)) != 180:
        raise RuntimeError(f"A1 sharded plan expected 180 selected-key specs, found {len(plan)}")
    first_pack = a1_select_first_pack_shards(plan)
    if int(len(first_pack)) != 10:
        raise RuntimeError(f"A1 first pack expected 10 selected-key specs, found {len(first_pack)}")
    if set(first_pack["definition_lane"].astype(str)) != {"a1_impulse_base_breakout", "a1_plus_compression", "h12_rv_compression_breakout", "h13_flat_range_escape", "h06_vcp_like_contraction"}:
        raise RuntimeError("A1 first pack does not cover exactly the five required long lanes")
    if first_pack["definition_lane"].astype(str).eq("short_diagnostic").any():
        raise RuntimeError("A1 first pack must exclude short_diagnostic")
    selected_hashes = set(first_pack["selected_key_policy_hash"].astype(str))
    plan["first_pack"] = plan["selected_key_policy_hash"].astype(str).isin(selected_hashes)
    role_map = dict(zip(first_pack["selected_key_policy_hash"].astype(str), first_pack["first_pack_role"].astype(str)))
    basis_map = dict(zip(first_pack["selected_key_policy_hash"].astype(str), first_pack["selection_basis"].astype(str)))
    plan["first_pack_role"] = plan["selected_key_policy_hash"].astype(str).map(role_map).fillna("")
    plan["selection_basis"] = plan["selected_key_policy_hash"].astype(str).map(basis_map).fillna(plan["selection_basis"])
    write_csv(ctx.run_root / "shards/full_manifest_shard_plan.csv", plan)
    write_csv(ctx.run_root / "shards/first_pack_shard_manifest.csv", first_pack)
    write_text(ctx.run_root / "performance/runtime_report.md", "\n".join([
        "# A1 + Compression Production Sharded Aggregate Runtime Report",
        "",
        f"Shard plan build seconds: `{time.time() - t0:.3f}`",
        f"Full manifest selected-key shards: `{len(plan)}`",
        "First pack shards: `10`",
        "This phase runs only the first pack; it does not run a monolithic full aggregate.",
    ]) + "\n")
    write_status(ctx, "complete", "a1-compression-production-shard-plan")


def stage_a1_compression_first_pack_sharded_aggregate(ctx: Context) -> None:
    t0 = time.time()
    feature_root = a1_feature_mask_repair_root()
    first_pack = read_csv_safe(ctx.run_root / "shards/first_pack_shard_manifest.csv")
    if len(first_pack) != 10:
        raise RuntimeError(f"first-pack execution requires exactly 10 planned shards, found {len(first_pack)}")
    manifest = load_a1_compression_manifest()
    definitions = a1_definitions_for_selected_key_specs(manifest, ctx, first_pack["selected_key_policy_hash"].astype(str).tolist())
    windows = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows)
    write_csv(ctx.run_root / "binding/definition_manifest_used.csv", definitions)
    shard_results: list[dict[str, Any]] = []
    cache_rows: list[dict[str, Any]] = []
    hash_rows: list[dict[str, Any]] = []
    freeze_rows: list[dict[str, Any]] = []
    protected_rows: list[dict[str, Any]] = []
    cap_rows: list[dict[str, Any]] = []
    first_aggregate_ts = 0.0
    peak_rss = current_rss_bytes()
    for idx, (_, shard) in enumerate(first_pack.iterrows(), start=1):
        elapsed = time.time() - t0
        if first_aggregate_ts <= 0 and elapsed > 90 * 60:
            raise RuntimeError("no first-pack aggregate rows produced within 90 minutes")
        shard_defs = definitions[definitions["selected_key_policy_hash"].astype(str).eq(str(shard.get("selected_key_policy_hash", "")))].copy()
        result = a1_execute_economic_shard(ctx, shard_row=shard.to_dict(), definitions=shard_defs, feature_root=feature_root, windows=windows)
        shard_results.append(result)
        peak_rss = max(peak_rss, int(result.get("peak_rss_bytes", 0) or 0), current_rss_bytes())
        if int(result.get("aggregate_rows", 0) or 0) > 0 and first_aggregate_ts <= 0:
            first_aggregate_ts = time.time()
        cache_rows.extend(a1_cache_reuse_rows_from_shard_result(result))
        shard_dir = ctx.run_root / "aggregate_shards" / str(result.get("shard_id", ""))
        selected_keys = read_csv_safe(shard_dir / "selected_keys.csv")
        selected_manifest = read_csv_safe(shard_dir / "selected_key_manifest.csv")
        if not selected_manifest.empty:
            hash_rows.extend(a1_shard_selected_key_hash_consistency(str(result.get("shard_id", "")), selected_keys, selected_manifest.iloc[0].to_dict(), str(result.get("selected_event_key_hash", ""))))
        freeze_rows.append({
            "shard_id": result.get("shard_id", ""),
            "selected_key_freeze_ts": result.get("selected_key_freeze_ts", ""),
            "outcome_cache_start_ts": result.get("outcome_cache_start_ts", ""),
            "outcome_after_freeze": result.get("outcome_after_freeze", False),
            "status": "pass" if parse_bool_value(result.get("outcome_after_freeze", False), default=False) else "fail",
        })
        protected_rows.append({"shard_id": result.get("shard_id", ""), "protected_interval_violations": int(result.get("protected_interval_violations", 0) or 0), "status": "pass" if int(result.get("protected_interval_violations", 0) or 0) == 0 else "fail"})
        for cap in str(result.get("cap_labels", "")).split(";"):
            if cap:
                cap_rows.append({"shard_id": result.get("shard_id", ""), "cap_label": cap, "status": "pass"})
        a1_write_heartbeat(
            ctx,
            "a1-compression-production-sharded-aggregate",
            heartbeat_filename="production_sharded_aggregate_heartbeat.json",
            shard_id=result.get("shard_id", ""),
            lane=result.get("definition_lane", ""),
            selected_key_specs_completed=idx,
            total_selected_key_specs=10,
            definitions_scored=sum(int(r.get("definition_count", 0) or 0) for r in shard_results),
            event_rows_scored=sum(int(r.get("outcome_event_count", 0) or 0) for r in shard_results),
            rss_bytes=current_rss_bytes(),
            elapsed_seconds=time.time() - t0,
            estimated_remaining_shards=10 - idx,
        )
        if peak_rss >= 8 * 1024**3:
            raise RuntimeError(f"A1 first pack RSS hard stop before kernel OOM: rss={peak_rss}")
    write_csv(ctx.run_root / "shards/first_pack_shard_manifest.csv", shard_results)
    write_csv(ctx.run_root / "audit/cache_reuse_audit.csv", cache_rows)
    write_csv(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv", hash_rows)
    write_csv(ctx.run_root / "audit/outcome_after_freeze_audit.csv", freeze_rows)
    write_csv(ctx.run_root / "audit/protected_interval_audit.csv", protected_rows)
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", [{"check": "first_pack_shards", "violations": sum(int(r.get("decision_input_leak_violations", 0) or 0) for r in shard_results), "status": "pass" if sum(int(r.get("decision_input_leak_violations", 0) or 0) for r in shard_results) == 0 else "fail"}])
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", [{"check": "first_pack_shards", "static_alphabetical_failures": sum(int(r.get("static_topn_failures", 0) or 0) for r in shard_results), "status": "pass" if sum(int(r.get("static_topn_failures", 0) or 0) for r in shard_results) == 0 else "fail"}])
    write_csv(ctx.run_root / "audit/cap_label_propagation_audit.csv", cap_rows or [{"shard_id": "", "cap_label": "none_observed", "status": "pass"}])
    write_csv(ctx.run_root / "performance/first_pack_shard_runtime.csv", shard_results)
    write_status(ctx, "complete", "a1-compression-first-pack-sharded-aggregate")


def stage_a1_compression_first_pack_reducer(ctx: Context) -> None:
    t0 = time.time()
    expected = read_csv_safe(ctx.run_root / "shards/first_pack_shard_manifest.csv")
    if expected.empty:
        raise RuntimeError("missing first-pack shard manifest for reducer")
    reduce_result = a1_reduce_first_pack_shards(ctx, expected)
    shard_status = read_csv_safe(ctx.run_root / "shards/shard_status_summary.csv")
    leak = read_csv_safe(ctx.run_root / "audit/decision_input_leak_audit.csv")
    topn = read_csv_safe(ctx.run_root / "audit/topn_dynamic_panel_audit.csv")
    protected = read_csv_safe(ctx.run_root / "audit/protected_interval_audit.csv")
    hash_audit = read_csv_safe(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv")
    cache_audit = read_csv_safe(ctx.run_root / "audit/cache_reuse_audit.csv")
    aggregate = read_csv_safe(ctx.run_root / "aggregate/first_pack_grouped_aggregate.csv")
    peak_rss = int(pd.to_numeric(shard_status.get("peak_rss_bytes", pd.Series(dtype=float)), errors="coerce").fillna(0).max()) if not shard_status.empty else current_rss_bytes()
    leak_violations = int(pd.to_numeric(leak.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not leak.empty else 1
    static_failures = int(pd.to_numeric(topn.get("static_alphabetical_failures", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not topn.empty else 1
    protected_violations = int(pd.to_numeric(protected.get("protected_interval_violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not protected.empty else 1
    hash_failures = int(hash_audit.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not hash_audit.empty else 1
    cache_failures = int(cache_audit.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not cache_audit.empty else 1
    completed = int(reduce_result.get("completed_shards", 0) or 0)
    pass_gate = (
        completed == 10
        and not aggregate.empty
        and leak_violations == 0
        and static_failures == 0
        and protected_violations == 0
        and hash_failures == 0
        and cache_failures == 0
        and peak_rss < 6 * 1024**3
    )
    total_runtime = float(pd.to_numeric(shard_status.get("runtime_seconds", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not shard_status.empty else 0.0
    projected = total_runtime * (180.0 / 10.0) if total_runtime else 0.0
    write_text(ctx.run_root / "performance/full_sharded_runtime_projection.md", "\n".join([
        "# A1 + Compression Full Sharded Runtime Projection",
        "",
        f"First-pack shard runtime seconds: `{total_runtime}`",
        "First-pack shards: `10`",
        "Full manifest shards: `180`",
        f"Projected full sharded runtime seconds: `{projected}`",
        "Projection is based on the first balanced economic shard pack and excludes validation, holdout, materialization, TSMOM, prior-high standalone, and live-prep.",
    ]) + "\n")
    write_text(ctx.run_root / "performance/runtime_report.md", "\n".join([
        "# A1 + Compression Production Sharded Aggregate Runtime Report",
        "",
        f"Completed first-pack shards: `{completed}/10`",
        f"Reducer runtime seconds: `{time.time() - t0:.3f}`",
        f"First-pack aggregate rows: `{len(aggregate)}`",
        f"First-pack event rows scored: `{reduce_result.get('event_rows_scored', 0)}`",
        f"Peak RSS bytes: `{peak_rss}`",
        f"Projected full sharded runtime seconds: `{projected}`",
    ]) + "\n")
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "monolithic_full_aggregate_launched": False,
        "first_shard_pack_completed": completed == 10,
        "selected_key_specs_scored": 10,
        "definitions_scored": int(pd.to_numeric(shard_status.get("definition_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not shard_status.empty else 0,
        "event_rows_scored": int(reduce_result.get("event_rows_scored", 0) or 0),
        "shard_manifests_written": completed == 10,
        "reducer_pass": completed == 10 and not aggregate.empty,
        "runtime_seconds": total_runtime,
        "peak_rss_bytes": peak_rss,
        "protected_interval_violations": protected_violations,
        "leak_violations": leak_violations,
        "static_topn_failures": static_failures,
        "top_line_net_R": reduce_result.get("top_line_net_R", 0.0),
        "top_line_gross_R": reduce_result.get("top_line_gross_R", 0.0),
        "projected_full_sharded_runtime_seconds": projected,
        "full_scan_can_proceed_by_resumable_shards": bool(pass_gate),
        "materialization_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "next_operator_decision": "first_pack_sharded_aggregate_complete_review_next" if pass_gate else "repair_a1_sharded_aggregate_component_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "a1-compression-first-pack-reducer")


def stage_a1_compression_true_streaming_cache_builder_repair(ctx: Context) -> None:
    t0 = time.time()
    failed_root = active_prior_benchmark_root(ctx.args)
    prior_repair_root = RESULTS_ROOT / A1_COMPRESSION_SEMANTIC_CACHE_REPAIR_RUN_ID
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    for root in [failed_root, prior_repair_root, contract_root]:
        if not root.exists():
            raise RuntimeError(f"missing A1 true-streaming repair reference root: {root}")
    failed_heartbeat = read_json(failed_root / "performance/full_train_cache_dry_run_heartbeat.json", {})
    write_json(ctx.run_root / "diagnostic/failed_dry_run_last_heartbeat.json", failed_heartbeat)
    oom_lines: list[str] = []
    try:
        dmesg = subprocess.run(["dmesg", "-T"], check=False, capture_output=True, text=True, timeout=10)
        oom_lines = [ln for ln in dmesg.stdout.splitlines() if "1837960" in ln or "Out of memory" in ln or "oom-kill" in ln][-20:]
    except Exception as exc:
        oom_lines = [f"dmesg_unavailable:{exc}"]
    write_text(ctx.run_root / "diagnostic/failed_dry_run_oom_postmortem.md", "\n".join([
        "# Failed A1 Full-Train Cache Dry-Run OOM Postmortem",
        "",
        f"Failed root: `{failed_root}`",
        f"Last heartbeat definitions processed: `{failed_heartbeat.get('definitions_processed', '')}`",
        f"Last heartbeat selected rows accumulated: `{failed_heartbeat.get('selected_event_keys_so_far', '')}`",
        f"Last heartbeat semantic specs completed: `{failed_heartbeat.get('semantic_specs_completed', '')}`",
        f"Last heartbeat RSS bytes: `{failed_heartbeat.get('rss_bytes', '')}`",
        "",
        "Root cause: the previous full-train dry run used repaired semantics but still retained full-run cache rows and selected-key rows in Python lists until final manifest writing. It therefore wrote no resumable cache shards/manifests before OOM.",
        "",
        "Kernel/OOM evidence:",
        *[f"- {ln}" for ln in oom_lines],
    ]) + "\n")
    write_text(ctx.run_root / "streaming/streaming_design_report.md", "\n".join([
        "# A1 True Streaming Cache Builder Design",
        "",
        "Decision-input cache rows are accumulated only inside bounded definition batches, flushed to deterministic CSV shards, and cleared after each batch. Selected-key rows are written as temp shards, then finalized after a deterministic streaming hash is computed.",
        "",
        "This phase does not build interval outcomes, aggregate R, controls, materialization, validation, holdout, TSMOM, prior-high standalone, or live-prep.",
    ]) + "\n")
    write_text(ctx.run_root / "streaming/shard_policy.md", "\n".join([
        "# Streaming Shard Policy",
        "",
        "- Shards are keyed by cache class, benchmark label/output prefix, and deterministic shard index.",
        "- Each final shard has a JSON manifest and an appended CSV manifest row.",
        "- Temp selected-key shards are explicitly marked `temp_incomplete` and are not accepted as complete resume artifacts.",
        "- Shard writes use temp file then atomic replace.",
    ]) + "\n")
    write_text(ctx.run_root / "streaming/memory_guard_policy.md", "\n".join([
        "# Streaming Memory Guard Policy",
        "",
        "- Warn above 5 GiB RSS.",
        "- Force flush and evict batch caches above 6 GiB RSS.",
        "- Fail closed above 8 GiB RSS before kernel OOM.",
        "- Batch-local symbol, rank, completed-frame, feature, parent, and funding caches are cleared after every flush/batch.",
    ]) + "\n")
    source = inspect.getsource(a1_build_true_streaming_cache_dry_run)
    forbidden = ["decision_rows: list", "rank_rows: list", "topn_rows: list", "selected_rows: list[dict[str, Any]] = []\n    timing_rows"]
    write_text(ctx.run_root / "audit/streaming_no_global_row_accumulation_audit.md", "\n".join([
        "# Streaming No Global Row Accumulation Audit",
        "",
        f"`a1_feature_bundle(` referenced: `{('a1_feature_bundle(' in source)}`",
        f"Forbidden global accumulator tokens present: `{[tok for tok in forbidden if tok in source]}`",
        "",
        "The streaming builder keeps row lists inside batch scope and flushes them to shards; selected-key finalization reads temp shards instead of retaining full-run selected rows.",
    ]) + "\n")
    manifest = load_a1_compression_manifest()
    windows_mech = a1_window_manifest()
    windows_full = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows_full)
    canary_defs = a1_select_mechanical_canary_definitions(manifest, prior_repair_root)
    medium_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=128)
    scale_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=512)
    write_csv(ctx.run_root / "benchmark/canary_definition_subset.csv", canary_defs)
    write_csv(ctx.run_root / "benchmark/medium_definition_subset.csv", medium_defs)
    write_csv(ctx.run_root / "benchmark/scale_512_definition_subset.csv", scale_defs)

    results: dict[str, Any] = {}
    memory_guard_triggered = False
    try:
        scalar_canary = build_a1_cache_dry_run_tables(ctx, canary_defs, windows=windows_mech)
        stream_canary = a1_build_true_streaming_cache_dry_run(ctx, canary_defs, windows=windows_mech, label="canary_streaming", output_prefix="canary_streaming", batch_size=4)
        canary_keys = a1_read_streaming_selected_keys(ctx, stream_canary["selected_cache_name"])
        canary_exact = a1_exactness_audit("canary_streaming_vs_scalar", canary_keys, scalar_a1_selected_keys_from_cache_tables(scalar_canary), set(canary_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/canary_streaming_exactness.csv", canary_exact)
        results["canary"] = stream_canary

        scalar_medium = build_a1_cache_dry_run_tables(ctx, medium_defs, windows=windows_mech)
        stream_medium = a1_build_true_streaming_cache_dry_run(ctx, medium_defs, windows=windows_mech, label="medium_streaming", output_prefix="medium_streaming", batch_size=4)
        medium_keys = a1_read_streaming_selected_keys(ctx, stream_medium["selected_cache_name"])
        medium_exact = a1_exactness_audit("medium_streaming_vs_scalar", medium_keys, scalar_a1_selected_keys_from_cache_tables(scalar_medium), set(medium_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/medium_streaming_exactness.csv", medium_exact)
        results["medium"] = stream_medium

        stream_512 = a1_build_true_streaming_cache_dry_run(ctx, scale_defs, windows=windows_full, label="scale_512_streaming", output_prefix="scale_512", batch_size=2)
        write_csv(ctx.run_root / "benchmark/scale_512_streaming_profile.csv", [{
            "definitions": stream_512["definitions"],
            "selected_event_key_rows": stream_512["selected_event_key_rows"],
            "runtime_seconds": stream_512["runtime_seconds"],
            "peak_rss_bytes": stream_512["peak_rss_bytes"],
            "peak_rss_gib": stream_512["peak_rss_bytes"] / 1024**3,
            "status": "pass" if stream_512["peak_rss_bytes"] < 6 * 1024**3 else "fail",
        }])
        results["scale_512"] = stream_512

        if int(stream_512["peak_rss_bytes"]) < 6 * 1024**3:
            stream_full = a1_build_true_streaming_cache_dry_run(ctx, manifest, windows=windows_full, label="full_train_streaming_1440", output_prefix="full_train", batch_size=2)
            results["full"] = stream_full
        else:
            results["full"] = {"definitions": 0, "selected_event_key_rows": 0, "selected_event_key_hash": "", "peak_rss_bytes": stream_512["peak_rss_bytes"], "runtime_seconds": 0.0, "selected_cache_name": "full_train_selected_event_key", "leak_violations": 0, "static_topn_failures": 0, "manifests": []}
    except MemoryGuardStop:
        memory_guard_triggered = True
    canary_exact_df = read_csv_safe(ctx.run_root / "benchmark/canary_streaming_exactness.csv")
    medium_exact_df = read_csv_safe(ctx.run_root / "benchmark/medium_streaming_exactness.csv")
    canary_mismatch = int(pd.to_numeric(canary_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not canary_exact_df.empty else 1
    medium_mismatch = int(pd.to_numeric(medium_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not medium_exact_df.empty else 1
    full = results.get("full", {})
    full_completed = int(full.get("definitions", 0) or 0) == 1440 and bool(full.get("selected_event_key_hash", ""))
    selected_cache_name = str(full.get("selected_cache_name", "full_train_selected_event_key"))
    provisional_summary = {
        "run_root": str(ctx.run_root),
        "status": "running_gate_finalization",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "controls_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "kernel_oom": False,
        "canary_exactness_pass": canary_mismatch == 0,
        "medium_exactness_pass": medium_mismatch == 0,
        "scale_512_benchmark_pass": bool(results.get("scale_512", {}).get("peak_rss_bytes", 9 * 1024**3) < 6 * 1024**3),
        "full_1440_dry_run_pass": full_completed,
        "definitions_covered": int(full.get("definitions", 0) or 0),
        "selected_event_key_rows_written": int(full.get("selected_event_key_rows", 0) or 0),
        "selected_event_key_hash": str(full.get("selected_event_key_hash", "")),
        "peak_rss_bytes": int(max([int(v.get("peak_rss_bytes", 0) or 0) for v in results.values()] + [current_rss_bytes()])),
        "memory_guard_triggered": memory_guard_triggered,
        "leak_violations": int(full.get("leak_violations", 0) or 0),
        "static_topn_failures": int(full.get("static_topn_failures", 0) or 0),
        "protected_decision_violations": 0,
        "projected_full_aggregate_runtime_seconds": float(full.get("runtime_seconds", 0.0) or 0.0),
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", provisional_summary)
    if full_completed:
        consistency = a1_selected_key_consistency_from_current_root(ctx, cache_name=selected_cache_name, include_decision_summary=True)
    else:
        consistency = pd.DataFrame([{"source": "full_train_selected_key_missing", "selected_event_key_hash": "", "matches": False, "status": "fail"}])
    write_csv(ctx.run_root / "audit/full_train_selected_key_hash_consistency_audit.csv", consistency)
    selected_consistency_pass = bool(not consistency.empty and consistency["status"].astype(str).eq("pass").all())
    protected_decision_violations = 0
    if full_completed:
        selected_keys = a1_read_streaming_selected_keys(ctx, selected_cache_name)
        protected_decision_violations = int(pd.to_datetime(selected_keys.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if not selected_keys.empty else 0
    write_csv(ctx.run_root / "audit/full_train_decision_input_leak_audit.csv", [{"benchmark": "full_train_streaming_1440", "violations": int(provisional_summary["leak_violations"]), "status": "pass" if int(provisional_summary["leak_violations"]) == 0 else "fail"}])
    topn_df = read_csv_safe(ctx.run_root / "cache/full_train_topn_membership_manifest.csv")
    write_csv(ctx.run_root / "audit/full_train_topn_dynamic_panel_audit.csv", [{"benchmark": "full_train_streaming_1440", "static_alphabetical_failures": int(provisional_summary["static_topn_failures"]), "manifest_rows": int(len(topn_df)), "status": "pass" if int(provisional_summary["static_topn_failures"]) == 0 else "fail"}])
    cap_rows = []
    if full_completed:
        selected_keys = a1_read_streaming_selected_keys(ctx, selected_cache_name)
        cap = selected_keys.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not selected_keys.empty else pd.Series(dtype=str)
        for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
            cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/full_train_cap_label_propagation_audit.csv", cap_rows)
    resume_rows = []
    for manifest_path in sorted((ctx.run_root / "cache").glob("*_manifest.csv")):
        if manifest_path.name.endswith("_tmp_manifest.csv"):
            temp = read_csv_safe(manifest_path)
            resume_rows.append({"manifest_path": str(manifest_path.relative_to(ctx.run_root)), "row_count": int(len(temp)), "accepted_as_complete": False, "status": "pass"})
            continue
        mf = read_csv_safe(manifest_path)
        for _, r in mf.iterrows():
            row = r.to_dict()
            validation = validate_semantic_cache_manifest(row, expected={"semantic_cache_hash": str(row.get("semantic_cache_hash", ""))})
            stale = validate_semantic_cache_manifest({**row, "semantic_cache_hash": "stale"}, expected={"semantic_cache_hash": str(row.get("semantic_cache_hash", ""))})
            complete = a1_streaming_manifest_is_complete(row)
            resume_rows.append({"manifest_path": str(manifest_path.relative_to(ctx.run_root)), "cache_class": row.get("cache_class", ""), "shard_path": row.get("shard_path", ""), "manifest_status": validation.get("status", ""), "stale_manifest_rejected": stale.get("status") == "fail", "accepted_as_complete": complete, "status": "pass" if validation.get("status") == "pass" and stale.get("status") == "fail" and complete else "fail"})
    write_csv(ctx.run_root / "audit/full_train_resume_safety_audit.csv", resume_rows)
    resume_pass = bool(resume_rows and all(str(r.get("status")) == "pass" for r in resume_rows))
    pass_gate = (
        canary_mismatch == 0
        and medium_mismatch == 0
        and bool(provisional_summary["scale_512_benchmark_pass"])
        and full_completed
        and selected_consistency_pass
        and int(provisional_summary["leak_violations"]) == 0
        and int(provisional_summary["static_topn_failures"]) == 0
        and protected_decision_violations == 0
        and bool(cap_rows)
        and resume_pass
        and int(provisional_summary["peak_rss_bytes"]) < 8 * 1024**3
        and not memory_guard_triggered
        and not (ctx.run_root / "aggregate/grouped_aggregate_summary.parquet").exists()
        and not (ctx.run_root / "cache/full_train_interval_outcome_manifest.csv").exists()
    )
    provisional_summary.update({
        "status": "complete" if pass_gate else "blocked",
        "selected_key_hash_consistency_pass": selected_consistency_pass,
        "protected_decision_violations": protected_decision_violations,
        "cap_labels_propagated": bool(cap_rows),
        "resume_safety_pass": resume_pass,
        "next_recommended_phase": "a1_compression_outcome_grouped_aggregate_dry_run_next" if pass_gate else "repair_a1_true_streaming_cache_builder_next",
        "total_runtime_seconds": time.time() - t0,
        "ts_utc": utc_now(),
    })
    write_json(ctx.run_root / "decision_summary.json", provisional_summary)
    write_text(ctx.run_root / "performance/full_aggregate_runtime_reprojection.md", "\n".join([
        "# A1 Full Aggregate Runtime Reprojection",
        "",
        f"Full streaming dry-run runtime seconds: `{provisional_summary['projected_full_aggregate_runtime_seconds']}`",
        "This includes decision-input cache construction and selected-key freeze only. Outcome-cache and grouped aggregate runtime must be benchmarked separately.",
    ]) + "\n")
    write_status(ctx, provisional_summary["status"], "a1-compression-true-streaming-cache-builder-repair")


def a1_write_parent_gate_hotpath_audits(ctx: Context) -> pd.DataFrame:
    builder_source = inspect.getsource(a1_build_true_streaming_cache_dry_run)
    parent_helper_source = inspect.getsource(a1_parent_gate_from_prepared_frames)
    rows = [
        {
            "surface": "a1_build_true_streaming_cache_dry_run",
            "check": "calls_legacy_a1_parent_gate",
            "remaining_count": builder_source.count("a1_parent_gate("),
            "classification": "hotpath",
            "status": "pass" if "a1_parent_gate(" not in builder_source else "fail",
        },
        {
            "surface": "a1_build_true_streaming_cache_dry_run",
            "check": "normalizes_candidate_bars_ts",
            "remaining_count": builder_source.count('pd.to_datetime(bars["ts"]'),
            "classification": "hotpath",
            "status": "pass" if 'pd.to_datetime(bars["ts"]' not in builder_source else "fail",
        },
        {
            "surface": "a1_build_true_streaming_cache_dry_run",
            "check": "uses_semantic_parent_gate_table",
            "remaining_count": builder_source.count("a1_parent_gate_semantic_table_for_window"),
            "classification": "hotpath",
            "status": "pass" if "a1_parent_gate_semantic_table_for_window" in builder_source else "fail",
        },
        {
            "surface": "a1_parent_gate_from_prepared_frames",
            "check": "normalizes_candidate_bars_ts",
            "remaining_count": parent_helper_source.count('pd.to_datetime(bars["ts"]'),
            "classification": "semantic_parent_gate_lookup",
            "status": "pass" if 'pd.to_datetime(bars["ts"]' not in parent_helper_source else "fail",
        },
    ]
    audit = pd.DataFrame(rows)
    write_csv(ctx.run_root / "audit/timestamp_normalization_hotpath_audit.csv", audit)
    write_text(ctx.run_root / "diagnostic/parent_gate_hotpath_report.md", "\n".join([
        "# A1 Parent-Gate Timestamp Hotpath Report",
        "",
        "The streaming selected-key builder now precomputes parent-gate state by `(parent_gate_policy_hash, parent_regime_gate, timeframe, window_id)` and decision timestamp.",
        "BTC/ETH parent frames are normalized once through `a1_prepare_parent_gate_frame`, then looked up with `numpy.searchsorted` in `a1_parent_gate_from_prepared_frames`.",
        "The selected-key hotpath no longer calls `a1_parent_gate(...)` with candidate symbol bars and no longer normalizes `bars[\"ts\"]` for parent-gate start/end derivation.",
    ]) + "\n")
    return audit


def a1_parent_gate_semantic_manifest_summary(ctx: Context) -> pd.DataFrame:
    rows: list[dict[str, Any]] = []
    for path in sorted((ctx.run_root / "cache").glob("*parent_gate_manifest.csv")):
        mf = read_csv_safe(path)
        rows.append({
            "manifest_path": str(path.relative_to(ctx.run_root)),
            "manifest_rows": int(len(mf)),
            "row_count_sum": int(pd.to_numeric(mf.get("row_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not mf.empty else 0,
            "semantic_hash_count": int(mf.get("semantic_cache_hash", pd.Series(dtype=str)).astype(str).nunique()) if not mf.empty else 0,
            "status": "pass" if not mf.empty else "fail",
        })
    out = pd.DataFrame(rows)
    write_csv(ctx.run_root / "cache/parent_gate_semantic_manifest.csv", out)
    return out


def stage_a1_compression_parent_gate_hotpath_repair(ctx: Context) -> None:
    t0 = time.time()
    stopped_root = active_prior_benchmark_root(ctx.args)
    failed_root = RESULTS_ROOT / "phase_kraken_a1_compression_full_train_cache_dry_run_20260708_v1_20260708_174033"
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    for root in [stopped_root, failed_root, contract_root]:
        if not root.exists():
            raise RuntimeError(f"missing A1 parent-gate hotpath reference root: {root}")
    hotpath_audit = a1_write_parent_gate_hotpath_audits(ctx)
    manifest = load_a1_compression_manifest()
    windows_mech = a1_window_manifest()
    windows_full = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows_full)
    canary_defs = a1_select_mechanical_canary_definitions(manifest, RESULTS_ROOT / A1_COMPRESSION_SEMANTIC_CACHE_REPAIR_RUN_ID)
    medium_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=128)
    scale_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=512)
    write_csv(ctx.run_root / "benchmark/canary_definition_subset.csv", canary_defs)
    write_csv(ctx.run_root / "benchmark/medium_definition_subset.csv", medium_defs)
    write_csv(ctx.run_root / "benchmark/scale_512_definition_subset.csv", scale_defs)
    results: dict[str, Any] = {}
    memory_guard_triggered = False
    scale_512_mismatch_count = 1
    scale_512_exactness_status = "not_run_independent_scalar_512_resource_guard"
    try:
        scalar_canary = build_a1_cache_dry_run_tables(ctx, canary_defs, windows=windows_mech)
        stream_canary = a1_build_true_streaming_cache_dry_run(ctx, canary_defs, windows=windows_mech, label="canary_streaming", output_prefix="canary_streaming", batch_size=4)
        canary_keys = a1_read_streaming_selected_keys(ctx, stream_canary["selected_cache_name"])
        canary_exact = a1_exactness_audit("canary_streaming_vs_scalar", canary_keys, scalar_a1_selected_keys_from_cache_tables(scalar_canary), set(canary_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/canary_streaming_exactness.csv", canary_exact)
        results["canary"] = stream_canary

        scalar_medium = build_a1_cache_dry_run_tables(ctx, medium_defs, windows=windows_mech)
        stream_medium = a1_build_true_streaming_cache_dry_run(ctx, medium_defs, windows=windows_mech, label="medium_streaming", output_prefix="medium_streaming", batch_size=4)
        medium_keys = a1_read_streaming_selected_keys(ctx, stream_medium["selected_cache_name"])
        medium_exact = a1_exactness_audit("medium_streaming_vs_scalar", medium_keys, scalar_a1_selected_keys_from_cache_tables(scalar_medium), set(medium_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/medium_streaming_exactness.csv", medium_exact)
        results["medium"] = stream_medium

        stream_512 = a1_build_true_streaming_cache_dry_run(ctx, scale_defs, windows=windows_full, label="scale_512_streaming", output_prefix="scale_512", batch_size=2)
        scale_keys = a1_read_streaming_selected_keys(ctx, stream_512["selected_cache_name"])
        selected_hash_consistent = bool(stream_512.get("selected_event_key_hash", "")) and not scale_keys.empty and scale_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(stream_512.get("selected_event_key_hash", ""))).all()
        write_csv(ctx.run_root / "benchmark/scale_512_streaming_profile.csv", [{
            "definitions": stream_512["definitions"],
            "selected_event_key_rows": stream_512["selected_event_key_rows"],
            "runtime_seconds": stream_512["runtime_seconds"],
            "peak_rss_bytes": stream_512["peak_rss_bytes"],
            "peak_rss_gib": stream_512["peak_rss_bytes"] / 1024**3,
            "selected_event_key_hash": stream_512["selected_event_key_hash"],
            "selected_key_hash_consistent": selected_hash_consistent,
            "scalar_cache_mismatch_count": scale_512_mismatch_count,
            "scalar_cache_exactness_status": scale_512_exactness_status,
            "status": "pass" if stream_512["peak_rss_bytes"] < 6 * 1024**3 and stream_512["runtime_seconds"] <= 5400 and selected_hash_consistent else "fail",
        }])
        results["scale_512"] = stream_512
    except MemoryGuardStop:
        memory_guard_triggered = True

    canary_exact_df = read_csv_safe(ctx.run_root / "benchmark/canary_streaming_exactness.csv")
    medium_exact_df = read_csv_safe(ctx.run_root / "benchmark/medium_streaming_exactness.csv")
    scale_profile = read_csv_safe(ctx.run_root / "benchmark/scale_512_streaming_profile.csv")
    canary_mismatch = int(pd.to_numeric(canary_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not canary_exact_df.empty else 1
    medium_mismatch = int(pd.to_numeric(medium_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not medium_exact_df.empty else 1
    scale = results.get("scale_512", {})
    scale_runtime = float(scale.get("runtime_seconds", 0.0) or 0.0)
    scale_selected_rows = int(scale.get("selected_event_key_rows", 0) or 0)
    scale_peak_rss = int(scale.get("peak_rss_bytes", 0) or 0)
    leak_violations = int(scale.get("leak_violations", 0) or 0)
    static_topn_failures = int(scale.get("static_topn_failures", 0) or 0)
    scale_keys = a1_read_streaming_selected_keys(ctx, str(scale.get("selected_cache_name", "scale_512_selected_event_key"))) if scale else pd.DataFrame()
    protected_decision_violations = int(pd.to_datetime(scale_keys.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if not scale_keys.empty else 0
    cap = scale_keys.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not scale_keys.empty else pd.Series(dtype=str)
    cap_rows = []
    for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
        cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/cap_label_propagation_audit.csv", cap_rows)
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", [{"benchmark": "scale_512_streaming", "violations": leak_violations, "status": "pass" if leak_violations == 0 else "fail"}])
    topn_df = read_csv_safe(ctx.run_root / "cache/scale_512_topn_membership_manifest.csv")
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", [{"benchmark": "scale_512_streaming", "static_alphabetical_failures": static_topn_failures, "manifest_rows": int(len(topn_df)), "status": "pass" if static_topn_failures == 0 else "fail"}])
    selected_hash_consistency = pd.DataFrame([{
        "source": "scale_512_selected_event_key",
        "selected_event_key_hash": str(scale.get("selected_event_key_hash", "")),
        "selected_rows": scale_selected_rows,
        "hash_nonblank": bool(str(scale.get("selected_event_key_hash", ""))),
        "matches": bool(not scale_keys.empty and scale_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(scale.get("selected_event_key_hash", ""))).all()),
        "status": "pass" if bool(not scale_keys.empty and str(scale.get("selected_event_key_hash", "")) and scale_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(scale.get("selected_event_key_hash", ""))).all()) else "fail",
    }])
    write_csv(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv", selected_hash_consistency)
    parent_manifest_summary = a1_parent_gate_semantic_manifest_summary(ctx)
    timing = read_csv_safe(ctx.run_root / "performance/full_train_streaming_timing.csv")
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", timing)
    projected_1440 = scale_runtime * (1440.0 / max(1, int(scale.get("definitions", 0) or 0))) if scale_runtime else 0.0
    write_text(ctx.run_root / "performance/full_manifest_runtime_reprojection.md", "\n".join([
        "# A1 Full Manifest Runtime Reprojection",
        "",
        f"512-definition selected-key runtime seconds: `{scale_runtime}`",
        f"Projected 1,440-definition selected-key runtime seconds: `{projected_1440}`",
        "Projection covers decision-input cache/selected-key construction only. Outcome cache and grouped aggregate were not launched.",
    ]) + "\n")
    pass_gate = (
        canary_mismatch == 0
        and medium_mismatch == 0
        and not scale_profile.empty
        and int(scale.get("definitions", 0) or 0) == 512
        and scale_runtime <= 5400
        and scale_runtime > 0
        and scale_peak_rss < 6 * 1024**3
        and scale_512_mismatch_count == 0
        and leak_violations == 0
        and static_topn_failures == 0
        and protected_decision_violations == 0
        and selected_hash_consistency["status"].astype(str).eq("pass").all()
        and hotpath_audit["status"].astype(str).eq("pass").all()
        and bool(cap_rows)
        and not memory_guard_triggered
    )
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "controls_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "canary_pass": canary_mismatch == 0,
        "medium_pass": medium_mismatch == 0,
        "scale_512_pass": pass_gate,
        "scale_512_runtime_seconds": scale_runtime,
        "scale_512_scalar_cache_mismatch_count": scale_512_mismatch_count,
        "scale_512_exactness_status": scale_512_exactness_status,
        "definitions_covered": int(scale.get("definitions", 0) or 0),
        "selected_event_key_rows_written": scale_selected_rows,
        "selected_event_key_hash": str(scale.get("selected_event_key_hash", "")),
        "peak_rss_bytes": int(max([int(v.get("peak_rss_bytes", 0) or 0) for v in results.values()] + [current_rss_bytes()])),
        "memory_guard_triggered": memory_guard_triggered,
        "kernel_oom": False,
        "leak_violations": leak_violations,
        "static_topn_failures": static_topn_failures,
        "protected_decision_violations": protected_decision_violations,
        "selected_key_hash_consistency_pass": selected_hash_consistency["status"].astype(str).eq("pass").all(),
        "cap_labels_propagated": bool(cap_rows),
        "parent_gate_semantic_manifest_rows": int(len(parent_manifest_summary)),
        "projected_1440_selected_key_runtime_seconds": projected_1440,
        "projected_full_aggregate_runtime_seconds": 0.0,
        "remaining_hotpath_bottleneck": "" if pass_gate else "scale_512_independent_scalar_exactness_not_available_or_runtime_gate_failed",
        "next_recommended_phase": "a1_compression_full_train_cache_dry_run_precompute_next" if pass_gate else "repair_a1_parent_gate_or_512_exactness_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "total_runtime_seconds": time.time() - t0,
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "a1-compression-parent-gate-hotpath-repair")


def stage_a1_compression_selected_key_compiler_repair(ctx: Context) -> None:
    t0 = time.time()
    parent_root = active_prior_benchmark_root(ctx.args)
    streaming_root = RESULTS_ROOT / A1_COMPRESSION_TRUE_STREAMING_CACHE_REPAIR_RUN_ID
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    for root in [parent_root, streaming_root, contract_root]:
        if not root.exists():
            raise RuntimeError(f"missing A1 selected-key compiler reference root: {root}")
    manifest = load_a1_compression_manifest()
    windows_mech = a1_window_manifest()
    windows_full = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows_full)
    dedup = a1_selected_key_dedup_audit(manifest, ctx)
    write_csv(ctx.run_root / "diagnostic/manifest_selected_key_dedup_audit.csv", dedup)
    write_text(ctx.run_root / "diagnostic/selected_key_compiler_design.md", "\n".join([
        "# A1 Selected-Key Compiler Design",
        "",
        "The selected-key compiler evaluates entry/selection semantics once per `selected_key_policy_hash`, then fans out selected event keys to the exit-policy variants that share the same entry policy.",
        "",
        "The hash excludes exit, hold, ATR stop/trailing, structure stop, VWAP, same-bar, stop-fill, parameter-vector, and candidate-id fields. It includes the remaining entry, universe, rank, regime, funding, compression, breakout, side, and cap fields.",
        "",
        "No interval outcomes, aggregate R, controls, materialization, validation, holdout, TSMOM, prior-high standalone, or live-prep work is launched by this profile.",
    ]) + "\n")
    write_text(ctx.run_root / "diagnostic/universe_materialization_bottleneck_report.md", "\n".join([
        "# Universe Materialization Bottleneck Report",
        "",
        "Previous stopped profiles materialized PIT universe rows inside the full-definition loop. The compiler instead caches `(universe_policy_hash, policy, target sizes, decision_ts)` once and writes only coarse universe membership manifest rows.",
        "",
        f"Full manifest rows: `{len(manifest)}`",
        f"Unique selected-key specs: `{dedup['selected_key_policy_hash'].nunique() if not dedup.empty else 0}`",
        f"Mean definitions per selected-key spec: `{float(pd.to_numeric(dedup.get('definition_count', pd.Series(dtype=float)), errors='coerce').mean()) if not dedup.empty else 0.0}`",
    ]) + "\n")
    source = inspect.getsource(a1_build_selected_key_compiler_dry_run)
    no_per_def_tokens = [
        'rows_by_class["liquid_universe"].append',
        "candidate_definition_id\": cid, \"decision_ts\"",
        "for d in def_records",
    ]
    write_text(ctx.run_root / "audit/no_per_definition_universe_materialization_audit.md", "\n".join([
        "# No Per-Definition Universe Materialization Audit",
        "",
        f"`rows_by_class[\"liquid_universe\"].append` present in compiler: `{no_per_def_tokens[0] in source}`",
        f"Compiler groups by selected-key policy: `{'groups:' in source and 'selected_key_policy_hash' in source}`",
        f"Full-definition universe append token present: `{no_per_def_tokens[1] in source}`",
        "",
        "The compiler may fan out selected keys to exit variants after selection, but universe/rank membership is computed by semantic key before fanout.",
    ]) + "\n")

    canary_defs = a1_select_mechanical_canary_definitions(manifest, RESULTS_ROOT / A1_COMPRESSION_SEMANTIC_CACHE_REPAIR_RUN_ID)
    medium_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=128)
    scale_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=512)
    write_csv(ctx.run_root / "benchmark/canary_definition_subset.csv", canary_defs)
    write_csv(ctx.run_root / "benchmark/medium_definition_subset.csv", medium_defs)
    write_csv(ctx.run_root / "benchmark/scale_512_definition_subset.csv", scale_defs)

    results: dict[str, Any] = {}
    memory_guard_triggered = False
    try:
        scalar_canary = build_a1_cache_dry_run_tables(ctx, canary_defs, windows=windows_mech)
        compiler_canary = a1_build_selected_key_compiler_dry_run(ctx, canary_defs, windows=windows_mech, label="canary_compiler", output_prefix="canary_compiler")
        canary_keys = a1_read_streaming_selected_keys(ctx, compiler_canary["selected_cache_name"])
        canary_exact = a1_exactness_audit("canary_compiler_vs_scalar", canary_keys, scalar_a1_selected_keys_from_cache_tables(scalar_canary), set(canary_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/canary_compiler_exactness.csv", canary_exact)
        results["canary"] = compiler_canary

        scalar_medium = build_a1_cache_dry_run_tables(ctx, medium_defs, windows=windows_mech)
        compiler_medium = a1_build_selected_key_compiler_dry_run(ctx, medium_defs, windows=windows_mech, label="medium_compiler", output_prefix="medium_compiler")
        medium_keys = a1_read_streaming_selected_keys(ctx, compiler_medium["selected_cache_name"])
        medium_exact = a1_exactness_audit("medium_compiler_vs_scalar", medium_keys, scalar_a1_selected_keys_from_cache_tables(scalar_medium), set(medium_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/medium_compiler_exactness.csv", medium_exact)
        results["medium"] = compiler_medium

        compiler_512 = a1_build_selected_key_compiler_dry_run(ctx, scale_defs, windows=windows_full, label="scale_512_compiler", output_prefix="scale_512_compiler", max_runtime_seconds=5400)
        scale_keys = a1_read_streaming_selected_keys(ctx, compiler_512["selected_cache_name"])
        selected_hash_consistent = bool(compiler_512.get("selected_event_key_hash", "")) and not scale_keys.empty and scale_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(compiler_512.get("selected_event_key_hash", ""))).all()
        write_csv(ctx.run_root / "benchmark/scale_512_compiler_profile.csv", [{
            "definitions": compiler_512["definitions"],
            "unique_selected_key_specs": compiler_512["unique_selected_key_specs"],
            "selected_event_key_rows": compiler_512["selected_event_key_rows"],
            "runtime_seconds": compiler_512["runtime_seconds"],
            "peak_rss_bytes": compiler_512["peak_rss_bytes"],
            "peak_rss_gib": compiler_512["peak_rss_bytes"] / 1024**3,
            "selected_event_key_hash": compiler_512["selected_event_key_hash"],
            "selected_key_hash_consistent": selected_hash_consistent,
            "max_open_buffer_rows": compiler_512["max_open_buffer_rows"],
            "shard_count": compiler_512["shard_count"],
            "scalar_cache_mismatch_count": "not_measured_resource_guard",
            "scalar_cache_exactness_status": "canary_and_medium_scalar_exactness_only",
            "status": "pass" if compiler_512["runtime_seconds"] <= 5400 and compiler_512["peak_rss_bytes"] < 6 * 1024**3 and selected_hash_consistent and compiler_512["shard_count"] < 10000 else "fail",
        }])
        results["scale_512"] = compiler_512

        projected_full_selected_key = compiler_512["runtime_seconds"] * (max(1, int(dedup["selected_key_policy_hash"].nunique())) / max(1, int(compiler_512["unique_selected_key_specs"])))
        if compiler_512["runtime_seconds"] <= 3600 and projected_full_selected_key <= 5400 and compiler_512["shard_count"] < 10000:
            compiler_full = a1_build_selected_key_compiler_dry_run(ctx, manifest, windows=windows_full, label="full_selected_key_compiler", output_prefix="full_selected_key_compiler", max_runtime_seconds=5400)
            results["full"] = compiler_full
    except MemoryGuardStop:
        memory_guard_triggered = True

    canary_exact_df = read_csv_safe(ctx.run_root / "benchmark/canary_compiler_exactness.csv")
    medium_exact_df = read_csv_safe(ctx.run_root / "benchmark/medium_compiler_exactness.csv")
    scale_profile = read_csv_safe(ctx.run_root / "benchmark/scale_512_compiler_profile.csv")
    canary_mismatch = int(pd.to_numeric(canary_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not canary_exact_df.empty else 1
    medium_mismatch = int(pd.to_numeric(medium_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not medium_exact_df.empty else 1
    scale = results.get("scale_512", {})
    primary = results.get("full", scale)
    primary_prefix = "full_selected_key_compiler" if "full" in results else "scale_512_compiler"
    selected_cache_name = str(primary.get("selected_cache_name", "scale_512_compiler_selected_event_key"))
    selected_keys = a1_read_streaming_selected_keys(ctx, selected_cache_name) if primary else pd.DataFrame()
    leak_violations = int(sum(int(v.get("leak_violations", 0) or 0) for v in results.values()))
    static_topn_failures = int(sum(int(v.get("static_topn_failures", 0) or 0) for v in results.values()))
    protected_decision_violations = int(sum(int(v.get("protected_decision_violations", 0) or 0) for v in results.values()))
    cap = selected_keys.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not selected_keys.empty else pd.Series(dtype=str)
    cap_rows = []
    for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
        cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/cap_label_propagation_audit.csv", cap_rows)
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", [{"benchmark": "selected_key_compiler_all_benchmarks", "violations": leak_violations, "status": "pass" if leak_violations == 0 else "fail"}])
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", [{"benchmark": "selected_key_compiler_all_benchmarks", "static_alphabetical_failures": static_topn_failures, "status": "pass" if static_topn_failures == 0 else "fail"}])
    consistency = a1_selected_key_consistency_from_current_root(ctx, cache_name=selected_cache_name, include_decision_summary=False) if primary else pd.DataFrame([{"source": "selected_keys_missing", "status": "fail"}])
    write_csv(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv", consistency)
    shard_count = a1_selected_key_compiler_shard_count(ctx)
    write_csv(ctx.run_root / "audit/shard_count_audit.csv", [{
        "total_cache_csv_shards": shard_count,
        "max_open_buffer_rows": int(max([int(v.get("max_open_buffer_rows", 0) or 0) for v in results.values()] + [0])),
        "hard_limit": 10000,
        "status": "pass" if shard_count < 10000 else "fail",
    }])
    for generic, prefixed in [
        ("pit_universe_membership_manifest.csv", f"{primary_prefix}_pit_universe_membership_manifest.csv"),
        ("topn_membership_manifest.csv", f"{primary_prefix}_topn_membership_manifest.csv"),
        ("feature_mask_manifest.csv", f"{primary_prefix}_feature_mask_manifest.csv"),
        ("selected_key_spec_manifest.csv", f"{primary_prefix}_selected_key_spec_manifest.csv"),
        ("selected_event_key_manifest.csv", f"{selected_cache_name}_manifest.csv"),
    ]:
        src = ctx.run_root / "cache" / prefixed
        if src.exists():
            shutil.copy2(src, ctx.run_root / "cache" / generic)
    timing = read_csv_safe(ctx.run_root / "performance/selected_key_compiler_timing.csv")
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", timing)
    scale_runtime = float(scale.get("runtime_seconds", 0.0) or 0.0)
    scale_specs = int(scale.get("unique_selected_key_specs", 0) or 0)
    full_specs = int(dedup["selected_key_policy_hash"].nunique()) if not dedup.empty else 0
    projected_full_selected_key = scale_runtime * (full_specs / max(1, scale_specs)) if scale_runtime else 0.0
    write_text(ctx.run_root / "performance/full_selected_key_precompute_projection.md", "\n".join([
        "# A1 Full Selected-Key Precompute Projection",
        "",
        f"512-definition compiler runtime seconds: `{scale_runtime}`",
        f"512 unique selected-key specs: `{scale_specs}`",
        f"Full manifest unique selected-key specs: `{full_specs}`",
        f"Projected full selected-key precompute runtime seconds: `{projected_full_selected_key}`",
        f"Full precompute executed in this phase: `{'full' in results}`",
        "Projection covers decision-input selected-key construction only. Outcomes and aggregate scoring were not launched.",
    ]) + "\n")
    scale_pass = bool(
        not scale_profile.empty
        and int(scale.get("definitions", 0) or 0) == 512
        and scale_runtime > 0
        and scale_runtime <= 5400
        and int(scale.get("peak_rss_bytes", 9 * 1024**3) or 0) < 6 * 1024**3
        and int(scale.get("shard_count", 999999) or 999999) < 10000
        and not bool(scale.get("runtime_gate_stopped", False))
    )
    consistency_pass = bool(not consistency.empty and consistency["status"].astype(str).eq("pass").all())
    pass_gate = (
        canary_mismatch == 0
        and medium_mismatch == 0
        and scale_pass
        and leak_violations == 0
        and static_topn_failures == 0
        and protected_decision_violations == 0
        and consistency_pass
        and shard_count < 10000
        and not memory_guard_triggered
    )
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "controls_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "canary_pass": canary_mismatch == 0,
        "medium_pass": medium_mismatch == 0,
        "scale_512_pass": scale_pass,
        "canary_mismatch_count": canary_mismatch,
        "medium_mismatch_count": medium_mismatch,
        "scale_512_scalar_cache_mismatch_count": "not_measured_resource_guard",
        "manifest_definition_count": int(len(manifest)),
        "unique_selected_key_specs_full_manifest": full_specs,
        "scale_512_unique_selected_key_specs": scale_specs,
        "scale_512_runtime_seconds": scale_runtime,
        "definitions_covered": int(primary.get("definitions", 0) or 0),
        "selected_event_key_rows_written": int(primary.get("selected_event_key_rows", 0) or 0),
        "selected_event_key_hash": str(primary.get("selected_event_key_hash", "")),
        "selected_key_hash_consistency_pass": consistency_pass,
        "leak_violations": leak_violations,
        "static_topn_failures": static_topn_failures,
        "protected_decision_violations": protected_decision_violations,
        "cap_labels_propagated": bool(cap_rows),
        "shard_count": shard_count,
        "max_open_buffer_rows": int(max([int(v.get("max_open_buffer_rows", 0) or 0) for v in results.values()] + [0])),
        "peak_rss_bytes": int(max([int(v.get("peak_rss_bytes", 0) or 0) for v in results.values()] + [current_rss_bytes()])),
        "memory_guard_triggered": memory_guard_triggered,
        "kernel_oom": False,
        "full_selected_key_precompute_executed": "full" in results,
        "full_selected_key_cache_directly_reusable": bool("full" in results and str(primary.get("selected_event_key_hash", ""))),
        "next_aggregate_can_skip_decision_input_rebuild": bool("full" in results and str(primary.get("selected_event_key_hash", ""))),
        "projected_1440_selected_key_runtime_seconds": projected_full_selected_key,
        "projected_full_aggregate_runtime_seconds": 0.0,
        "next_recommended_phase": "a1_compression_full_train_selected_key_precompute_next" if pass_gate and "full" not in results else ("a1_compression_full_aggregate_launch_gate_next" if pass_gate else "repair_a1_selected_key_compiler_next"),
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "total_runtime_seconds": time.time() - t0,
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "a1-compression-selected-key-compiler-repair")


def stage_a1_compression_feature_mask_compiler_repair(ctx: Context) -> None:
    t0 = time.time()
    selected_key_root = active_prior_benchmark_root(ctx.args)
    parent_root = RESULTS_ROOT / A1_COMPRESSION_PARENT_GATE_HOTPATH_REPAIR_RUN_ID
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    for root in [selected_key_root, parent_root, contract_root]:
        if not root.exists():
            raise RuntimeError(f"missing A1 feature-mask compiler reference root: {root}")
    manifest = load_a1_compression_manifest()
    windows_mech = a1_window_manifest()
    windows_full = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows_full)
    dedup = a1_selected_key_dedup_audit(manifest, ctx)
    write_csv(ctx.run_root / "diagnostic/selected_key_dedup_audit.csv", dedup)
    write_text(ctx.run_root / "diagnostic/feature_mask_compiler_design.md", "\n".join([
        "# A1 Feature-Mask Compiler Design",
        "",
        "This repair removes A1/compression raw feature construction from the selected symbol/decision hot path.",
        "",
        "Feature masks are built once per `(feature_spec_hash, symbol_id, decision_timeframe, window_id)` and then joined to selected Top-N symbol/decision rows. Exit-policy fanout happens only after entry, parent, and funding masks pass.",
        "",
        "The mask builder preserves the scalar boundary contract: the current completed signal bar may have `source_ts <= decision_ts`; reference impulse/base/compression windows use bars with `source_ts < decision_ts`; no decision-input row may use `feature_available_ts > decision_ts`.",
        "",
        "This phase launches no aggregate scoring, outcome cache, materialization, controls, validation, holdout, TSMOM, prior-high standalone, or live-prep work.",
    ]) + "\n")
    builder_source = inspect.getsource(a1_build_feature_mask_compiler_dry_run)
    mask_source = inspect.getsource(a1_feature_mask_table_from_completed)
    raw_call_present = "a1_raw_feature_bundle_from_completed(" in builder_source
    write_text(ctx.run_root / "diagnostic/feature_hotpath_report.md", "\n".join([
        "# A1 Feature Hotpath Report",
        "",
        f"Previous selected-key root: `{selected_key_root}`",
        "Previous blocker: `a1_raw_feature_bundle_from_completed()` was called once per selected symbol/decision row in the full-window selected-key compiler.",
        "",
        f"New compiler raw bundle call present: `{raw_call_present}`",
        f"Feature-mask helper calls scalar raw bundle: `{'a1_raw_feature_bundle_from_completed(' in mask_source}`",
        "Remaining expected hotpath work: PIT universe/rank Top-N construction and feature-mask table joins. Outcome and aggregate work are not launched.",
    ]) + "\n")
    write_csv(ctx.run_root / "audit/no_raw_feature_bundle_hotpath_audit.csv", [{
        "function": "a1_build_feature_mask_compiler_dry_run",
        "raw_feature_bundle_call_present": bool(raw_call_present),
        "status": "pass" if not raw_call_present else "fail",
    }])

    canary_defs = a1_select_mechanical_canary_definitions(manifest, RESULTS_ROOT / A1_COMPRESSION_SEMANTIC_CACHE_REPAIR_RUN_ID)
    medium_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=128)
    single_defs = a1_select_single_selected_key_spec_definitions(manifest, ctx)
    balanced_defs = a1_select_balanced_selected_key_spec_definitions(manifest, ctx, target_specs=32)
    write_csv(ctx.run_root / "benchmark/canary_definition_subset.csv", canary_defs)
    write_csv(ctx.run_root / "benchmark/medium_definition_subset.csv", medium_defs)
    write_csv(ctx.run_root / "benchmark/single_full_window_spec_definition_subset.csv", single_defs)
    write_csv(ctx.run_root / "benchmark/balanced_32_spec_definition_subset.csv", balanced_defs)

    results: dict[str, Any] = {}
    memory_guard_triggered = False
    try:
        scalar_canary = build_a1_cache_dry_run_tables(ctx, canary_defs, windows=windows_mech)
        canary = a1_build_feature_mask_compiler_dry_run(ctx, canary_defs, windows=windows_mech, label="canary_feature_mask", output_prefix="canary_feature_mask")
        canary_keys = a1_read_streaming_selected_keys(ctx, canary["selected_cache_name"])
        canary_exact = a1_exactness_audit("canary_feature_mask_vs_scalar", canary_keys, scalar_a1_selected_keys_from_cache_tables(scalar_canary), set(canary_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/canary_feature_mask_exactness.csv", canary_exact)
        results["canary"] = canary

        scalar_medium = build_a1_cache_dry_run_tables(ctx, medium_defs, windows=windows_mech)
        medium = a1_build_feature_mask_compiler_dry_run(ctx, medium_defs, windows=windows_mech, label="medium_feature_mask", output_prefix="medium_feature_mask")
        medium_keys = a1_read_streaming_selected_keys(ctx, medium["selected_cache_name"])
        medium_exact = a1_exactness_audit("medium_feature_mask_vs_scalar", medium_keys, scalar_a1_selected_keys_from_cache_tables(scalar_medium), set(medium_defs["candidate_definition_id"].astype(str)))
        write_csv(ctx.run_root / "benchmark/medium_feature_mask_exactness.csv", medium_exact)
        results["medium"] = medium

        single = a1_build_feature_mask_compiler_dry_run(ctx, single_defs, windows=windows_full, label="single_full_window_feature_mask", output_prefix="single_full_window_feature_mask", max_runtime_seconds=1800)
        single_keys = a1_read_streaming_selected_keys(ctx, single["selected_cache_name"])
        write_csv(ctx.run_root / "benchmark/single_full_window_spec_profile.csv", [{
            "definitions": single["definitions"],
            "unique_selected_key_specs": single["unique_selected_key_specs"],
            "selected_event_key_rows": single["selected_event_key_rows"],
            "feature_mask_rows": single["feature_mask_rows"],
            "runtime_seconds": single["runtime_seconds"],
            "peak_rss_bytes": single["peak_rss_bytes"],
            "peak_rss_gib": single["peak_rss_bytes"] / 1024**3,
            "selected_event_key_hash": single["selected_event_key_hash"],
            "selected_key_hash_nonblank": bool(str(single.get("selected_event_key_hash", ""))),
            "selected_key_hash_consistent": bool(single.get("selected_event_key_hash", "")) and not single_keys.empty and single_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(single.get("selected_event_key_hash", ""))).all(),
            "scalar_cache_mismatch_count": "not_measured_full_window_spec_benchmark",
            "status": "pass" if single["runtime_seconds"] <= 1800 and not bool(single.get("runtime_gate_stopped", False)) and single["peak_rss_bytes"] < 6 * 1024**3 and bool(str(single.get("selected_event_key_hash", ""))) else "fail",
        }])
        results["single"] = single

        balanced = a1_build_feature_mask_compiler_dry_run(ctx, balanced_defs, windows=windows_full, label="balanced_32_feature_mask", output_prefix="balanced_32_feature_mask", max_runtime_seconds=5400)
        balanced_keys = a1_read_streaming_selected_keys(ctx, balanced["selected_cache_name"])
        covered_lanes = sorted(set(balanced_defs.get("definition_lane", pd.Series(dtype=str)).dropna().astype(str)))
        write_csv(ctx.run_root / "benchmark/balanced_32_spec_profile.csv", [{
            "definitions": balanced["definitions"],
            "unique_selected_key_specs": balanced["unique_selected_key_specs"],
            "covered_lanes": ";".join(covered_lanes),
            "required_long_lanes_present": all(l in set(covered_lanes) for l in ["a1_impulse_base_breakout", "a1_plus_compression", "h12_rv_compression_breakout", "h13_flat_range_escape", "h06_vcp_like_contraction"]),
            "selected_event_key_rows": balanced["selected_event_key_rows"],
            "feature_mask_rows": balanced["feature_mask_rows"],
            "runtime_seconds": balanced["runtime_seconds"],
            "peak_rss_bytes": balanced["peak_rss_bytes"],
            "peak_rss_gib": balanced["peak_rss_bytes"] / 1024**3,
            "selected_event_key_hash": balanced["selected_event_key_hash"],
            "selected_key_hash_nonblank": bool(str(balanced.get("selected_event_key_hash", ""))),
            "selected_key_hash_consistent": bool(balanced.get("selected_event_key_hash", "")) and not balanced_keys.empty and balanced_keys.get("selected_event_keys_hash", pd.Series(dtype=str)).astype(str).eq(str(balanced.get("selected_event_key_hash", ""))).all(),
            "scalar_cache_mismatch_count": "not_measured_full_window_32_spec_benchmark",
            "status": "pass" if balanced["runtime_seconds"] <= 5400 and not bool(balanced.get("runtime_gate_stopped", False)) and balanced["peak_rss_bytes"] < 6 * 1024**3 and bool(str(balanced.get("selected_event_key_hash", ""))) else "fail",
        }])
        results["balanced_32"] = balanced
    except MemoryGuardStop:
        memory_guard_triggered = True

    canary_exact_df = read_csv_safe(ctx.run_root / "benchmark/canary_feature_mask_exactness.csv")
    medium_exact_df = read_csv_safe(ctx.run_root / "benchmark/medium_feature_mask_exactness.csv")
    single_profile = read_csv_safe(ctx.run_root / "benchmark/single_full_window_spec_profile.csv")
    balanced_profile = read_csv_safe(ctx.run_root / "benchmark/balanced_32_spec_profile.csv")
    canary_mismatch = int(pd.to_numeric(canary_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not canary_exact_df.empty else 1
    medium_mismatch = int(pd.to_numeric(medium_exact_df.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(1).sum()) if not medium_exact_df.empty else 1
    single_pass = bool(not single_profile.empty and single_profile.get("status", pd.Series(["fail"])).astype(str).eq("pass").all())
    balanced_pass = bool(not balanced_profile.empty and balanced_profile.get("status", pd.Series(["fail"])).astype(str).eq("pass").all())
    primary = results.get("balanced_32", results.get("single", results.get("medium", {})))
    selected_cache_name = str(primary.get("selected_cache_name", "balanced_32_feature_mask_selected_event_key"))
    selected_keys = a1_read_streaming_selected_keys(ctx, selected_cache_name) if primary else pd.DataFrame()
    leak_violations = int(sum(int(v.get("leak_violations", 0) or 0) for v in results.values()))
    static_topn_failures = int(sum(int(v.get("static_topn_failures", 0) or 0) for v in results.values()))
    protected_decision_violations = int(sum(int(v.get("protected_decision_violations", 0) or 0) for v in results.values()))
    cap = selected_keys.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not selected_keys.empty else pd.Series(dtype=str)
    cap_rows = []
    for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
        cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/cap_label_propagation_audit.csv", cap_rows)
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", [{"benchmark": "feature_mask_compiler_all_benchmarks", "violations": leak_violations, "status": "pass" if leak_violations == 0 else "fail"}])
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", [{"benchmark": "feature_mask_compiler_all_benchmarks", "static_alphabetical_failures": static_topn_failures, "status": "pass" if static_topn_failures == 0 else "fail"}])
    consistency = a1_selected_key_consistency_from_current_root(ctx, cache_name=selected_cache_name, include_decision_summary=False) if primary else pd.DataFrame([{"source": "selected_keys_missing", "status": "fail"}])
    write_csv(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv", consistency)
    consistency_pass = bool(not consistency.empty and consistency["status"].astype(str).eq("pass").all())
    primary_prefix = "balanced_32_feature_mask" if "balanced_32" in results else ("single_full_window_feature_mask" if "single" in results else "medium_feature_mask")
    for generic, prefixed in [
        ("feature_spec_manifest.csv", f"{primary_prefix}_feature_spec_manifest.csv"),
        ("feature_mask_manifest.csv", f"{primary_prefix}_feature_mask_manifest.csv"),
        ("selected_key_spec_manifest.csv", f"{primary_prefix}_selected_key_spec_manifest.csv"),
        ("selected_event_key_manifest.csv", f"{selected_cache_name}_manifest.csv"),
    ]:
        src = ctx.run_root / "cache" / prefixed
        if src.exists():
            shutil.copy2(src, ctx.run_root / "cache" / generic)
    timing = read_csv_safe(ctx.run_root / "performance/feature_mask_compiler_timing.csv")
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", timing)
    full_specs = int(dedup["selected_key_policy_hash"].nunique()) if not dedup.empty else 0
    balanced_runtime = float(results.get("balanced_32", {}).get("runtime_seconds", 0.0) or 0.0)
    balanced_specs = int(results.get("balanced_32", {}).get("unique_selected_key_specs", 0) or 0)
    projected_full_selected_key = balanced_runtime * (full_specs / max(1, balanced_specs)) if balanced_runtime else 0.0
    write_text(ctx.run_root / "performance/selected_key_runtime_projection.md", "\n".join([
        "# A1 Feature-Mask Selected-Key Runtime Projection",
        "",
        f"Balanced benchmark runtime seconds: `{balanced_runtime}`",
        f"Balanced unique selected-key specs: `{balanced_specs}`",
        f"Full manifest unique selected-key specs: `{full_specs}`",
        f"Projected full 180-spec selected-key runtime seconds: `{projected_full_selected_key}`",
        "Projection covers decision-input selected-key construction only. Outcomes and aggregate scoring were not launched.",
    ]) + "\n")
    pass_gate = (
        not raw_call_present
        and canary_mismatch == 0
        and medium_mismatch == 0
        and single_pass
        and balanced_pass
        and leak_violations == 0
        and static_topn_failures == 0
        and protected_decision_violations == 0
        and consistency_pass
        and not memory_guard_triggered
        and int(max([int(v.get("peak_rss_bytes", 0) or 0) for v in results.values()] + [current_rss_bytes()])) < 6 * 1024**3
    )
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "controls_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "manifest_definition_count": int(len(manifest)),
        "unique_selected_key_specs_full_manifest": full_specs,
        "canary_pass": canary_mismatch == 0,
        "medium_pass": medium_mismatch == 0,
        "single_full_window_spec_pass": single_pass,
        "balanced_32_spec_pass": balanced_pass,
        "canary_mismatch_count": canary_mismatch,
        "medium_mismatch_count": medium_mismatch,
        "scalar_cache_mismatch_count": int(canary_mismatch + medium_mismatch),
        "single_full_window_spec_runtime_seconds": float(results.get("single", {}).get("runtime_seconds", 0.0) or 0.0),
        "balanced_32_spec_runtime_seconds": balanced_runtime,
        "selected_event_key_rows_written": int(primary.get("selected_event_key_rows", 0) or 0),
        "selected_event_key_hash": str(primary.get("selected_event_key_hash", "")),
        "selected_key_hash_consistency_pass": consistency_pass,
        "leak_violations": leak_violations,
        "static_topn_failures": static_topn_failures,
        "protected_decision_violations": protected_decision_violations,
        "cap_labels_propagated": bool(cap_rows),
        "peak_rss_bytes": int(max([int(v.get("peak_rss_bytes", 0) or 0) for v in results.values()] + [current_rss_bytes()])),
        "memory_guard_triggered": memory_guard_triggered,
        "kernel_oom": False,
        "raw_feature_bundle_hotpath_removed": not raw_call_present,
        "remaining_hotpath_bottleneck": "" if pass_gate else ("raw_feature_bundle_hotpath" if raw_call_present else "feature_mask_benchmark_gate_failed"),
        "projected_180_selected_key_spec_runtime_seconds": projected_full_selected_key,
        "produced_caches_reusable_by_aggregate": pass_gate,
        "next_recommended_phase": "a1_compression_full_train_selected_key_precompute_next" if pass_gate else "repair_a1_feature_mask_compiler_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "total_runtime_seconds": time.time() - t0,
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "a1-compression-feature-mask-compiler-repair")


def stage_a1_compression_semantic_cache_builder_repair(ctx: Context) -> None:
    t0 = time.time()
    stop_root = active_prior_benchmark_root(ctx.args)
    binding_root = RESULTS_ROOT / A1_COMPRESSION_BINDING_CACHE_DRY_RUN_RUN_ID
    mechanical_root = RESULTS_ROOT / A1_COMPRESSION_MECHANICAL_CANARY_RUN_ID
    if not stop_root.exists():
        raise RuntimeError(f"missing A1 stop/archive root: {stop_root}")
    if not binding_root.exists() or not mechanical_root.exists():
        raise RuntimeError("missing A1 binding or mechanical reference root")
    manifest = load_a1_compression_manifest()
    windows = a1_window_manifest()
    canary_defs = a1_select_mechanical_canary_definitions(manifest, binding_root)
    medium_defs = a1_select_medium_semantic_benchmark_definitions(manifest, target=128)
    write_csv(ctx.run_root / "benchmark/canary_definition_subset.csv", canary_defs)
    write_csv(ctx.run_root / "benchmark/medium_definition_subset.csv", medium_defs)
    semantic_inventory = a1_extract_semantic_spec_inventory(manifest, ctx)
    write_csv(ctx.run_root / "audit/semantic_cache_hash_audit.csv", semantic_inventory)
    scalar_canary = build_a1_cache_dry_run_tables(ctx, canary_defs, windows=windows)
    cache_canary = a1_build_semantic_cache_tables(ctx, canary_defs, windows=windows, label="canary_42_repaired_cache", write_outputs=False)
    scalar_canary_keys = scalar_a1_selected_keys_from_cache_tables(scalar_canary)
    canary_exact = a1_exactness_audit("canary_42_repaired_cache_vs_scalar", cache_canary["tables"]["selected_event_keys"], scalar_canary_keys, set(canary_defs["candidate_definition_id"].astype(str)))
    write_csv(ctx.run_root / "benchmark/canary_scalar_cache_exactness.csv", canary_exact)
    scalar_medium = build_a1_cache_dry_run_tables(ctx, medium_defs, windows=windows)
    cache_medium = a1_build_semantic_cache_tables(ctx, medium_defs, windows=windows, label="medium_128_repaired_cache", write_outputs=True)
    scalar_medium_keys = scalar_a1_selected_keys_from_cache_tables(scalar_medium)
    medium_exact = a1_exactness_audit("medium_128_repaired_cache_vs_scalar", cache_medium["tables"]["selected_event_keys"], scalar_medium_keys, set(medium_defs["candidate_definition_id"].astype(str)))
    write_csv(ctx.run_root / "benchmark/medium_scalar_cache_exactness.csv", medium_exact)
    leak_violations = int(cache_canary["leak_violations"]) + int(cache_medium["leak_violations"])
    write_csv(ctx.run_root / "audit/decision_input_leak_audit.csv", [{"benchmark": "canary_plus_medium", "violations": leak_violations, "status": "pass" if leak_violations == 0 else "fail"}])
    topn_failures = int(cache_canary["static_topn_failures"]) + int(cache_medium["static_topn_failures"])
    topn = cache_medium["tables"]["topn_membership"]
    write_csv(ctx.run_root / "audit/topn_dynamic_panel_audit.csv", [{
        "benchmark": "medium_128_repaired_cache",
        "topn_rows": int(len(topn)),
        "distinct_selected_panel_hashes": int(topn.get("selected_topn_symbols_hash", pd.Series(dtype=str)).astype(str).nunique()) if not topn.empty else 0,
        "static_alphabetical_failures": topn_failures,
        "status": "pass" if topn_failures == 0 else "fail",
    }])
    selected = cache_medium["tables"]["selected_event_keys"]
    protected_violations = int(pd.to_datetime(selected.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if not selected.empty else 0
    cap = selected.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not selected.empty else pd.Series(dtype=str)
    cap_rows = []
    for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
        cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/cap_label_propagation_audit.csv", cap_rows)
    consistency = a1_selected_key_consistency_from_current_root(ctx)
    write_csv(ctx.run_root / "audit/selected_key_hash_consistency_audit.csv", consistency)
    resume_rows = []
    for m in cache_medium["manifests"]:
        validation = validate_semantic_cache_manifest(m, expected={"semantic_cache_hash": str(m.get("semantic_cache_hash", ""))})
        stale = validate_semantic_cache_manifest({**m, "semantic_cache_hash": "stale"}, expected={"semantic_cache_hash": str(m.get("semantic_cache_hash", ""))})
        resume_rows.append({"cache_class": m.get("cache_class", ""), "path": m.get("path", ""), "manifest_status": validation.get("status", ""), "stale_manifest_rejected": stale.get("status") == "fail", "content_hash": m.get("content_hash", ""), "status": "pass" if validation.get("status") == "pass" and stale.get("status") == "fail" and m.get("content_hash") else "fail"})
    write_csv(ctx.run_root / "audit/resume_safety_audit.csv", resume_rows)
    timing = pd.DataFrame([
        {"stage": "scalar_canary_selected_keys", "definitions": int(len(canary_defs)), "runtime_seconds": 0.0, "rss_bytes": current_rss_bytes()},
        {"stage": "repaired_canary_cache", "definitions": int(len(canary_defs)), "runtime_seconds": cache_canary["runtime_seconds"], "rss_bytes": cache_canary["peak_rss_bytes"]},
        {"stage": "scalar_medium_selected_keys", "definitions": int(len(medium_defs)), "runtime_seconds": 0.0, "rss_bytes": current_rss_bytes()},
        {"stage": "repaired_medium_cache", "definitions": int(len(medium_defs)), "runtime_seconds": cache_medium["runtime_seconds"], "rss_bytes": cache_medium["peak_rss_bytes"]},
    ])
    write_csv(ctx.run_root / "performance/stage_timing_breakdown.csv", timing)
    medium_runtime = float(cache_medium["runtime_seconds"])
    projected = medium_runtime * (len(manifest) / max(1, len(medium_defs)))
    write_text(ctx.run_root / "performance/full_manifest_runtime_projection.md", "\n".join([
        "# A1 Full-Manifest Runtime Projection",
        "",
        f"Medium benchmark definitions: `{len(medium_defs)}`",
        f"Full manifest definitions: `{len(manifest)}`",
        f"Medium repaired-cache runtime seconds: `{medium_runtime:.3f}`",
        f"Linear full-manifest projection seconds: `{projected:.3f}`",
        f"Linear full-manifest projection hours: `{projected / 3600.0:.3f}`",
        "",
        "Projection is from repaired decision-input cache construction on full PIT universe over mechanical windows. A full train window still requires a separate dry-run/launch gate.",
    ]) + "\n")
    canary_mismatch = int(pd.to_numeric(canary_exact.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    medium_mismatch = int(pd.to_numeric(medium_exact.get("mismatch_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum())
    resume_pass = bool(resume_rows and all(str(r.get("status")) == "pass" for r in resume_rows))
    cap_pass = bool(cap_rows)
    selected_consistency_pass = bool(not consistency.empty and consistency["status"].astype(str).eq("pass").all())
    manifest_failures = int(sum(1 for m in cache_medium["manifests"] if str(m.get("status", "")) != "pass"))
    peak_rss = int(max(current_rss_bytes(), int(cache_canary["peak_rss_bytes"]), int(cache_medium["peak_rss_bytes"])))
    pass_gate = canary_mismatch == 0 and medium_mismatch == 0 and leak_violations == 0 and topn_failures == 0 and protected_violations == 0 and manifest_failures == 0 and resume_pass and selected_consistency_pass and peak_rss < 6 * 1024**3
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "materialization_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "canary_exactness_pass": canary_mismatch == 0,
        "medium_exactness_pass": medium_mismatch == 0,
        "mismatch_count": canary_mismatch + medium_mismatch,
        "leak_violations": leak_violations,
        "static_topn_failures": topn_failures,
        "protected_interval_violations": protected_violations,
        "selected_event_key_rows_in_benchmark": int(len(selected)),
        "peak_rss_bytes": peak_rss,
        "projected_full_manifest_runtime_seconds": projected,
        "resume_safe_shards_manifests_produced": resume_pass,
        "cap_labels_propagated": cap_pass,
        "selected_key_hash_consistency_pass": selected_consistency_pass,
        "next_recommended_phase": "a1_compression_full_train_cache_dry_run_next" if pass_gate else "repair_a1_compression_semantic_cache_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "A1_COMPRESSION_SEMANTIC_CACHE_BUILDER_REPAIR_REPORT.md", "\n".join([
        "# A1 + Compression Semantic Cache Builder Repair Report",
        "",
        "This is a code repair plus benchmark phase. It did not launch full aggregate, materialization, validation, holdout, TSMOM, prior-high standalone, or live-prep.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Full manifest definitions: `{len(manifest)}`",
        f"Canary definitions benchmarked: `{len(canary_defs)}`",
        f"Medium definitions benchmarked: `{len(medium_defs)}`",
        f"Canary exactness pass: `{summary['canary_exactness_pass']}`",
        f"Medium exactness pass: `{summary['medium_exactness_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Leak violations: `{summary['leak_violations']}`",
        f"Static Top-N failures: `{summary['static_topn_failures']}`",
        f"Selected event key rows in benchmark: `{summary['selected_event_key_rows_in_benchmark']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Projected full-manifest runtime seconds: `{summary['projected_full_manifest_runtime_seconds']}`",
        f"Next recommended phase: `{summary['next_recommended_phase']}`",
    ]) + "\n")
    write_status(ctx, summary["status"], "a1-compression-semantic-cache-builder-repair")


def stage_a1_compression_full_train_cache_dry_run(ctx: Context) -> None:
    t0 = time.time()
    semantic_root = active_prior_benchmark_root(ctx.args)
    stopped_root = RESULTS_ROOT / "phase_kraken_a1_compression_full_train_aggregate_20260708_v1_20260708_154653"
    stop_archive_root = RESULTS_ROOT / "phase_kraken_a1_compression_full_aggregate_stop_archive_20260708_v1"
    mechanical_root = RESULTS_ROOT / A1_COMPRESSION_MECHANICAL_CANARY_RUN_ID
    contract_root = A1_COMPRESSION_CONTRACT_ROOT
    missing = [str(p) for p in [semantic_root, stopped_root, stop_archive_root, mechanical_root, contract_root] if not p.exists()]
    if missing:
        raise RuntimeError("missing A1 full-train cache dry-run references: " + "; ".join(missing))
    helper_source = inspect.getsource(a1_build_semantic_cache_tables)
    monolithic_bundle_used = "a1_feature_bundle(" in helper_source
    write_csv(ctx.run_root / "audit/full_train_no_monolithic_feature_bundle_audit.csv", [{
        "check": "a1_feature_bundle_not_called_by_repaired_semantic_cache_path",
        "monolithic_a1_feature_bundle_reference_found": monolithic_bundle_used,
        "status": "fail" if monolithic_bundle_used else "pass",
    }])
    if monolithic_bundle_used:
        raise RuntimeError("repaired full-train cache dry-run path still references a1_feature_bundle")
    manifest = load_a1_compression_manifest()
    windows = a1_full_train_window_manifest(ctx, manifest)
    write_csv(ctx.run_root / "mechanical/full_train_window_manifest.csv", windows)
    write_csv(ctx.run_root / "binding/full_train_definition_manifest_used.csv", manifest)
    write_csv(ctx.run_root / "audit/full_train_semantic_cache_hash_audit.csv", a1_extract_semantic_spec_inventory(manifest, ctx))
    cache_result = a1_build_semantic_cache_tables(
        ctx,
        manifest,
        windows=windows,
        label="full_train_all_1440_decision_input_cache_dry_run",
        write_outputs=True,
        output_prefix="full_train",
        heartbeat_stage="a1-compression-full-train-cache-dry-run",
        heartbeat_filename="full_train_cache_dry_run_heartbeat.json",
    )
    selected = cache_result["tables"]["selected_event_keys"]
    topn = cache_result["tables"]["topn_membership"]
    protected_decision_violations = int(pd.to_datetime(selected.get("decision_ts", pd.Series(dtype=str)), utc=True, errors="coerce").ge(PROTECTED_TS).sum()) if not selected.empty else 0
    leak_violations = int(cache_result.get("leak_violations", 0))
    static_topn_failures = int(cache_result.get("static_topn_failures", 0))
    write_csv(ctx.run_root / "audit/full_train_decision_input_leak_audit.csv", [{"benchmark": "full_train_all_1440", "violations": leak_violations, "status": "pass" if leak_violations == 0 else "fail"}])
    write_csv(ctx.run_root / "audit/full_train_topn_dynamic_panel_audit.csv", [{
        "benchmark": "full_train_all_1440",
        "topn_rows": int(len(topn)),
        "distinct_selected_panel_hashes": int(topn.get("selected_topn_symbols_hash", pd.Series(dtype=str)).astype(str).nunique()) if not topn.empty else 0,
        "static_alphabetical_failures": static_topn_failures,
        "status": "pass" if static_topn_failures == 0 else "fail",
    }])
    cap = selected.get("label_cap_reason", pd.Series(dtype=str)).fillna("").astype(str) if not selected.empty else pd.Series(dtype=str)
    cap_rows = []
    for cap_name in ["short_diagnostic", "no_parent_gate_diagnostic", "no_funding_gate_diagnostic_cap", "kraken_listed_liquid_tail_capped", "oi_omitted_or_sidecar_cap"]:
        cap_rows.append({"cap_label": cap_name, "rows": int(cap.str.contains(cap_name, regex=False).sum()), "status": "pass"})
    write_csv(ctx.run_root / "audit/full_train_cap_label_propagation_audit.csv", cap_rows)
    resume_rows = []
    for m in cache_result["manifests"]:
        validation = validate_semantic_cache_manifest(m, expected={"semantic_cache_hash": str(m.get("semantic_cache_hash", ""))})
        stale = validate_semantic_cache_manifest({**m, "semantic_cache_hash": "stale"}, expected={"semantic_cache_hash": str(m.get("semantic_cache_hash", ""))})
        resume_rows.append({"cache_class": m.get("cache_class", ""), "path": m.get("path", ""), "manifest_status": validation.get("status", ""), "stale_manifest_rejected": stale.get("status") == "fail", "content_hash": m.get("content_hash", ""), "status": "pass" if validation.get("status") == "pass" and stale.get("status") == "fail" and m.get("content_hash") else "fail"})
    write_csv(ctx.run_root / "audit/full_train_resume_safety_audit.csv", resume_rows)
    runtime_seconds = time.time() - t0
    peak_rss = int(max(current_rss_bytes(), int(cache_result.get("peak_rss_bytes", 0))))
    timing_rows = [
        {"stage": "full_train_decision_input_cache_dry_run", "definitions": int(len(manifest)), "runtime_seconds": runtime_seconds, "rss_bytes": peak_rss, "selected_event_key_rows": int(len(selected))},
    ]
    write_csv(ctx.run_root / "performance/full_train_cache_dry_run_timing.csv", timing_rows)
    prior_projection = read_json(semantic_root / "decision_summary.json", {})
    medium_projection_seconds = safe_float(prior_projection.get("projected_full_manifest_runtime_seconds", np.nan), np.nan)
    full_aggregate_projection = runtime_seconds
    write_text(ctx.run_root / "performance/full_aggregate_runtime_reprojection.md", "\n".join([
        "# A1 Full Aggregate Runtime Reprojection",
        "",
        f"Full-train decision-input dry-run seconds: `{runtime_seconds:.3f}`",
        f"Previous mechanical-window full-manifest projection seconds: `{medium_projection_seconds}`",
        "",
        "This phase did not build interval outcomes or aggregate R. Full aggregate runtime must add post-freeze outcome-cache and grouped-aggregate time from a separate outcome dry run.",
    ]) + "\n")
    benchmark_hash = ""
    bench = read_csv_safe(semantic_root / "benchmark/medium_scalar_cache_exactness.csv")
    if not bench.empty:
        row = bench[bench.get("check", pd.Series(dtype=str)).astype(str).eq("selected_event_key_hash")]
        if not row.empty:
            benchmark_hash = str(row.iloc[0].get("cache_value", ""))
    hash_scope_explanation = (
        "different_scope_expected: benchmark hash covers the medium_128 mechanical-window selected-key subset; "
        "full-train freeze/manifest hash covers all 1440 A1/compression definitions over the full train decision window"
    )
    selected_hash = str(cache_result.get("selected_hash", ""))
    provisional_summary = {
        "run_root": str(ctx.run_root),
        "status": "running_gate_finalization",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "full_aggregate_launched": False,
        "outcome_cache_built": False,
        "materialization_launched": False,
        "controls_launched": False,
        "validation_launched": False,
        "holdout_touched": False,
        "tsmom_launched": False,
        "prior_high_standalone_launched": False,
        "live_prep_launched": False,
        "definitions_covered": int(len(manifest)),
        "expected_definition_count": 1440,
        "selected_event_key_rows": int(len(selected)),
        "selected_event_key_hash": selected_hash,
        "benchmark_selected_event_key_hash": benchmark_hash,
        "benchmark_vs_manifest_hash_scope_explanation": hash_scope_explanation,
        "leak_violations": leak_violations,
        "static_topn_failures": static_topn_failures,
        "protected_decision_violations": protected_decision_violations,
        "cap_labels_propagated": bool(cap_rows),
        "peak_rss_bytes": peak_rss,
        "dry_run_runtime_seconds": runtime_seconds,
        "projected_full_aggregate_runtime_seconds_after_dry_run": full_aggregate_projection,
        "resume_safety_pass": bool(resume_rows and all(str(r.get("status")) == "pass" for r in resume_rows)),
        "old_monolithic_feature_bundle_path_used": monolithic_bundle_used,
        "next_recommended_phase": "a1_compression_outcome_grouped_aggregate_dry_run_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", provisional_summary)
    consistency = a1_selected_key_consistency_from_current_root(ctx, cache_name="full_train_selected_event_key", include_decision_summary=True)
    write_csv(ctx.run_root / "audit/full_train_selected_key_hash_consistency_audit.csv", consistency)
    selected_consistency_pass = bool(not consistency.empty and consistency["status"].astype(str).eq("pass").all())
    pass_gate = (
        int(len(manifest)) == 1440
        and not monolithic_bundle_used
        and bool(selected_hash)
        and selected_consistency_pass
        and leak_violations == 0
        and static_topn_failures == 0
        and protected_decision_violations == 0
        and bool(cap_rows)
        and provisional_summary["resume_safety_pass"]
        and peak_rss < 6 * 1024**3
        and not (ctx.run_root / "cache/full_train_interval_outcome_manifest.csv").exists()
        and not (ctx.run_root / "aggregate/grouped_aggregate_summary.parquet").exists()
    )
    provisional_summary.update({
        "status": "complete" if pass_gate else "blocked",
        "selected_key_hash_consistency_pass": selected_consistency_pass,
        "next_recommended_phase": "a1_compression_outcome_grouped_aggregate_dry_run_next" if pass_gate else "repair_a1_compression_full_train_cache_dry_run_next",
        "ts_utc": utc_now(),
    })
    write_json(ctx.run_root / "decision_summary.json", provisional_summary)
    write_text(ctx.run_root / "A1_COMPRESSION_FULL_TRAIN_CACHE_DRY_RUN_REPORT.md", "\n".join([
        "# A1 + Compression Full-Train Cache Dry Run Report",
        "",
        "This phase built full-train decision-input caches and froze selected event keys only. It did not build outcomes, aggregate R, materialization, controls, validation, holdout, TSMOM, prior-high standalone, or live-prep.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Definitions covered: `{len(manifest)}`",
        f"Selected event key rows: `{len(selected)}`",
        f"Selected event key hash: `{selected_hash}`",
        f"Selected-key hash consistency pass: `{selected_consistency_pass}`",
        f"Benchmark-vs-manifest hash scope: `{hash_scope_explanation}`",
        f"Leak violations: `{leak_violations}`",
        f"Static Top-N failures: `{static_topn_failures}`",
        f"Protected decision violations: `{protected_decision_violations}`",
        f"Peak RSS bytes: `{peak_rss}`",
        f"Dry-run runtime seconds: `{runtime_seconds}`",
        f"Next recommended phase: `{provisional_summary['next_recommended_phase']}`",
    ]) + "\n")
    write_status(ctx, provisional_summary["status"], "a1-compression-full-train-cache-dry-run")


def stage_a1_compression_full_train_aggregate_cached(ctx: Context) -> None:
    raise RuntimeError("A1 full train aggregate is blocked until `a1_compression_full_train_cache_dry_run_next` is explicitly run after semantic-cache repair review")


def full_tsmom_v6_aggregate_reference_roots() -> dict[str, Path]:
    roots = {
        "dry_run": RESULTS_ROOT / "phase_kraken_full_tsmom_v6_cache_dry_run_20260707_v1_20260708_082952",
        "scaling_benchmark": RESULTS_ROOT / "phase_kraken_tsmom_end_to_end_scaling_benchmark_20260707_v1",
        "outcome_grouped": RESULTS_ROOT / "phase_kraken_tsmom_outcome_grouped_aggregate_20260707_v1",
        "selected_key": RESULTS_ROOT / "phase_kraken_tsmom_mask_selected_key_builder_20260707_v1_20260707_201216",
        "rank_topn": RESULTS_ROOT / "phase_kraken_tsmom_rank_topn_cache_builder_20260707_v1_20260707_153811",
        "calendar_universe": RESULTS_ROOT / "phase_kraken_tsmom_calendar_universe_cache_builder_20260707_v1_20260707_123020",
    }
    missing = [f"{name}:{root}" for name, root in roots.items() if not root.exists()]
    if missing:
        raise RuntimeError("missing full TSMOM aggregate reference roots: " + "; ".join(missing))
    return roots


def copy_parquet_as_csv_and_parquet(src: Path, csv_dst: Path, parquet_dst: Path) -> pd.DataFrame:
    df = read_parquet_safe(src)
    if df.empty:
        raise RuntimeError(f"required parquet artifact is empty or missing: {src}")
    write_csv(csv_dst, df)
    parquet_dst.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(df).to_parquet(parquet_dst, index=False)
    return df


def summarize_invalid_reasons_from_outcomes(outcomes: pd.DataFrame) -> pd.DataFrame:
    if outcomes.empty:
        return pd.DataFrame([{"invalid_reason": "no_outcomes", "rows": 0, "status": "fail"}])
    reason_cols = [c for c in ["invalid_reason", "funding_gate_status", "parent_gate_status", "vol_scale_status", "label_cap_reason"] if c in outcomes.columns]
    if not reason_cols:
        return pd.DataFrame([{"invalid_reason": "no_invalid_reason_columns_present", "rows": int(len(outcomes)), "status": "pass"}])
    rows: list[dict[str, Any]] = []
    for col in reason_cols:
        values = outcomes[col].fillna("").astype(str).replace({"": "blank"})
        for val, cnt in values.value_counts(dropna=False).items():
            rows.append({"field": col, "reason": val, "rows": int(cnt), "status": "pass"})
    return pd.DataFrame(rows)


def summarize_cap_flags_from_outcomes(outcomes: pd.DataFrame) -> pd.DataFrame:
    if outcomes.empty:
        return pd.DataFrame([{"cap_field": "no_outcomes", "active_rows": 0, "status": "fail"}])
    rows: list[dict[str, Any]] = []
    bool_cols = [c for c in outcomes.columns if c.endswith("_cap") or c.endswith("_cap_active") or c in {"funding_proxy_used", "mechanics_cap_active", "liquidity_proxy_universe_cap"}]
    for col in sorted(set(bool_cols)):
        try:
            active = int(parse_bool_series(outcomes[col], default=False, strict=False).sum())
        except Exception:
            active = int(outcomes[col].fillna("").astype(str).str.strip().ne("").sum())
        rows.append({"cap_field": col, "active_rows": active, "total_rows": int(len(outcomes)), "status": "pass"})
    if "label_cap_reason" in outcomes.columns:
        for reason, cnt in outcomes["label_cap_reason"].fillna("").astype(str).replace({"": "blank"}).value_counts().items():
            rows.append({"cap_field": "label_cap_reason", "cap_reason": reason, "active_rows": int(cnt), "total_rows": int(len(outcomes)), "status": "pass"})
    return pd.DataFrame(rows or [{"cap_field": "no_cap_columns_present", "active_rows": 0, "total_rows": int(len(outcomes)), "status": "pass"}])


def stage_full_tsmom_v6_aggregate_run(ctx: Context) -> None:
    t_start = time.time()
    ctx.notifier.send("Full TSMOM v6 aggregate started", f"Run root: {ctx.run_root}", level="info")
    roots = full_tsmom_v6_aggregate_reference_roots()
    dry_summary = read_json(roots["dry_run"] / "decision_summary.json", {})
    outcome_summary = read_json(roots["outcome_grouped"] / "decision_summary.json", {})
    scaling_summary = read_json(roots["scaling_benchmark"] / "decision_summary.json", {})
    if dry_summary.get("status") != "complete" or not bool(dry_summary.get("selected_event_keys_frozen")):
        raise RuntimeError("authoritative full cache dry-run root is not complete with frozen selected keys")
    if outcome_summary.get("status") != "complete" or not bool(outcome_summary.get("exactness_pass")):
        raise RuntimeError("outcome/grouped aggregate root is not complete/exactness-passing")
    if scaling_summary.get("status") != "complete":
        raise RuntimeError("scaling benchmark root is not complete")
    dry_hash = str(dry_summary.get("selected_event_key_hash", ""))
    outcome_hash = str(outcome_summary.get("selected_event_key_hash", ""))
    if not dry_hash or dry_hash != outcome_hash:
        raise RuntimeError(f"selected event key hash mismatch dry-run={dry_hash} outcome={outcome_hash}")

    write_csv(ctx.run_root / "preflight/full_tsmom_v6_aggregate_reference_roots.csv", [
        {"reference_name": name, "root": str(root), "decision_status": read_json(root / "decision_summary.json", {}).get("status", ""), "status": "pass"}
        for name, root in roots.items()
    ])
    write_json(ctx.run_root / "performance/full_aggregate_heartbeat.json", {
        "run_root": str(ctx.run_root),
        "stage": "full-tsmom-v6-aggregate-run",
        "status": "started",
        "ts_utc": utc_now(),
        "rss_bytes": current_rss_bytes(),
    })
    write_status(ctx, "running", "full-tsmom-v6-aggregate-run")

    copied: list[dict[str, Any]] = []
    copy_plan = [
        (roots["dry_run"] / "cache/selected_event_key_manifest.csv", ctx.run_root / "cache/selected_event_key_manifest.csv"),
        (roots["dry_run"] / "cache/selected_event_key_freeze_summary.json", ctx.run_root / "cache/selected_event_key_freeze_summary.json"),
        (roots["dry_run"] / "cache/decision_calendar_manifest.csv", ctx.run_root / "cache/decision_calendar_manifest.csv"),
        (roots["dry_run"] / "cache/universe_membership_manifest.csv", ctx.run_root / "cache/universe_membership_manifest.csv"),
        (roots["dry_run"] / "cache/tsmom_rank_feature_manifest.csv", ctx.run_root / "cache/tsmom_rank_feature_manifest.csv"),
        (roots["dry_run"] / "cache/tsmom_topn_manifest.csv", ctx.run_root / "cache/tsmom_topn_manifest.csv"),
        (roots["dry_run"] / "cache/tsmom_signal_mask_manifest.csv", ctx.run_root / "cache/tsmom_signal_mask_manifest.csv"),
        (roots["dry_run"] / "cache/parent_gate_manifest.csv", ctx.run_root / "cache/parent_gate_manifest.csv"),
        (roots["dry_run"] / "cache/funding_gate_manifest.csv", ctx.run_root / "cache/funding_gate_manifest.csv"),
        (roots["dry_run"] / "cache/vol_scale_manifest.csv", ctx.run_root / "cache/vol_scale_manifest.csv"),
        (roots["dry_run"] / "audit/decision_input_leak_audit.csv", ctx.run_root / "audit/decision_input_leak_audit.csv"),
        (roots["dry_run"] / "audit/topn_dynamic_panel_audit.csv", ctx.run_root / "audit/topn_dynamic_panel_audit.csv"),
        (roots["dry_run"] / "audit/topn_correctness_audit.csv", ctx.run_root / "audit/topn_correctness_audit.csv"),
        (roots["dry_run"] / "audit/protected_boundary_selected_key_audit.csv", ctx.run_root / "audit/protected_boundary_selected_key_audit.csv"),
        (roots["outcome_grouped"] / "cache/tsmom_interval_outcome_manifest.csv", ctx.run_root / "cache/tsmom_interval_outcome_manifest.csv"),
        (roots["outcome_grouped"] / "audit/outcome_after_freeze_audit.csv", ctx.run_root / "audit/outcome_after_freeze_audit.csv"),
        (roots["outcome_grouped"] / "audit/protected_holdout_interval_audit.csv", ctx.run_root / "audit/protected_holdout_interval_audit.csv"),
        (roots["outcome_grouped"] / "audit/funding_boundary_audit.csv", ctx.run_root / "audit/funding_boundary_audit.csv"),
        (roots["outcome_grouped"] / "audit/grouped_aggregate_arithmetic_audit.csv", ctx.run_root / "audit/grouped_aggregate_arithmetic_audit.csv"),
        (roots["outcome_grouped"] / "audit/no_scalar_fallback_audit.csv", ctx.run_root / "audit/no_scalar_fallback_audit.csv"),
        (roots["outcome_grouped"] / "benchmark/outcome_grouped_performance.csv", ctx.run_root / "benchmark/outcome_grouped_performance_reference.csv"),
    ]
    for src, dst in copy_plan:
        copied.append(copy_reference_artifact(src, dst))
    write_csv(ctx.run_root / "audit/full_aggregate_artifact_binding_audit.csv", copied)
    if any(str(r.get("status")) != "pass" for r in copied):
        raise RuntimeError("one or more required full aggregate artifacts are missing")

    keys = read_csv_safe(ctx.run_root / "cache/selected_event_key_manifest.csv")
    recomputed_hash = freeze_selected_event_keys(keys.copy())[1] if not keys.empty else ""
    if recomputed_hash != dry_hash:
        raise RuntimeError("selected event key hash no longer matches authoritative dry-run hash")
    outcome_manifest = read_csv_safe(ctx.run_root / "cache/tsmom_interval_outcome_manifest.csv")
    manifest_hashes = set(outcome_manifest.get("selected_event_key_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) if not outcome_manifest.empty else set()
    if manifest_hashes != {dry_hash}:
        raise RuntimeError(f"interval outcome manifest selected-key hash mismatch: {manifest_hashes}")

    grouped = copy_parquet_as_csv_and_parquet(
        roots["outcome_grouped"] / "aggregate/grouped_aggregate_summary.parquet",
        ctx.run_root / "aggregate/tsmom_v6_full_aggregate_summary.csv",
        ctx.run_root / "aggregate/tsmom_v6_full_aggregate_summary.parquet",
    )
    symbol_month = read_parquet_safe(roots["outcome_grouped"] / "aggregate/symbol_month_summary.parquet")
    if symbol_month.empty:
        raise RuntimeError("symbol-month summary is missing from outcome/grouped root")
    parquet_safe_frame(symbol_month).to_parquet(ctx.run_root / "aggregate/symbol_month_summary.parquet", index=False)
    parquet_safe_frame(symbol_month).to_parquet(ctx.run_root / "aggregate/tsmom_v6_full_symbol_month_summary.parquet", index=False)
    outcomes = read_parquet_safe(roots["outcome_grouped"] / "cache/tsmom_interval_outcome.parquet")
    if outcomes.empty:
        raise RuntimeError("interval outcome cache is empty")
    write_csv(ctx.run_root / "aggregate/invalid_reason_counts.csv", summarize_invalid_reasons_from_outcomes(outcomes))
    write_csv(ctx.run_root / "aggregate/cap_flag_summary.csv", summarize_cap_flags_from_outcomes(outcomes))
    funding_boundary = read_csv_safe(ctx.run_root / "audit/funding_boundary_audit.csv")
    write_csv(ctx.run_root / "aggregate/funding_boundary_exact_proxy_counts.csv", funding_boundary)
    if "candidate_definition_id" in grouped.columns:
        grouped_def = grouped.groupby("candidate_definition_id", dropna=False)
        by_def = grouped_def.agg(
            events=("events", lambda s: numeric_sum(s)),
            gross_R=("gross_R", lambda s: numeric_sum(s)),
            fees_R=("fees_R", lambda s: numeric_sum(s)),
            funding_R=("funding_R", lambda s: numeric_sum(s)),
            slippage_R=("slippage_R", lambda s: numeric_sum(s)),
            net_R=("net_R", lambda s: numeric_sum(s)),
            raw_net_R=("raw_net_R", lambda s: numeric_sum(s)),
            scaled_net_R=("scaled_net_R", lambda s: numeric_sum(s)),
        ).reset_index()
        by_def["active_symbols"] = grouped_def["symbol"].agg(lambda s: len(set(s.astype(str)))).values if "symbol" in grouped.columns else 0
        by_def["aggregate_nonfutile"] = pd.to_numeric(by_def.get("scaled_net_R", pd.Series(dtype=float)), errors="coerce").fillna(0).gt(0)
    else:
        by_def = pd.DataFrame()
    write_csv(ctx.run_root / "aggregate/tsmom_v6_definition_level_aggregate_summary.csv", by_def)

    setup_root = tsmom_v6_accelerated_setup_root()
    rep = select_tsmom_v6_accelerated_candidate_rows(ctx, setup_root, rows_per_definition=3, max_defs=8, write_registry=False)
    med = select_tsmom_v6_candidate_rows_for_scale(ctx, setup_root, max_defs=32, rows_per_definition=4)
    exact_frames: list[pd.DataFrame] = []
    perf_rows: list[dict[str, Any]] = []
    for label, sample in [("exactness_sentinel_24_heavy_path", rep), ("exactness_sentinel_128_real_rows", med)]:
        exact, perf = outcome_grouped_exactness_benchmark(ctx, label, sample, outcomes)
        exact_frames.append(exact)
        perf_rows.append(perf)
        write_json(ctx.run_root / "performance/full_aggregate_heartbeat.json", {
            "run_root": str(ctx.run_root),
            "stage": "full-tsmom-v6-aggregate-run",
            "status": f"{label}_complete",
            "ts_utc": utc_now(),
            "rss_bytes": current_rss_bytes(),
        })
    exactness = pd.concat(exact_frames, ignore_index=True, sort=False) if exact_frames else pd.DataFrame()
    write_csv(ctx.run_root / "benchmark/exactness_sentinel_after_full_run.csv", exactness)
    write_csv(ctx.run_root / "benchmark/exactness_sentinel_performance.csv", perf_rows)
    mismatch_count = int(exactness.get("status", pd.Series(dtype=str)).astype(str).ne("pass").sum()) if not exactness.empty else 1
    leak = read_csv_safe(ctx.run_root / "audit/decision_input_leak_audit.csv")
    leak_violations = int(pd.to_numeric(leak.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not leak.empty else 1
    outcome_freeze = read_csv_safe(ctx.run_root / "audit/outcome_after_freeze_audit.csv")
    outcome_after_freeze_pass = bool(outcome_freeze.get("status", pd.Series(dtype=str)).astype(str).eq("pass").all()) if not outcome_freeze.empty else False
    protected = read_csv_safe(ctx.run_root / "audit/protected_holdout_interval_audit.csv")
    protected_violations = int(pd.to_numeric(protected.get("violations", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not protected.empty else 1
    topn_dyn = read_csv_safe(ctx.run_root / "audit/topn_dynamic_panel_audit.csv")
    static_topn_failures = int(pd.to_numeric(topn_dyn.get("alphabetical_static_topn_failure_count", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not topn_dyn.empty else 1
    event_sampling = bool(parse_bool_series(grouped.get("event_sampling_used", pd.Series(False, index=grouped.index)), default=False).any()) if not grouped.empty else False
    event_caps = bool(parse_bool_series(grouped.get("event_cap_used", pd.Series(False, index=grouped.index)), default=False).any()) if "event_cap_used" in grouped.columns else False
    peak_rss = int(max(current_rss_bytes(), int(outcome_summary.get("peak_rss_bytes", 0) or 0)))
    soft = memory_soft_limit_bytes(ctx)
    runtime_seconds = float(time.time() - t_start)
    nonfutile_count = int(parse_bool_series(by_def.get("aggregate_nonfutile", pd.Series(dtype=bool)), default=False).sum()) if not by_def.empty else 0
    pass_gate = (
        mismatch_count == 0
        and leak_violations == 0
        and static_topn_failures == 0
        and outcome_after_freeze_pass
        and protected_violations == 0
        and not event_sampling
        and not event_caps
        and peak_rss < int(soft * 0.70)
    )
    trace = pd.DataFrame([
        {"stage": "artifact_validation_and_binding", "runtime_seconds": runtime_seconds, "rows": len(copied), "rss_bytes": current_rss_bytes(), "scalar_fallback_used": False, "aggregate_or_sweep_launched": False},
        {"stage": "full_grouped_aggregate_publication", "runtime_seconds": runtime_seconds, "rows": int(len(grouped)), "rss_bytes": current_rss_bytes(), "scalar_fallback_used": False, "aggregate_or_sweep_launched": False},
        {"stage": "exactness_sentinel_scalar_comparison", "runtime_seconds": float(sum(float(r.get("total_runtime_seconds", 0) or 0) for r in perf_rows)), "rows": int(len(exactness)), "rss_bytes": current_rss_bytes(), "scalar_fallback_used": False, "scalar_used_only_for_labeled_sentinel": True},
    ])
    write_csv(ctx.run_root / "performance/full_tsmom_v6_aggregate_trace.csv", trace)
    write_json(ctx.run_root / "performance/full_aggregate_heartbeat.json", {
        "run_root": str(ctx.run_root),
        "stage": "full-tsmom-v6-aggregate-run",
        "status": "complete" if pass_gate else "blocked",
        "ts_utc": utc_now(),
        "rss_bytes": current_rss_bytes(),
        "selected_event_count": int(len(outcomes)),
        "candidate_symbol_rows": int(len(grouped)),
    })
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "non_smoke_two_family_sweep_launched": False,
        "prior_high_route_touched": False,
        "validation_run": False,
        "final_holdout_touched": False,
        "materialization_run": False,
        "rows_evaluated": int(len(grouped)),
        "definitions_evaluated": int(grouped.get("candidate_definition_id", pd.Series(dtype=str)).astype(str).nunique()) if not grouped.empty else 0,
        "selected_event_count": int(len(outcomes)),
        "selected_event_key_hash": dry_hash,
        "selected_event_key_hash_matches_dry_run": True,
        "scalar_fallback_used": False,
        "scalar_used_only_for_labeled_exactness_sentinel": True,
        "exactness_sentinel_pass": mismatch_count == 0,
        "mismatch_count": mismatch_count,
        "outcome_after_freeze_pass": outcome_after_freeze_pass,
        "protected_interval_violations": protected_violations,
        "decision_input_leak_violations": leak_violations,
        "static_topn_failures": static_topn_failures,
        "event_sampling_used": event_sampling,
        "event_caps_used": event_caps,
        "total_runtime_seconds": runtime_seconds,
        "peak_rss_bytes": peak_rss,
        "soft_memory_limit_bytes": int(soft),
        "memory_gate_pass": peak_rss < int(soft * 0.70),
        "nonfutile_aggregate_count": nonfutile_count,
        "telegram_status": ctx.notifier.status,
        "telegram_remote_available": ctx.notifier.remote_available,
        "telegram_alert_events_configured": ["start", "stage_transition", "completion", "failure"],
        "next_operator_decision": "review_tsmom_v6_aggregate_for_targeted_materialization_next" if pass_gate else "repair_tsmom_v6_full_aggregate_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_text(ctx.run_root / "FULL_TSMOM_V6_AGGREGATE_REPORT.md", "\n".join([
        "# Full TSMOM v6 Aggregate Report",
        "",
        "This is a TSMOM-only train-only aggregate run. It did not launch a two-family sweep, run prior-high/reclaim, run validation, touch final holdout, materialize candidates, run controls, or use event sampling/caps.",
        "",
        f"Run root: `{ctx.run_root}`",
        f"Rows evaluated: `{summary['rows_evaluated']}`",
        f"Definitions evaluated: `{summary['definitions_evaluated']}`",
        f"Selected event count: `{summary['selected_event_count']}`",
        f"Scalar fallback used: `{summary['scalar_fallback_used']}`",
        f"Exactness sentinel pass: `{summary['exactness_sentinel_pass']}`",
        f"Mismatch count: `{summary['mismatch_count']}`",
        f"Protected interval violations: `{summary['protected_interval_violations']}`",
        f"Event sampling/caps: `{summary['event_sampling_used']}` / `{summary['event_caps_used']}`",
        f"Runtime seconds: `{summary['total_runtime_seconds']}`",
        f"Peak RSS bytes: `{summary['peak_rss_bytes']}`",
        f"Nonfutile aggregate count: `{summary['nonfutile_aggregate_count']}`",
        f"Next operator decision: `{summary['next_operator_decision']}`",
        "",
        "This is train-only aggregate infrastructure output. It is not strategy evidence, not validation, not final holdout evidence, not live readiness, and not permission to trade.",
    ]) + "\n")
    ctx.notifier.send("Full TSMOM v6 aggregate complete", f"Status: {summary['status']}\nRun root: {ctx.run_root}\nRows: {summary['rows_evaluated']}\nMismatches: {summary['mismatch_count']}", level="info" if pass_gate else "warning")
    write_status(ctx, summary["status"], "full-tsmom-v6-aggregate-run")


def tsmom_v6_targeted_materialization_roots(ctx: Context) -> dict[str, Path]:
    shortlist = resolve_path(ctx.args.candidate_definition_manifest) if getattr(ctx.args, "candidate_definition_manifest", "") else TSMOM_V6_SURVIVOR_PLAN_ROOT / "selection/survivor_shortlist.csv"
    survivor_root = shortlist.parents[1] if shortlist.name == "survivor_shortlist.csv" and len(shortlist.parents) >= 2 else TSMOM_V6_SURVIVOR_PLAN_ROOT
    full_aggregate = resolve_path(ctx.args.prior_benchmark_root) if getattr(ctx.args, "prior_benchmark_root", "") else FULL_TSMOM_V6_AGGREGATE_ROOT
    outcome_grouped = resolve_path(ctx.args.cache_root) if getattr(ctx.args, "cache_root", "") else TSMOM_V6_OUTCOME_GROUPED_ROOT
    roots = {
        "survivor_plan": survivor_root,
        "shortlist": shortlist,
        "deferred_duplicates": survivor_root / "selection/rejected_or_deferred_candidates.csv",
        "duplicate_clusters": survivor_root / "selection/duplicate_cluster_report.csv",
        "full_aggregate": full_aggregate,
        "outcome_grouped": outcome_grouped,
    }
    missing = [f"{name}:{path}" for name, path in roots.items() if not path.exists()]
    if missing:
        raise RuntimeError("missing TSMOM v6 targeted materialization roots/artifacts: " + "; ".join(missing))
    return roots


def validate_tsmom_v6_targeted_lineage(ctx: Context, *, write_outputs: bool) -> tuple[dict[str, Any], pd.DataFrame, pd.DataFrame]:
    roots = tsmom_v6_targeted_materialization_roots(ctx)
    shortlist = read_csv_safe(roots["shortlist"])
    deferred = read_csv_safe(roots["deferred_duplicates"])
    full_summary = read_json(roots["full_aggregate"] / "decision_summary.json", {})
    outcome_summary = read_json(roots["outcome_grouped"] / "decision_summary.json", {})
    aggregate = read_csv_safe(roots["full_aggregate"] / "aggregate/tsmom_v6_full_aggregate_summary.csv")
    definition_summary = read_csv_safe(roots["full_aggregate"] / "aggregate/tsmom_v6_definition_level_aggregate_summary.csv")
    outcome_manifest = read_csv_safe(roots["outcome_grouped"] / "cache/tsmom_interval_outcome_manifest.csv")
    outcomes = read_parquet_safe(roots["outcome_grouped"] / "cache/tsmom_interval_outcome.parquet")
    expected_shortlist = set(TSMOM_V6_TARGETED_SHORTLIST_IDS)
    expected_deferred = set(TSMOM_V6_TARGETED_DEFERRED_DUPLICATE_IDS)
    selected_hash = str(full_summary.get("selected_event_key_hash", ""))
    rows: list[dict[str, Any]] = []

    def add(check: str, status: bool, detail: str = "", candidate_definition_id: str = "", severity: str = "P1") -> None:
        rows.append({
            "candidate_definition_id": candidate_definition_id,
            "check": check,
            "status": "pass" if status else "fail",
            "severity_if_fail": severity,
            "detail": detail,
        })

    shortlist_ids = set(shortlist.get("candidate_definition_id", pd.Series(dtype=str)).dropna().astype(str))
    deferred_ids = set(deferred.get("candidate_definition_id", pd.Series(dtype=str)).dropna().astype(str))
    add("shortlist_loaded_from_survivor_shortlist_csv", not shortlist.empty and roots["shortlist"].name == "survivor_shortlist.csv", str(roots["shortlist"]))
    add("shortlist_exact_expected_ids", shortlist_ids == expected_shortlist and len(shortlist) == 3, f"actual={sorted(shortlist_ids)} expected={sorted(expected_shortlist)}")
    add("deferred_duplicates_exact_expected_ids", deferred_ids == expected_deferred and len(deferred) == 7, f"actual={sorted(deferred_ids)} expected={sorted(expected_deferred)}")
    add("full_aggregate_root_complete", full_summary.get("status") == "complete", str(roots["full_aggregate"]))
    add("full_aggregate_exactness_pass", bool(full_summary.get("exactness_sentinel_pass")) and int(safe_float(full_summary.get("mismatch_count", 1), 1.0)) == 0, json.dumps({"exactness_sentinel_pass": full_summary.get("exactness_sentinel_pass"), "mismatch_count": full_summary.get("mismatch_count")}))
    add("full_aggregate_protected_and_topn_gates_pass", int(safe_float(full_summary.get("protected_interval_violations", 1), 1.0)) == 0 and int(safe_float(full_summary.get("decision_input_leak_violations", 1), 1.0)) == 0 and int(safe_float(full_summary.get("static_topn_failures", 1), 1.0)) == 0, json.dumps({"protected_interval_violations": full_summary.get("protected_interval_violations"), "decision_input_leak_violations": full_summary.get("decision_input_leak_violations"), "static_topn_failures": full_summary.get("static_topn_failures")}))
    add("outcome_grouped_root_complete", outcome_summary.get("status") == "complete", str(roots["outcome_grouped"]))
    add("outcome_grouped_exactness_pass", bool(outcome_summary.get("exactness_pass")) and int(safe_float(outcome_summary.get("mismatch_count", 1), 1.0)) == 0, json.dumps({"exactness_pass": outcome_summary.get("exactness_pass"), "mismatch_count": outcome_summary.get("mismatch_count")}))
    add("selected_key_hash_present", bool(selected_hash), selected_hash)
    outcome_hashes = set(outcome_manifest.get("selected_event_key_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) if not outcome_manifest.empty else set()
    add("outcome_manifest_selected_key_hash_matches_full_aggregate", outcome_hashes == {selected_hash}, f"manifest_hashes={sorted(outcome_hashes)} full_hash={selected_hash}")
    add("outcome_cache_loaded", not outcomes.empty, f"rows={len(outcomes)}")
    add("aggregate_summary_loaded", not aggregate.empty and not definition_summary.empty, f"aggregate_rows={len(aggregate)} definition_rows={len(definition_summary)}")

    aggregate_by_id = aggregate.groupby("candidate_definition_id", dropna=False) if "candidate_definition_id" in aggregate.columns else {}
    outcome_by_id = outcomes.groupby("candidate_definition_id", dropna=False) if "candidate_definition_id" in outcomes.columns else {}
    def_by_id = definition_summary.set_index("candidate_definition_id", drop=False) if "candidate_definition_id" in definition_summary.columns else pd.DataFrame()
    for _, row in shortlist.iterrows():
        cid = str(row.get("candidate_definition_id", ""))
        add("shortlisted_definition_expected", cid in expected_shortlist, "", cid)
        expected_hash = str(row.get("parameter_vector_hash", ""))
        agg_sub = aggregate_by_id.get_group(cid) if hasattr(aggregate_by_id, "groups") and cid in aggregate_by_id.groups else pd.DataFrame()
        out_sub = outcome_by_id.get_group(cid) if hasattr(outcome_by_id, "groups") and cid in outcome_by_id.groups else pd.DataFrame()
        agg_hashes = set(agg_sub.get("parameter_vector_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) if not agg_sub.empty else set()
        out_hashes = set(out_sub.get("parameter_vector_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) if not out_sub.empty else set()
        add("parameter_vector_hash_matches_full_aggregate", agg_hashes == {expected_hash}, f"shortlist={expected_hash} aggregate={sorted(agg_hashes)}", cid)
        add("parameter_vector_hash_matches_outcome_cache", out_hashes == {expected_hash}, f"shortlist={expected_hash} outcome={sorted(out_hashes)}", cid)
        shortlist_hash = str(row.get("selected_event_key_hash", ""))
        outcome_selected_hashes = set(out_sub.get("selected_event_keys_hash", pd.Series(dtype=str)).dropna().astype(str).unique()) if not out_sub.empty else set()
        add("selected_key_hash_matches_shortlist_full_and_outcomes", shortlist_hash == selected_hash and outcome_selected_hashes == {selected_hash}, f"shortlist={shortlist_hash} full={selected_hash} outcome={sorted(outcome_selected_hashes)}", cid)
        shortlist_events = int(safe_float(row.get("actual_event_rows", row.get("events", 0)), 0.0))
        def_events = int(safe_float(def_by_id.loc[cid].get("events", 0), 0.0)) if not def_by_id.empty and cid in def_by_id.index else -1
        add("event_count_matches_definition_summary_and_outcomes", shortlist_events == def_events == len(out_sub), f"shortlist={shortlist_events} definition_summary={def_events} outcomes={len(out_sub)}", cid)
        scaled_net = safe_float(row.get("scaled_net_R", 0.0), 0.0)
        raw_net = safe_float(row.get("raw_net_R", 0.0), 0.0)
        review_required = cid == "tsmom_v6_059" and raw_net < 0 < scaled_net
        add("raw_negative_scaled_positive_review_flag", review_required if cid == "tsmom_v6_059" else True, f"raw_net_R={raw_net} scaled_net_R={scaled_net} review_required={review_required}", cid, severity="P2")

    audit = pd.DataFrame(rows)
    pass_gate = bool(not audit.empty and audit["status"].astype(str).eq("pass").all())
    freeze = deferred.copy()
    if not freeze.empty:
        freeze["freeze_status"] = "frozen_deferred_duplicate_not_independent_discovery"
        freeze["can_be_materialized_without_operator_approval"] = False
        freeze["expected_deferred_duplicate"] = freeze["candidate_definition_id"].astype(str).isin(expected_deferred)
    summary = {
        "status": "pass" if pass_gate else "fail",
        "shortlisted_definitions_frozen": sorted(shortlist_ids),
        "deferred_duplicates_frozen": sorted(deferred_ids),
        "shortlist_count": int(len(shortlist)),
        "deferred_duplicate_count": int(len(deferred)),
        "lineage_audit_failures": int(audit["status"].astype(str).ne("pass").sum()) if not audit.empty else 1,
        "selected_event_key_hash": selected_hash,
        "full_aggregate_root": str(roots["full_aggregate"]),
        "outcome_grouped_root": str(roots["outcome_grouped"]),
        "survivor_plan_root": str(roots["survivor_plan"]),
        "shortlist_path": str(roots["shortlist"]),
    }
    if write_outputs:
        write_csv(ctx.run_root / "preflight/shortlist_lineage_audit.csv", audit)
        write_csv(ctx.run_root / "preflight/deferred_duplicate_freeze.csv", freeze)
    return summary, audit, freeze


def write_tsmom_v6_targeted_profile_docs(ctx: Context, lineage: Mapping[str, Any]) -> None:
    write_text(ctx.run_root / "profile/profile_contract.md", "\n".join([
        "# TSMOM v6 Targeted Materialization Profile Contract",
        "",
        f"Dry-run profile: `{TSMOM_V6_TARGETED_MATERIALIZATION_PROFILE_PHASE_PROFILE}`",
        f"Launch profile: `{TSMOM_V6_TARGETED_MATERIALIZATION_CONTROLS_PHASE_PROFILE}`",
        "",
        "The launch profile may consume only `selection/survivor_shortlist.csv` from the survivor plan root.",
        "It must not rerank, reselect, expand candidates, run validation, touch final holdout, run prior-high/reclaim, or launch broad sweep work.",
        "The only supported shortlisted definitions are `tsmom_v6_079`, `tsmom_v6_059`, and `tsmom_v6_041`.",
        "Deferred duplicate definitions remain frozen unless the operator explicitly approves a separate near-neighbor run.",
        "",
        "Every launch must validate candidate_definition_id, parameter_vector_hash, selected-event-key hash, full aggregate root, selected-key lineage, outcome cache manifest, and grouped aggregate root before materialization.",
        "Event-level ledgers are built from the post-freeze interval outcome cache for the three shortlisted representatives only.",
        "Evidence labels remain train-only capped. This is not validation, final holdout evidence, live readiness, or permission to trade.",
    ]) + "\n")
    write_text(ctx.run_root / "profile/stage_sequence.md", "\n".join([
        "# Stage Sequence",
        "",
        "## Dry-Run Implementation Profile",
        "",
        *[f"- `{stage}`" for stage in TSMOM_V6_TARGETED_MATERIALIZATION_PROFILE_STAGES],
        "",
        "## Future Launch Profile",
        "",
        *[f"- `{stage}`" for stage in TSMOM_V6_TARGETED_MATERIALIZATION_CONTROLS_STAGES],
        "",
        "The dry-run profile stops after lineage validation and launch-prompt generation. It does not execute the future materialization/control/stress stages.",
    ]) + "\n")
    write_json(ctx.run_root / "profile/lineage_requirements.json", {
        "required_shortlist_path_suffix": "selection/survivor_shortlist.csv",
        "expected_shortlisted_definitions": list(TSMOM_V6_TARGETED_SHORTLIST_IDS),
        "expected_deferred_duplicates": list(TSMOM_V6_TARGETED_DEFERRED_DUPLICATE_IDS),
        "required_selected_event_key_hash": lineage.get("selected_event_key_hash", ""),
        "required_full_aggregate_root": lineage.get("full_aggregate_root", str(FULL_TSMOM_V6_AGGREGATE_ROOT)),
        "required_outcome_grouped_root": lineage.get("outcome_grouped_root", str(TSMOM_V6_OUTCOME_GROUPED_ROOT)),
        "fail_closed_on_lineage_mismatch": True,
        "no_reselection": True,
        "no_candidate_expansion": True,
        "no_event_sampling_or_caps": True,
        "train_only_capped_labels": True,
    })
    write_text(ctx.run_root / "profile/control_semantics.md", "\n".join([
        "# Control Semantics",
        "",
        "Controls must be real matched null controls generated from the materialized event ledgers by the family engine control builder.",
        "Placeholders, copied candidate rows, summary-only rows, or empty controls are not acceptable launch outputs.",
        "Controls remain train-only diagnostics unless a separate evidence-control phase is approved. Diagnostic/control-tested labels remain capped by funding proxy, lifecycle, same-bar, and mechanics caps.",
    ]) + "\n")
    write_text(ctx.run_root / "profile/stress_semantics.md", "\n".join([
        "# Stress Semantics",
        "",
        "The launch profile must report fee stress, slippage stress, funding stress, raw-vs-scaled decomposition, vol-scale cap/decomposition, and concentration by symbol, month, and symbol-month.",
        "`tsmom_v6_059` must carry `raw_negative_scaled_positive_vol_scaling_review_required` because it is scaled-positive but raw-negative in the aggregate screen.",
        "Stress outputs are train-only diagnostics and cannot produce validation or live-readiness labels.",
    ]) + "\n")


def write_tsmom_v6_targeted_launch_prompt(ctx: Context) -> Path:
    prompt = ctx.run_root / "prelaunch/next_materialization_launch_prompt.md"
    launch_root = f"results/rebaseline/{TSMOM_V6_TARGETED_MATERIALIZATION_CONTROLS_RUN_ID}_<UTC_SUFFIX>"
    write_text(prompt, "\n".join([
        "# Next TSMOM v6 Targeted Materialization Launch Prompt",
        "",
        "Use this only after operator approval. It launches train-only targeted materialization/controls/stress for the frozen three-definition shortlist; it does not run validation, final holdout, prior-high/reclaim, broad sweep, or live-readiness work.",
        "",
        "```bash",
        "./.venv/bin/python tools/run_kraken_family_engine_aggregate_first_sweep.py \\",
        f"  --phase-profile {TSMOM_V6_TARGETED_MATERIALIZATION_CONTROLS_PHASE_PROFILE} \\",
        "  --stage all \\",
        "  --resume \\",
        f"  --run-root {launch_root} \\",
        f"  --prior-benchmark-root {FULL_TSMOM_V6_AGGREGATE_ROOT} \\",
        f"  --candidate-definition-manifest {TSMOM_V6_SURVIVOR_PLAN_ROOT / 'selection/survivor_shortlist.csv'} \\",
        f"  --cache-root {TSMOM_V6_OUTCOME_GROUPED_ROOT} \\",
        "  --family-list scheduled_tsmom_engine \\",
        "  --control-mode diagnostic \\",
        "  --disable-telegram",
        "```",
        "",
        "Required launch invariants: no candidate reselection, no candidate expansion, no event sampling, no event caps, exact lineage/hash match, and train-only capped labels only.",
    ]) + "\n")
    return prompt


def stage_tsmom_v6_targeted_materialization_profile_dry_run(ctx: Context) -> None:
    lineage, audit, freeze = validate_tsmom_v6_targeted_lineage(ctx, write_outputs=True)
    write_tsmom_v6_targeted_profile_docs(ctx, lineage)
    prompt = write_tsmom_v6_targeted_launch_prompt(ctx)
    pass_gate = lineage["status"] == "pass"
    write_text(ctx.run_root / "preflight/profile_dry_run_report.md", "\n".join([
        "# TSMOM v6 Targeted Materialization Profile Dry-Run Report",
        "",
        f"Lineage status: `{lineage['status']}`",
        f"Shortlisted definitions frozen: `{len(lineage['shortlisted_definitions_frozen'])}`",
        f"Deferred duplicates frozen: `{len(lineage['deferred_duplicates_frozen'])}`",
        f"Lineage failures: `{lineage['lineage_audit_failures']}`",
        f"Launch prompt: `{prompt}`",
        "",
        "No materialization, controls, validation, holdout, prior-high/reclaim, or broad sweep work was launched.",
    ]) + "\n")
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "materialization_launched": False,
        "validation_run": False,
        "final_holdout_touched": False,
        "prior_high_route_touched": False,
        "shortlisted_definitions_frozen": lineage["shortlisted_definitions_frozen"],
        "deferred_duplicates_frozen": lineage["deferred_duplicates_frozen"],
        "lineage_audit_pass": pass_gate,
        "lineage_audit_failures": lineage["lineage_audit_failures"],
        "supported_profile_name": TSMOM_V6_TARGETED_MATERIALIZATION_CONTROLS_PHASE_PROFILE,
        "next_launch_prompt_path": str(prompt),
        "next_operator_decision": "launch_tsmom_v6_targeted_materialization_controls_stress_next" if pass_gate else "repair_tsmom_v6_targeted_lineage_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)


