def stage_a1_compression_targeted_stress(ctx: Context) -> None:
    required = [ctx.run_root / "stress/funding_slippage_summary.csv", ctx.run_root / "forensics/top_event_dependency.csv", ctx.run_root / "forensics/paired_exit_comparison.csv"]
    missing = [str(path) for path in required if not path.exists()]
    if missing:
        raise RuntimeError("A1 targeted stress/forensic artifacts missing: " + "; ".join(missing))
    write_status(ctx, "complete", "a1-compression-targeted-stress")


def stage_a1_compression_targeted_decision(ctx: Context) -> None:
    summary = read_json(ctx.run_root / "decision_summary.json", {})
    if summary.get("status") != "complete":
        raise RuntimeError("A1 targeted candidate decision is absent or blocked")
    write_status(ctx, "complete", "a1-compression-targeted-decision")


def stage_tsmom_v6_targeted_lineage_gate(ctx: Context) -> None:
    lineage, _, _ = validate_tsmom_v6_targeted_lineage(ctx, write_outputs=True)
    if lineage["status"] != "pass":
        raise RuntimeError("TSMOM v6 targeted materialization lineage gate failed")
    write_status(ctx, "complete", "tsmom-v6-targeted-lineage-gate")


def stage_tsmom_v6_targeted_materialization(ctx: Context) -> None:
    lineage, _, _ = validate_tsmom_v6_targeted_lineage(ctx, write_outputs=False)
    if lineage["status"] != "pass":
        raise RuntimeError("lineage gate must pass before targeted materialization")
    roots = tsmom_v6_targeted_materialization_roots(ctx)
    shortlist = read_csv_safe(roots["shortlist"])
    selected_ids = list(TSMOM_V6_TARGETED_SHORTLIST_IDS)
    outcomes = read_parquet_safe(roots["outcome_grouped"] / "cache/tsmom_interval_outcome.parquet")
    out_dir = ctx.run_root / "materialized/event_ledgers"
    out_dir.mkdir(parents=True, exist_ok=True)
    manifest: list[dict[str, Any]] = []
    coverage: list[dict[str, Any]] = []
    mechanics: list[dict[str, Any]] = []
    for cid in selected_ids:
        ledger = outcomes[outcomes["candidate_definition_id"].astype(str).eq(cid)].copy()
        if ledger.empty:
            raise RuntimeError(f"no frozen outcome rows for shortlisted definition {cid}")
        p = out_dir / f"{safe_filename(cid)}.parquet"
        parquet_safe_frame(ledger).to_parquet(p, index=False, compression="zstd")
        event_hash = canonical_frame_hash(ledger, sort_keys=["candidate_definition_id", "candidate_symbol_id", "symbol", "decision_ts", "event_id", "seq"])
        short = shortlist[shortlist["candidate_definition_id"].astype(str).eq(cid)].iloc[0]
        manifest.append({
            "candidate_definition_id": cid,
            "path": str(p.relative_to(ctx.run_root)),
            "event_rows": int(len(ledger)),
            "event_ledger_hash": event_hash,
            "parameter_vector_hash": str(short.get("parameter_vector_hash", "")),
            "selected_event_key_hash": lineage["selected_event_key_hash"],
            "materialization_source": "post_freeze_tsmom_interval_outcome_cache",
            "event_sampling_used": False,
            "event_caps_used": False,
        })
        coverage.append({
            "candidate_definition_id": cid,
            "expected_event_count": int(safe_float(short.get("actual_event_rows", 0), 0.0)),
            "materialized_event_count": int(len(ledger)),
            "coverage_ratio": float(len(ledger) / max(1.0, safe_float(short.get("actual_event_rows", 0), 0.0))),
            "status": "pass" if int(len(ledger)) == int(safe_float(short.get("actual_event_rows", 0), 0.0)) else "fail",
        })
        mechanics.append({
            "candidate_definition_id": cid,
            "rows": int(len(ledger)),
            "raw_fields_present": {"raw_gross_R", "raw_fee_R", "raw_funding_R", "raw_slippage_R", "raw_net_R"}.issubset(ledger.columns),
            "scaled_fields_present": {"scaled_gross_R", "scaled_fee_R", "scaled_funding_R", "scaled_slippage_R", "scaled_net_R", "vol_scale"}.issubset(ledger.columns),
            "funding_fields_present": {"funding_exact", "funding_proxy_used", "funding_boundary_crossed"}.issubset(ledger.columns),
            "parent_gate_fields_present": {"parent_gate_pass", "parent_gate_feature_source_ts"}.issubset(ledger.columns),
            "status": "pass",
        })
    write_csv(ctx.run_root / "materialized/materialized_ledger_manifest.csv", manifest)
    write_csv(ctx.run_root / "materialized/full_event_coverage_audit.csv", coverage)
    write_csv(ctx.run_root / "mechanics/selected_materialized_mechanics_audit.csv", mechanics)


def stage_tsmom_v6_targeted_controls(ctx: Context) -> None:
    manifest = read_csv_safe(ctx.run_root / "materialized/materialized_ledger_manifest.csv")
    if manifest.empty:
        raise RuntimeError("materialized ledgers are required before targeted controls")
    roots = tsmom_v6_targeted_materialization_roots(ctx)
    full_outcomes = read_parquet_safe(roots["outcome_grouped"] / "cache/tsmom_interval_outcome.parquet")
    if full_outcomes.empty:
        raise RuntimeError("full TSMOM outcome cache is required as the real-control source pool")
    frozen_ids = set(TSMOM_V6_TARGETED_SHORTLIST_IDS) | set(TSMOM_V6_TARGETED_DEFERRED_DUPLICATE_IDS)
    control_source_base = full_outcomes[~full_outcomes["candidate_definition_id"].astype(str).isin(frozen_ids)].copy()
    if control_source_base.empty:
        raise RuntimeError("real-control source pool is empty after excluding shortlisted and deferred-duplicate definitions")
    if "parent_regime" not in control_source_base.columns:
        if "regime_label" in control_source_base.columns:
            control_source_base["parent_regime"] = control_source_base["regime_label"].astype(str)
        elif "parent_gate_status" in control_source_base.columns:
            control_source_base["parent_regime"] = control_source_base["parent_gate_status"].astype(str)
        else:
            control_source_base["parent_regime"] = "unknown"
    if "parent_regime" not in full_outcomes.columns:
        if "regime_label" in full_outcomes.columns:
            full_outcomes["parent_regime"] = full_outcomes["regime_label"].astype(str)
        elif "parent_gate_status" in full_outcomes.columns:
            full_outcomes["parent_regime"] = full_outcomes["parent_gate_status"].astype(str)
        else:
            full_outcomes["parent_regime"] = "unknown"

    def exact_window_key(frame: pd.DataFrame) -> pd.Series:
        cols = [c for c in ["symbol", "decision_ts", "entry_ts", "exit_ts", "exit_interval_end_ts"] if c in frame.columns]
        if not cols:
            return pd.Series("", index=frame.index)
        tmp = frame[cols].copy()
        for c in cols:
            if c.endswith("_ts") or c in {"decision_ts", "entry_ts", "exit_ts"}:
                tmp[c] = pd.to_datetime(tmp[c], utc=True, errors="coerce").astype(str)
            else:
                tmp[c] = tmp[c].astype(str)
        return tmp.astype(str).agg("|".join, axis=1)

    def recompute_control_summary(controls: pd.DataFrame) -> pd.DataFrame:
        rows: list[dict[str, Any]] = []
        if controls.empty:
            return pd.DataFrame(rows)
        for (candidate_id, control_type), g in controls.groupby(["matched_candidate_id", "control_type"], dropna=False):
            vals = pd.to_numeric(g.get("control_net_R", pd.Series(dtype=float)), errors="coerce")
            candidate_events = int(safe_float(g.get("candidate_event_count", pd.Series([0])).iloc[0], 0.0))
            candidate_net = safe_float(g.get("candidate_net_R", pd.Series([np.nan])).iloc[0], np.nan)
            control_events = int(vals.notna().sum())
            raw_control = float(vals.sum()) if control_events else float("nan")
            norm = normalize_control_net(candidate_events, raw_control, control_events)
            target = int(safe_float(g.get("target_control_event_count", pd.Series([candidate_events * max(1, int(ctx.args.nulls_per_event))])).iloc[0], candidate_events * max(1, int(ctx.args.nulls_per_event))))
            rows.append({
                "candidate_id": candidate_id,
                "candidate_definition_id": candidate_id,
                "control_type": control_type,
                "candidate_event_count": candidate_events,
                "control_event_count": control_events,
                "target_control_event_count": target,
                "control_coverage_ratio": control_events / target if target else float("nan"),
                "candidate_net_R": candidate_net,
                "raw_control_net_R": raw_control,
                "normalized_control_net_R": norm,
                "control_uplift_R": candidate_net - norm if np.isfinite(candidate_net) and np.isfinite(norm) else float("nan"),
                "beats_control": bool(np.isfinite(candidate_net) and np.isfinite(norm) and candidate_net > norm),
                "controls_normalized_to_candidate_count": True,
                "match_basis": ";".join(sorted(g.get("match_basis", pd.Series(dtype=str)).dropna().astype(str).unique())),
                "match_status": ";".join(sorted(g.get("match_status", pd.Series(dtype=str)).dropna().astype(str).unique())),
                "control_source_set_hash": stable_hash(*g.get("control_source_row_id", pd.Series(dtype=str)).astype(str).tolist()) if control_events else "",
                "all_control_rows_have_source_ids": bool(g.get("control_source_row_id", pd.Series(dtype=str)).notna().all() and g.get("source_window_id", pd.Series(dtype=str)).notna().all()),
            })
        return pd.DataFrame(rows)

    all_controls: list[pd.DataFrame] = []
    all_summary: list[pd.DataFrame] = []
    audit: list[dict[str, Any]] = []
    for _, m in manifest.iterrows():
        p = ctx.run_root / str(m["path"])
        ledger = read_parquet_safe(p)
        if ledger.empty:
            raise RuntimeError(f"empty materialized ledger for controls: {p}")
        if "parent_regime" not in ledger.columns:
            ledger = ledger.copy()
            if "regime_label" in ledger.columns:
                ledger["parent_regime"] = ledger["regime_label"].astype(str)
            elif "parent_gate_status" in ledger.columns:
                ledger["parent_regime"] = ledger["parent_gate_status"].astype(str)
            else:
                ledger["parent_regime"] = "unknown"
        cid = str(m["candidate_definition_id"])
        candidate_windows = set(exact_window_key(ledger).astype(str))
        source_pool = control_source_base[~exact_window_key(control_source_base).astype(str).isin(candidate_windows)].copy()
        combined_pool = pd.concat([ledger, source_pool], ignore_index=True, sort=False)
        standardized = standardize_event_ledger(combined_pool, source_path="full_tsmom_v6_outcome_cache_control_pool", family_hint="Volatility-managed TSMOM")
        _, controls, raw_summary = build_real_controls(
            standardized,
            candidate_keys=[cid],
            nulls_per_event=ctx.args.nulls_per_event,
            seed=ctx.args.seed,
        )
        if not controls.empty:
            controls = controls.sort_values(["matched_candidate_id", "control_type", "selection_rank"], kind="mergesort")
            controls = controls.drop_duplicates(["matched_candidate_id", "control_event_id", "source_window_id"], keep="first").reset_index(drop=True)
            controls["control_row_semantics_policy"] = ENGINES["scheduled_tsmom_engine"].row_semantics()
            controls["control_engine_id"] = "scheduled_tsmom_engine"
            controls["candidate_definition_id"] = cid
            controls["control_source_pool"] = "full_tsmom_v6_outcome_cache_excluding_shortlist_and_deferred_duplicates"
        summary = recompute_control_summary(controls)
        if summary.empty and not raw_summary.empty:
            summary = raw_summary.copy()
            summary["candidate_definition_id"] = cid
        else:
            summary["candidate_definition_id"] = cid
        missing_reasons = raw_summary[raw_summary.get("control_event_count", pd.Series(dtype=float)).astype(float).eq(0)].copy() if not raw_summary.empty and "control_event_count" in raw_summary.columns else pd.DataFrame()
        controls["candidate_definition_id"] = m["candidate_definition_id"]
        summary["candidate_definition_id"] = m["candidate_definition_id"]
        if not controls.empty:
            all_controls.append(controls)
        all_summary.append(summary)
        result = validate_control_rows(controls, allow_empty=False)
        audit.append({
            "candidate_definition_id": m["candidate_definition_id"],
            "event_rows": int(len(ledger)),
            "control_rows": int(len(controls)),
            "control_summary_rows": int(len(summary)),
            "control_validation_status": result.status,
            "control_validation_violations": result.violations,
            "zero_control_type_reasons": "; ".join(f"{r.get('control_type')}={r.get('match_status')}" for _, r in missing_reasons.iterrows()) if not missing_reasons.empty else "",
            "control_source_pool_rows": int(len(source_pool)),
            "excluded_exact_candidate_windows": int(len(candidate_windows)),
            "frozen_definition_control_sources_excluded": ";".join(sorted(frozen_ids)),
            "control_semantics": "real_matched_controls_not_placeholders",
        })
    summary_df = pd.concat(all_summary, ignore_index=True)
    if not all_controls:
        write_csv(ctx.run_root / "controls/control_summary.csv", summary_df)
        write_csv(ctx.run_root / "controls/control_semantics_audit.csv", audit)
        raise RuntimeError("real matched controls produced zero rows for all targeted candidates")
    controls_df = pd.concat(all_controls, ignore_index=True)
    out = ctx.run_root / "controls/control_ledger/control_ledger.parquet"
    out.parent.mkdir(parents=True, exist_ok=True)
    parquet_safe_frame(controls_df).to_parquet(out, index=False, compression="zstd")
    write_csv(ctx.run_root / "controls/control_summary.csv", summary_df)
    write_csv(ctx.run_root / "controls/control_semantics_audit.csv", audit)
    failures = [
        f"{r['candidate_definition_id']}:control_rows={r['control_rows']}:status={r['control_validation_status']}:violations={r['control_validation_violations']}"
        for r in audit
        if int(r["control_rows"]) <= 0 or str(r["control_validation_status"]) != "pass"
    ]
    if failures:
        raise RuntimeError("targeted real controls failed closed: " + "; ".join(failures))
    write_status(ctx, "complete", "tsmom-v6-targeted-controls")


def stage_tsmom_v6_targeted_stress(ctx: Context) -> None:
    manifest = read_csv_safe(ctx.run_root / "materialized/materialized_ledger_manifest.csv")
    if manifest.empty:
        raise RuntimeError("materialized ledgers are required before targeted stress")
    summary_rows: list[dict[str, Any]] = []
    raw_scaled_rows: list[dict[str, Any]] = []
    attribution_rows: list[dict[str, Any]] = []
    concentration_rows: list[dict[str, Any]] = []
    vol_rows: list[dict[str, Any]] = []
    for _, m in manifest.iterrows():
        cid = str(m["candidate_definition_id"])
        ledger = read_parquet_safe(ctx.run_root / str(m["path"]))
        if ledger.empty:
            continue
        net = pd.to_numeric(ledger.get("scaled_net_R", ledger.get("net_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
        gross = pd.to_numeric(ledger.get("scaled_gross_R", ledger.get("gross_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
        fees = pd.to_numeric(ledger.get("scaled_fee_R", ledger.get("fees_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
        funding = pd.to_numeric(ledger.get("scaled_funding_R", ledger.get("funding_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
        slippage = pd.to_numeric(ledger.get("scaled_slippage_R", ledger.get("slippage_R", pd.Series(dtype=float))), errors="coerce").fillna(0.0)
        raw_gross = pd.to_numeric(ledger.get("raw_gross_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        raw_fee = pd.to_numeric(ledger.get("raw_fee_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        raw_funding = pd.to_numeric(ledger.get("raw_funding_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        raw_slippage = pd.to_numeric(ledger.get("raw_slippage_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        raw_net = pd.to_numeric(ledger.get("raw_net_R", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
        scaled_net_total = float(net.sum())
        funding_exact_events = int(parse_bool_series(ledger.get("funding_exact", pd.Series(False, index=ledger.index)), default=False, strict=False).sum()) if "funding_exact" in ledger.columns else 0
        funding_proxy_events = int(parse_bool_series(ledger.get("funding_proxy_used", pd.Series(False, index=ledger.index)), default=False, strict=False).sum()) if "funding_proxy_used" in ledger.columns else 0
        summary_rows.append({
            "candidate_definition_id": cid,
            "events": int(len(ledger)),
            "gross_R": float(gross.sum()),
            "fees_R": float(fees.sum()),
            "funding_R": float(funding.sum()),
            "slippage_R": float(slippage.sum()),
            "net_R": scaled_net_total,
            "raw_net_R": float(raw_net.sum()),
            "fee_stress_plus_2bps_net_R": float(scaled_net_total - 0.02 * len(ledger)),
            "fee_stress_plus_5bps_net_R": float(scaled_net_total - 0.05 * len(ledger)),
            "slippage_stress_plus_5bps_net_R": float(scaled_net_total - 0.05 * len(ledger)),
            "funding_stress_no_funding_net_R": float((net - funding).sum()),
            "funding_stress_150pct_funding_net_R": float((net + 0.5 * funding).sum()),
            "raw_negative_scaled_positive_vol_scaling_review_required": bool(cid == "tsmom_v6_059" and raw_net.sum() < 0 < scaled_net_total),
            "evidence_label": "level_3_train_only_materialized_stress_diagnostic_capped",
        })
        raw_scaled_rows.append({
            "candidate_definition_id": cid,
            "events": int(len(ledger)),
            "raw_gross_R": float(raw_gross.sum()),
            "raw_fee_R": float(raw_fee.sum()),
            "raw_funding_R": float(raw_funding.sum()),
            "raw_slippage_R": float(raw_slippage.sum()),
            "raw_net_R": float(raw_net.sum()),
            "scaled_gross_R": float(gross.sum()),
            "scaled_fee_R": float(fees.sum()),
            "scaled_funding_R": float(funding.sum()),
            "scaled_slippage_R": float(slippage.sum()),
            "scaled_net_R": scaled_net_total,
            "scaled_minus_raw_net_R": float(scaled_net_total - raw_net.sum()),
            "raw_negative_scaled_positive_vol_scaling_review_required": bool(cid == "tsmom_v6_059" and raw_net.sum() < 0 < scaled_net_total),
        })
        attribution_rows.append({
            "candidate_definition_id": cid,
            "events": int(len(ledger)),
            "gross_R": float(gross.sum()),
            "fee_R": float(fees.sum()),
            "funding_R": float(funding.sum()),
            "slippage_R": float(slippage.sum()),
            "net_R": scaled_net_total,
            "fee_R_share_of_abs_gross": float(abs(fees.sum()) / max(abs(gross.sum()), 1e-12)),
            "funding_R_share_of_abs_gross": float(abs(funding.sum()) / max(abs(gross.sum()), 1e-12)),
            "slippage_R_share_of_abs_gross": float(abs(slippage.sum()) / max(abs(gross.sum()), 1e-12)),
            "funding_exact_events": funding_exact_events,
            "funding_proxy_events": funding_proxy_events,
            "funding_proxy_event_share": float(funding_proxy_events / max(len(ledger), 1)),
        })
        if "decision_ts" in ledger.columns:
            ledger = ledger.copy()
            ledger["month"] = pd.to_datetime(ledger["decision_ts"], utc=True, errors="coerce").dt.strftime("%Y-%m")
        for scope, cols in [("symbol", ["symbol"]), ("month", ["month"]), ("symbol_month", ["symbol", "month"])]:
            if all(c in ledger.columns for c in cols):
                g = ledger.groupby(cols, dropna=False)["scaled_net_R" if "scaled_net_R" in ledger.columns else "net_R"].sum().reset_index(name="scaled_net_R")
                g["candidate_definition_id"] = cid
                g["concentration_scope"] = scope
                concentration_rows.extend(g.to_dict("records"))
        if "vol_scale" in ledger.columns:
            vol = pd.to_numeric(ledger["vol_scale"], errors="coerce")
            vol_rows.append({
                "candidate_definition_id": cid,
                "events": int(len(ledger)),
                "vol_scale_min_observed": float(vol.min()),
                "vol_scale_max_observed": float(vol.max()),
                "vol_scale_mean": float(vol.mean()),
                "vol_scale_at_min_cap_events": int((vol <= safe_float(ledger.get("vol_scale_min", pd.Series([0.25])).iloc[0] if "vol_scale_min" in ledger.columns else 0.25, 0.25)).sum()),
                "vol_scale_at_max_cap_events": int((vol >= safe_float(ledger.get("vol_scale_max", pd.Series([2.0])).iloc[0] if "vol_scale_max" in ledger.columns else 2.0, 2.0)).sum()),
            })
    write_csv(ctx.run_root / "stress/targeted_stress_summary.csv", summary_rows)
    write_csv(ctx.run_root / "stress/raw_vs_scaled_decomposition.csv", raw_scaled_rows)
    write_csv(ctx.run_root / "stress/funding_fee_slippage_attribution.csv", attribution_rows)
    write_csv(ctx.run_root / "stress/vol_scale_decomposition.csv", vol_rows)
    write_csv(ctx.run_root / "stress/concentration_by_symbol_month.csv", concentration_rows)
    write_status(ctx, "complete", "tsmom-v6-targeted-stress")


def stage_tsmom_v6_targeted_decision(ctx: Context) -> None:
    manifest = read_csv_safe(ctx.run_root / "materialized/materialized_ledger_manifest.csv")
    controls = read_csv_safe(ctx.run_root / "controls/control_semantics_audit.csv")
    stress = read_csv_safe(ctx.run_root / "stress/targeted_stress_summary.csv")
    raw_scaled = read_csv_safe(ctx.run_root / "stress/raw_vs_scaled_decomposition.csv")
    pass_gate = not manifest.empty and len(manifest) == len(TSMOM_V6_TARGETED_SHORTLIST_IDS) and not controls.empty and controls.get("control_validation_status", pd.Series(dtype=str)).astype(str).eq("pass").all() and not stress.empty
    decision_rows: list[dict[str, Any]] = []
    library_rows: list[dict[str, Any]] = []
    stress_by_id = stress.set_index("candidate_definition_id", drop=False) if "candidate_definition_id" in stress.columns else pd.DataFrame()
    controls_by_id = controls.set_index("candidate_definition_id", drop=False) if "candidate_definition_id" in controls.columns else pd.DataFrame()
    raw_scaled_by_id = raw_scaled.set_index("candidate_definition_id", drop=False) if "candidate_definition_id" in raw_scaled.columns else pd.DataFrame()
    for _, m in manifest.iterrows():
        cid = str(m.get("candidate_definition_id", ""))
        c = controls_by_id.loc[cid] if not controls_by_id.empty and cid in controls_by_id.index else pd.Series(dtype=object)
        s = stress_by_id.loc[cid] if not stress_by_id.empty and cid in stress_by_id.index else pd.Series(dtype=object)
        rs = raw_scaled_by_id.loc[cid] if not raw_scaled_by_id.empty and cid in raw_scaled_by_id.index else pd.Series(dtype=object)
        if isinstance(c, pd.DataFrame):
            c = c.iloc[0]
        if isinstance(s, pd.DataFrame):
            s = s.iloc[0]
        if isinstance(rs, pd.DataFrame):
            rs = rs.iloc[0]
        control_pass = str(c.get("control_validation_status", "fail")) == "pass" and int(safe_float(c.get("control_rows", 0), 0.0)) > 0
        stress_pass = bool(not s.empty)
        raw_scaled_review = bool(rs.get("raw_negative_scaled_positive_vol_scaling_review_required", False))
        status = "preserved_for_train_only_review_capped" if control_pass and stress_pass else "deferred_control_or_stress_issue"
        decision_rows.append({
            "candidate_definition_id": cid,
            "event_rows": int(safe_float(m.get("event_rows", 0), 0.0)),
            "control_rows": int(safe_float(c.get("control_rows", 0), 0.0)),
            "controls_pass": control_pass,
            "stress_pass": stress_pass,
            "raw_net_R": safe_float(rs.get("raw_net_R", np.nan), np.nan),
            "scaled_net_R": safe_float(rs.get("scaled_net_R", s.get("net_R", np.nan)), np.nan),
            "raw_negative_scaled_positive_vol_scaling_review_required": raw_scaled_review,
            "candidate_decision_status": status,
            "evidence_level_assigned": "level_3_train_only_materialized_controls_stress_diagnostic_capped",
            "can_support_validation_or_live_readiness": False,
        })
        library_rows.append({
            "candidate_definition_id": cid,
            "parameter_vector_hash": str(m.get("parameter_vector_hash", "")),
            "selected_event_key_hash": str(m.get("selected_event_key_hash", "")),
            "candidate_library_status": status,
            "materialization_status": "targeted_materialized_controls_stress_complete" if control_pass and stress_pass else "targeted_materialized_controls_stress_blocked",
            "event_rows": int(safe_float(m.get("event_rows", 0), 0.0)),
            "control_rows": int(safe_float(c.get("control_rows", 0), 0.0)),
            "raw_negative_scaled_positive_vol_scaling_review_required": raw_scaled_review,
            "evidence_label": "level_3_train_only_materialized_controls_stress_diagnostic_capped",
            "can_support_strategy_claim": False,
            "validation_or_live_readiness": False,
        })
    for cid in TSMOM_V6_TARGETED_DEFERRED_DUPLICATE_IDS:
        library_rows.append({
            "candidate_definition_id": cid,
            "parameter_vector_hash": "",
            "selected_event_key_hash": "",
            "candidate_library_status": "frozen_deferred_duplicate_not_independent_discovery",
            "materialization_status": "not_materialized_frozen_duplicate",
            "event_rows": 0,
            "control_rows": 0,
            "raw_negative_scaled_positive_vol_scaling_review_required": False,
            "evidence_label": "deferred_duplicate_train_only_no_materialized_evidence",
            "can_support_strategy_claim": False,
            "validation_or_live_readiness": False,
        })
    write_csv(ctx.run_root / "decision/candidate_level_decision_table.csv", decision_rows)
    write_csv(ctx.run_root / "candidate_library/targeted_materialization_candidate_library_update.csv", library_rows)
    summary = {
        "run_root": str(ctx.run_root),
        "status": "complete" if pass_gate else "blocked",
        "phase_profile": ctx.args.phase_profile,
        "code_modified": True,
        "materialization_launched": True,
        "validation_run": False,
        "final_holdout_touched": False,
        "prior_high_route_touched": False,
        "materialized_definition_count": int(len(manifest)),
        "control_rows": int(pd.to_numeric(controls.get("control_rows", pd.Series(dtype=float)), errors="coerce").fillna(0).sum()) if not controls.empty else 0,
        "stress_rows": int(len(stress)),
        "candidate_decision_table_path": str(ctx.run_root / "decision/candidate_level_decision_table.csv"),
        "candidate_library_update_path": str(ctx.run_root / "candidate_library/targeted_materialization_candidate_library_update.csv"),
        "evidence_label": "level_3_train_only_materialized_controls_stress_diagnostic_capped",
        "next_operator_decision": "review_targeted_materialization_controls_stress_outputs_next" if pass_gate else "repair_tsmom_v6_targeted_materialization_next",
        "compact_bundle_path": str(ctx.run_root / "compact_review_bundle"),
        "ts_utc": utc_now(),
    }
    write_json(ctx.run_root / "decision_summary.json", summary)
    write_status(ctx, summary["status"], "tsmom-v6-targeted-decision")


def stage_tests(ctx: Context) -> None:
    write_text(ctx.run_root / "tests/test_plan.md", "# Test Plan\n\nExternal verification runs py_compile and `unit_tests.test_kraken_family_engine_aggregate_first_sweep`. This stage records the required commands and does not launch non-smoke sweeps.\n")


